INSERT INTO public.news VALUES ('1b25c930-c507-407a-b1da-d9fd319ee615', '82f6a8a', 'قرار جديد يلزم موظفي الشرقية الصحي بدوام تسع ساعات يومياً', 'إجراء إداري صارم في ظل مرحلة انتقالية جديدة', 'أقر تجمع الشرقية الصحي لائحة دوام إلزامية بمعدل تسع ساعات يومياً، ضمن تحول إداري جديد تحت مظلة الصحة القابضة، مع إعادة هيكلة شاملة لجداول المناوبات لضمان الكفاءة.', '<p>أقر تجمع الشرقية الصحي لائحة دوام رسمية تُلزم كافة منسوبيه بالعمل لمدة تسع ساعات يومياً، في أول إجراء إداري عقب انتقال الموظفين رسمياً إلى كادر شركة الصحة القابضة، وذلك وفقاً لما نشرته صحيفة اليوم.</p><p style="text-align: right;">يمثل القرار تحولاً جوهرياً في بيئة العمل الصحي بالمنطقة تزامناً مع المرحلة الانتقالية للقطاع؛ حيث حددت وحدة مراقبة انتظام الموارد البشرية إطاراً زمنياً صارماً يبدأ من السابعة والنصف صباحاً وحتى الرابعة والنصف مساءً. ويهدف هذا الإجراء، بحسب تقرير صحيفة اليوم، إلى توحيد التوقيت الزمني في كافة المراكز الصحية التابعة للتجمع وضمان تقديم الخدمات بكفاءة طوال ساعات العمل المقررة دون استثناءات.</p><p style="text-align: right;">وجهت إدارة التجمع بإعادة هيكلة فورية لجداول المناوبات لتتوافق مع واقع الساعات التسع الجديد، مع التشدد في تطبيق الانضباط الوظيفي. ومن المتوقع أن يعقب هذه الخطوة إجراءات تنظيمية أخرى تهدف إلى ضبط الأداء تحت إدارة “الصحة القابضة”، مما يضع الكوادر الصحية أمام واقع إداري جديد يتطلب التكيف السريع مع معايير الإنتاجية الجديدة.</p>', 'saudi-health', NULL, NULL, '/objects/uploads/98d43cd5-69d1-4ecb-952b-9454d5da551e', NULL, 'موظفو الشرقية الصحي يلتزمون بدوام تسع ساعات يومياً', 'قرار جديد من تجمع الشرقية الصحي يشدد على دوام تسع ساعات يومياً، يأتي ذلك ضمن تحول إداري تحت شركة الصحة القابضة لضمان تقديم خدمات فعالة.', '{"تجمع الشرقية الصحي","الصحة القابضة","الدوام تسع ساعات","إجراءات إدارية","الخدمات الصحية","انضباط وظيفي","هيكلة المناوبات"}', false, 'published', NULL, NULL, '2026-01-24 15:11:57.65', '2026-01-24 15:11:58.558556', '2026-01-24 15:11:58.558556');
INSERT INTO public.news VALUES ('716c4cf0-ef6b-4e73-9ba0-44a3ea505edd', '8fbfbcc', 'انقسام أمريكي تاريخي: كاليفورنيا تعود لمنظمة الصحة العالمية وتتحدى عزلة واشنطن', NULL, 'كبسولة الصحية &#8211; رويترز أكملت الولايات المتحدة رسمياً إجراءات انسحابها من منظمة الصحة العالمية، لتنهي التزاماً دولياً دام 78 عاماًK وفي خطوة مثلت طعنة سياسية لقرار البيت الأبيض، أعلنت ولاية كاليفورنيا انضمامها الفردي لشبكة الاستجابة العالمية التابعة للمنظمة، في تحرك يكشف عن انقسام داخلي حاد حول', '<p>كبسولة الصحية &#8211; رويترز</p>
<p>أكملت الولايات المتحدة رسمياً إجراءات انسحابها من منظمة الصحة العالمية، لتنهي التزاماً دولياً دام 78 عاماًK وفي خطوة مثلت طعنة سياسية لقرار البيت الأبيض، أعلنت ولاية كاليفورنيا انضمامها الفردي لشبكة الاستجابة العالمية التابعة للمنظمة، في تحرك يكشف عن انقسام داخلي حاد حول كيفية إدارة التهديدات البيولوجية العابرة للحدود.</p>
<p><strong>لماذا انسحبت واشنطن؟ </strong></p>
<p>(جذور الأزمة) اتخذت إدارة الرئيس دونالد ترامب قرار الانسحاب بناءً على ثلاثة محاور رئيسية:</p>
<p><strong>اتهامات الفشل الميداني:</strong></p>
<p>ترى الإدارة الأمريكية أن المنظمة أخفقت بشكل كارثي في بداية جائحة كورونا، وتأخرت في إعلان الطوارئ العالمية.</p>
<p><strong>النفوذ الصيني: </strong></p>
<p>اتهمت واشنطن المنظمة بالانحياز لبكين والمساعدة في &#8220;تسييس&#8221; أصل الفيروس، معتبرة أن أمريكا -الممول الأكبر- لم تعد تملك صوتاً موازناً لهذا النفوذ.</p>
<p><strong>السيادة المالية: </strong></p>
<p>رغبت واشنطن في تحويل ميزانيتها المقدرة بـ 450 مليون دولار سنوياً من المنظمة الدولية إلى مشاريع صحية أمريكية خالصة تحت شعار &#8220;أمريكا أولاً&#8221;.</p>
<p><strong>لماذا تتمرد الولايات (كاليفورنيا نموذجاً)؟ </strong></p>
<p>يأتي تمرد ولاية كاليفورنيا مدفوعاً بضرورات واقعية تتجاوز الخلاف السياسي:</p>
<p><strong>الأمن الصحي المستقل:</strong></p>
<p>كاليفورنيا تمتلك خامس أكبر اقتصاد في العالم، وبها موانئ ومطارات عالمية تجعلها خط دفاع أول. الانسحاب الفيدرالي يحرم مختبرات الولاية من الوصول السريع لبيانات الأمراض الناشئة التي توفرها المنظمة.</p>
<p><strong>الاقتصاد والبحث العلمي: </strong></p>
<p>تضم الولاية مراكز أبحاث عالمية وشركات أدوية كبرى في &#8220;سيليكون فالي&#8221;، وهذه المؤسسات تحتاج للغطاء الدولي الذي توفره المنظمة لتصدير ابتكاراتها والمشاركة في الأبحاث العالمية.</p>
<p><strong>الصدام الدستوري: </strong></p>
<p>يتيح النظام الفيدرالي الأمريكي للولايات هامشاً من المناورة في الاتفاقيات &#8220;الفنية&#8221;. كاليفورنيا لم تنضم كـ &#8220;دولة عضو&#8221; (وهو أمر غير قانوني)، بل انضمت كـ &#8220;شريك فني&#8221; في شبكة الاستجابة (GOARN)، وهي ثغرة قانونية سمحت لها بالبقاء في المظلة الدولية دون كسر القانون الفيدرالي صراحة.</p>
<p><strong>هل تنهار الوحدة الصحية الأمريكية؟</strong></p>
<p>تحرك كاليفورنيا يفتح الباب أمام &#8220;دبلوماسية الولايات&#8221;؛ حيث بدأت ولايات زرقاء (ديمقراطية) أخرى في دراسة خطوات مماثلة. هذا التشرذم يعني أن العالم سيتعامل مع أمريكا ككيانات صحية منفصلة: واشنطن في عزلة، وكاليفورنيا (وربما نيويورك لاحقاً) في قلب التعاون الدولي.</p>
<p>يضع هذا الانقسام منظمة الصحة العالمية في موقف حرج؛ فهي بحاجة لخبرات كاليفورنيا الفنية وميزانيتها المحلية، لكنها تخشى إغضاب الحكومة الفيدرالية. وبحسب لقاء حاكم كاليفورنيا والمدير العام للمنظمة في &#8220;دافوس&#8221;، فإن التوجه القادم هو خلق &#8220;مسارات بديلة&#8221; تضمن بقاء الكفاءات الأمريكية داخل النظام العالمي، بانتظار تغير المناخ السياسي في واشنطن الذي قد يعيد توحيد الصف الصحي الأمريكي مرة أخرى.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/39c884f8-8bc7-4a5e-be89-d3b004bab466.webp', 'انقسام أمريكي تاريخي: كاليفورنيا تعود لمنظمة الصحة العالمية وتتحدى عزلة واشنطن', 'انقسام أمريكي تاريخي: كاليفورنيا تعود لمنظمة الصحة العالمية وتتحدى عزلة واشنطن', 'كبسولة الصحية &#8211; رويترز أكملت الولايات المتحدة رسمياً إجراءات انسحابها من منظمة الصحة العالمية، لتنهي التزاماً دولياً دام 78 عاماًK وفي خطوة مثلت طعنة سياس', '{أمريكا,كاليفورنيا,"منظمة الصحة العالمية"}', false, 'deleted', NULL, NULL, '2026-01-24 11:01:55', '2026-01-24 16:23:12.527179', '2026-01-24 16:23:12.527179');
INSERT INTO public.news VALUES ('debc07d2-fcf2-43fd-bf0c-cafd92304537', 'EllSZm3', 'فحص دم ثوري بالوخز يُبشّر بتشخيص مبكر للزهايمر', 'ابتكار طبي يكتشف المرض قبل 15 عاماً من الأعراض', 'أطلقت دراسة دولية لفحص دم يعتمد على وخز الإصبع لتشخيص الزهايمر مبكراً في المملكة المتحدة وأمريكا وكندا. الفحص تحليل لبروتينات حيوية ويمهد لفحوص سهلة ودقيقة بديلاً عن الطرق المعقدة الحالية.', '<p>بدأت تجربة سريرية دولية تشمل ألف متطوع في المملكة المتحدة وأمريكا وكندا لاختبار فحص دم بسيط يعتمد على “وخزة إصبع” لتشخيص مرض الزهايمر. يركز الفحص على تحليل ثلاثة بروتينات حيوية في الدم تعمل كمؤشرات دقيقة لوجود المرض، مما يتيح اكتشاف تراكم بروتينات “الأميلويد والتاو” الضارة في الدماغ قبل ظهور الأعراض السريرية بنحو 15 عاماً.</p><p style="text-align: right;">تعتمد التشخيصات الحالية على وسائل مكلفة ومعقدة مثل التصوير المقطعي (PET) أو سحب السائل النخاعي، وهي فحوصات لا تتوفر إلا لـ 2% فقط من المرضى بسبب تكلفتها وصعوبة إجراءاتها. تكمن قيمة الفحص الجديد في قدرته على توفير تشخيص دقيق وسهل المنال، حيث يمكن إجراء الاختبار في المنزل وإرسال العينة للمختبر دون الحاجة لتبريد، مما يزيل الحواجز الجراحية والمالية أمام ملايين المصابين.</p><p style="text-align: right;">تستمر الدراسات لمقارنة نتائج وخز الإصبع مع نتائج التصوير الإشعاعي التقليدي لضمان أعلى مستويات الدقة قبل اعتماده عالمياً. يتوقع الخبراء أن يتحول هذا الفحص إلى إجراء روتيني لكبار السن فوق سن الستين، مما يسهم في بدء العلاج والتدخل الطبي في مراحل مبكرة جداً، وهو الأمر الذي يعزز فرص السيطرة على تدهور القدرات الإدراكية قبل فوات الأوان.</p>', 'misc', NULL, NULL, '/objects/uploads/1f2ed388-4f4a-4baa-a4f7-6996dff82edb', NULL, 'فحص دم مبتكر لتشخيص الزهايمر مبكراً', 'دراسة جديدة تبحث فحص دم بسيط لتشخيص الزهايمر بدقة، بدل الطرق التقليدية المكلفة والمعقدة، مما يُحدث ثورة صحية قادمة.', '{"فحص دم",الزهايمر,"تشخيص مبكر","الطب الحديث","تحليل البروتينات","وخزة إصبع","أبحاث طبية"}', true, 'published', NULL, NULL, '2026-01-24 18:35:30.933', '2026-01-24 18:35:31.435461', '2026-01-24 18:35:31.435461');
INSERT INTO public.news VALUES ('a63a9e2d-f428-434d-a5e0-aeaac6205c35', 'a4rQShk', 'اكتشاف طبي يفتح أفقاً جديداً لعلاجات السرطان المستهدفة', 'دور بروتين NPM1 في وقف نمو الخلايا السرطانية', 'فريق علمي بجامعة غلاسكو يكتشف أن تثبيط بروتين NPM1 يعيق نمو الخلايا السرطانية، مشيراً إلى إمكانية تطوير علاج آمن وفعال لسرطانات الأمعاء والكبد دون التأثير على الأنسجة السليمة، مما يمهد لجيل جديد من العلاجات.', '<p>يتواجد بمستويات مرتفعة في أورام الأمعاء والكبد، ويعمل كمحرك أساسي لنمو الخلايا السرطانية عبر السيطرة على نظام إشارات (WNT). ووجد علماء من جامعة غلاسكو أن الأخطاء الجينية في هذا النظام تمنع الخلايا من التوقف عن النمو، مما يجعل اكتشاف دور هذا البروتين تحديداً نقطة تحول في فهم كيفية تكوّن الأورام في هذه الأنسجة الصعبة.</p><p style="text-align: right;">تكمن أهمية هذا الاكتشاف في أن بروتين (NPM1) ليس ضرورياً لصحة الأنسجة الطبيعية لدى البالغين، مما يعني أن استهدافه بالعلاج وتثبيطه قد يكون وسيلة آمنة وفعالة للقضاء على الخلايا السرطانية دون إلحاق ضرر بالخلايا السليمة. وبحسب ما نقلته (آر تي)، فإن إزالة هذا البروتين تجعل الخلايا السرطانية عاجزة عن إنتاج بروتيناتها بشكل صحيح، مما يسمح للجسم بتفعيل “مثبطات الأورام” الطبيعية ومنع نمو السرطان مجدداً.</p><p style="text-align: right;">يتطلع الفريق العلمي حالياً إلى تطوير علاجات دوائية تستهدف تثبيط هذا البروتين، وهو ما قد يفتح الباب أمام جيل جديد من العلاجات الموجهة لأنواع أخرى من السرطان مستقبلاً.</p><p style="text-align: right;">ويأمل الباحثون أن تساهم هذه النتائج في تقليل معدلات الوفيات الناتجة عن سرطانات الأمعاء والكبد التي تعد من أكثر الأنواع تعقيداً في العلاج، مع التركيز على تحويل هذه النتائج المخبرية إلى بروتوكولات علاجية متاحة للمرضى في أقرب وقت.</p>', 'misc', NULL, NULL, '/objects/uploads/41f31ce8-a207-481a-b198-44ebece9e62d', NULL, 'اكتشاف دور NPM1 لعلاجات أورام الكبد والأمعاء', 'دراسة من جامعة غلاسكو تكشف أهمية استهداف بروتين NPM1 لعلاج سرطانات الأمعاء والكبد بشكل آمن وفعّال، وتطوير علاجات جديدة مستقبلاً.', '{"بروتين NPM1","سرطان الأمعاء","سرطان الكبد","العلاجات المستهدفة","جامعة غلاسكو",الأورام,"نظام إشارات WNT"}', true, 'published', '2026-01-24 21:55:00', NULL, '2026-01-24 21:55:00', '2026-01-24 18:37:02.094792', '2026-01-24 18:37:02.094792');
INSERT INTO public.news VALUES ('4fc08f4f-8400-4158-aec9-194dec295e7d', 'bBBqDS4', 'نجاح أول عمليتين لترميم صيوان الأذن بمعدات حديثة', 'إطلاق برنامج وطني للجراحات الترميمية المتطورة', 'تحتفل وزارة الحرس الوطني بنجاح أول عمليتين لترميم عيوب صيوان الأذن الخَلقية، معلنةً إطلاق برنامج طبي وطني يتيح إجراء التدخلات الجراحية عبر عملية واحدة للأطفال قبل سن السادسة باستخدام غرسات طبية متطورة.', '<p>أعلنت الشؤون الصحية بوزارة الحرس الوطني عن نجاح أول عمليتين لترميم عيوب صيوان الأذن الخَلقية Microtia)) معلنةً بذلك إطلاق برنامج وطني متخصص لترميم هذه العيوب باستخدام الغرسات الطبية المتقدمة. ويأتي هذا الإنجاز كجزء من استراتيجية الوزارة لتوطين أحدث الجراحات الدقيقة والمعقدة في المملكة.</p><p style="text-align: right;">وتبرز أهمية هذا البرنامج في قدرته على تقديم حلول جراحية متطورة تنجز عبر “عملية واحدة فقط”، وهو ما يمثل نقلة نوعية مقارنة بالأساليب التقليدية. كما يتيح البرنامج التدخل المبكر للأطفال دون سن السادسة، مما يساهم في تحسين جودة حياتهم واندماجهم المجتمعي في سن مبكرة، بناءً على تقييم طبي ومعايير إكلينيكية دقيقة.</p><p style="text-align: right;">ويستهدف البرنامج تعزيز ريادة المملكة في الجراحات الترميمية المتقدمة، وتوفير بيئة علاجية تتبنى أحدث التقنيات العالمية لخدمة المرضى، مما يقلل من فترات التعافي والعبء النفسي والجسدي على الأطفال وذويهم.</p>', 'health-reports', NULL, NULL, '/objects/uploads/43fe2e3e-4490-42fd-afc5-2971de23664e', NULL, 'نجاح ترميم عيوب الأذن الخَلقية لأول مرة', 'وزارة الحرس الوطني تطلق برنامجاً وطنياً للجراحات الترميمية يقدم حلاً مدعماً بغرسات طبية لأطفال يعانون عيوب الأذن الخَلقية.', '{"ترميم الأذن",Microtia,"وزارة الحرس الوطني","غرسات طبية","جراحات دقيقة","برنامج وطني","التدخل المبكر"}', true, 'published', NULL, NULL, '2026-01-24 17:43:51.318', '2026-01-24 17:43:54.189018', '2026-01-24 17:43:54.189018');
INSERT INTO public.news VALUES ('71746483-5a6d-4a0f-81bc-b6fdb2fb29b9', 'cf346be', 'كيف يحول داء السكري الجهاز البولي لبيئة حاضنة للبكتيريا؟', NULL, 'متابعة – كبسولة الصحية كشفت التقارير الطبية عن ارتباط وثيق بين ارتفاع مستويات السكر في الدم وزيادة معدلات الإصابة بالتهابات المسالك البولية، حيث يعمل &#8220;الغلوكوز&#8221; الزائد كغذاء مثالي لنمو بكتيريا &#8220;الإشريكية القولونية&#8221;. وأوضحت صحيفة (الشرق الأوسط) أن مرض السكري لا يكتفي بتغذية ال', '<p>متابعة – كبسولة الصحية</p>
<p>كشفت التقارير الطبية عن ارتباط وثيق بين ارتفاع مستويات السكر في الدم وزيادة معدلات الإصابة بالتهابات المسالك البولية، حيث يعمل &#8220;الغلوكوز&#8221; الزائد كغذاء مثالي لنمو بكتيريا &#8220;الإشريكية القولونية&#8221;.</p>
<p>وأوضحت صحيفة (الشرق الأوسط) أن مرض السكري لا يكتفي بتغذية العدوى، بل يضعف جهاز المناعة ويسبب تلفاً في أعصاب المثانة، مما يمنع تفريغها بالكامل ويخلق بيئة مستقرة لتراكم البكتيريا والالتهابات المتكررة.</p>
<p>تكمن خطورة هذا الارتباط في &#8220;التأثير المزدوج&#8221; للسكر على الكلى والمثانة؛ فمن جهة يؤدي فقدان السوائل الناتج عن كثرة التبول إلى تشكل الحصوات، ومن جهة أخرى يسبب الارتفاع المستمر للسكر ضيقاً في مجرى الدم المغذي للكليتين. هذا الضيق يؤدي تدريجياً إلى ضمور في أنسجة الكلى ويجعلها أكثر عرضة للالتهابات الحادة التي قد تتطور إلى مضاعفات خطيرة تؤثر على كفاءة الجهاز البولي بشكل كامل.</p>
<p>يتطلب التعامل مع هذه الحالة مراقبة دقيقة لأعراض مثل ألم الحوض، والبول العكر، والتبول المتكرر الذي يصاحبه ألم. وينصح الأطباء مرضى السكري بضرورة تعويض السوائل المفقودة لتجنب الحصوات، مع إجراء فحوصات دورية لوظائف الكلى والمسالك. وتساهم التوعية المبكرة بهذه الأعراض في تقليل مخاطر &#8220;سلس البول&#8221; والتهابات بطانة الجهاز البولي، مما يحمي المرضى من الدخول في دوامة الالتهابات المزمنة.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/637eb8eb-a478-43cd-b4ba-f5e86260ecba.webp', 'كيف يحول داء السكري الجهاز البولي لبيئة حاضنة للبكتيريا؟', 'كيف يحول داء السكري الجهاز البولي لبيئة حاضنة للبكتيريا؟', 'متابعة – كبسولة الصحية كشفت التقارير الطبية عن ارتباط وثيق بين ارتفاع مستويات السكر في الدم وزيادة معدلات الإصابة بالتهابات المسالك البولية، حيث يعمل &#8220;الغ', '{البكتيريا,البول,السكري}', false, 'published', NULL, NULL, '2026-01-24 01:23:10', '2026-01-24 16:23:12.930935', '2026-01-24 16:23:12.930935');
INSERT INTO public.news VALUES ('61f1b7a5-4d9c-41c3-b65e-683b5239dfe8', '3e2b76a', 'وخزة إصبع تكشف مخاطر مرض الزهايمر مبكراً', NULL, 'كبسولة الصحية &#8211;  إم إس إن هيلث بدأت تجربة سريرية دولية تشمل ألف متطوع في المملكة المتحدة وأمريكا وكندا لاختبار فحص دم بسيط يعتمد على &#8220;وخزة إصبع&#8221; لتشخيص مرض الزهايمر. يركز الفحص على تحليل ثلاثة بروتينات حيوية في الدم تعمل كمؤشرات دقيقة لوجود المرض، مما يتيح اكتشاف تراكم بروتينات &#8', '<p>كبسولة الصحية &#8211;  إم إس إن هيلث</p>
<p>بدأت تجربة سريرية دولية تشمل ألف متطوع في المملكة المتحدة وأمريكا وكندا لاختبار فحص دم بسيط يعتمد على &#8220;وخزة إصبع&#8221; لتشخيص مرض الزهايمر. يركز الفحص على تحليل ثلاثة بروتينات حيوية في الدم تعمل كمؤشرات دقيقة لوجود المرض، مما يتيح اكتشاف تراكم بروتينات &#8220;الأميلويد والتاو&#8221; الضارة في الدماغ قبل ظهور الأعراض السريرية بنحو 15 عاماً.</p>
<p>تعتمد التشخيصات الحالية على وسائل مكلفة ومعقدة مثل التصوير المقطعي (PET) أو سحب السائل النخاعي، وهي فحوصات لا تتوفر إلا لـ 2% فقط من المرضى بسبب تكلفتها وصعوبة إجراءاتها. تكمن قيمة الفحص الجديد في قدرته على توفير تشخيص دقيق وسهل المنال، حيث يمكن إجراء الاختبار في المنزل وإرسال العينة للمختبر دون الحاجة لتبريد، مما يزيل الحواجز الجراحية والمالية أمام ملايين المصابين.</p>
<p>تستمر الدراسات لمقارنة نتائج وخز الإصبع مع نتائج التصوير الإشعاعي التقليدي لضمان أعلى مستويات الدقة قبل اعتماده عالمياً. يتوقع الخبراء أن يتحول هذا الفحص إلى إجراء روتيني لكبار السن فوق سن الستين، مما يسهم في بدء العلاج والتدخل الطبي في مراحل مبكرة جداً، وهو الأمر الذي يعزز فرص السيطرة على تدهور القدرات الإدراكية قبل فوات الأوان.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/733ee0af-bd24-4457-b96f-c1e33e979acb.webp', 'وخزة إصبع تكشف مخاطر مرض الزهايمر مبكراً', 'وخزة إصبع تكشف مخاطر مرض الزهايمر مبكراً', 'كبسولة الصحية &#8211;  إم إس إن هيلث بدأت تجربة سريرية دولية تشمل ألف متطوع في المملكة المتحدة وأمريكا وكندا لاختبار فحص دم بسيط يعتمد على &#8220;وخزة إصبع&#822', '{الزهايمر,"فحص دم"}', false, 'published', NULL, NULL, '2026-01-24 01:14:54', '2026-01-24 16:23:14.419355', '2026-01-24 16:23:14.419355');
INSERT INTO public.news VALUES ('b641a064-3d90-43d9-a0aa-e6dc95d55efc', '3cd5209', 'كيف يوقف الجسم معارك الالتهاب داخلياً؟', NULL, 'لندن – كبسولة الصحية كشف باحثون في جامعة كوليدج لندن عن وجود &#8220;مكبح جزيئي&#8221; طبيعي داخل جسم الإنسان يساعد على إيقاف الالتهاب ومنع تحوله إلى مرض مزمن. تعتمد هذه الآلية على جزيئات دهنية تسمى &#8220;إيبوكسي-أوكسيليبينات&#8221; تعمل كعوامل مهدئة لجهاز المناعة، حيث توجهه للتوقف عن الهجوم والبدء ', '<p>لندن – كبسولة الصحية</p>
<p>كشف باحثون في جامعة كوليدج لندن عن وجود &#8220;مكبح جزيئي&#8221; طبيعي داخل جسم الإنسان يساعد على إيقاف الالتهاب ومنع تحوله إلى مرض مزمن.</p>
<p>تعتمد هذه الآلية على جزيئات دهنية تسمى &#8220;إيبوكسي-أوكسيليبينات&#8221; تعمل كعوامل مهدئة لجهاز المناعة، حيث توجهه للتوقف عن الهجوم والبدء في مرحلة الشفاء بعد القضاء على الميكروبات، مما يمنع تضرر الأنسجة السليمة.</p>
<p>يعد الالتهاب رد فعل طبيعي للحماية، لكن استمراره دون توقف يؤدي إلى تدمير أعضاء الجسم وظهور الأمراض المزمنة. تكمن أهمية هذا الاكتشاف في تحديد إنزيم معين يتحكم في هذه الجزيئات المهدئة، وقد نجح العلماء في تجربة دواء يزيد من مستويات هذه الدهون الواقية لدى البشر، مما أثبت قدرة الجسم على استعادة توازنه المناعي ذاتياً دون إضعاف الدفاعات الكلية للجسم.</p>
<p>يفتح هذا المسار الطبيعي الباب أمام جيل جديد من العلاجات التي تعيد توازن الجهاز المناعي بدلاً من تثبيطه بالكامل. ويركز العلماء حالياً على تطوير أدوية تستهدف هذا &#8220;المفتاح الجزيئي&#8221; لتهدئة الالتهابات بسرعة أكبر، وهو ما قد يشكل حلاً فعالاً للمصابين بأمراض الالتهابات المزمنة التي لا تستجيب للعلاجات التقليدية، مع الحفاظ على قدرة الجسم الفطرية على مواجهة العدوى اليومية.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/7c625b2b-fba8-4840-bd75-5a084ecfe6a3.webp', 'كيف يوقف الجسم معارك الالتهاب داخلياً؟', 'كيف يوقف الجسم معارك الالتهاب داخلياً؟', 'لندن – كبسولة الصحية كشف باحثون في جامعة كوليدج لندن عن وجود &#8220;مكبح جزيئي&#8221; طبيعي داخل جسم الإنسان يساعد على إيقاف الالتهاب ومنع تحوله إلى مرض مزمن. ت', '{"إيقاف الالتهاب","الجهاز المناعي"}', false, 'published', NULL, NULL, '2026-01-24 01:12:46', '2026-01-24 16:23:14.72967', '2026-01-24 16:23:14.72967');
INSERT INTO public.news VALUES ('9cb5f05d-239a-41f0-b407-95ce8c5fa907', 'd9f09de', 'كيف تخدع دماغك للعودة إلى النوم؟', NULL, 'متابعة – كبسولة الصحية كشف عالم الأعصاب أندرو هوبرمان عن تقنية فيزيولوجية تعتمد على &#8220;حركة العين والتنفس&#8221; لإنهاء حالة الأرق الليلي. تعتمد الطريقة على تحريك العينين ببطء خلف الجفون مع إطالة الزفير، وهي إشارة بيولوجية تجبر الجهاز العصبي على إيقاف استجابة التوتر، مما يسهل العودة إلى النوم سر', '<p>متابعة – كبسولة الصحية</p>
<p>كشف عالم الأعصاب أندرو هوبرمان عن تقنية فيزيولوجية تعتمد على &#8220;حركة العين والتنفس&#8221; لإنهاء حالة الأرق الليلي. تعتمد الطريقة على تحريك العينين ببطء خلف الجفون مع إطالة الزفير، وهي إشارة بيولوجية تجبر الجهاز العصبي على إيقاف استجابة التوتر، مما يسهل العودة إلى النوم سريعاً بعد الاستيقاظ في الثالثة صباحاً.</p>
<p>الاستيقاظ في منتصف الليل يحول هدوء الغرفة إلى ساحة للقلق الذهني، حيث يرتفع هرمون التوتر بمجرد التفكير في ساعات النوم الضائعة. أهمية تقنية هوبرمان أنها لا تتطلب مجهوداً ذهنياً، بل تستهدف الوظائف الحيوية للجسم مباشرة، مما يجعل الدماغ ينتقل من حالة &#8220;التأهب&#8221; إلى حالة &#8220;الأمان&#8221; والنعاس في دقائق معدودة.</p>
<p>ينصح الخبراء بتجنب مقاومة الأرق بالجهد الذهني، وبدلاً من ذلك، البدء فوراً في ممارسة &#8220;الزفير الطويل&#8221; مع تحريك العينين يميناً ويساراً بهدوء. هذه الطريقة توفر حلًا طبيعيًا ومجانيًا لمن يعانون من تقطع النوم، ومن المتوقع أن تنتشر كبديل فعال للوسائل التقليدية كونها تعتمد على استجابات فطرية مسجلة في الدماغ البشري.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/09e367b9-1c8b-4d05-9666-d202e046abd2.webp', 'كيف تخدع دماغك للعودة إلى النوم؟', 'كيف تخدع دماغك للعودة إلى النوم؟', 'متابعة – كبسولة الصحية كشف عالم الأعصاب أندرو هوبرمان عن تقنية فيزيولوجية تعتمد على &#8220;حركة العين والتنفس&#8221; لإنهاء حالة الأرق الليلي. تعتمد الطريقة على', '{التنفس,اليقظة,"حركة العين"}', false, 'published', NULL, NULL, '2026-01-24 01:08:46', '2026-01-24 16:23:15.049681', '2026-01-24 16:23:15.049681');
INSERT INTO public.news VALUES ('0bd76104-619d-4c92-9082-e6972727fa43', 'd0cd6c2', 'نصيحة طبية لنوم أفضل .. هذه مخاطر القيلولة', NULL, 'لندن – كبسولة الصحية كشف خبراء النوم في تقرير نشرته صحيفة &#8220;تليغراف&#8221; أن الاستغراق في النوم خلال أقل من 5 دقائق ليس دائماً علامة جودة، بل قد يكون مؤشراً على &#8220;الحرمان الشديد من النوم&#8221; أو النعاس المفرط. وبحسب التقرير الذي نشره موقع &#8220;24&#8221;، فإن الشخص السليم يحتاج في المت', '<p>لندن – كبسولة الصحية</p>
<p>كشف خبراء النوم في تقرير نشرته صحيفة &#8220;تليغراف&#8221; أن الاستغراق في النوم خلال أقل من 5 دقائق ليس دائماً علامة جودة، بل قد يكون مؤشراً على &#8220;الحرمان الشديد من النوم&#8221; أو النعاس المفرط. وبحسب التقرير الذي نشره موقع &#8220;24&#8221;، فإن الشخص السليم يحتاج في المتوسط من 15 إلى 20 دقيقة ليدخل في النوم. هذا التوضيح يغير النظرة السائدة التي تعتبر النوم السريع جداً &#8220;موهبة&#8221;، مؤكداً أن الاستعداد الوراثي وانخفاض التوتر يساعدان، لكن السرعة المفرطة تعني أن جسدك &#8220;منهك&#8221; لدرجة خطيرة.</p>
<p>تكمن الأهمية في فهم &#8220;ساعة الجسد&#8221;؛ فبينما تقترب دول مثل فرنسا من متوسط 8 ساعات نوم، تعاني دول آسيوية من انخفاض هذا المتوسط إلى 6 ساعات أو أقل ؛ فالحصول على ضوء الصباح الطبيعي، وتجنب القيلولة بعد الرابعة مساءً، والابتعاد عن الرياضة العنيفة قبل النوم بساعتين، كلها عوامل تضمن الدخول في &#8220;نوم عميق&#8221; وليس مجرد &#8220;إغماءة&#8221; ناتجة عن التعب.</p>
<p>لتحقيق توازن صحي في النوم، ينصح الخبراء بضبط حرارة الغرفة عند 18 درجة مئوية والالتزام بروتين ثابت للاستيقاظ والنوم، وهذا يتطلب منا في المجتمع المحلي إعادة النظر في &#8220;ثقافة السهر&#8221; والاعتماد على المنبهات؛ فالحل ليس في إجبار الجسد على النوم السريع، بل في تهيئة البيئة المناسبة من فراش مريح وتقنيات تنفس بسيطة لمدة دقائق قبل النوم. تذكر أن سرعة نومك قد تكون &#8220;صرخة استغاثة&#8221; من قلبك وجهازك العصبي الذي لم يأخذ كفايته من الراحة طوال الأسبوع.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/aa416ca5-ae36-48b7-a597-89b9a13b60c0.webp', 'نصيحة طبية لنوم أفضل .. هذه مخاطر القيلولة', 'نصيحة طبية لنوم أفضل .. هذه مخاطر القيلولة', 'لندن – كبسولة الصحية كشف خبراء النوم في تقرير نشرته صحيفة &#8220;تليغراف&#8221; أن الاستغراق في النوم خلال أقل من 5 دقائق ليس دائماً علامة جودة، بل قد يكون مؤشر', '{"الصحة النفسية","النوم الهادئ","سر القيلولة"}', false, 'published', NULL, NULL, '2026-01-24 01:05:13', '2026-01-24 16:23:15.373825', '2026-01-24 16:23:15.373825');
INSERT INTO public.news VALUES ('0576945d-1f6e-46af-95d7-a34b9f59bce1', NULL, 'Eating Nuts May Help Reduce Food Cravings, Promote Weight Management', NULL, NULL, 'Young adults with a higher risk of metabolic syndrome may benefit from eating nuts, researchers say. fcafotodigital/Getty Images A new study suggests that swapping high carb snacks for nuts can help curb sweet cravings. Participants at risk for metabolic syndrome who made the switch also tended to increase their protein intake. Nuts are high in satiating nutrients like healthy fats, protein, and fiber. If you&#8217;re allergic to tree nuts, seeds can make a good substitute. Swapping your usual between-meal snacks for a handful of mixed tree nuts could help cut cravings for sweets and fast food and improve the overall quality of your diet. That&#8217;s according to a new study published on December 2 in Nutrients. Researchers found that young adults at higher risk for metabolic syndrome who snacked on nuts daily for 16 weeks reported fewer urges for sugary and salty treats, ate more protein-rich foods, and scored better on a measure of diet quality. Here&#8217;s what you need to know about the metabolic health benefits of nut consumption. Nuts vs. high carb snacks The research team at Vanderbilt University Medical Center recruited 84 males and females between the ages of 22 and 36. All participants had at least one risk factor for metabolic syndrome — a cluster of conditions, such as high blood pressure, excess belly fat, and abnormal cholesterol levels, that raise the risk for heart disease and diabetes. To qualify, participants had to have maintained a stable weight for at least three months and fall within a specific body mass index (BMI) range. Those with nut allergies, chronic diseases like diabetes, or certain lifestyle factors such as smoking were excluded. Before the main part of the trial began, everyone went through a two-week “run-in” period, eating a balanced diet that included typical high-carbohydrate snacks but no nuts. After that, participants were randomly assigned to one of two groups: Tree nuts snack group: Ate a 33.5-gram mix of unsalted raw almonds, walnuts, pecans, macadamia nuts, hazelnuts, pistachios, and cashews twice a day. High-carbohydrate snack group: Ate snacks such as pretzels, animal crackers, graham crackers, or granola bars twice a day. Both snack types were similar in calories, protein, fiber, and sodium, and were eaten between 6:00 a.m. and 6:00 p.m. Participants met with registered dietitians every two weeks to receive counseling and their pre-portioned snacks. The study lasted 16 weeks, during which researchers measured food cravings, daily food intake, and overall diet quality at both the start and end. They also collected blood samples to look at hormones related to appetite. Nuts led to fewer sweet cravings, higher protein intake By the end of the study, the nut-snacking group showed notable changes in their eating habits and cravings. Participants who ate tree nuts reported: Less craving for sweets and fast food: Ratings for cravings dropped for items like cookies, brownies, donuts, candy, ice cream, chips, and pizza. For example, cravings for brownies fell by nearly half a point on a five-point scale, and cravings for cookies dropped by more than 0.6 points. Reduced preference for sweet taste: About 12.5% fewer people in the nut group said they preferred sweet flavors compared to at the start of the study. Eating fewer sugary and salty snacks: The frequency of eating frozen desserts and salty snacks went down. Eating more protein-rich foods: On average, they increased their daily servings of protein foods, especially from seafood and plant-based sources, by more than four servings. These changes were linked to shifts in certain appetite-related hormones. In the nut group, levels of GLP-1 — a hormone that can help regulate appetite — increased, and this rise was associated with reduced cravings for cakes, brownies, candy, and ice cream. Furthermore, the nut group’s overall score on the Healthy Eating Index (HEI), which measures how well a person’s diet aligns with national dietary guidelines, improved by 19%. This bump reflected a higher intake of healthy unsaturated fats and protein-rich foods, as well as a lower intake of sodium and refined grains. In contrast, the high-carbohydrate snack group did not see significant changes in food cravings or diet quality. In fact, they showed a small decrease in fruit consumption, an increase in daily calorie intake of approximately 350 calories, and an average weight gain of roughly 0.8 kilograms (about 1.8 pounds) over the 16-week period. The nut group, on the other hand, did not gain weight, even though they were eating calorie-dense snacks. While they ate about 468 grams less total food by weight each day, their overall calorie intake stayed about the same. Hunger and fullness ratings did not change significantly in the nut group, suggesting they felt just as satisfied as before. The findings suggest that replacing typical snack foods with a modest portion of mixed tree nuts may help young adults at risk for metabolic syndrome steer away from less healthy foods and make choices that improve the overall quality of their diets, without unwanted weight gain. How nuts help reduce cravings for sweets Kezia Joy, a registered dietitian and medical advisor with Welzo, noted that replacing higher-carbohydrate snack foods with nuts can help reduce cravings due to the balanced nutrients within nuts. Joy wasn&#8217;t involved in the new study. They contain a high amount of fat, protein, and fiber. &#8220;The slow digestion of these nutrients creates steady blood sugar and enhances feelings of being satisfied for longer periods,&#8221; she told Healthline. Joy additionally noted that eating nuts helps regulate blood sugar. &#8220;Steady blood sugars are associated with fewer or no fluctuations in blood glucose (spikes [and] drops), and the less frequent the spikes and dips, the less likely your body is to send signals of &#8216;urgent&#8217; need for energy via hunger/cravings,&#8221; she said. Joy concluded by saying that chewing nuts also requires more time and effort relative to other foods. &#8220;[T]his additional time, along with providing a greater feeling of fullness, contributes to enhanced satisfaction post-meal and supports better long-term appetite regulation,&#8221; she said. Guidelines for healthy nut consumption Jacqueline A. Vernarelli, associate professor of Public Health and Director of Research Education and Consultation, College of Health Professions, Sacred Heart University, suggested aiming for about a quarter cup of nuts. &#8220;Mix it up, literally and figuratively,&#8221; said Vernarelli, who wasn&#8217;t involved in the new study. Vernarelli told Healthline that there are a variety of nuts — including almonds, cashews, walnuts, Brazil nuts, and macadamia nuts — that make a great high protein, satiating snack. &#8220;Be sure to choose whole, raw or dry-roasted varieties,&#8221; she said, &#8220;and choose unsalted nuts when possible, as salted or flavored varieties are typically high in sodium.&#8221; Allergic to tree nuts? &#8220;Seeds are a great protein-packed option,&#8221; said Vernarelli, &#8220;especially sunflower and pumpkin seeds.&#8221; They also contain healthy fats and fiber. According to Joy, other alternatives to tree nuts include roasted legumes, such as roasted chickpeas and roasted edamame. &#8220;Other balanced options that will help you feel full and aid your metabolism without the risk of an allergic reaction [from nuts] are Greek yogurt, hummus with vegetables, and whole grain foods eaten with a spread made from seeds,&#8221; she said.', 'health-news', NULL, 'https://www.healthline.com/health-news/nuts-reduce-cravings-promote-weight-management', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/pouring-nuts-hand-1296x728-header.jpg', NULL, NULL, NULL, NULL, false, 'deleted', NULL, '2026-01-25 08:22:14.942', '2026-01-25 08:21:44.223809', '2026-01-25 08:21:44.223809', '2026-01-25 08:21:44.223809');
INSERT INTO public.news VALUES ('a264b2d3-5258-414a-a70d-c074a023288b', 'c1fb02c', 'سباق مع الزمن في سقطرى.. إنقاذ يمني سبعيني من الموت', NULL, 'الرياض- كبسولة الصحية في ملحمة إنسانية عكست الجاهزية العالية للمملكة، نجح البرنامج السعودي لتنمية وإعمار اليمن في إنقاذ حياة مسن يمني بمستشفى سقطرى، إثر تعرضه لحادث دهس أدى لنزيف حاد في الدماغ. وبحسب ما أوردته صحيفة &#8220;الرياض&#8221;، فقد تمت الاستجابة للبلاغ في زمن قياسي لم يتجاوز 12 ساعة، رغم ت', '<p>الرياض- كبسولة الصحية</p>
<p>في ملحمة إنسانية عكست الجاهزية العالية للمملكة، نجح البرنامج السعودي لتنمية وإعمار اليمن في إنقاذ حياة مسن يمني بمستشفى سقطرى، إثر تعرضه لحادث دهس أدى لنزيف حاد في الدماغ.</p>
<p>وبحسب ما أوردته صحيفة &#8220;الرياض&#8221;، فقد تمت الاستجابة للبلاغ في زمن قياسي لم يتجاوز 12 ساعة، رغم تعقيدات الحالة وصعوبة النقل الجوي للمصاب.</p>
<p>وتجسدت كفاءة التنسيق السعودي في رحلة &#8220;تأمين الاستشاري&#8221;؛ حيث نُقل طبيب مخ وأعصاب برًا من المكلا إلى المهرة، ثم جوًا إلى سقطرى لتعويض النقص التخصصي في المحافظة. وتزامنت هذه الرحلة مع جسر إمداد عاجل نقل المستلزمات الطبية والأدوية من عدن إلى سقطرى مباشرة، لتبدأ العملية الجراحية فور وصول الفريق والمعدات.</p>
<p>ويأتي نجاح العملية واستقرار حالة المريض ليؤكد الأثر المباشر للدعم السعودي في إنقاذ الأرواح بالمناطق النائية، متجاوزاً التحديات اللوجستية والجغرافية. وتبرز هذه الواقعة الدور الاستراتيجي للبرنامج في تشغيل المنشآت الصحية الحيوية وتحويلها إلى مراكز قادرة على التعامل مع الحالات الحرجة في أصعب الظروف.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/46dc2b4c-019b-418b-93a4-b8fa12ccdd63.jpg', 'سباق مع الزمن في سقطرى.. إنقاذ يمني سبعيني من الموت', 'سباق مع الزمن في سقطرى.. إنقاذ يمني سبعيني من الموت', 'الرياض- كبسولة الصحية في ملحمة إنسانية عكست الجاهزية العالية للمملكة، نجح البرنامج السعودي لتنمية وإعمار اليمن في إنقاذ حياة مسن يمني بمستشفى سقطرى، إثر تعرضه ل', '{"إنقاذ يمني سبعيني",المملكة}', false, 'published', NULL, NULL, '2026-01-23 22:51:48', '2026-01-24 16:23:15.723422', '2026-01-24 16:23:15.723422');
INSERT INTO public.news VALUES ('c032e617-4fee-4bda-b278-ce889ebacec1', '118e447', 'بصمة ملكية في سجلات الطب العالمي.. "تقنية الحربي" اختراع  سعودي ينهي آلام جراحات الورك', NULL, 'الرياض- كبسولة الصحية حقق فريق بحثي مشترك من الشؤون الصحية بوزارة الحرس الوطني، وجامعة الملك سعود بن عبدالعزيز للعلوم الصحية، ومركز &#8220;كيمار&#8221; إنجازاً علمياً نوعياً، حيث حصل الفريق على براءة اختراع من مكتب براءات الاختراع والعلامات التجارية الأمريكي (USPTO  )   عن ابتكار طبي متقدم حمل اسم “', '<p>الرياض- كبسولة الصحية</p>
<p>حقق فريق بحثي مشترك من الشؤون الصحية بوزارة الحرس الوطني، وجامعة الملك سعود بن عبدالعزيز للعلوم الصحية، ومركز &#8220;كيمار&#8221; إنجازاً علمياً نوعياً، حيث حصل الفريق على براءة اختراع من مكتب براءات الاختراع والعلامات التجارية الأمريكي (USPTO  )   عن ابتكار طبي متقدم حمل اسم “Harbi Technique”. .</p>
<p>ويمثل هذا الابتكار نقلة نوعية في التخدير الجزئي لعمليات الورك، إذ يعتمد على توجيه التخدير مباشرة للأعصاب الحسية المسؤولة عن الألم من خلال نقطة حقن واحدة باستخدام الأشعة فوق الصوتية.</p>
<p>&nbsp;</p>
<p><img loading="lazy" decoding="async" class="alignnone size-medium wp-image-24292" src="https://capsulah.com/wp-content/uploads/2026/01/q44-258x300.jpg" alt="" width="258" height="300" title="" srcset="https://capsulah.com/wp-content/uploads/2026/01/q44-258x300.jpg 258w, https://capsulah.com/wp-content/uploads/2026/01/q44.jpg 584w" sizes="auto, (max-width: 258px) 100vw, 258px" /></p>
<p>تثبيت معايير الأمان والتعافي</p>
<p>تكمن أهمية &#8220;تقنية الحربي&#8221; في قدرتها الفريدة على تغطية جميع الأعصاب المرتبطة بآلام الورك مع الحفاظ الكامل على الوظائف الحركية للمريض. هذا الأسلوب المبتكر يسهم في تقليل مضاعفات التخدير الكامل ويعزز سرعة التعافي، محققاً أعلى درجات الدقة والأمان في العمليات الجراحية المعقدة.</p>
<p>مستقبل الجراحة والتعافي السريع</p>
<p>يفتح هذا الاختراع الباب لتمكين المرضى من المشي والحركة خلال وقت قياسي بعد الجراحة. وبحصوله على هذا الاعتراف الدولي، تترسخ مكانة المؤسسات البحثية السعودية كمرجع عالمي في ابتكار الحلول الطبية التي تخدم البشرية وتسهل رحلة علاج المرضى.</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/3a793fc8-96bb-46c5-8364-7ac66300856d.jpg', 'بصمة ملكية في سجلات الطب العالمي.. &#8220;تقنية الحربي&#8221; اختراع  سعودي ينهي آلام جراحات الورك', 'بصمة ملكية في سجلات الطب العالمي.. &#8220;تقنية الحربي&#8221; اختراع  سعودي ينهي آلام جراحات الورك', 'الرياض- كبسولة الصحية حقق فريق بحثي مشترك من الشؤون الصحية بوزارة الحرس الوطني، وجامعة الملك سعود بن عبدالعزيز للعلوم الصحية، ومركز &#8220;كيمار&#8221; إنجازاً ', '{"اختراع سعودي","تقنية الحربي"}', false, 'published', NULL, NULL, '2026-01-23 09:40:12', '2026-01-24 16:23:16.74345', '2026-01-24 16:23:16.74345');
INSERT INTO public.news VALUES ('bf76556f-f189-40b5-b714-4cd1b218c5b9', 'b259a0b', 'كيف يحمي فحص "مسحة الرحم" النساء من خطر السرطان؟', NULL, 'متابعة – كبسولة الصحية أكدت استشارية طب النساء والولادة، الدكتورة مها النمر، أن الكشف المبكر عن سرطان عنق الرحم يعتمد بشكل أساسي على إجراء &#8220;مسحة پاپ&#8221; (Pap Smear) بانتظام. ووفقاً لما نشرته النمر عبر حسابها الرسمي، فإن هذا الفحص يتيح اكتشاف الخلايا المتغيرة قبل تحولها إلى أورام سرطانية، مم', '<p>متابعة – كبسولة الصحية</p>
<p>أكدت استشارية طب النساء والولادة، الدكتورة مها النمر، أن الكشف المبكر عن سرطان عنق الرحم يعتمد بشكل أساسي على إجراء &#8220;مسحة پاپ&#8221; (Pap Smear) بانتظام. ووفقاً لما نشرته النمر عبر حسابها الرسمي، فإن هذا الفحص يتيح اكتشاف الخلايا المتغيرة قبل تحولها إلى أورام سرطانية، مما يرفع نسب نجاح العلاج بشكل كبير ويوقف تطور المرض الناتـج عن الفيروس الحليمي البشري (HPV).</p>
<p>تكمن أهمية الفحص الدوري في كونه الوسيلة الوحيدة لاكتشاف نشاط الفيروس الحليمي الصامت قبل فوات الأوان. وتوضح الدكتورة النمر أن الوقاية تتطلب مسارين؛ الأول هو التطعيم ضد الفيروس قبل الزواج، والثاني هو الالتزام بجدول الفحص الذي يتم كل 3 سنوات في الحالات العادية، أو كل 5 سنوات في حال إجراء فحص إضافي لنوع الفيروس الجيني (HPV genotype)، وذلك لضمان المراقبة الدقيقة لسلامة الأنسجة.</p>
<p>ينصح الخبراء النساء بضرورة التوجه لطبيبة النساء فور انتهاء الدورة الشهرية لإجراء المسحة كإجراء روتيني وقائي. ويساهم الالتزام بهذه المواعيد الدورية في خلق بيئة صحية آمنة، حيث يتوقع أن تنخفض معدلات الإصابة بسرطان عنق الرحم بشكل حاد في حال تبني ثقافة &#8220;الفحص الوقائي&#8221; كبديل لانتظار ظهور الأعراض المتأخرة، مع التأكيد على أن التطعيم المبكر يمثل خط الدفاع الأول للفتيات.</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/e0f01ba3-5eae-4502-bbd9-fc74a6170729.webp', 'كيف يحمي فحص &#8220;مسحة الرحم&#8221; النساء من خطر السرطان؟', 'كيف يحمي فحص &#8220;مسحة الرحم&#8221; النساء من خطر السرطان؟', 'متابعة – كبسولة الصحية أكدت استشارية طب النساء والولادة، الدكتورة مها النمر، أن الكشف المبكر عن سرطان عنق الرحم يعتمد بشكل أساسي على إجراء &#8220;مسحة پاپ&#8221', '{السرطان,النساء,"مسحة الرحم"}', false, 'published', NULL, NULL, '2026-01-23 03:27:14', '2026-01-24 16:23:17.134812', '2026-01-24 16:23:17.134812');
INSERT INTO public.news VALUES ('118311c8-3b4e-418c-97f2-09b4cfc37479', '4e500c4', 'الجرب يغزو المملكة المتحدة بمعدلات قياسية', NULL, 'كبسولة الصحية &#8211;  ذا ميرور سجلت المملكة المتحدة طفرة مقلقة في إصابات &#8220;الجرب&#8221; الجلدي، حيث رصدت الأجهزة الطبية نحو 900 حالة خلال أسبوع واحد، بزيادة قدرها 20% عن العام الماضي. وحذر خبراء الكلية الملكية للأطباء من أن هذا المرض، الذي تسببه حشرة &#8220;العث&#8221;، شديد العدوى وينتقل عبر ', '<p>كبسولة الصحية &#8211;  ذا ميرور</p>
<p>سجلت المملكة المتحدة طفرة مقلقة في إصابات &#8220;الجرب&#8221; الجلدي، حيث رصدت الأجهزة الطبية نحو 900 حالة خلال أسبوع واحد، بزيادة قدرها 20% عن العام الماضي. وحذر خبراء الكلية الملكية للأطباء من أن هذا المرض، الذي تسببه حشرة &#8220;العث&#8221;، شديد العدوى وينتقل عبر التلامس الجلدي المباشر، مما يضع عائلات بأكملها تحت التهديد، خاصة وأن الأعراض المتمثلة في الحكة الشديدة قد تتأخر في الظهور لمدة تصل إلى شهرين.</p>
<p>تكمن خطورة هذا الانتشار في قدرة الطفيليات وبيضها على البقاء حية داخل الأقمشة والمناشف والأسرة، مما يسهل عملية انتقال العدوى بشكل صامت. وبالرغم من أن المرض ليس قاتلاً، إلا أن عودته بهذه الكثافة تعيد للأذهان ظروف العصر الفيكتوري، وتفرض ضغطاً على المنظومة الصحية، خاصة مع ظهور نوع نادر ومقاوم يسمى &#8220;الجرب المتقشر&#8221; الذي يصيب ذوي المناعة الضعيفة ويتطلب بروتوكولات علاجية خاصة.</p>
<p>تتطلب السيطرة على هذا &#8220;الغزو الجلدي&#8221; علاج جميع أفراد الأسرة المصابة في وقت واحد لضمان عدم تكرار العدوى، مع استخدام كريمات طبية تكرر بعد سبعة أيام. كما تشدد التوصيات البريطانية على ضرورة غسل المنسوجات عند درجة حرارة 60 مئوية، مع التنبيه على أن الأطفال دون سن الثانية يحتاجون لمتابعة طبية دقيقة، لضمان القضاء التام على العث داخل المنازل ومنع تحوله إلى وباء.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/3fe85a7a-d253-4cea-bc98-cc94667d1d1a.png', 'الجرب يغزو المملكة المتحدة بمعدلات قياسية', 'الجرب يغزو المملكة المتحدة بمعدلات قياسية', 'كبسولة الصحية &#8211;  ذا ميرور سجلت المملكة المتحدة طفرة مقلقة في إصابات &#8220;الجرب&#8221; الجلدي، حيث رصدت الأجهزة الطبية نحو 900 حالة خلال أسبوع واحد، بزيا', '{الجرب,بريطانيا}', false, 'published', NULL, NULL, '2026-01-23 03:24:38', '2026-01-24 16:23:17.558453', '2026-01-24 16:23:17.558453');
INSERT INTO public.news VALUES ('f1fdfe6b-e21c-488d-b874-b8ef52cd4d7b', NULL, 'حمية «بورتفوليو»: النظام الغذائي النباتي الذي يطيل عمر القلب', 'انخفاض الوفاة بأمراض القلب حتى 18% مع هذه الحمية', 'حمية "بورتفوليو" النباتية تقلل مخاطر أمراض القلب بنسبة 18% وتؤخر الأحداث القلبية الوعائية 13 عاماً وفق دراسات حديثة. تعتمد الحمية على عناصر غذائية مخفضة للكوليسترول تم تصميمها عام 2003.', 'أظهرت دراسات حديثة أن الالتزام بحمية «بورتفوليو» النباتية يرتبط بانخفاض خطر الوفاة بسبب أمراض القلب بنسبة تصل إلى 18%، ويعزو الباحثون ذلك إلى «تأثير تراكمي» ناتج عن دمج أربع فئات غذائية مخفضة للكوليسترول. كما تشير النتائج إلى أن البدء بهذه الحمية في سن مبكرة قد يؤخر حدوث الأحداث القلبية الوعائية لمدة قد تصل إلى 13 عاماً، وأن حتى الالتزام المعتدل يحقق فوائد واضحة.

ورغم شهرة حميتي البحر المتوسط و«داش» بفوائد قلبية مثبتة، تبرز «بورتفوليو» كنمط أقل شهرة لكنه واعد. صُممت الحمية عام 2003 على يد البروفيسور ديفيد جنكينز في جامعة تورنتو، وتعتمد على استبدال أطعمة مألوفة بمكونات من «محفظة» غذائية مخفضة للكوليسترول ضمن أربع مجموعات رئيسية:
- بروتينات الصويا/البروتينات النباتية التي تزاحم الدهون المشبعة.
- الستيرولات النباتية التي تُعطل امتصاص الكوليسترول.
- المكسرات الغنية بالدهون غير المشبعة المفيدة للقلب.
- الألياف الذائبة التي ترتبط بالأحماض الصفراوية والكوليسترول وتساعد على طرحهما.

يؤكد اختصاصيو التغذية القلبية أن الجمع بين هذه العناصر يعظم خفض كوليسترول LDL «الضار»، مع ضرورة تجنب الأطعمة فائقة المعالجة والمضافات السكرية ضمن أي نمط غذائي يهدف لصحة القلب.

وعلى صعيد الآثار طويلة المدى، أظهر بحث مُحكّم نُشر عام 2023 في دورية «سيركيوليشن» التابعة لجمعية القلب الأمريكية أن الحمية قد تقلل مخاطر الأمراض القلبية الوعائية، بما فيها السكتة الدماغية ومرض القلب التاجي. كما أفاد باحثو كلية «تيمرتي» للطب بجامعة تورنتو بأن هذه هي المرة الأولى التي تُربط فيها «بورتفوليو» بانخفاض وفيات أمراض القلب والوفيات لجميع الأسباب.

وفي دراسة نُشرت في «بي إم سي ميديسن» في مايو/أيار 2025، جُمعت بيانات قرابة 15 ألف مشارك من أمريكيين متنوعين عرقياً على مدى عقدين. سجّل المشاركون استهلاكهم اليومي، ونالوا نقاطاً إيجابية لأطعمة من «بورتفوليو» وسلبية لأطعمة غنية بالدهون المشبعة والكوليسترول. أظهرت النتائج أن الالتزام المتوسط بالحمية خفّض خطر الوفاة من أمراض القلب والأوعية الدموية بنسبة 12%، ومن مرض القلب التاجي بنسبة 14%، وخفّض الوفيات العامة بنسبة 12%. ومع ارتفاع درجة الالتزام، زادت الفوائد إلى انخفاض بنسبة 16% و18% في وفيات الأمراض القلبية الوعائية ومرض القلب التاجي على التوالي، وانخفضت الوفيات العامة بنسبة 14%.

يشير الخبراء إلى أن إضافات صغيرة ومتسقة—مثل حفنة مكسرات يومية أو حصة من البقول—قد تمنح نتائج ملموسة حتى مع التزام معتدل بالحمية، فيما يمنح البدء المبكر فرصة أكبر لتأخير الأحداث القلبية الوعائية لسنوات.', 'nutrition', NULL, 'https://www.healthline.com/health-news/portfolio-diet-improve-heart-health-lower-cholesterol', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Portfolio-Diet-Stocksy_txp395ca629ewC400_Medium_1764645-Header.jpg', NULL, 'حمية «بورتفوليو» تقلل مخاطر أمراض القلب', 'اكتشف حمية "بورتفوليو" النباتية التي تقلل خطر الوفاة بأمراض القلب بنسبة تصل إلى 18% عبر عناصر مخفضة للكوليسترول.', '{"حمية بورتفوليو","أمراض القلب",كوليسترول,"نظام غذائي نباتي","فوائد صحية","مخاطر أمراض القلب","خفض الوفيات"}', false, 'published', NULL, NULL, '2026-01-25 08:24:00.137401', '2026-01-25 08:24:00.137401', '2026-01-25 08:24:00.137401');
INSERT INTO public.news VALUES ('87c49137-600d-4096-96f5-afebcef65243', '9816dc2', 'تشققات الشفاه المستمرة قد تشير إلى عدوى فطرية', NULL, 'كبسولة الصحية &#8211; وكالات كم عدد عبوات مرطب الشفاه التي استهلكتها خلال عام 2025؟ إذا كانت إجابتك &#8220;كثيرة جداً&#8221; ومع ذلك لا تزال شفاهك تعاني من الجفاف والتشقق المزمن، فربما حان الوقت للتوقف عن شراء المزيد من المرطبات والبحث عن السبب الحقيقي خلف هذه المشكلة. كشفت منشئة المحتوى الشهيرة Pum', '<p>كبسولة الصحية &#8211; وكالات</p>
<p>كم عدد عبوات مرطب الشفاه التي استهلكتها خلال عام 2025؟ إذا كانت إجابتك &#8220;كثيرة جداً&#8221; ومع ذلك لا تزال شفاهك تعاني من الجفاف والتشقق المزمن، فربما حان الوقت للتوقف عن شراء المزيد من المرطبات والبحث عن السبب الحقيقي خلف هذه المشكلة.</p>
<p>كشفت منشئة المحتوى الشهيرة Pumpkin Head عن جانب خفي لمشاكل الشفاه، عبر رسالة تلقتها من أخصائية تنظيف الأسنان، التي لاحظت تشقق شفاه بامبكن المزمن.</p>
<p>ولم تكن الرسالة انتقاداً، بل تحذيراً من نوع من الفطريات التي قد تنمو في زوايا الفم، مع نصيحة غريبة: &#8220;جربي كريم مضاد للفطريات&#8221;.</p>
<p>بعد محاولات مضنية وفاشلة مع أغلى أنواع المرطبات، قررت &#8220;بامبكن&#8221; اتباع النصيحة الجريئة، واستخدمت كريم علاج &#8220;قدم الرياضيين&#8221; (المضاد للفطريات). والنتيجة؟ اختفاء تام للألم والتقشر الذي لازمها لأشهر. وبحسب موقع &#8220;مترو&#8221; فإن هذه التجربة سلطت الضوء على حالة طبية تُعرف بـ &#8220;التهاب زاوية الشفة&#8221;</p>
<p>هذا الالتهاب ليس مجرد جفاف عابر، بل قد يتفاقم بسبب عوامل عدة منها التدخين وتقويم الأسنان غير المناسب ونقص فيتامين ب.</p>
<p>رأي الطب:</p>
<p>رغم نجاح تجربة &#8220;بامبكن&#8221;، يضع الأطباء النقاط على الحروف لتجنب التشخيص الخاطئ. أوضح الدكتور كونال بيريت، استشاري الأمراض الجلدية في عيادة &#8220;ديفونشاير&#8221;، أن أغلب حالات تشقق الشفاه تعود لأسباب تقليدية مثل لعق الشفاه المتكرر، الحساسية، أو التعرض للشمس، وليست الفطريات هي السبب الأكثر شيوعاً كما توحي وسائل التواصل الاجتماعي.</p>
<p>يقول الدكتور بيريت: &#8220;وسائل التواصل جعلت العدوى الفطرية تبدو منتشرة أكثر من الواقع. علاج السبب الخاطئ بمنتجات غير مخصصة قد يؤدي إلى إطالة أمد المعاناة وزيادة التهيج&#8221;.</p>
<p>مشكلة فطرية</p>
<p>إذا كنت تشك في إصابتك بفطريات الشفاه، ابحث عن هذه الأعراض الإضافية:</p>
<p>بقع بيضاء داخل الفم</p>
<p>احمرار شديد في زوايا الشفاه</p>
<p>إحساس بالحرقان أو ألم عند فتح الفم</p>
<p>بدلاً من اللجوء للعلاجات المنزلية العشوائية، يقدم استشاري الجلدية خارطة طريق للتعافي:</p>
<p>استخدام مرطبات بسيطة مثل الفازلين الخالي من العطور</p>
<p>تجنب المنتجات المعطرة أو المنكهة لأنها تزيد التهيج</p>
<p>التوقف فوراً عن لعق، قضم، أو تقشير الجلد الجاف يدوياً</p>
<p>ضرورة استخدام واقي شمس (SPF) مخصص للشفاه للحماية من الرياح والشمس</p>
<p>الشفاه تحتاج إلى أسبوعين من الالتزام بالمرطبات اللطيفة لتبدأ بالتعافي</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/4db6a345-4043-4cc6-b087-068b9db920b6.webp', 'تشققات الشفاه المستمرة قد تشير إلى عدوى فطرية', 'تشققات الشفاه المستمرة قد تشير إلى عدوى فطرية', 'كبسولة الصحية &#8211; وكالات كم عدد عبوات مرطب الشفاه التي استهلكتها خلال عام 2025؟ إذا كانت إجابتك &#8220;كثيرة جداً&#8221; ومع ذلك لا تزال شفاهك تعاني من الجف', '{الفطريات,"تشققات الشفاة"}', false, 'published', NULL, NULL, '2026-01-20 01:43:24', '2026-01-24 16:23:30.086181', '2026-01-24 16:23:30.086181');
INSERT INTO public.news VALUES ('131ce361-1e4c-4772-a8be-c01a22fb0d6f', 'dceaa3f', '"طبية" جامعة الملك سعود تحصل على اعتماد "MAGNET" العالمي', NULL, 'كبسولة الصحية &#8211; واس حصلت المدينة الطبية الجامعية بجامعة الملك سعود على اعتماد &#8220;MAGNET&#8221; الأمريكي لمستشفياتها الثلاثة؛ مستشفى الملك عبدالعزيز الجامعي، ومستشفى الملك خالد الجامعي، ومستشفى طب الأسنان الجامعي، ويُعد هذا الاعتماد إحدى أرقى الشهادات العالمية في مجال التمريض والرعاية الصحي', '<p>كبسولة الصحية &#8211; واس</p>
<p>حصلت المدينة الطبية الجامعية بجامعة الملك سعود على اعتماد &#8220;MAGNET&#8221; الأمريكي لمستشفياتها الثلاثة؛ مستشفى الملك عبدالعزيز الجامعي، ومستشفى الملك خالد الجامعي، ومستشفى طب الأسنان الجامعي، ويُعد هذا الاعتماد إحدى أرقى الشهادات العالمية في مجال التمريض والرعاية الصحية، ويمنحه المركز الأمريكي لاعتماد الممرضين (ANCC) للمؤسسات التي تحقق أعلى معايير الجودة في الممارسات التمريضية وبيئة العمل الداعمة، جاء ذلك خلال حفل أقيم بهذه المناسبة بحضور رئيس جامعة الملك سعود المكلّف الدكتور علي بن محمد مسملي.</p>
<p>وأعرب المدير العام التنفيذي للمدينة الطبية الجامعية بالجامعة الدكتور أحمد بن صلاح هرسي، عن اعتزازه لما وصلت إليه الخدمات الصحية، والتدريب الطبي، والبحث العلمي في المدينة الطبية الجامعية من تميز جعلها منافسًا لكبرى المراكز الصحية العالمية، مؤكدًا أن اعتماد &#8220;MAGNET&#8221; يأتي تتويجًا لمسيرة مهنية طويلة من العمل الجماعي والتطوير المستمر في ممارسات التمريض والرعاية الصحية ما يعكس التزام المدينة الطبية الجامعية بتوفير بيئة عمل جاذبة ومحفّزة للكوادر التمريضية، وتقديم خدمات صحية مبنية على أفضل الممارسات العالمية، بما ينعكس إيجابًا على سلامة المرضى ونتائج الرعاية الصحية، ودعم الجهود الوطنية في تطوير القطاع الصحي بالمملكة.</p>
<p>من جانبه أوضح المدير العام لشؤون التمريض في المدينة الطبية الجامعية الدكتور يوسف الشملاني، أن برنامج &#8220;MAGNET&#8221; يمثل معيارًا عالميًا يعكس التميز في جودة الرعاية التمريضية، مشيرًا إلى أن حصول ثلاثة مستشفيات تحت مظلة المدينة الطبية الجامعية على هذا الاعتماد يُعد سابقة من نوعها؛ إذ تجري العادة أن يتم تقييم مستشفى واحد فقط من قبل المركز الأمريكي لاعتماد الممرضين، بينما تُقيّم المستشفيات الأخرى بشكل مستقل.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/04160863-0ad1-4bdb-8183-985fe09032fe.webp', '&#8220;طبية&#8221; جامعة الملك سعود تحصل على اعتماد &#8220;MAGNET&#8221; العالمي', '&#8220;طبية&#8221; جامعة الملك سعود تحصل على اعتماد &#8220;MAGNET&#8221; العالمي', 'كبسولة الصحية &#8211; واس حصلت المدينة الطبية الجامعية بجامعة الملك سعود على اعتماد &#8220;MAGNET&#8221; الأمريكي لمستشفياتها الثلاثة؛ مستشفى الملك عبدالعزيز ال', '{"اعتماد عالمي","جامعة الملك سعود"}', false, 'published', NULL, NULL, '2026-01-22 14:51:02', '2026-01-24 16:23:21.693779', '2026-01-24 16:23:21.693779');
INSERT INTO public.news VALUES ('5468dfd9-7afe-440a-b007-5d48857e1ab0', '9a1d17f', 'هل ينهي بروتين "NPM1" معاناة مرضى سرطانات الأمعاء والكبد؟', NULL, 'كبسولة الصحية &#8211;  ديلي ميل كشفت دراسة حديثة نشرتها مجلة  ( Nature Genetics)   عن وجود بروتين يُدعى &#8220;نيوكليوفوسمين&#8221;   NPM1 يتواجد بمستويات مرتفعة في أورام الأمعاء والكبد، ويعمل كمحرك أساسي لنمو الخلايا السرطانية عبر السيطرة على نظام إشارات (WNT). ووجد علماء من جامعة غلاسكو أن الأخطاء', '<p>كبسولة الصحية &#8211;  ديلي ميل</p>
<p>كشفت دراسة حديثة نشرتها مجلة  ( Nature Genetics)   عن وجود بروتين يُدعى &#8220;نيوكليوفوسمين&#8221;   NPM1 يتواجد بمستويات مرتفعة في أورام الأمعاء والكبد، ويعمل كمحرك أساسي لنمو الخلايا السرطانية عبر السيطرة على نظام إشارات (WNT). ووجد علماء من جامعة غلاسكو أن الأخطاء الجينية في هذا النظام تمنع الخلايا من التوقف عن النمو، مما يجعل اكتشاف دور هذا البروتين تحديداً نقطة تحول في فهم كيفية تكوّن الأورام في هذه الأنسجة الصعبة.</p>
<p>تكمن أهمية هذا الاكتشاف في أن بروتين (NPM1) ليس ضرورياً لصحة الأنسجة الطبيعية لدى البالغين، مما يعني أن استهدافه بالعلاج وتثبيطه قد يكون وسيلة آمنة وفعالة للقضاء على الخلايا السرطانية دون إلحاق ضرر بالخلايا السليمة. وبحسب ما نقلته (آر تي)، فإن إزالة هذا البروتين تجعل الخلايا السرطانية عاجزة عن إنتاج بروتيناتها بشكل صحيح، مما يسمح للجسم بتفعيل &#8220;مثبطات الأورام&#8221; الطبيعية ومنع نمو السرطان مجدداً.</p>
<p>يتطلع الفريق العلمي حالياً إلى تطوير علاجات دوائية تستهدف تثبيط هذا البروتين، وهو ما قد يفتح الباب أمام جيل جديد من العلاجات الموجهة لأنواع أخرى من السرطان مستقبلاً.</p>
<p>ويأمل الباحثون أن تساهم هذه النتائج في تقليل معدلات الوفيات الناتجة عن سرطانات الأمعاء والكبد التي تعد من أكثر الأنواع تعقيداً في العلاج، مع التركيز على تحويل هذه النتائج المخبرية إلى بروتوكولات علاجية متاحة للمرضى في أقرب وقت.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/7f83c08f-7047-4575-bbe4-cf70424b3956.png', 'هل ينهي بروتين &#8220;NPM1&#8221; معاناة مرضى سرطانات الأمعاء والكبد؟', 'هل ينهي بروتين &#8220;NPM1&#8221; معاناة مرضى سرطانات الأمعاء والكبد؟', 'كبسولة الصحية &#8211;  ديلي ميل كشفت دراسة حديثة نشرتها مجلة  ( Nature Genetics)   عن وجود بروتين يُدعى &#8220;نيوكليوفوسمين&#8221;   NPM1 يتواجد بمستويات مرتفع', '{"سرطان الأمعاء","سرطان الكبد",نيوكليوفوسمين}', false, 'published', NULL, NULL, '2026-01-23 03:12:48', '2026-01-24 16:23:18.450833', '2026-01-24 16:23:18.450833');
INSERT INTO public.news VALUES ('88e2790d-f793-4688-92c7-0e7881769a97', '378bf12', 'ما هي منتجات العناية بالبشرة المسموحة والممنوعة أثناء الحمل؟', NULL, 'متابعة – كبسولة الصحية حددت استشارية طب النساء والولادة، الدكتورة مها النمر، قائمة بمنتجات العناية بالبشرة التي يمكن للحامل استخدامها بأمان وتلك التي يجب تجنبها تماماً لحماية الجنين. ووفقاً لما نشرته النمر عبر حسابها الرسمي، فإن قائمة المسموحات تشمل &#8220;حمض الساليسيليك، أحماض الفواكه، الهيلورونيك', '<p>متابعة – كبسولة الصحية</p>
<p>حددت استشارية طب النساء والولادة، الدكتورة مها النمر، قائمة بمنتجات العناية بالبشرة التي يمكن للحامل استخدامها بأمان وتلك التي يجب تجنبها تماماً لحماية الجنين. ووفقاً لما نشرته النمر عبر حسابها الرسمي، فإن قائمة المسموحات تشمل &#8220;حمض الساليسيليك، أحماض الفواكه، الهيلورونيك أسيد، وفيتامين سي&#8221;، بالإضافة إلى كريم &#8220;سكينورين&#8221;، وهي مكونات لا تشكل خطراً على سلامة الحمل عند استخدامها موضعياً.</p>
<p>تكمن الخطورة في بعض المشتقات الشائعة التي قد تؤثر سلباً على نمو الجنين أو تسبب مضاعفات نتيجة امتصاصها عبر الجلد؛ لذا تشدد الدكتورة النمر على ضرورة التوقف التام عن استخدام &#8220;الأكرتين، الدفرين، الريتينول، والهيدروكوينون&#8221;. كما حذرت من استخدام بعض المواد الطبيعية مثل &#8220;عرق السوس&#8221; لعدم وجود دراسات كافية تثبت أمانها خلال فترة الحمل، مما يجعل الحذر منها واجباً طبياً لتجنب أي احتمالات غير محسومة علمياً.</p>
<p>ينصح الأطباء بضرورة مراجعة مكونات أي منتج تجميلي قبل استخدامه خلال شهور الحمل، والاعتماد على الخيارات الآمنة مثل &#8220;حمض الأزليك&#8221; ومرطبات الهيلورونيك للحفاظ على نضارة البشرة. ويساهم هذا الوعي في تقليل القلق لدى الحوامل، مع التأكيد على أن استشارة الطبيب المختص تظل الخطوة الأهم قبل إدخال أي عنصر جديد في روتين العناية اليومي، لضمان موازنة احتياجات الأم الجمالية مع صحة الجنين.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/4fd155fa-0128-4335-8707-2738676180c8.webp', 'ما هي منتجات العناية بالبشرة المسموحة والممنوعة أثناء الحمل؟', 'ما هي منتجات العناية بالبشرة المسموحة والممنوعة أثناء الحمل؟', 'متابعة – كبسولة الصحية حددت استشارية طب النساء والولادة، الدكتورة مها النمر، قائمة بمنتجات العناية بالبشرة التي يمكن للحامل استخدامها بأمان وتلك التي يجب تجنبها', '{البشرة,الحمل,"منتجات التجميل"}', false, 'published', NULL, NULL, '2026-01-22 07:06:45', '2026-01-24 16:23:22.743693', '2026-01-24 16:23:22.743693');
INSERT INTO public.news VALUES ('af2d5b8c-25f2-4b19-ab83-f29655e29b74', '61444c8', 'السعودية تطلق برنامجاً وطنياً للصحة النفسية', NULL, 'أعلنت وزارة الصحة السعودية عن إطلاق برنامج وطني شامل لتعزيز الصحة النفسية في المملكة.', 'أطلقت وزارة الصحة السعودية برنامجاً وطنياً طموحاً للصحة النفسية يهدف إلى:

- توفير خدمات الصحة النفسية في جميع المناطق
- تدريب 5000 أخصائي نفسي جديد
- إطلاق خط مساعدة نفسية مجاني 24/7
- حملات توعية لإزالة وصمة المرض النفسي

البرنامج يأتي ضمن رؤية 2030 لتحسين جودة الحياة.', 'health-news', 'وزارة الصحة السعودية', 'https://www.moh.gov.sa', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-27 00:00:00', '2026-01-24 13:59:54.270463', '2026-01-24 13:59:54.270463');
INSERT INTO public.news VALUES ('c2aba37c-e251-4a4f-b0f2-179d3b18c60f', NULL, 'حمية منخفضة السعرات تحاكي الصيام تخفف أعراض مرض كرون', NULL, NULL, '<p>أظهرت دراسة جديدة أن اتباع <strong>حمية منخفضة السعرات تحاكي الصيام</strong> لفترات قصيرة قد يسهم في تحسين أعراض مرض كرون، مع تأثيرات ملحوظة على مؤشرات الالتهاب في الأمعاء. الدراسة التي قادها باحثون من جامعة ستانفورد ونُشرت في <strong>13 يناير بمجلة Nature Medicine</strong> تقدّم أدلة أولية على فائدة هذا النهج الغذائي لبعض المرضى.</p><p>شملت الدراسة 97 شخصاً مصاباً بمرض كرون بدرجة خفيفة إلى متوسطة من مختلف مناطق الولايات المتحدة، وقارنت بين مجموعة اتّبعت الحمية المحاكية للصيام وأخرى واصلت نظامها الغذائي المعتاد.</p><p><strong>تفاصيل الحمية والدراسة:</strong></p><ul><li>عدد المشاركين: 97 مصاباً بكرون (خفيف إلى متوسط)</li><li>مجموعة الحمية: 65 مشاركاً؛ مجموعة الضبط: 32 مشاركاً</li><li>السعرات اليومية: بين 700 و1100 سعرة حرارية لمدة خمسة أيام متتالية كل شهر</li><li>نوع الوجبات: نباتية خلال أيام الحمية</li><li>المدة الإجمالية: ثلاثة أشهر، مع العودة للنظام المعتاد بقية الشهر</li></ul><p>عند نهاية الأشهر الثلاثة، سجّل نحو <strong>ثلثي</strong> أفراد مجموعة الحمية تحسناً في الأعراض، مقابل أقل من <strong>النصف</strong> في مجموعة الضبط، وهو ما يرجّحه الباحثون بتقلّبات طبيعية في مسار المرض والالتزام بالرعاية القياسية. وقال سيدهارتا س. سينها، أستاذ مساعد أمراض الجهاز الهضمي والكبد في ستانفورد وكبير مؤلفي الدراسة: «فوجئنا بسرور بأن غالبية المرضى بدت عليهم استفادة من هذه الحمية، ولاحظنا فوائد سريرية حتى بعد دورة واحدة منها. هذه النتائج تمنح الأطباء أدلة تدعم التوصيات في مجال يثير فضول المرضى».</p><p>على المستوى البيولوجي، سجّل المشاركون الذين اتّبعوا الحمية انخفاضاً في <strong>بروتين الكالبروتكتين</strong> في البراز، وهو مؤشر على تراجع التهاب الأمعاء، كما أظهرت تحاليل الدم أن خلاياهم المناعية أنتجت كميات أقل من عدة جزيئات التهابية.</p><p>ورغم أن النتائج واعدة، يشير خبراء إلى ضرورة الحذر. يرى إميران ماير، اختصاصي أمراض الجهاز الهضمي في جامعة كاليفورنيا لوس أنجلوس (لم يشارك في الدراسة)، أن التصميم قوي والنتائج مثيرة للاهتمام، لكنه يلفت إلى أن معظم المشاركين كانوا بمرض خفيف، حيث يمكن أن تصل الاستجابات الوهمية إلى 40%، وأن المجموعة الضابطة حققت بالفعل نحو 40% تحسناً دون تدخل غذائي. كما أن عدم تعمية مجموعة الحمية قد يؤثر في تقارير الأعراض.</p><p>ويؤكد المختصون أن هذا النهج <strong>قد لا يناسب جميع مرضى كرون</strong>، خاصة المعرضين لمخاطر مثل سوء التغذية، فقدان الوزن، والجفاف. لذلك ينبغي مناقشة أي تغيير غذائي مع الطبيب، وأن يُنظر إلى الحمية المحاكية للصيام كخيار تكميلي محتمل ضمن خطة العلاج، مع الحاجة لمزيد من الدراسات لتحديد الفئات الأكثر استفادة والآثار طويلة المدى.</p>', 'nutrition', NULL, 'https://www.healthline.com/health-news/fasting-mimicking-diet-improves-crohns-disease', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Crohns-Diet-Stocksy_txp8bc11ae6E7E400_Medium_6396304-Header.jpg', NULL, NULL, NULL, '{}', false, 'published', NULL, NULL, '2026-01-25 08:52:55.263225', '2026-01-25 08:52:55.263225', '2026-01-25 08:52:55.263225');
INSERT INTO public.news VALUES ('ce22442b-e074-4e50-97b1-d4eb4adefc57', 'fb2349c', 'دراسة: حمية البحر المتوسط تقلل خطر السكري بنسبة 40%', NULL, 'بحث جديد يؤكد فوائد حمية البحر المتوسط في الوقاية من مرض السكري من النوع الثاني.', 'نشرت مجلة لانسيت دراسة واسعة تظهر أن اتباع حمية البحر المتوسط يقلل خطر الإصابة بمرض السكري من النوع الثاني بنسبة تصل إلى 40%.

حمية البحر المتوسط تعتمد على:
- زيت الزيتون البكر
- الخضروات والفواكه الطازجة
- الحبوب الكاملة
- الأسماك والمكسرات
- تقليل اللحوم الحمراء

الباحثون يوصون بهذه الحمية كوسيلة فعالة للوقاية من الأمراض المزمنة.', 'nutrition', 'مجلة لانسيت', 'https://www.thelancet.com', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-29 00:00:00', '2026-01-24 13:59:54.178947', '2026-01-24 13:59:54.178947');
INSERT INTO public.news VALUES ('a53caf55-43c9-4c73-a4f4-4026908bcb37', 'ac69962', 'فخ المبردات.. بكتيريا خفية تسكن فوهات مياه الشرب', NULL, 'كبسولة الصحية – ديلي ميل حذرت مراجعة علمية حديثة أجراها باحثون من جامعة &#8220;لوما ليندا&#8221; من أن موزعات ومبردات المياه في المكاتب والأماكن العامة قد تحتوي على مستويات بكتيرية تفوق مياه الصنبور العادية نتيجة تشكل &#8220;أغشية حيوية&#8221; لزجة داخل الأنابيب والفوهات. وتكمن خطورة هذه الأجهزة في ', '<p><strong> </strong><strong>كبسولة الصحية – ديلي ميل</strong></p>
<p>حذرت مراجعة علمية حديثة أجراها باحثون من جامعة &#8220;لوما ليندا&#8221; من أن موزعات ومبردات المياه في المكاتب والأماكن العامة قد تحتوي على مستويات بكتيرية تفوق مياه الصنبور العادية نتيجة تشكل &#8220;أغشية حيوية&#8221; لزجة داخل الأنابيب والفوهات.</p>
<p>وتكمن خطورة هذه الأجهزة في أن أنظمة الترشيح الملحقة بها تعمل على إزالة الكلور المتبقي من الماء، وهو المادة التي تمنع نمو الميكروبات، مما يحول الخزانات وفوهات التعبئة إلى بيئة خصبة لتكاثر البكتيريا بما في ذلك &#8220;القولونيات البرازية&#8221; المرتبطة بأمراض الجهاز الهضمي. وبناءً على هذه النتائج، يوصي الخبراء بضرورة الالتزام بجدول صيانة صارم يتضمن تنظيف الأجهزة وتعقيمها كل أسبوعين إلى أربعة أسابيع كحد أقصى، مع استبدال المرشحات بانتظام لضمان عدم تحولها من أداة تنقية إلى مصدر للتلوث البكتيري.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/e8fb603a-d801-45d5-8681-8f9cc8ac3fd9.png', 'فخ المبردات.. بكتيريا خفية تسكن فوهات مياه الشرب', 'فخ المبردات.. بكتيريا خفية تسكن فوهات مياه الشرب', 'كبسولة الصحية – ديلي ميل حذرت مراجعة علمية حديثة أجراها باحثون من جامعة &#8220;لوما ليندا&#8221; من أن موزعات ومبردات المياه في المكاتب والأماكن العامة قد تحتوي', '{البكتيريا,المبردات}', false, 'published', NULL, NULL, '2026-01-21 01:35:39', '2026-01-24 16:23:26.817385', '2026-01-24 16:23:26.817385');
INSERT INTO public.news VALUES ('04f464bb-348a-42b9-bdb0-e1c40edab56e', '630a158', '70% نسبة النجاة.. "السرطان" يتراجع أمام الطب', NULL, 'واشنطن – كبسولة الصحية كشف التقرير السنوي للجمعية الأمريكية للسرطان لعام 2026 أن 7 من كل 10 مصابين بالسرطان يتجاوزون مرحلة الخطر ويعيشون لسنوات طويلة، وهي أعلى نسبة نجاة تُسجل في التاريخ. ورغم هذا الإنجاز، إلا أن هناك &#8220;تحدياً&#8221; كبيراً يتمثل في وصول عدد الإصابات الجديدة إلى 2.1 مليون حالة ', '<p>واشنطن – كبسولة الصحية</p>
<p>كشف التقرير السنوي للجمعية الأمريكية للسرطان لعام 2026 أن 7 من كل 10 مصابين بالسرطان يتجاوزون مرحلة الخطر ويعيشون لسنوات طويلة، وهي أعلى نسبة نجاة تُسجل في التاريخ. ورغم هذا الإنجاز، إلا أن هناك &#8220;تحدياً&#8221; كبيراً يتمثل في وصول عدد الإصابات الجديدة إلى 2.1 مليون حالة هذا العام، ما يعني أن العلم يبرع في &#8220;علاج&#8221; المرض، لكننا ما زلنا مقصرين في &#8220;منع&#8221; حدوثه من الأساس.</p>
<p>هذا التحول يكسر حاجز الخوف من السرطان في مجتمعنا؛ فأنواع مثل الغدة الدرقية والبروستاتا وصلت نسبة النجاة فيها إلى 98%، وحتى سرطان الرئة الذي كان يثير الرعب، زادت فرص النجاة فيه 5 أضعاف. الأهمية هنا تكمن في تغيير النظرة الاجتماعية للمريض؛ فلم يعد المصاب &#8220;مفقوداً&#8221;، بل هو شخص يخوض رحلة علاجية بفرص نجاح تتجاوز الثلثين، مما يدفعنا لتشجيع الجميع على الفحص المبكر دون خوف من النتائج التي كانت تسكن الأذهان قديماً.</p>
<p>المعركة القادمة ليست في غرف العمليات فقط، بل في مراكز التوعية والوقاية. هذا الارتفاع في عدد الناجين عالمياً يضعنا في المملكة أمام مسؤولية تجهيز &#8220;منظومة متكاملة للتعافي&#8221;؛ فنحن نحتاج لمراكز رعاية تلطيفية وتأهيلية تستوعب هؤلاء الناجين وتساعدهم على العودة للعمل والحياة الطبيعية. وبما أن الأرقام في ازدياد، فإن الاستثمار في &#8220;الفحص الدوري&#8221; بالمراكز الصحية الأولية هو الحل الوحيد لتقليل الفاتورة العلاجية الباهظة، وحماية المجتمع من تحول هذا المرض إلى عبء يستنزف الأسر والمنظومة الصحية.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/4197fa93-8674-43d6-a6a5-d7bf6ee71400.jpg', '70% نسبة النجاة.. &#8220;السرطان&#8221; يتراجع أمام الطب', '70% نسبة النجاة.. &#8220;السرطان&#8221; يتراجع أمام الطب', 'واشنطن – كبسولة الصحية كشف التقرير السنوي للجمعية الأمريكية للسرطان لعام 2026 أن 7 من كل 10 مصابين بالسرطان يتجاوزون مرحلة الخطر ويعيشون لسنوات طويلة، وهي أعلى ', '{"الجمعية الأمريكية",السرطان,"نسب الشفاء"}', false, 'published', NULL, NULL, '2026-01-22 04:36:37', '2026-01-24 16:23:23.397374', '2026-01-24 16:23:23.397374');
INSERT INTO public.news VALUES ('121982bc-ea97-48d9-9c37-8e26786dac0e', '4660f19', 'أخيراً  اكتشاف سبب آلام العضلات الناتجة عن أدوية الكوليسترول', NULL, 'متابعة – كبسولة الصحية قد وجد الباحثون أن بعض الستاتينات قادرة على الارتباط ببروتين عضلي أساسي، ما يسبب تسرباً طفيفاً ولكنه ضار للكالسيوم داخل خلايا العضلات. وبحسب &#8220;ساينس دايلي&#8221;، قد يضعف هذا التسرب العضلات بشكل مباشر، أو ينشط عمليات تؤدي إلى تحللها تدريجياً، مقدماً بذلك تفسيراً طال انتظا', '<p>متابعة – كبسولة الصحية</p>
<p>قد وجد الباحثون أن بعض الستاتينات قادرة على الارتباط ببروتين عضلي أساسي، ما يسبب تسرباً طفيفاً ولكنه ضار للكالسيوم داخل خلايا العضلات.</p>
<p>وبحسب &#8220;ساينس دايلي&#8221;، قد يضعف هذا التسرب العضلات بشكل مباشر، أو ينشط عمليات تؤدي إلى تحللها تدريجياً، مقدماً بذلك تفسيراً طال انتظاره للآلام المرتبطة بتناول الستاتينات.</p>
<p>الإرهاق المستمر</p>
<p>ويتوقف العديد ممن وُصفت لهم الستاتينات لخفض الكوليسترول عن تناولها بسبب آلام العضلات أو ضعفها أو الإرهاق المستمر، وذلك بحسب موقع 24</p>
<p>وهذه الأعراض من أكثر الأسباب شيوعاً لتوقف المرضى عن تناول هذه الأدوية.</p>
<p>ويشير بحث جديد من جامعة كولومبيا إلى تفسير محتمل لحدوث ذلك لدى بعض الأفراد.</p>
<p>ويقول الدكتور أندرو ماركس، الباحث الرئيسي: &#8220;من غير المرجح أن ينطبق هذا التفسير على جميع من يعانون من آثار جانبية عضلية مع الستاتينات، ولكن حتى لو كان يفسر حالة شريحة صغيرة منهم، فهذا يعني أننا نستطيع مساعدة الكثيرين إذا تمكنا من حل المشكلة&#8221;.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/5b39b9be-50b5-49d2-a249-5ae327eaa42e.webp', 'أخيراً  اكتشاف سبب آلام العضلات الناتجة عن أدوية الكوليسترول', 'أخيراً  اكتشاف سبب آلام العضلات الناتجة عن أدوية الكوليسترول', 'متابعة – كبسولة الصحية قد وجد الباحثون أن بعض الستاتينات قادرة على الارتباط ببروتين عضلي أساسي، ما يسبب تسرباً طفيفاً ولكنه ضار للكالسيوم داخل خلايا العضلات. وب', '{"آلام العضلات",الكوليسترول}', false, 'published', NULL, NULL, '2026-01-22 04:30:59', '2026-01-24 16:23:23.707181', '2026-01-24 16:23:23.707181');
INSERT INTO public.news VALUES ('94950733-802e-4812-876b-91c3b19b7c33', 'b4d514e', 'لحماية الذاكرة.. "الغسيل البريتوني" يتفوق في حفظ القدرات الذهنية لمرضى الكلى', NULL, 'متابعة- كبسولة الصحية كشفت دراسة بريطانية حديثة من &#8220;كلية كينغز كوليدج لندن&#8221; أن غسيل الكلى البريتوني (الصفاقي) يعد الخيار الأفضل للحفاظ على القدرات الإدراكية والذهنية لدى مرضى الفشل الكلوي المزمن، مقارنة بغسيل الكلى الدموي التقليدي. وأوضحت المراجعة التي شملت بيانات أكثر من 326 ألف مريض أن', '<p>متابعة- كبسولة الصحية<br />
كشفت دراسة بريطانية حديثة من &#8220;كلية كينغز كوليدج لندن&#8221; أن غسيل الكلى البريتوني (الصفاقي) يعد الخيار الأفضل للحفاظ على القدرات الإدراكية والذهنية لدى مرضى الفشل الكلوي المزمن، مقارنة بغسيل الكلى الدموي التقليدي. وأوضحت المراجعة التي شملت بيانات أكثر من 326 ألف مريض أن الغسيل البريتوني يساهم بفعالية في حماية الذاكرة والوظائف التنفيذية وسرعة المعالجة الذهنية، مما يقلل من احتمالات الإصابة بالخرف التي تزداد لدى مرضى الكلى بنسبة تصل إلى 46%.<br />
وأرجعت الدراسة، التي استعرضتها الدكتورة عبير مبارك في صحيفة &#8220;الشرق الأوسط&#8221;، هذه الفوائد إلى استقرار مؤشرات الدورة الدموية والتصفية المستمرة للسموم التي يوفرها الغسيل البريتوني، بالإضافة إلى منحه المريض استقلالية أكبر ومرونة في النظام الغذائي.<br />
ويمثل هذا التوجه ركيزة استراتيجية في &#8220;جودة الحياة الصحية&#8221;؛ حيث يتجاوز الهدف مجرد البقاء على قيد الحياة إلى حماية &#8220;السلامة المعرفية&#8221; للمريض، مما يقلل من الأعباء النفسية والاجتماعية المرتبطة بالتدهور الذهني، ويضمن كفاءة المنظومة الصحية عبر تشجيع الحلول المنزلية التي تصون قدرات الفرد واستقلاليته.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/0ab5f55f-0fd1-4402-a1e4-cc7f9d0baa80.jpg', 'لحماية الذاكرة.. &#8220;الغسيل البريتوني&#8221; يتفوق في حفظ القدرات الذهنية لمرضى الكلى', 'لحماية الذاكرة.. &#8220;الغسيل البريتوني&#8221; يتفوق في حفظ القدرات الذهنية لمرضى الكلى', 'متابعة- كبسولة الصحية كشفت دراسة بريطانية حديثة من &#8220;كلية كينغز كوليدج لندن&#8221; أن غسيل الكلى البريتوني (الصفاقي) يعد الخيار الأفضل للحفاظ على القدرات ا', '{"أمراض الكلى","الغسيل البريتوني","حماية الذاكرة"}', false, 'published', NULL, NULL, '2026-01-22 04:26:51', '2026-01-24 16:23:24.026346', '2026-01-24 16:23:24.026346');
INSERT INTO public.news VALUES ('f416fbb3-fb42-4420-aff4-4b99629a4c88', '33a7fb1', 'اكتشاف بروتين جديد يوقف انتشار السرطان', NULL, 'علماء يكتشفون بروتين قادر على إيقاف انتشار الخلايا السرطانية في الجسم.', 'اكتشف فريق بحثي دولي بروتيناً جديداً يُدعى "STOP-C" قادر على إيقاف انتشار الخلايا السرطانية.

الاكتشاف يفتح آفاقاً جديدة لعلاج السرطان دون الحاجة للعلاج الكيميائي التقليدي.

التجارب السريرية ستبدأ العام المقبل.', 'health-news', 'مجلة Cell', 'https://www.cell.com', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-21 00:00:00', '2026-01-24 13:59:54.543172', '2026-01-24 13:59:54.543172');
INSERT INTO public.news VALUES ('ebe7f89c-4cda-4d83-93ea-586d37e5e2e8', 'f963677', 'دراسة تحذر من الاستخدام المفرط للمضادات الحيوية', NULL, 'متابعة – كبسولة الصحية حذّرت دراسة طبية حديثة من أن الاستخدام المفرط والمتكرر لمضادات الحيوية يترك آثارا خطيرة على الصحة الجسدية والنفسية، وفقاً لموقع آر تي. بحث القائمون على الدراسة تأثير مضادات الحيوية على الجسم والعلاقة بين الميكروبات المعوية وعمل الدماغ، وخلال التجارب التي أجروها على الفئران الم', '<p>متابعة – كبسولة الصحية</p>
<p>حذّرت دراسة طبية حديثة من أن الاستخدام المفرط والمتكرر لمضادات الحيوية يترك آثارا خطيرة على الصحة الجسدية والنفسية، وفقاً لموقع آر تي.</p>
<p>بحث القائمون على الدراسة تأثير مضادات الحيوية على الجسم والعلاقة بين الميكروبات المعوية وعمل الدماغ، وخلال التجارب التي أجروها على الفئران المخبرية تبين لهم أن هذه الأدوية تحدث اضطرابات كبيرة في تكوين بكتيريا الأمعاء وتقلل من مستويات الأستيل كولين، وهو ناقل عصبي مهم يُشارك في تنظيم المشاعر، وأن هذه التغيرات تترافق بظهور سلوك توتري مرتبط ارتباطا بخلل عمل منظومة الأمعاء والدماغ.</p>
<p>وحصل الباحثون على نتائج مماثلة عند البشر، إذ كان لدى المرضى الذين تناولوا مضادات الحيوية مؤخرا مستويات قلق أعلى وتراكيز أقل من الأستيل كولين في الدم والأمعاء مقارنة بالمرضى الذين لم يتناولوا هذه الأدوية.</p>
<p>ويعتقد العلماء أن بكتيريا معينة من جنس Bacteroides موجودة في الجسم تلعب دورا محوريا في الاضطرابات النفسية، إذ تزامن انخفاض مستوياتها مع تدهور الحالة النفسية والعاطفية، وأدوية مضادات الحيوية تؤثر بشكل كبير على هذه البكتيريا.</p>
<p>نشر الباحثون بيانات دراستهم في مجلة &#8220;Molecular Psychiatry&#8221;، وأكدوا على أن الدراسة لا تدعو إلى التخلي عن مضادات الحيوية، ولكنها تسلط الضوء على المخاطر المحتملة لاستخدامها المفرط وغير المبرر.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/941d4a1c-2913-41bf-bbf0-20b63e504c3a.webp', 'دراسة تحذر من الاستخدام المفرط للمضادات الحيوية', 'دراسة تحذر من الاستخدام المفرط للمضادات الحيوية', 'متابعة – كبسولة الصحية حذّرت دراسة طبية حديثة من أن الاستخدام المفرط والمتكرر لمضادات الحيوية يترك آثارا خطيرة على الصحة الجسدية والنفسية، وفقاً لموقع آر تي. بح', '{"الصحة العامة","الصحة النفسية","المضادات الحيوية"}', false, 'published', NULL, NULL, '2026-01-22 04:21:22', '2026-01-24 16:23:24.370317', '2026-01-24 16:23:24.370317');
INSERT INTO public.news VALUES ('cff7685f-f923-4902-a1c9-3f4bbdcd3cc2', '792a3f6', '"ملف خاص" ميزان المعادن: هل تحدد "المائدة" جنس مولودك القادم؟', NULL, 'توازن الصوديوم والكالسيوم في التخطيط الأسري القاهرة – محمد مطاوع تشير الأبحاث في علم الأجنة والتغذية إلى وجود علاقة بين التوازن المعدني في دم الأم وبين نوع الوسط (حمضي أو قلوي) الذي تستقبله الخلايا التناسلية، مما يفتح الباب أمام إمكانية التأثير &#8220;النسبي&#8221; على جنس المولود عبر تعديل النظام ا', '<p><strong> توازن الصوديوم والكالسيوم في التخطيط الأسري</strong></p>
<p>القاهرة – محمد مطاوع</p>
<p>تشير الأبحاث في علم الأجنة والتغذية إلى وجود علاقة بين التوازن المعدني في دم الأم وبين نوع الوسط (حمضي أو قلوي) الذي تستقبله الخلايا التناسلية، مما يفتح الباب أمام إمكانية التأثير &#8220;النسبي&#8221; على جنس المولود عبر تعديل النظام الغذائي قبل الحمل بفتـرة كافية.</p>
<p><strong>نظرية الوسط القلوي والحمضي</strong></p>
<p>تعتمد هذه الاستراتيجية العلمية على حقيقة أن الخلايا التناسلية الذكرية تفضل الوسط &#8220;القلوي&#8221;، بينما تميل الأنثوية للوسط &#8220;الحمضي&#8221;.</p>
<p>ويؤكد الخبراء أن زيادة استهلاك الصوديوم والبوتاسيوم (الموجود في الموز، الطماطم، واللحوم) تساهم في رفع قلوية الجسم، مما قد يعزز فرص إنجاب الذكور، في المقابل، فإن التركيز على الكالسيوم والمغنيسيوم (الموجود في الحليب، الأجبان الطبيعية، والمكسرات) يعزز الوسط الحمضي الذي يخدم فرص إنجاب الإناث.</p>
<p><strong>التوقيت والبروتوكول الغذائي</strong></p>
<p>يستلزم هذا التحول البيولوجي اتباع نظام غذائي صارم لمدة لا تقل عن شهرين قبل حدوث الحمل، لمنح الجسم فرصة لتعديل مخزونه المعدني. وتوضح الدراسات أن هذا المسار لا يضمن النتيجة بنسبة 100%، ولكنه يغير من &#8220;الاحتمالات الإحصائية&#8221; عبر تهيئة بيئة حيوية تنجذب إليها نوعية محددة من الخلايا، مما يجعله خياراً طبيعياً متاحاً للأسر التي ترغب في الموازنة بين أفرادها بعيداً عن التدخلات الجراحية المعقدة.</p>
<p><strong>التوازن الصحي أولاً</strong></p>
<p>يحذر الأطباء من الاندفاع خلف هذه الأنظمة دون استشارة طبية، خاصة لمن يعانون من ضغط الدم (بسبب الصوديوم) أو مشكلات الكلى (بسبب الكالسيوم). الهدف هو الوصول لـ &#8220;توازن ذكي&#8221; يخدم الرغبة الأسرية دون الإخلال بالصحة العامة للأم، مع التأكيد على أن العلم يظل في طور الاستكشاف لهذه الروابط الدقيقة بين الغذاء والهرمونات، وأن الطبيعة تملك دائماً كلمتها الأخيرة في هذا التنوع البيولوجي المذهل.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/e7bf607c-9589-4a0a-8e2e-98ff7afc650a.png', '&#8220;ملف خاص&#8221; ميزان المعادن: هل تحدد &#8220;المائدة&#8221; جنس مولودك القادم؟', '&#8220;ملف خاص&#8221; ميزان المعادن: هل تحدد &#8220;المائدة&#8221; جنس مولودك القادم؟', 'توازن الصوديوم والكالسيوم في التخطيط الأسري القاهرة – محمد مطاوع تشير الأبحاث في علم الأجنة والتغذية إلى وجود علاقة بين التوازن المعدني في دم الأم وبين نوع الوس', '{الأطعمة,المعادن,"جنس المولود"}', false, 'published', NULL, NULL, '2026-01-22 04:14:56', '2026-01-24 16:23:24.703927', '2026-01-24 16:23:24.703927');
INSERT INTO public.news VALUES ('6b0d41e4-9c52-48ba-ac39-935ed69d7053', '666ab04', 'لغز البروستاتا والمغنسيوم.. هل تنهي المعادن الطبيعية آلام الحوض؟', NULL, 'نيويورك – كبسولة الصحية كشفت مراجعات بحثية حديثة عن وجود علاقة بين مستويات المغنسيوم وصحة غدة البروستاتا، حيث أظهرت الدراسات أن الرجال المصابين بالتهاب البروستاتا المزمن يعانون من انخفاض ملحوظ في تركيز المغنسيوم داخل السائل المنوي مقارنة بالأصحاء. ورغم الأدوار البيولوجية المعروفة للمغنسيوم في تنظيم ', '<p>نيويورك – كبسولة الصحية</p>
<p>كشفت مراجعات بحثية حديثة عن وجود علاقة بين مستويات المغنسيوم وصحة غدة البروستاتا، حيث أظهرت الدراسات أن الرجال المصابين بالتهاب البروستاتا المزمن يعانون من انخفاض ملحوظ في تركيز المغنسيوم داخل السائل المنوي مقارنة بالأصحاء.</p>
<p>ورغم الأدوار البيولوجية المعروفة للمغنسيوم في تنظيم الالتهاب والوظائف العصبية والعضلية، إلا أن الأبحاث العلمية لا تزال تفتقر إلى أدلة سريرية قاطعة تثبت أن تناول المكملات الغذائية لهذا المعدن يعالج الالتهاب أو يخفف أعراضه بشكل مباشر.</p>
<p>ويشير الخبراء إلى أن نقص المغنسيوم قد يكون مؤشراً على اضطرابات وظيفية في الغدة وليس بالضرورة سبباً لها، محذرين من الاعتماد على الأقراص بصفة علاجية دون استشارة طبية، خاصة وأن الأبحاث حول النظام الغذائي ككل تظهر نتائج مختلطة تتأثر بعوامل أخرى مثل الدهون والفيتامينات.</p>
<p>ويبقى التوجه الحالي هو الحصول على المغنسيوم من مصادره الطبيعية كالخضراوات الورقية والمكسرات كجزء من نمط حياة صحي، في انتظار مزيد من التجارب السريرية التي تحسم الدور الحقيقي لهذا المعدن في مواجهة آلام الحوض وتشنجات البروستاتا.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/6e816f53-1c8f-4ad5-9879-2e2773508bb4.webp', 'لغز البروستاتا والمغنسيوم.. هل تنهي المعادن الطبيعية آلام الحوض؟', 'لغز البروستاتا والمغنسيوم.. هل تنهي المعادن الطبيعية آلام الحوض؟', 'نيويورك – كبسولة الصحية كشفت مراجعات بحثية حديثة عن وجود علاقة بين مستويات المغنسيوم وصحة غدة البروستاتا، حيث أظهرت الدراسات أن الرجال المصابين بالتهاب البروستا', '{"آلام الحوض",البروستاتا,المغنسيوم}', false, 'published', NULL, NULL, '2026-01-21 02:07:57', '2026-01-24 16:23:25.392353', '2026-01-24 16:23:25.392353');
INSERT INTO public.news VALUES ('9a706369-242a-4422-9f12-ad93263d58a2', '0a7474d', 'قوة التوقعات.. التفاؤل والنشاط الذهني يعززان مفعول اللقاحات', NULL, 'لندن – كبسولة الصحية كشفت دراسة بريطانية حديثة نشرتها صحيفة &#8220;الغارديان&#8221; عن وجود صلة سببية ومباشرة بين العقل ودفاعات الجسم الطبيعية، حيث تبيّن أن الأفكار الإيجابية وتنشيط &#8220;نظام المكافأة&#8221; في الدماغ يسهمان بشكل ملحوظ في رفع كفاءة الاستجابة المناعية للقاحات. وأجرى الباحثون تجاربه', '<p>لندن – كبسولة الصحية</p>
<p>كشفت دراسة بريطانية حديثة نشرتها صحيفة &#8220;الغارديان&#8221; عن وجود صلة سببية ومباشرة بين العقل ودفاعات الجسم الطبيعية، حيث تبيّن أن الأفكار الإيجابية وتنشيط &#8220;نظام المكافأة&#8221; في الدماغ يسهمان بشكل ملحوظ في رفع كفاءة الاستجابة المناعية للقاحات.</p>
<p>وأجرى الباحثون تجاربهم على متطوعين خضعوا لجلسات تدريب ذهني تهدف لتحفيز مناطق محددة في المخ، ليظهر لاحقاً أن الأشخاص الذين نجحوا في تنشيط المنطقة السقيفة البطنية عبر التوقعات الإيجابية وتخيل الأحداث الجيدة سجلوا أعلى مستويات من الأجسام المضادة بعد تلقيهم لقاح التهاب الكبد &#8220;ب&#8221;.</p>
<p>وتكمن أهمية هذه النتائج في كونها المرة الأولى التي يُثبت فيها علمياً قدرة استراتيجيات التفكير الإيجابي على زيادة فاعلية التطعيمات لدى البشر، مما يفتح آفاقاً جديدة لاستخدام العقل كأداة داعمة للجهاز المناعي في مكافحة العدوى، مع تأكيد الباحثين على ضرورة التوسع في هذه الدراسات لتقييم الفاعلية السريرية على نطاق أوسع.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/83f17b50-c622-47d9-aa9c-6ab87e919f7b.webp', 'قوة التوقعات.. التفاؤل والنشاط الذهني يعززان مفعول اللقاحات', 'قوة التوقعات.. التفاؤل والنشاط الذهني يعززان مفعول اللقاحات', 'لندن – كبسولة الصحية كشفت دراسة بريطانية حديثة نشرتها صحيفة &#8220;الغارديان&#8221; عن وجود صلة سببية ومباشرة بين العقل ودفاعات الجسم الطبيعية، حيث تبيّن أن الأ', '{التفاؤل,اللقاحات,"النشاط الذهني"}', false, 'published', NULL, NULL, '2026-01-21 02:00:58', '2026-01-24 16:23:25.72838', '2026-01-24 16:23:25.72838');
INSERT INTO public.news VALUES ('56ef724d-4798-480a-8c9c-2fb5ee62ad9e', 'd0b296c', 'درع الخمسين.. لقاح الحزام الناري يبطئ قطار الشيخوخة', NULL, 'واشنطن – كبسولة الصحية كشفت دراسة حديثة من جامعة جنوب كاليفورنيا أن لقاح الحزام الناري يتجاوز دوره التقليدي في الوقاية من الفيروس ليلعب دوراً جوهرياً في إبطاء الشيخوخة البيولوجية لدى كبار السن. واستند البحث إلى تحليل بيانات آلاف المشاركين ممن تجاوزوا سن السبعين، حيث أظهرت النتائج أن الحاصلين على الل', '<p>واشنطن – كبسولة الصحية</p>
<p>كشفت دراسة حديثة من جامعة جنوب كاليفورنيا أن لقاح الحزام الناري يتجاوز دوره التقليدي في الوقاية من الفيروس ليلعب دوراً جوهرياً في إبطاء الشيخوخة البيولوجية لدى كبار السن.</p>
<p>واستند البحث إلى تحليل بيانات آلاف المشاركين ممن تجاوزوا سن السبعين، حيث أظهرت النتائج أن الحاصلين على اللقاح يتمتعون بمعدلات شيخوخة أبطأ ومؤشرات التهاب مزمن أقل مقارنة بغير الملقحين، وهو ما ينعكس إيجاباً على كفاءة الخلايا وقدرتها على إنتاج البروتينات. وتكمن أهمية هذا الكشف في أن فوائد اللقاح استمرت لأكثر من أربع سنوات، مما يعزز فرضية أن تقوية الجهاز المناعي وتقليل الالتهابات يسهمان بشكل مباشر في تأخير أمراض القلب والتدهور المعرفي.</p>
<p>ويفتح هذا الإنجاز الباب أمام استراتيجيات صحية جديدة لا تنظر للقاحات كمجرد وسيلة للوقاية من العدوى، بل كأداة فعالة لإطالة سنوات الحياة الصحية وتحسين جودة العيش مع التقدم في السن.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/c27b8d6b-2d8f-4cae-bfde-526433e4d693.webp', 'درع الخمسين.. لقاح الحزام الناري يبطئ قطار الشيخوخة', 'درع الخمسين.. لقاح الحزام الناري يبطئ قطار الشيخوخة', 'واشنطن – كبسولة الصحية كشفت دراسة حديثة من جامعة جنوب كاليفورنيا أن لقاح الحزام الناري يتجاوز دوره التقليدي في الوقاية من الفيروس ليلعب دوراً جوهرياً في إبطاء ا', '{الشيخوخة,"لقاح الحزام الناري"}', false, 'published', NULL, NULL, '2026-01-21 01:53:33', '2026-01-24 16:23:26.050803', '2026-01-24 16:23:26.050803');
INSERT INTO public.news VALUES ('ad1d8b34-8d92-44a1-864f-5eb1b1dc1292', 'b48ad60', 'هذا تأثير الزنك على التهاب البروستاتا', NULL, 'متابعة – كبسولة الصحية تُعدّ غدة البروستاتا من أكثر أعضاء الجسم احتواءً على الزنك، إذ تصل تركيزاته فيها إلى ما يعادل 5- 10 أضعاف تركيزه في معظم الأنسجة الأخرى. هذا الارتفاع ليس عشوائياً، بل يعكس الدور الحيوي للزنك في الحفاظ على الوظيفة الطبيعية للبروستاتا. وتشير الدراسات الحديثة، ومنها مراجعة علمية ', '<p>متابعة – كبسولة الصحية</p>
<p>تُعدّ غدة البروستاتا من أكثر أعضاء الجسم احتواءً على الزنك، إذ تصل تركيزاته فيها إلى ما يعادل 5- 10 أضعاف تركيزه في معظم الأنسجة الأخرى. هذا الارتفاع ليس عشوائياً، بل يعكس الدور الحيوي للزنك في الحفاظ على الوظيفة الطبيعية للبروستاتا.</p>
<p>وتشير الدراسات الحديثة، ومنها مراجعة علمية نُشرت عام 2025 في مجلة «جورنال أوف ترايس إليمنتس إن ميديسين آند بيولوجي» الطبية، إلى أن توازن الزنك داخل البروستاتا عنصر أساسي في الوقاية من أمراض البروستاتا المختلفة، بما فيها التهاب البروستاتا.</p>
<p>يمتلك الزنك خصائص مضادة للالتهاب والأكسدة، مما يجعله عنصراً مهماً في تهدئة التفاعلات الالتهابية داخل أنسجة البروستاتا. فهو يساعد على تقليل الإجهاد التأكسدي الذي يفاقم تلف الخلايا، كما يدعم آليات «الموت الخلوي المبرمج» للخلايا غير الطبيعية، مما يمنع تحولها إلى خلايا مريضة أو خبيثة. هذه الخصائص تجعل الزنك عاملاً وقائياً مهماً في حالات التهاب البروستاتا، وخصوصاً المزمن منها.</p>
<p><strong>دعم المناعة </strong></p>
<p>يلعب الزنك دوراً محورياً في تقوية الجهاز المناعي، إذ يشارك في تنشيط الخلايا المناعية وتنظيم استجابتها،  كما أنه يسهم في تقليل نمو بعض أنواع البكتيريا، وهو أمر بالغ الأهمية في حالات التهاب البروستاتا الجرثومي. هذا التأثير المناعي والمضاد للميكروبات قد يخفف من حدة الأعراض، ويقلل من تكرار الالتهابات. وذلك وفقاً لصحيفة الشرق الأوسط</p>
<p><strong>أعراض التهاب البروستاتا المزمن</strong></p>
<p>يعاني مرضى التهاب البروستاتا المزمن غالباً من أعراض مزعجة مثل الألم في منطقة الحوض، والحرقان في أثناء التبول، واضطرابات التبول. وتشير الأبحاث إلى أن اختلال توازن الزنك داخل البروستاتا يرتبط بتفاقم هذه الأعراض. بالمقابل، فإن استعادة هذا التوازن قد تساعد على تخفيف الألم وتحسين وظيفة الغدة، مما ينعكس إيجاباً على جودة حياة المريض.</p>
<p><strong>تناول مكملات الزنك</strong></p>
<p>على الرغم من الفوائد المحتملة للزنك، فإن الإفراط في تناوله قد يسبب آثاراً جانبية مثل الغثيان، والإسهال، واضطرابات الجهاز الهضمي. لذلك، يُنصح دائماً باستشارة الطبيب قبل استخدام مكملات الزنك، لتحديد الجرعة المناسبة حسب الحالة الصحية واحتياجات الجسم، وضمان تحقيق الفائدة دون التعرض لمخاطر الجرعات الزائدة.</p>
<p>يُعدّ الزنك عنصراً محورياً في صحة البروستاتا، إذ يسهم في تقليل الالتهاب، وتعزيز المناعة، والحد من نمو البكتيريا، وقد يساعد على تخفيف أعراض التهاب البروستاتا المزمن. غير أن التوازن هو الأساس، فالحفاظ على مستويات طبيعية من الزنك -سواء عبر الغذاء أو المكملات بإشراف طبي- يمثل خطوة مهمة في دعم صحة البروستاتا والوقاية من أمراضها.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/0dd5da1b-f081-404c-a3eb-7d7252b14edf.jpg', 'هذا تأثير الزنك على التهاب البروستاتا', 'هذا تأثير الزنك على التهاب البروستاتا', 'متابعة – كبسولة الصحية تُعدّ غدة البروستاتا من أكثر أعضاء الجسم احتواءً على الزنك، إذ تصل تركيزاته فيها إلى ما يعادل 5- 10 أضعاف تركيزه في معظم الأنسجة الأخرى. ', '{البروستاتا,الزنك}', false, 'published', NULL, NULL, '2026-01-20 02:23:38', '2026-01-24 16:23:29.351809', '2026-01-24 16:23:29.351809');
INSERT INTO public.news VALUES ('dfbb30a7-edf9-407e-a1ed-a061a06fac79', '763a2d3', 'العلاقة الحميمة.. "الوصفة الذهبية" للصحة النفسية', NULL, 'كبسولة الصحية &#8211; جازيت يشير البروفيسور موتونغ تشين من جامعة شاندونغ إلى أن ممارسة الجنس بانتظام مرة أو مرتين أسبوعيا ترتبط بصحة نفسية أكثر استقرارا وانخفاضا في معدل الاكتئاب. ووفقا لموقع VOI.id يستشهد البروفيسور بنتائج دراسة تحليلية لبيانات النشاط الجنسي والحالة النفسية لأكثر من 15 ألف شخص. وأظ', '<p>كبسولة الصحية &#8211; جازيت</p>
<p>يشير البروفيسور موتونغ تشين من جامعة شاندونغ إلى أن ممارسة الجنس بانتظام مرة أو مرتين أسبوعيا ترتبط بصحة نفسية أكثر استقرارا وانخفاضا في معدل الاكتئاب.</p>
<p>ووفقا لموقع VOI.id يستشهد البروفيسور بنتائج دراسة تحليلية لبيانات النشاط الجنسي والحالة النفسية لأكثر من 15 ألف شخص. وأظهرت النتائج أن المشاركين الذين يمارسون الجنس مرة أو مرتين أسبوعيا سجلوا أفضل مؤشرات الصحة النفسية. أما لدى من يمارس الجنس بوتيرة أقل أو بشكل غير منتظم، فكانت العلاقة بالصحة النفسية أقل وضوحا.</p>
<p>ويشير البروفيسور إلى أن النشاط الجنسي عموما يحسن جودة الحياة ويزيد الشعور بالرضا الذاتي، وهو ما ينعكس بمرور الوقت على الصحة النفسية. ومع ذلك، لا تزال الآلية البيولوجية أو النفسية الدقيقة وراء هذا التأثير غير واضحة.</p>
<p>ويؤكد أن النتائج تُظهر ارتباطا إحصائيا وليس علاقة سببية مباشرة، لذلك سيكون تحديد كيفية تأثير العلاقات الحميمة على الصحة النفسية محورا لمزيد من البحوث والدراسات.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/18d45c45-4f19-4b1f-8802-3de93cde3dfe.jpg', 'العلاقة الحميمة.. &#8220;الوصفة الذهبية&#8221; للصحة النفسية', 'العلاقة الحميمة.. &#8220;الوصفة الذهبية&#8221; للصحة النفسية', 'كبسولة الصحية &#8211; جازيت يشير البروفيسور موتونغ تشين من جامعة شاندونغ إلى أن ممارسة الجنس بانتظام مرة أو مرتين أسبوعيا ترتبط بصحة نفسية أكثر استقرارا وانخفاض', '{"الصحة النفسية","العلاقة الحميمة"}', false, 'published', NULL, NULL, '2026-01-20 01:51:22', '2026-01-24 16:23:29.772505', '2026-01-24 16:23:29.772505');
INSERT INTO public.news VALUES ('9b067c16-c1fc-4444-8a38-9e12964ec2e4', '7bf92d8', 'تمرين بسيط يكشف صحة العضلات والدماغ', NULL, 'متابعة – كبسولة الصحية كشفت تقارير طبية حديثة أن الوقوف على ساق واحدة، رغم بساطته الظاهرية، يُعد مؤشراً مهماً على صحة العضلات والدماغ، خاصة مع التقدم في العمر، كما يمكن أن يسهم في تقليل مخاطر السقوط وتعزيز الذاكرة والحفاظ على صحة الدماغ  . إن الحفاظ على التوازن أثناء الوقوف على قدم واحدة يصبح أكثر ص', '<p>متابعة – كبسولة الصحية</p>
<p><strong>كشفت تقارير طبية حديثة أن الوقوف على ساق واحدة، رغم بساطته الظاهرية، يُعد مؤشراً مهماً على صحة العضلات والدماغ، خاصة مع التقدم في العمر، كما يمكن أن يسهم في تقليل مخاطر السقوط وتعزيز الذاكرة والحفاظ على صحة الدماغ  .</strong></p>
<p>إن الحفاظ على التوازن أثناء الوقوف على قدم واحدة يصبح أكثر صعوبة مع التقدم في السن، بعد أن تبلغ القدرة على التوازن ذروتها عادة في أواخر الثلاثينيات، ثم تبدأ في التراجع تدريجياً .</p>
<p>وتشير الدراسات إلى أن هذه القدرة تنضج لدى الأطفال بين سن التاسعة والعاشرة، لكنها قد تصبح تحدياً   حقيقياً بعد سن الخمسين  .</p>
<p>ويؤكد متخصصون أن القدرة على الوقوف على ساق واحدة لبضع ثوانٍ فقط بعد هذا العمر يمكن أن تكشف الكثير عن الحالة الصحية العامة ومدى جودة التقدم في السن، كما أن تدريب التوازن بانتظام لا يقتصر على تحسين الثبات الجسدي، بل يمتد تأثيره ليشمل تقوية العضلات وتحسين الذاكرة وصحة الدماغ  .</p>
<p>من جانبها، قالت تريسي إسبيريتو مكاي، اختصاصية طب إعادة التأهيل في الأكاديمية الأمريكية لطب إعادة التأهيل: &#8220;إذا وجدت أن الوقوف على ساق واحدة ليس سهلاً، فقد حان الوقت للبدء في تدريب توازنك&#8221;.</p>
<p>يرتبط اختبار الوقوف على ساق واحدة ارتباطاً وثيقاً بفقدان الكتلة العضلية المرتبط بالتقدم في العمر، والمعروف باسم &#8220;الساركوبينيا&#8221;، فمنذ سن الثلاثين، يفقد الإنسان ما يصل إلى 8% من كتلته العضلية كل عقد، وتشير أبحاث إلى أن نحو 50% من الأشخاص في الثمانينيات يعانون من ساركوبينيا سريرية.</p>
<p>ويرتبط هذا التراجع العضلي بضعف التحكم في سكر الدم وتراجع المناعة، كما ينعكس بشكل مباشر على القدرة على التوازن.</p>
<p>لا يعتمد التوازن على قوة العضلات فقط، بل يتطلب تكاملاً دقيقاً بين الدماغ والجهاز العصبي، إذ يشمل ذلك معالجة المعلومات القادمة من العينين، والجهاز الدهليزي في الأذن الداخلية المسؤول عن التوازن، إضافة إلى الجهاز الحسي الجسدي الذي يساعد على إدراك وضعية الجسم.</p>
<p>ويشير كوفمان إلى أن جميع هذه الأنظمة تتدهور مع التقدم في العمر، ولكن بمعدلات مختلفة، ما يجعل الوقوف على ساق واحدة اختباراً كاشفاً لصحة مناطق دماغية مهمة، تتعلق بسرعة الاستجابة والقدرة على أداء المهام اليومية.</p>
<p>فيما تحذر إسبيريتو مكاي من أن التسارع في ضمور الدماغ قد يزيد من خطر السقوط ويحد من القدرة على العيش باستقلالية في المراحل المتقدمة من العمر.</p>
<p>وتُظهر بيانات مراكز السيطرة على الأمراض والوقاية منها أن السقوط غير المقصود، الناتج غالباً عن فقدان التوازن، هو السبب الرئيسي للإصابات بين من تجاوزوا 65 عاماً في الولايات المتحدة.</p>
<p>اللافت أن القدرة على الوقوف على ساق واحدة قد تعكس أيضاً خطر الوفاة المبكرة، فقد أظهرت دراسة نُشرت عام 2022 أن الأشخاص غير القادرين على الحفاظ على هذا الوضع لمدة 10 ثوانٍ كانوا أكثر عرضة للوفاة بنسبة 84% خلال السنوات السبع التالية، مقارنة بغيرهم.</p>
<p>يوصي الباحثون باستغلال الأنشطة اليومية البسيطة، مثل الوقوف عند غسل الصحون أو تنظيف الأسنان، للتدرب على الوقوف على ساق واحدة مع تقليل التمايل قدر الإمكان. ويؤكدون أن تخصيص 10 دقائق يومياً فقط لممارسة تمارين التوازن يمكن أن يحقق نتائج ملموسة.</p>
<p>كما تساعد تمارين تقوية الوركين باستخدام مقاومة خفيفة، المعروفة باسم التمارين الإيزوكينيتية، على تحسين القدرة على التوازن. وتشير دراسات إلى أن الجمع بين تمارين القوة والتمارين الهوائية وتمارين التوازن يمكن أن يقلل من مخاطر السقوط بنسبة تصل إلى 50%.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/b86c0ce0-7b3e-40a2-8f57-c02528a5c0c7.webp', 'تمرين بسيط يكشف صحة العضلات والدماغ', 'تمرين بسيط يكشف صحة العضلات والدماغ', 'متابعة – كبسولة الصحية كشفت تقارير طبية حديثة أن الوقوف على ساق واحدة، رغم بساطته الظاهرية، يُعد مؤشراً مهماً على صحة العضلات والدماغ، خاصة مع التقدم في العمر، ', '{الدماغ,العضلات}', false, 'published', NULL, NULL, '2026-01-20 01:29:54', '2026-01-24 16:23:30.38318', '2026-01-24 16:23:30.38318');
INSERT INTO public.news VALUES ('11065de5-b06c-4b4a-85b6-caa2280f4b1f', 'c39df2b', 'إطلاق تطبيق سعودي للاستشارات الطبية عن بعد', NULL, 'وزارة الصحة تطلق تطبيق ''صحة'' للاستشارات الطبية المجانية على مدار الساعة.', 'أطلقت وزارة الصحة السعودية تطبيق ''صحة'' الجديد الذي يتيح للمواطنين والمقيمين الحصول على استشارات طبية مجانية.

مميزات التطبيق:
- استشارات مع أطباء معتمدين
- حجز مواعيد إلكترونياً
- صرف الوصفات الطبية
- متابعة الحالة الصحية

التطبيق متاح على iOS وAndroid.', 'health-news', 'وزارة الصحة السعودية', 'https://www.moh.gov.sa', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-22 00:00:00', '2026-01-24 13:59:54.497624', '2026-01-24 13:59:54.497624');
INSERT INTO public.news VALUES ('9ae9d9f1-e8d8-4304-a61b-19b3c493b67d', 'bZCuPCi', 'دراسة سويدية تكشف تأثير مذهل للأجبان كاملة الدسم على الدماغ', 'تقرير حديث يظهر دور الدهون الطبيعية في الوقاية بالخرف', 'دراسة سويدية حديثة تؤكد أن تناول الأجبان كاملة الدسم قد يحمي الدماغ من التدهور المعرفي والخرف الوعائي، بفضل فيتامين K2 الذي يعزز صحة الشرايين والأوعية الدماغية.', '<p>لطالما ارتبطت الدهون المشبعة في أذهاننا بقائمة المحظورات، إلا أن تقريراً نشرته صحيفة الشرق الأوسط سلط الضوء على دراسة سويدية حديثة قلبت الطاولة على المفاهيم التقليدية، كاشفة عن دور إيجابي غير متوقع لمنتجات الألبان كاملة الدسم في تعزيز صحة الدماغ والوقاية من التدهور المعرفي.</p><p style="text-align: right;"><strong>كواليس الدراسة السويدية؟</strong></p><p style="text-align: right;">قام باحثون من جامعة “لوند” في السويد بتحليل بيانات ضخمة شملت أكثر من 27 ألف شخص، وتتبعوهم لمدة ربع قرن كامل. وبحسب النتائج التي تناقلتها الأوساط العلمية ونشرت تفاصيلها الشرق الأوسط، تبين أن الأشخاص الذين تناولوا ما يعادل شريحتين من الجبن عالي الدسم يومياً (مثل الشيدر والبري والجودة)، انخفض لديهم خطر الإصابة بالخرف بنسبة 13% مقارنة بمن تجنبوا هذه الدهون.</p><p style="text-align: right;"><strong>لماذا يتفوق الجبن عالي الدسم على البدائل الأخرى؟</strong></p><p style="text-align: right;">تطرح الدراسة تساؤلاً جوهرياً: لماذا لم تحقق الألبان قليلة الدسم أو الزبادي نفس التأثير؟ يرجح العلماء أن السر يكمن في “البنية الغذائية” للجبن كامل الدسم؛ فهو غني بفيتامين K2 الذي يمنع تكلس الشرايين ويحمي الأوعية الدموية الدقيقة في الدماغ. هذا النوع من الحماية يقلل تحديداً من خطر “الخرف الوعائي” بنسبة تصل إلى 29%، وهو الخرف الناتج عن تراكم سكتات دماغية صغيرة بمرور الوقت.</p><p style="text-align: right;">بين النصيحة الطبية وحذر الخبراء رغم هذه الأرقام، تشير القراءة المتأنية للتقرير إلى أن الخبراء لا يزالون يتوخون الحذر؛ فالبحث استنتاجي ولم يختبر الآليات البيولوجية المباشرة بعد. كما تظل المخاوف قائمة من أن الإفراط في الدهون المشبعة قد يرفع مستويات الكوليسترول الضار لدى البعض، مما يستوجب الموازنة بين تناول الأجبان والحفاظ على نمط حياة نشط.</p><p style="text-align: right;">تفتح هذه النتائج الباب أمام مراجعة شاملة للإرشادات الغذائية العالمية التي حاربت الدهون لعقود. التوجه القادم، كما تشير التحليلات، يركز على “جودة الغذاء” كحزمة متكاملة؛ حيث يبدو أن بعض الدهون الطبيعية تحمل مفاتيح سرية لحماية الذاكرة لم تكن في الحسبان.</p>', 'nutrition', NULL, NULL, '/objects/uploads/a3bd209e-f37b-4b53-a7e9-84e07d1140a6', NULL, 'دور الأجبان كاملة الدسم في صحة الدماغ', 'دراسة تكشف فوائد الأجبان كاملة الدسم في الوقاية من الخرف وتعزيز صحة الذاكرة، بفضل الدهون المشبعة الطبيعية وفيتامين K2.', '{"دراسة سويدية","الأجبان عالية الدسم","صحة الدماغ","الوقاية من الخرف","فيتامين K2",الذاكرة,"دهون مشبعة"}', false, 'published', NULL, NULL, '2026-01-25 07:02:07.441', '2026-01-25 07:02:08.532989', '2026-01-25 07:02:08.532989');
INSERT INTO public.news VALUES ('181d0c8b-a0eb-4c77-9f1a-b1e148a95db5', '2aeaf17', 'وفد رسمي من نقابة أطباء لبنان طرابلس يزور مقر اتحاد الأطباء العرب بالقاهرة..', NULL, 'القاهرة – كبسولة الصحية استقبل الأستاذ الدكتور علي أبو سيف، الأمين العام لاتحاد الأطباء العرب،  بمقر الأمانة العامة بدار الحكمة بالقاهرة، أمس الأحد 18 يناير 2026، الدكتور محمد صافي رئيس المجلس الأعلى للاتحاد، ووفد رسمي من نقابة أطباء لبنان – طرابلس، يترأسه النقيب ابراهيم المقدسي وعدد من أعضاء المجلس', '<p>القاهرة – كبسولة الصحية</p>
<p>استقبل الأستاذ الدكتور علي أبو سيف، الأمين العام لاتحاد الأطباء العرب،  بمقر الأمانة العامة بدار الحكمة بالقاهرة، أمس الأحد 18 يناير 2026، الدكتور محمد صافي رئيس المجلس الأعلى للاتحاد، ووفد رسمي من نقابة أطباء لبنان – طرابلس، يترأسه النقيب ابراهيم المقدسي وعدد من أعضاء المجلس، لبحث سبل تعزيز التعاون بين الجانبين، والتعرف عن قرب على مراكز ولجان الاتحاد.</p>
<p>وأوضح الاتحاد في بيان له، أن وفد نقابة الأطباء طرابلس،  أعرب عن سعادته بزيارة اتحاد الأطباء العرب، وتقديره للدور الإغاثي والمهني الكبير الذي يقوم به الاتحاد، موجها الشكر للأمين العام للاتحاد الدكتور علي أبو سيف على حسن وحفاوة الاستقبال.</p>
<p>وتضمنت جولة وفد نقابة أطباء لبنان بطرابلس، ويتقدمه النقيب وعدد من أعضاء مجلس النقابة، زيارة لقطاع الإغاثة والطوارئ، حيث استمع الوفد للمشروعات التي يقدمها القطاع في المجال الاغاثي والإنساني، حيث يعمل القطاع من خلال ثلاثة محاور رئيسية، هي: المحور الصحي ويشمل القوافل الطبية، والمحور الإغاثي، أما المحور الثالث فهو التنموي من خلال توفير المياه الصالحة للشرب من خلال حفر الآبار الارتوازية والسطحية، كما تفقد الوفد قاعات التدريب بالمعهد العربي للتنمية المهنية المستدامة &#8220;معتمد&#8221;، التابع للاتحاد، وتعرف عن قرب على البرامج التدريبية التي يقدمها المعهد.</p>
<p>وتحدث الدكتور عبد الرحمن كامل، أمين معهد &#8220;معتمد&#8221;، بشكل واف على الدبلومات المهنية والدورات التدريبية التي يقدمها المعهد العربي، مؤكدا أن المعهد يستهدف الارتقاء بالأداء المهني والعلمي للأطباء والعاملين في حقل الرعاية الصحية في الوطن العربي.</p>
<p>وثمن كامل، التعاون المشترك بين المعهد العربي ونقابة أطباء طرابلس، من أجل الارتقاء بالمستوى المهني للأطباء عبر تلبية الاحتياجات التدريبية العلمية المتخصصة المختلفة للأطباء.</p>
<p>بدورهم، أكد أعضاء وفد نقابة أطباء طرابلس، أن الزيارة  جاءت لتعزيز التعاون، والتعرف عن قرب على مستجدات المشروعات والأدوار الإغاثية والإنسانية والمهنية</p>
<p>وأكد الوفد، أن نقابة طرابلس تعتز بعضويتها الفاعلة في اتحاد الأطباء العرب، وتحرص على دعم دوره ورسـالته.</p>
<p>وقال الدكتور إبراهيم المقدسي، نقيب أطباء لبنان بطرابلس، إن زيارتنا إلى القاهرة تأتي في إطار العلاقات الثنائية الراسخة بين النقابة واتحاد الأطباء العرب، وتعزيزا لمسارات التعاون المهني والعلمي المشترك.</p>
<p>وأضاف أن هناك تعاونا تدريبيا قائما بالفعل، حيث يشارك عدد من أطباء طرابلس حاليا في دورات تأهيلية بالقاهرة، مع السعي إلى توسيع هذا المجال بما يخدم التعاون العلمي والمهني بين لبنان ومصر.</p>
<p>وفيما يتعلق بمجالات التعاون الأخرى، أوضح أن التنسيق بين نقابة أطباء لبنان طرابلس واتحاد الأطباء العرب يتم على مستوى عال، في ظل وجود أمين عام مساعد من نقابة أطباء طرابلس، وهو الدكتور أحمد البوش.</p>
<p>وأشار إلى أن هناك تنسيق مستمر في القضايا الإنسانية، وعلى رأسها دعم القطاع الصحي في غزة خلال العدوان الإسرائيلي، إلى جانب التعاون العلمي والتدريبي، في إطار التنمية المهنية للطبيب العربي، كما شدد على أهمية تعزيز مشاركة الأطباء الأكاديميين اللبنانيين في مجلة اتحاد الأطباء العرب.</p>
<p>وأكد أن دور اتحاد الأطباء العرب محوريا وأساسيا، كونه مظلة جامعة تتيح تبادل الخبرات وتوحيد الرؤى، موضحا أن اتساع قاعدة المشاركة العلمية يسهم في الوصول إلى نتائج أكثر دقة واستدامة.</p>
<p>&nbsp;</p>
<p><img loading="lazy" decoding="async" class="alignnone size-medium wp-image-24133" src="https://capsulah.com/wp-content/uploads/2026/01/qg17-300x200.jpeg" alt="" width="300" height="200" title="" srcset="https://capsulah.com/wp-content/uploads/2026/01/qg17-300x200.jpeg 300w, https://capsulah.com/wp-content/uploads/2026/01/qg17-1024x682.jpeg 1024w, https://capsulah.com/wp-content/uploads/2026/01/qg17-768x512.jpeg 768w, https://capsulah.com/wp-content/uploads/2026/01/qg17-1536x1023.jpeg 1536w, https://capsulah.com/wp-content/uploads/2026/01/qg17.jpeg 1600w" sizes="auto, (max-width: 300px) 100vw, 300px" /></p>
<p>وقال الدكتور أحمد البوش، عضو مجلس نقابة أطباء لبنان طرابلس، وأمين صندوق النقابة، والأمين العام المساعد لاتحاد الأطباء العرب،  إن الزيارة الحالية إلى القاهرة تأتي في إطار مهمة رسمية تهدف إلى تعزيز العمل المشترك بين نقابة أطباء لبنان طرابلس واتحاد الأطباء العرب.</p>
<p>وأوضح البوش أن الزيارة الحالية تتم بمشاركة وفد نقابي رفيع يضم  3 نقباء سابقين، إلى جانب عدد من أعضاء مجلس النقابة،، موضحا أن الهدف الأساسي هو ترسيخ التعاون المؤسسي، وزيادة التنسيق المشترك بين النقابة والاتحاد، وبحث سبل تعزيز التعاون مع معهد معتمد في مجالات الدورات والدبلومات، وتنظيم برامج تخصصية متقدمة للأطباء الراغبين في رفع مستواهم العلمي والعملي، تحت إشراف الاتحاد وبالتعاون مع النقابة.</p>
<p>وشدد على أن الزيارة تحمل أيضا رسالة واضحة لدعم الشرعية الحالية لاتحاد الأطباء العرب برئاسة الأمين العام الدكتور علي أبو سيف، مؤكدا الثقة الكاملة في كفاءته العلمية والمهنية والإدارية، وفي مؤسسات الاتحاد المختلفة، والسير على النهج الذي أرساه الراحل الدكتور أسامة رسلان، بهدف تحقيق تنمية علمية ومهنية مستدامة، والارتقاء بالمستوى الطبي والأكاديمي في لبنان ومختلف الدول العربية.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/7124a5a1-f6b5-4b07-8153-370e2c92808a.jpg', 'وفد رسمي من نقابة أطباء لبنان طرابلس يزور مقر اتحاد الأطباء العرب بالقاهرة..', 'وفد رسمي من نقابة أطباء لبنان طرابلس يزور مقر اتحاد الأطباء العرب بالقاهرة..', 'القاهرة – كبسولة الصحية استقبل الأستاذ الدكتور علي أبو سيف، الأمين العام لاتحاد الأطباء العرب،  بمقر الأمانة العامة بدار الحكمة بالقاهرة، أمس الأحد 18 يناير 202', '{"اتحاد الأطباء العرب بالقاهرة","نقابة أطباء لبنان"}', false, 'published', NULL, NULL, '2026-01-19 13:32:42', '2026-01-24 16:23:30.872038', '2026-01-24 16:23:30.872038');
INSERT INTO public.news VALUES ('df78371b-25ad-4e4b-9c4c-781362d5688d', 'f2328aa', 'دراسة كندية: علاجات ضبط السكر والوزن تمنح وقاية عصبية وتفتح آفاقاً جديدة لصحة الدماغ', NULL, 'مونتريال- كبسولة الصحية كشفت دراسة أجرتها جامعة &#8220;ماكغيل&#8221; في كندا، شملت بيانات 450 ألف مريض، أن فئتين من أدوية السكري من النوع الثاني ترتبطان بانخفاض ملحوظ في خطر الإصابة بالخرف. وأظهرت النتائج أن الأدوية التي تعمل على تنظيم هرمونات الجسم الطبيعية لضبط الغلوكوز والشهية ساهمت في خفض احتمال', '<p>مونتريال- كبسولة الصحية</p>
<p>كشفت دراسة أجرتها جامعة &#8220;ماكغيل&#8221; في كندا، شملت بيانات 450 ألف مريض، أن فئتين من أدوية السكري من النوع الثاني ترتبطان بانخفاض ملحوظ في خطر الإصابة بالخرف. وأظهرت النتائج أن الأدوية التي تعمل على تنظيم هرمونات الجسم الطبيعية لضبط الغلوكوز والشهية ساهمت في خفض احتمالات التدهور الإدراكي بنسبة 23%، مما يثبت أن فوائد هذه العلاجات تمتد لحماية الجهاز العصبي ولا تقتصر على ضبط سكر الدم فقط، وهو ما يعد اختراقاً مهماً لمرضى السكري الذين يواجهون عادةً خطراً أعلى للإصابة بالخرف بنسبة 60%.</p>
<p>وأوضحت الدكتورة كريستيل رينو، الباحثة الرئيسية في الدراسة، أن هذه النتائج توفر أدلة قوية على فوائد &#8220;إدراكية&#8221; كانت محل شك لدى العلماء لفترة طويلة، خاصة مع تزايد استخدام هذه الأدوية عالمياً لأغراض إنقاص الوزن.</p>
<p>ويمثل هذا الكشف ركيزة استراتيجية في تحسين جودة الحياة لكبار السن؛ حيث يساهم اختيار بروتوكولات علاجية ذكية للسكري في ضرب عصفورين بحجر واحد: السيطرة على المرض المزمن وحماية الذاكرة من ألزهايمر.</p>
<p>إن هذا التوجه يعزز كفاءة المنظومة الصحية عبر تقليل الأعباء الاقتصادية والاجتماعية المرتبطة برعاية مرضى الخرف، ويصون القدرات الذهنية للمجتمع، مما يضمن شيخوخة آمنة ومستقلة بعيداً عن التدهور العقلي.</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/dfbe34f5-a7b2-4aac-8307-e4a39708a197.webp', 'دراسة كندية: علاجات ضبط السكر والوزن تمنح وقاية عصبية وتفتح آفاقاً جديدة لصحة الدماغ', 'دراسة كندية: علاجات ضبط السكر والوزن تمنح وقاية عصبية وتفتح آفاقاً جديدة لصحة الدماغ', 'مونتريال- كبسولة الصحية كشفت دراسة أجرتها جامعة &#8220;ماكغيل&#8221; في كندا، شملت بيانات 450 ألف مريض، أن فئتين من أدوية السكري من النوع الثاني ترتبطان بانخفاض', '{الخرف,السكري,"صحة الدماغ"}', false, 'published', NULL, NULL, '2026-01-19 01:53:48', '2026-01-24 16:23:32.643959', '2026-01-24 16:23:32.643959');
INSERT INTO public.news VALUES ('8bf84542-756a-4c1e-bfdd-79534291b85e', 'de60666', '"الفخ الوردي": مخدر "إنستغرامي" يغزو نوادي أمريكا', NULL, 'كبسولة الصحية &#8211; وكالات يمثل مخدر &#8220;الكوكايين الوردي&#8221; أو ما يُعرف بـ &#8220;توسي&#8221; (Tusi)، أحدث موجات التهديد الكيميائي في الولايات المتحدة، حيث يغزو النوادي الليلية ومنصات التواصل الاجتماعي كخليط &#8220;غير مستقر&#8221; يفتقر في معظم عينات ضبطه إلى الكوكايين الحقيقي، مستدرجاً ا', '<p>كبسولة الصحية &#8211; وكالات</p>
<p>يمثل مخدر &#8220;الكوكايين الوردي&#8221; أو ما يُعرف بـ &#8220;توسي&#8221; (Tusi)، أحدث موجات التهديد الكيميائي في الولايات المتحدة، حيث يغزو النوادي الليلية ومنصات التواصل الاجتماعي كخليط &#8220;غير مستقر&#8221; يفتقر في معظم عينات ضبطه إلى الكوكايين الحقيقي، مستدرجاً الشباب بلونه الجذاب الذي يجعله مادة &#8220;قابلة للنشر على إنستغرام&#8221;.</p>
<p>تصاعدت عمليات ضبط هذا المسحوق الوردي من لوس أنجلوس إلى ميامي، مسجلةً حضوراً لافتاً في قضايا تهريب كبرى بنيويورك ومداهمات لنوادٍ سرية في كولورادو. هذا المخدر هو &#8220;استيراد لفكرة&#8221; نشأت في كولومبيا، تعتمد على مزج عشوائي لمواد منشطة ومثبطة وأفيونية؛ حيث يكشف التحليل المخبري غالباً عن وجود الكيتامين والإكستاسي، الممزوجين أحياناً بـ &#8220;الميثامفيتامين&#8221; أو &#8220;الفنتانيل&#8221; القاتل. وقد ارتبط اسم هذا المخدر مؤخراً بحالات وفاة مأساوية لشخصيات معروفة، من بينهم المغني ليام باين، مما كشف عن اتساع رقعة انتشاره بين رواد موسيقى الرقص الإلكتروني بنسبة وصلت إلى 2.7% في نيويورك وحدها.</p>
<p>تكمن الخطورة الفائقة لـ &#8220;الكوكايين الوردي&#8221; في كونه مخبراً كيميائياً مفتوحاً بلا صيغة قياسية، فلا توجد دفعتان متطابقتان منه، مما يجعل خطر الجرعة الزائدة في أعلى مستوياته. المتعاطون غالباً ما يقعون في فخ &#8220;الوهم البصري&#8221; للصبغة الوردية، معتقدين أنهم يتناولون مهلوسات خفيفة، بينما هم في الواقع يستهلكون تركيبات خطيرة تهاجم القلب والدماغ والتنفس في آن واحد. ويؤكد الأطباء أن هذا الخليط المعقد يفتقر إلى وجود &#8220;ترياق&#8221; محدد، مما يترك الفرق الطبية أمام خيار وحيد وهو دعم الوظائف الحيوية للمريض وانتظار زوال مفعول السموم، وهو رهان قد ينتهي بالموت في حالات كثيرة.</p>
<p>تتجه السلطات الأمريكية نحو تشديد الرقابة على الأسواق الإلكترونية التي تروج للمخدر في أكياس مخصصة، مع إطلاق حملات توعية مكثفة تستهدف الفئات العمرية الصغيرة والمناطق الريفية التي بدأ المخدر يتسلل إليها. ومن المتوقع أن تبدأ الوكالات الأمنية في ضرب مواقع الإنتاج والتهريب المرتبطة بالعصابات العابرة للحدود، خاصة مع ظهور مؤشرات على تحول هذا المخدر من مجرد &#8220;سلعة مهربة&#8221; إلى &#8220;ثقافة عابرة للقارات&#8221; يتم تصنيعها محلياً بمواد متاحة، مما يصعب ملاحقة سلاسل الإمداد التقليدية.</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/3a873734-a0d5-4817-aee5-34ce314fa205.jpg', '&#8220;الفخ الوردي&#8221;: مخدر &#8220;إنستغرامي&#8221; يغزو نوادي أمريكا', '&#8220;الفخ الوردي&#8221;: مخدر &#8220;إنستغرامي&#8221; يغزو نوادي أمريكا', 'كبسولة الصحية &#8211; وكالات يمثل مخدر &#8220;الكوكايين الوردي&#8221; أو ما يُعرف بـ &#8220;توسي&#8221; (Tusi)، أحدث موجات التهديد الكيميائي في الولايات المتحدة', '{أمريكا,"الكوكايين الوردي"}', false, 'published', NULL, NULL, '2026-01-15 00:34:52', '2026-01-24 16:23:47.489767', '2026-01-24 16:23:47.489767');
INSERT INTO public.news VALUES ('c4c3a4ae-8d74-42f7-8846-33b19ff9b89c', 'caece17', 'تنبيه عصبي: الصداع والدوخة قد يكشفان تضيق أوعية الرقبة', NULL, 'كبسولة الصحية &#8211; جازيت حذر الدكتور كيريل المازوف، أخصائي طب الأعصاب، من أن أعراضاً شائعة مثل الصداع المتكرر، والدوخة، وطنين الأذن، وفقدان البصر المفاجئ، ليست دائماً نتيجة للإرهاق، بل قد تكون مؤشرات خطيرة على تضيق الأوعية الدموية في الرقبة. وأوضح أن ضعف التركيز وصعوبة تذكر المعلومات الجديدة يعدا', '<p>كبسولة الصحية &#8211; جازيت</p>
<p>حذر الدكتور كيريل المازوف، أخصائي طب الأعصاب، من أن أعراضاً شائعة مثل الصداع المتكرر، والدوخة، وطنين الأذن، وفقدان البصر المفاجئ، ليست دائماً نتيجة للإرهاق، بل قد تكون مؤشرات خطيرة على تضيق الأوعية الدموية في الرقبة. وأوضح أن ضعف التركيز وصعوبة تذكر المعلومات الجديدة يعدان علامات تحذيرية لنقص وصول الأكسجين والمواد المغذية للدماغ بسبب انسداد أو تضيق الشرايين، مما يستوجب إجراء فحص بالموجات فوق الصوتية لتقييم تدفق الدم وحالة الأوعية الدماغية.</p>
<p>وأشار المازوف إلى أن بروتوكول العلاج يتحدد بناءً على نتائج الفحص؛ فوجود لويحات تصلب الشرايين يستدعي تدخلاً من أطباء القلب لضبط الكوليسترول، بينما قد تتطلب حالات التضيق التي تتجاوز 70% تدخلاً جراحياً فورياً لمنع الانسداد، أما في الحالات الناتجة عن تشنجات عضلية، فيتم الاعتماد على الأدوية المحفزة للدورة الدموية والتمارين العلاجية.</p>
<p>ويمثل هذا التوجه الطبي ركيزة في &#8220;الوقاية من السكتات الدماغية&#8221;؛ حيث يساهم التشخيص المبكر لأوعية الرقبة في تلافي مخاطر جسيمة، مما يعزز كفاءة المنظومة الصحية ويصون القدرات الذهنية والبدنية للأفراد، ويحول دون تفاقم مشكلات بسيطة إلى أزمات صحية معقدة.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/a0f971d1-53c8-4f84-ac00-92fdfd24bdd3.jpg', 'تنبيه عصبي: الصداع والدوخة قد يكشفان تضيق أوعية الرقبة', 'تنبيه عصبي: الصداع والدوخة قد يكشفان تضيق أوعية الرقبة', 'كبسولة الصحية &#8211; جازيت حذر الدكتور كيريل المازوف، أخصائي طب الأعصاب، من أن أعراضاً شائعة مثل الصداع المتكرر، والدوخة، وطنين الأذن، وفقدان البصر المفاجئ، لي', '{الدوخة,الصداع,"ضيق الأوعية"}', false, 'published', NULL, NULL, '2026-01-19 01:00:08', '2026-01-24 16:23:32.984481', '2026-01-24 16:23:32.984481');
INSERT INTO public.news VALUES ('9db1f0b0-8412-4d1a-a8be-d5e5bbff85c5', 'adeb906', 'انقطاع الطمث ليس سبباً للسكري.. نمط الحياة هو المتهم الحقيقي', NULL, 'لندن- كبسولة الصحية نسفت دراسة طبية واسعة النطاق، شملت بيانات 147 ألف امرأة، الاعتقاد الشائع بأن انقطاع الطمث يزيد من خطر الإصابة بمرض السكري. وأثبت الباحثون بعد متابعة استمرت لأكثر من 14 عاماً أن الارتباط الإحصائي بين غياب الدورة الشهرية والسكري يتلاشى تماماً عند مراعاة عوامل أخرى، مؤكدين أن المسبب', '<p>لندن- كبسولة الصحية</p>
<p>نسفت دراسة طبية واسعة النطاق، شملت بيانات 147 ألف امرأة، الاعتقاد الشائع بأن انقطاع الطمث يزيد من خطر الإصابة بمرض السكري.</p>
<p>وأثبت الباحثون بعد متابعة استمرت لأكثر من 14 عاماً أن الارتباط الإحصائي بين غياب الدورة الشهرية والسكري يتلاشى تماماً عند مراعاة عوامل أخرى، مؤكدين أن المسببات الحقيقية هي السمنة، والتدخين، وارتفاع استهلاك الملح، وانخفاض تناول الخضروات، بالإضافة إلى بعض الأدوية المخفضة للكوليسترول.</p>
<p>وتعد هذه النتائج مشجعة في سياق الصحة النسائية؛ إذ تشير إلى أن العوامل المسببة للمرض يمكن التحكم بها وتغييرها، على عكس التغيرات الهرمونية الفطرية التي لا يمكن تجنبها.</p>
<p>ويمثل هذا الكشف ركيزة في تعزيز &#8220;الوعي الصحي الاستباقي&#8221;؛ حيث يوجه الجهود نحو تحسين جودة الحياة عبر النشاط البدني والغذاء المتوازن بدلاً من القلق من مراحل النمو الطبيعية. إن التركيز على تصحيح الأنماط السلوكية يساهم في بناء مجتمع يتمتع بوقاية عالية ويقلل من الأعباء الصحية المرتبطة بالأمراض المزمنة، مما يضمن للمرأة حياة صحية ومستقرة في كافة مراحلها العمرية.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/3d416f59-6d10-4ba6-b625-351c64ead960.jpg', 'انقطاع الطمث ليس سبباً للسكري.. نمط الحياة هو المتهم الحقيقي', 'انقطاع الطمث ليس سبباً للسكري.. نمط الحياة هو المتهم الحقيقي', 'لندن- كبسولة الصحية نسفت دراسة طبية واسعة النطاق، شملت بيانات 147 ألف امرأة، الاعتقاد الشائع بأن انقطاع الطمث يزيد من خطر الإصابة بمرض السكري. وأثبت الباحثون بع', '{التدخين,السكري,الملح,"انقطاع الطمث"}', false, 'published', NULL, NULL, '2026-01-19 00:56:08', '2026-01-24 16:23:33.320315', '2026-01-24 16:23:33.320315');
INSERT INTO public.news VALUES ('4e27a42f-099a-428c-ac9f-a90ed308e389', '77288f9', 'خطر "الكرسي": الجلوس الطويل يعطل ضخ الدم ويسبب دوالي الساقين', NULL, 'موسكو- كبسولة الصحية حذر الدكتور أوليمي شيرينبيك، أخصائي جراحة الأوردة، من أن العمل المكتبي لساعات طويلة أمام الكمبيوتر يضعف عضلات الساقين ويعطل تدفق الدم الطبيعي نحو القلب، مما يؤدي إلى توسع الأوردة وظهور الدوالي. وأوضح أن خمول العضلات يتسبب في فقدان جدران الأوعية لمرونتها وتلف صماماتها، وهو ما يظه', '<p>موسكو- كبسولة الصحية</p>
<p>حذر الدكتور أوليمي شيرينبيك، أخصائي جراحة الأوردة، من أن العمل المكتبي لساعات طويلة أمام الكمبيوتر يضعف عضلات الساقين ويعطل تدفق الدم الطبيعي نحو القلب، مما يؤدي إلى توسع الأوردة وظهور الدوالي.</p>
<p>وأوضح أن خمول العضلات يتسبب في فقدان جدران الأوعية لمرونتها وتلف صماماتها، وهو ما يظهر في البداية على شكل ثقل وتورم في الساقين، وقد يتطور إلى تشنجات ليلية وخطورة تكوّن جلطات دموية.</p>
<p>وللوقاية من هذه المخاطر، شدد الطبيب على ضرورة النهوض والمشي دورياً، وتجنب وضع ساق فوق الأخرى، مع ممارسة تمارين بسيطة للقدمين أثناء الجلوس.</p>
<p>وفي حال وقوع الإصابة، أشار شيرينبيك إلى توفر تقنيات علاجية حديثة تعتمد على &#8220;اللاصق الحيوي&#8221; الذي يستغرق 20 دقيقة فقط دون حاجة لتخدير أو جراحة معقدة. ويمثل هذا التوجه نحو &#8220;الوقاية الحركية&#8221; ركيزة أساسية في جودة الحياة المهنية عام 2026؛ فالحفاظ على كفاءة الجهاز الوريدي يقلل من الغياب المرضي ويرفع من حيوية الكوادر البشرية، مما يضمن استمرارية العطاء البدني والذهني بعيداً عن مضاعفات أمراض العصر المرتبطة بالخمول.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/b54168a7-419e-4bc5-a97e-f1d129400746.jpg', 'خطر &#8220;الكرسي&#8221;: الجلوس الطويل يعطل ضخ الدم ويسبب دوالي الساقين', 'خطر &#8220;الكرسي&#8221;: الجلوس الطويل يعطل ضخ الدم ويسبب دوالي الساقين', 'موسكو- كبسولة الصحية حذر الدكتور أوليمي شيرينبيك، أخصائي جراحة الأوردة، من أن العمل المكتبي لساعات طويلة أمام الكمبيوتر يضعف عضلات الساقين ويعطل تدفق الدم الطبي', '{"الجلوس الطويل","دوالي الساقين"}', false, 'published', NULL, NULL, '2026-01-19 00:29:27', '2026-01-24 16:23:33.636058', '2026-01-24 16:23:33.636058');
INSERT INTO public.news VALUES ('3fb4bf07-45d2-4771-ae1c-7046b99fd7b3', '91c533a', 'خزان المناعة الخفي.. الزائدة الدودية "مستودع" للبكتيريا النافعة وليست عضواً زائداً', NULL, 'كبسولة الصحية &#8211; وكالات نسفت الدراسات الطبية الحديثة الاعتقاد الشائع بأن الزائدة الدودية عضو &#8220;عديم الفائدة&#8221;، مؤكدة أنها تلعب دوراً حيوياً كمستودع استراتيجي للبكتيريا النافعة التي تشكل &#8220;ميكروبيوم&#8221; الأمعاء. وأوضحت الأبحاث أن هذا النتوء الصغير يعمل كمركز طوارئ لإعادة توازن ', '<p>كبسولة الصحية &#8211; وكالات</p>
<p>نسفت الدراسات الطبية الحديثة الاعتقاد الشائع بأن الزائدة الدودية عضو &#8220;عديم الفائدة&#8221;، مؤكدة أنها تلعب دوراً حيوياً كمستودع استراتيجي للبكتيريا النافعة التي تشكل &#8220;ميكروبيوم&#8221; الأمعاء. وأوضحت الأبحاث أن هذا النتوء الصغير يعمل كمركز طوارئ لإعادة توازن البيئة المعوية بعد الإصابة بالالتهابات أو تناول المضادات الحيوية التي قد تدمر البكتيريا الصديقة، كما تحتوي على أنسجة لمفاوية كثيفة تساهم في تطوير منظومة المناعة وإنتاج الأجسام المضادة، خاصة في مراحل الحياة المبكرة.</p>
<p>ورغم قدرة الجسم على التعويض في حال استئصالها، إلا أن غيابها قد يؤدي أحياناً إلى اختلال توازن البكتيريا أو تكرار الالتهابات المعوية نتيجة فقدان هذا المخزون الطبيعي. ويمثل هذا الكشف العلمي دعوة لتعزيز &#8220;الثقافة الوقائية&#8221; وتجنب التدخلات الجراحية غير الضرورية؛ حيث يثبت العلم يوماً بعد آخر أن جسم الإنسان منظومة متكاملة لا تحتوي على أجزاء &#8220;زائدة&#8221; بلا وظيفة. إن فهم هذه الوظائف الخفية يساهم في تحسين جودة الحياة الصحية ويقلل من الأعباء الناتجة عن اختلال الجهاز الهضمي، مما يرسخ مفهوم &#8220;السيادة الجسدية&#8221; القائم على الحفاظ على تكامل الأعضاء الحيوية ووظائفها الفطرية.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/1b145388-35cf-4897-9928-3688f6e3fccb.jpg', 'خزان المناعة الخفي.. الزائدة الدودية &#8220;مستودع&#8221; للبكتيريا النافعة وليست عضواً زائداً', 'خزان المناعة الخفي.. الزائدة الدودية &#8220;مستودع&#8221; للبكتيريا النافعة وليست عضواً زائداً', 'كبسولة الصحية &#8211; وكالات نسفت الدراسات الطبية الحديثة الاعتقاد الشائع بأن الزائدة الدودية عضو &#8220;عديم الفائدة&#8221;، مؤكدة أنها تلعب دوراً حيوياً كمستو', '{"البكتيريا النافعة","الزائدة الدودية"}', false, 'published', NULL, NULL, '2026-01-19 00:23:17', '2026-01-24 16:23:34.282167', '2026-01-24 16:23:34.282167');
INSERT INTO public.news VALUES ('98843da3-8b62-405c-8464-293316ada606', '194bee0', '"هيئة الطيران المدني" تمنح مستشفى التخصصي أول رخصة لنقل المستحضرات الصيدلانية المشعّة جوًا', NULL, 'كبسولة الصحية &#8211;  واس في إنجاز نوعي يعكس تطور الأطر التنظيمية والتكامل الإستراتيجي بين قطاعي الطيران والصحة، أعلنت الهيئة العامة للطيران المدني، منح مستشفى الملك فيصل التخصصي ومركز الأبحاث شهادة ترخيص إعداد المواد الخطرة (DGPC)، ليصبح بذلك أول مستشفى في المملكة يُرخص له رسميًا لإعداد ونقل المست', '<p>كبسولة الصحية &#8211;  واس</p>
<p>في إنجاز نوعي يعكس تطور الأطر التنظيمية والتكامل الإستراتيجي بين قطاعي الطيران والصحة، أعلنت الهيئة العامة للطيران المدني، منح مستشفى الملك فيصل التخصصي ومركز الأبحاث شهادة ترخيص إعداد المواد الخطرة (DGPC)، ليصبح بذلك أول مستشفى في المملكة يُرخص له رسميًا لإعداد ونقل المستحضرات الصيدلانية المشعة عبر الجو، وذلك لامتلاكه منشآت متخصصة لإنتاج المستحضرات الصيدلانية المشعّة وفق أعلى المعايير المعتمدة.</p>
<p>وجرى إصدار الشهادة، وفقًا للائحة التنفيذية لسلامة الطيران المدني (الجزء 109)، وبعد استيفاء المستشفى لجميع الاشتراطات والمعايير الفنية واللوجستية العالمية؛ مما يضمن أعلى درجات السلامة والامتثال للأنظمة المحلية والدولية في نقل هذه المواد الحساسة.</p>
<p>وتكتسب هذه الرخصة أهمية نظرًا لطبيعة &#8220;المستحضرات الصيدلانية المشعة&#8221; المستخدمة في أقسام الطب النووي والتصوير المقطعي، إذ تهدف الخطوة إلى تحقيق عدد من الأهداف منها: كسر حاجز الوقت بتسريع عمليات النقل الجوي للمستحضرات المشعة من الرياض إلى مختلف مناطق المملكة، نظرًا لمحدودية مدة صلاحيتها (قصر عمر النصف الإشعاعي)؛ مما يضمن وصولها في الوقت المناسب للمرضى، ودعم منظومة الطب النووي بتلبية الاحتياجات المتزايدة للمستشفيات في المملكة وضمان استمرارية الخدمات التشخيصية والعلاجية المتقدمة وفق أعلى كفاءة، إلى جانب رفع كفاءة المنظومة الصحية من خلال تقليل الاعتماد على النقل البري الطويل وتعزيز الاعتماد على الشبكة الجوية؛ لضمان جودة وفعالية المواد الطبية الحيوية.</p>
<p>وأكَّد نائب الرئيس التنفيذي لسلامة الطيران والاستدامة البيئية الكابتن سليمان بن صالح المحيميدي، التزام الهيئة من خلال هذا المنح بدورها كمُمكن للجهات الوطنية، عبر توفير البيئة التنظيمية والتشريعية التي تسمح بنقل المواد الخطرة والطبية وفق أعلى معايير الأمان العالمية، مُشيرًا إلى أن هذا التعاون مع مستشفى الملك فيصل التخصصي يُجسد نموذجًا للعمل التكاملي الذي يسهم في تحقيق مستهدفات رؤية المملكة 2030 في قطاعي الصحة والنقل اللوجستي.</p>
<p>من جانبها أوضحت المديرة التنفيذية للأبحاث والابتكار في مستشفى الملك فيصل التخصصي ومركز الأبحاث الدكتورة جاكي ينغ، أن الحصول على هذا الترخيص يعكس جاهزية المستشفى وقدراته التقنية والبشرية للتعامل مع المستحضرات الطبية عالية الحساسية، مشيرةً إلى أن قسم السايكلوترون والمستحضرات الصيدلانية المشعّة أنتج أكثر من ثلاثين مستحضرًا، وقدّم ما يزيد على 800 ألف جرعة.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/5df56874-46e4-4dd9-92b9-88fac786c615.webp', '&#8220;هيئة الطيران المدني&#8221; تمنح مستشفى التخصصي أول رخصة لنقل المستحضرات الصيدلانية المشعّة جوًا', '&#8220;هيئة الطيران المدني&#8221; تمنح مستشفى التخصصي أول رخصة لنقل المستحضرات الصيدلانية المشعّة جوًا', 'كبسولة الصحية &#8211;  واس في إنجاز نوعي يعكس تطور الأطر التنظيمية والتكامل الإستراتيجي بين قطاعي الطيران والصحة، أعلنت الهيئة العامة للطيران المدني، منح مستشفى', '{"مستشفى الملك فيصل التخصصي ومركز الأبحاث","هيئة الطيران المدني"}', false, 'published', NULL, NULL, '2026-01-18 20:03:40', '2026-01-24 16:23:36.646016', '2026-01-24 16:23:36.646016');
INSERT INTO public.news VALUES ('83fd40c0-8526-476c-8714-7b60c5c35e30', 'f5f750e', 'بين الطبيعة والمرض.. ماذا تخفي برودة اليدين والقدمين المستمرة؟', NULL, 'موسكو- كبسولة الصحية أوضح الدكتور أندريه كوندراخين أن استمرار برودة اليدين والقدمين قد يندرج ضمن الحالات الطبيعية لبعض الفئات، مثل النساء نتيجة تفوق فقدان الحرارة على إنتاجها، وحديثي الولادة بسبب ضعف تنظيم حرارة أجسامهم، وكبار السن نتيجة بطء عمليات الأيض. ورغم ذلك، حذر كوندراخين من أن هذه الظاهرة قد', '<p>موسكو- كبسولة الصحية</p>
<p>أوضح الدكتور أندريه كوندراخين أن استمرار برودة اليدين والقدمين قد يندرج ضمن الحالات الطبيعية لبعض الفئات، مثل النساء نتيجة تفوق فقدان الحرارة على إنتاجها، وحديثي الولادة بسبب ضعف تنظيم حرارة أجسامهم، وكبار السن نتيجة بطء عمليات الأيض. ورغم ذلك، حذر كوندراخين من أن هذه الظاهرة قد تكون &#8220;عرضاً تحذيرياً&#8221; لأمراض خطيرة تستوجب العلاج، وفي مقدمتها فقر الدم، وقصور القلب المزمن، وأمراض الرئة، أو حتى حالات التسمم.</p>
<p>ولمواجهة هذه البرودة، نصح الخبير باتباع أساليب عملية تشمل ارتداء الملابس والجوارب الصوفية التي لا تضغط على الأطراف، مع التركيز على المشروبات والأطعمة الساخنة مثل الشاي العشبي والمرق، لما لها من &#8220;تأثير ديناميكي&#8221; يساعد في توزيع الحرارة بكافة أنحاء الجسم.</p>
<p>ويمثل هذا الوعي الطبي ركيزة في &#8220;الإدارة الذاتية للصحة&#8221;؛ حيث تساهم التفرقة بين البرودة الطبيعية والمرضية في الكشف المبكر عن اضطرابات الدورة الدموية، مما يضمن تدخلاً طبياً استباقياً يصون سلامة المنظومة الجسدية ويمنع تفاقم الأمراض الكامنة خلف مظهر بسيط مثل برودة الأطراف.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/b4e74238-6993-4bdc-a7c7-1b9fe6df8eef.jpg', 'بين الطبيعة والمرض.. ماذا تخفي برودة اليدين والقدمين المستمرة؟', 'بين الطبيعة والمرض.. ماذا تخفي برودة اليدين والقدمين المستمرة؟', 'موسكو- كبسولة الصحية أوضح الدكتور أندريه كوندراخين أن استمرار برودة اليدين والقدمين قد يندرج ضمن الحالات الطبيعية لبعض الفئات، مثل النساء نتيجة تفوق فقدان الحرا', '{الأيض,النساء,"برودة اليدين والقدمين","حرارة الجسم","كبار السن"}', false, 'published', NULL, NULL, '2026-01-18 00:27:03', '2026-01-24 16:23:37.297338', '2026-01-24 16:23:37.297338');
INSERT INTO public.news VALUES ('38250847-4916-4095-baf0-461a14e380db', 'a296b20', 'بصمة الخلايا المفردة: تقنية مجهرية متطورة تنهي "مراوغة" البكتيريا للمضادات الحيوية', NULL, 'بازل- كبسولة الصحية ابتكر علماء في جامعة بازل السويسرية طريقة اختبار دقيقة تُعرف باسم &#8220;اختبار الخلايا المفردة المضاد للميكروبات&#8221;، تهدف إلى حل معضلة بقاء البكتيريا حية رغم تناول المضادات الحيوية. وتعتمد التقنية الجديدة على استخدام مجهر متطور لمراقبة ملايين البكتيريا بشكل فردي وعلى مدار عد', '<p>بازل- كبسولة الصحية</p>
<p>ابتكر علماء في جامعة بازل السويسرية طريقة اختبار دقيقة تُعرف باسم &#8220;اختبار الخلايا المفردة المضاد للميكروبات&#8221;، تهدف إلى حل معضلة بقاء البكتيريا حية رغم تناول المضادات الحيوية. وتعتمد التقنية الجديدة على استخدام مجهر متطور لمراقبة ملايين البكتيريا بشكل فردي وعلى مدار عدة أيام، لتحديد الأدوية القادرة على القضاء التام على العدوى، بدلاً من مجرد إيقاف نموها مؤقتاً، مما يمنع البكتيريا &#8220;الخاملة&#8221; من النشاط مجدداً وإعادة العدوى بعد انتهاء العلاج.</p>
<p>وأثبت الفريق البحثي كفاءة هذه الطريقة عبر اختبار 65 تركيبة دوائية ضد بكتيريا السل، بالإضافة إلى عينات من 400 مريض يعانون من عدوى رئوية حادة. وتسمح هذه التقنية بتصميم بروتوكولات علاجية مخصصة لسلالات البكتيريا لدى كل مريض على حدة، مما يرفع من دقة النتائج ويقلص فترات العلاج الطويلة. ويمثل هذا الابتكار ركيزة استراتيجية في تعزيز أمان المنظومة الصحية؛ حيث يساهم في الحد من &#8220;المقاومة البكتيرية&#8221; ويضمن كفاءة الإنفاق الدوائي عبر اختيار المضاد الحيوي القاتل بدقة منذ المرة الأولى، مما يصون القوة البشرية ويحميها من تبعات العدوى المزمنة والمتكررة.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/2ce43053-5160-4bbf-a4ef-5467b6555582.webp', 'بصمة الخلايا المفردة: تقنية مجهرية متطورة تنهي &#8220;مراوغة&#8221; البكتيريا للمضادات الحيوية', 'بصمة الخلايا المفردة: تقنية مجهرية متطورة تنهي &#8220;مراوغة&#8221; البكتيريا للمضادات الحيوية', 'بازل- كبسولة الصحية ابتكر علماء في جامعة بازل السويسرية طريقة اختبار دقيقة تُعرف باسم &#8220;اختبار الخلايا المفردة المضاد للميكروبات&#8221;، تهدف إلى حل معضلة ', '{البكتيريا,"المضادات الحيوية","بصمة الخلايا المفردة"}', false, 'published', NULL, NULL, '2026-01-18 00:24:24', '2026-01-24 16:23:37.629672', '2026-01-24 16:23:37.629672');
INSERT INTO public.news VALUES ('8a7a5ea4-1c34-4583-95e6-8076cab586c0', '8830c33', 'صمام أمان حيوي: عدد أسنانك السليمة "المؤشر الذهبي" للتنبؤ بطول العمر', NULL, 'أوساكا- كبسولة الصحية كشفت دراسة طبية ضخمة أجراها باحثون من جامعة أوساكا اليابانية، شملت أكثر من 190 ألف شخص، أن عدد الأسنان السليمة يمثل مؤشراً دقيقاً للتنبؤ بخطر الوفاة المبكرة، مما يحول &#8220;طب الأسنان الوقائي&#8221; إلى ركيزة استراتيجية لخفض معدلات الوفيات المرتبطة بالأمراض المزمنة. وخلصت نتائ', '<p><strong>أوساكا- كبسولة الصحية</strong></p>
<p>كشفت دراسة طبية ضخمة أجراها باحثون من جامعة أوساكا اليابانية، شملت أكثر من 190 ألف شخص، أن عدد الأسنان السليمة يمثل مؤشراً دقيقاً للتنبؤ بخطر الوفاة المبكرة، مما يحول &#8220;طب الأسنان الوقائي&#8221; إلى ركيزة استراتيجية لخفض معدلات الوفيات المرتبطة بالأمراض المزمنة. وخلصت نتائج الدراسة المنشورة في دورية &#8220;BMC Oral Health&#8221; إلى أن الحفاظ على الأسنان كاملة يقلل من مخاطر الوفاة لأي سبب كان، بينما يبرز فقدانها كجرس إنذار لضعف وظيفي عام ناتج عن التهابات كامنة تنتشر عبر مجرى الدم لتصيب أعضاء حيوية مثل القلب والدماغ.</p>
<p>وأثبتت الدراسة أن دمج عدد الأسنان السليمة والمحشوة معاً هو &#8220;المؤشر الذهبي&#8221; لطول العمر، مما يؤكد أن الاستثمار في ترميم الأسنان المتهالكة يمنح الجسد استقراراً وظيفياً يماثل الأسنان الطبيعية ويحمي المنظومة الصحية من ضغط الأمراض المعقدة. ويرجع العلماء هذا الارتباط الوثيق إلى دور الفم كبوابة أولى للصحة؛ حيث يؤدي فقدان الأسنان إلى سوء التغذية وتراجع جودة الحياة، بينما ترفع أمراض اللثة والنزيف المتكرر مخاطر الإصابة بالنوبات القلبية والسكتات الدماغية بنسبة تصل إلى 86%، بالإضافة إلى وجود رابط وثيق بين سوء صحة الفم وتراجع القدرات الإدراكية المؤدية للزهايمر.</p>
<p>وتأتي هذه النتائج لتعزز من أهمية &#8220;الإدارة الاستباقية للصحة&#8221;؛ حيث لم يعد تنظيف الفم مجرد طقس تجميلي، بل هو إجراء وقائي يقلل من الحاجة للتدخلات الجراحية والعلاجات المكلفة في الكبر.</p>
<p>إن هذا الوعي الطبي يساهم في بناء مجتمع يتمتع بجودة حياة عالية ويقلل من الأعباء الاقتصادية المترتبة على إهمال الرعاية الأولية للفم، مما يجعل من &#8220;كرسي طبيب الأسنان&#8221; خط دفاع أول لصيانة القوة البشرية وإطالة العمر الصحي للأفراد.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/879ce958-6f73-4db3-98ef-96cee6aeaf71.webp', 'صمام أمان حيوي: عدد أسنانك السليمة &#8220;المؤشر الذهبي&#8221; للتنبؤ بطول العمر', 'صمام أمان حيوي: عدد أسنانك السليمة &#8220;المؤشر الذهبي&#8221; للتنبؤ بطول العمر', 'أوساكا- كبسولة الصحية كشفت دراسة طبية ضخمة أجراها باحثون من جامعة أوساكا اليابانية، شملت أكثر من 190 ألف شخص، أن عدد الأسنان السليمة يمثل مؤشراً دقيقاً للتنبؤ ب', '{"الصحة العامة","صحة الأسنان","طول العمر"}', false, 'published', NULL, NULL, '2026-01-18 00:22:07', '2026-01-24 16:23:38.035221', '2026-01-24 16:23:38.035221');
INSERT INTO public.news VALUES ('012ebfa0-2eb2-4301-8545-7b40b1698f7b', '1af4446', 'جلد "ذكي" يتوهج بالأخضر.. إنذار بيولوجي مبكر يكشف الأمراض الصامتة', NULL, 'طوكيو – كبسولة الصحية نجح فريق بحثي من جامعة مدينة طوكيو في تطوير نسيج جلدي حي مهندس وراثياً يعمل كجهاز إنذار بيولوجي، حيث يتوهج باللون الأخضر الساطع عند رصد أي التهاب داخل الجسم. ويعتمد هذا الابتكار على تعديل الخلايا الجذعية الجلدية البشرية لتنتج بروتيناً فلورياً بمجرد استشعار جزيئات التهابية ناتجة', '<p>طوكيو – كبسولة الصحية</p>
<p>نجح فريق بحثي من جامعة مدينة طوكيو في تطوير نسيج جلدي حي مهندس وراثياً يعمل كجهاز إنذار بيولوجي، حيث يتوهج باللون الأخضر الساطع عند رصد أي التهاب داخل الجسم. ويعتمد هذا الابتكار على تعديل الخلايا الجذعية الجلدية البشرية لتنتج بروتيناً فلورياً بمجرد استشعار جزيئات التهابية ناتجة عن استجابات مناعية.</p>
<p>وفي التجارب التي أُجريت على الفئران، استمرت رقعة الجلد -التي تماثل حجم عملة معدنية- في العمل لأكثر من 200 يوم دون الحاجة لبطاريات أو صيانة، حيث جددت الخلايا نفسها طبيعياً وحافظت على قدرتها على الإضاءة خلال 24 ساعة من تحفيز الالتهاب.</p>
<p>تكمن أهمية هذا الابتكار في قدرته على العمل كـ &#8220;كاشف دخان بيولوجي&#8221; يرصد الإشارات الالتهابية التي تتراكم بصمت في الجسم قبل ظهور الأعراض السريرية الواضحة. وقد أثبتت التجارب المخبرية أن شدة التوهج تتناسب طردياً مع مستوى النشاط الالتهابي؛ فكلما زاد الالتهاب زاد سطوع اللون الأخضر، مما يوفر قراءة حية وفورية للحالة الصحية للمريض. هذا النظام يفتح الباب أمام مراقبة الأمراض المزمنة بدقة فائقة، متجاوزاً عقبات الأجهزة الإلكترونية التقليدية التي تتطلب مصادر طاقة خارجية أو تبدي رفضاً مناعياً من الجسم.</p>
<p>رغم أن التطبيقات البشرية قد تستغرق عدة سنوات، إلا أن العلماء نجحوا بالفعل في بناء نسيج جلدي حقيقي يحاكي وظائف الجلد الطبيعي عبر دمج الخلايا المعدلة مع مكونات جلدية أخرى. ويتمثل الهدف المستقبلي في تحويل ممارسة الطب من &#8220;رد الفعل&#8221; وعلاج الأعراض الظاهرة إلى &#8220;الاستباق&#8221; واكتشاف المشكلات في مراحلها المبكرة القابلة للعلاج الجذري. وسيعمل الباحثون في المرحلة القادمة على ضبط التركيب الجيني لضمان استمرارية التوهج بدقة أعلى ولمدد أطول، تمهيداً لاختبارها كرقاقات بيولوجية ذكية يمكن زرعها لدى الفئات الأكثر عرضة للأمراض الالتهابية المزمنة.</p>
<p>الاندماج البيولوجي.. نهاية عصر المستشعرات الصلبة</p>
<p>يمثل هذا الابتكار ذروة التحول نحو &#8220;الطب التجديدي&#8221; الذي يلغي الفجوة بين الجسم والجهاز الرقابي. من منظور استراتيجي، نحن ننتقل من عصر (Wearables) أو الأجهزة القابلة للارتداء، إلى عصر (In-build Biology) حيث يصبح الجلد نفسه هو الشاشة واللاقط. إن نجاح الخلايا الجذعية في تجديد نفسها لأكثر من 6 أشهر يعني انخفاضاً هائلاً في تكاليف الرعاية طويلة الأمد وتقليص الحاجة للعمليات الجراحية المتكررة لاستبدال المستشعرات. هذا النوع من التقنيات سيعيد تعريف &#8220;الأمن الصحي الشخصي&#8221;، حيث تصبح الاستجابة المناعية مرئية للعين المجردة، مما يمنح المريض والمنظومة الصحية فرصة ذهبية للتدخل قبل وقوع &#8220;الكارثة الصحية&#8221;، وهو ما يتماشى مع التوجهات العالمية في تقليل الإنفاق على العلاجات المتقدمة عبر الاستثمار في الكشف المبكر المطلق.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/ed6c936d-ef89-4c08-aac3-5ee580d9196f.webp', 'جلد &#8220;ذكي&#8221; يتوهج بالأخضر.. إنذار بيولوجي مبكر يكشف الأمراض الصامتة', 'جلد &#8220;ذكي&#8221; يتوهج بالأخضر.. إنذار بيولوجي مبكر يكشف الأمراض الصامتة', 'طوكيو – كبسولة الصحية نجح فريق بحثي من جامعة مدينة طوكيو في تطوير نسيج جلدي حي مهندس وراثياً يعمل كجهاز إنذار بيولوجي، حيث يتوهج باللون الأخضر الساطع عند رصد أي', '{"إنذار بيولوجي","الأمراض الصامتة",الجلد}', false, 'published', NULL, NULL, '2026-01-18 00:19:35', '2026-01-24 16:23:38.344551', '2026-01-24 16:23:38.344551');
INSERT INTO public.news VALUES ('900c1374-ef36-4fce-b13d-e1933c5ca038', 'f5e9432', 'دراسة حديثة: صحة الفم والأسنان ركيزة أساسية لحماية القلب والشرايين', NULL, 'كبسولة الصحية &#8211; مديكال إكسبريس كشف بيان علمي جديد نُشر في مجلة &#8220;سيركوليشن&#8221; الصادرة عن جمعية القلب الأمريكية، عن أدلة متزايدة تؤكد الارتباط الوثيق بين أمراض اللثة وزيادة مخاطر الإصابة بأمراض القلب والأوعية الدموية. وأوضح البيان أن العناية باللثة لا تقتصر على صحة الفم فحسب، بل تمتد ل', '<p><strong>كبسولة الصحية &#8211; مديكال إكسبريس</strong></p>
<p>كشف بيان علمي جديد نُشر في مجلة &#8220;سيركوليشن&#8221; الصادرة عن جمعية القلب الأمريكية، عن أدلة متزايدة تؤكد الارتباط الوثيق بين أمراض اللثة وزيادة مخاطر الإصابة بأمراض القلب والأوعية الدموية. وأوضح البيان أن العناية باللثة لا تقتصر على صحة الفم فحسب، بل تمتد لتكون جزءاً حيوياً من الوقاية من النوبات القلبية والسكتات الدماغية.</p>
<p><strong>كيف تؤثر اللثة على القلب؟</strong> أشار الدكتور أندرو إتش تران، محرر البيان ومدير برنامج طب القلب الوقائي، إلى أن سوء نظافة الفم يسمح بدخول البكتيريا إلى مجرى الدم. وتؤدي هذه العملية إلى حدوث التهابات قد تتسبب في تلف الأوعية الدموية، مما يزيد من احتمالية تراكم اللويحات الشريانية (الترسبات الدهنية) المؤدية لتصلب الشرايين.</p>
<p><strong>نتائج رقمية لافتة</strong> استعرضت الدراسة بيانات توضح أثر العادات اليومية في الوقاية من الأمراض خلال عشر سنوات:</p>
<ul>
<li><strong>7.35%</strong> هي نسبة خطر الإصابة بأمراض القلب لدى الأشخاص الذين ينظفون أسنانهم <strong>3 </strong><strong>مرات أو أكثر</strong> يومياً.</li>
<li><strong>13.7%</strong> ترتفع النسبة لتصل إلى هذا الحد لدى من ينظفون أسنانهم <strong>مرة واحدة أو أقل</strong> يومياً.</li>
</ul>
<p><strong>توصيات وقائية</strong> أكد البيان العلمي على عدة نقاط لحماية الجهاز الدوري:</p>
<ul>
<li>يساهم العلاج الفعال لأمراض دواعم السن في تقليل عبء أمراض القلب عالمياً.</li>
<li>يستفيد الأشخاص الذين لديهم عوامل خطر إصابة قلبية من فحوصات الأسنان الدورية لمعالجة الالتهابات المزمنة.</li>
<li>تُعد العناية بالفم عن طريق الفرشاة والخيط جزءاً مهماً من حماية القلب، لكونهما وسيلة مباشرة لمنع وصول البكتيريا لمجرى الدم.</li>
</ul>
<p>واختتم الدكتور تران بتأكيده على أن &#8220;الفم والقلب متصلان&#8221;، مشدداً على ضرورة دمج رعاية الأسنان ضمن الخطط الوقائية لصحة القلب.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/0d8b0a66-b36c-4948-8366-5a08b65e6d69.webp', 'دراسة حديثة: صحة الفم والأسنان ركيزة أساسية لحماية القلب والشرايين', 'دراسة حديثة: صحة الفم والأسنان ركيزة أساسية لحماية القلب والشرايين', 'كبسولة الصحية &#8211; مديكال إكسبريس كشف بيان علمي جديد نُشر في مجلة &#8220;سيركوليشن&#8221; الصادرة عن جمعية القلب الأمريكية، عن أدلة متزايدة تؤكد الارتباط الو', '{الشرايين,القلب,"صحة الفم"}', false, 'published', NULL, NULL, '2026-01-18 00:12:15', '2026-01-24 16:23:39.062674', '2026-01-24 16:23:39.062674');
INSERT INTO public.news VALUES ('de1e8b11-811f-4a14-b2dc-0053ca7068b8', '5215945', '"ملف خاص" أناقة خانقة: حين تقتل "الموضة" فرص الإنجاب', NULL, 'ضريبة القالب الضيق: مخاطر بيولوجية تتجاوز حدود المظهر القاهرة – محمد مطاوع تؤكد الدراسات السريرية المنشورة في مجلات عالمية مثل (Human Reproduction) أن ارتداء البناطيل الضيقة لفترات طويلة يرفع درجة حرارة الأنسجة الحيوية، مما يؤدي إلى تراجع حاد في كفاءة وإنتاج الخلايا التناسلية. فخ الحرارة الموضعية يت', '<p><strong>ضريبة القالب الضيق: مخاطر بيولوجية تتجاوز حدود المظهر</strong></p>
<p>القاهرة – محمد مطاوع</p>
<p>تؤكد الدراسات السريرية المنشورة في مجلات عالمية مثل (Human Reproduction) أن ارتداء البناطيل الضيقة لفترات طويلة يرفع درجة حرارة الأنسجة الحيوية، مما يؤدي إلى تراجع حاد في كفاءة وإنتاج الخلايا التناسلية.</p>
<p><strong>فخ الحرارة الموضعية</strong></p>
<p>يتطلب إنتاج الخلايا التناسلية لدى الرجال درجة حرارة أقل من حرارة الجسم الطبيعية بمقدار درجتين تقريباً. وتعمل البناطيل الضيقة (وخاصة &#8220;الجينز&#8221;) كعازل حراري يمنع التهوية الطبيعية، مما يرفع درجة حرارة تلك المنطقة الحساسة ويؤدي إلى &#8220;إجهاد حراري&#8221; يقتل الخلايا أو يضعف قدرتها على الحركة، وهو ما يفسر تزايد حالات تأخر الإنجاب في المجتمعات التي تتبع صرعات الموضة الضيقة.</p>
<p><strong>أرقام من واقع المختبرات</strong> رصدت أبحاث أجريت في جامعة هارفارد أن الرجال الذين يرتدون ملابس داخلية وبناطيل فضفاضة يمتلكون تركيزاً أعلى من الخلايا التناسلية بنسبة <strong>25%</strong> مقارنة بالذين يفضلون القوالب الضيقة. وتظهر النتائج المخبرية أن الضغط الميكانيكي المستمر يقلل من تدفق الدم في الأوعية الدقيقة، مما يحرم الأنسجة من الأكسجين اللازم للعمليات الحيوية، ويحول &#8220;الأناقة&#8221; إلى عائق بيولوجي صامت.</p>
<p><strong>تأثير &#8220;النايلون&#8221; والألياف الصناعية</strong></p>
<p>تزداد الخطورة عند استخدام بناطيل تحتوي على نسب عالية من الألياف الصناعية والنايلون؛ فهذه المواد تولد شحنات كهروستاتيكية وتمنع امتصاص العرق، مما يخلق بيئة خصبة للالتهابات الفطرية وتراكم البكتيريا. ويشدد خبراء المسالك البولية على أن ارتداء الأقمشة الطبيعية مثل القطن والكتان بتصاميم مريحة هو الضمان الأمثل للحفاظ على الوظائف الحيوية والوقاية من الاحتقان المزمن الذي قد يتطور لمشكلات صحية معقدة.</p>
<p><strong>التأثير على الخصوبة النسائية</strong></p>
<p>لا يقتصر الضرر على الرجال فحسب، بل يمتد للنساء؛ حيث يؤدي الضغط المستمر للبناطيل الضيقة على منطقة الحوض إلى إعاقة الدورة الدموية، مما قد يسبب آلاماً مزمنة في الظهر والحوض. كما تساهم هذه البيئة &#8220;غير المهواة&#8221; في اضطراب التوازن البكتيري الطبيعي، مما يرفع احتمالات الإصابة بالتهابات المسالك البولية التي قد تؤثر بشكل غير مباشر على الصحة الإنجابية العامة إذا تركت دون علاج.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/0b9db10a-2f03-4b08-952b-66c1cbefffcf.jpg', '&#8220;ملف خاص&#8221; أناقة خانقة: حين تقتل &#8220;الموضة&#8221; فرص الإنجاب', '&#8220;ملف خاص&#8221; أناقة خانقة: حين تقتل &#8220;الموضة&#8221; فرص الإنجاب', 'ضريبة القالب الضيق: مخاطر بيولوجية تتجاوز حدود المظهر القاهرة – محمد مطاوع تؤكد الدراسات السريرية المنشورة في مجلات عالمية مثل (Human Reproduction) أن ارتداء ال', '{الجينز,"خصوبة الرجال"}', false, 'published', NULL, NULL, '2026-01-18 00:04:09', '2026-01-24 16:23:39.746701', '2026-01-24 16:23:39.746701');
INSERT INTO public.news VALUES ('635ba22c-bb95-4044-ae94-2b624af9259e', '1619f06', 'إصابة أكثر من 100 طالب في مدرسة بجنوب الصين بفيروس "نورو"', NULL, 'كبسولة الصحية &#8211;  واس أعلنت السُلطات الصحية في مقاطعة جوانجدونج بجنوب الصين اليوم، أن ما مجموعه 103 طلاب في مدرسة ثانوية في مدينة فوشان أصيبوا بفيروس &#8220;نورو&#8221;، مشيرة إلى أنه لم يُبلغ عن أي حالات خطيرة أو مميتة. ويتسبب فيروس &#8220;نورو&#8221; في أعراض مثل القيء كما يعرف بأنه شديد العد', '<p>كبسولة الصحية &#8211;  واس</p>
<p>أعلنت السُلطات الصحية في مقاطعة جوانجدونج بجنوب الصين اليوم، أن ما مجموعه 103 طلاب في مدرسة ثانوية في مدينة فوشان أصيبوا بفيروس &#8220;نورو&#8221;، مشيرة إلى أنه لم يُبلغ عن أي حالات خطيرة أو مميتة.</p>
<p>ويتسبب فيروس &#8220;نورو&#8221; في أعراض مثل القيء كما يعرف بأنه شديد العدوى وينتقل عبر الأسطح الملوثة، أو الطعام، أو الاتصال المباشر، وقد أصيب تلاميذ مدرسة شينجهي المتوسطة مؤخرًا بأعراض تم التأكيد مبدئيًا أنها ناجمة عن عدوى فيروس &#8220;نورو&#8221;.</p>
<p>وأوضحت السُلطات أن جميع الطلاب البالغ عددهم (103) في حالة مستقرة، وقد تم تطهير حرم المدرسة، ويخضع الطلاب للمراقبة الصحية وفحوصات الحضور، وتجري أيضًا عملية مسح وبائي.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/39840430-d00e-409f-9ac8-8396bfbc9710.jpg', 'إصابة أكثر من 100 طالب في مدرسة بجنوب الصين بفيروس &#8220;نورو&#8221;', 'إصابة أكثر من 100 طالب في مدرسة بجنوب الصين بفيروس &#8220;نورو&#8221;', 'كبسولة الصحية &#8211;  واس أعلنت السُلطات الصحية في مقاطعة جوانجدونج بجنوب الصين اليوم، أن ما مجموعه 103 طلاب في مدرسة ثانوية في مدينة فوشان أصيبوا بفيروس &#822', '{الصين,الطلاب,"فيروس نورو"}', false, 'published', NULL, NULL, '2026-01-17 13:40:37', '2026-01-24 16:23:40.096267', '2026-01-24 16:23:40.096267');
INSERT INTO public.news VALUES ('27bcf71f-27fd-4a03-860a-fa87fe79d911', 'da7ee5a', 'مشرط "النيابة الملكية" يطال الختان: صِدام الهوية والقانون في بريطانيا', NULL, 'كبسولة الصحية &#8211; غارديان تتجه دائرة الادعاء الملكية البريطانية (CPS) إلى تصنيف ختان الذكور كشكل محتمل من أشكال &#8220;إساءة معاملة الأطفال&#8221; ضمن مسودة توجيهات جديدة، واضعةً هذه الممارسة الدينية التاريخية في قائمة واحدة مع &#8220;تطهير العذرية&#8221; و&#8221;تشويه الأعضاء التناسلية الأنثوية', '<p>كبسولة الصحية &#8211; غارديان</p>
<p>تتجه دائرة الادعاء الملكية البريطانية (CPS) إلى تصنيف ختان الذكور كشكل محتمل من أشكال &#8220;إساءة معاملة الأطفال&#8221; ضمن مسودة توجيهات جديدة، واضعةً هذه الممارسة الدينية التاريخية في قائمة واحدة مع &#8220;تطهير العذرية&#8221; و&#8221;تشويه الأعضاء التناسلية الأنثوية&#8221;.</p>
<p>كشفت مسودة وثيقة رسمية للنيابة العامة البريطانية عن توجه قانوني جديد يدرج الختان ضمن &#8220;الممارسات الضارة&#8221; والجرائم المرتبطة بـ &#8220;الدفاع عن الشرف&#8221;، محذرةً من أن هذا الإجراء قد يشكل جريمة جنائية ضد القاصرين إذا أدى إلى أضرار جسيمة أو نُفذ في ظروف غير صحية.</p>
<p>وجاء هذا التحرك بعد تسجيل 7 وفيات لأطفال في بريطانيا منذ عام 2001 نتيجة مضاعفات الختان، كان آخرها وفاة رضيع في السادسة من عمره عام 2023، مما دفع القضاة والمحققين للمطالبة بتنظيم صارم لهذه الممارسة التي لا تزال تفتقر لرقابة قانونية شاملة في المملكة المتحدة.</p>
<p>يمثل هذا التوجه &#8220;هزة زلزالية&#8221; للعلاقة بين الدولة والجاليات الدينية؛ حيث يرى القادة المسلمون واليهود أن وصف الختان بـ &#8220;الممارسة الضارة&#8221; بحد ذاته هو إهانة للهوية الثقافية والدينية.</p>
<p>وفي الوقت الذي يحذر فيه أطباء شرعيون من &#8220;الفوضى التنظيمية&#8221; التي تسمح لغير المختصين بإجراء الجراحة، تبرز تقارير طبية عالمية مثل مركز السيطرة على الأمراض الأمريكي CDC تؤكد أن فوائد الختان في الوقاية من الأمراض الجنسية وفيروس نقص المناعة المكتسبة تفوق مخاطره بمراحل، مما يضع القانون البريطاني في مواجهة مباشرة مع الحقائق الطبية والحقوق الدينية.</p>
<p>تستعد المنظمات الإسلامية واليهودية لخوض جولة مفاوضات شرسة مع النيابة العامة لتعديل صياغة المسودة قبل اعتمادها نهائياً، مع المطالبة باستبدال &#8220;التجريم&#8221; بـ &#8220;التنظيم&#8221;. ومن المتوقع أن يضغط الحقوقيون لفرض نظام &#8220;اعتماد رسمي&#8221; للخاتنين، بينما يرى تيار آخر ضرورة رفع السن القانوني للختان إلى 16 عاماً لضمان &#8220;الموافقة الواعية&#8221;، وهو ما قد يشعل فتيل أزمة قضائية قد تصل إلى المحكمة الأوروبية لحقوق الإنسان.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/1a2faccc-18f2-475b-82fd-bbdc68297eca.jpg', 'مشرط &#8220;النيابة الملكية&#8221; يطال الختان: صِدام الهوية والقانون في بريطانيا', 'مشرط &#8220;النيابة الملكية&#8221; يطال الختان: صِدام الهوية والقانون في بريطانيا', 'كبسولة الصحية &#8211; غارديان تتجه دائرة الادعاء الملكية البريطانية (CPS) إلى تصنيف ختان الذكور كشكل محتمل من أشكال &#8220;إساءة معاملة الأطفال&#8221; ضمن مسودة', '{الختان,بريطانيا}', false, 'published', NULL, NULL, '2026-01-17 00:24:55', '2026-01-24 16:23:40.420186', '2026-01-24 16:23:40.420186');
INSERT INTO public.news VALUES ('95e2b3fb-2c52-463b-89a2-a2c03acc5844', 'a5b28df', '20 مرضاً بـ "صفر روبل": روسيا تجدد عقد الرعاية المجانية مع مواطنيها', NULL, 'كبسولة الصحية &#8211; سبوتنيك تعهدت الحكومة الروسية بضمان الرعاية الطبية المجانية الشاملة لمواطنيها لأكثر من 20 نوعاً من الأمراض والحالات الصحية المعقدة خلال العام الحالي، في خطوة تهدف لتعزيز الأمان الصحي والاجتماعي. أصدرت الحكومة الروسية قراراً رسمياً يوسع قائمة الأمراض التي تُعالج مجاناً بالكامل، ', '<p>كبسولة الصحية &#8211; سبوتنيك</p>
<p>تعهدت الحكومة الروسية بضمان الرعاية الطبية المجانية الشاملة لمواطنيها لأكثر من 20 نوعاً من الأمراض والحالات الصحية المعقدة خلال العام الحالي، في خطوة تهدف لتعزيز الأمان الصحي والاجتماعي.</p>
<p>أصدرت الحكومة الروسية قراراً رسمياً يوسع قائمة الأمراض التي تُعالج مجاناً بالكامل، لتشمل الأورام، وأمراض القلب، واضطرابات الجهاز العصبي، والمناعي، وحتى الجراحات عالية التقنية. كما أدرج القرار فحوصات حديثة مجانية مثل اختبارات الحمض النووي للجنين والحماية من سرطان عنق الرحم، مع توفير تطعيمات وقائية لكبار السن، مما يجعل المنظومة الصحية الروسية واحدة من أكثر المنظومات شمولاً في تقديم الخدمات الطبية المتطورة دون مقابل مادي مباشر من المريض.</p>
<p>تأتي هذه الخطوة لترسيخ &#8220;العقد الاجتماعي&#8221; بين الدولة والمواطن في ظل تحديات اقتصادية دولية، حيث تسعى موسكو لتقليل معدلات الوفيات عبر &#8220;الطب الوقائي&#8221; بدلاً من العلاجي فقط. إن تحمل الدولة كلفة فحوصات البروتين الدهني والجينات يعني الانتقال من رعاية &#8220;المرض&#8221; إلى رعاية &#8220;الإنسان&#8221; قبل إصابته، وهو ما يوفر على ميزانية الدولة مليارات الروبلات التي كانت تُنفق على علاج الحالات المتأخرة، ويحمي الأسر من &#8220;الإفلاس الطبي&#8221; الذي تعاني منه مجتمعات غربية أخرى.</p>
<p>سيركز النظام الصحي الروسي في المرحلة المقبلة على &#8220;رقمنة&#8221; هذه الخدمات لضمان وصولها لكل مواطن، مع التوسع في استخدام الذكاء الاصطناعي في التشخيص المبكر للأورام ضمن القائمة المجانية. التحدي القادم يكمن في الحفاظ على &#8220;جودة&#8221; هذه الخدمة المجانية أمام الطلب المتزايد، وضمان تحديث الأجهزة الطبية عالية التقنية في الأقاليم البعيدة عن المركز لضمان عدالة التوزيع الصحي.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/0eb24791-4f9d-4ee4-9621-e35be8169b25.jpg', '20 مرضاً بـ &#8220;صفر روبل&#8221;: روسيا تجدد عقد الرعاية المجانية مع مواطنيها', '20 مرضاً بـ &#8220;صفر روبل&#8221;: روسيا تجدد عقد الرعاية المجانية مع مواطنيها', 'كبسولة الصحية &#8211; سبوتنيك تعهدت الحكومة الروسية بضمان الرعاية الطبية المجانية الشاملة لمواطنيها لأكثر من 20 نوعاً من الأمراض والحالات الصحية المعقدة خلال ال', '{"الرعاية الصحية المجانية",روسيا}', false, 'published', NULL, NULL, '2026-01-17 00:22:41', '2026-01-24 16:23:40.861744', '2026-01-24 16:23:40.861744');
INSERT INTO public.news VALUES ('c8adaaa0-e3ff-4e6a-9b71-3e49bf1034ba', '5a98f7f', 'بصمة "تريتشر كولينز": عائلة إندونيسية تكسر حصار "التنمر" وتتحول إلى أيقونة عالمية', NULL, 'جاكرتا – كبسولة الصحية تحولت قصة عائلة &#8220;مانورونغ&#8221; في شمال سومطرة بإندونيسيا من مأساة اجتماعية مغلفة بالعزلة والخرافات إلى ملهمة عالمية في قبول الذات، بعد أن وثق أفرادها حياتهم مع &#8220;متلازمة تريتشر كولينز&#8221; (Treacher Collins Syndrome). وولد أربعة من بين ستة أشقاء بملامح وجه غير م', '<p>جاكرتا – كبسولة الصحية</p>
<p>تحولت قصة عائلة &#8220;مانورونغ&#8221; في شمال سومطرة بإندونيسيا من مأساة اجتماعية مغلفة بالعزلة والخرافات إلى ملهمة عالمية في قبول الذات، بعد أن وثق أفرادها حياتهم مع &#8220;متلازمة تريتشر كولينز&#8221; (Treacher Collins Syndrome). وولد أربعة من بين ستة أشقاء بملامح وجه غير مألوفة ورثوها عن والدهم، شملت تشوهات في عظام الخدين والفك، وهي حالة طبية نادرة تؤثر على بنية الوجه دون المساس بالذكاء أو الوظائف الحيوية للجسم.</p>
<p>واجهت العائلة في بداياتها وصمة اجتماعية قاسية في قريتهم &#8220;كيدونكانغ&#8221;، حيث فسر السكان مظهرهم بـ&#8221;اللعنات&#8221;، مما أدى لرفضهم في سوق العمل وفقدانهم الثقة بالنفس. إلا أن الانفتاح على وسائل التواصل الاجتماعي غير مسار حياتهم؛ حيث قرر الأشقاء مواجهة العالم علناً، محولين منصات &#8220;تيك توك&#8221; و&#8221;يوتيوب&#8221; إلى ساحات لزيادة الوعي بالحالات الوراثية النادرة، مما أكسبهم ملايين المتابعين ومصدراً مستداماً للدخل مكنهم من تجاوز عقبات التمييز المهني.</p>
<p>ويبرز البعد الإنساني في هذه القصة من خلال قدرة العائلة على تحويل &#8220;الاختلاف الجيني&#8221; من عائق إلى رسالة حضارية تؤكد أن كرامة الإنسان ومكانته لا تحددها الملامح بل قدرته على العطاء والتأثير. إن نجاح عائلة &#8220;مانورونغ&#8221; يمثل انتصاراً للعلم على الخرافة، وللثقة بالنفس على الوصمة الاجتماعية، مما يجعل من تجربتهم درساً عالمياً في كيفية استثمار التكنولوجيا لكسر الحواجز النفسية والاجتماعية وبناء جسور من القبول الإنساني العابر للحدود.</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/26400559-77bc-4eec-be0f-22f1053b770a.webp', 'بصمة &#8220;تريتشر كولينز&#8221;: عائلة إندونيسية تكسر حصار &#8220;التنمر&#8221; وتتحول إلى أيقونة عالمية', 'بصمة &#8220;تريتشر كولينز&#8221;: عائلة إندونيسية تكسر حصار &#8220;التنمر&#8221; وتتحول إلى أيقونة عالمية', 'جاكرتا – كبسولة الصحية تحولت قصة عائلة &#8220;مانورونغ&#8221; في شمال سومطرة بإندونيسيا من مأساة اجتماعية مغلفة بالعزلة والخرافات إلى ملهمة عالمية في قبول الذات', '{"بصمة تريتشر كولينز",جاكرتا}', false, 'published', NULL, NULL, '2026-01-17 00:10:29', '2026-01-24 16:23:42.467321', '2026-01-24 16:23:42.467321');
INSERT INTO public.news VALUES ('2a386137-7d52-475b-9b87-0fa7f1ed5a02', 'd71988b', 'بالشاي المغلي وسوق "اللايكات".. الجلد محروق لا محالة!', NULL, 'القاهرة – محمد مطاوع لم يعد &#8220;كوب الشاي&#8221; رمزاً للمزاج، بل أصبح أداة في &#8220;مقامرة جسدية&#8221; يقودها هوس المراهقين بجمع الإعجابات؛ حيث انتشر ترند سكب الشاي المغلي على الأيدي المتشابكة كاختبار للولاء والارتباط. هذا الجنون الذي يغلي على منصات التواصل ليس شجاعة، بل هو &#8220;تجارة بالألم', '<p>القاهرة – محمد مطاوع</p>
<p>لم يعد &#8220;كوب الشاي&#8221; رمزاً للمزاج، بل أصبح أداة في &#8220;مقامرة جسدية&#8221; يقودها هوس المراهقين بجمع الإعجابات؛ حيث انتشر ترند سكب الشاي المغلي على الأيدي المتشابكة كاختبار للولاء والارتباط.</p>
<p>هذا الجنون الذي يغلي على منصات التواصل ليس شجاعة، بل هو &#8220;تجارة بالألم&#8221; يتم فيها استبدال سلامة الجسد بـ &#8220;لايك&#8221; عابر، والنتيجة دائمًا هي صرخات في غرف الطوارئ وندوب لن تُمحى، ستبقى &#8220;وشماً للندم&#8221; يُذكّر صاحبها بأنه أحرق نفسه من أجل جمهور لا يراه إلا &#8220;محتوى&#8221; للصدمة والفرجة.</p>
<p>إننا أمام &#8220;إفلاس قيمي&#8221; حاد؛ حيث يتم تزييف الوعي ليصبح الحرق دليل حب، والتشويه دليل وفاء.</p>
<p>استراتيجياً، يمثل هذا التحدي قمة &#8220;الاستلاب الرقمي&#8221;، إذ تُسلّم الإرادة والجسد لخوارزميات تقتات على أذى البشر.</p>
<p>إن مواجهة هذا العبث تتطلب صرخة وعي تعيد بناء مفهوم الكرامة الجسدية؛ فالارتباط الذي يبدأ بـ &#8220;شيّ الجلود&#8221; هو علاقة مسمومة، واليد التي تُسلق اليوم من أجل &#8220;لايك&#8221;، لن تجد غداً من يداوي جراحها حين يرحل الجمهور بحثاً عن ضحية جديدة في &#8220;ترند&#8221; آخر.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/78be96ba-711d-4927-bc8a-a7b3a0d1a7dd.jpg', 'بالشاي المغلي وسوق &#8220;اللايكات&#8221;.. الجلد محروق لا محالة!', 'بالشاي المغلي وسوق &#8220;اللايكات&#8221;.. الجلد محروق لا محالة!', 'القاهرة – محمد مطاوع لم يعد &#8220;كوب الشاي&#8221; رمزاً للمزاج، بل أصبح أداة في &#8220;مقامرة جسدية&#8221; يقودها هوس المراهقين بجمع الإعجابات؛ حيث انتشر ترند', '{"ترند الشاي المغلي"}', false, 'published', NULL, NULL, '2026-01-17 00:05:00', '2026-01-24 16:23:43.140663', '2026-01-24 16:23:43.140663');
INSERT INTO public.news VALUES ('37690130-190b-4a82-a2ed-655a3fe7430a', '53f5e36', 'خلف أسوار "المنطقة المجاورة للوجه".. الدماغ يتهم نفسه بالمسؤولية عن ضغط الدم', NULL, 'كبسولة الصحية &#8211; وكالات كشفت أحدث الدراسات العلمية الصادرة عن جامعة أوكلاند بنيوزيلندا عن مفاجأة طبية قد تعيد صياغة بروتوكولات علاج ضغط الدم عالمياً، حيث حدد الباحثون منطقة غامضة في جذع الدماغ تُدعى &#8220;المنطقة المجاورة للوجه&#8221; (Parafacial Zone) كمسؤول مباشر عن نشوء حالات الارتفاع المزم', '<p>كبسولة الصحية &#8211; وكالات</p>
<p>كشفت أحدث الدراسات العلمية الصادرة عن جامعة أوكلاند بنيوزيلندا عن مفاجأة طبية قد تعيد صياغة بروتوكولات علاج ضغط الدم عالمياً، حيث حدد الباحثون منطقة غامضة في جذع الدماغ تُدعى &#8220;المنطقة المجاورة للوجه&#8221; (Parafacial Zone) كمسؤول مباشر عن نشوء حالات الارتفاع المزمن. هذه المنطقة، التي طالما عُرفت بدورها التقليدي في التحكم بالوظائف اللاإرادية كالتنفس والضحك والسعال، تبين أنها تمتلك قدرة &#8220;تخريبية&#8221; عند نشاطها الزائد، حيث ترسل إشارات عصبية تحفز انقباض الأوعية الدموية بشكل مستمر، مما يؤدي إلى رفع الضغط لمستويات مرضية.</p>
<p>وقد أثبت الفريق البحثي، بقيادة عالم وظائف الأعضاء الدكتور جوليان باتون، أن تعطيل هذه المنطقة أو تهدئة أعصابها في النماذج المختبرية أدى فوراً إلى انخفاض ضغط الدم وعودته لمستوياته الطبيعية، مما يضع &#8220;الدماغ&#8221; في قفص الاتهام كالمحرك الرئيسي للمرض وليس مجرد مستجيب له. ورغم أن عوامل نمط الحياة مثل السمنة واستهلاك الأملاح لا تزال تتربع على عرش المسببات المعروفة، إلا أن هذا الاكتشاف يسلط الضوء على &#8220;الخلفية العصبية&#8221; التي قد تكون السبب الخفي وراء فشل العلاجات التقليدية لدى شريحة واسعة من المرضى.</p>
<p>سيادة الدماغ على القلب.. تحول في فلسفة العلاج</p>
<p>يمثل هذا الاكتشاف تحولاً بنيوياً في &#8220;الاستراتيجية الوقائية والعلاجية&#8221; للأمراض المزمنة، حيث ننتقل من مرحلة &#8220;علاج الأطراف&#8221; (عبر الأدوية التي توسع الأوعية الدموية أو تدر البول) إلى مرحلة &#8220;إدارة المركز&#8221; (التحكم في الإشارات الصادرة من جذع الدماغ).</p>
<p>استراتيجياً، يفتح هذا المسار الباب أمام تقنيات &#8220;التعديل العصبي&#8221; غير الجراحية، التي قد توفر حلولاً جذرية بدلاً من الاستمرار في صرف مليارات الدولارات سنوياً على أدوية الضغط التقليدية التي تُعطى مدى الحياة دون معالجة السبب الجذري في الدماغ.</p>
<p>يفرض هذا التحول تحدياً جديداً أمام الجهات الرقابية الصحية (مثل الغذاء والدواء) لتقييم واعتماد أجهزة &#8220;تهدئة الأعصاب&#8221; كبدائل علاجية معتمدة، وهو ما يتطلب تحديثاً سريعاً للتشريعات الطبية لتواكب عصر &#8220;الطب العصبي الرقمي&#8221;.</p>
<p>إن تأكيد هذه النتائج على البشر سيعني أن بروتوكولات التشخيص المستقبلي يجب أن تشمل &#8220;مسحاً وظيفياً&#8221; لنشاط الدماغ قبل البدء في خطة العلاج، لضمان تقديم طب شخصي دقيق يفرق بين الضغط الناتج عن &#8220;نمط الحياة&#8221; والضغط الناتج عن &#8220;خلل الدوائر العصبية&#8221;، مما يرفع من جودة حياة المريض ويقلل من الأضرار الجانبية للأدوية غير الضرورية.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/01b24277-a390-4559-9ddb-4c6e35c68b7c.webp', 'خلف أسوار &#8220;المنطقة المجاورة للوجه&#8221;.. الدماغ يتهم نفسه بالمسؤولية عن ضغط الدم', 'خلف أسوار &#8220;المنطقة المجاورة للوجه&#8221;.. الدماغ يتهم نفسه بالمسؤولية عن ضغط الدم', 'كبسولة الصحية &#8211; وكالات كشفت أحدث الدراسات العلمية الصادرة عن جامعة أوكلاند بنيوزيلندا عن مفاجأة طبية قد تعيد صياغة بروتوكولات علاج ضغط الدم عالمياً، حيث ح', '{الدماغ,"ضغط الدم"}', false, 'published', NULL, NULL, '2026-01-16 01:10:44', '2026-01-24 16:23:43.994763', '2026-01-24 16:23:43.994763');
INSERT INTO public.news VALUES ('c6ca4250-4770-4432-9956-528e84afd988', 'e1615b0', 'تحرك دولي لرفع ضرائب "المنتجات الضارة".. منظمة الصحة العالمية تحذر من رخص المشروبات السكرية', NULL, 'جنيف – كبسولة الصحية أطلقت منظمة الصحة العالمية نداءً عالمياً عاجلاً دعت فيه الحكومات إلى ضرورة تشديد الضرائب المفروضة على المشروبات السكرية والكحولية بشكل جذري، محذرة من أن بقاء هذه المنتجات رخيصة الثمن يساهم في تفاقم أزمات السمنة والسكري وأمراض القلب والسرطان، خاصة بين فئتي الأطفال والشباب. وأكد ا', '<p>جنيف – كبسولة الصحية</p>
<p>أطلقت منظمة الصحة العالمية نداءً عالمياً عاجلاً دعت فيه الحكومات إلى ضرورة تشديد الضرائب المفروضة على المشروبات السكرية والكحولية بشكل جذري، محذرة من أن بقاء هذه المنتجات رخيصة الثمن يساهم في تفاقم أزمات السمنة والسكري وأمراض القلب والسرطان، خاصة بين فئتي الأطفال والشباب.</p>
<p>وأكد المدير العام للمنظمة، الدكتور تيدروس أدهانوم جيبريسوس، أن الأنظمة الضريبية الحالية لم تواكب معدلات التضخم، مما جعل هذه المنتجات في متناول الجميع بشكل أكبر، بينما تظل الضريبة المتوسطة على المشروبات الغازية الشائعة لا تتجاوز 2% فقط، وهو ما يسمح لشركات الإنتاج بجني أرباح هائلة مقابل تحميل المجتمعات تكاليف صحية واقتصادية باهظة. وفي هذا السياق، كشفت المنظمة عن مبادرتها الطموحة، التي تهدف إلى رفع الأسعار الحقيقية للتبغ والكحول والمشروبات السكرية بحلول عام 2035 عبر إعادة هيكلة الضرائب لتشمل قطاعات مهملة مثل عصائر الفاكهة المحلاة ومشروبات الطاقة.</p>
<p>وتعكس هذه المبادرة تحولاً جوهرياً في &#8220;الاستراتيجية الصحية الدولية&#8221; من مجرد التوعية التقليدية إلى التدخل الاقتصادي المباشر لإعادة هندسة السلوك الاستهلاكي. فمن المنظور الاستراتيجي، تُعد الضريبة الصحية أداة مزدوجة الفعالية؛ فهي تعمل ككابح للطلب على المنتجات الضارة، وفي الوقت ذاته توفر تدفقات نقدية سيادية يمكن توجيهها لتمويل الأنظمة الصحية التي تئن تحت وطأة الأمراض غير المعدية.</p>
<p>إن إصرار المنظمة على شمولية الضرائب وربطها بالتضخم يقطع الطريق على &#8220;لوبيات&#8221; صناعة السكر التي تستغل الثغرات التنظيمية للبقاء في السوق بأسعار تنافسية. ومن المتوقع أن يواجه هذا التوجه ضغوطاً اقتصادية كبرى، إلا أن نجاحه يمثل الضمانة الوحيدة لتقليل الإنفاق الحكومي طويل الأمد على الرعاية العلاجية، مما يجعل من &#8220;الضريبة الصحية&#8221; استثماراً وطنياً في رأس المال البشري وليس مجرد جباية مالية.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/585b14f2-ee3d-4f3f-ad39-1dbe9cc39466.jpg', 'تحرك دولي لرفع ضرائب &#8220;المنتجات الضارة&#8221;.. منظمة الصحة العالمية تحذر من رخص المشروبات السكرية', 'تحرك دولي لرفع ضرائب &#8220;المنتجات الضارة&#8221;.. منظمة الصحة العالمية تحذر من رخص المشروبات السكرية', 'جنيف – كبسولة الصحية أطلقت منظمة الصحة العالمية نداءً عالمياً عاجلاً دعت فيه الحكومات إلى ضرورة تشديد الضرائب المفروضة على المشروبات السكرية والكحولية بشكل جذري', '{"الصحة العالمية","ضرائب المشروبات السكرية"}', false, 'published', NULL, NULL, '2026-01-16 00:59:41', '2026-01-24 16:23:45.373408', '2026-01-24 16:23:45.373408');
INSERT INTO public.news VALUES ('7c5e5e71-2fd1-49c9-899b-857a938357a9', '14d7482', 'الكاميرون ترفع مستوى التأهب الصحي بسبب تفشي جدري القرود', NULL, 'كبسولة الصحية &#8211;  واس أعلنت السلطات الصحية في الكاميرون، حالة التأهب القصوى؛ عقب تسجيل ارتفاع في حالات الإصابة بجدري القرود، خصوصًا في إقليمي الساحل والوسط، مع ظهور حالات في أقاليم أخرى؛ مما دفع وزير الصحة العامة إلى تفعيل نظام المراقبة. وأفادت وزارة الصحة الكاميرونية، أن تفشي المرض بدأ منذ نها', '<p>كبسولة الصحية &#8211;  واس</p>
<p>أعلنت السلطات الصحية في الكاميرون، حالة التأهب القصوى؛ عقب تسجيل ارتفاع في حالات الإصابة بجدري القرود، خصوصًا في إقليمي الساحل والوسط، مع ظهور حالات في أقاليم أخرى؛ مما دفع وزير الصحة العامة إلى تفعيل نظام المراقبة.</p>
<p>وأفادت وزارة الصحة الكاميرونية، أن تفشي المرض بدأ منذ نهاية عام 2025، حيث سجّلت السلطات الصحية خمس حالات مؤكدة على مستوى البلاد.</p>
<p>وأوضحت أنه منذ الأول من يناير 2026، جرى تسجيل 114 حالة مشتبه بإصابتها بالمرض، من بينها 10 حالات مؤكدة، دون تسجيل أي وفيات.</p>
<p>وفي مواجهة هذا التفشي، أوصى وزيرة الصحة بتنفيذ خطة استجابة تشمل تعزيز المراقبة الوبائية، وإنشاء نظام لإدارة الحوادث الصحية، وتكثيف حملات التوعية، والإدارة الفعالة للحالات في مرافق الرعاية الصحية، مع وضع باقي الأقاليم تحت أقصى درجات التأهب.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/8d0c0354-d03e-40d5-b5e6-5ad454bb3eaf.webp', 'الكاميرون ترفع مستوى التأهب الصحي بسبب تفشي جدري القرود', 'الكاميرون ترفع مستوى التأهب الصحي بسبب تفشي جدري القرود', 'كبسولة الصحية &#8211;  واس أعلنت السلطات الصحية في الكاميرون، حالة التأهب القصوى؛ عقب تسجيل ارتفاع في حالات الإصابة بجدري القرود، خصوصًا في إقليمي الساحل والوسط', '{الكاميرون,"جدري القرود"}', false, 'published', NULL, NULL, '2026-01-15 12:34:51', '2026-01-24 16:23:46.462311', '2026-01-24 16:23:46.462311');
INSERT INTO public.news VALUES ('4dd54d78-19be-4529-b988-d49474f120d9', '94436b8', 'سابقة تاريخية في ناسا.. إنهاء مهمة فضائية قبل موعدها لدواعٍ طبية', NULL, 'متابعة – كبسولة الصحية في تطور دراماتيكي هو الأول من نوعه في تاريخ وكالة الفضاء الأمريكية &#8220;ناسا&#8221;، غادرت كبسولة تابعة لشركة &#8220;سبيس إكس&#8221; محطة الفضاء الدولية وعلى متنها طاقم من أربعة أفراد في رحلة عودة طارئة إلى الأرض. وجاء هذا القرار المفاجئ  عقب تعرض أحد رواد الفضاء لحالة طبية ', '<p>متابعة – كبسولة الصحية</p>
<p>في تطور دراماتيكي هو الأول من نوعه في تاريخ وكالة الفضاء الأمريكية &#8220;ناسا&#8221;، غادرت كبسولة تابعة لشركة &#8220;سبيس إكس&#8221; محطة الفضاء الدولية وعلى متنها طاقم من أربعة أفراد في رحلة عودة طارئة إلى الأرض.</p>
<p>وجاء هذا القرار المفاجئ  عقب تعرض أحد رواد الفضاء لحالة طبية خطيرة لم يُكشف عن تفاصيلها، مما استدعى إنهاء المهمة رقم 11 قبل موعدها المحدد ببضعة أسابيع.</p>
<p>وأفادت صحيفة &#8220;الرياض&#8221; أن كبسولة &#8220;كرو دراجون&#8221; (إنديفور) بدأت هبوطها من المدار متجهة نحو المحيط الهادئ قبالة ساحل كاليفورنيا، في رحلة استغرقت حوالي 10 ساعات ونصف الساعة لتختتم مهمة فضائية دامت 167 يوماً.</p>
<p>ويكشف هذا الهبوط الاضطراري عن أبعاد استراتيجية تتعلق بـ &#8220;أمن الاستكشاف الفضائي&#8221; ومدى قدرة المنظومات الطبية المدارية على التعامل مع الحالات الحرجة. فمن المنظور التقني، تبرز هذه الحادثة أن الصحة البشرية تظل التحدي الأكبر والحلقة الأضعف في مشاريع التواجد البشري الطويل خارج كوكب الأرض؛ إذ إن اضطرار &#8220;ناسا&#8221; لاتخاذ قرار الإخلاء الطبي الشامل يعزز من ضرورة إعادة النظر في &#8220;بروتوكولات الإسعاف الفضائي&#8221; وتطوير تقنيات جراحية وتشخيصية ذاتية داخل المحطات لتقليل الاعتماد على رحلات العودة المعقدة والمكلفة.</p>
<p>استراتيجياً، يضع هذا الحدث شركات الفضاء الخاصة أمام اختبار حقيقي لإثبات قدرة مركباتها على تنفيذ عمليات &#8220;إخلاء سريع&#8221; بسلامة تامة. كما أن التكتم على طبيعة الأزمة الطبية يثير تساؤلات حول الآثار طويلة المدى للجاذبية الصغرى والإشعاعات على وظائف الأعضاء الحيوية، وهو ما سيفرض تشديد المعايير الصحية وتطوير حلول وقائية أكثر صرامة.</p>
<p>إن نجاح رحلة العودة في هذا الزمن القياسي يثبت كفاءة نظام النقل الحالي، لكنه يدق ناقوس الخطر حول مستقبل الرحلات المأهولة للمريخ، حيث لن يكون &#8220;الخروج العاجل&#8221; خياراً متاحاً كما هو الحال في مدار الأرض المنخفض.</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/571e4f18-2b12-4ee5-8a80-44d311617153.jpg', 'سابقة تاريخية في ناسا.. إنهاء مهمة فضائية قبل موعدها لدواعٍ طبية', 'سابقة تاريخية في ناسا.. إنهاء مهمة فضائية قبل موعدها لدواعٍ طبية', 'متابعة – كبسولة الصحية في تطور دراماتيكي هو الأول من نوعه في تاريخ وكالة الفضاء الأمريكية &#8220;ناسا&#8221;، غادرت كبسولة تابعة لشركة &#8220;سبيس إكس&#8221; مح', '{"رواد فضاء","سبيس إكس","مشكلة الصحية",ناسا}', false, 'published', NULL, NULL, '2026-01-15 12:05:52', '2026-01-24 16:23:47.15531', '2026-01-24 16:23:47.15531');
INSERT INTO public.news VALUES ('c289e5ac-adc7-4785-9071-c357bedd1eaa', '82f68b7', 'مؤتمر الرعاية الصحية الأولية ينطلق برعاية سعود بن نايف', 'تجمع الشرقية الصحي يستعرض المشاريع والمبادرات التحسينية', 'تحت رعاية الأمير سعود بن نايف، يجتمع الخبراء والمختصون لمناقشة أحدث ممارسات الرعاية الصحية الأولية في مؤتمر يستمر يومين ويتضمن جلسات علمية ومشروعات نوعية.', '<p>يرعى صاحب السمو الملكي الأمير سعود بن نايف بن عبدالعزيز أمير المنطقة الشرقية، غدًا الأحد، حفل تدشين مؤتمر الرعاية الصحية الأولية، الذي ينظمه تجمع الشرقية الصحي، ويستمر لمدة يومين، وذلك في فندق شيراتون الدمام.<br> ويهدف المؤتمر إلى تسليط الضوء على دور الرعاية الصحية الأولية في تعزيز جودة الخدمات الصحية وتحسين تجربة المستفيد، من خلال مناقشة أحدث الممارسات والتجارب المتقدمة في هذا المجال.<br> ويتضمن المؤتمر أربع جلسات علمية، بمشاركة 12 مشاركًا، وأكثر من 20 متحدثًا من الخبراء والمختصين على مستوى المملكة.<br> ويشهد المؤتمر عرض أكثر من 30 مشروعًا وبحثًا تحسينيًا من مختلف أقسام ومنشآت تجمع الشرقية الصحي، تستعرض مبادرات تطويرية وتجارب نوعية تسهم في رفع كفاءة الأداء وتحسين مخرجات الرعاية الصحية الأولية، بما ينسجم مع مستهدفات التحول الصحي ورؤية المملكة 2030.<br> يُذكر أن عدد مراكز الرعاية الصحية الأولية التابعة لتجمع الشرقية الصحي يبلغ 120 مركزًا، من بينها 8 مراكز استشارية في مدينة الدمام ومحافظة الخبر ومحافظة القطيف.</p>', 'saudi-health', 'واس', NULL, '/objects/uploads/53e20872-b034-49b1-9b23-20837a1f7cc0', NULL, 'مؤتمر الرعاية الصحية برعاية سعود بن نايف', 'مؤتمر صحي برعاية الأمير سعود بن نايف يناقش أحدث ممارسات الرعاية الأولية بمشاركة خبراء ومبادرات تطويرية.', '{"الرعاية الصحية الأولية","مؤتمر الدمام","سعود بن نايف","تجمع الشرقية الصحي","رؤية 2030","الجلسات العلمية","المبادرات التحسينية"}', false, 'published', NULL, NULL, '2026-01-24 16:48:07.747', '2026-01-24 16:48:17.391755', '2026-01-24 16:48:17.391755');
INSERT INTO public.news VALUES ('fa48052d-21c3-41d0-9fe6-4f092d19ef83', '52d8bfb', 'اتفاقية لدعم جودة حياة الأطفال في المنشآت الصحية السعودية', 'تعزيز معايير الاعتماد لتحسين الرعاية الصحية النفسية والجسدية', 'وقع "سباهي" اتفاقية مع جمعية حياة الطفل لتعزيز جودة حياة الأطفال المرضى وأسرهم من خلال معايير اعتماد متطورة تتماشى مع أفضل الممارسات الصحية والنفسية.', '<p>وقع المركز السعودي لاعتماد المنشآت الصحية "سباهي" اتفاقية تعاون مع جمعية حياة الطفل مستهدفةً تحقيق التميز في الرعاية الصحية الشاملة وتعزيز جودة حياة الأطفال المرضى وأسرهم.<br> وأوضح المدير العام للمركز السعودي لاعتماد المنشآت الصحية الدكتور سالم بن عبدالله الوهابي أن الاتفاقية تسعى إلى دعم إعداد وتحديث معايير الاعتماد بما يُراعي الاحتياجات الصحية والنفسية للأطفال، وبما يُسهم في رفع جودة الخدمات الصحية المقدمة لهم.<br> وأفاد أن الاتفاقية تدعم تطوير وإدراج معايير ضمن منظومة الاعتماد الوطنية تشمل وجود متخصصين في الصحة النفسية والبدنيّة للطفل كمكوّن أساسي في فرق الرعاية الصحية المقدمة للأطفال، مع تحديد نطاق ممارستهم المهنية، ومتطلبات تأهيلهم وتدريبهم المستمر، وتطوير مؤشرات قياس أثر تدخلاتهم على السلامة النفسية وجودة تجربة الطفل وأسرته، مشيرًا إلى أهمية إدراج معايير وإجراءات موحدة لتقييم وعلاج الألم لدى الأطفال، بما يتوافق مع أفضل الممارسات الطبية تعزيزًا لمفهوم السلامة العاطفية.<br> وبين أن هذا التوجه يأتي ضمن الجهود الوطنية الرامية إلى الارتقاء بجودة الرعاية الصحية المقدمة للأطفال، وتعزيز الجوانب النفسية والاجتماعية المصاحبة للعلاج، بما يُسهم في تحسين تجربة الطفل وأسرته داخل المنشآت الصحية، ويواكب مستهدفات تطوير القطاع الصحي ورفع كفاءة الخدمات المقدمة وفق أفضل الممارسات المعتمدة".</p>', 'saudi-health', 'واس', NULL, '/objects/uploads/9bf79637-0f91-4be4-80de-096cb08a2212', NULL, 'اتفاقية لتحسين جودة حياة الأطفال بالسعودية', 'اتفاقية بين سباهي وحياة الطفل تركز على تطوير معايير الاعتماد لتعزيز الرعاية الصحية النفسية والجسدية للأطفال المرضى وأسرهم في السعودية.', '{"جودة الحياة","الرعاية الصحية للأطفال",سباهي,"الصحة النفسية للأطفال","معايير الاعتماد"}', false, 'published', NULL, NULL, '2026-01-24 17:24:33.996', '2026-01-24 17:24:35.290895', '2026-01-24 17:24:35.290895');
INSERT INTO public.news VALUES ('cdeba257-fc2a-431a-bb35-207a39d6e4f9', '09ce625', 'اكتشاف علاج جديد لمرض الزهايمر يظهر نتائج واعدة في التجارب السريرية', NULL, 'أعلن باحثون في جامعة هارفارد عن تطوير علاج جديد لمرض الزهايمر أظهر نتائج إيجابية في المراحل الأولى من التجارب السريرية.', 'باحثون في جامعة هارفارد يعلنون عن اكتشاف علاج جديد لمرض الزهايمر. العلاج الجديد يستهدف البروتينات المتراكمة في الدماغ والتي تسبب المرض.

أظهرت التجارب السريرية الأولية تحسناً ملحوظاً في الذاكرة والوظائف الإدراكية لدى المرضى. الباحثون يخططون لإجراء تجارب موسعة خلال العام المقبل.

يتوقع الخبراء أن يكون هذا العلاج متاحاً للجمهور خلال 3-5 سنوات إذا استمرت النتائج الإيجابية.', 'health-news', 'جامعة هارفارد', 'https://www.harvard.edu', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-11-03 00:00:00', '2026-01-24 13:59:53.943078', '2026-01-24 13:59:53.943078');
INSERT INTO public.news VALUES ('dfbc09a3-5daf-4792-a0f0-302e99be530a', '4bb7840', 'دراسة: المشي 10,000 خطوة يومياً يقلل خطر الأمراض القلبية بنسبة 50%', NULL, 'دراسة جديدة تؤكد أن المشي المنتظم له تأثير كبير على صحة القلب والأوعية الدموية.', 'نشرت مجلة القلب الأمريكية دراسة شاملة شملت 100,000 مشارك على مدى 10 سنوات. الدراسة وجدت أن الأشخاص الذين يمشون 10,000 خطوة يومياً لديهم خطر أقل بنسبة 50% للإصابة بأمراض القلب.

الباحثون يؤكدون أن المشي المنتظم يحسن ضغط الدم، يقلل الكوليسترول، ويساعد في التحكم بالوزن. النتائج تشير إلى أن حتى المشي بوتيرة معتدلة له فوائد صحية كبيرة.', 'health-news', 'جمعية القلب الأمريكية', 'https://www.heart.org', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-11-02 00:00:00', '2026-01-24 13:59:53.995389', '2026-01-24 13:59:53.995389');
INSERT INTO public.news VALUES ('a9cdaca1-a4a6-448a-a18f-2df63b0e845b', '521903e', 'تقنية جديدة للكشف المبكر عن سرطان الرئة بدقة 98%', NULL, 'طور باحثون في معهد ماساتشوستس للتقنية نظام ذكاء اصطناعي قادر على اكتشاف سرطان الرئة في مراحله الأولى.', 'كشف فريق بحثي في معهد MIT عن تقنية ذكاء اصطناعي جديدة قادرة على تحليل صور الأشعة المقطعية واكتشاف سرطان الرئة بدقة تصل إلى 98%.

التقنية الجديدة تتفوق على الأطباء في اكتشاف الأورام الصغيرة جداً التي يصعب رؤيتها بالعين المجردة.

يتوقع أن تساهم هذه التقنية في إنقاذ آلاف الأرواح سنوياً من خلال الكشف المبكر.', 'health-news', 'معهد MIT', 'https://www.mit.edu', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-28 00:00:00', '2026-01-24 13:59:54.22428', '2026-01-24 13:59:54.22428');
INSERT INTO public.news VALUES ('ec04aa73-83fa-4b20-9983-4c153a745e18', '3f0f183', 'الإمارات تفتتح أكبر مستشفى ذكي في الشرق الأوسط', NULL, 'افتتاح مستشفى متكامل يعتمد على الذكاء الاصطناعي والروبوتات في العمليات الجراحية.', 'افتتحت الإمارات مستشفى المستقبل الذكي في دبي، وهو أكبر منشأة صحية ذكية في المنطقة.

المستشفى يتميز بـ:
- غرف عمليات روبوتية
- نظام ذكي لإدارة المرضى
- صيدلية آلية بالكامل
- طاقم تمريض روبوتي

المستشفى يستوعب 1000 سرير ويخدم أكثر من مليون مريض سنوياً.', 'health-news', 'وزارة الصحة الإماراتية', 'https://www.mohap.gov.ae', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-24 00:00:00', '2026-01-24 13:59:54.406766', '2026-01-24 13:59:54.406766');
INSERT INTO public.news VALUES ('76e808af-2661-4373-99a4-839a974509c5', '4268877', 'هل سماعات الأذن تهدد سمعك؟ تحذيرات طبية خطيرة', 'استخدام خاطئ يُسبب فقدان السمع والطنين المستمر', 'الدكتور فلاديمير زايتسيف يكشف عن مخاطر استخدام سماعات الرأس لفترات طويلة ودورها في تلف الخلايا الشعرية بالأذن الداخلية. استخدام الصوت العالي يؤدي لفقدان السمع المزمن، خاصة بين الشباب. الأطباء ينصحون بتقليل الاستخدام واستعمال خاصية إلغاء الضوضاء.', '<p>حذر الدكتور فلاديمير زايتسيف، أخصائي أمراض الأذن والحنجرة، من أن الاستماع المستمر للموسيقى عبر سماعات الرأس يؤدي إلى تلف غير قابل للإصلاح في “الخلايا الشعرية” بالأذن الداخلية. وأوضح في تصريحات نقلتها (آر تي) أن هذه الخلايا هي المسؤول الأول عن تحويل الاهتزازات الصوتية إلى إشارات يفهمها الدماغ، وهي خلايا لا تتجدد؛ مما يعني أن تضررها المتكرر بفعل الصوت العالي ينتهي بفقدان سمع دائم وحالات من الطنين المستمر.</p><p style="text-align: right;">تكمن الخطورة في أن الجهاز السمعي البشري مصمم للعمل ضمن نطاق فيزيولوجي محدود، وتجاوز هذا النطاق عبر “سماعات الأذن” الملاصقة للقناة السمعية يضع ضغطاً هائلاً على العصب السمعي. وبحسب الخبراء، فإن الشباب والمراهقين هم الفئة الأكثر عرضة للإصابة بـ “فقدان السمع الحسي العصبي” نتيجة رفع مستوى الصوت لتغطية الضجيج الخارجي، وهو ما يحول هواية يومية بسيطة إلى مسبب لأمراض عصبية مزمنة.</p><p style="text-align: right;">يوصي الأطباء بقاعدة “الساعة الواحدة” كحد أقصى للاستخدام اليومي، مع تقسيمها إلى فترتين مدة كل منهما 30 دقيقة. كما يُنصح بالانتقال إلى مكبرات الصوت الخارجية كلما أمكن ذلك، أو استخدام سماعات الرأس المزودة بخاصية “إلغاء الضوضاء” (Noise Cancelling)؛ لأنها تتيح الاستماع بوضوح دون الحاجة لرفع الصوت لمستويات خطرة، مما يحمي الخلايا الحسية من التآكل التدريجي ويحافظ على سلامة العصب السمعي لسنوات أطول.</p>', 'health-news', NULL, NULL, '/objects/uploads/79efa703-dea9-41e3-b696-f57c1d3e5226', ' الاستماع المستمر للموسيقى عبر سماعات الرأس يؤدي إلى تلف', 'هل سماعات الأذن تهدد سمعك؟', 'تحذيرات طبية تكشف مخاطر سماعات الرأس على الأذن الداخلية وطرق الوقاية لحماية السمع وضمان سلامة الجهاز العصبي السمعي.', '{"سماعات الأذن","فقدان السمع","خلايا شعرية","طنين الأذن","إلغاء الضوضاء","العصب السمعي","مشاكل السمع"}', false, 'published', NULL, NULL, '2026-01-24 15:02:41.165', '2026-01-24 15:02:41.775834', '2026-01-24 15:02:41.775834');
INSERT INTO public.news VALUES ('6af1b1d6-e038-4df0-a5f8-65d8f94cab6a', '9465fc7', 'انسحاب أمريكا من منظمة الصحة العالمية: انقسام داخلي!', 'كاليفورنيا تستجيب عالمياً رغم الانسحاب الرسمي', 'انسحبت الولايات المتحدة رسمياً من منظمة الصحة العالمية بعد 78 عاماً. كاليفورنيا تتحدى قرار واشنطن بانضمامها للشبكة العالمية وسط انقسام سياسي حول التهديدات الصحية الدولية.', '<p>أكملت الولايات المتحدة رسمياً إجراءات انسحابها من منظمة الصحة العالمية، لتنهي التزاماً دولياً دام 78 عاماًK وفي خطوة مثلت طعنة سياسية لقرار البيت الأبيض، أعلنت ولاية كاليفورنيا انضمامها الفردي لشبكة الاستجابة العالمية التابعة للمنظمة، في تحرك يكشف عن انقسام داخلي حاد حول كيفية إدارة التهديدات البيولوجية العابرة للحدود.</p><p style="text-align: right;"><strong>لماذا انسحبت واشنطن؟</strong></p><p style="text-align: right;">(جذور الأزمة) اتخذت إدارة الرئيس دونالد ترامب قرار الانسحاب بناءً على ثلاثة محاور رئيسية:</p><p style="text-align: right;"><strong>اتهامات الفشل الميداني:</strong></p><p style="text-align: right;">ترى الإدارة الأمريكية أن المنظمة أخفقت بشكل كارثي في بداية جائحة كورونا، وتأخرت في إعلان الطوارئ العالمية.</p><p style="text-align: right;"><strong>النفوذ الصيني:</strong></p><p style="text-align: right;">اتهمت واشنطن المنظمة بالانحياز لبكين والمساعدة في “تسييس” أصل الفيروس، معتبرة أن أمريكا -الممول الأكبر- لم تعد تملك صوتاً موازناً لهذا النفوذ.</p><p style="text-align: right;"><strong>السيادة المالية:</strong></p><p style="text-align: right;">رغبت واشنطن في تحويل ميزانيتها المقدرة بـ 450 مليون دولار سنوياً من المنظمة الدولية إلى مشاريع صحية أمريكية خالصة تحت شعار “أمريكا أولاً”.</p><p style="text-align: right;"><strong>لماذا تتمرد الولايات (كاليفورنيا نموذجاً)؟</strong></p><p style="text-align: right;">يأتي تمرد ولاية كاليفورنيا مدفوعاً بضرورات واقعية تتجاوز الخلاف السياسي:</p><p style="text-align: right;"><strong>الأمن الصحي المستقل:</strong></p><p style="text-align: right;">كاليفورنيا تمتلك خامس أكبر اقتصاد في العالم، وبها موانئ ومطارات عالمية تجعلها خط دفاع أول. الانسحاب الفيدرالي يحرم مختبرات الولاية من الوصول السريع لبيانات الأمراض الناشئة التي توفرها المنظمة.</p><p style="text-align: right;"><strong>الاقتصاد والبحث العلمي:</strong></p><p style="text-align: right;">تضم الولاية مراكز أبحاث عالمية وشركات أدوية كبرى في “سيليكون فالي”، وهذه المؤسسات تحتاج للغطاء الدولي الذي توفره المنظمة لتصدير ابتكاراتها والمشاركة في الأبحاث العالمية.</p><p style="text-align: right;"><strong>الصدام الدستوري:</strong></p><p style="text-align: right;">يتيح النظام الفيدرالي الأمريكي للولايات هامشاً من المناورة في الاتفاقيات “الفنية”. كاليفورنيا لم تنضم كـ “دولة عضو” (وهو أمر غير قانوني)، بل انضمت كـ “شريك فني” في شبكة الاستجابة (GOARN)، وهي ثغرة قانونية سمحت لها بالبقاء في المظلة الدولية دون كسر القانون الفيدرالي صراحة.</p><p style="text-align: right;"><strong>هل تنهار الوحدة الصحية الأمريكية؟</strong></p><p style="text-align: right;">تحرك كاليفورنيا يفتح الباب أمام “دبلوماسية الولايات”؛ حيث بدأت ولايات زرقاء (ديمقراطية) أخرى في دراسة خطوات مماثلة. هذا التشرذم يعني أن العالم سيتعامل مع أمريكا ككيانات صحية منفصلة: واشنطن في عزلة، وكاليفورنيا (وربما نيويورك لاحقاً) في قلب التعاون الدولي.</p><p style="text-align: right;">يضع هذا الانقسام منظمة الصحة العالمية في موقف حرج؛ فهي بحاجة لخبرات كاليفورنيا الفنية وميزانيتها المحلية، لكنها تخشى إغضاب الحكومة الفيدرالية. وبحسب لقاء حاكم كاليفورنيا والمدير العام للمنظمة في “دافوس”، فإن التوجه القادم هو خلق “مسارات بديلة” تضمن بقاء الكفاءات الأمريكية داخل النظام العالمي، بانتظار تغير المناخ السياسي في واشنطن الذي قد يعيد توحيد الصف الصحي الأمريكي مرة أخرى.</p>', 'health-news', 'رويترز', NULL, '/objects/uploads/9ee92b71-7fab-486c-8c83-90ebfdf7bf4e', 'حاكم ولاية كاليفورنيا الأمريكية غافين نيوسوم', 'انسحاب أمريكا من منظمة الصحة العالمية', 'أمريكا تنهى علاقتها بمنظمة الصحة العالمية بعد سبعة عقود. كاليفورنيا تتخذ موقفاً منفرداً في مواجهة القرارات الفيدرالية.', '{"انسحاب أمريكا","منظمة الصحة العالمية",كاليفورنيا,"السياسة الصحية","أمن صحي","الأبحاث العالمية",كورونا}', false, 'published', NULL, NULL, '2026-01-24 15:09:25.118', '2026-01-24 15:09:28.053413', '2026-01-24 15:09:28.053413');
INSERT INTO public.news VALUES ('4fdebe88-4c5d-4640-a5fa-0a9f07963980', 'caa68cb', 'برعاية أمير المنطقة الشرقية غدًا ينطلق مؤتمر الرعاية الصحية الأولية', NULL, 'كبسولة الصحية &#8211; واس يرعى صاحب السمو الملكي الأمير سعود بن نايف بن عبدالعزيز أمير المنطقة الشرقية، غدًا الأحد، حفل تدشين مؤتمر الرعاية الصحية الأولية، الذي ينظمه تجمع الشرقية الصحي، ويستمر لمدة يومين، وذلك في فندق شيراتون الدمام. ويهدف المؤتمر إلى تسليط الضوء على دور الرعاية الصحية الأولية في ت', '<p>كبسولة الصحية &#8211; واس</p>
<p>يرعى صاحب السمو الملكي الأمير سعود بن نايف بن عبدالعزيز أمير المنطقة الشرقية، غدًا الأحد، حفل تدشين مؤتمر الرعاية الصحية الأولية، الذي ينظمه تجمع الشرقية الصحي، ويستمر لمدة يومين، وذلك في فندق شيراتون الدمام.</p>
<p>ويهدف المؤتمر إلى تسليط الضوء على دور الرعاية الصحية الأولية في تعزيز جودة الخدمات الصحية وتحسين تجربة المستفيد، من خلال مناقشة أحدث الممارسات والتجارب المتقدمة في هذا المجال.</p>
<p>ويتضمن المؤتمر أربع جلسات علمية، بمشاركة 12 مشاركًا، وأكثر من 20 متحدثًا من الخبراء والمختصين على مستوى المملكة.</p>
<p>ويشهد المؤتمر عرض أكثر من 30 مشروعًا وبحثًا تحسينيًا من مختلف أقسام ومنشآت تجمع الشرقية الصحي، تستعرض مبادرات تطويرية وتجارب نوعية تسهم في رفع كفاءة الأداء وتحسين مخرجات الرعاية الصحية الأولية، بما ينسجم مع مستهدفات التحول الصحي ورؤية المملكة 2030.</p>
<p>يُذكر أن عدد مراكز الرعاية الصحية الأولية التابعة لتجمع الشرقية الصحي يبلغ 120 مركزًا، من بينها 8 مراكز استشارية في مدينة الدمام ومحافظة الخبر ومحافظة القطيف.</p>
<p><strong> </strong></p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/2a721ec5-2ee0-4cb8-857f-dfc9f49e3a8d.webp', 'برعاية أمير المنطقة الشرقية غدًا ينطلق مؤتمر الرعاية الصحية الأولية', 'برعاية أمير المنطقة الشرقية غدًا ينطلق مؤتمر الرعاية الصحية الأولية', 'كبسولة الصحية &#8211; واس يرعى صاحب السمو الملكي الأمير سعود بن نايف بن عبدالعزيز أمير المنطقة الشرقية، غدًا الأحد، حفل تدشين مؤتمر الرعاية الصحية الأولية، الذي', '{"أميلر الشرقية","مؤتمر الرعاية الصحية الأولية"}', false, 'published', NULL, NULL, '2026-01-24 16:48:35', '2026-01-24 16:23:11.751812', '2026-01-24 16:23:11.751812');
INSERT INTO public.news VALUES ('4d102a15-f238-4b1b-82ab-5b0c95b8db97', 'de51762', 'بصمة طبية سعودية.. الحرس الوطني ينهي معاناة عيوب "صيوان الأذن"', NULL, 'متابعة – كبسولة الصحية أعلنت الشؤون الصحية بوزارة الحرس الوطني عن نجاح أول عمليتين لترميم عيوب صيوان الأذن الخَلقية Microtia)) معلنةً بذلك إطلاق برنامج وطني متخصص لترميم هذه العيوب باستخدام الغرسات الطبية المتقدمة. ويأتي هذا الإنجاز كجزء من استراتيجية الوزارة لتوطين أحدث الجراحات الدقيقة والمعقدة في', '<p>متابعة – كبسولة الصحية</p>
<p>أعلنت الشؤون الصحية بوزارة الحرس الوطني عن نجاح أول عمليتين لترميم عيوب صيوان الأذن الخَلقية Microtia)) معلنةً بذلك إطلاق برنامج وطني متخصص لترميم هذه العيوب باستخدام الغرسات الطبية المتقدمة. ويأتي هذا الإنجاز كجزء من استراتيجية الوزارة لتوطين أحدث الجراحات الدقيقة والمعقدة في المملكة.</p>
<p>وتبرز أهمية هذا البرنامج في قدرته على تقديم حلول جراحية متطورة تنجز عبر &#8220;عملية واحدة فقط&#8221;، وهو ما يمثل نقلة نوعية مقارنة بالأساليب التقليدية. كما يتيح البرنامج التدخل المبكر للأطفال دون سن السادسة، مما يساهم في تحسين جودة حياتهم واندماجهم المجتمعي في سن مبكرة، بناءً على تقييم طبي ومعايير إكلينيكية دقيقة.</p>
<p>ويستهدف البرنامج تعزيز ريادة المملكة في الجراحات الترميمية المتقدمة، وتوفير بيئة علاجية تتبنى أحدث التقنيات العالمية لخدمة المرضى، مما يقلل من فترات التعافي والعبء النفسي والجسدي على الأطفال وذويهم.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/800c007f-576b-48e7-a093-49b61465dfa7.jpg', 'بصمة طبية سعودية.. الحرس الوطني ينهي معاناة عيوب &#8220;صيوان الأذن&#8221;', 'بصمة طبية سعودية.. الحرس الوطني ينهي معاناة عيوب &#8220;صيوان الأذن&#8221;', 'متابعة – كبسولة الصحية أعلنت الشؤون الصحية بوزارة الحرس الوطني عن نجاح أول عمليتين لترميم عيوب صيوان الأذن الخَلقية Microtia)) معلنةً بذلك إطلاق برنامج وطني متخ', '{"الشؤون الصحية بوزارة الحرس الوطني","ترميم صيوان الأذن"}', false, 'published', NULL, NULL, '2026-01-23 22:41:15', '2026-01-24 16:23:16.066861', '2026-01-24 16:23:16.066861');
INSERT INTO public.news VALUES ('33fd60af-c85e-48c2-9aed-42c7ac6c9767', 'f4717aa', '"كيمارك" يرسم مستقبل الابتكار الصحي بالذكاء الاصطناعي', NULL, 'كبسولة الصحية &#8211; واس ينطلق في الرياض خلال الفترة من 4 إلى 5 فبراير 2026 المؤتمر الدولي الثالث للدراسات السريرية، الذي ينظمه مركز الملك عبدالله العالمي للأبحاث الطبية (كيمارك) تحت شعار &#8220;صوت الأمل&#8221;. ويجمع هذا الحدث نخبة من الخبراء وصنّاع القرار العالميين لتعزيز منظومة البحث العلمي وتط', '<p>كبسولة الصحية &#8211; واس</p>
<p>ينطلق في الرياض خلال الفترة من 4 إلى 5 فبراير 2026 المؤتمر الدولي الثالث للدراسات السريرية، الذي ينظمه مركز الملك عبدالله العالمي للأبحاث الطبية (كيمارك) تحت شعار &#8220;صوت الأمل&#8221;.</p>
<p>ويجمع هذا الحدث نخبة من الخبراء وصنّاع القرار العالميين لتعزيز منظومة البحث العلمي وتطوير بروتوكولات الدراسات السريرية بما يضمن أثراً صحياً مستداماً.</p>
<p>وتأتي أهمية هذا التجمع من كونه منصة لمناقشة التوجهات العالمية الحديثة، مع تركيز خاص على دمج التقنيات الرقمية وتوظيف الذكاء الاصطناعي في الأبحاث الطبية، كما يهدف المؤتمر إلى تمكين المرضى وتحسين وصولهم للدراسات السريرية، مع ضمان الالتزام الصارم بالممارسات الأخلاقية التي تعزز الثقة بين المؤسسات البحثية والمجتمع.</p>
<p>ويسعى المؤتمر من خلال جلساته إلى استشراف حلول مبتكرة لمواجهة التحديات الراهنة في القطاع الصحي، عبر إبراز قصص النجاح وتعزيز الشراكات الاستراتيجية بين الجهات البحثية. ويؤكد هذا التحرك دور المملكة المتنامي كمركز دولي لدعم الابتكار الطبي وتحسين جودة الرعاية الصحية عبر الأبحاث العلمية المتقدمة.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/7fa8f535-47e2-4f53-82eb-79d3a43ec9c7.jpg', '&#8220;كيمارك&#8221; يرسم مستقبل الابتكار الصحي بالذكاء الاصطناعي', '&#8220;كيمارك&#8221; يرسم مستقبل الابتكار الصحي بالذكاء الاصطناعي', 'كبسولة الصحية &#8211; واس ينطلق في الرياض خلال الفترة من 4 إلى 5 فبراير 2026 المؤتمر الدولي الثالث للدراسات السريرية، الذي ينظمه مركز الملك عبدالله العالمي للأب', '{كيمارك,"مؤتمر صوت الأمل"}', false, 'published', NULL, NULL, '2026-01-23 19:11:51', '2026-01-24 16:23:16.402562', '2026-01-24 16:23:16.402562');
INSERT INTO public.news VALUES ('86ab0b42-5bf5-49f9-b701-90ede69bf5d5', 'fecfdf9', 'مركز التميّز للعيون يعلن نجاح أول عملية متقدمة لعلاج الجلوكوما', NULL, 'متابعة – كبسولة الصحية أعلن مركز التميّز للعيون في تجمع الرياض الصحي الأول عن نجاح إجراء أول عملية PreserFlo MicroShunt لعلاج الجلوكوما (المياه الزرقاء) في مستشفى الإيمان، تحت إشراف استشاري طب وجراحة العيون الدكتور حسن الكويكبي، بما يعزز منظومة علاج الجلوكوما وأمراض العصب البصري وفق أحدث الممارسات ا', '<p>متابعة – كبسولة الصحية</p>
<p>أعلن مركز التميّز للعيون في تجمع الرياض الصحي الأول عن نجاح إجراء أول عملية PreserFlo MicroShunt لعلاج الجلوكوما (المياه الزرقاء) في مستشفى الإيمان، تحت إشراف استشاري طب وجراحة العيون الدكتور حسن الكويكبي، بما يعزز منظومة علاج الجلوكوما وأمراض العصب البصري وفق أحدث الممارسات العالمية، وفقاً لما نشرته صحيفة الرياض.</p>
<p>وتُعد تقنية PreserFlo MicroShunt من التقنيات الجراحية المتقدمة التي تمثل نقلة نوعية في علاج الجلوكوما، لما توفره من خفض فعّال لضغط العين مع مستوى عالٍ من الأمان، وتقليل الحاجة إلى التدخلات الجراحية التقليدية، بما ينعكس إيجابًا على النتائج العلاجية طويلة المدى للمرضى.</p>
<p>ويأتي هذا الإنجاز ضمن سياق أداء سريري متكامل حققه مركز التميّز للعيون خلال عام 2025، حيث قدّم ما يزيد على 44,438 خدمة تشخيصية وعلاجية عبر عيادات العيون وعيادات البصريات، إلى جانب تنفيذ 3,016 عملية جراحية شملت نطاقًا واسعًا من الحالات المتقدمة، من جراحات الماء الأبيض والماء الأزرق، إلى عمليات الشبكية، وتصحيح الإبصار، وزراعة القرنية، إضافة إلى عمليات ترميم محجر العين باستخدام المنظار، ما يعكس تنوّع الخبرات وعمق التخصص والجاهزية السريرية داخل المركز.</p>
<p>وأكد الدكتور حسن الكويكبي أن إدخال هذه التقنية يمثل خطوة استراتيجية لتوسيع خيارات علاج الجلوكوما، ويجسّد جاهزية الفرق الطبية لتقديم رعاية تخصصية دقيقة وفق أعلى معايير الجودة والسلامة.</p>
<p>من جانبه، أوضح المدير الطبي لمركز التميّز للعيون الدكتور محمد العنزي أن هذا الإنجاز يعكس نضج النموذج السريري والتشغيلي للمركز، وقدرته على تحويل الحجم التشغيلي الكبير إلى قيمة صحية ملموسة، مؤكدًا استمرار المركز في توطين التقنيات المتقدمة وبناء القدرات الوطنية، بما يعزز مكانته كمركز مرجعي في التخصصات الدقيقة لطب وجراحة العيون.</p>
<p>ويواصل مركز التميّز للعيون التزامه بتقديم رعاية صحية متقدمة تتمحور حول المريض، وتسهم في تحسين جودة الحياة، بما ينسجم مع مستهدفات التحول الصحي ورفع كفاءة الخدمات التخصصية.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/92dfda37-e46f-4aa0-aa21-031027111b81.jpg', 'مركز التميّز للعيون يعلن نجاح أول عملية متقدمة لعلاج الجلوكوما', 'مركز التميّز للعيون يعلن نجاح أول عملية متقدمة لعلاج الجلوكوما', 'متابعة – كبسولة الصحية أعلن مركز التميّز للعيون في تجمع الرياض الصحي الأول عن نجاح إجراء أول عملية PreserFlo MicroShunt لعلاج الجلوكوما (المياه الزرقاء) في مستش', '{الجلوكوما,"مركز التميز للعيون"}', false, 'published', NULL, NULL, '2026-01-22 20:20:06', '2026-01-24 16:23:19.727523', '2026-01-24 16:23:19.727523');
INSERT INTO public.news VALUES ('e38a4072-a7a0-448d-b702-78ff400e2983', '6ce463a', '"التخصصي" يوقّع مذكرة تفاهم في مجال الأمراض النادرة', NULL, 'كبسولة الصحية &#8211; واس وقّع مستشفى الملك فيصل التخصصي ومركز الأبحاث مذكرة تفاهم مع سيرفييه العربية السعودية للتجارة؛ بهدف التعاون في مجالات علمية وسريرية مرتبطة بالأمراض النادرة، بما في ذلك الأورام الدِّبقية، التي تُعد من المجالات التي تستدعي مزيدًا من العمل البحثي والسريري في المملكة والمنطقة، ل', '<p>كبسولة الصحية &#8211; واس</p>
<p>وقّع مستشفى الملك فيصل التخصصي ومركز الأبحاث مذكرة تفاهم مع سيرفييه العربية السعودية للتجارة؛ بهدف التعاون في مجالات علمية وسريرية مرتبطة بالأمراض النادرة، بما في ذلك الأورام الدِّبقية، التي تُعد من المجالات التي تستدعي مزيدًا من العمل البحثي والسريري في المملكة والمنطقة، لا سيما أنها تصيب مرضى في مراحل عمرية نشطة، بما ينعكس سلبًا على جودة حياتهم ومسارهم العلاجي.</p>
<p>وتنص المذكرة، التي وُقِّعت في مقر المستشفى بالرياض، على إرساء إطار عام للتعاون بين الجانبين في المجالات ذات الاهتمام المشترك، بما يدعم تطوير المعرفة المتخصصة بالأورام الدِّبقية ومجالات الأورام الأخرى ذات الصلة داخل المملكة، إلى جانب استكشاف فرص توليد رؤى مستمدة من الممارسة السريرية وتقييم مجالات محتملة للابتكار في الصحة الرقمية.</p>
<p>وتسعى المذكرة إلى دعم المبادرات البحثية، واستكشاف فرص الابتكار في الصحة الرقمية، إضافة إلى التبادل العلمي والتعليم الطبي، وذلك من خلال المؤتمرات والندوات وورش العمل والأنشطة التعليمية ذات الصلة، إضافة إلى مبادرات تهدف إلى دعم الوعي وبناء القدرات في مجال الطب الدقيق وفحوصات الجينوم ذات الصلة.</p>
<p>يُذكر أن مستشفى الملك فيصل التخصصي ومركز الأبحاث صُنف الأول في الشرق الأوسط وشمال أفريقيا والـ 15 عالميًا ضمن قائمة أفضل 250 مؤسسة رعاية صحية أكاديمية حول العالم لعام 2025، والعلامة التجارية الصحية الأعلى قيمة في المملكة والشرق الأوسط، وذلك بحسب براند فاينانس لعام 2025، كما أُدرج ضمن قوائم مجلة نيوزويك لأفضل المستشفيات في العالم لعام 2025، وأفضل المستشفيات الذكية لعام 2026، وأفضل المستشفيات المتخصصة لعام 2026.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/5b8e5cfb-aba6-4712-a76c-c17a5f15b437.webp', '&#8220;التخصصي&#8221; يوقّع مذكرة تفاهم في مجال الأمراض النادرة', '&#8220;التخصصي&#8221; يوقّع مذكرة تفاهم في مجال الأمراض النادرة', 'كبسولة الصحية &#8211; واس وقّع مستشفى الملك فيصل التخصصي ومركز الأبحاث مذكرة تفاهم مع سيرفييه العربية السعودية للتجارة؛ بهدف التعاون في مجالات علمية وسريرية مرت', '{"الأمراض النادرة",التخصصي}', false, 'published', NULL, NULL, '2026-01-22 19:24:29', '2026-01-24 16:23:20.042129', '2026-01-24 16:23:20.042129');
INSERT INTO public.news VALUES ('fe191aad-30dd-4823-a879-7aa54299bd41', 'f315e0c', 'المعهد الوطني لأبحاث الصحة ينظم لقاءً متخصصًا', NULL, 'كبسولة الصحية &#8211;  واس نظّم المعهد الوطني لأبحاث الصحة لقاءً متخصصًا حول تعزيز الامتثال والجودة في الأبحاث الصحية، وذلك ضمن جهوده المستمرة للارتقاء بمنظومة البحث العلمي في المملكة، بحضور نخبة من المختصين وممثلي الجهات ذات العلاقة في القطاع الصحي والبحثي. وشهد اللقاء تكريم الرئيس التنفيذي للمعهد ', '<p>كبسولة الصحية &#8211;  واس</p>
<p>نظّم المعهد الوطني لأبحاث الصحة لقاءً متخصصًا حول تعزيز الامتثال والجودة في الأبحاث الصحية، وذلك ضمن جهوده المستمرة للارتقاء بمنظومة البحث العلمي في المملكة، بحضور نخبة من المختصين وممثلي الجهات ذات العلاقة في القطاع الصحي والبحثي.</p>
<p>وشهد اللقاء تكريم الرئيس التنفيذي للمعهد الدكتور فارس العنزي للجهات الحاصلة على اعتماد برنامج حماية المشتركين في الأبحاث (HRPP)، التي شملت مدينة الملك عبدالله الطبية بمكة المكرمة، ومجموعة الموسى الصحية بالأحساء، وجامعة الإمام عبدالرحمن بن فيصل بالدمام، وذلك تقديرًا لالتزامهم بتطبيق أعلى معايير أخلاقيات البحث العلمي وضمان حماية حقوق وسلامة المشتركين في الدراسات والأبحاث.</p>
<p>ويُعد برنامج حماية المشتركين في الأبحاث (HRPP) أحد الأهداف الإستراتيجية للمعهد الوطني لأبحاث الصحة، حيث يهدف إلى ترسيخ بيئة بحثية آمنة وأخلاقية، وتعزيز حماية المشتركين في الأبحاث الصحية، بما يضمن حقوقهم وكرامتهم، ويرفع من مستوى الامتثال المؤسسي للمعايير المعتمدة.</p>
<p>ويعمل البرنامج على تمكين المؤسسات البحثية من تطوير الهياكل التنظيمية والسياسات والإجراءات اللازمة لحماية المشتركين في الأبحاث، بما يسهم في تحسين جودة الأبحاث الصحية، وضمان إجرائها وفق أعلى المعايير الأخلاقية والعلمية، وتعزيز موثوقية مخرجات البحث العلمي في المملكة، وتحويل مخرجات الأبحاث الصحية إلى فوائد صحية واقتصادية وإيجاد الأثر منها من خلال تطبيق أعلى المعايير الأخلاقية في الأبحاث الانتقالية.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/0ec8638b-55ab-4f42-8a22-2d889736296e.jpg', 'المعهد الوطني لأبحاث الصحة ينظم لقاءً متخصصًا', 'المعهد الوطني لأبحاث الصحة ينظم لقاءً متخصصًا', 'كبسولة الصحية &#8211;  واس نظّم المعهد الوطني لأبحاث الصحة لقاءً متخصصًا حول تعزيز الامتثال والجودة في الأبحاث الصحية، وذلك ضمن جهوده المستمرة للارتقاء بمنظومة ', '{"المعهد الوطني لأبحاث الصحة"}', false, 'published', NULL, NULL, '2026-01-22 18:24:42', '2026-01-24 16:23:20.383719', '2026-01-24 16:23:20.383719');
INSERT INTO public.news VALUES ('2686eb6e-9348-46a4-935d-19af2bac37e0', 'ef47096', 'مجلس الضمان الصحي يعلن جزاءات الربع الرابع', NULL, 'كبسولة الصحية &#8211;  واس أعلن مجلس الضمان الصحي صدور 180 قرارًا يقضي بفرض جزاءات على أصحاب العمل خلال الربع الرابع من العام 2025، نتيجة مخالفة أحكام نظام الضمان الصحي. وأوضح المجلس أن إجمالي الغرامات المترتبة على أصحاب العمل بلغ 6,186,562.49 ريالًا، وذلك بعد التنبيه عليهم بتصحيح أوضاعهم وفق أحكام ', '<p>كبسولة الصحية &#8211;  واس</p>
<p>أعلن مجلس الضمان الصحي صدور 180 قرارًا يقضي بفرض جزاءات على أصحاب العمل خلال الربع الرابع من العام 2025، نتيجة مخالفة أحكام نظام الضمان الصحي.</p>
<p>وأوضح المجلس أن إجمالي الغرامات المترتبة على أصحاب العمل بلغ 6,186,562.49 ريالًا، وذلك بعد التنبيه عليهم بتصحيح أوضاعهم وفق أحكام نظام الضمان الصحي، استنادًا إلى المادة 14 التي تنص على أنه في حال لم يلتزم صاحب العمل بسداد الأقساط المستحقة عن العاملين لديه وأسرهم المشمولين بالنظام، فإنه يلزم بسدادها، إضافة إلى غرامة مالية لا تتجاوز قيمة الاشتراك السنوي لكل فرد، مع إمكانية منع المخالفين من استقدام العمالة مؤقتًا أو دائمًا.</p>
<p>وأكدت المتحدثة الرسمية لمجلس الضمان الصحي إيمان الطريقي، أن مجلس الضمان الصحي يتخذ إجراءات صارمة لتطبيق الأنظمة واللوائح كجهة معنية بتطبيق إلزامية التغطية الصحية على أصحاب العمل، بما يضمن استمرارية تقديم الرعاية الصحية للمستفيدين دون انقطاع.</p>
<p>وأضافت: &#8220;يسعى المجلس إلى تسهيل وصول المستفيدين إلى خدمات صحية عالية الجودة والكفاءة، وتمكين أصحاب العمل وتطوير قدرتهم على توفير التغطية الصحية، مع مواصلة متابعة الالتزام، ورصد المخالفات، وتطبيق الأنظمة بحق المنشآت غير الممتثلة بتوفير التغطية الصحية الإلزامية للعاملين لديهم وأسرهم المشمولين بالنظام&#8221;.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/e52b50a7-b976-4394-bd0e-8472ccbecc1f.jpg', 'مجلس الضمان الصحي يعلن جزاءات الربع الرابع', 'مجلس الضمان الصحي يعلن جزاءات الربع الرابع', 'كبسولة الصحية &#8211;  واس أعلن مجلس الضمان الصحي صدور 180 قرارًا يقضي بفرض جزاءات على أصحاب العمل خلال الربع الرابع من العام 2025، نتيجة مخالفة أحكام نظام الضم', '{"مجلس الضمان الصحي"}', false, 'published', NULL, NULL, '2026-01-22 16:44:58', '2026-01-24 16:23:20.710329', '2026-01-24 16:23:20.710329');
INSERT INTO public.news VALUES ('23ea65db-bd22-4b98-b717-7d6d752d216b', 'e613067', 'دراسة: التمارين الصباحية أفضل لحرق الدهون', NULL, 'بحث علمي يكشف أن ممارسة الرياضة صباحاً تحرق دهوناً أكثر بنسبة 20%.', 'أظهرت دراسة جديدة أن ممارسة التمارين الرياضية في الصباح الباكر تزيد من حرق الدهون بنسبة 20% مقارنة بالتمارين المسائية.

الأسباب:
- مستويات الكورتيزول المرتفعة صباحاً
- الجسم يستخدم الدهون كمصدر للطاقة
- تحسين الأيض طوال اليوم

ينصح بالتمرين قبل الإفطار.', 'health-news', 'مجلة الطب الرياضي', 'https://www.bjsm.bmj.com', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-16 00:00:00', '2026-01-24 13:59:54.769558', '2026-01-24 13:59:54.769558');
INSERT INTO public.news VALUES ('bf44b24e-6925-4d13-ba82-dc18b505e441', 'a1fbaf5', 'مُحافظ الطائف يستقبل المشرف على المدن الصحية بالمحافظة', NULL, 'كبسولة الصحية &#8211;  واس استقبل صاحب السمو الملكي الأمير سعود بن نهار بن سعود بن عبدالعزيز محافظ الطائف اليوم، المشرف على المدن الصحية بالمحافظة تركي دغريري. وتسلّم سموه خلال اللقاء التقرير السنوي للمدن الصحية بالمحافظة، مطلعًا على أبرز البرامج والمبادرات المنفذة، إلى جانب الخطط المستقبلية الهادفة', '<p>كبسولة الصحية &#8211;  واس</p>
<p>استقبل صاحب السمو الملكي الأمير سعود بن نهار بن سعود بن عبدالعزيز محافظ الطائف اليوم، المشرف على المدن الصحية بالمحافظة تركي دغريري.</p>
<p>وتسلّم سموه خلال اللقاء التقرير السنوي للمدن الصحية بالمحافظة، مطلعًا على أبرز البرامج والمبادرات المنفذة، إلى جانب الخطط المستقبلية الهادفة إلى رفع كفاءة الأعمال وتعزيز أثرها في تحسين جودة الحياة.</p>
<p>واستعرض اللقاء أوجه التعاون والتكامل بين مدينة الطائف وعدد من المدن الصحية في المملكة، بما يسهم في تبادل الخبرات وتطوير الممارسات الداعمة لمستهدفات المدن الصحية.</p>
<p>وثمّن سمو محافظ الطائف الجهود المبذولة في هذا المسار، مؤكدًا أهمية مواصلة العمل التكاملي بين الجهات ذات العلاقة بما يحقق مستهدفات رؤية المملكة 2030.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/376663d5-ea46-436b-8aef-8ded58d8a69e.webp', 'مُحافظ الطائف يستقبل المشرف على المدن الصحية بالمحافظة', 'مُحافظ الطائف يستقبل المشرف على المدن الصحية بالمحافظة', 'كبسولة الصحية &#8211;  واس استقبل صاحب السمو الملكي الأمير سعود بن نهار بن سعود بن عبدالعزيز محافظ الطائف اليوم، المشرف على المدن الصحية بالمحافظة تركي دغريري. ', '{"محافظ الطائف","وزارة الصحة"}', false, 'published', NULL, NULL, '2026-01-22 15:01:59', '2026-01-24 16:23:21.047168', '2026-01-24 16:23:21.047168');
INSERT INTO public.news VALUES ('c52e1042-75eb-495e-8a3a-989e997d390e', 'f087aa1', 'أمير نجران يتسلَّم التقرير السنوي لفرع وزارة الصحة بالمنطقة', NULL, 'كبسولة الصحية &#8211;  واس تسلَّم صاحب السموّ الملكي الأمير تركي بن هذلول بن عبد العزيز نائب أمير منطقة نجران التقرير السنوي لأعمال فرع وزارة الصحة بالمنطقة لعام 2025 م. جاء ذلك خلال استقبال سموه في مكتبه اليوم، المدير العام لفرع وزارة الصحة بالمنطقة الدكتور إبراهيم بن صالح بني هميم. وتضمَّن التقرير', '<p>كبسولة الصحية &#8211;  واس</p>
<p>تسلَّم صاحب السموّ الملكي الأمير تركي بن هذلول بن عبد العزيز نائب أمير منطقة نجران التقرير السنوي لأعمال فرع وزارة الصحة بالمنطقة لعام 2025 م.</p>
<p>جاء ذلك خلال استقبال سموه في مكتبه اليوم، المدير العام لفرع وزارة الصحة بالمنطقة الدكتور إبراهيم بن صالح بني هميم.</p>
<p>وتضمَّن التقرير أبرز منجزات الفرع والخطط التطويرية والمبادرات المجتمعية، وتنظيم الملتقيات العلمية، ومساهمات القطاع غير الربحي، إضافة إلى مؤشر نسبة متوسط العمر، ومؤشرات تجربة المستفيد من الخدمات الصحية المقدمة بالمنطقة.</p>
<p>وأكَّد سموه أهمية مواصلة العمل للارتقاء بجودة الخدمات الصحية، وتحقيق مستهدفات رؤية المملكة 2030، مشيدًا بجهود الفرع وما يقدمه من خدمات ومبادرات صحية.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/13e4c035-699f-4a14-9e08-78ec972a2c7f.webp', 'أمير نجران يتسلَّم التقرير السنوي لفرع وزارة الصحة بالمنطقة', 'أمير نجران يتسلَّم التقرير السنوي لفرع وزارة الصحة بالمنطقة', 'كبسولة الصحية &#8211;  واس تسلَّم صاحب السموّ الملكي الأمير تركي بن هذلول بن عبد العزيز نائب أمير منطقة نجران التقرير السنوي لأعمال فرع وزارة الصحة بالمنطقة لعا', '{"أمير نجران","وزارة الصحة"}', false, 'published', NULL, NULL, '2026-01-22 14:57:53', '2026-01-24 16:23:21.361039', '2026-01-24 16:23:21.361039');
INSERT INTO public.news VALUES ('6d2642a2-bb2d-4bdc-8636-5453b9aa4335', NULL, 'سارة جيسيكا باركر تكشف حلها لتشوش الرؤية المرتبط بالعمر', 'النجمة تعتمد قطرات العين بدل نظارات القراءة', 'سارة جيسيكا باركر تشارك تجربتها مع تشوش الرؤية القريبة المرتبط بالعمر، وتختار قطرات Mo Vizz لتحسين الرؤية. حملة تسلط الضوء على خيارات علاج تناسب الملايين.', '<p>أكدت سارة جيسيكا باركر أنها لن تسمح لتشوش الرؤية القريبة المرتبط بالعمر بأن ينتزع منها متعة القراءة؛ إذ اختارت وضع نظارات القراءة جانباً والاعتماد على قطرات عين موصوفة طبياً، في إطار حملة توعية بهذه الحالة الشائعة.</p><p>النجمة التي حصدت جائزة كارول بورنيت من الغولدن غلوب إلى جانب ست جوائز غولدن غلوب عن «Sex and the City»، معروفة بنهمها للكتب؛ فقد قرأت 153 كتاباً عام 2025 بصفتها حكماً لجائزة بوكر، كما رُشح الوثائقي الذي أنتجته «The Librarians» عام 2026 لجائزة بافتا. لكنها تكشف أن هوايتها تأثرت عندما بدأت تُلاحظ منذ نحو 15 عاماً صعوبة مريحة في قراءة النصوص عن قرب، قائلة إن عينيها كانت «تطلب المساعدة بلطف».</p><p>طبياً، يُعرف هذا التشوش باسم <strong>قصور البصر الشيخي</strong>، وهو فقدان تدريجي لقدرة العين على تركيز الرؤية القريبة يبدأ عادة بين سن الأربعين والخامسة والأربعين ويستمر حتى ستينيات العمر. يوضح راندي ماكلوغلين، أستاذ مساعد في طب العيون السريري بمركز ويكسنر في جامعة ولاية أوهايو، أن السبب هو تَصَلُّب عدسة العين البلورية مع التقدم في السن؛ وهي العدسة نفسها التي قد تتطور لاحقاً إلى إعتام عدسة (ماء أبيض). ويضيف أن الحالة غير قابلة للوقاية، وإن كان بعض الأشخاص يمتلكون «رؤية أحادية طبيعية» تجعل عيناً أكثر وضوحاً للقريب وأخرى للبعيد.</p><p>وتشمل العلامات الشائعة لتشوش الرؤية القريبة المرتبط بالعمر:</p><ul><li>صعوبة رؤية الأشياء القريبة بوضوح</li><li>الحاجة لإبعاد مواد القراءة عن العين للتركيز</li><li>إجهاد العين أو الإحساس بالتعب</li><li>الصداع بعد القراءة أو العمل القريب</li></ul><p>وغالباً ما تكون نظارات القراءة أو العدسات متعددة البؤر الحلّ الأول. غير أن باركر لجأت مؤخراً إلى وصفة لقطرات يومية تُعرف باسم Vizz، تمنح وضوحاً أفضل للرؤية القريبة لمدة تصل إلى 10 ساعات عبر <strong>تضييق حدقة العين</strong> لتحسين القدرة على التركيز على الأجسام القريبة دون التأثير في رؤية البعيد. وينبغي استخدام هذه القطرات وغيرها من الخيارات الدوائية تحت إشراف طبيب العيون؛ كما قد تختلف توافُر العلاجات بين البلدان.</p><p>بحسب التقديرات، فإن نحو 128 مليون شخص في الولايات المتحدة يعيشون مع تشوش الرؤية القريبة المرتبط بالعمر، ما يؤكد شيوع الحالة والحاجة للتوعية بخيارات العلاج المتاحة.</p>', 'misc', NULL, 'https://www.healthline.com/health-news/sarah-jessica-parker-talks-age-related-blurry-vision-treatment', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Sarah-Jessica-Parker-1296x728-header.jpg', NULL, 'حل سارة جيسيكا باركر لتشوش الرؤية المرتبط بالعمر', 'سارة جيسيكا باركر تعتمد قطرات يومية لمحاربة تشوش الرؤية القريبة المرتبط بالتقدم في العمر. حملة توعية تبرز خيارات العلاج.', '{"سارة جيسيكا باركر","تشوش الرؤية","قطرات عين","قصور البصر الشيخي","علاج الرؤية القريبة","صحة العين","نظارات القراءة"}', false, 'published', NULL, NULL, '2026-01-26 06:22:51.403012', '2026-01-26 06:22:51.403012', '2026-01-26 06:22:51.403012');
INSERT INTO public.news VALUES ('b3e62163-8847-4e48-889b-f519a377bc48', '90fb201', 'تذمّر من طول انتظار صرف الدواء في مستشفى الملك عبدالله الجامعي بجامعة الأميرة نورة', NULL, 'الرياض – كبسولة الصحية تذمر عدد من المراجعين والمرضى من طول مدة انتظار صرف الأدوية نتيجة الزحام أمام الصيدلية في مستشفى الملك عبد الله بن عبد العزيز الجامعي، التابع لـ جامعة الأميرة نورة بنت عبدالرحمن، مشيرين إلى أن فترة الانتظار تمتد أحيانًا لفترات أطول من المتوقع، الأمر الذي ينعكس &#8220;بحسب وصفه', '<p>الرياض – كبسولة الصحية</p>
<p>تذمر عدد من المراجعين والمرضى من طول مدة انتظار صرف الأدوية نتيجة الزحام أمام الصيدلية في مستشفى الملك عبد الله بن عبد العزيز الجامعي، التابع لـ جامعة الأميرة نورة بنت عبدالرحمن، مشيرين إلى أن فترة الانتظار تمتد أحيانًا لفترات أطول من المتوقع، الأمر الذي ينعكس &#8220;بحسب وصفهم&#8221; على تجربة المريض ورضاه عن الخدمة المقدمة، لا سيما في أوقات الذروة.</p>
<p>وأوضح عدد من المراجعين لصحيفة &#8220;كبسولة الصحية&#8221; أن الازدحام أمام صيدلية المستشفى يُعد من أبرز التحديات التي تواجههم بعد الانتهاء من الكشف الطبي، مطالبين بإيجاد حلول تنظيمية تسهم في تسريع إجراءات صرف الدواء وتحسين انسيابية الخدمة، خاصة لكبار السن وذوي الأمراض المزمنة.</p>
<p>وفي تعليق توضيحي لـ&#8221;كبسولة الصحية&#8221; نفى الدكتور محمد الحربي، مدير مستشفى الملك عبدالله بن عبدالعزيز الجامعي، صحة ما يتم تداوله بشأن طول مدة انتظار صرف الدواء، مؤكدًا أن متوسط زمن الصرف يتراوح ما بين ربع ساعة إلى 20 دقيقة.</p>
<p>إلى ذلك تؤكد &#8220;كبسولة الصحية&#8221; أن طرح هذه الملاحظات يأتي في إطار دورها الإعلامي المهني الهادف إلى نقل صوت المستفيدين، وتسليط الضوء على تجربة المريض، وتعزيز الحوار البنّاء بين المنشآت الصحية والمراجعين، بما ينعكس في تحسين جودة الخدمات الصحية والارتقاء بتجربة المستفيد.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/23256c9c-ed88-45cd-b0bf-003ddf98d9ad.jpg', 'تذمّر من طول انتظار صرف الدواء في مستشفى الملك عبدالله الجامعي بجامعة الأميرة نورة', 'تذمّر من طول انتظار صرف الدواء في مستشفى الملك عبدالله الجامعي بجامعة الأميرة نورة', 'الرياض – كبسولة الصحية تذمر عدد من المراجعين والمرضى من طول مدة انتظار صرف الأدوية نتيجة الزحام أمام الصيدلية في مستشفى الملك عبد الله بن عبد العزيز الجامعي، ال', '{"مستشفى الملك عبد الله بن عبد العزيز الجامعي"}', false, 'published', NULL, NULL, '2026-01-22 14:45:38', '2026-01-24 16:23:22.052328', '2026-01-24 16:23:22.052328');
INSERT INTO public.news VALUES ('0b447314-496d-40f0-a485-cb2791fb04e2', '6bf52ae', 'جمعية إشراق توقّع مذكرة تعاون مع مؤسسة سعي الوقفية', NULL, 'الرياض- كبسولة الصحية وقّعت الجمعية السعودية لاضطراب فرط الحركة وتشتت الانتباه (جمعية إشراق) مذكرة تعاون مشترك مع مؤسسة سعي الوقفية لتأهيل وتوظيف الأشخاص ذوي الإعاقة، وذلك في مدينة الرياض، في خطوة استراتيجية تهدف إلى تعزيز التكامل بين الجانبين وتوسيع أثر البرامج الاجتماعية والتنموية المقدمة للمستفيد', '<p>الرياض- كبسولة الصحية</p>
<p>وقّعت الجمعية السعودية لاضطراب فرط الحركة وتشتت الانتباه (جمعية إشراق) مذكرة تعاون مشترك مع مؤسسة سعي الوقفية لتأهيل وتوظيف الأشخاص ذوي الإعاقة، وذلك في مدينة الرياض، في خطوة استراتيجية تهدف إلى تعزيز التكامل بين الجانبين وتوسيع أثر البرامج الاجتماعية والتنموية المقدمة للمستفيدين.</p>
<p>وتهدف مذكرة التعاون إلى دعم وتمكين الأشخاص المشخصين باضطراب فرط الحركة وتشتت الانتباه (ADHD) من خلال التنسيق المشترك في مجالات التأهيل، والدعم النفسي والاجتماعي، والتوعية المجتمعية، إضافة إلى المساهمة في تعزيز فرص التوظيف والاستقرار المهني بما يحقق جودة حياة أفضل للمستفيدين.</p>
<p>وتضمنت المذكرة عددًا من مجالات التعاون، من أبرزها: ترشيح المؤهلين لشغل الفرص الوظيفية المتاحة، وتنفيذ برامج تدريبية وتأهيلية، وتقديم ورش تثقيفية متخصصة، إلى جانب تفعيل الحملات الإعلامية والتوعوية المشتركة، والمشاركة في المناسبات والأيام العالمية ذات العلاقة بالصحة النفسية والإعاقة.</p>
<p>وأكد الطرفان أن هذه الشراكة تأتي انطلاقًا من حرصهما على توحيد الجهود وتبادل الخبرات بما يخدم الفئات المستفيدة، ويسهم في تحقيق مستهدفات التنمية الاجتماعية، وفق الأنظمة واللوائح المعمول بها في المملكة العربية السعودية.</p>
<p>وتُعد هذه المذكرة امتدادًا لرسالة جمعية إشراق في دعم وتمكين المشخصين باضطراب فرط الحركة وتشتت الانتباه، وتعزيز الشراكات الفاعلة مع الجهات غير الربحية، بما يسهم في بناء مجتمع أكثر وعيًا واحتواءً.</p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/d39a6058-0b19-453c-858f-4e6a8f993461.png', 'جمعية إشراق توقّع مذكرة تعاون مع مؤسسة سعي الوقفية', 'جمعية إشراق توقّع مذكرة تعاون مع مؤسسة سعي الوقفية', 'الرياض- كبسولة الصحية وقّعت الجمعية السعودية لاضطراب فرط الحركة وتشتت الانتباه (جمعية إشراق) مذكرة تعاون مشترك مع مؤسسة سعي الوقفية لتأهيل وتوظيف الأشخاص ذوي ال', '{"جمعية إشراق","سعي الوقفية"}', false, 'published', NULL, NULL, '2026-01-22 09:25:54', '2026-01-24 16:23:22.439248', '2026-01-24 16:23:22.439248');
INSERT INTO public.news VALUES ('9df92fee-a6a2-48b3-ae8d-f28fdd14e6dd', 'd586946', '"التخصصي" يحتفل بتخريج 379 طبيبًا من برامج الزمالة والاختصاص', NULL, 'الرياض – كبسولة الصحية احتفل مستشفى الملك فيصل التخصصي ومركز الأبحاث بتخريج 379 طبيبًا من برامج شهادة الاختصاص والزمالة السعودية في مختلف التخصصات الطبية والصحية لعام 2025، ضمن التزامه بتأهيل الكوادر الطبية الوطنية وتعزيز جاهزيتها للإسهام في تطوير القطاع الصحي. وأقيم الحفل بقاعة الأميرة هيا بنت تركي', '<p>الرياض – كبسولة الصحية</p>
<p>احتفل مستشفى الملك فيصل التخصصي ومركز الأبحاث بتخريج 379 طبيبًا من برامج شهادة الاختصاص والزمالة السعودية في مختلف التخصصات الطبية والصحية لعام 2025، ضمن التزامه بتأهيل الكوادر الطبية الوطنية وتعزيز جاهزيتها للإسهام في تطوير القطاع الصحي.</p>
<p>وأقيم الحفل بقاعة الأميرة هيا بنت تركي للمؤتمرات بجامعة الفيصل بالرياض، تحت رعاية معالي الرئيس التنفيذي للمستشفى الدكتور ماجد بن إبراهيم الفياض، حيث شكّل أطباء برامج الزمالة العدد الأكبر بواقع 233 طبيبًا من مختلف البرامج، بينما تخرج 124 طبيبًا مقيماً، و22 خريجًا من برامج الدبلومات السريرية المختلفة.</p>
<p>ويُعد تخريج هذه الدفعة من الأطباء رافدًا للقطاع الصحي، ومساهمًا فاعلاً في دعم برنامج تحول القطاع الصحي، أحد برامج رؤية السعودية 2030، الذي يهدف لبناء نظام صحي نموذجي يعزز الوقاية، ويُمكّن الكوادر الوطنية من تقديم رعاية صحية متكاملة وفق أفضل الممارسات العالمية.</p>
<p>ويعكس هذا التخريج التزام التخصصي بالمساهمة في إعداد كوادر وطنية مؤهلة علميًا ومهنيًا، مستندًا إلى منظومة أكاديمية تقدم أكثر من 200 برنامج في مختلف التخصصات الطبية الدقيقة، يحظى العديد منها باعترافات دولية، ويتفرد بتقديم بعضها في المنطقة.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/14ab1cd5-4863-4e91-8d90-9f1d3a073a8a.jpg', '&#8220;التخصصي&#8221; يحتفل بتخريج 379 طبيبًا من برامج الزمالة والاختصاص', '&#8220;التخصصي&#8221; يحتفل بتخريج 379 طبيبًا من برامج الزمالة والاختصاص', 'الرياض – كبسولة الصحية احتفل مستشفى الملك فيصل التخصصي ومركز الأبحاث بتخريج 379 طبيبًا من برامج شهادة الاختصاص والزمالة السعودية في مختلف التخصصات الطبية والصحي', '{"الاختصاص والزمالة",التخصصي,"تخريج أطباء"}', false, 'published', NULL, NULL, '2026-01-21 18:36:12', '2026-01-24 16:23:25.055708', '2026-01-24 16:23:25.055708');
INSERT INTO public.news VALUES ('1264d37a-ce68-43bd-8e3c-fed67b5697d4', '4c81823', 'مناعتك أهم.. التطعيم هو خط الحماية الأول', NULL, 'متابعة  كبسولة الصحية أطلقت هيئة الصحة العامة (وقاية) حملة توعوية تحت شعار &#8220;مناعتك أهم&#8221;، شددت خلالها على أن التطعيم يظل خط الحماية الأول ضد العدوى. وأوضحت الهيئة أن هناك فئات محددة تعد الأكثر حاجة لتلقي التطعيمات والجرعات التعزيزية لحمايتهم من المخاطر الصحية، مؤكدة أن الالتزام باستكمال ا', '<p>متابعة  كبسولة الصحية</p>
<p>أطلقت هيئة الصحة العامة (وقاية) حملة توعوية تحت شعار &#8220;مناعتك أهم&#8221;، شددت خلالها على أن التطعيم يظل خط الحماية الأول ضد العدوى.</p>
<p>وأوضحت الهيئة أن هناك فئات محددة تعد الأكثر حاجة لتلقي التطعيمات والجرعات التعزيزية لحمايتهم من المخاطر الصحية، مؤكدة أن الالتزام باستكمال الجرعات، خاصة ضد &#8220;الحصبة&#8221;، هو ضرورة ملحة لتعزيز المناعة المجتمعية.</p>
<p>تكمن أهمية هذا التنبيه في تحديد الفئات &#8220;الأكثر عرضة للخطر&#8221; والتي تشمل: الأطفال، المراهقين، والمسافرين للمناطق الموبوءة، بالإضافة إلى الأشخاص الذين لا يعرفون تاريخهم التحصيني وما إذا كانوا قد تلقوا اللقاح سابقاً أم لا. استراتيجياً، تهدف هذه الخطوة إلى تقليل فرص انتشار الأوبئة بين الفئات النشطة مجتمعياً (مثل الطلاب والمسافرين)، مما يضمن استقرار الحالة الصحية العامة وتخفيف الضغط على المنشآت الطبية.</p>
<p>يجب على الأسر المبادرة بمراجعة السجلات التطعيمية لأطفالهم والتأكد من أخذ &#8220;الجرعة التعزيزية&#8221; لضمان حماية قصوى. وعلى المستوى المحلي، يعزز هذا التوجه من كفاءة برامج &#8220;التحصين الوطني&#8221; بما يتوافق مع المعايير العالمية للوقاية من الأمراض المعدية. إن حماية نفسك ومن تحب تبدأ بقرار بسيط وهو التأكد من أخذ اللقاح في وقته المحدد، لأن الوقاية دائماً أقل تكلفة وأضمن نتيجة من العلاج.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/8b0814bf-b573-40a2-93d2-b941d379da6a.jpg', 'مناعتك أهم.. التطعيم هو خط الحماية الأول', 'مناعتك أهم.. التطعيم هو خط الحماية الأول', 'متابعة  كبسولة الصحية أطلقت هيئة الصحة العامة (وقاية) حملة توعوية تحت شعار &#8220;مناعتك أهم&#8221;، شددت خلالها على أن التطعيم يظل خط الحماية الأول ضد العدوى. ', '{الأطفال,المراهقون,المسافرون,"كبار السن",وقاية}', false, 'published', NULL, NULL, '2026-01-18 20:13:21', '2026-01-24 16:23:35.960298', '2026-01-24 16:23:35.960298');
INSERT INTO public.news VALUES ('04c5a997-8ee7-49ef-9df2-f32ad32b116f', 'ad164ae', 'نائب أمير جازان يشهد حفل ختام أعمال تجمع جازان الصحي 2025', NULL, 'كبسولة الصحية &#8211;  واس برعاية صاحب السمو الملكي الأمير محمد بن عبد العزيز بن محمد بن عبدالعزيز أمير منطقة جازان، شهد صاحب السمو الأمير ناصر بن محمد بن عبدالله بن جلوي نائب أمير المنطقة اليوم، حفل ختام أعمال تجمع جازان الصحي لعام 2025، وذلك بالمركز الحضاري بجازان، بمشاركة قيادات القطاع الصحي ومنس', '<p>كبسولة الصحية &#8211;  واس</p>
<p>برعاية صاحب السمو الملكي الأمير محمد بن عبد العزيز بن محمد بن عبدالعزيز أمير منطقة جازان، شهد صاحب السمو الأمير ناصر بن محمد بن عبدالله بن جلوي نائب أمير المنطقة اليوم، حفل ختام أعمال تجمع جازان الصحي لعام 2025، وذلك بالمركز الحضاري بجازان، بمشاركة قيادات القطاع الصحي ومنسوبي التجمع والجهات ذات العلاقة.</p>
<p>واستعرض الملتقى أبرز منجزات التجمع خلال عام 2025، التي شملت تطوير منظومة الرعاية الصحية، ورفع كفاءة الخدمات المقدمة للمستفيدين، وتحقيق مؤشرات أداء متقدمة في مجالات العمليات الجراحية، والعيادات الافتراضية، وجودة وسلامة المرضى، إلى جانب التوسع في نماذج الرعاية الصحية وتحسين تجربة المستفيد.</p>
<p>وتناول الملتقى الأرقام والمؤشرات التي عكست حجم العمل المنجز، من بينها تنفيذ أكثر من (48,440) عملية جراحية، وإنجاز أكثر من مليون موعد افتراضي، إضافة إلى التقدم في برامج الوقاية، والكشف المبكر عن الأمراض المزمنة، والتوسع في خدمات الرعاية المنزلية والتخصصية، بما يسهل الوصول للخدمة الصحية في مختلف محافظات المنطقة.</p>
<p>كما سلّط الملتقى الضوء على ما حققه التجمع من اعتمادات محلية ودولية للمنشآت الصحية، وحصوله على جوائز وتكريمات نظير التميز في الأداء المؤسسي وجودة الخدمات الصحية، إلى جانب استعراض مبادرات التحول الصحي، ونسب التوطين، وبرامج تنمية رأس المال البشري.</p>
<p>وأكد الرئيس التنفيذي لتجمع جازان الصحي فالح بن ناصر الشهراني أن ما تحقق خلال عام 2025 جاء بدعم القيادة الرشيدة، ومتابعة سمو أمير منطقة جازان وسمو نائبه، مشيرًا إلى أن التجمع واصل العمل على ترسيخ نموذج الرعاية الصحية الحديث، وتحسين جودة وكفاءة الخدمات، وتعزيز سلامة المرضى، ورفع مستوى رضا المستفيدين.</p>
<p>وأوضح أن المرحلة المقبلة ستشهد استمرار التطوير في مسارات الرعاية الصحية، والتوسع في الحلول الرقمية، وتعزيز التكامل بين منشآت التجمع، بما يواكب مستهدفات برنامج التحول الصحي، ويسهم في تحقيق مستهدفات رؤية المملكة  2030.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/4a2e3015-942e-441b-9892-5358c665cc3a.webp', 'نائب أمير جازان يشهد حفل ختام أعمال تجمع جازان الصحي 2025', 'نائب أمير جازان يشهد حفل ختام أعمال تجمع جازان الصحي 2025', 'كبسولة الصحية &#8211;  واس برعاية صاحب السمو الملكي الأمير محمد بن عبد العزيز بن محمد بن عبدالعزيز أمير منطقة جازان، شهد صاحب السمو الأمير ناصر بن محمد بن عبدال', '{"تجمع جازان الصحي","نائب أمير جازان"}', false, 'published', NULL, NULL, '2026-01-21 01:44:55', '2026-01-24 16:23:26.408628', '2026-01-24 16:23:26.408628');
INSERT INTO public.news VALUES ('826bccea-28f9-4cc3-8c4d-d791285fdd13', 'e1655b8', 'مستشفى الزلفي العام يعلن بدء الحجز في عيادة الممارس الصحي المتطوع للأطفال والمراهقين', NULL, 'الزلفي &#8211; الرياض أعلن مستشفى الزلفي العام، ممثلاً بقسم المسؤولية المجتمعية والتطوع، وبالتعاون مع الجمعية الصحية التطوعية بالزلفي، عن بدء الحجز في عيادة الممارس الصحي المتطوع، والتي تُعنى بتقديم خدمات الطب النفسي للأطفال والمراهقين. وأوضح المستشفى أن العيادة تهدف إلى دعم الصحة النفسية للأطفال وا', '<p>الزلفي &#8211; الرياض</p>
<p>أعلن مستشفى الزلفي العام، ممثلاً بقسم المسؤولية المجتمعية والتطوع، وبالتعاون مع الجمعية الصحية التطوعية بالزلفي، عن بدء الحجز في عيادة الممارس الصحي المتطوع، والتي تُعنى بتقديم خدمات الطب النفسي للأطفال والمراهقين.</p>
<p>وأوضح المستشفى أن العيادة تهدف إلى دعم الصحة النفسية للأطفال والمراهقين، والمساهمة في تشخيص ومعالجة عدد من الحالات النفسية والسلوكية الشائعة، من أبرزها: العنف لدى الأطفال والمراهقين، الاكتئاب، رفض المدرسة، تشتت الانتباه وفرط الحركة، إضافة إلى حالات التبول والتبرز اللاإرادي لمن هم فوق سن خمس سنوات.</p>
<p>وتُدار العيادة بإشراف الدكتور أيمن بن أحمد البداح، استشاري الطب النفسي للأطفال والمراهقين، وذلك ضمن إطار تطوعي يعكس تكامل الجهود بين مستشفى الزلفي العام والجمعية الصحية التطوعية بالزلفي في تعزيز الدور المجتمعي وتقديم خدمات صحية نوعية.</p>
<p>ودعا المستشفى أولياء الأمور الراغبين في الاستفادة من خدمات العيادة إلى حجز موعد عبر التوجه إلى مكتب تنسيق العيادات الخارجية، مشيراً إلى أن عملية الفرز تتم يومياً من الساعة الثامنة حتى التاسعة صباحاً، مع التأكيد على إحضار الأشعة والتحاليل الطبية قبل الحضور.</p>
<p>وللاستفسار والتواصل، خصص المستشفى البريد الإلكتروني التالي:</p>
<p>Ruh-alzh-opd@moh.gov.sa</p>
<p>ويأتي إطلاق هذه العيادة ضمن جهود مستشفى الزلفي العام، وبالتعاون مع الجمعية الصحية التطوعية بالزلفي، لتعزيز الصحة النفسية للأطفال والمراهقين، ودعم المبادرات التطوعية التي تسهم في رفع جودة الحياة وتحسين مستوى الخدمات الصحية المقدمة للمجتمع.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/8d062c19-f767-4d77-a9e5-b8f035f0356c.jpg', 'مستشفى الزلفي العام يعلن بدء الحجز في عيادة الممارس الصحي المتطوع للأطفال والمراهقين', 'مستشفى الزلفي العام يعلن بدء الحجز في عيادة الممارس الصحي المتطوع للأطفال والمراهقين', 'الزلفي &#8211; الرياض أعلن مستشفى الزلفي العام، ممثلاً بقسم المسؤولية المجتمعية والتطوع، وبالتعاون مع الجمعية الصحية التطوعية بالزلفي، عن بدء الحجز في عيادة الم', '{الزلفي,"عيادة الممارس الصحي"}', false, 'published', NULL, NULL, '2026-01-21 01:24:37', '2026-01-24 16:23:27.53076', '2026-01-24 16:23:27.53076');
INSERT INTO public.news VALUES ('c067a9b7-4858-402b-bde0-f0621a5a571b', '235e1f4', 'حظر دجاج "سوزانا" وتجميد استيراده فوراً', NULL, 'متابعة – كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء قراراً يقضي بحظر استيراد ومنع تداول منتجات صدور الدجاج المشوية الجاهزة للأكل من إنتاج شركة &#8220;مطبخ سوزانا&#8221; (Suzanna&#8217;s Kitchen) بعد ثبوت تلوثها بكتيرياً. اتخذت الهيئة هذا الإجراء الرقابي النافذ بعد أن كشفت نتائج الفحوصات المخبر', '<p><strong>متابعة – كبسولة الصحية</strong></p>
<p>أصدرت الهيئة العامة للغذاء والدواء قراراً يقضي بحظر استيراد ومنع تداول منتجات صدور الدجاج المشوية الجاهزة للأكل من إنتاج شركة &#8220;مطبخ سوزانا&#8221; (Suzanna&#8217;s Kitchen) بعد ثبوت تلوثها بكتيرياً.</p>
<p>اتخذت الهيئة هذا الإجراء الرقابي النافذ بعد أن كشفت نتائج الفحوصات المخبرية عن وجود بكتيريا &#8220;ليستيريا مونوسيتوجينس&#8221; في المنتجات التي تحمل رقم التشغيل (lot code 60104 P1382 287 5 J14). وشمل القرار تجميد دخول هذه الشحنات عبر المنافذ الحدودية وتوجيه الفرق الميدانية لضبط أي كميات قد تكون تسربت إلى الأسواق.</p>
<p>تكمن أهمية هذا الحظر في كونه إجراءً وقائياً استباقياً لمنع حدوث حالات تسمم غذائي حاد، حيث تُعرف بكتيريا الليستيريا بقدرتها على إحداث مضاعفات صحية خطيرة. ويمثل التحرك السريع للهيئة تفعيلاً لأدوات الحماية الصحية لضمان سلامة الغذاء المستورد وعدم وصول منتجات ملوثة إلى المستهلك النهائي.</p>
<p>تواصل الهيئة تشديد الرقابة لضمان التنفيذ الكامل لقرار المنع، مع التأكيد على ضرورة تعاون الموزعين والمستهلكين بالتخلص من المنتج فوراً في حال امتلاكه، كما شددت على وجوب استخدام القنوات الرسمية للإبلاغ عن أي مخالفات مرصودة عبر مركز الاتصال الموحد 19999 لضمان المحاصرة الكاملة لهذا المنتج المخالف.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/e7698691-ae8d-4b9c-973a-f3bd4358975b.jpg', 'حظر دجاج &#8220;سوزانا&#8221; وتجميد استيراده فوراً', 'حظر دجاج &#8220;سوزانا&#8221; وتجميد استيراده فوراً', 'متابعة – كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء قراراً يقضي بحظر استيراد ومنع تداول منتجات صدور الدجاج المشوية الجاهزة للأكل من إنتاج شركة &#8220;مطبخ', '{البكتبريا,"الهيئة العامة الغذاء والدواء"}', false, 'published', NULL, NULL, '2026-01-20 16:10:07', '2026-01-24 16:23:27.854432', '2026-01-24 16:23:27.854432');
INSERT INTO public.news VALUES ('04afa48e-8f9e-42e4-89eb-6531bec00cdf', 'da0b6f9', 'القصيم الصحي: تفعيل خدمات مناظير الجهاز الهضمي بمستشفى عيون الجواء العام', NULL, 'متابعة – كبسولة الصحية أعلن تجمع القصيم الصحي عن تفعيل خدمات مناظير الجهاز الهضمي التشخيصية والعلاجية بمستشفى عيون الجواء العام، ضمن أهدافه لتوسيع الخدمات التخصصية وتقليل إحالات المرضى إلى المستشفيات المرجعية. وأوضح التجمع  &#8211; بحسب صحيفة الرياض &#8211;  أن الخدمة تشمل المناظير العلوية والسفلية ', '<p>متابعة – كبسولة الصحية</p>
<p>أعلن تجمع القصيم الصحي عن تفعيل خدمات مناظير الجهاز الهضمي التشخيصية والعلاجية بمستشفى عيون الجواء العام، ضمن أهدافه لتوسيع الخدمات التخصصية وتقليل إحالات المرضى إلى المستشفيات المرجعية.</p>
<p>وأوضح التجمع  &#8211; بحسب صحيفة الرياض &#8211;  أن الخدمة تشمل المناظير العلوية والسفلية لأغراض تشخيصية وعلاجية، وتمكّن من الكشف المبكر عن أمراض الجهاز الهضمي ومعالجة بعض الحالات دون الحاجة إلى تدخل جراحي، بما يسهم في سرعة اتخاذ القرار الطبي وفق أفضل الممارسات وأشار التجمع إلى أن وحدة المناظير مجهزة بأحدث الأجهزة والتقنيات، ويعمل بها كادر طبي وفني مؤهل لضمان تقديم الخدمة وفق أعلى معايير الجودة وسلامة المرضى.</p>
<p>وأكد التجمع أن هذه الخطوة تأتي ضمن جهود توطين الخدمات التخصصية في محافظات المنطقة، وتعكس حرص قياداته على تطوير الأداء وتعزيز كفاءة منظومة الرعاية الصحية المتكاملة.</p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/5af0dc1e-3d4c-47a5-b34e-cfe7dcb400c4.jpg', 'القصيم الصحي: تفعيل خدمات مناظير الجهاز الهضمي بمستشفى عيون الجواء العام', 'القصيم الصحي: تفعيل خدمات مناظير الجهاز الهضمي بمستشفى عيون الجواء العام', 'متابعة – كبسولة الصحية أعلن تجمع القصيم الصحي عن تفعيل خدمات مناظير الجهاز الهضمي التشخيصية والعلاجية بمستشفى عيون الجواء العام، ضمن أهدافه لتوسيع الخدمات التخص', '{"تجمع القصيم الصحي","عيون الجواء","مناظير الجهاز الهضمي"}', false, 'published', NULL, NULL, '2026-01-20 15:50:50', '2026-01-24 16:23:28.175656', '2026-01-24 16:23:28.175656');
INSERT INTO public.news VALUES ('d15500a7-2fd5-42f3-8378-20dd8e5a2edd', 'd71a29c', 'بوبا العربية تحوّل أكثر من 3 مليارات خطوة إلى أثر مجتمعي', NULL, 'طارق العمودي: نحوّل السلوك الصحي اليومي إلى أثر علاجي حقيقي جدة- كبسولة الصحية في تحول لافت في مفهوم المبادرات الصحية والمسؤولية المجتمعية، كشفت شركة بوبا العربية للتأمين التعاوني، عن نتائج مبادرة اعتمدت على تحويل النشاط البدني اليومي للعملاء إلى دعم علاج وتأهيل للفئات الأكثر احتياجاً داخل المملكة، ', '<p><strong>طارق العمودي: نحوّل السلوك الصحي اليومي إلى أثر علاجي حقيقي</strong></p>
<p><strong>جدة- كبسولة الصحية</strong></p>
<p>في تحول لافت في مفهوم المبادرات الصحية والمسؤولية المجتمعية، كشفت شركة بوبا العربية للتأمين التعاوني، عن نتائج مبادرة اعتمدت على تحويل النشاط البدني اليومي للعملاء إلى دعم علاج وتأهيل للفئات الأكثر احتياجاً داخل المملكة، حيث اعتمدت المبادرة على الخطوات باعتبارها وحدة قياس للأثر العلاجي، وليس مجرد مؤشر لياقة، في محاولة لإعادة تعريف العلاقة بين السلوك الصحي الفردي والأثر المجتمعي المباشر.</p>
<p>وتجاوز عدد المشاركين في المبادرة 20 ألف مشترك، وبلغ إجمالي الخطوات أكثر من 3 مليارات خطوة، وهو رقم أنتج أثراً نوعياً تمثل في دعم برامج علاج وتأهيل وتوعية، على نحو يبرز قابلية المجتمع للتفاعل مع نماذج مشاركة جديدة لا تعتمد على التبرع المالي المباشر بقدر ما تعتمد على السلوك الصحي اليومي.</p>
<p><strong>وقاية وصحة</strong></p>
<p>استندت فكرة المبادرة إلى تحويل المشي اليومي إلى قيمة علاجية ملموسة، سواء عبر جلسات تأهيل لذوي الإعاقة، أو دعم نفسي واجتماعي لمريضات سرطان الثدي، أو تعزيز الوعي والتشخيص المبكر لسرطان البروستاتا. ويمثل النموذج انتقالاً من العمل الخيري إلى الشراكات الصحية الوقائية، في سياق يتماشى مع التحول الذي تشهده المملكة العربية السعودية في سياسات جودة الحياة والصحة المستدامة.</p>
<p>وفي هذا السياق، قال طارق العمودي، الرئيس التنفيذي للموارد البشرية في بوبا العربية: &#8220;نحن نؤمن بأن سلامة المجتمع تبدأ من صحة كل فرد فيه. ومن خلال هذه المبادرة، نجحنا في تحويل الخطوات إلى مساهمة فعلية تترجم مباشرةً إلى جلسات علاجية، ودعم نفسي، وتأهيل متخصص&#8221;، مشيرًا إلى أن جوهر استراتيجية الشركة هو: أن نكون شريكاً صحياً يحدث فرقاً حقيقياً وملموساً في حياة الناس&#8221;.</p>
<p><strong>شراكات واستدامة</strong></p>
<p>ولم تقف المبادرة عند جمع البيانات الصحية للمشاركين، بل قامت بتوجيه أثرها عبر شراكات مع عدد من الجهات التخصصية. فعلى صعيد دعم ذوي الإعاقة، جرى دعم مركز الرعاية المتطورة ببرامج تأهيل وعلاج وتعليم، إلى جانب مساندة لوجستية تسهل مشاركة المستفيدين وتنقلهم وتعزز استقلاليتهم ونشاطهم داخل المجتمع. وفي مجال صحة المرأة، استفادت جمعية زهرة من دعم برامج نفسية واجتماعية لمريضات سرطان الثدي خلال مراحل العلاج، فيما حصلت جمعية العلاج الآمن في مجال سرطان البروستاتا على دعم يسهم في تعزيز التوعية والتشخيص المبكر وتحسين رحلة المرضى.</p>
<p>وتعد المبادرة جزءاً من نهج يسعى إلى تبني نموذج مسؤولية مجتمعية قابل للقياس، يُركّز على تحويل السلوك اليومي إلى نتائج قابلة للملاحظة، وربط الأثر العلاجي ببيانات واضحة يمكن تتبعها داخل منظومة الصحة العامة.</p>
<p>بدوره، قال المهندس علي شنيمر، الرئيس التنفيذي لتطوير الأعمال في بوبا العربية: &#8220;يعكس هذا الإنجاز التزام بوبا العربية بتقديم نموذج مسؤولية مجتمعية هادف، يقوم على إشراك المجتمع وتحويل السلوكيات الصحية اليومية إلى أثر إيجابي مستدام. نحن نؤمن بأن دورنا يتجاوز تقديم خدمات التأمين الصحي، ليشمل الإسهام الفعلي في تحسين جودة الحياة ودعم الحملات الصحية والإنسانية ذات الأولوية&#8221;.</p>
<p><strong>أثر قابل للقياس</strong></p>
<p>ويمثل تسجيل أكثر من ثلاثة مليارات خطوة مؤشراً على تنامي الوعي المجتمعي بأهمية الوقاية والنشاط البدني، إلى جانب قابلية الأفراد للمشاركة في مبادرات صحية غير تقليدية تعتمد على التحفيز وليس على المنح المالية، كما يعزز هذا النوع من المبادرات تكامل الأدوار بين القطاع الخاص والقطاع الصحي والجمعيات التخصصية، ويفتح المجال أمام تحويل مبادرات المسؤولية المجتمعية إلى منصات لقياس أثر الصحة الوقائية وجودة الحياة.</p>
<p>وتشير بوبا العربية إلى أن العمل جارٍ على توسيع نطاق المبادرة خلال الأعوام المقبلة لتغطية شرائح أوسع وقضايا صحية متعددة، بما يعزز مفهوم الصحة المستدامة ويواكب توجهات جودة الحياة داخل المملكة.</p>
<div id="attachment_24154" style="width: 310px" class="wp-caption alignnone"><img loading="lazy" decoding="async" aria-describedby="caption-attachment-24154" class="wp-image-24154 size-medium" src="https://capsulah.com/wp-content/uploads/2026/01/Ali-Sheneamer1-300x200.jpg" alt="" width="300" height="200" title="" srcset="https://capsulah.com/wp-content/uploads/2026/01/Ali-Sheneamer1-300x200.jpg 300w, https://capsulah.com/wp-content/uploads/2026/01/Ali-Sheneamer1-1024x682.jpg 1024w, https://capsulah.com/wp-content/uploads/2026/01/Ali-Sheneamer1-768x512.jpg 768w, https://capsulah.com/wp-content/uploads/2026/01/Ali-Sheneamer1.jpg 1042w" sizes="auto, (max-width: 300px) 100vw, 300px" /><p id="caption-attachment-24154" class="wp-caption-text">علي شنيمر</p></div>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/aadd4d81-e64a-4ff2-9a66-dab80705442b.jpg', 'بوبا العربية تحوّل أكثر من 3 مليارات خطوة إلى أثر مجتمعي', 'بوبا العربية تحوّل أكثر من 3 مليارات خطوة إلى أثر مجتمعي', 'طارق العمودي: نحوّل السلوك الصحي اليومي إلى أثر علاجي حقيقي جدة- كبسولة الصحية في تحول لافت في مفهوم المبادرات الصحية والمسؤولية المجتمعية، كشفت شركة بوبا العرب', '{الصحة,المشي,بوبا}', false, 'published', NULL, NULL, '2026-01-20 10:11:41', '2026-01-24 16:23:28.517309', '2026-01-24 16:23:28.517309');
INSERT INTO public.news VALUES ('1f963f60-db9f-4fe9-802e-73164fda0015', '0b09979', 'أحدث تقنية لتبديل مفصل الورك متوفرة في المملكة وتتيح المشي بعد ساعات قليلة', NULL, 'الرياض &#8211; كبسولة الصحية نجح فريق جراحة العظام في مستشفى دله النخيل في إجراء عملية تبديل مفصل الورك باستخدام تقنية المدخل الأمامي (Direct Anterior Approach)، إحدى أحدث وأدق التقنيات الجراحية عالمياً حيث تعتمد هذه الطريقة على إجراء الجراحة من مقدمة الفخذ دون قطع العضلات، مما يقلل الألم بعد العملي', '<p>الرياض &#8211; كبسولة الصحية</p>
<p>نجح فريق جراحة العظام في مستشفى دله النخيل في إجراء عملية تبديل مفصل الورك باستخدام تقنية المدخل الأمامي (Direct Anterior Approach)، إحدى أحدث وأدق التقنيات الجراحية عالمياً حيث تعتمد هذه الطريقة على إجراء الجراحة من مقدمة الفخذ دون قطع العضلات، مما يقلل الألم بعد العملية ويسرع التعافي، ويمكّن المريض من الوقوف والمشي خلال ساعات قليلة، مع الحفاظ على ثبات المفصل وتقليل احتمالية الخلع.</p>
<p>أُجريت العملية بنجاح على يد د. محمد الشولي، استشاري جراحة العظام وتبديل المفاصل في مستشفى دله النخيل، الحاصل على زمالة دقيقة ومتقدمة في جراحة مفصل الورك والركبة، بعد خضوع المريض لتقييمات سريرية دقيقة وفحوصات إشعاعية متقدمة أكدت الحاجة للتدخل الجراحي.<br />
تم تنفيذ العملية باستخدام تقنيات تضمن دقة وضع المفصل الصناعي بما يتوافق مع التركيب التشريحي الطبيعي للمفصل، مما انعكس إيجاباً على كفاءة الحركة وتسريع التعافي وتحسين النتائج الوظيفية وجودة حياة المريض.</p>
<p>ويأتي هذا الإنجاز تأكيداً على التزام مستشفى دله النخيل بتبني أحدث التقنيات الطبية والجراحية وتقديم رعاية صحية تخصصية متقدمة وفق أعلى المعايير العالمية.</p>
<p>يذكر بأن دلّه الصحية تقدّم خدماتها لأكثر من أربعة ملايين مراجع سنوياً من خلال شبكة واسعة من المستشفيات والعيادات التخصصية، بالإضافة إلى خدمات الرعاية المنزلية. وبالاعتماد على فريق متمرس ونخبة من الأطباء المتخصصين، تعمل دلّه الصحية وفقاً لأعلى معايير الجودة وسلامة المرضى، وتحرص على القيم الإنسانية والمهنية التي جعلتها المرجع الأول للرعاية الصحية الموثوقة في المملكة.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/47ef4f69-87dd-450f-8487-e30405125052.jpg', 'أحدث تقنية لتبديل مفصل الورك متوفرة في المملكة وتتيح المشي بعد ساعات قليلة', 'أحدث تقنية لتبديل مفصل الورك متوفرة في المملكة وتتيح المشي بعد ساعات قليلة', 'الرياض &#8211; كبسولة الصحية نجح فريق جراحة العظام في مستشفى دله النخيل في إجراء عملية تبديل مفصل الورك باستخدام تقنية المدخل الأمامي (Direct Anterior Approach)', '{"تبديل مفصل الورك","دله النخيل"}', false, 'published', NULL, NULL, '2026-01-20 09:04:00', '2026-01-24 16:23:29.004164', '2026-01-24 16:23:29.004164');
INSERT INTO public.news VALUES ('1b043aae-fb94-4655-b5c0-23813c49325a', '703d992', 'تحذير من منتجات خضراء ملوثة بالسالمونيلا', NULL, 'متابعة- كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء تحذيراً من استهلاك منتجات المكمل الغذائي &#8220;Super Greens&#8221; التابع للعلامة التجارية Live it Up. يأتي التحذير بسبب احتمالية تلوث المنتج ببكتيريا السالمونيلا الخطيرة، ويشمل التحذير نكهتي &#8220;Original&#8221; و&#8221;Wild Berry&#8221; ب', '<p>متابعة- كبسولة الصحية</p>
<p>أصدرت الهيئة العامة للغذاء والدواء تحذيراً من استهلاك منتجات المكمل الغذائي &#8220;Super Greens&#8221; التابع للعلامة التجارية Live it Up.</p>
<p>يأتي التحذير بسبب احتمالية تلوث المنتج ببكتيريا السالمونيلا الخطيرة، ويشمل التحذير نكهتي &#8220;Original&#8221; و&#8221;Wild Berry&#8221; بكافة الأحجام والأوزان.</p>
<p>وتسبب  بكتيريا السالمونيلا تسمماً غذائياً حاداً، وتعد خطيرة جداً على الأطفال، وكبار السن، ومن يعانون من ضعف المناعة، وتكمن أهمية هذا التحذير في حماية المستهلك من منتجات يتم الترويج لها كـ &#8220;صحية&#8221;، بينما قد تحمل خطراً ميكروبياً داهماً. استراتيجياً، يبرز هذا التحرك قدرة الرقابة السعودية على فحص جودة المكملات الغذائية المستوردة، وضمان أن &#8220;الصحة&#8221; الموعودة في هذه المنتجات لا تتحول إلى عبء مرضي.</p>
<p>ونصحت الهيئة المستهلكين الذين يملكون هذا المنتج بالتوقف عن استخدامه فوراً والتخلص منه. كما دعت الهيئة للتواصل معها عبر الرقم (19999) في حال وجود أي استفسار أو بلاغ عن وجود المنتج في الأسواق المحلية.</p>
<p>ويمثل الخطأ في الملصق التعريفي تهديداً مباشراً لحياة الأشخاص الذين يعانون من &#8220;حساسية المكسرات أو الفول السوداني&#8221;،  فتناول كمية بسيطة من المكسرات غير المذكورة قد يؤدي إلى رد فعل تحسسي عنيف. استراتيجياً، هذا التنبيه يجسد دور الرقابة في حماية &#8220;حق المستهلك في المعرفة&#8221;، ويؤكد أن دقة المعلومات على العبوات الغذائية هي جزء لا يتجزأ من السلامة العامة، وليست مجرد إجراء شكلي.</p>
<p>يُنصح كل من اشترى هذا المنتج ويعاني من حساسية تجاه المكسرات بعدم تناوله نهائياً. يجب إعادة المنتج فوراً إلى المتجر الذي تم شراؤه منه لاسترداد كامل القيمة. كما دعت الجهات المختصة المستهلكين للتأكد دائماً من ملصقات المكونات، والإبلاغ عن أي مخالفات في التغليف عبر القنوات الرسمية.</p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/7be05bb0-41be-4172-8028-6d2bb87113e4.jpg', 'تحذير من منتجات خضراء ملوثة بالسالمونيلا', 'تحذير من منتجات خضراء ملوثة بالسالمونيلا', 'متابعة- كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء تحذيراً من استهلاك منتجات المكمل الغذائي &#8220;Super Greens&#8221; التابع للعلامة التجارية Live it Up.', '{"الهيئة العامة للغذاء والدواء",بكتيريا,"مكملات غذائية"}', false, 'published', NULL, NULL, '2026-01-19 12:09:04', '2026-01-24 16:23:31.293792', '2026-01-24 16:23:31.293792');
INSERT INTO public.news VALUES ('1f2e3ea0-9d27-4997-a02a-4087a8d6e3e6', 'a997da5', 'زبيب الشوكولاتة.. خطأ في "الملصق" يهدد الحياة', NULL, 'متابعة – كبسولة الصحية حذرت الهيئة العامة للغذاء والدواء من استهلاك منتج &#8220;زبيب جامبو مغطى بالشوكولاتة البلجيكية&#8221; من العلامة التجارية Forest Feast. التحذير جاء بعد اكتشاف احتواء المنتج على &#8220;فول سوداني ومكسرات&#8221; لم يتم ذكرها ضمن قائمة المكونات على العبوة، ويأتي هذا  المنتج بوزن ', '<p>متابعة – كبسولة الصحية</p>
<p>حذرت الهيئة العامة للغذاء والدواء من استهلاك منتج &#8220;زبيب جامبو مغطى بالشوكولاتة البلجيكية&#8221; من العلامة التجارية Forest Feast. التحذير جاء بعد اكتشاف احتواء المنتج على &#8220;فول سوداني ومكسرات&#8221; لم يتم ذكرها ضمن قائمة المكونات على العبوة، ويأتي هذا  المنتج بوزن 1 كجم، ويحمل تاريخ انتهاء 31 ديسمبر 2026.</p>
<p>إن نقص المعلومات يمثل خطراً حقيقياً على الأشخاص الذين يعانون من &#8220;حساسية المكسرات&#8221;، حيث يمكن أن يؤدي تناول كمية بسيطة منها إلى رد فعل تحسسي شديد يهدد السلامة العامة.</p>
<p>يبرز هذا التحرك دور الهيئة في حماية &#8220;حق المستهلك في المعرفة&#8221;، ويؤكد أن دقة الملصقات الغذائية هي خط الدفاع الأول في منظومة الأمن الصحي. إن عدم الإفصاح عن المكونات يُعد مخالفة جسيمة، لأن صحة الفئات الحساسة في المجتمع تتقدم على أي اعتبارات تجارية أو تسويقية.</p>
<p>شددت الهيئة على المستهلكين الذين يعانون من حساسية تجاه المكسرات أو الفول السوداني بضرورة التوقف عن تناول هذا المنتج فوراً. كما دعت إلى إعادته لمنفذ البيع لاسترداد قيمته. وتنصح الجميع دائماً بالتأكد من مكونات الأغذية، والإبلاغ عن أي منتج مخالف عبر مركز الاتصال الموحد (19999) لضمان سلامة الجميع.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/866a9f25-f784-45cf-8035-2945e2d6fd80.webp', 'زبيب الشوكولاتة.. خطأ في &#8220;الملصق&#8221; يهدد الحياة', 'زبيب الشوكولاتة.. خطأ في &#8220;الملصق&#8221; يهدد الحياة', 'متابعة – كبسولة الصحية حذرت الهيئة العامة للغذاء والدواء من استهلاك منتج &#8220;زبيب جامبو مغطى بالشوكولاتة البلجيكية&#8221; من العلامة التجارية Forest Feast. ا', '{"الشوكولاتة البلجيكية","الهيئة العامة الغذاء والدواء"}', false, 'published', NULL, NULL, '2026-01-19 12:06:18', '2026-01-24 16:23:31.619658', '2026-01-24 16:23:31.619658');
INSERT INTO public.news VALUES ('8493b88c-d23d-4db0-a58f-ec9f50f9a9c8', '1fdd806', 'احذروا بكتيريا الأجبان .. منع استيراد 5 أنواع عالمية', NULL, 'متابعة – كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء تحذيراً عاجلاً، بعد رصد احتمالية تلوث مجموعة من منتجات الأجبان ببكتيريا &#8220;الليستيريا&#8221; (Listeria monocytogenes). التحذير شمل علامات تجارية عالمية وهي: (Ambriola, Locatelli, Member&#8217;s Mark, Pinna, and Boar&#8217;s Head). تعد بكت', '<p>متابعة – كبسولة الصحية</p>
<p>أصدرت الهيئة العامة للغذاء والدواء تحذيراً عاجلاً، بعد رصد احتمالية تلوث مجموعة من منتجات الأجبان ببكتيريا &#8220;الليستيريا&#8221; (Listeria monocytogenes). التحذير شمل علامات تجارية عالمية وهي: (Ambriola, Locatelli, Member&#8217;s Mark, Pinna, and Boar&#8217;s Head).</p>
<p>تعد بكتيريا &#8220;الليستيريا&#8221; من الملوثات الخطيرة التي تسبب عدوى قد تكون قاتلة، خاصة للأطفال، كبار السن، والنساء الحوامل. تكمن خطورتها في قدرتها على النمو حتى في درجات حرارة الثلاجة. استراتيجياً، هذا التحذير يعكس قوة &#8220;الرادار الرقابي&#8221; السعودي الذي لا ينتظر وقوع الإصابة، بل يستبقها بمنع استيراد المنتجات المشبوهة فور ظهورها في أنظمة الإنذار الدولية.</p>
<p>وجهت الهيئة بمنع استيراد هذه الأجبان بالبيانات الموضحة، ودعت المستهلكين للتخلص فوراً مما لديهم منها. كما طلبت الهيئة من الجميع الإبلاغ عن أي استيراد سابق أو وجود للمنتج في الأسواق عبر الرقم (19999).</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/a59929ea-d396-4893-9e2c-340805de0665.webp', 'احذروا بكتيريا الأجبان .. منع استيراد 5 أنواع عالمية', 'احذروا بكتيريا الأجبان .. منع استيراد 5 أنواع عالمية', 'متابعة – كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء تحذيراً عاجلاً، بعد رصد احتمالية تلوث مجموعة من منتجات الأجبان ببكتيريا &#8220;الليستيريا&#8221; (List', '{أجبان,"الهيئة العامة للغذاء والدواء","بكتيريا الليستيريا"}', false, 'published', NULL, NULL, '2026-01-19 10:07:28', '2026-01-24 16:23:31.963967', '2026-01-24 16:23:31.963967');
INSERT INTO public.news VALUES ('4ff3f8b7-b0ae-4524-828d-ebb554c4a6da', 'd04029a', 'تسمم في علبة "برجر"', NULL, 'متابعة – كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء تحذيراً عاجلاً من منتج &#8220;برجر بقري&#8221; (Beef Burgers) من العلامة التجارية الكندية الشهيرة &#8220;No Name&#8221; (التي تُعرف بمنتجاتها التي تأتي بدون اسم تجاري محدد سوى وصف المنتج على خلفية صفراء). جاء التحذير بعد رصد تلوث المنتج ببكتي', '<p>متابعة – كبسولة الصحية</p>
<p>أصدرت الهيئة العامة للغذاء والدواء تحذيراً عاجلاً من منتج &#8220;برجر بقري&#8221; (Beef Burgers) من العلامة التجارية الكندية الشهيرة &#8220;No Name&#8221; (التي تُعرف بمنتجاتها التي تأتي بدون اسم تجاري محدد سوى وصف المنتج على خلفية صفراء).</p>
<p>جاء التحذير بعد رصد تلوث المنتج ببكتيريا E. coli O157:H7 القاتلة، ويزن المنتج 1.36 كجم، ويحمل تاريخ انتهاء &#8220;5 مايو 2026&#8221;.</p>
<p>تكمن الخطورة في أن اللحم الملوث قد لا تظهر عليه علامات فساد أو روائح كريهة، لكنه يسبب تسمماً عنيفاً. تبدأ الأعراض بالغثيان والقيء وتشنجات حادة وإسهال دموي،  وفي حالاتها الشديدة، قد يتطور الأمر إلى فشل كلوي دائم، جلطات، أو حتى الوفاة. هذا الاستنفار الرقابي السعودي يعكس كفاءة &#8220;المسح الاستباقي&#8221; العابر للحدود، حيث تم رصد التحذير الدولي ومنع وصول الخطر للمائدة المحلية فوراً.</p>
<p>إن دمج هذه اليقظة في سلاسل الإمداد يكرس مفهوم &#8220;الأمن الغذائي&#8221; كخط أحمر، ويؤكد أن حماية المستهلك في المملكة تسبق أي اعتبارات تجارية للشركات المستوردة.</p>
<p>وشددت  الهيئة على المستهلكين بضرورة التحقق من ثلاجاتهم، والتخلص من المنتج فوراً أو إعادته لمكان الشراء،  كما دعت الهيئة كل من لديه معلومات عن استيراد سابق لهذا المنتج المخالف للتواصل مع مركز الاتصال الموحد (19999) لضمان خلو الأسواق منه تماماً.</p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/66439aed-67d7-46c9-835c-affcdb795546.jpg', 'تسمم في علبة &#8220;برجر&#8221;', 'تسمم في علبة &#8220;برجر&#8221;', 'متابعة – كبسولة الصحية أصدرت الهيئة العامة للغذاء والدواء تحذيراً عاجلاً من منتج &#8220;برجر بقري&#8221; (Beef Burgers) من العلامة التجارية الكندية الشهيرة &#82', '{"الهيئة العامة الغذاء والدواء","بكتيريا أيكولاي"}', false, 'published', NULL, NULL, '2026-01-19 10:03:50', '2026-01-24 16:23:32.269418', '2026-01-24 16:23:32.269418');
INSERT INTO public.news VALUES ('b8fee824-3c97-40b5-bccc-8cc9e8826a1f', 'e809ce7', '"الأكاديمية الصحية" تعلن بدء التقديم على 3 برامج تدريبية', NULL, 'كبسولة الصحية &#8211;  واس أعلنت الهيئة السعودية للتخصصات الصحية اليوم، بدء التقديم على (3) برامج تدريبية من برامج الأكاديمية الصحية، تتمثل في برنامج مساعد طبيب أسنان، وبرنامج فني رعاية المرضى، وبرنامج فني الترميز الطبي، التي تمنح من خلالها المتدربين المهارات والمعارف اللازمة، وتؤهلهم لمزاولة المهنة', '<p>كبسولة الصحية &#8211;  واس</p>
<p>أعلنت الهيئة السعودية للتخصصات الصحية اليوم، بدء التقديم على (3) برامج تدريبية من برامج الأكاديمية الصحية، تتمثل في برنامج مساعد طبيب أسنان، وبرنامج فني رعاية المرضى، وبرنامج فني الترميز الطبي، التي تمنح من خلالها المتدربين المهارات والمعارف اللازمة، وتؤهلهم لمزاولة المهنة بعد اجتياز الاختبارات ومتطلبات البرامج.</p>
<p>وأتاحت الهيئة التقديم على البرامج، من خلال البوابة الإلكترونية الخاصة بالأكاديمية الصحية، وذلك اعتبارًا من اليوم تاريخ 18 حتى 20 يناير لبرنامج فني الترميز الطبي، ومن 18 حتى 24 يناير لبرنامجي مساعد طبيب أسنان, وفني رعاية مرضى.</p>
<p>ودعت الهيئة الراغبين في التقديم إلى الاطلاع على متطلبات القبول في البرامج من خلال البوابة، والتأكد من إرفاق جميع المتطلبات لكل تخصص، وذلك عبر الموقع الإلكتروني للأكاديمية الصحية: https://ha.edu.sa.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/30aa79a1-6863-48d2-a59a-a6d59caca002.jpg', '&#8220;الأكاديمية الصحية&#8221; تعلن بدء التقديم على 3 برامج تدريبية', '&#8220;الأكاديمية الصحية&#8221; تعلن بدء التقديم على 3 برامج تدريبية', 'كبسولة الصحية &#8211;  واس أعلنت الهيئة السعودية للتخصصات الصحية اليوم، بدء التقديم على (3) برامج تدريبية من برامج الأكاديمية الصحية، تتمثل في برنامج مساعد طبيب', '{"الأكاديمية الصحية","الهيئة السعودية للتخصصات الصحية"}', false, 'published', NULL, NULL, '2026-01-18 20:29:45', '2026-01-24 16:23:35.281375', '2026-01-24 16:23:35.281375');
INSERT INTO public.news VALUES ('34312169-438b-4240-913f-6e9f244764a4', 'b09376b', 'رحلة الأمومة.. من "الإبرة التفجيرية" إلى تعافي القيصرية', NULL, 'متابعة – كبسولة الصحية قدمت استشارية النساء والولادة، د. مها النمر، دليلاً إرشادياً مزدوجاً يتناول محطتين مفصليتين في حياة المرأة. المحطة الأولى هي &#8220;الإبرة التفجيرية&#8221;، وهي هرمون يُحقن (بالعضل أو تحت الجلد) لتحفيز خروج البويضة عندما يصل حجمها إلى 15-18 ملم، حيث يحدث التبويض بعد 36-48 ساعة', '<p>متابعة – كبسولة الصحية</p>
<p>قدمت استشارية النساء والولادة، د. مها النمر، دليلاً إرشادياً مزدوجاً يتناول محطتين مفصليتين في حياة المرأة. المحطة الأولى هي &#8220;الإبرة التفجيرية&#8221;، وهي هرمون يُحقن (بالعضل أو تحت الجلد) لتحفيز خروج البويضة عندما يصل حجمها إلى 15-18 ملم، حيث يحدث التبويض بعد 36-48 ساعة من الحقن،  أما المحطة الثانية، فتتعلق بتقنيات &#8220;تخدير الألم&#8221; بعد الولادة القيصرية، مثل &#8220;تاب بلوك&#8221; (تخدير أعصاب جدار البطن) أو استخدام جهاز (PCA) الذي يسمح للمريضة بالتحكم في جرعة المسكن عبر الوريد.</p>
<p>تكمن أهمية هذه النصائح في ضبط &#8220;التوقيت&#8221; و&#8221;التوقعات&#8221;؛ ففي محاولة الحمل، يجب أن يكون الجماع في نفس يوم الإبرة ولمدة 5 أيام (يوم بعد يوم)، ولا يُنصح بإجراء تحليل الحمل إلا بعد مرور 14 يوماً لتجنب النتائج الخاطئة. وفي مرحلة ما بعد القيصري، تبرز الأهمية في ضمان أن يكون مقياس الألم عند السيدة 4 أو أقل؛ وذلك عبر دمج تقنيات المستشفى المتقدمة مع أدوية الخروج مثل (الباراسيتامول والفولتارين) لضمان تعافٍ سريع وبدون معاناة.</p>
<p>يمثل هذا الوعي الطبي جسراً لتقليل القلق لدى السيدات، سواء في مرحلة التخطيط للحمل أو الخوف من آلام الجراحة. والمطلوب الآن هو تعزيز الثقافة الطبية التي تؤكد أن &#8220;الألم ليس قدراً&#8221; بعد العمليات، وأن اتباع بروتوكولات التوقيت الدقيقة في المنشطات الهرمونية هو المفتاح لرفع نسب النجاح. إن الربط بين التقنية الطبية (كالأشعة الصوتية في تخدير الأعصاب) والالتزام بالخطة العلاجية المنزلية، يضمن للمرأة رحلة أمومة آمنة تبدأ بدقة العلم وتنتهي براحة التعافي.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/e95b802b-ccae-46cf-8bdd-7199456b9551.webp', 'رحلة الأمومة.. من &#8220;الإبرة التفجيرية&#8221; إلى تعافي القيصرية', 'رحلة الأمومة.. من &#8220;الإبرة التفجيرية&#8221; إلى تعافي القيصرية', 'متابعة – كبسولة الصحية قدمت استشارية النساء والولادة، د. مها النمر، دليلاً إرشادياً مزدوجاً يتناول محطتين مفصليتين في حياة المرأة. المحطة الأولى هي &#8220;الإبر', '{"الإبرة التفجيرية",القيصرية,"د.مها النمر"}', false, 'published', NULL, NULL, '2026-01-18 20:20:06', '2026-01-24 16:23:35.616136', '2026-01-24 16:23:35.616136');
INSERT INTO public.news VALUES ('61fca728-6394-4b72-a309-0266af0b7fd3', 'd405559', 'استئصال ورم يزن 2.5 كجم يُنهي معاناة مقيمة', NULL, 'كبسولة الصحية – واس نجح فريق النساء والولادة بمستشفى الدرعية، التابع لتجمع الرياض الصحي الثالث، في إجراء عملية جراحية دقيقة ومعقدة لاستئصال ورم ليفي ضخم من رحم مريضة مقيمة، الورم الذي بلغ وزنه 2.5 كيلوجرام وطوله 25 سنتيمتراً، تم استئصاله بالكامل في عملية استغرقت 3 ساعات دون أي مضاعفات، مما سمح للمري', '<p>كبسولة الصحية – واس</p>
<p>نجح فريق النساء والولادة بمستشفى الدرعية، التابع لتجمع الرياض الصحي الثالث، في إجراء عملية جراحية دقيقة ومعقدة لاستئصال ورم ليفي ضخم من رحم مريضة مقيمة، الورم الذي بلغ وزنه 2.5 كيلوجرام وطوله 25 سنتيمتراً، تم استئصاله بالكامل في عملية استغرقت 3 ساعات دون أي مضاعفات، مما سمح للمريضة بمغادرة المستشفى وهي بصحة جيدة لممارسة حياتها الطبيعية.</p>
<p>تكمن أهمية هذا النجاح في دقة التدخل الجراحي؛ فاستئصال ورم بهذا الحجم يتطلب مهارة عالية للحفاظ على سلامة الرحم والأعضاء المحيطة. هذا الإنجاز يعكس التطور الكبير في مستشفيات &#8220;تجمعات الرياض الصحية&#8221;، وقدرتها على التعامل مع الحالات التخصصية المعقدة بأعلى معايير السلامة والجودة، دون الحاجة لتحويل المرضى إلى مراكز أخرى، مما يعزز الثقة في المنظومة الصحية المحلية.</p>
<p>يؤكد هذا النجاح الطبي على ضرورة التوعية بالفحوصات الدورية للنساء لاكتشاف الأورام الليفية في مراحلها الأولى قبل أن تصل لهذه الأحجام المقلقة.</p>
<p>يثبت مستشفى الدرعية جاهزيته كمركز متخصص في جراحات النساء المعقدة، وهو ما يتماشى مع مستهدفات التحول الصحي في المملكة لرفع جودة الرعاية الصحية للمرأة وتوفير أفضل الكفاءات الوطنية لإجراء أدق العمليات الجراحية بأمان تام.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/f2c8e44e-a2e5-4526-b815-a5492c425073.jpg', 'استئصال ورم يزن 2.5 كجم يُنهي معاناة مقيمة', 'استئصال ورم يزن 2.5 كجم يُنهي معاناة مقيمة', 'كبسولة الصحية – واس نجح فريق النساء والولادة بمستشفى الدرعية، التابع لتجمع الرياض الصحي الثالث، في إجراء عملية جراحية دقيقة ومعقدة لاستئصال ورم ليفي ضخم من رحم ', '{"مستشفى الدرعية","ورم ليفي"}', false, 'published', NULL, NULL, '2026-01-18 12:39:15', '2026-01-24 16:23:36.97244', '2026-01-24 16:23:36.97244');
INSERT INTO public.news VALUES ('51eb7181-a7b1-4bc4-b0b8-abd85c1ff240', '10be5f9', 'تأمين "مخزون الدم": استراتيجية طبية لتقليل مخاطر نقل الدم أثناء الولادة', NULL, 'متابعة – كبسولة الصحية أكدت استشارية النساء والولادة، الدكتورة مها النمر، على ضرورة التزام الحوامل بمستويات محددة من قوة الدم قبل الدخول في الشهر التاسع، مشددة على أن بلوغ مستوى الهيموجلوبين فوق 11 ومخزون الحديد (فيرتين) فوق 35 يعد صمام أمان لتقليل احتمالية الحاجة لنقل الدم أثناء الولادة. وأوضحت أن ', '<p>متابعة – كبسولة الصحية</p>
<p>أكدت استشارية النساء والولادة، الدكتورة مها النمر، على ضرورة التزام الحوامل بمستويات محددة من قوة الدم قبل الدخول في الشهر التاسع، مشددة على أن بلوغ مستوى <strong>الهيموجلوبين فوق 11</strong> و<strong>مخزون الحديد (فيرتين) فوق 35</strong> يعد صمام أمان لتقليل احتمالية الحاجة لنقل الدم أثناء الولادة.</p>
<p>وأوضحت أن امتصاص الحديد قد ينخفض مع تقدم الحمل، مما يستدعي إعادة فحص الهيموجلوبين والفيرتين في الشهر السابع لتصحيح أي نقص بشكل استباقي.</p>
<p>وكشفت الدكتورة النمر عن حلول طبية متطورة للحوامل اللواتي لا يستجبن للمكملات الغذائية الفموية أو يعانين من أعراضها الجانبية مثل الغثيان والإمساك، مشيرة إلى توفر إبر حديد وريدية (مثل كاربوكسي مالتوز) تؤخذ عبر جرعة أو جرعتين كحد أقصى، وتساهم في رفع مخزون الحديد بسرعة وفعالية، مما ينهي أعراض الإرهاق العام وتساقط الشعر المرتبطة بفقر الدم.</p>
<p>ويأتي هذا التوجه الطبي ليدعم كفاءة المنظومة الصحية عبر تقليل الاعتماد على نقل الدم في غرف العمليات، وهو إجراء يتقاطع مع الأهداف الاستراتيجية لتقليل مخاطر الولادات وما يتبعها من مضاعفات. إن تصحيح نقص الحديد بالوريد يمثل انتقالاً من العلاج التقليدي إلى &#8220;الإدارة الاستباقية للصحة&#8221;، مما يضمن للأم رحلة ولادة آمنة ويقلل من فترات الاستشفاء، وهو ما ينعكس إيجاباً على جودة الرعاية الصحية المقدمة للأم والجنين في آن واحد.</p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/3c9c8978-b1be-4c63-83e0-baff207aefac.jpg', 'تأمين &#8220;مخزون الدم&#8221;: استراتيجية طبية لتقليل مخاطر نقل الدم أثناء الولادة', 'تأمين &#8220;مخزون الدم&#8221;: استراتيجية طبية لتقليل مخاطر نقل الدم أثناء الولادة', 'متابعة – كبسولة الصحية أكدت استشارية النساء والولادة، الدكتورة مها النمر، على ضرورة التزام الحوامل بمستويات محددة من قوة الدم قبل الدخول في الشهر التاسع، مشددة ', '{الولادة,"د.مها النمر","نقل الدم"}', false, 'published', NULL, NULL, '2026-01-17 00:19:13', '2026-01-24 16:23:41.313263', '2026-01-24 16:23:41.313263');
INSERT INTO public.news VALUES ('266cf080-4964-43c3-b355-ada070aea47f', '2d4cd2b', 'يوم الطفل الخليجي: جغرافيا الصحة تبدأ من "البيئة المحيطة" لكسر سلاسل السمنة', NULL, 'متابعة – كبسولة الصحية أكد مجلس الصحة الخليجي، تزامناً مع يوم الطفل الخليجي، أن الاهتمام بالبيئة المحيطة للطفل هو المحرك الأساسي لإحداث فارق جوهري في نموه وصحته، مشدداً على أن السمنة ليست خياراً ذاتياً للطفل، بل هي نتاج مباشر للعادات والخيارات التي توفرها الأسرة والمجتمع. وكشفت الحملة عن حقيقة إحصائ', '<p>متابعة – كبسولة الصحية</p>
<p>أكد مجلس الصحة الخليجي، تزامناً مع يوم الطفل الخليجي، أن الاهتمام بالبيئة المحيطة للطفل هو المحرك الأساسي لإحداث فارق جوهري في نموه وصحته، مشدداً على أن السمنة ليست خياراً ذاتياً للطفل، بل هي نتاج مباشر للعادات والخيارات التي توفرها الأسرة والمجتمع. وكشفت الحملة عن حقيقة إحصائية صادمة تدفع بملف صحة الطفل إلى واجهة الأمن الصحي، حيث يساهم اتباع نمط حياة صحي في منع <strong>80% </strong><strong>من الأمراض المزمنة والوفاة المبكرة</strong>.</p>
<p>ولتمكين الأسر من ممارسة دورها في حماية &#8220;القوة البشرية&#8221; القادمة، حدد المجلس خطوات عملية لصياغة بيئة غذائية واعية تشمل:</p>
<ul>
<li><strong>قراءة الملصقات التغذوية</strong><strong>:</strong> لمقارنة المنتجات واختيار الأقل ضرراً.</li>
<li><strong>التخطيط المسبق</strong><strong>:</strong> شراء مكونات صحية وتجهيز الوجبات لتفادي خيارات اللحظة الأخيرة غير الصحية.</li>
<li><strong>الإشراك الفعال</strong><strong>:</strong> دمج الطفل في عملية إعداد الطعام لتعزيز ارتباطه بالخيارات المفيدة.</li>
<li><strong>المشاركة العائلية</strong><strong>:</strong> تقديم غذاء متوازن خلال وجبات مشتركة تجمع كافة أفراد الأسرة.</li>
</ul>
<p>وضمن سياق إدارة جودة الحياة، دعت التوصيات إلى ضرورة الموازنة بين النشاط البدني والراحة عبر تشجيع الحرك واللعب، والحرص على نيل القسط الكافي من النوم، مع تقليل ساعات الجلوس أمام الشاشات والأجهزة الإلكترونية.</p>
<p>إن هذا الحراك الصحي الخليجي يرسخ قناعة بأن الصحة تبدأ من &#8220;البيت&#8221;، وأن حماية الأطفال من السكريات والوجبات السريعة والسهر هي الضمانة الحقيقية لبناء مجتمع منتج، يمتلك المناعة الجسدية والذهنية لمواجهة تحديات المستقبل.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/8b546095-19c9-412d-a916-50f8a6c26158.jpg', 'يوم الطفل الخليجي: جغرافيا الصحة تبدأ من &#8220;البيئة المحيطة&#8221; لكسر سلاسل السمنة', 'يوم الطفل الخليجي: جغرافيا الصحة تبدأ من &#8220;البيئة المحيطة&#8221; لكسر سلاسل السمنة', 'متابعة – كبسولة الصحية أكد مجلس الصحة الخليجي، تزامناً مع يوم الطفل الخليجي، أن الاهتمام بالبيئة المحيطة للطفل هو المحرك الأساسي لإحداث فارق جوهري في نموه وصحته', '{"يوم الطفل الخليجي"}', false, 'published', NULL, NULL, '2026-01-17 00:15:56', '2026-01-24 16:23:41.708216', '2026-01-24 16:23:41.708216');
INSERT INTO public.news VALUES ('c42545b1-6c46-47ad-946c-108f05a2c495', '50e3dc2', 'اعتماد  تسجيل مستحضر "أنكتيفا" لعلاج مرضى سرطان المثانة وسرطان الرئة', NULL, 'كبسولة الصحية &#8211; واس اعتمدت الهيئة العامة للغذاء والدواء، ضمن موافقة مشروطة وكأول جهة رقابية عالميًا، استخدام مستحضر أنكتيفا (نوجابنديكين ألفا إنباكيسيبت) لعلاج المرضى البالغين المصابين بسرطان الرئة ذو الخلايا غير الصغيرة النقيلي (NSCLC) كعلاج مضاف للعلاجات المناعية، وذلك عند تفاقم المرض وبعد ف', '<p>كبسولة الصحية &#8211; واس</p>
<p>اعتمدت الهيئة العامة للغذاء والدواء، ضمن موافقة مشروطة وكأول جهة رقابية عالميًا، استخدام مستحضر أنكتيفا (نوجابنديكين ألفا إنباكيسيبت) لعلاج المرضى البالغين المصابين بسرطان الرئة ذو الخلايا غير الصغيرة النقيلي (NSCLC) كعلاج مضاف للعلاجات المناعية، وذلك عند تفاقم المرض وبعد فشل العلاج القياسي.</p>
<p>كما اعتمدت الهيئة استخدام مستحضر أنكتيفا للمرضى البالغين المصابين بسرطان المثانة عالي الخطورة وغير الغازي للعضلة (NMIBC)، كعلاج مضاف إلى العلاج القياسي (BCG) لدى من لم يستجيبوا له.</p>
<p>وأوضحت &#8220;الغذاء والدواء&#8221; أن المستحضر يعمل بطريقة مبتكرة من خلال الارتباط وتحفيز مستقبلات إنترلوكين-15، مما يؤدي إلى تنشيط وتكاثر الخلايا القاتلة الطبيعية، والخلايا التائية لتحفيز الجهاز المناعي بشكل انتقائي، مع محدودية تكاثر الخلايا التائية التنظيمية المثبطة للاستجابة المناعية، ويُعطى المستحضر للمرضى المصابين بسرطان الرئة عن طريق الحقن تحت الجلد، في حين يُعطى للمرضى المصابين بسرطان المثانة عن طريق الحقن المباشر داخل المثانة المصابة.</p>
<p>وأشارت &#8220;الهيئة&#8221; إلى أن تسجيل المستحضر تم بناءً على تقييم شامل لمجمل الأدلة التي شملت فعاليته وسلامته وجودته وفقًا للمتطلبات التنظيمية المعتمدة، حيث أظهرت نتائج الدراسة السريرية على مرضى سرطان المثانة غير الغازي للعضلة معدل استجابة كاملة بلغ 62%، والتي اعتُمدت كنقطة النهاية الأساسية للدراسة.</p>
<p>كما جاءت الموافقة المشروطة على الادعاء الطبي المتعلق بسرطان الرئة ذو الخلايا غير الصغيرة بناءً على نتائج دراسة سريرية أُجريت على مرضى لم يستجيبوا مسبقًا لعلاج واحد أو أكثر، بما في ذلك الحواجز المناعية، حيث أظهرت الدراسة مؤشرات مبدئية لاحتمالية تحسن في معدل البقاء على قيد الحياة -بمشيئة الله-، كما اشترطت الهيئة أن تنفيذ دراسات تأكيدية لإثبات الفائدة السريرية النهائية على المدى البعيد للحفاظ على حالة الموافقة المشروطة.</p>
<p>واعتبرت &#8220;الهيئة&#8221; استنادًا إلى هذه النتائج أن المستحضر يوفر خيارًا علاجيًا جديدًا للمرضى ذوي البدائل العلاجية المحدودة؛ مما يسهم في تعزيز فرص السيطرة على المرض وتحسين البقاء على قيد الحياة -بمشيئة الله-.</p>
<p>وذكرت أن الأعراض الجانبية الأكثر شيوعًا التي ظهرت خلال الدراسات السريرية في سرطان المثانة شملت: ارتفاع الكرياتينين، وعسر التبول، ووجود دم في البول، وكثرة التبول، إضافة إلى التهاب المسالك البولية وارتفاع البوتاسيوم وآلام العضلات والعظام والقشعريرة والحمى.</p>
<p>أما الدراسات السريرية الخاصة بسرطان الرئة، فقد أظهرت أن الأعراض الجانبية الأكثر شيوعًا تضمنت: تفاعلات موضع الحقن مثل الاحمرار أو الحكة، إضافة إلى القشعريرة والإرهاق والحمى والغثيان وأعراض شبيهة بالإنفلونزا وفقدان الشهية.</p>
<p>ويعكس هذا الاعتماد التزام &#8220;الغذاء والدواء&#8221; المستمر بدعم الابتكار وتوسيع الوصول إلى العلاجات المتقدمة، بما يسهم في تعزيز جودة الرعاية الصحية ويتماشى مع مستهدفات برنامج تحول القطاع الصحي، أحد البرامج الرئيسية لرؤية المملكة 2030، ويعزز مكانة المملكة إقليميًا ودوليًا في مجال التنظيم الدوائي.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/12f0680f-d065-44f9-b95a-bf0fc73bc0af.webp', 'اعتماد  تسجيل مستحضر &#8220;أنكتيفا&#8221; لعلاج مرضى سرطان المثانة وسرطان الرئة', 'اعتماد  تسجيل مستحضر &#8220;أنكتيفا&#8221; لعلاج مرضى سرطان المثانة وسرطان الرئة', 'كبسولة الصحية &#8211; واس اعتمدت الهيئة العامة للغذاء والدواء، ضمن موافقة مشروطة وكأول جهة رقابية عالميًا، استخدام مستحضر أنكتيفا (نوجابنديكين ألفا إنباكيسيبت) ', '{"الهيئة العامة الغذاء والدواء","مستحضر أنكتيفا"}', false, 'published', NULL, NULL, '2026-01-17 00:12:55', '2026-01-24 16:23:42.024364', '2026-01-24 16:23:42.024364');
INSERT INTO public.news VALUES ('77ebb3b4-226f-4dc8-9c61-5d6009830729', '9f9f87d', 'جمعية "كبدك" تشارك في مهرجان الزيتون الدولي عبر مبادرة "ابتسامة العافية"', NULL, 'كبسولة الصحية &#8211;  واس شاركت الجمعية السعودية الخيرية لمرضى الكبد &#8220;كبدك&#8221; في مهرجان الزيتون الدولي، من خلال مبادرة &#8220;ابتسامة العافية&#8221;؛ بهدف رفع مستوى الوعي الصحي بأمراض الكبد وتعزيز الوقاية لدى أفراد المجتمع. وتضمنت مشاركة الجمعية تقديم نبذة تعريفية عن رسالتها وخدماتها، إلى', '<p>كبسولة الصحية &#8211;  واس</p>
<p>شاركت الجمعية السعودية الخيرية لمرضى الكبد &#8220;كبدك&#8221; في مهرجان الزيتون الدولي، من خلال مبادرة &#8220;ابتسامة العافية&#8221;؛ بهدف رفع مستوى الوعي الصحي بأمراض الكبد وتعزيز الوقاية لدى أفراد المجتمع.</p>
<p>وتضمنت مشاركة الجمعية تقديم نبذة تعريفية عن رسالتها وخدماتها، إلى جانب توزيع مطبوعات توعوية، وتنفيذ برامج تثقيف صحي حول أمراض الكبد، وإجراء فحوصات مبدئية للكشف عن التهاب الكبد الوبائي (B وC)، إضافة إلى تقديم هدايا تثقيفية للزوار من مختلف الفئات العمرية.</p>
<p>واستقبل ركن الجمعية أكثر من 12 ألف زائر من المواطنين والمقيمين، في تفاعل لافت يعكس وعي المجتمع بأهمية الفحص المبكر والتثقيف الصحي، وأسهم في إيصال الرسائل التوعوية للفئات المستهدفة.</p>
<p>وتأتي هذه المشاركة ضمن جهود جمعية &#8220;كبدك&#8221; المستمرة لتعزيز الوعي الصحي، والإسهام في تحسين جودة الحياة، بما ينسجم مع مستهدفات الصحة العامة.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/b5275b41-a21c-4786-b0ef-6b5d9b0a11bc.webp', 'جمعية &#8220;كبدك&#8221; تشارك في مهرجان الزيتون الدولي عبر مبادرة &#8220;ابتسامة العافية&#8221;', 'جمعية &#8220;كبدك&#8221; تشارك في مهرجان الزيتون الدولي عبر مبادرة &#8220;ابتسامة العافية&#8221;', 'كبسولة الصحية &#8211;  واس شاركت الجمعية السعودية الخيرية لمرضى الكبد &#8220;كبدك&#8221; في مهرجان الزيتون الدولي، من خلال مبادرة &#8220;ابتسامة العافية&#8221;؛', '{"ابتسامة العافية","جمعية كبدك"}', false, 'published', NULL, NULL, '2026-01-17 00:08:20', '2026-01-24 16:23:42.787056', '2026-01-24 16:23:42.787056');
INSERT INTO public.news VALUES ('249bc097-8e9b-45a7-bc42-fd546006769e', 'af55349', 'بأمر خادم الحرمين ..منح وسام الملك عبدالعزيز من الدرجة الثالثة لـ 200 مواطن ومواطنة ', NULL, 'كبسولة الصحية &#8211; واس صدرت موافقة خادم الحرمين الشريفين الملك سلمان بن عبدالعزيز آل سعود -حفظه الله-, على منح وسام الملك عبدالعزيز من الدرجة الثالثة لـ200 مواطن ومواطنة, وذلك لتبرع كل منهم بأحد أعضائه الرئيسة سواءً كان العضو من حي أو من متوفى دماغيًا. وفيما يلي أسماء المتبرعين والمتبرعات: إبراهي', '<p>كبسولة الصحية &#8211; واس</p>
<p>صدرت موافقة خادم الحرمين الشريفين الملك سلمان بن عبدالعزيز آل سعود -حفظه الله-, على منح وسام الملك عبدالعزيز من الدرجة الثالثة لـ200 مواطن ومواطنة, وذلك لتبرع كل منهم بأحد أعضائه الرئيسة سواءً كان العضو من حي أو من متوفى دماغيًا.</p>
<p>وفيما يلي أسماء المتبرعين والمتبرعات: إبراهيم بن علي بن عثمان الحسني الزهراني، إبراهيم بن محمد بن حسن عياشي، أحمد بن سعد بن عواد الضبعاني الشراري، أحمد بن علي بن عامر آل جميل الشهري، أحمد بن مريع بن أحمد مداوي، أحمد بن مفلح بن صالح القويعاني البلوي، أحمد بن وحيدي بن سالم النقمي الزهراني، إياد طلال بن سعد بن مبارك الضبعاني الشراري، أحمد بن منصور بن سليمان الخمسي العطوي، بدر بن علي بن عيد الغنامي الحويطي، بسام بن حمد بن عبدالله الدغامين الحربي، بندر بن مبيريك بن صويلح القميش المطيري، تركي بن محمد بن سليمان الخيبري، تركي بن محمد بن عوض الأصلبي الحربي، جاسر بن مجيول بن بعيجان القرفي البقمي، جميل بن عيد بن سالم السعيداني العطوي، حازم بن علي بن محمد الحازمي، حسن بن علي بن حسن مسملي، حسن بن علي بن عبده حريصي، حسن بن علي بن ناصر آل نبهان، حسين بن حسن بن ضيف الله الشلوي، حسين بن سعد بن حسين الحسان الشهراني، حسين بن عبدالله بن حسن آل موسى الشهري، حسين بن محمد بن صالح الدهيمي المالكي، حمزه بن إبراهيم بن أحمد الصالحي المقعدي، حمزه بن عمر بن عبدالقادر السويني العامودي، خالد بن أحمد بن جمعان آل جمعان الزهراني، خالد بن أحمد بن سليمان السعيد، خالد بن حضيض بن مسلم الأحمدي، خالد بن سعود بن صالح الضمادي، خالد بن منصور بن إبراهيم الخياري الرشيدي، راشد بن محمد بن مفرح آل راضي الغامدي، زهير بن جعفر بن عبدالله آل خريده، زياد بن مبارك بن طاحوس الجلادين العصيمي، زكي بن فاضل بن علوي آل درويش، زيد بن أحمد بن شبيط الاسلمي الشمري، سعد بن سعيد بن سعد آل حمد الدعجاني، سعد بن علي بن أحمد غزواني، سعود بن عوض بن علي آل سعيد الحربي، سعيد بن سلطان بن علي آل فارع القحطاني، سعيد بن علي بن محمد البيشي، سعيد بن محمد بن سعيد آل ناميه الغامدي، سلطان بن مبارك بن عبدالرحمن المنبهي البيشي، سلمان بن قاسم بن امشريف غزواني، سليمان بن علي بن حسن عائض، شاكر بن نازل بن فلحى شلاقي الشمري، صالح بن محمد بن هادي الشدوق المري، صالح بن ناصر بن عبدالله الشريان، طارق بن قاسم بن موسى جعفري، طارق بن على بن محمد العمري الزهراني، طلال بن خالد بن عبدالكريم الصويلح، طلال بن محمد بن عبدالله العامري الزهراني، عادل بن جمعان بن غالي القرشى، عاصم بن علي بن يحي عريشي، عبدالرحمن بن ضيف الله بن عبدالرحمن الكناني الزهراني، عبدالعزيز بن