INSERT INTO public.news VALUES ('2c85dbfa-51d8-4620-ae71-96ee6eb397b9', '7078060', 'بصمة وراثية معقدة: اجتماع "المنجلية" و"الثلاسيميا" يهدد الأجيال بمرض مشترك', NULL, 'تقنيات &#8220;أطفال الأنابيب PGD&#8221; ترفع نسبة سلامة الأجنة إلى 97%.. وفحص المشيمة خيار حاسم متابعة – كبسولة الصحية صححت استشارية النساء والولادة، الدكتورة مها النمر، مفهوماً مغلوطاً وشائعاً يدعي أن اختلاف نوع المرض الوراثي بين الوالدين (مثل حمل أحدهما للأنيميا المنجلية والآخر للثلاسيميا) يمنع ان', '<p><strong>تقنيات &#8220;أطفال الأنابيب</strong><strong> PGD&#8221; </strong><strong>ترفع نسبة سلامة الأجنة إلى 97%.. وفحص المشيمة خيار حاسم</strong></p>
<p><strong>متابعة – كبسولة الصحية</strong></p>
<p>صححت استشارية النساء والولادة، الدكتورة مها النمر، مفهوماً مغلوطاً وشائعاً يدعي أن اختلاف نوع المرض الوراثي بين الوالدين (مثل حمل أحدهما للأنيميا المنجلية والآخر للثلاسيميا) يمنع انتقال المرض للأبناء. وأكدت أن الواقع العلمي يثبت احتمالية إصابة الجنين بنسبة 25% بمرض هجين يسمى <strong>&#8220;</strong><strong>ثلاسيميا منجلية</strong><strong>&#8220;</strong>، وهو اضطراب وراثي يؤدي إلى تكسر الدم، مما يفرض ضرورة الوعي الطبي الاستباقي قبل اتخاذ قرار الحمل.</p>
<p>وضمن جهود تعزيز الصحة الإنجابية وتقليل الأمراض الوراثية، قدمت الدكتورة النمر مسارين عمليين لضمان ولادة أطفال أصحاء في الحالات التي تعاني من هذا التداخل الجيني:</p>
<ul>
<li><strong>تقنية أطفال الأنابيب مع الفحص الوراثي</strong><strong> (PGD):</strong> وهي تقنية متطورة لفحص الأجنة وراثياً قبل انغراسها في الرحم، حيث تضمن سلامة الجنين بنسبة تصل إلى 97%.</li>
<li><strong>التشخيص الجيني المبكر</strong><strong>:</strong> في حالات الحمل الطبيعي، يمكن اللجوء لمستشفيات متخصصة لإجراء خزعة من المشيمة (بين الأسبوعين 11 و14) أو فحص السائل الأمنيوسي (من الأسبوع 15)، وتصل دقة هذه النتائج إلى 100% لكونها تؤخذ مباشرة من خلايا الجنين.</li>
</ul>
<p>ويأتي هذا التنبيه الطبي ليعزز من أهمية الوعي بالخريطة الجينية واللجوء للتقنيات الطبية المتقدمة التي تتيحها المنظومة الصحية الوطنية، لضمان بناء مجتمع سليم وحماية الأسر من التبعات النفسية والمادية للأمراض المزمنة.</p>
<p>إن التوسع في هذه المسارات التشخيصية يمثل ركيزة استراتيجية في وقاية المجتمع من الأمراض الوراثية، وتحويل التحديات الجينية إلى فرص لحياة مستقرة للأجيال القادمة.</p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/8c0cf247-0b53-4b67-9911-c9314233cd23.jpg', 'بصمة وراثية معقدة: اجتماع &#8220;المنجلية&#8221; و&#8221;الثلاسيميا&#8221; يهدد الأجيال بمرض مشترك', 'بصمة وراثية معقدة: اجتماع &#8220;المنجلية&#8221; و&#8221;الثلاسيميا&#8221; يهدد الأجيال بمرض مشترك', 'تقنيات &#8220;أطفال الأنابيب PGD&#8221; ترفع نسبة سلامة الأجنة إلى 97%.. وفحص المشيمة خيار حاسم متابعة – كبسولة الصحية صححت استشارية النساء والولادة، الدكتورة م', '{"الأنيميا المنجلية","البصمة الوراثية"}', false, 'published', NULL, NULL, '2026-01-16 01:07:45', '2026-01-24 16:23:44.340837', '2026-01-24 16:23:44.340837');
INSERT INTO public.news VALUES ('c967871e-08a2-4189-af00-8408f432b809', '0087028', 'يوم الطفل الخليجي: العادات الصحية ترسم مستقبل الأجيال بعيداً عن السمنة', NULL, 'متابعة – كبسولة الصحية أطلقت منصة &#8220;عش بصحة&#8221; التابعة لوزارة الصحة، تزامناً مع يوم الطفل الخليجي، حملة توعوية تؤكد أن السمنة لدى الأطفال تتشكل نتيجة العادات المحيطة بهم، وليست خياراً يقرره الطفل. وتأتي هذه الخطوة لترسيخ مفهوم &#8220;بناء الإنسان السليم&#8221; كركيزة أساسية في جودة الحياة، ', '<p>متابعة – كبسولة الصحية</p>
<p>أطلقت منصة &#8220;عش بصحة&#8221; التابعة لوزارة الصحة، تزامناً مع يوم الطفل الخليجي، حملة توعوية تؤكد أن السمنة لدى الأطفال تتشكل نتيجة العادات المحيطة بهم، وليست خياراً يقرره الطفل. وتأتي هذه الخطوة لترسيخ مفهوم &#8220;بناء الإنسان السليم&#8221; كركيزة أساسية في جودة الحياة، حيث لم تعد صحة الطفل مجرد شأن أسري، بل أصبحت قضية أمن وطني تهدف إلى بناء جيل حيوي قادر على قيادة مستقبل المملكة بعيداً عن عبء الأمراض المزمنة.</p>
<p>وشددت الحملة على أن المسؤولية تقع على عاتق البيئة المحيطة في تغيير الأنماط السلوكية المسببة للسمنة، عبر اتباع خمس خطوات وقائية أساسية:</p>
<p>&#8211; توفير خيارات أكل صحية ومتنوعة للطفل بشكل دائم.</p>
<p>&#8211; تعزيز النوم الجيد وتجنيب الأطفال السهر لضمان توازن العمليات الحيوية.</p>
<p>&#8211; تشجيع الأطفال على ممارسة الأنشطة الحركية بانتظام.</p>
<p>&#8211; تقليل ساعات الجلوس أمام الشاشات والأجهزة الإلكترونية.</p>
<p>&#8211; الحد من تناول السكريات والوجبات السريعة التي تساهم في زيادة الوزن بشكل مفرط.</p>
<p>وأوضح المختصون أن حماية الطفل من السمنة في هذا العمر المبكر هي الخط الدفاعي الأول لتقليل الضغط على المنظومة الصحية مستقبلاً، حيث يساهم تنظيم عادات النوم وتقنين استخدام الشاشات في خلق توازن بدني وذهني يحتاجه الطفل في مراحل نموه الحرجة. ويهدف يوم الطفل الخليجي هذا العام إلى التأكيد على أن توفير الخيارات الصحية هو استثمار استراتيجي في القوة البشرية للمملكة، يضمن للأجيال القادمة حياة آمنة ومزدهرة بعيداً عن مخاطر السمنة المفرطة وتبعاتها.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/4c660ad1-a630-4305-928d-02aa46e38af4.jpg', 'يوم الطفل الخليجي: العادات الصحية ترسم مستقبل الأجيال بعيداً عن السمنة', 'يوم الطفل الخليجي: العادات الصحية ترسم مستقبل الأجيال بعيداً عن السمنة', 'متابعة – كبسولة الصحية أطلقت منصة &#8220;عش بصحة&#8221; التابعة لوزارة الصحة، تزامناً مع يوم الطفل الخليجي، حملة توعوية تؤكد أن السمنة لدى الأطفال تتشكل نتيجة ا', '{"يوم الطفل الخليجي"}', false, 'published', NULL, NULL, '2026-01-16 01:04:23', '2026-01-24 16:23:44.703526', '2026-01-24 16:23:44.703526');
INSERT INTO public.news VALUES ('2465087a-e233-4e63-a9ae-fa3dc3e671a6', 'd0e52e0', 'بدء التسجيل لحضور ملتقى نموذج الرعاية الصحية السعودي 2026 بالرياض', NULL, 'كبسولة الصحية &#8211;  واس تحت رعاية معالي وزير الصحة رئيس مجلس إدارة الصحة القابضة الأستاذ فهد بن عبدالرحمن الجلاجل، ينطلق في مدينة الرياض ملتقى نموذج الرعاية الصحية السعودي 2026 في نسخته الثالثة، خلال يومي 9 و10 فبراير المقبل، الذي تنظمه الصحة القابضة، وسط حضور عدد من المتحدثين المحليين والدوليين،', '<p>كبسولة الصحية &#8211;  واس</p>
<p>تحت رعاية معالي وزير الصحة رئيس مجلس إدارة الصحة القابضة الأستاذ فهد بن عبدالرحمن الجلاجل، ينطلق في مدينة الرياض ملتقى نموذج الرعاية الصحية السعودي 2026 في نسخته الثالثة، خلال يومي 9 و10 فبراير المقبل، الذي تنظمه الصحة القابضة، وسط حضور عدد من المتحدثين المحليين والدوليين، تحت عنوان &#8220;صناعة الأثر&#8221;.</p>
<p>ويمكن التسجيل والاطلاع على جميع المعلومات حول الملتقى من خلال زيارة الموقع الإلكتروني: https://www.health.sa/ar/moc-forum.</p>
<p>وشهدت النسخة الماضية من الملتقى تسجيل أكثر من 20 ألف ممارس صحي، وحضور ما يزيد عن 3 آلاف.</p>
<p>ويأتي الملتقى هذا العام ليستعرض قصص نجاح أنظمة ومسارات نموذج الرعاية الصحية السعودي والتعريف به محليًا وعالميًا، وتسليط الضوء على أثر تطبيق النموذج الصحي السعودي على حياة الفرد وصحة المجتمع، كما يستعرض الملتقى آخر التطورات والمبادرات الصحة التي ابتكرتها الصحة القابضة وفق أعلى المعايير لتعزيز جودة خدمات الرعاية الصحية بالمملكة، وسبل تسهيل وصول المستفيدين إليها، وبرامج تعزيز الوعي الصحي لتفعيل مبدأ الوقاية قبل العلاج، تماشيًا مع مستهدفات رؤية المملكة 2030 وبرنامج تحول القطاع الصحي.</p>
<p>ويمثل الملتقى المرحلة الثانية من أربع مراحل إستراتيجية ضمن مسيرة التحول في القطاع الصحي، التي تهدف إلى تطوير نموذج الرعاية الصحية في المملكة، حيث تضطلع الصحة القابضة بدور محوري في تمكين تقديم الخدمات الصحية عبر 20 تجمعًا صحيًا تغطي كافة مناطق ومدن المملكة.</p>
<p>ويصاحب ملتقى نموذج الرعاية الصحية السعودي 2026 برنامجًا علميًا متكاملًا يشمل ورش عمل وجلسات متخصصة، بمشاركة أكثر من 25 متحدثًا محليًا ودوليًا، إضافة إلى معرض مصاحب يضم أكثر من 85 جهة عارضة تستعرض أحدث الحلول والممارسات في مجالات الرعاية الصحية، كما سيشهد الملتقى تكريم الفائزين في جائزة ملتقى نموذج الرعاية الصحية السعودي 2026.</p>
<p>يُذكر أن الصحة القابضة هي شركة وطنية تتولى تقديم الرعاية الصحية الشاملة والمتكاملة من خلال 20 تجمعًا صحيًا تستهدف خدمة الإنسان في كافة مناطق المملكة، عبر تطبيق نموذج الرعاية الصحية السعودي الذي يضع الإنسان في محور اهتمامه، ويقوم على التحول في طريقة تقديم الخدمات الصحية، وتفعيل الوقاية قبل العلاج، كما يسهم في تسهيل وصول المستفيدين إلى الرعاية، والارتقاء بمستوى جودة الخدمات.</p>
<p><strong> </strong></p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/67e1d40a-0ce6-4b9c-943a-c0bcd63668e9.jpg', 'بدء التسجيل لحضور ملتقى نموذج الرعاية الصحية السعودي 2026 بالرياض', 'بدء التسجيل لحضور ملتقى نموذج الرعاية الصحية السعودي 2026 بالرياض', 'كبسولة الصحية &#8211;  واس تحت رعاية معالي وزير الصحة رئيس مجلس إدارة الصحة القابضة الأستاذ فهد بن عبدالرحمن الجلاجل، ينطلق في مدينة الرياض ملتقى نموذج الرعاية ', '{"ملتقى نموذج الرعاية الصحية السعودي"}', false, 'published', NULL, NULL, '2026-01-16 01:02:14', '2026-01-24 16:23:45.027181', '2026-01-24 16:23:45.027181');
INSERT INTO public.news VALUES ('3c5650c9-c32f-4810-9cf0-5567de06d9c9', '6b7d4c3', 'برعاية وزارة الصحة انطلاق المؤتمر الدولي التاسع للجمعية السعودية للأشعة التداخلية (SIRS 2026)', NULL, 'كبسولة الصحية &#8211;  واس انطلقت في العاصمة الرياض اليوم، أعمال المؤتمر الدولي التاسع للجمعية السعودية للأشعة التداخلية (SIRS 2026)، وذلك برعاية وزارة الصحة، وبمشاركة واسعة من القيادات الصحية والخبراء والمتخصصين في مجال الأشعة التداخلية من داخل المملكة وخارجها، ويستمر المؤتمر حتى 17 يناير 2026. ويُ', '<p>كبسولة الصحية &#8211;  واس</p>
<p>انطلقت في العاصمة الرياض اليوم، أعمال المؤتمر الدولي التاسع للجمعية السعودية للأشعة التداخلية (SIRS 2026)، وذلك برعاية وزارة الصحة، وبمشاركة واسعة من القيادات الصحية والخبراء والمتخصصين في مجال الأشعة التداخلية من داخل المملكة وخارجها، ويستمر المؤتمر حتى 17 يناير 2026.</p>
<p>ويُعد المؤتمر أحد أبرز الفعاليات العلمية المتخصصة في مجال الأشعة التداخلية على مستوى المنطقة، إذ يجسد توجه الجمعية السعودية للأشعة التداخلية نحو تعزيز دور هذا التخصص الحيوي في تطوير الرعاية الصحية، ودعم تطبيق الحلول العلاجية الحديثة غير الجراحية، بما يسهم في تحسين تجربة المريض ورفع كفاءة الخدمات الطبية.</p>
<p>وشهد المؤتمر حضورًا علميًا مكثفًا، بمشاركة أكثر من 160 متحدثًا محليًا ودوليًا، يقدمون برنامجًا علميًا متنوعًا يضم أكثر من 50 جلسة علمية وورش عمل متخصصة، تستعرض أحدث المستجدات البحثية والتقنيات المتقدمة والتطبيقات الإكلينيكية في الأشعة التداخلية، بمشاركة خبراء من 20 دولة، ما يعزز من الحضور الدولي للمؤتمر ومكانته العلمية.</p>
<p>ويهدف المؤتمر إلى ترسيخ مفهوم تبادل المعرفة ونقل الخبرات بين المختصين، وتسليط الضوء على إسهامات الأشعة التداخلية في تقديم حلول علاجية آمنة وفعّالة، أسهمت في تقليل مدة التنويم وتسريع تعافي المرضى، إضافة إلى دعم تمكين المنشآت الصحية في مختلف مناطق المملكة من تقديم خدمات متقدمة دون الحاجة إلى إحالة المرضى خارج مناطقهم.</p>
<p>وأكد رئيس مجلس إدارة الجمعية السعودية للأشعة التداخلية الدكتور حسن بن موسى الشهري أن المؤتمر يشكل منصة علمية متقدمة تجمع نخبة من الخبراء العالميين، ويعكس حرص الجمعية على مواكبة التطورات المتسارعة في هذا المجال، وتعزيز التعاون العلمي والمهني بين الكفاءات الوطنية والدولية، بما يدعم الابتكار ويسهم في تحقيق مستهدفات تطوير القطاع الصحي في المملكة.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/cd14bc03-e2b0-447d-97f1-cc7ac117dfdb.webp', 'برعاية وزارة الصحة انطلاق المؤتمر الدولي التاسع للجمعية السعودية للأشعة التداخلية (SIRS 2026)', 'برعاية وزارة الصحة انطلاق المؤتمر الدولي التاسع للجمعية السعودية للأشعة التداخلية (SIRS 2026)', 'كبسولة الصحية &#8211;  واس انطلقت في العاصمة الرياض اليوم، أعمال المؤتمر الدولي التاسع للجمعية السعودية للأشعة التداخلية (SIRS 2026)، وذلك برعاية وزارة الصحة، و', '{"المؤتمر الدولي التاسع للجمعية السعودية للأشعة التداخلية","وزارة الصحة"}', false, 'published', NULL, NULL, '2026-01-15 21:49:38', '2026-01-24 16:23:45.717105', '2026-01-24 16:23:45.717105');
INSERT INTO public.news VALUES ('43038a30-16aa-4052-b40e-21a8ab6f9fcc', 'ff03f9a', 'مستشفى قوى الأمن بالرياض يُجري عملية نوعية لاستبدال مفصل الركبة بتقنية الروبوت الجراحي', NULL, 'كبسولة الصحية &#8211;  واس أجرى فريق جراحة العظام بمستشفى قوى الأمن بالرياض عملية نوعية لاستبدال مفصل الركبة لأحد المستفيدين، باستخدام تقنية الروبوت الجراحي المتقدمة (CORI)، التي تسهم في تعزيز دقة الإجراءات الجراحية وتحسين النتائج العلاجية. وأوضح الفريق الطبي أن التقنية تعتمد على التخطيط ثلاثي الأبع', '<p>كبسولة الصحية &#8211;  واس</p>
<p>أجرى فريق جراحة العظام بمستشفى قوى الأمن بالرياض عملية نوعية لاستبدال مفصل الركبة لأحد المستفيدين، باستخدام تقنية الروبوت الجراحي المتقدمة (CORI)، التي تسهم في تعزيز دقة الإجراءات الجراحية وتحسين النتائج العلاجية.</p>
<p>وأوضح الفريق الطبي أن التقنية تعتمد على التخطيط ثلاثي الأبعاد قبل وأثناء العملية، بما يتيح تحديدًا دقيقًا لزوايا القطع العظمية ومواقع الزراعة وفق القياسات الفعلية لكل مريض، ويسهم في تقليل فقدان الدم والمضاعفات المحتملة، وتسريع التعافي بعد الجراحة، وتحسين ثبات المفصل المزروع وزيادة عمره الافتراضي.</p>
<p>ويأتي توظيف هذه التقنية ضمن جهود الخدمات الطبية بوزارة الداخلية لتبني التقنيات الطبية الحديثة والارتقاء بجودة الرعاية المقدمة وفق أفضل الممارسات الطبية.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/f811b839-59ce-48ff-8c1e-d512f0e2a114.jpg', 'مستشفى قوى الأمن بالرياض يُجري عملية نوعية لاستبدال مفصل الركبة بتقنية الروبوت الجراحي', 'مستشفى قوى الأمن بالرياض يُجري عملية نوعية لاستبدال مفصل الركبة بتقنية الروبوت الجراحي', 'كبسولة الصحية &#8211;  واس أجرى فريق جراحة العظام بمستشفى قوى الأمن بالرياض عملية نوعية لاستبدال مفصل الركبة لأحد المستفيدين، باستخدام تقنية الروبوت الجراحي الم', '{"استبدال مفصل الركبة","مستشفى قوى الأمن بالرياض"}', false, 'published', NULL, NULL, '2026-01-15 12:38:44', '2026-01-24 16:23:46.118091', '2026-01-24 16:23:46.118091');
INSERT INTO public.news VALUES ('a05d39ee-3cb6-4ee4-85f9-72f6ed3fc386', '68fddc9', 'المدينة الطبية بجامعة الملك سعود تحصل على شهادة ISO 31000 لإدارة المخاطر', NULL, 'كبسولة الصحية &#8211; واس حصلت المدينة الطبية بجامعة الملك سعود على شهادة ISO 31000 لإدارة المخاطر، نظير التزامها بتطبيق أعلى المعايير والمنهجيات العالمية في مجال إدارة المخاطر المؤسسية، وتعزيز كفاءة الحوكمة المؤسسية. ويأتي ذلك ضمن حزمة من المبادرات الإستراتيجية التي تهدف إلى ترسيخ ثقافة إدارة المخا', '<p>كبسولة الصحية &#8211; واس</p>
<p>حصلت المدينة الطبية بجامعة الملك سعود على شهادة ISO 31000 لإدارة المخاطر، نظير التزامها بتطبيق أعلى المعايير والمنهجيات العالمية في مجال إدارة المخاطر المؤسسية، وتعزيز كفاءة الحوكمة المؤسسية.</p>
<p>ويأتي ذلك ضمن حزمة من المبادرات الإستراتيجية التي تهدف إلى ترسيخ ثقافة إدارة المخاطر، ورفع مستوى الجاهزية المؤسسية، والتحكم بالمخاطر المحتملة التي قد تؤثر على تحقيق أهداف المدينة الطبية الجامعية ورؤيتها المستقبلية.</p>
<p>وأكد المدير العام التنفيذي للمدينة الطبية الدكتور أحمد هرسي، أهمية مواصلة تطوير أنظمة إدارة المخاطر وفق أفضل الممارسات العالمية، بما يدعم جودة الخدمات الصحية والتعليمية والبحثية المقدمة.</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/0a6c2886-1720-4161-8f9d-e3307dc894ac.webp', 'المدينة الطبية بجامعة الملك سعود تحصل على شهادة ISO 31000 لإدارة المخاطر', 'المدينة الطبية بجامعة الملك سعود تحصل على شهادة ISO 31000 لإدارة المخاطر', 'كبسولة الصحية &#8211; واس حصلت المدينة الطبية بجامعة الملك سعود على شهادة ISO 31000 لإدارة المخاطر، نظير التزامها بتطبيق أعلى المعايير والمنهجيات العالمية في مج', '{"المدينة الطبية بجامعة الملك سعود","شهادة الأيزو"}', false, 'published', NULL, NULL, '2026-01-15 12:30:21', '2026-01-24 16:23:46.78864', '2026-01-24 16:23:46.78864');
INSERT INTO public.news VALUES ('51c30f91-a390-4adf-90f2-f1cea54c0253', 'f59b3a7', 'رسمياً.. زيادة ساعات العمل في "تجمع الشرقية الصحي" إلى 9 ساعات يومياً', NULL, 'متابعة – كبسولة الصحية أقر تجمع الشرقية الصحي لائحة دوام رسمية تُلزم كافة منسوبيه بالعمل لمدة تسع ساعات يومياً، في أول إجراء إداري عقب انتقال الموظفين رسمياً إلى كادر شركة الصحة القابضة، وذلك وفقاً لما نشرته صحيفة اليوم. يمثل القرار تحولاً جوهرياً في بيئة العمل الصحي بالمنطقة تزامناً مع المرحلة الان', '<p>متابعة – كبسولة الصحية</p>
<p>أقر تجمع الشرقية الصحي لائحة دوام رسمية تُلزم كافة منسوبيه بالعمل لمدة تسع ساعات يومياً، في أول إجراء إداري عقب انتقال الموظفين رسمياً إلى كادر شركة الصحة القابضة، وذلك وفقاً لما نشرته صحيفة اليوم.</p>
<p>يمثل القرار تحولاً جوهرياً في بيئة العمل الصحي بالمنطقة تزامناً مع المرحلة الانتقالية للقطاع؛ حيث حددت وحدة مراقبة انتظام الموارد البشرية إطاراً زمنياً صارماً يبدأ من السابعة والنصف صباحاً وحتى الرابعة والنصف مساءً. ويهدف هذا الإجراء، بحسب تقرير صحيفة اليوم، إلى توحيد التوقيت الزمني في كافة المراكز الصحية التابعة للتجمع وضمان تقديم الخدمات بكفاءة طوال ساعات العمل المقررة دون استثناءات.</p>
<p>وجهت إدارة التجمع بإعادة هيكلة فورية لجداول المناوبات لتتوافق مع واقع الساعات التسع الجديد، مع التشدد في تطبيق الانضباط الوظيفي. ومن المتوقع أن يعقب هذه الخطوة إجراءات تنظيمية أخرى تهدف إلى ضبط الأداء تحت إدارة &#8220;الصحة القابضة&#8221;، مما يضع الكوادر الصحية أمام واقع إداري جديد يتطلب التكيف السريع مع معايير الإنتاجية الجديدة.</p>
<p>&nbsp;</p>
', 'health-news', 'https://capsulah.com', NULL, '/objects/uploads/c680a99e-2475-4b84-b34a-4f1c52951330.jpg', 'رسمياً.. زيادة ساعات العمل في &#8220;تجمع الشرقية الصحي&#8221; إلى 9 ساعات يومياً', 'رسمياً.. زيادة ساعات العمل في &#8220;تجمع الشرقية الصحي&#8221; إلى 9 ساعات يومياً', 'متابعة – كبسولة الصحية أقر تجمع الشرقية الصحي لائحة دوام رسمية تُلزم كافة منسوبيه بالعمل لمدة تسع ساعات يومياً، في أول إجراء إداري عقب انتقال الموظفين رسمياً إل', '{"الصحة القابضة","تجمع الشرقية الصحي","ساعات العمل"}', false, 'deleted', NULL, NULL, '2026-01-24 16:28:17', '2026-01-24 16:23:12.20637', '2026-01-24 16:23:12.20637');
INSERT INTO public.news VALUES ('55a01b48-9354-4c26-844d-4908bc2dd9e9', 'c7a61f0', 'مؤتمر الطب العربي 2025: أحدث التطورات في الرعاية الصحية', NULL, 'انطلاق مؤتمر الطب العربي السنوي في دبي بمشاركة أكثر من 5000 طبيب من 50 دولة.', 'افتتح مؤتمر الطب العربي 2025 في دبي بحضور نخبة من الأطباء والباحثين من جميع أنحاء العالم. المؤتمر يركز على أحدث التطورات في الطب الدقيق والذكاء الاصطناعي في الرعاية الصحية.

أهم المواضيع المطروحة:
- الطب الشخصي والجينوم
- الذكاء الاصطناعي في التشخيص
- التقنيات الجراحية الحديثة
- الوقاية من الأمراض المزمنة

المؤتمر يستمر لمدة ثلاثة أيام ويشمل أكثر من 200 محاضرة وورشة عمل.', 'health-events', 'مؤتمر الطب العربي', 'https://www.arabmedconf.com', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-31 00:00:00', '2026-01-24 13:59:54.086944', '2026-01-24 13:59:54.086944');
INSERT INTO public.news VALUES ('ee2767ce-959e-4e77-9e31-23255b49bd03', '10fba91', 'مؤتمر جدة للابتكار الصحي 2025', NULL, 'انطلاق مؤتمر جدة للابتكار الصحي بمشاركة خبراء عالميين.', 'انطلق مؤتمر جدة للابتكار الصحي 2025 بمشاركة أكثر من 3000 خبير من 40 دولة.

المحاور الرئيسية:
- الطب الدقيق
- الروبوتات الجراحية
- التطبيب عن بعد
- الذكاء الاصطناعي في الرعاية الصحية

المؤتمر يستمر ثلاثة أيام.', 'health-events', 'مؤتمر جدة الصحي', 'https://www.jeddahhealthconf.sa', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-18 00:00:00', '2026-01-24 13:59:54.67958', '2026-01-24 13:59:54.67958');
INSERT INTO public.news VALUES ('26bb6c10-cf16-4bea-acd9-d9278bebd7e3', '64aab03', 'فوائد الأفوكادو للصحة: غذاء خارق', NULL, 'دراسة تكشف الفوائد الصحية المذهلة للأفوكادو.', 'الأفوكادو يعتبر من الأطعمة الخارقة لفوائده المتعددة:

- غني بالدهون الصحية
- يحسن صحة القلب
- يعزز امتصاص العناصر الغذائية
- غني بالألياف
- يحتوي على البوتاسيوم أكثر من الموز

ينصح بتناول نصف حبة يومياً.', 'nutrition', 'جمعية التغذية الأمريكية', 'https://www.eatright.org', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-14 00:00:00', '2026-01-24 13:59:54.861899', '2026-01-24 13:59:54.861899');
INSERT INTO public.news VALUES ('ff888a19-a39c-4800-9207-a462c0c4545b', 'f381157', 'دراسة: النوم الجيد يقوي جهاز المناعة بنسبة 70%', NULL, 'بحث علمي جديد يكشف العلاقة القوية بين جودة النوم وقوة الجهاز المناعي.', 'نشرت مجلة Nature دراسة شاملة تؤكد أن الحصول على 7-8 ساعات من النوم الجيد يومياً يعزز جهاز المناعة بنسبة تصل إلى 70%.

الدراسة أظهرت أن:
- قلة النوم تضعف الخلايا المناعية
- النوم العميق ضروري لإنتاج الأجسام المضادة
- الأشخاص الذين ينامون جيداً أقل عرضة للإصابة بالعدوى

الباحثون ينصحون بالنوم المنتظم في أوقات ثابتة.', 'health-community', 'مجلة Nature', 'https://www.nature.com', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-26 00:00:00', '2026-01-24 13:59:54.315878', '2026-01-24 13:59:54.315878');
INSERT INTO public.news VALUES ('59845916-d3ee-44e3-bf5b-c53a7b793606', 'df696d8', 'منظمة الصحة العالمية: تراجع وفيات الملاريا بنسبة 60%', NULL, 'تقرير جديد يظهر انخفاضاً كبيراً في وفيات الملاريا عالمياً بفضل اللقاحات الجديدة.', 'أعلنت منظمة الصحة العالمية عن تراجع كبير في وفيات الملاريا بنسبة 60% خلال السنوات الخمس الأخيرة.

الأسباب الرئيسية:
- انتشار لقاح الملاريا الجديد
- تحسن برامج مكافحة البعوض
- زيادة الوعي الصحي

الهدف القضاء على الملاريا بحلول 2030.', 'health-community', 'منظمة الصحة العالمية', 'https://www.who.int', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-20 00:00:00', '2026-01-24 13:59:54.588561', '2026-01-24 13:59:54.588561');
INSERT INTO public.news VALUES ('f18832e4-1571-4f0a-aa40-f5e6cd6ea64c', '7056e37', 'حملة توعية: أهمية الكشف المبكر عن سرطان الثدي', NULL, 'إطلاق حملة وطنية للتوعية بأهمية الفحص المبكر لسرطان الثدي خلال شهر أكتوبر الوردي.', 'أطلقت وزارة الصحة حملة وطنية شاملة للتوعية بأهمية الكشف المبكر عن سرطان الثدي. الحملة تتضمن فحوصات مجانية في جميع المراكز الصحية.

الإحصائيات تشير إلى أن الكشف المبكر يزيد فرص الشفاء إلى أكثر من 95%. الحملة تستهدف النساء فوق سن 40 عاماً.

الأطباء ينصحون بإجراء فحص ذاتي شهري وماموجرام سنوي للكشف المبكر.', 'health-community', 'وزارة الصحة', 'https://www.moh.gov.sa', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-30 00:00:00', '2026-01-24 13:59:54.132624', '2026-01-24 13:59:54.132624');
INSERT INTO public.news VALUES ('853c2cce-2813-4c81-bd6e-8283c049db77', 'dab3dfa', 'مصر تطلق مبادرة للقضاء على فيروس سي', NULL, 'نجاح مبادرة 100 مليون صحة في علاج ملايين المصابين بفيروس سي.', 'أعلنت مصر نجاح مبادرة "100 مليون صحة" في علاج أكثر من 4 ملايين مصاب بفيروس سي.

إنجازات المبادرة:
- فحص 60 مليون مواطن
- علاج 4 ملايين مصاب
- نسبة شفاء تتجاوز 98%
- خفض معدل الإصابة بنسبة 90%

مصر تقترب من القضاء التام على الفيروس.', 'health-community', 'وزارة الصحة المصرية', 'https://www.mohp.gov.eg', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-15 00:00:00', '2026-01-24 13:59:54.815943', '2026-01-24 13:59:54.815943');
INSERT INTO public.news VALUES ('9625a1c6-fc07-4188-be80-a3c0371dd697', 'bbc1d76', 'إطلاق لقاح جديد للإنفلونزا الموسمية بفعالية 95%', NULL, 'شركة فايزر تعلن عن لقاح جديد للإنفلونزا يوفر حماية أفضل من اللقاحات التقليدية.', 'أعلنت شركة فايزر عن تطوير لقاح جديد للإنفلونزا الموسمية بفعالية تصل إلى 95%. اللقاح الجديد يستخدم تقنية mRNA المشابهة للتقنية المستخدمة في لقاحات كوفيد-19.

اللقاح أظهر فعالية عالية ضد جميع سلالات الإنفلونزا الشائعة. يتوقع أن يكون متاحاً في الموسم القادم للإنفلونزا.

الخبراء يعتبرون هذا التطور نقلة نوعية في الوقاية من الإنفلونزا الموسمية.', 'health-reports', 'فايزر', 'https://www.pfizer.com', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-11-01 00:00:00', '2026-01-24 13:59:54.041453', '2026-01-24 13:59:54.041453');
INSERT INTO public.news VALUES ('4a473204-26a6-4d63-a897-9d50312b1e62', '0cb2567', 'دواء جديد لعلاج الصداع النصفي في دقائق', NULL, 'إدارة الغذاء والدواء توافق على دواء جديد يوقف نوبات الصداع النصفي خلال 15 دقيقة.', 'وافقت إدارة الغذاء والدواء الأمريكية على دواء جديد لعلاج الصداع النصفي يُدعى "ميغرا-ستوب".

الدواء الجديد:
- يوقف الألم خلال 15 دقيقة
- بأعراض جانبية قليلة
- متاح على شكل بخاخ أنفي
- مناسب للبالغين فوق 18 عاماً

سيتوفر في الصيدليات الشهر المقبل.', 'health-reports', 'إدارة الغذاء والدواء', 'https://www.fda.gov', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-17 00:00:00', '2026-01-24 13:59:54.723932', '2026-01-24 13:59:54.723932');
INSERT INTO public.news VALUES ('7aabe0e1-5ff1-423c-b890-b2fd7398fe70', 'btXBgmh', 'نجاح عالمي: زراعة كبد بروبوت لمريض بمتبرعين أحياء', 'المستشفى التخصصي يحقق إنجازاً غير مسبوق عالمياً', 'تصدّر مستشفى الملك فيصل التخصصي ومركز الأبحاث عناوين الصحف بعد نجاحه في إجراء أول عملية زراعة كبد روبوتية بالكامل باستخدام فصّين من متبرعين أحياء. العملية، التي لم تشهد أي مضاعفات، تؤكد قدرة المستشفى على تقديم حلول مبتكرة في زراعة الأعضاء، مع تصنيفه ضمن الأوائل عالمياً في الرعاية الصحية.', '<p></p><p>نجح مستشفى الملك فيصل التخصصي ومركز الأبحاث في إجراء عملية زراعة كبد لمريض من متبرعين أحياء، باستخدام الجراحة الروبوتية بشكل كامل في مرحلتي استئصال الكبد من المتبرعين وزراعته للمريض، ويأتي هذا الإجراء ضمن سلسلة متقدمة من العمليات الروبوتية لزراعة الكبد التي نُفذت في المستشفى وتجاوز عددها 100 عملية.</p><p>ويُعد هذا التدخل الجراحي الأول من نوعه على مستوى العالم، إذ استلزمت حالة المريض الحصول على فصّين أيسرَين من الكبد من متبرعين حيّين من الأقارب، لضمان حجم كبدي كافٍ، مع الحفاظ في الوقت ذاته على حجم كبدي آمن لكل متبرع، ويُظهر هذا الإجراء قدرة مركز التميز لزراعة الأعضاء على تقديم حلول علاجية مصمّمة وفق خصوصية كل حالة عبر مسار روبوتي بالكامل، يشمل جراحات المتبرعين وزراعة الكبد للمتلقي، بما يوسّع نطاق ما يمكن إنجازه بأمان في زراعة الكبد من متبرعين أحياء.</p><p>وجاءت نتائج العملية إيجابية ودون تسجيل أي مضاعفات لكلٍ من المتبرعين والمتلقي؛ إذ غادر المتبرعان المستشفى في اليوم الثالث بعد الجراحة، فيما استقرت حالة المريض وخرج من العناية المركزة بعد سبعة أيام، قبل أن يستكمل فترة التنويم اللازمة للمتابعة الطبية والرعاية الداعمة خلال مرحلة التعافي.</p><p>وقال البروفيسور ديتر برورينغ، المدير التنفيذي لزراعة الأعضاء، إن هذا الإجراء يعكس التوسع المرحلي في استخدام الجراحة الروبوتية في زراعة الكبد، بالاستناد إلى خبرة تراكمية طويلة في هذا المجال، مؤكدًا أن توظيف التقنيات المتقدمة يهدف إلى دعم سلامة الجراحة، وتسريع التعافي، وتحسين جودة الحياة على المدى الطويل، مع التزام صارم بالحفاظ على سلامة المتبرعين في جميع مراحل العلاج.</p><p>يُذكر أن مستشفى الملك فيصل التخصصي ومركز الأبحاث صُنف الأول في الشرق الأوسط وأفريقيا، والـ 15عالميًا ضمن قائمة أفضل 250 مؤسسة رعاية صحية أكاديمية حول العالم لعام 2025، والعلامة التجارية الصحية الأعلى قيمة في المملكة والشرق الأوسط، وذلك بحسب "براند فاينانس" لعام 2024، كما أُدرج ضمن قائمة مجلة "نيوزويك" لأفضل مستشفيات العالم لعام 2025، وأفضل المستشفيات الذكية لعام 2026، وأفضل المستشفيات التخصصية لعام 2026 .</p>', 'saudi-health', 'كبسولة الصحية', NULL, '/objects/uploads/d668e2b3-b7ac-4a75-b128-3b26af50b4f7', NULL, 'أول زراعة كبد بروبوت عالمياً بمستشفى سعودي', 'مستشفى الملك فيصل ينجح بزراعة كبد بروبوت بالكامل. إنجاز طبي سعودي عالمي.', '{"زراعة كبد","الجراحة الروبوتية","مستشفى الملك فيصل","عمليات جراحية","طب سعودي",تخصصي,"إنجاز طبي"}', false, 'published', NULL, NULL, '2026-01-26 12:52:52.4', '2026-01-26 12:52:52.937871', '2026-01-26 12:52:52.937871');
INSERT INTO public.news VALUES ('d138bee0-3472-42aa-ab0f-29bdff408855', 'oP3ScZz', 'حديقة الفجر تحتضن مبادرة نبض الحي لتعزيز الصحة', 'أنشطة صحية وترفيهية لنشر الوقاية والوعي المجتمعي', 'أطلقت أمانة منطقة حائل مبادرة "نبض الحي" بحديقة الفجر بالتعاون مع مجموعة الأهلي الطبي، لتعزيز الصحة العامة ونشر الوقاية، عبر فحوصات مجانية للأطفال وأنشطة تفاعلية تهدف لتحسين جودة الحياة.', '<p>فعَّلت أمانة منطقة حائل مبادرة "نبض الحي" في حديقة الفجر، بالتعاون مع مجموعة الأهلي الطبي، وذلك ضمن جهودها المتواصلة لتعزيز الصحة العامة وبناء مجتمع حيوي، ونشر الوعي الصحي، وتقديم خدمات وقائية مباشرة لسكان الأحياء في مواقعهم الترفيهية.<br> وشهدت المبادرة تقديم عددٍ من الخدمات الصحية، من أبرزها قياس العلامات الحيوية للمشاركين؛ للإسهام في متابعة المؤشرات الصحية العامة وتعزيز مفاهيم الوقاية والكشف المبكر، إضافة إلى الكشف على أسنان الأطفال للاطمئنان على صحتهم الفموية، ورفع مستوى الوعي بأهمية العناية بالأسنان منذ الصغر.<br> وصاحب المبادرة تنظيم أنشطة تفاعلية موجهة للأطفال، شملت الرسم على الوجه؛ بهدف إيجاد أجواء إيجابية مشجعة على المشاركة، وربط الرسائل الصحية بتجربة ترفيهية ممتعة للأسرة والطفل.<br> وأكَّدت أمانة منطقة حائل أن مبادرة "نبض الحي" تأتي ضمن برامجها المجتمعية الهادفة إلى تفعيل الحدائق العامة كمساحات حيوية تخدم المجتمع، وتسهم في تعزيز التلاحم الاجتماعي، وتحويل المرافق الترفيهية إلى منصات للتوعية الصحية ونشر الثقافة الوقائية، إلى جانب تحفيز أفراد المجتمع على تبنّي أنماط حياة نشطة وصحية.<br> وتعكس المبادرة أهمية الشراكة الفاعلة بين القطاعين الحكومي والخاص في دعم المبادرات الصحية المجتمعية، وتقديم خدمات نوعية تسهم في رفع مستوى الوعي الصحي وتحسين جودة الحياة، انسجامًا مع مستهدفات رؤية المملكة 2030 الرامية إلى بناء مجتمع صحي وحيوي، وتعزيز الوقاية الصحية، وتوفير بيئة داعمة للرفاه وجودة الحياة في مدن المملكة.</p>', 'saudi-health', 'واس', NULL, '/objects/uploads/f76bd21c-cf83-4e02-abd9-489104748fca', NULL, 'مبادرة نبض الحي بحديقة الفجر لتحسين جودة الحياة', 'تعرف على مبادرة "نبض الحي" بحائل لتعزيز الصحة العامة ورفع الوعي الصحي عبر خدمات فريدة للأطفال وأنشطة ترفيهية مبتكرة.', '{"مبادرة نبض الحي","حديقة الفجر","الصحة العامة","الأهلي الطبي","وعي صحي","رؤية 2030","صحة الأطفال"}', false, 'published', NULL, NULL, '2026-01-26 13:17:22.718', '2026-01-26 13:17:23.232847', '2026-01-26 13:17:23.232847');
INSERT INTO public.news VALUES ('309bb8ea-e274-4617-82c0-fd2c30580ec2', 'eJt23LO', 'بعد 17 عاماً من الصبر والعلاج: 3 توائم يولدون بصحة جيدة', 'إنجاز طبي بمستشفى دله النخيل يحقق حلم الإنجاب لزوجين', 'فريق مستشفى دله النخيل ينجح في تحقيق حلم الإنجاب لزوجين بعد 17 عاماً من العقم، باستخدام عملية تلقيح مجهري مبتكرة. نتج الحمل بثلاثة أجنة بصحة ممتازة بعد متابعة دقيقة ورعاية متخصصة.', '<p>في إنجاز طبي جديد، تمكّن فريق مستشفى النساء والولادة دله النخيل بقيادة د. لمياء خليل – استشارية أمراض النساء والولادة والعقم - من مساعدة زوجين عانيا من العقم لمدة 17 عام نتيجة عوامل مشتركة لدى الزوج والزوجة، وذلك من خلال برنامج علاجي متكامل قائم على أحدث الممارسات الطبية.</p><p>بعد التقييم الدقيق للحالة، أُجريت عملية التلقيح المجهري، حيث تكللت بالنجاح من أول محاولة وأسفرت عن حدوث حمل بثلاثة أجنة.</p><p>خضعت المريضة لمتابعة طبية مكثفة ومنتظمة في مستشفى دله النخيل مبنى النساء والولادة ، مع تطبيق  متابعة دقيقة تهدف إلى الحد من احتمالية الولادة المبكرة. وبفضل الله ثم العناية الطبية المتخصصة واستخدام العلاجات المناسبة، تم تثبيت الحمل بنجاح والاستمرار به حتى الأسبوع الخامس والثلاثين من الحمل.</p><p>وفي الوقت المناسب، أجريت عملية ولادة ناجحة، نتج عنها ولادة ثلاثة أطفال ذكور بصحة جيدة ولله الحمد، وبأوزان طبيعية، دون الحاجة إلى إدخالهم إلى وحدة العناية المركزة لحديثي الولادة.</p><p>من خلال الجمع بين الخبرة الطبية والتقنيات الحديثة، جسد هذ الإنجاز نموذجا للتميّز الطبي الذي يقدمه مستشفى النساء والولادة دله النخيل للرعاية المتكاملة، تحقيقاً لأعلى معايير الجودة وسلامة الأم والمواليد.</p><p>يذكر بأن دلّه الصحية تقدّم خدماتها لأكثر من أربعة ملايين مراجع سنوياً من خلال شبكة واسعة من المستشفيات والعيادات التخصصية، بالإضافة إلى خدمات الرعاية المنزلية والطب الاتصالي. وبالاعتماد على فريق متمرس ونخبة من الأطباء المتخصصين، تعمل دلّه الصحية وفقاً لأعلى معايير الجودة وسلامة المرضى، وتحرص على القيم الإنسانية والمهنية التي جعلتها المرجع الأول للرعاية الصحية الموثوقة في المملكة.</p>', 'saudi-health', 'كبسولة الصحية ', NULL, '/objects/uploads/16b85b20-ede8-42d2-a1d4-b1e32713ffe3', NULL, 'إنجاز طبي بمستشفى دله: 3 توائم يولدون بصحة جيدة', 'مستشفى دله النخيل يحقق حلم الإنجاب لزوجين بعد 17 عاماً من العقم، بولادة 3 توائم بصحة ممتازة بفضل التقنيات الحديثة والمتابعة الدقيقة.', '{إنجاب,"مستشفى دله","التلقيح المجهري","إنجاز طبي",ولادة,"صحة الأم","الرعاية الصحية"}', false, 'published', NULL, NULL, '2026-01-26 17:52:16.3', '2026-01-26 17:52:26.213485', '2026-01-26 17:52:26.213485');
INSERT INTO public.news VALUES ('dfee1536-dea7-4d0a-8466-b227e55e6423', 'ukt86fu', 'تحقيق: آلام لقاح تكشف محكمة تعويضات صحية أمريكية', 'برنامج VICP يوفر حلولاً معقدة للإصابات النادرة', 'بعد لقاح في 2019، واجه الفتى كيثرون ألماً مزمناً كشف برنامج تعويض الإصابات النادرة المعروف بـ«محكمة اللقاحات» الذي أُنشئ عام 1986 لحماية الإمدادات ودعم المصابين.', '<p>بعد تلقي لقاح روتيني في 2019، شعر الفتى كيثرون توماس، وكان حينها في الحادية عشرة، بألم حاد في كتفه امتد إلى ذراعه. ظنّت والدته ميلاني بوستيك أن الألم سيزول خلال أيام، لكنه طال أسابيع ثم شهوراً وسنين. ومع تراكم الفواتير الطبية، اكتشفت برنامجاً اتحادياً للتعويض عن إصابات اللقاحات النادرة يُعرف باسم «محكمة اللقاحات».</p><p>أُنشئ <strong>برنامج تعويض إصابات اللقاح (VICP)</strong> عام <strong>1986</strong> بعد موجة دعاوى قضائية كادت تخرج مصنّعي اللقاحات من السوق. هدفه توفير مسار أسرع وأكثر سخاءً للتعويض عن الإصابات، مع حماية الإمدادات من خلال تحصين الشركات من جزء من المسؤولية القانونية. البرنامج ممول من دافعي الضرائب، والحكومة هي من تدفع تعويضات المستحقين ورسوم أتعاب محاميهم.</p><p>في 2022 قدّمت بوستيك مطالبة لتعويض تكاليف علاج ابنها. تواصلت مع «كارلسون لو فيرم» التي أحالتها إلى المحامي أندرو داونينغ في أريزونا—الذي أصبح لاحقاً كبير مستشاري <strong>وزير الصحة والخدمات الإنسانية روبرت ف. كينيدي الابن</strong>. وفق عقد اطّلعت عليه KFF Health News، تولّى داونينغ القضية وسلّمته بوستيك مستندات وتقارير طبية كما طلب.</p><p>لكن بعد أشهر من الانتظار وتبادل المذكرات، قال لها داونينغ إن الوقت حان للانسحاب من البرنامج ورفع دعوى مباشرة على الشركة المصنّعة. وعندما رفضت الانسحاب، تنحّى عن القضية. وبحسب سجلات المحكمة، دفعت الحكومة له <strong>445 دولاراً في الساعة</strong> مقابل تمثيلها—وهو أجر معتاد لمحامي البرنامج بخبرته—بينما تؤكد بوستيك أنها لم تحصل على أي تعويض حتى اليوم، وقد صار ابنها، الآن في الثامنة عشرة، يعاني ألماً مزمناً قد لا يزول أبداً.</p><p>داونينغ رفض التعليق، ووزارة الصحة والخدمات الإنسانية لم ترد على طلبات التعليق بشأن هذه القضية.</p><p>وفي يونيو، منحت الوزارة—برئاسة كينيدي—شركة داونينغ القانونية «برُويكنر سبِتلِر شيلتس» عقداً اتحادياً مباشراً للاستشارة في <strong>إعادة هيكلة برنامج VICP</strong>، ارتفعت قيمته إلى <strong>410 آلاف دولار</strong>. يُذكر أن داونينغ هو المحامي الوحيد على موقع الشركة الذي مارس فعلياً أمام «محكمة اللقاحات». كينيدي وصف البرنامج مراراً بأنه «معطّل»، معتبراً أنه يحمي الشركات «مهما بلغت درجة الإهمال»، وهو محامٍ للتعويضات قاد سابقاً دعاوى مدنية ضد «ميرك».</p><p>وتُظهر مراجعة سجلات المحاكم وبيانات البرنامج التي أجرتها KFF Health News أن داونينغ ونحو عشرات من المحامين نقلوا <strong>مئات</strong> الملفات من «محكمة اللقاحات» إلى القضاء المدني، حيث تبدو المكاسب المحتملة أكبر للمرضى ومحاميهم. وفي الوقت نفسه، تقاضوا <strong>ملايين الدولارات</strong> من أتعاب ممولة حكومياً ضمن «محكمة اللقاحات»، بينما يدفعون نحو ما صُمم البرنامج أصلاً لتجنبه: دعاوى مباشرة ضد مصنّعي اللقاحات.</p><p>يرى خبراء أن هذا التحوّل في الاستراتيجية يعزز حملة كينيدي ضد «ميرك»، وقد يلحق الضرر ببعض المصابين. تقول دوريت رايس، أستاذة القانون بجامعة كاليفورنيا في سان فرانسيسكو والتي درست «محكمة اللقاحات» لأكثر من عقد وتتبع صعود التيارات المناهضة للتطعيم في السياسة الأمريكية، إن المحامين الذين يجمعون بين العمل في البرنامج ومقاضاة الشركات «لديهم حوافز لتوجيه مزيد من الناس» إلى الدعاوى المدنية «حتى عندما لا يكون ذلك في مصلحتهم».</p><p>بالنسبة لبوستيك، انتهت مطالبتها في «محكمة اللقاحات» بالرفض. وتقول بغضب إن الأموال المدفوعة لأتعاب محاميها كان الأولى أن تُصرف لعلاج ابنها: «كان ينبغي أن تذهب تلك الأموال إلى ابني… كيف تجرؤون؟»</p><p>المادة مستندة إلى تقرير KFF Health News.</p>', 'health-reports', 'KFF Health News', 'https://kffhealthnews.org/news/article/vicp-vaccine-court-cases-moved-lawsuits-lawyers-merck-hpv-rfk-allies-hhs/', '/objects/uploads/cc639f44-1120-4461-be7a-35084eaa3a8e.jpg', NULL, 'كيف تعمل المحكمة الأمريكية لتعويض إصابات اللقاحات؟', 'ألم دائم بسبب لقاح يثير التساؤلات حول برنامج تعويضات الإصابات النادرة، المعروف باسم «محكمة اللقاحات»، ومسيرة تحقيق العدالة الصحية.', '{"محكمة اللقاحات","تعويض الإصابات الصحية","برنامج VICP","الألم المزمن","الحماية الصحية","إصابات اللقاحات","كيثرون توماس"}', false, 'published', NULL, NULL, '2026-01-31 08:14:08.963339', '2026-01-31 08:14:08.963339', '2026-01-31 08:14:08.963339');
INSERT INTO public.news VALUES ('544e9f0e-cff8-4f00-9f65-b83673419de8', NULL, 'فاتورة مفاجئة تكشف خطأً أسقط تأمين أطفال رجل إطفاء', NULL, NULL, '<p>بعد وفاة زوجها عام 2018، واصلت سوزانا ريد-مكولو وزوجتاها الصغيرتان الاستفادة من التأمين الصحي عبر جهة عمله كرجل إطفاء في ولاية ماريلاند. لكن في عام 2024 تلقت سوزانا فاتورة غير متوقعة بقيمة <strong>377 دولاراً</strong> مقابل كشف روتيني لإحدى ابنتيها في خريف العام السابق.</p><p>اتصلت سوزانا بقسم الفوترة لدى الطبيب لتكتشف أن شركة التأمين <strong>أسقطت تغطية الطفلتين بالخطأ</strong>. وبينما تأكد لاحقاً أن الأمر مجرد خلل إداري، اضطرت الأم للتنقل بين قسم الموارد البشرية في جهة عمل زوجها الراحل وشركة التأمين لتصحيح الوضع، وسط قلق حقيقي من بقاء ابنتيها من دون تأمين.</p><p>القصة تندرج ضمن سلسلة "رعاية مكلفة" التي تنتجها InvestigateTV وKFF Health News، والتي تسلط الضوء على كيف يمكن للأخطاء الإدارية أن تترك المرضى أمام فواتير لا ينبغي أن يدفعوها، مع خيارات محدودة لتصحيح مشكلات لم يتسببوا بها.</p><p>وفي حديثها للسلسلة، قالت إليزابيث روزنثال، كبيرة المحررين المشاركين في KFF Health News، إن إسقاط التغطية بالخطأ يعد <strong>"مشكلة شائعة"</strong> تستدعي اهتمام الجهات التنظيمية في الولايات. وأضافت: "الناس يخطئون، والأنظمة تخطئ، ويجب تحميلهم المسؤولية عن ذلك، لا المريض".</p><p>توضح هذه الحالة أن خللاً بسيطاً في الأنظمة يمكن أن ينعكس بتبعات مالية ونفسية كبيرة على الأسر، وتعيد طرح السؤال حول دور الرقابة والتنظيم في حماية حقوق المؤمن عليهم ومنع تكرار مثل هذه الثغرات.</p>', 'health-reports', NULL, 'https://kffhealthnews.org/news/article/watch-costly-care-checkup-surprise-bill-line-of-duty-health-insurance-benefits-children/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/investigate-tv-uninsured-firefighter-surprise-bill.jpg?w=1024', NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2026-01-29 13:48:13.805224', '2026-01-29 13:48:13.805224', '2026-01-29 13:48:13.805224');
INSERT INTO public.news VALUES ('45207944-3872-429b-a30b-e06e826b0df5', NULL, 'فاتورة مفاجئة تكشف خطأً أسقط تأمين أطفال رجل إطفاء', NULL, NULL, '<p>بعد وفاة زوجها عام 2018، واصلت سوزانا ريد-مكولو وزوجتاها الصغيرتان الاستفادة من التأمين الصحي عبر جهة عمله كرجل إطفاء في ولاية ماريلاند. لكن في عام 2024 تلقت سوزانا فاتورة غير متوقعة بقيمة <strong>377 دولاراً</strong> مقابل كشف روتيني لإحدى ابنتيها في خريف العام السابق.</p><p>اتصلت سوزانا بقسم الفوترة لدى الطبيب لتكتشف أن شركة التأمين <strong>أسقطت تغطية الطفلتين بالخطأ</strong>. وبينما تأكد لاحقاً أن الأمر مجرد خلل إداري، اضطرت الأم للتنقل بين قسم الموارد البشرية في جهة عمل زوجها الراحل وشركة التأمين لتصحيح الوضع، وسط قلق حقيقي من بقاء ابنتيها من دون تأمين.</p><p>القصة تندرج ضمن سلسلة "رعاية مكلفة" التي تنتجها InvestigateTV وKFF Health News، والتي تسلط الضوء على كيف يمكن للأخطاء الإدارية أن تترك المرضى أمام فواتير لا ينبغي أن يدفعوها، مع خيارات محدودة لتصحيح مشكلات لم يتسببوا بها.</p><p>وفي حديثها للسلسلة، قالت إليزابيث روزنثال، كبيرة المحررين المشاركين في KFF Health News، إن إسقاط التغطية بالخطأ يعد <strong>"مشكلة شائعة"</strong> تستدعي اهتمام الجهات التنظيمية في الولايات. وأضافت: "الناس يخطئون، والأنظمة تخطئ، ويجب تحميلهم المسؤولية عن ذلك، لا المريض".</p><p>توضح هذه الحالة أن خللاً بسيطاً في الأنظمة يمكن أن ينعكس بتبعات مالية ونفسية كبيرة على الأسر، وتعيد طرح السؤال حول دور الرقابة والتنظيم في حماية حقوق المؤمن عليهم ومنع تكرار مثل هذه الثغرات.</p>', 'health-reports', NULL, 'https://kffhealthnews.org/news/article/watch-costly-care-checkup-surprise-bill-line-of-duty-health-insurance-benefits-children/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/investigate-tv-uninsured-firefighter-surprise-bill.jpg?w=1024', NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2026-01-29 13:48:12.650426', '2026-01-29 13:48:12.650426', '2026-01-29 13:48:12.650426');
INSERT INTO public.news VALUES ('41895146-dbb3-47a8-81c5-a59537bced8b', '07c60b3', 'تطوير جهاز ذكي لمراقبة السكر في الدم بدون وخز', NULL, 'شركة أبل تعلن عن تقنية جديدة لقياس السكر من خلال الساعة الذكية.', 'أعلنت شركة أبل عن تطوير تقنية ثورية لقياس مستوى السكر في الدم باستخدام أشعة الليزر دون الحاجة لوخز الإصبع.

التقنية الجديدة ستكون متاحة في الجيل القادم من ساعة أبل. هذا التطور سيغير حياة ملايين مرضى السكري حول العالم.', 'health-news', 'أبل', 'https://www.apple.com', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-25 00:00:00', '2026-01-24 13:59:54.361223', '2026-01-24 13:59:54.361223');
INSERT INTO public.news VALUES ('a1dec70a-9aeb-4cb0-bd39-70b91f8072c2', '0417a6c', 'فوائد الصيام المتقطع: دراسة علمية شاملة', NULL, 'دراسة جديدة تكشف فوائد الصيام المتقطع على الصحة العامة وإنقاص الوزن.', 'أظهرت دراسة حديثة أن الصيام المتقطع له فوائد صحية متعددة تشمل:

- تحسين حساسية الأنسولين
- تقليل الالتهابات
- تحسين صحة القلب
- تعزيز وظائف الدماغ

الباحثون يوصون بالصيام 16 ساعة والأكل خلال 8 ساعات.', 'nutrition', 'جامعة كامبريدج', 'https://www.cam.ac.uk', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-23 00:00:00', '2026-01-24 13:59:54.452222', '2026-01-24 13:59:54.452222');
INSERT INTO public.news VALUES ('cfe583ae-ac98-4c43-96f4-82f1407910c2', '72bfaab', 'فوائد الشاي الأخضر: 10 أسباب لشربه يومياً', NULL, 'دراسات علمية تؤكد الفوائد الصحية المتعددة للشاي الأخضر.', 'أكدت دراسات علمية متعددة فوائد الشاي الأخضر الصحية:

1. مضاد للأكسدة
2. يعزز الأيض
3. يحسن صحة الدماغ
4. يقلل خطر السرطان
5. يحسن صحة الفم
6. يساعد في إنقاص الوزن
7. يقلل الكوليسترول
8. يحسن صحة الجلد
9. يقوي المناعة
10. يحسن المزاج

ينصح بشرب 3-5 أكواب يومياً.', 'nutrition', 'مجلة التغذية الأمريكية', 'https://www.nutrition.org', NULL, NULL, NULL, NULL, NULL, false, 'deleted', NULL, NULL, '2025-10-19 00:00:00', '2026-01-24 13:59:54.634385', '2026-01-24 13:59:54.634385');
INSERT INTO public.news VALUES ('8c172c09-0dd7-4bf0-b6a8-4ce2b19d1696', '0ac1d74', 'كم بيضة يمكن تناولها يومياً دون ضرر؟ واحدة تكفي!', NULL, 'كبسولة الصحية &#8211;  ديلي ميل حدد خبراء الصحة وأطباء القلب الكمية الآمنة لتناول البيض بيضة كاملة واحدة يومياً للأشخاص الأصحاء، مع التحذير من أن الخطر الحقيقي لا يكمن في الكوليسترول الموجود داخل البيضة نفسها، بل في &#8220;الدهون المشبعة&#8221; المصاحبة لها في الطبق أو المستخدمة في القلي. وأوضح الخب', '<p>كبسولة الصحية &#8211;  ديلي ميل</p>
<p>حدد خبراء الصحة وأطباء القلب الكمية الآمنة لتناول البيض بيضة كاملة واحدة يومياً للأشخاص الأصحاء، مع التحذير من أن الخطر الحقيقي لا يكمن في الكوليسترول الموجود داخل البيضة نفسها، بل في &#8220;الدهون المشبعة&#8221; المصاحبة لها في الطبق أو المستخدمة في القلي. وأوضح الخبراء أن تناول بيضة واحدة يومياً لا يرفع خطر الإصابة بالنوبات القلبية، شريطة الانتباه للمكونات الأخرى مثل الزبدة واللحوم المصنعة.</p>
<p>تؤثر الدهون المشبعة بشكل مباشر على ارتفاع الكوليسترول الضار (LDL) وتراكم الترسبات في الشرايين، وهو ما يفوق تأثير الكوليسترول الغذائي المتوفر في البيض. وتعد هذه المعلومة ضرورية لمرضى السكري والقلب، حيث يُنصحون بعدم تجاوز أربع صفارات بيض أسبوعياً، خاصة وأن طريقة التحضير (مثل السلق أو القلي في مقلاة غير لاصقة) تلعب دوراً حاسماً في الحفاظ على صحة الأوعية الدموية.</p>
<p>ينصح خبراء التغذية بالتركيز على &#8220;إجمالي الدهون&#8221; في الوجبة بدلاً من عد حبات البيض فقط، واستبدال الإضافات الدهنية مثل السجق والجبن بالخضراوات الطازجة. ويتجه التوجه الطبي الحالي نحو تشجيع البروتينات النباتية والمأكولات البحرية كبدائل جزئية، مع التأكيد على أن الاعتدال في تناول البيض يمنح الجسم عناصر حيوية مثل &#8220;الكولين واللوتين&#8221; دون تهديد سلامة القلب.</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/32e8a13f-b9b1-48e0-b7d3-ad2f26638755.png', 'كم بيضة يمكن تناولها يومياً دون ضرر؟ واحدة تكفي!', 'كم بيضة يمكن تناولها يومياً دون ضرر؟ واحدة تكفي!', 'كبسولة الصحية &#8211;  ديلي ميل حدد خبراء الصحة وأطباء القلب الكمية الآمنة لتناول البيض بيضة كاملة واحدة يومياً للأشخاص الأصحاء، مع التحذير من أن الخطر الحقيقي ', '{البيض,"الصحة العامة",الكوليسترول}', false, 'published', NULL, NULL, '2026-01-24 01:17:42', '2026-01-24 16:23:14.105652', '2026-01-24 16:23:14.105652');
INSERT INTO public.news VALUES ('bd6b0e5d-5397-4891-9d6c-89a7e676a2e1', '9dc2f05', 'الشاي الأخضر أم الأسود.. أيهما يمنح جسمك حماية أكبر؟', NULL, 'كبسولة الصحية &#8211; تايمز ناو كشفت مقارنة طبية حديثة عن تباينات جوهرية في الفوائد الصحية بين الشاي الأخضر والأسود، فرغم اشتراكهما في احتواء &#8220;الفلافونويدات&#8221; المضادة للالتهابات، إلا أن الشاي الأسود يتفوق في حماية القلب وخفض خطر السكتة الدماغية، بينما يتميز الشاي الأخضر بقدرة أكبر على خفض', '<p><strong>كبسولة الصحية &#8211; تايمز ناو</strong></p>
<p>كشفت مقارنة طبية حديثة عن تباينات جوهرية في الفوائد الصحية بين الشاي الأخضر والأسود، فرغم اشتراكهما في احتواء &#8220;الفلافونويدات&#8221; المضادة للالتهابات، إلا أن الشاي الأسود يتفوق في حماية القلب وخفض خطر السكتة الدماغية، بينما يتميز الشاي الأخضر بقدرة أكبر على خفض ضغط الدم وتحسين الوظائف الإدراكية للدماغ بفضل مركب &#8220;إيبيجالوكاتشين&#8221;. ووفقاً لما نقله موقع &#8220;تايمز ناو&#8221;، فإن الاختلاف في طريقة المعالجة يجعل الشاي الأسود مصدراً أعلى للكافيين (50 ملجم) مقارنة بالأخضر (30 ملجم).</p>
<p>تكمن أهمية هذه المفاضلة في اختيار المشروب المناسب للحالة الصحية؛ فالشاي الأخضر يعد خياراً مثالياً للوقاية من السرطان وتأخير الشيخوخة وأمراض الكبد، بينما يعمل الشاي الأسود كدرع لحماية الخلايا الدهنية وتعزيز اليقظة بتركيزات أعلى من الكافيين. ومع ذلك، يحذر الخبراء من أن الإفراط في كلا النوعين (أكثر من 4 أكواب يومياً) قد يقلب الفوائد إلى أضرار، مسبباً القلق، الأرق، وتهيج المعدة، بالإضافة إلى احتمالية تداخله مع أدوية ضغط الدم ومضادات التخثر.</p>
<p>ينصح الأطباء بالاعتدال في شرب الشاي وتغيير النوع بناءً على الحاجة الجسدية، مع التنبيه على ضرورة الحذر من اصفرار الأسنان الناتج عن التصبغات.</p>
<p>ويبقى الخيار النهائي رهيناً بالتفضيل الشخصي والمذاق، حيث يوفر كلاهما حمض &#8220;الثيانين&#8221; الأميني الذي يعزز صحة الدماغ، مما يجعل الجمع بينهما في نظام غذائي متوازن وسيلة فعالة لتنويع مضادات الأكسدة التي يحتاجها الجسم لمقاومة الأمراض الفيروسية والعصبية.</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/abe74d80-d3e6-4a6f-a88b-a3addae3c637.webp', 'الشاي الأخضر أم الأسود.. أيهما يمنح جسمك حماية أكبر؟', 'الشاي الأخضر أم الأسود.. أيهما يمنح جسمك حماية أكبر؟', 'كبسولة الصحية &#8211; تايمز ناو كشفت مقارنة طبية حديثة عن تباينات جوهرية في الفوائد الصحية بين الشاي الأخضر والأسود، فرغم اشتراكهما في احتواء &#8220;الفلافونويد', '{"السكتة الدماغية","الشاي الأحمر","الشاي الأخضر","ضغط الدم"}', false, 'published', NULL, NULL, '2026-01-23 03:18:11', '2026-01-24 16:23:17.874859', '2026-01-24 16:23:17.874859');
INSERT INTO public.news VALUES ('4534d226-97f1-44ae-baf6-019c22dd5f2d', '8b70626', 'متى يصبح شرب القهوة آمناً للأطفال؟', NULL, 'متابعة – كبسولة الصحية كشفت الدكتورة داريا روساكوفا، خبيرة التغذية، عن السن القانونية والمناسبة لبدء تناول القهوة، محذرة من تقديمها للأطفال دون سن السابعة. ووفقاً لما نقلته (آر تي)، فإن الجهاز العصبي للطفل في هذه المرحلة لا يكون مكتملاً، مما يجعل الكافيين محفزاً قوياً لفرط النشاط، وعدم الاستقرار الع', '<p>متابعة – كبسولة الصحية</p>
<p>كشفت الدكتورة داريا روساكوفا، خبيرة التغذية، عن السن القانونية والمناسبة لبدء تناول القهوة، محذرة من تقديمها للأطفال دون سن السابعة. ووفقاً لما نقلته (آر تي)، فإن الجهاز العصبي للطفل في هذه المرحلة لا يكون مكتملاً، مما يجعل الكافيين محفزاً قوياً لفرط النشاط، وعدم الاستقرار العاطفي، واضطرابات النوم الحادة، مما يتطلب تجنبها نهائياً قبل هذا العمر.</p>
<p>تكمن أهمية هذا التحذير في الحساسية العالية لأجهزة الطفل الحيوية تجاه الكافيين؛ حيث يؤدي شرب القهوة إلى إجهاد القلب والجهاز البولي، ورفع ضغط الدم بشكل قد لا يتحمله جسم الطفل. كما شددت الخبيرة على ضرورة الامتناع التام في حال وجود مشكلات في الكلى أو التهابات في المعدة، لأن القهوة قد تسبب تهيجاً حاداً في البطانة المعدية، خاصة إذا تم تناولها على معدة فارغة.</p>
<p>يُسمح للأطفال فوق سن السابعة الذين لا يعانون من مشاكل صحية بتناول كميات صغيرة ومخففة بالحليب أو الكريمة، بمعدل لا يتجاوز 2.5 ملغ من الكافيين لكل كيلوغرام من وزن الطفل يومياً. وينصح الأطباء بالالتزام بهذه الجرعة الآمنة لتحسين الوظائف الإدراكية دون الإضرار بنمو الطفل، مع التأكيد على ضرورة مراعاة الحالة الصحية العامة والامتناع الفوري في حال لاحظ الأهل زيادة في التوتر أو صعوبة في النوم.</p>
<p>&nbsp;</p>
<p>&nbsp;</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/9fd6d1ad-a8e1-4bd6-8724-d9dab374dffc.jpg', 'متى يصبح شرب القهوة آمناً للأطفال؟', 'متى يصبح شرب القهوة آمناً للأطفال؟', 'متابعة – كبسولة الصحية كشفت الدكتورة داريا روساكوفا، خبيرة التغذية، عن السن القانونية والمناسبة لبدء تناول القهوة، محذرة من تقديمها للأطفال دون سن السابعة. ووفق', '{الأطفال,القهوة}', false, 'published', NULL, NULL, '2026-01-23 03:08:45', '2026-01-24 16:23:19.349993', '2026-01-24 16:23:19.349993');
INSERT INTO public.news VALUES ('5b63175e-6907-4e8b-9920-bcb23b575868', '63a23ee', 'خرافة "هرمونات الأنوثة".. "عش بصحة" تبرئ الصويا وتكشف الخطر الحقيقي', NULL, 'متابعة – كبسولة الصحية حسمت منصة &#8220;عش بصحة&#8221; الجدل المثار حول منتجات الصويا، مؤكدة أن الأبحاث العلمية أثبتت أن استهلاكها المعتاد آمن تماماً ولا يؤثر على خصوبة الرجال أو مستويات هرمون الأنوثة لديهم. وبددت المنصة المخاوف المنتشرة، موضحة أن الصويا لا تغير من طبيعة هرمونات الرجل بغض النظر عن ك', '<p>متابعة – كبسولة الصحية</p>
<p>حسمت منصة &#8220;عش بصحة&#8221; الجدل المثار حول منتجات الصويا، مؤكدة أن الأبحاث العلمية أثبتت أن استهلاكها المعتاد آمن تماماً ولا يؤثر على خصوبة الرجال أو مستويات هرمون الأنوثة لديهم.</p>
<p>وبددت المنصة المخاوف المنتشرة، موضحة أن الصويا لا تغير من طبيعة هرمونات الرجل بغض النظر عن كمية أو مدة تناولها، لتضع حداً لشائعة قديمة طالما أثارت القلق في المجتمع.</p>
<p>تكمن أهمية هذا التوضيح في نقل تركيز الناس من &#8220;خرافة&#8221; إلى &#8220;حقيقة&#8221; صحية هامة؛ فالمشكلة ليست في الصويا كبروتين، بل في &#8220;الاعتدال&#8221;. وحذرت المنصة من أن الخطر الحقيقي يكمن في &#8220;الصويا المصنعة&#8221; التي تحتوي على كميات عالية جداً من الصوديوم (الأملاح) والألوان الاصطناعية التي قد تضر بالصحة العامة، وليس في تأثيرها الهرموني المزعوم.</p>
<p>هذا التصحيح يدفعنا كمجتمع إلى إعادة النظر في عاداتنا الغذائية، والتركيز على قراءة محتويات الأطعمة بدلاً من الانسياق وراء الشائعات. واستراتيجياً، يبرز دور المنصات الوطنية مثل &#8220;عش بصحة&#8221; في حماية الوعي العام؛ فالمرحلة القادمة تتطلب تكثيف الرقابة على الأغذية &#8220;المصنعة&#8221; التي تغرق الأسواق بنسب صوديوم عالية تهدد برفع معدلات ضغط الدم، مع التأكيد على أن الاعتدال هو الأساس دائماً لضمان صحة مستدامة للجميع.</p>
<p>&nbsp;</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/06a07663-e49f-4e7d-9c14-da83b2cc112e.webp', 'خرافة &#8220;هرمونات الأنوثة&#8221;.. &#8220;عش بصحة&#8221; تبرئ الصويا وتكشف الخطر الحقيقي', 'خرافة &#8220;هرمونات الأنوثة&#8221;.. &#8220;عش بصحة&#8221; تبرئ الصويا وتكشف الخطر الحقيقي', 'متابعة – كبسولة الصحية حسمت منصة &#8220;عش بصحة&#8221; الجدل المثار حول منتجات الصويا، مؤكدة أن الأبحاث العلمية أثبتت أن استهلاكها المعتاد آمن تماماً ولا يؤثر ع', '{"عِش بصحة","منتجات الصويا","هرمونات الأنوثة"}', false, 'published', NULL, NULL, '2026-01-22 04:42:36', '2026-01-24 16:23:23.077361', '2026-01-24 16:23:23.077361');
INSERT INTO public.news VALUES ('7a3c5684-d887-4a41-a841-5fafc7880dfa', 'c0939e2', ' الذهب الأحمر.. ترياق الذاكرة وتوازن الأعصاب ', NULL, 'متابعة – كبسولة الصحية كشفت دراسة علمية حديثة أن مستخلص نبات الزعفران يحتوي على مركبات نشطة مثل السافرنال والكروسين التي تعمل بفاعلية على دعم خلايا الدماغ وتحسين الذاكرة وتخفيف مستويات القلق، بالإضافة إلى دورها في تنظيم عملية التمثيل الغذائي وحماية الكبد من اضطرابات الدهون المرتبطة بالتقدم في العمر.', '<p><strong>متابعة – كبسولة الصحية</strong></p>
<p>كشفت دراسة علمية حديثة أن مستخلص نبات الزعفران يحتوي على مركبات نشطة مثل السافرنال والكروسين التي تعمل بفاعلية على دعم خلايا الدماغ وتحسين الذاكرة وتخفيف مستويات القلق، بالإضافة إلى دورها في تنظيم عملية التمثيل الغذائي وحماية الكبد من اضطرابات الدهون المرتبطة بالتقدم في العمر. وتكمن أهمية هذه النتائج في قدرة الزعفران على إعادة تنظيم الجزيئات الإشارية في الدماغ المسؤولة عن التوتر والمرونة العصبية، مما يجعله مرشحاً واعداً كدعم غذائي لمواجهة تدهور الوظائف الإدراكية واضطرابات المزاج المرتبطة بالشيخوخة ومرض باركنسون.</p>
<p>وينتظر العلماء حالياً نقل هذه التجارب من المختبرات إلى المرحلة السريرية على البشر لتحديد الجرعات الدقيقة، وسط توقعات بدخوله كعنصر أساسي في المكملات الغذائية المعتمدة لدعم الصحة النفسية والتمثيل الغذائي.</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/a7961cd8-51ed-419f-9134-38f31a84905c.jpg', ' الذهب الأحمر.. ترياق الذاكرة وتوازن الأعصاب ', ' الذهب الأحمر.. ترياق الذاكرة وتوازن الأعصاب ', 'متابعة – كبسولة الصحية كشفت دراسة علمية حديثة أن مستخلص نبات الزعفران يحتوي على مركبات نشطة مثل السافرنال والكروسين التي تعمل بفاعلية على دعم خلايا الدماغ وتحسي', '{الأعصاب,الذاكرة,الزعفران}', false, 'published', NULL, NULL, '2026-01-21 01:29:26', '2026-01-24 16:23:27.179135', '2026-01-24 16:23:27.179135');
INSERT INTO public.news VALUES ('7983c7b9-53c5-4c9b-acc3-cb704b68984e', 'ba8f475', 'كيمياء الاسترخاء: "ببتيدات الجوز" والثيانين خيار واعد لعلاج أرق الإجهاد المزمن', NULL, 'موسكو- كبسولة الصحية كشفت دراسة طبية حديثة أن مزيجاً من ببتيدات الجوز وحمض &#8220;الثيانين&#8221; الأميني يساهم بشكل فعال في تحسين جودة النوم ومكافحة حالات الإرهاق المزمن. وأظهرت التجارب السريرية والمخبرية أن هذا المزيج لا يكتفي بتنظيم ساعات النوم فحسب، بل يزيد من نسبة &#8220;النوم العميق&#8221; عبر', '<p>موسكو- كبسولة الصحية</p>
<p>كشفت دراسة طبية حديثة أن مزيجاً من ببتيدات الجوز وحمض &#8220;الثيانين&#8221; الأميني يساهم بشكل فعال في تحسين جودة النوم ومكافحة حالات الإرهاق المزمن. وأظهرت التجارب السريرية والمخبرية أن هذا المزيج لا يكتفي بتنظيم ساعات النوم فحسب، بل يزيد من نسبة &#8220;النوم العميق&#8221; عبر خفض مستويات هرمون التوتر (الكورتيكوستيرون)، وتنظيم الكيمياء العصبية المسؤولة عن الاسترخاء مثل حمض &#8220;غاما-أمينوبيوتيريك&#8221; (GABA) والتريبتوفان الضروري لتخليق الميلاتونين.</p>
<p>وأثبت الباحثون أن هذا التأثير المزدوج للمكملات الغذائية يوفر وسيلة آمنة لتحسين الصحة النفسية والبدنية للأشخاص الذين يعانون من ضغوط مستمرة، حيث يعمل الجوز كمضاد أكسدة طبيعي يحمي الأعصاب ويقلل الالتهابات الحيوية.</p>
<p>ويمثل هذا الاكتشاف ركيزة في &#8220;السيادة الصحية&#8221; القائمة على الاستفادة من المكونات الطبيعية والحلول الغذائية لتقليل الاعتماد على العقاقير الكيميائية المنومة؛ إذ إن تحسين جودة النوم يرفع من كفاءة القوة البشرية وإنتاجيتها، ويقلل من الأعباء الاقتصادية المرتبطة بأمراض التوتر المزمن، مما يعزز استدامة العافية المجتمعية والقدرة على مواجهة متطلبات الحياة العصرية بكفاءة وذهن متوقد.</p>
<p>&nbsp;</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/18dd3b75-f836-4b97-83dd-55a853a0f019.jpg', 'كيمياء الاسترخاء: &#8220;ببتيدات الجوز&#8221; والثيانين خيار واعد لعلاج أرق الإجهاد المزمن', 'كيمياء الاسترخاء: &#8220;ببتيدات الجوز&#8221; والثيانين خيار واعد لعلاج أرق الإجهاد المزمن', 'موسكو- كبسولة الصحية كشفت دراسة طبية حديثة أن مزيجاً من ببتيدات الجوز وحمض &#8220;الثيانين&#8221; الأميني يساهم بشكل فعال في تحسين جودة النوم ومكافحة حالات الإر', '{الإرهاق,الجوز}', false, 'published', NULL, NULL, '2026-01-19 00:26:34', '2026-01-24 16:23:33.960473', '2026-01-24 16:23:33.960473');
INSERT INTO public.news VALUES ('6e748699-e97a-4b55-b8f8-91c89cc1931e', '109558d', 'صيدلية المطبخ: 10 أطعمة تحارب الاكتئاب وترفع هرمونات السعادة', NULL, 'القاهرة- كبسولة الصحية كشف خبراء تغذية أن نوعية الطعام تلعب دوراً محورياً يتجاوز الصحة الجسدية ليصل إلى ضبط الحالة المزاجية ومحاربة الخمول، مؤكدين أن بعض &#8220;الأغذية الخارقة&#8221; تعمل كمنشطات طبيعية للدماغ. وتصدرت الأسماك الدهنية كالسلمون القائمة بفضل أحماض &#8220;أوميغا-3&#8221; التي تحسن إشار', '<p>القاهرة- كبسولة الصحية</p>
<p>كشف خبراء تغذية أن نوعية الطعام تلعب دوراً محورياً يتجاوز الصحة الجسدية ليصل إلى ضبط الحالة المزاجية ومحاربة الخمول، مؤكدين أن بعض &#8220;الأغذية الخارقة&#8221; تعمل كمنشطات طبيعية للدماغ. وتصدرت الأسماك الدهنية كالسلمون القائمة بفضل أحماض &#8220;أوميغا-3&#8221; التي تحسن إشارات هرموني السيروتونين والدوبامين، تليها الشوكولاتة الداكنة الغنية بمضادات الأكسدة، والأطعمة المخمّرة (كالزبادي) التي تعزز صحة الدماغ عبر تحسين بكتيريا الجهاز الهضمي.</p>
<p>وشملت القائمة خيارات متنوعة مثل بذور اليقطين الغنية بالمغنيسيوم المحارب للقلق، والتوت الذي يحتوي على مضادات اكتئاب طبيعية، والأفوكادو والمشروم اللذين يدعمان وظائف الدماغ بفيتامينات ومعادن نادرة.</p>
<p>ويمثل هذا التوجه نحو &#8220;التغذية النفسية&#8221; ركيزة استراتيجية في رفع جودة الحياة وتقليل الاعتماد على العقاقير؛ فبناء نظام غذائي واعي يساهم في تعزيز المناعة النفسية للمجتمع وزيادة إنتاجية الأفراد عبر حمايتهم من تقلبات المزاج والإرهاق المزمن، مما يحول مائدة الطعام إلى خط دفاع أول لصون الصحة العقلية والبدنية في آن واحد.</p>
<p>&nbsp;</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/005b6cfa-add9-40fe-a534-7c004afca67c.webp', 'صيدلية المطبخ: 10 أطعمة تحارب الاكتئاب وترفع هرمونات السعادة', 'صيدلية المطبخ: 10 أطعمة تحارب الاكتئاب وترفع هرمونات السعادة', 'القاهرة- كبسولة الصحية كشف خبراء تغذية أن نوعية الطعام تلعب دوراً محورياً يتجاوز الصحة الجسدية ليصل إلى ضبط الحالة المزاجية ومحاربة الخمول، مؤكدين أن بعض &#8220', '{"الأسماك الدهنية","الشوكولاتة الداكنة"}', false, 'published', NULL, NULL, '2026-01-19 00:18:17', '2026-01-24 16:23:34.632574', '2026-01-24 16:23:34.632574');
INSERT INTO public.news VALUES ('70b8b95a-06bc-4d18-b35f-108c7e150a2e', 'e986135', 'خسارة الفائدة.. 5 مكملات غذائية يمنع تناولها مع قهوة الصباح', NULL, 'نيويورك- كبسولة الصحية حذر خبراء صحة من أن تناول القهوة الصباحية تزامناً مع بعض المكملات الغذائية قد يقلل من فعاليتها بشكل كبير أو يسبب آثاراً جانبية مزعجة. وأوضح الدكتور كاران راجان أن القهوة غنية بمركبات &#8220;البوليفينول&#8221; التي ترتبط بالحديد والزنك في الجهاز الهضمي وتصعّب امتصاصهما، مما يست', '<p>نيويورك- كبسولة الصحية</p>
<p>حذر خبراء صحة من أن تناول القهوة الصباحية تزامناً مع بعض المكملات الغذائية قد يقلل من فعاليتها بشكل كبير أو يسبب آثاراً جانبية مزعجة. وأوضح الدكتور كاران راجان أن القهوة غنية بمركبات &#8220;البوليفينول&#8221; التي ترتبط بالحديد والزنك في الجهاز الهضمي وتصعّب امتصاصهما، مما يستوجب الفصل بينهما بساعتين على الأقل. كما أشار الخبراء إلى أن الكافيين يعمل كمدر للبول، مما يزيد من فقدان الكالسيوم والمغنيسيوم وفيتامين &#8220;ب 1&#8221; عبر البول، وهو ما قد يؤدي لنقص هذه العناصر لدى الأشخاص الذين يستهلكون القهوة بكميات كبيرة.</p>
<p>وتمثل هذه التوصيات ركيزة في &#8220;الوعي الغذائي الذكي&#8221;؛ حيث أن الجهل بتوقيت تناول المكملات يؤدي إلى هدر مالي وصحي وتراجع في كفاءة الجسم الوظيفية.</p>
<p>إن الحفاظ على فوارق زمنية بين المنبهات والمكملات يضمن الاستفادة القصوى من العناصر الحيوية، مما يدعم مناعة المجتمع وقدرته على استثمار الموارد الدوائية والغذائية بشكل صحيح، ويقلل من احتمالات الإصابة بنقص المعادن الناتج عن العادات اليومية الخاطئة، وهو ما يصب في مفعول &#8220;السيادة الصحية&#8221; للفرد على جسده.</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/7119708f-27f5-48f0-8134-bf771174305a.webp', 'خسارة الفائدة.. 5 مكملات غذائية يمنع تناولها مع قهوة الصباح', 'خسارة الفائدة.. 5 مكملات غذائية يمنع تناولها مع قهوة الصباح', 'نيويورك- كبسولة الصحية حذر خبراء صحة من أن تناول القهوة الصباحية تزامناً مع بعض المكملات الغذائية قد يقلل من فعاليتها بشكل كبير أو يسبب آثاراً جانبية مزعجة. وأو', '{الكافيين,"مكملات غذائية"}', false, 'published', NULL, NULL, '2026-01-19 00:13:48', '2026-01-24 16:23:34.961493', '2026-01-24 16:23:34.961493');
INSERT INTO public.news VALUES ('96a94beb-e07e-4546-83d9-319a3372185d', '46bbcdc', '"عش بصحة" تطلق حملة "فسحة عِش بصحّة" لتعزيز الصحة الغذائية في المدارس بالشراكة مع وزارة التعليم', NULL, 'متابعة – كبسولة الصحية بالشراكة بين وزارة الصحة ووزارة التعليم، أطلقت مبادرة &#8220;عش بصحة&#8221; التابعة لوزارة الصحة، حملة &#8220;فسحة عِش بصحّة&#8221;؛ الهادفة إلى تعزيز الصحة الغذائية وترسيخ السلوكيات الصحية داخل البيئة المدرسية، من خلال توعية وتمكين الأهالي والطلاب بالمعلومات والأدوات اللازمة ', '<p>متابعة – كبسولة الصحية</p>
<p>بالشراكة بين وزارة الصحة ووزارة التعليم، أطلقت مبادرة &#8220;عش بصحة&#8221; التابعة لوزارة الصحة، حملة &#8220;فسحة عِش بصحّة&#8221;؛ الهادفة إلى تعزيز الصحة الغذائية وترسيخ السلوكيات الصحية داخل البيئة المدرسية، من خلال توعية وتمكين الأهالي والطلاب بالمعلومات والأدوات اللازمة لتهيئة فسحة مدرسية أكثر صحة.</p>
<p>وتسعى الحملة إلى تمكين أفراد المجتمع من تبنّي أنماط حياة صحية، وتعزيز مفاهيم الوقاية، بما يدعم رفع كفاءة الصحة الوقائية، ورفع متوسط العمر المتوقع للإنسان في المملكة إلى 80 عامًا، وذلك انسجامًا مع مستهدفات برنامج تحول القطاع الصحي المنبثق عن رؤية المملكة 2030، لبناء &#8220;مجتمع حيوي&#8221; يتمتع بصحة مستدامة.</p>
<p>وتركز الحملة على ترسيخ أهمية تقديم الإفطار المفيد من قبل الوالدين لأطفالهم، وتعزيز ثقافة الفطور المدرسي الصحي، إلى جانب تحسين سلوكيات اختيار مكونات الإفطار المتوازن لدى الوالدين والطلاب والمعلمين، وتمكين الفئات المستهدفة من اتخاذ قرارات غذائية صحية تُسهم في تعزيز العادات السليمة منذ مراحل مبكرة.</p>
<p>وتأتي هذه الحملة ضمن جهود مبادرة &#8220;عش بصحة&#8221; للإسهام في تحقيق الأهداف الإستراتيجية لوزارة الصحة، وفي مقدمتها تعزيز الحياة الصحية، من خلال التثقيف ورفع مستوى الوعي الصحي والغذائي لدى مختلف فئات المجتمع، بما ينعكس إيجابًا على صحة الأفراد وجودة حياتهم.</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/83548027-d4f3-4755-8eb9-480243f2006f.jpg', '&#8220;عش بصحة&#8221; تطلق حملة &#8220;فسحة عِش بصحّة&#8221; لتعزيز الصحة الغذائية في المدارس بالشراكة مع وزارة التعليم', '&#8220;عش بصحة&#8221; تطلق حملة &#8220;فسحة عِش بصحّة&#8221; لتعزيز الصحة الغذائية في المدارس بالشراكة مع وزارة التعليم', 'متابعة – كبسولة الصحية بالشراكة بين وزارة الصحة ووزارة التعليم، أطلقت مبادرة &#8220;عش بصحة&#8221; التابعة لوزارة الصحة، حملة &#8220;فسحة عِش بصحّة&#8221;؛ الها', '{"الصحة الغذائية","فسحة عِش بصحّة"}', false, 'published', NULL, NULL, '2026-01-18 20:08:52', '2026-01-24 16:23:36.323847', '2026-01-24 16:23:36.323847');
INSERT INTO public.news VALUES ('f1a5b628-0825-4e35-a1a5-d1925dc162b6', '55ca33f', 'أطعمة غنية بالزنك لتعزيز المناعة في الشتاء.. تعرف على المصادر والكميات الموصى بها', NULL, 'كبسولة الصحية &#8211;  فري ويل هيلث يُعد الزنك معدناً أساسياً لا يقتصر دوره على الصحة العامة والعافية فحسب، بل يمتد ليشمل دعم وظائف الجهاز المناعي والمشاركة في مئات العمليات الإنزيمية وتخليق الحمض النووي والبروتينات. وبحسب تقارير صحية، تتراوح الاحتياجات اليومية منه بين 8 و11 ملغ للبالغين، مع زيادة ط', '<p>كبسولة الصحية &#8211;  فري ويل هيلث</p>
<p>يُعد الزنك معدناً أساسياً لا يقتصر دوره على الصحة العامة والعافية فحسب، بل يمتد ليشمل دعم وظائف الجهاز المناعي والمشاركة في مئات العمليات الإنزيمية وتخليق الحمض النووي والبروتينات. وبحسب تقارير صحية، تتراوح الاحتياجات اليومية منه بين 8 و11 ملغ للبالغين، مع زيادة طفيفة للحوامل والمرضعات لتصل إلى 13 ملغ.</p>
<p>ولتلبية هذه الاحتياجات، تبرز مجموعة من المصادر الغذائية المتنوعة التي يمكن إدراجها في النظام الغذائي اليومي:</p>
<ol>
<li>المأكولات البحرية واللحوم</li>
</ol>
<p>يُعد المحار المصدر الأغنى بالزنك، حيث توفر 3 حبات متوسطة الحجم حوالي 24 ملغ.</p>
<p>يحتوي بلح البحر على 2.4 ملغ لكل كوب نيئ، بينما يوفر الروبيان 1.3 ملغ لكل 85 غراماً مطبوخاً.</p>
<p>توفر شريحة لحم البقر (85 غراماً) 3.8 ملغ، بينما يحتوي صدر الديك الرومي على 1.4 ملغ لنفس الوزن.</p>
<p>&nbsp;</p>
<p><img loading="lazy" decoding="async" class="alignnone size-medium wp-image-24049" src="https://capsulah.com/wp-content/uploads/2026/01/vx80-300x172.webp" alt="" width="300" height="172" title="" srcset="https://capsulah.com/wp-content/uploads/2026/01/vx80-300x172.webp 300w, https://capsulah.com/wp-content/uploads/2026/01/vx80-768x440.webp 768w, https://capsulah.com/wp-content/uploads/2026/01/vx80.webp 856w" sizes="auto, (max-width: 300px) 100vw, 300px" /></p>
<ol start="2">
<li>الخيارات النباتية والبقوليات</li>
</ol>
<p>يُعد العدس المسلوق والتوفو مصادر جيدة للنباتيين، حيث يوفر نصف كوب من كل منهما حوالي 2 ملغ من الزنك.</p>
<p>تشمل القائمة أيضاً الفاصوليا بأنواعها (البيضاء والسوداء)، واللوبيا، والحمص.</p>
<ol start="3">
<li>المكسرات ومنتجات الألبان</li>
</ol>
<p>توفر ربع كوب من بذور اليقطين 2.3 ملغ، وبذور دوار الشمس 1.8 ملغ، واللوز 1.1 ملغ.</p>
<p>يحتوي كوب من حليب البقر أو شريحة من جبن الشيدر على حوالي 1 ملغ من الزنك.</p>
<ol start="4">
<li>الشوكولا الداكنة</li>
</ol>
<p>لمحبي الحلويات، توفر الشوكولا الداكنة (بنسبة كاكاو 70-80%) حوالي 3.3 ملغ من الزنك لكل 100 غرام، مما يجعلها خياراً إضافياً لتعزيز مستويات هذا المعدن في الجسم.</p>
<p>&nbsp;</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/2139cc49-3591-4cd6-8ab5-47251503ddb8.webp', 'أطعمة غنية بالزنك لتعزيز المناعة في الشتاء.. تعرف على المصادر والكميات الموصى بها', 'أطعمة غنية بالزنك لتعزيز المناعة في الشتاء.. تعرف على المصادر والكميات الموصى بها', 'كبسولة الصحية &#8211;  فري ويل هيلث يُعد الزنك معدناً أساسياً لا يقتصر دوره على الصحة العامة والعافية فحسب، بل يمتد ليشمل دعم وظائف الجهاز المناعي والمشاركة في ', '{الزنك,الشتاء,"الشكولاتة الداكنة",اللحوم,"المأكولات البحرية"}', false, 'published', NULL, NULL, '2026-01-18 00:15:45', '2026-01-24 16:23:38.745247', '2026-01-24 16:23:38.745247');
INSERT INTO public.news VALUES ('4ca368c2-cb59-4744-8115-58981cd89568', '7904b23', 'معلومة في كبسولة: الجبن كامل الدسم وصحة الدماغ', NULL, 'كبسولة الصحية – خاص في دراسة عالمية: تناول 50 غراماً أو أكثر من الجبن كامل الدسم يومياً يرتبط بانخفاض خطر الإصابة بالخرف بنسبة 13%.. الأنواع الموصى بها: شملت الدراسة أنواعاً مثل الشيدر، والبري، والغودا التي تحتوي على دهون بنسبة تزيد عن 20%. الكمية المثالية: تعادل تقريباً شريحتين من الجبن يومياً. إضا', '<p><strong>كبسولة الصحية – خاص</strong></p>
<p><strong>في دراسة عالمية: </strong></p>
<ul>
<li>تناول <strong>50 </strong><strong>غراماً</strong> أو أكثر من الجبن كامل الدسم يومياً يرتبط بانخفاض خطر الإصابة بالخرف بنسبة <strong>13%</strong>..</li>
<li><strong>الأنواع الموصى بها</strong><strong>:</strong> شملت الدراسة أنواعاً مثل <strong>الشيدر، والبري، والغودا</strong> التي تحتوي على دهون بنسبة تزيد عن 20%.</li>
<li><strong>الكمية المثالية</strong><strong>:</strong> تعادل تقريباً <strong>شريحتين</strong> من الجبن يومياً.</li>
<li><strong>إضافة مفيدة</strong><strong>:</strong> تناول <strong>20 </strong><strong>غراماً</strong> أو أكثر من الكريمة كاملة الدسم يومياً قلل الخطر بنسبة <strong>16%</strong>.</li>
<li><strong>ملاحظة هامة</strong><strong>:</strong> لم يظهر أي تأثير وقائي مماثل عند تناول منتجات الألبان <strong>قليلة الدسم</strong>.</li>
</ul>
<p><strong>* المصدر</strong><strong>:</strong> دراسة جامعة لوند السويدية</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/aba65350-ed12-4599-a16c-7d519c4cc28a.webp', 'معلومة في كبسولة: الجبن كامل الدسم وصحة الدماغ', 'معلومة في كبسولة: الجبن كامل الدسم وصحة الدماغ', 'كبسولة الصحية – خاص في دراسة عالمية: تناول 50 غراماً أو أكثر من الجبن كامل الدسم يومياً يرتبط بانخفاض خطر الإصابة بالخرف بنسبة 13%.. الأنواع الموصى بها: شملت ال', '{"الجبن كامل الدسم","صحة الدماغ","كبسولة الصحية"}', false, 'published', NULL, NULL, '2026-01-18 00:10:10', '2026-01-24 16:23:39.397838', '2026-01-24 16:23:39.397838');
INSERT INTO public.news VALUES ('caee6bd7-21c3-41c3-ba83-a5477ea5dc72', 'bfcb811', 'سحب منتجات "حمص" من الأسواق الأمريكية', NULL, 'كبسولة الصحية – ديلي ميل أعلنت إدارة الغذاء والدواء الأمريكية (FDA) سحب كميات من منتجات &#8220;الحمص&#8221; من متاجر الساحل الشرقي، بعد اكتشاف وجود مادة السمسم بداخلها دون تدوينها على الملصق الخارجي، مما يشكل خطراً داهماً على حياة المستهلكين الذين يعانون من الحساسية. قامت شركة &#8220;كاروت توب كانتر', '<p>كبسولة الصحية – ديلي ميل</p>
<p>أعلنت <strong>إدارة الغذاء والدواء الأمريكية</strong><strong> (FDA)</strong> سحب كميات من منتجات &#8220;الحمص&#8221; من متاجر الساحل الشرقي، بعد اكتشاف وجود مادة <strong>السمسم</strong> بداخلها دون تدوينها على الملصق الخارجي، مما يشكل خطراً داهماً على حياة المستهلكين الذين يعانون من الحساسية.</p>
<p>قامت شركة &#8220;كاروت توب كانتري كيتشنز&#8221; بسحب خمس نكهات محددة من منتجات الحمص (تشمل الثوم، والزنجبيل، والكمأة البيضاء، والطماطم المجففة) المعبأة في عبوات بلاستيكية سعة 8 أونصات. هذه المنتجات، التي تم توزيعها في ولايتي نيويورك وكونيتيكت، تحتوي على <strong>مكون السمسم</strong> دون الإفصاح عنه في قائمة المكونات. وتعد هذه الخطوة إجراءً احترازياً ضرورياً لمنع وقوع إصابات بين المتسوقين في أسواق المزارعين والمتاجر المتخصصة التي وصلت إليها هذه الشحنات.</p>
<p>تكمن الأهمية في الطبيعة الغادرة لحساسية السمسم، حيث يصنفها العلم ضمن مسببات الحساسية الرئيسية التي تستوجب استجابة مناعية عنيفة. عند تعرض الشخص الحساس لهذا المكون الخفي، يفرز الجسم أجساماً مضادة تحفز <strong>الهيستامين</strong>، مما قد يؤدي خلال دقائق إلى أعراض خطيرة تبدأ بالحكة وتنميل الفم، وتتطور سريعاً إلى <strong>ضيق تنفس حاد وانخفاض مفاجئ في ضغط الدم</strong>. غياب التحذير على الملصق يحرم المستهلك من حقه في حماية نفسه، ويجعل من تناول ملعقة حمص واحدة مقامرة بحياة الأشخاص الذين يعانون من استجابات مناعية مفرطة.</p>
<p>تتجه السلطات الرقابية لتكثيف الجولات التفتيشية على &#8220;المطابخ الحرفية&#8221; لضمان مطابقة ملصقاتها للمعايير الفيدرالية الصارمة. ومن المتوقع أن تقوم الشركة المصنعة بمراجعة شاملة لعمليات التعبئة والتغليف قبل السماح بعودة منتجاتها للأرفف. كما دعت إدارة الغذاء والدواء جميع المستهلكين الذين اشتروا هذه النكهات إلى التخلص منها فوراً أو إعادتها لنقطة الشراء، مع توقعات بصدور تشريعات أكثر صرامة تلزم المنتجين الصغار باختبارات مخبرية دورية للكشف عن المكونات غير المعلنة.</p>
', 'nutrition', 'https://capsulah.com', NULL, '/objects/uploads/140bdd5c-1842-4975-a730-4f4a23c8d182.png', 'سحب منتجات &#8220;حمص&#8221; من الأسواق الأمريكية', 'سحب منتجات &#8220;حمص&#8221; من الأسواق الأمريكية', 'كبسولة الصحية – ديلي ميل أعلنت إدارة الغذاء والدواء الأمريكية (FDA) سحب كميات من منتجات &#8220;الحمص&#8221; من متاجر الساحل الشرقي، بعد اكتشاف وجود مادة السمسم ', '{أمريكا,الحمص}', false, 'published', NULL, NULL, '2026-01-15 00:31:48', '2026-01-24 16:23:48.121092', '2026-01-24 16:23:48.121092');
INSERT INTO public.news VALUES ('1a278753-a0ec-45ce-9bb0-01bee137f6b9', 'b86fa4e', 'لماذا تهدد سماعات الرأس حاسة السمع للأبد؟', NULL, 'كبسولة الصحية &#8211;  برافدا رو حذر الدكتور فلاديمير زايتسيف، أخصائي أمراض الأذن والحنجرة، من أن الاستماع المستمر للموسيقى عبر سماعات الرأس يؤدي إلى تلف غير قابل للإصلاح في &#8220;الخلايا الشعرية&#8221; بالأذن الداخلية. وأوضح في تصريحات نقلتها (آر تي) أن هذه الخلايا هي المسؤول الأول عن تحويل الاهتز', '<p>كبسولة الصحية &#8211;  برافدا رو</p>
<p>حذر الدكتور فلاديمير زايتسيف، أخصائي أمراض الأذن والحنجرة، من أن الاستماع المستمر للموسيقى عبر سماعات الرأس يؤدي إلى تلف غير قابل للإصلاح في &#8220;الخلايا الشعرية&#8221; بالأذن الداخلية. وأوضح في تصريحات نقلتها (آر تي) أن هذه الخلايا هي المسؤول الأول عن تحويل الاهتزازات الصوتية إلى إشارات يفهمها الدماغ، وهي خلايا لا تتجدد؛ مما يعني أن تضررها المتكرر بفعل الصوت العالي ينتهي بفقدان سمع دائم وحالات من الطنين المستمر.</p>
<p>تكمن الخطورة في أن الجهاز السمعي البشري مصمم للعمل ضمن نطاق فيزيولوجي محدود، وتجاوز هذا النطاق عبر &#8220;سماعات الأذن&#8221; الملاصقة للقناة السمعية يضع ضغطاً هائلاً على العصب السمعي. وبحسب الخبراء، فإن الشباب والمراهقين هم الفئة الأكثر عرضة للإصابة بـ &#8220;فقدان السمع الحسي العصبي&#8221; نتيجة رفع مستوى الصوت لتغطية الضجيج الخارجي، وهو ما يحول هواية يومية بسيطة إلى مسبب لأمراض عصبية مزمنة.</p>
<p>يوصي الأطباء بقاعدة &#8220;الساعة الواحدة&#8221; كحد أقصى للاستخدام اليومي، مع تقسيمها إلى فترتين مدة كل منهما 30 دقيقة. كما يُنصح بالانتقال إلى مكبرات الصوت الخارجية كلما أمكن ذلك، أو استخدام سماعات الرأس المزودة بخاصية &#8220;إلغاء الضوضاء&#8221; (Noise Cancelling)؛ لأنها تتيح الاستماع بوضوح دون الحاجة لرفع الصوت لمستويات خطرة، مما يحمي الخلايا الحسية من التآكل التدريجي ويحافظ على سلامة العصب السمعي لسنوات أطول.</p>
<p>&nbsp;</p>
', 'saudi-health', 'https://capsulah.com', NULL, '/objects/uploads/0205b1d0-6e05-4291-9bc1-693e11b596c3.jpg', 'لماذا تهدد سماعات الرأس حاسة السمع للأبد؟', 'لماذا تهدد سماعات الرأس حاسة السمع للأبد؟', 'كبسولة الصحية &#8211;  برافدا رو حذر الدكتور فلاديمير زايتسيف، أخصائي أمراض الأذن والحنجرة، من أن الاستماع المستمر للموسيقى عبر سماعات الرأس يؤدي إلى تلف غير قا', '{"سماعات الرأس","صحة السمع"}', false, 'deleted', NULL, NULL, '2026-01-24 01:20:21', '2026-01-24 16:23:13.288204', '2026-01-24 16:23:13.288204');


