INSERT INTO public.radar_items VALUES ('460c0161-bb87-4749-a81e-5d868e8d4338', '490fde3d-85bd-4d4f-b8b9-33004455eadc', 'e60295a37c7f5d4e44c3cb553f0a7718', 'CDC confirms H5N1 Bird Flu Infection in a Child in California', NULL, 'The Centers for Disease Control and Prevention (CDC) has confirmed a human infection with avian influenza A(H5N1) (H5N1 bird flu) in a child in California.', NULL, '', NULL, 'https://tools.cdc.gov/podcasts/download.asp?m=132608&c=754904', NULL, NULL, '2024-11-22 13:13:00', '2026-01-25 06:50:19.725166', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:19.725166', '2026-01-25 06:50:19.725166');
