INSERT INTO public.radar_items VALUES ('8b7f413a-9cf4-4a70-955e-0c8868a75922', '490fde3d-85bd-4d4f-b8b9-33004455eadc', 'cf0e3feae7f18786ec7d2bd08325ba74', 'Onions served at McDonald''s are likely source of E. coli outbreak', NULL, 'An update to CDC''s Food Safety Alert regarding an outbreak of E. coli infections linked to onions served at McDonald''s', NULL, '', NULL, 'https://tools.cdc.gov/podcasts/download.asp?m=132608&c=754058', NULL, NULL, '2024-10-30 17:07:00', '2026-01-25 06:50:20.453539', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:20.453539', '2026-01-25 06:50:20.453539');
INSERT INTO public.radar_items VALUES ('371786ac-bf76-4710-b424-2f08fb5be774', '490fde3d-85bd-4d4f-b8b9-33004455eadc', '8740bbce4c8401c725398b13b9a747b6', 'Lassa Fever Suspected in Death of U.S. Traveler Returning from West Africa', NULL, 'The CDC and the Iowa Department of Health are investigating a suspected case of Lassa fever, which was diagnosed today in an Iowa resident who returned to the United States from West Africa early this month.', NULL, '', NULL, 'https://tools.cdc.gov/podcasts/download.asp?m=132608&c=753987', NULL, NULL, '2024-10-28 19:40:00', '2026-01-25 06:50:20.575457', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:20.575457', '2026-01-25 06:50:20.575457');
INSERT INTO public.radar_items VALUES ('abd91c19-244f-4152-acf2-3370d36b738c', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '28c4ac4d3994b6ef7ef7a82fb00d1b6f', 'Countries progress negotiations in support of WHO Pandemic Agreement', NULL, 'The World Health Organization (WHO) Member States this week advanced their negotiations on the Pathogen Access and Benefit‑Sharing (PABS) system in a resumed session of the Intergovernmental Working Group (IGWG) on the WHO Pandemic Agreement. The PABS system is a core element of the agreement adopted by the World Health Assembly (WHA) in May 2025. During the session held on 20–22 January 2026, Member States continued text‑based negotiations on outstanding issues in the draft annex and exchanged ', NULL, 'The World Health Organization (WHO) Member States this week advanced their negotiations on the Pathogen Access and Benefit‑Sharing (PABS) system in a resumed session of the Intergovernmental Working Group (IGWG) on the WHO Pandemic Agreement. The PABS system is a core element of the agreement adopted by the World Health Assembly (WHA) in May 2025.During the session held on 20&ndash;22 January 2026, Member States continued text‑based negotiations on outstanding issues in the draft annex and exchanged views aimed at narrowing differences and identifying areas of convergence.&ldquo;I am encouraged by the progress we have made in several areas, with signs of emerging consensus for some parts of the Pathogen Access and Benefit‑Sharing system,&rdquo; said IGWG Bureau co‑chair Ambassador Tovar da Silva Nunes, of Brazil. &ldquo;As we look ahead to the fifth session, the focus will be on the outstanding, complex issues. The resumed session has helped us gain a clearer picture of where we stand.&rdquo; Established by the WHA, the IGWG is tasked, as a priority, with drafting and negotiating the PABS system, which is intended to enable safe, transparent and accountable sharing of pathogens with pandemic potential and their genetic sequence information, alongside the fair and equitable sharing of benefits arising from their use, including vaccines, therapeutics and diagnostics.The resumed session was held following a request by Member States to extend the fourth meeting of the IGWG, which convened in December 2025.&ldquo;Member States have engaged in constructive discussions this week," said IGWG Bureau co-chair Mr Matthew Harpur, of the United Kingdom. "As we make progress towards the May deadline, I am encouraged by their willingness to work together and bridge differences to deliver an effective Pathogen Access and Benefit‑Sharing system."Further meetings of the IGWG are scheduled in the coming months as Member States continue their negotiations.&ldquo;A strong Pathogen Access and Benefit‑Sharing system will be a cornerstone of a safer and more equitable world,&rdquo; said Dr Tedros Adhanom Ghebreyesus, WHO Director-General. &ldquo;I thank countries for their commitment to multilateral solutions.&rdquo;The outcome of IGWG&rsquo;s work will be submitted to the Seventy‑ninth World Health Assembly in May 2026 for its consideration.', NULL, 'https://www.who.int/news/item/23-01-2026-countries-progress-negotiations-in-support-of-who-pandemic-agreement', NULL, NULL, '2026-01-23 16:24:59', '2026-01-25 06:50:29.429421', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:29.429421', '2026-01-25 06:50:29.429421');
INSERT INTO public.radar_items VALUES ('c83d71a7-6ffd-4e6e-befc-14e0c14dcf5f', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'a47c5a301fe4396a0ef493eaf60f8dc4', 'WHO renews commitment to a leprosy-free world, spotlighting partnership and progress ahead of World Leprosy Day', NULL, 'Access to treatment for leprosy is essential to global efforts to eliminate leprosy, says the World Health Organization (WHO) ahead of World Leprosy Day, to be observed on 25 January. Leprosy is an infectious disease caused by a type of bacteria, Mycobacterium leprae, and is one of the oldest diseases known to humanity. The disease predominantly affects the skin and peripheral nerves. Left untreated, the disease may cause progressive and permanent disabilities and causes stigma and social isolat', NULL, 'Access to treatment for leprosy is essential to global efforts to eliminate leprosy, says the World Health Organization (WHO) ahead of World Leprosy Day, to be observed on 25 January.Leprosy is an infectious disease caused by a type of bacteria, Mycobacterium leprae, and is one of the oldest diseases known to humanity. The disease predominantly affects the skin and peripheral nerves. Left untreated, the disease may cause progressive and permanent disabilities and causes stigma and social isolation. However, the disease can be cured with multidrug therapy (MDT).Efforts to eliminate leprosy have been leading to reductions in the number of new cases in many areas; of the 188 countries, areas or territories that submitted data in 2024, 55 reported zero cases. But still 172 717 new cases were detected worldwide and reported to WHO in the same year.Many partners, including pharmaceutical companies such as Novartis, have been strong supporters of efforts to eliminate leprosy. WHO has collaborated with Novartis since 2000 to provide MDT and clofazimine, free of cost, to all leprosy patients worldwide. This partnership remains one of the most sustained pharmaceutical donation programmes in global health.Marking 25 years of partnership, WHO and Novartis have extended a Memorandum of Understanding (MoU) for an additional 5 years (2026&minus;2030). The extension makes provision for continued supply of MDT and also includes funding for procurement and distribution of single dose rifampicin (SDR) for post-exposure prophylaxis (PEP).&ldquo;The unwavering commitment of partners like Novartis over the past quarter-century has been foundational to the progress made against leprosy,&rdquo; said Dr Jeremy Farrar, WHO Assistant Director-General for Health Promotion, Disease Prevention and Care. &ldquo;Their steadfast support in ensuring free access to treatment has helped transform millions of lives and moved us closer to a world free from this ancient disease. This enduring collaboration exemplifies the power of global solidarity in health &ndash; a reminder that, together, we can overcome even the oldest and most entrenched health challenges when science, equity, and partnership align.&rdquo;Availability of free MDT has made it possible to cure the disease, prevent disabilities, mitigate stigma, and has enabled affected individuals to continue working and leading normal lives. Additionally, clofazimine has ensured the treatment of lepra reactions, which are characterized by sudden, severe inflammatory episodes, leading to disabilities, if left untreated.&ldquo;Leprosy is one of the oldest infectious diseases known to humanity and combatting it has been part of our company&rsquo;s history since discovering the first effective cure,&rdquo; said Dr Lutz Hegemann, President of Global Health at Novartis. &ldquo;Over the last 25 years, we have reached millions of patients together with WHO, and we are committed to going further to pursue our vision of a world free of leprosy.&rdquo;While significant progress has been made, sustaining and building on this momentum requires political commitment, community engagement and continued collaboration and partnership.The theme for this year&rsquo;s World Leprosy Day is &ldquo;Leprosy is curable, the real challenge is stigma&rdquo;.This year also marks the 25th anniversary of Mr Yohei Sasakawa&rsquo;s work as the WHO Goodwill Ambassador for Leprosy Elimination. He said, &ldquo;One of the most stubborn challenges that I encounter on my travels is the social stigma attached to leprosy, which can be more problematic than the disease itself, and which can persist beyond the end of treatment. This is particularly true for people who have been left with residual disabilities as a result of leprosy. They may face various forms of discrimination, including forced divorce, lost educational opportunities and unfair dismissal. Even after being cured, they endure the unending pain of social exclusion.&rdquo;As leprosy is one of the target diseases under the broader umbrella of Neglected Tropical Diseases (NTDs), this work also supports the unified global effort towards a world free of NTDs. Learn more about the collective action and join our campaign on World NTD Day 2026 on 30 January. Notes for editorsThe NTD Roadmap 2021-2030 aims at elimination of leprosy (interruption of transmission). The Global Leprosy Strategy 2021&ndash;2030 underpinning the Roadmap, shifts the paradigm beyond the achievement of &lsquo;elimination of leprosy as a public health problem&rsquo; toward interruption of transmission and elimination of leprosy disease. Contact screening along with scale-up of preventive chemotherapy and mitigation of stigma and discrimination constitute key pillars of this strategy. Beyond working to ensure that every person affected by leprosy is detected early and treated promptly, WHO leads efforts to combat the discrimination that persons affected by leprosy too often face.', NULL, 'https://www.who.int/news/item/21-01-2026-who-renews-commitment-to-a-leprosy-free-world--spotlighting-partnership-and-progress-ahead-of-world-leprosy-day', NULL, NULL, '2026-01-21 17:14:46', '2026-01-25 06:50:29.555905', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:29.555905', '2026-01-25 06:50:29.555905');
INSERT INTO public.radar_items VALUES ('e65cb1cf-1923-4125-8b80-d43ede9d0f69', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'b2eb2b9fb2ca82108dc53aa0b8ffaec9', 'Cheaper drinks will see a rise in noncommunicable diseases and injuries', NULL, 'In two new global reports released today, the World Health Organization is calling on governments to significantly strengthen taxes on sugary drinks and alcoholic beverages. The reports warn that weak tax systems are allowing harmful products to remain cheap while health systems face mounting financial pressure from preventable noncommunicable diseases and injuries.', NULL, 'In two new global reports released today, the World Health Organization is calling on governments to significantly strengthen taxes on sugary drinks and alcoholic beverages. The reports warn that weak tax systems are allowing harmful products to remain cheap while health systems face mounting financial pressure from preventable noncommunicable diseases and injuries.', NULL, 'https://www.who.int/news/item/13-01-2026-cheaper-drinks-will-see-a-rise-in-noncommunicable-diseases-and-injuries', NULL, NULL, '2026-01-13 13:00:04', '2026-01-25 06:50:29.679213', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:29.679213', '2026-01-25 06:50:29.679213');
INSERT INTO public.radar_items VALUES ('3988c03d-0d5b-4a28-8bd6-d987ee024956', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '349f26c9cee9ce90eeeff4681f84589c', 'Sudan: 1000 days of war deepen the world’s worst health and humanitarian crisis', NULL, 'Today, the conflict in Sudan reaches its 1000th day, with over 20 million people requiring health assistance and 21 million desperately needing food. Nearly three years of continuous violence, severe access constraints, and reduced funding have turned Sudan into the worst humanitarian crisis globally. An estimated 33.7 million people will need humanitarian aid this year. The health system has been severely damaged by ongoing fighting, increasingly deadly attacks on health care, mass displacement', NULL, 'Today, the conflict in Sudan reaches its 1000th day, with over 20 million people requiring health assistance and 21 million desperately needing food.Nearly three years of continuous violence, severe access constraints, and reduced funding have turned Sudan into the worst humanitarian crisis globally. An estimated 33.7 million people will need humanitarian aid this year.The health system has been severely damaged by ongoing fighting, increasingly deadly attacks on health care, mass displacement, lack of essential medical supplies, and shortages of health personnel and funding. Despite sustained efforts by WHO and partners to restore and revive health services across the country, more than one third of health facilities (37%) remain non-functional, depriving millions of people of essential and lifesaving health services.Since the start of the conflict in April 2023, WHO has verified 201 attacks on health care, resulting in 1858 deaths and 490 injuries. These attacks, which violate international humanitarian law, undermine access to lifesaving care and put health care workers, patients and caregivers at grave risk.&ldquo;One thousand days of conflict in Sudan have driven the health system to the brink of collapse. Under the strain of disease, hunger and a lack of access to basic services, people face a devastating situation,&rdquo; said WHO Representative in Sudan, Dr Shible Sahbani. &ldquo;WHO is doing what we can, where we can, and we know we are saving lives and rebuilding the health system. Despite the challenges, we are also working on recovery of the health system.&rdquo;The level of displacement is unprecedented. An estimated 13.6 million people are currently displaced, making Sudan the largest displacement crisis in the world. Fueled by poor living conditions, overcrowding in displacement sites, disrupted health and water, sanitation and hygiene services, and a breakdown of routine immunization, disease outbreaks are spreading, compounding the crisis. WHO is currently supporting the response to outbreaks of cholera, dengue, malaria, and measles, with cholera being reported from all 18 states, dengue from 14 states, and malaria from 16 states. Access to preventive and curative care, including for the management of chronic conditions and severe malnutrition, remains limited.WHO works with Sudan&rsquo;s Federal and State Ministries of Health and partners to improve access to critical health services across Sudan and rehabilitate the health system. Since the start of the conflict in April 2023, WHO has delivered 3378 metric tons of medicines and medical supplies worth about US$ 40 million, including diagnostic supplies, treatments for malnutrition, and diseases such as cholera, malaria, dengue, and emergency surgery, to 48 health partners for lifesaving operations. About 24 million people have received cholera vaccinations, and WHO has supported the country to introduce and scale up malaria vaccines. Additionally, more than 3.3 million people have accessed health care at WHO-supported hospitals, primary health care facilities, and temporary mobile clinics. More than 112 400 children with severe acute malnutrition with medical complications have received treatment at functional stabilization centres, all of which receive lifesaving WHO nutrition supplies. State and National public health laboratories have been equipped and strengthened to confirm disease outbreaks and enable a rapid response.&ldquo;As the relentless conflict renders some areas inaccessible, particularly in the Darfur and Kordofan regions, the population&rsquo;s health needs continue to increase,&rdquo; Dr Sahbani said. &ldquo;To meet these mounting needs and prevent the crisis from spiraling out of hand, WHO and humanitarian partners require safe and unimpeded access to all areas of Sudan, and increased financial resources.&rdquo;Ultimately, WHO calls parties to the conflict to urgently work towards a ceasefire and peace for the people of Sudan.', NULL, 'https://www.who.int/news/item/09-01-2026-sudan-1000-days-of-war-deepen-the-world-s-worst-health-and-humanitarian-crisis', NULL, NULL, '2026-01-12 10:44:06', '2026-01-25 06:50:29.802864', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:29.802864', '2026-01-25 06:50:29.802864');
INSERT INTO public.radar_items VALUES ('544ccdb0-c959-48e6-bae2-de4a7028d972', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '637da62135ae5eed0fdabb9266db159f', 'WHO Global Summit charts a bold future for traditional medicine', NULL, 'The second WHO Global Summit on Traditional Medicine, jointly organized with the Government of India, concluded today in New Delhi, marking a major milestone for global health as it drew over 16 000 online registrations and brought together 800 delegates from more than 100 countries, including ministers from over 20 nations. Combined with a strong line up of 160 speakers, the global traditional medicine community shared insights on how traditional medicine (TM) can strengthen health systems with', NULL, 'The second WHO Global Summit on Traditional Medicine, jointly organized with the Government of India, concluded today in New Delhi, marking a major milestone for global health as it drew over 16 000 online registrations and brought together 800 delegates from more than 100 countries, including ministers from over 20 nations. Combined with a strong line up of 160 speakers, the global traditional medicine community shared insights on how traditional medicine (TM) can strengthen health systems with more safe, evidence-based, and affordable care. The energy in Delhi was palpable as ministers, scientists, Indigenous leaders, and practitioners came together to advance the WHO Global Traditional Medicine Strategy 2025&ndash;2034. The Summit was not just about dialogue &ndash; it was about action. WHO unveiled the Traditional Medicine Global Library, a first-of-its-kind digital platform consolidating 1.6 million resources on TM, from scientific studies to Indigenous knowledge. With advanced features like Evidence Gap Maps and an AI-powered tool, TMGL GPT, the Library promises to transform access to trusted information and accelerate research worldwide. Innovation took centre stage with the launch of Health & Heritage Innovations (H2I), an initiative to nurture breakthrough ideas that bridge traditional practices with cutting-edge technologies such as AI, genomics, and digital health. From over 1000 submissions, 21 finalists were announced at the Summit and will enter a year-long acceleration programme to refine prototypes, receive scientific and regulatory guidance, and connect with policy-makers and investors. WHO also announced the Strategic and Technical Advisory Group on Traditional, Complementary and Integrative Medicine (STAG-TM), a new advisory body to guide the Global Strategy. Comprised of 19 independent experts, STAG-TM will shape research priorities, develop standards, and advise on integration into health systems. At its inaugural meeting during the Summit, the group set urgent priorities: evidence generation, preservation of traditional knowledge, digital innovation, and capacity building. Countries rallied behind the Delhi Declaration, with commitments from 26 Member States, signaling a new era for traditional medicine. This collective pledge focuses on integrating traditional medicine into primary health care, strengthening regulation and safety standards, investing in research, and building interoperable data systems to track outcomes. It&rsquo;s a shift from recognition to results &ndash; ensuring traditional medicine is not a parallel system but a driver of universal health coverage. &ldquo;Through the Delhi Commitment, countries have agreed not only on why traditional medicine matters &ndash; but on how to act,&rdquo; said Dr Tedros Adhanom Ghebreyesus, WHO Director-General. &ldquo;Traditional medicine can help to address many of the threats to health of our modern world: the growing burden of noncommunicable diseases; inequitable access to health services; and climate change. It can help to support care that is person-centred, culturally grounded, and holistic.&rdquo; Looking ahead, WHO will work with Member States to turn these commitments into reality&ndash; scaling access to trusted knowledge, accelerating innovation, and embedding TM into health systems everywhere. The Global Traditional Medicine Strategy 2025&ndash;2034 charts a bold course toward a future where care is more inclusive, culturally grounded, and resilient.', NULL, 'https://www.who.int/news/item/22-12-2025-who-global-summit-charts-a-bold-future-for-traditional-medicine', 'https://cdn.who.int/media/images/default-source/headquarters/initiatives/global-centre-for-traditional-medicine/2nd-tm-traditional-medicine-summit-dg-modi-family-photo.jpeg?sfvrsn=6842b65_3', NULL, '2025-12-22 17:50:16', '2026-01-25 06:50:29.925524', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:29.925524', '2026-01-25 06:50:29.925524');
INSERT INTO public.radar_items VALUES ('4f7356cb-36f8-4836-93c0-bf8ad2317a50', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '538b75f3100b4f412c68fb621c9c5b06', 'UN agencies welcome news that famine has been pushed back in the Gaza Strip, but warn fragile gains could be reversed without increased and sustained support', NULL, 'The latest Integrated Food Security Phase Classification (IPC) analysis for Gaza confirms that no areas of the Strip are currently classified in famine following the October ceasefire and improved humanitarian and commercial access.', NULL, 'The latest Integrated Food Security Phase Classification (IPC) analysis for Gaza confirms that no areas of the Strip are currently classified in famine following the October ceasefire and improved humanitarian and commercial access.', NULL, 'https://www.who.int/news/item/19-12-2025-un-agencies-welcome-news-that-famine-has-been-pushed-back-in-the-gaza-strip-but-warn-fragile-gains-could-be-reversed-without-increased-and-sustained-support', NULL, NULL, '2025-12-19 16:56:10', '2026-01-25 06:50:30.05279', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.05279', '2026-01-25 06:50:30.05279');
INSERT INTO public.radar_items VALUES ('ec04a8ba-7cd8-4b5d-b929-97ba04ee27a5', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'e6260868c429ee088065433d8b939940', 'WHO validates Brazil for eliminating mother-to-child transmission of HIV', NULL, 'The World Health Organization (WHO) has validated Brazil for the elimination of mother-to-child transmission (EMTCT) of HIV, making it the most populous country in the Americas to achieve this historic milestone. This accomplishment reflects Brazil’s long-standing commitment to universal and free access to health services through its Unified Health System (SUS), anchored in a strong primary health-care system and respect for human rights. “Eliminating mother-to-child transmission of HIV is a maj', NULL, 'The World Health Organization (WHO) has validated Brazil for the elimination of mother-to-child transmission (EMTCT) of HIV, making it the most populous country in the Americas to achieve this historic milestone. This accomplishment reflects Brazil&rsquo;s long-standing commitment to universal and free access to health services through its Unified Health System (SUS), anchored in a strong primary health-care system and respect for human rights.&ldquo;Eliminating mother-to-child transmission of HIV is a major public health achievement for any country, especially for a country as large and complex as Brazil,&rdquo; said Dr Tedros Adhanom Ghebreyesus, WHO Director-General. &ldquo;Brazil has shown that with sustained political commitment and equitable access to quality health services, every country can ensure that every child is born free of HIV and every mother receives the care she deserves.&rdquo;The milestone was marked during a ceremony in Bras&iacute;lia, attended by President Luiz In&aacute;cio Lula da Silva, Brazil&rsquo;s Minister of Health Alexandre Padilha, and the Director of the Pan American Health Organization (PAHO) Dr Jarbas Barbosa, along with representatives from UNAIDS.Meeting validation criteriaBrazil met all the criteria for EMTCT validation, including reducing vertical transmission of HIV to below 2% and achieving over 95% coverage for prenatal care, routine HIV testing, and timely treatment for pregnant women living with HIV. In addition to meeting the targets of the validation, Brazil demonstrated the delivery of quality services for mothers and their infants, robust data and laboratory systems, and a strong commitment to human rights, gender equality and community engagement.The country implemented a progressive, subnational approach by first certifying states and municipalities with over 100 000 inhabitants, adapting the PAHO/WHO validation methodology to its national context while maintaining coherence across the country.The evaluation, supported by PAHO, was conducted by independent experts who reviewed data, documentation, and health facility operations. Findings were then assessed by WHO&rsquo;s Global Validation Advisory Committee, which formally recommended Brazil&rsquo;s validation for elimination.&ldquo;This achievement shows that eliminating vertical transmission of HIV is possible when pregnant women know their HIV status, receive timely treatment, and have access to maternal health services and safe delivery,&rdquo; said Dr Jarbas Barbosa, Director of PAHO. &ldquo;It is also the result of the tireless dedication of thousands of health professionals, community health workers, and civil society organizations. Every day, they sustain the continuity of care, identify obstacles, and work to overcome them, ensuring that even the most vulnerable populations can access essential health services."Part of a broader initiativeOver the past decade (2015-2024), more than 50 000 pediatric HIV infections have been averted in the Region of the Americas as a result of the implementation of the initiative to eliminate mother-to-child transmission of HIV.Brazil&rsquo;s success is part of the broader EMTCT Plus Initiative, which seeks to eliminate mother-to-child transmission of HIV, syphilis, hepatitis B, and congenital Chagas, in collaboration with UNICEF and UNAIDS. It is embedded within PAHO&rsquo;s Elimination Initiative, a regional effort to eliminate more than 30 communicable diseases and related conditions in the Americas by 2030."I am delighted that Brazil has just been certified by WHO/PAHO for eliminating vertical transmission &ndash; the first country of more than 100 million people to do so,&rdquo; said Winnie Byanyima, UNAIDS Executive Director. &ldquo;And they did it by doing what we know works &ndash;prioritizing universal health care, tackling the social determinants that drive the epidemic, protecting human rights, and even &ndash; when necessary &ndash; breaking monopolies to secure access to medicines."Global contextBrazil is one of 19 countries and territories worldwide that have been validated by WHO for EMTCT. Twelve of these are in the Region of the Americas. In 2015, Cuba became the first country in the world to be validated for EMTCT of HIV and the elimination of congenital syphilis. Other countries in the Region include Anguilla, Antigua and Barbuda, Bermuda, Cayman Islands, Montserrat, and Saint Kitts and Nevis in 2017; Dominica in 2020; Belize in 2023; and Jamaica and Saint Vincent and the Grenadines in 2024.Outside the Americas, countries validated for EMTCT of HIV include Armenia, Belarus, Malaysia, Maldives, Oman, Sri Lanka, and Thailand.', NULL, 'https://www.who.int/news/item/18-12-2025-who-validates-brazil-for-eliminating-mother-to-child-transmission-of-hiv', NULL, NULL, '2025-12-18 15:43:16', '2026-01-25 06:50:30.175399', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.175399', '2026-01-25 06:50:30.175399');
INSERT INTO public.radar_items VALUES ('87e3f0c5-9ca0-48f9-898f-d4b7a8c32c5b', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'dc451e6db3df4ef30eec873a39b57be5', 'WHO hosts the second Global Summit to advance evidence, integration and innovation for traditional medicine', NULL, 'The World Health Organization (WHO)’s Second Global Summit on Traditional Medicine, jointly organized with the Government of India, opens today, bringing together government ministers, scientists, Indigenous leaders, and practitioners from more than 100 countries. The Summit is expected to announce major scientific initiatives and new commitments aimed at advancing the implementation of the WHO Global Traditional Medicine Strategy 2025–2034, centred on stronger evidence, better regulation, syste', NULL, 'The World Health Organization (WHO)&rsquo;s Second Global Summit on Traditional Medicine, jointly organized with the Government of India, opens today, bringing together government ministers, scientists, Indigenous leaders, and practitioners from more than 100 countries. The Summit is expected to announce major scientific initiatives and new commitments aimed at advancing the implementation of the WHO Global Traditional Medicine Strategy 2025&ndash;2034, centred on stronger evidence, better regulation, systems integration, collaboration and community engagement. Traditional medicine (TM) encompasses codified and non-codified systems that predate biomedicine and have continued to evolve for contemporary use. For many, TM remains the main source of health care&mdash;locally accessible, affordable and bio-culturally aligned&mdash;and for many more, it is a preferred, personalized and more natural health option. Nearly 90% of WHO Member States (170 out of 194) report that 40&ndash;90% of their populations use TM.&ldquo;WHO is committed to uniting the wisdom of millennia with the power of modern science and technology to realise the vision of health for all,&rdquo; said Dr Tedros Adhanom Ghebreyesus, WHO Director-General. &ldquo;By engaging responsibly, ethically, and equitably, and by harnessing innovation from AI to genomics, we can unlock the potential of traditional medicine to deliver safer, smarter, and more sustainable health solutions for every community and for our planet.&rdquo;Strengthening evidence, regulation and integration of TM into health systemsIn a world facing increasing challenges to health systems, nearly half of the global population &ndash; 4.6 billion &ndash; lack access to essential health services, while a quarter &ndash; over 2 billion people &ndash; experience financial hardship to access health care. Integrating TM into health systems is critical to expanding access and choice to affordable, people-centred health care and advancing UHC, ensuring everyone can receive health care they need without financial strain.Emerging evidence indicates that integrating TM into health systems can deliver cost efficiencies and improve health outcomes. Such integration emphasizes prevention and health promotion, contributing to broader health benefits such as more appropriate use of antibiotics.Achieving effective integration requires robust science, global standards for quality and safety, and strong regulatory mechanisms. &ldquo;We need to apply the same scientific rigour to the assessment and validation of biomedicine and traditional medicines, while respecting biodiversity, cultural specificities and ethical principles,&rdquo; said Dr Sylvie Briand, WHO Chief Scientist. &ldquo;Stronger collaborations and frontier technologies &ndash; such as AI, genomics, systems biology, neurosciences and advanced data analytics &ndash; can transform how we study and apply traditional medicine.&rdquo;Advancing innovation, investment and sustainable benefitsTM underpins fast-growing global industries, such as herbal medicines. All TM formulations, and more than half of biomedical pharmaceuticals, originate from natural resources, which remain a vital source for new drug discovery. Indigenous Peoples safeguard around 40% of the world&rsquo;s biodiversity while representing just 6% of the global population. Advancing TM requires addressing Indigenous rights, fair trade, and benefit-sharing considerations.Despite TM&rsquo;s widespread use and vital role in stewarding natural resources for health and well-being, less than 1% of global health research funding is dedicated to TM. To help close the knowledge and research gaps, WHO is launching the Traditional Medicine Global Library, the first of its kind, featuring more than 1.6 million scientific records spanning research, policies, regulations and thematic collections on diverse TM applications. Developed in response to calls by Heads of State during G20 and BRICS meetings in 2023, the Library also provides equitable online access to peer-reviewed content for institutions in lower-income countries through the Research4Life initiative. It also supports countries in documenting TM with intellectual property protections and in building scientific capacity to drive innovation. &ldquo;Advancing traditional medicine is an evidence-based, ethical and environmental imperative,&rdquo; said Dr Shyama Kuruvilla, Director a.i. of WHO&rsquo;s Global Traditional Medicine Centre. &ldquo;The Global Summit fosters the conditions and collaborations required for TM to contribute at scale to the flourishing of all people and the planet.&rdquo;The Summit (17&ndash;19 December 2025, New Delhi) will also announce new commitments from governments and other stakeholders, alongside a call for a global consortium to address systemic gaps and accelerate implementation of the Global TM Strategy at scale.', NULL, 'https://www.who.int/news/item/17-12-2025-who-hosts-the-second-global-summit-to-advance-evidence--integration-and-innovation-for-traditional-medicine', NULL, NULL, '2025-12-17 08:09:29', '2026-01-25 06:50:30.297821', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.297821', '2026-01-25 06:50:30.297821');
INSERT INTO public.radar_items VALUES ('b3716f7a-579f-4ddd-8061-2cb3a84b1bfe', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '8fe9818bc4c4df26ecdc6bc8cff86de1', 'World leaders adopt a historic global declaration on noncommunicable diseases and mental health', NULL, 'Leaders from across the world at the Eightieth United Nations General Assembly (UNGA) have adopted the political declaration to combat noncommunicable diseases (NCDs) and mental health challenges through a fully integrated approach. This is the outcome of the intergovernmental negotiations in advance of and considered by the fourth high-level meeting of the UNGA on the prevention and control of NCDs and the promotion of mental health and well-being, held on 25 September 2025.', NULL, 'Leaders from across the world at the Eightieth United Nations General Assembly (UNGA) have adopted the political declaration to combat noncommunicable diseases (NCDs) and mental health challenges through a fully integrated approach. This is the outcome of the intergovernmental negotiations in advance of and considered by the fourth high-level meeting of the UNGA on the prevention and control of NCDs and the promotion of mental health and well-being, held on 25 September 2025.', NULL, 'https://www.who.int/news/item/16-12-2025-world-leaders-adopt-a-historic-global-declaration-on-noncommunicable-diseases-and-mental-health', NULL, NULL, '2025-12-16 08:06:59', '2026-01-25 06:50:30.421563', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.421563', '2026-01-25 06:50:30.421563');
INSERT INTO public.radar_items VALUES ('637ec0d9-921d-46fb-a7c2-076559d52dd6', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '89dfe31ff521c6a250cb04a14d5fff16', 'WHO expert group’s new analysis reaffirms there is no link between vaccines and autism', NULL, 'New analysis from a WHO global expert committee on vaccine safety has found that, based on available evidence, no causal link exists between vaccines and autism spectrum disorders (ASD). The conclusion reaffirms WHO’s position that childhood vaccines do not cause autism.', NULL, 'New analysis from a WHO global expert committee on vaccine safety has found that, based on available evidence, no causal link exists between vaccines and autism spectrum disorders (ASD). The conclusion reaffirms WHO’s position that childhood vaccines do not cause autism.', NULL, 'https://www.who.int/news/item/11-12-2025-who-expert-group-s-new-analysis-reaffirms-there-is-no-link-between-vaccines-and-autism', NULL, NULL, '2025-12-11 15:09:10', '2026-01-25 06:50:30.544702', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.544702', '2026-01-25 06:50:30.544702');
INSERT INTO public.radar_items VALUES ('f6c2e47b-326a-4bc9-a74d-b39685e1ef5b', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '66f32badeef342f4fe6afbe57bb07baf', 'Most countries make progress towards universal health coverage, but major challenges remain, WHO–World Bank report finds', NULL, 'Since 2000, most countries – across all income levels and regions – have made concurrent progress in expanding health service coverage and reducing the financial hardship associated with health costs, according to a new joint report from the World Health Organization (WHO) and the World Bank Group. These two indicators are the foundation of universal health coverage (UHC) – the global commitment that everyone, everywhere can access the care they need without financial hardship by 2030. The UHC G', NULL, 'Since 2000, most countries &ndash; across all income levels and regions &ndash; have made concurrent progress in expanding health service coverage and reducing the financial hardship associated with health costs, according to a new joint report from the World Health Organization (WHO) and the World Bank Group. These two indicators are the foundation of universal health coverage (UHC) &ndash; the global commitment that everyone, everywhere can access the care they need without financial hardship by 2030.The UHC Global Monitoring Report 2025 shows that health service coverage, measured by the Service Coverage Index (SCI), rose from 54 to 71 points between 2000 and 2023. Meanwhile, the share of people experiencing financial hardship due to large and impoverishing out-of-pocket (OOP) health payments declined from 34% to 26% between 2000 and 2022.However, the report cautions that the poorest populations continue to bear the greatest burden of unaffordable health costs, with 1.6 billion people further pushed into poverty. Overall, an estimated 4.6 billion people worldwide still lack access to essential health services and 2.1 billion people experience financial hardship to access health care, including the 1.6 billion people living in poverty or pushed deeper into it due to health expenses."Universal health coverage is the ultimate expression of the right to health, but this report shows that for billions of people who cannot access or afford the health services they need, that right remains out of reach,&rdquo; said Dr Tedros Adhanom Ghebreyesus, WHO Director-General. &ldquo;In the context of severe cuts to international aid, now is the time for countries to invest in their health systems, to protect the health of their people and economies. WHO is supporting them to do that.&rdquo;Financial hardship in health is defined as household spending more than 40% of its discretionary budget on OOP health expenses. Cost of medicines is a major driver of financial hardship: in three-quarters of countries with available data, medicines account for at least 55% of people&rsquo;s OOP health expenses. The burden is even greater among people living in poverty who allocate a median of 60% of their OOP health expenses on medicines diverting their scarce resources from other essential needs.While the burden of OOP health costs falls mostly on poorer people, it also affects better-off segments of the population that allocate a large share of their budgets to health expenses, particularly in middle-income countries where this group of people is growing.Without faster progress, full-service coverage without financial hardship will remain out of reach for many: the global SCI is projected to reach only 74 out of 100 by 2030, with nearly 1 in 4 people worldwide still facing financial hardship at the end of the Sustainable Development Goals (SDG) era.Encouraging progress in low-income countries with largest gapsDespite positive direction, the global progress rate has slowed since 2015 with only one-third of countries improving in both increasing health coverage and reducing financial hardship. All WHO regions have improved service coverage, but only half &ndash; Africa, South-East Asia, the Western Pacific &ndash; also reduced financial hardship. Low-income countries achieved the fastest gains in both areas but are still facing the largest gaps.The global increase in health service coverage has been driven largely by advances in infectious disease programmes. Coverage for noncommunicable diseases (NCDs) has shown steady improvement, while gains in reproductive, maternal, newborn, and child health have been modest.The report notes that improved sanitation has supported service coverage gains. At the same time, inclusive economic growth, rising incomes, and stronger social protection mechanisms have driven poverty reduction, especially in low-income countries, contributing to declines in financial hardship. However, health costs have increasingly become a source of financial hardship among the poor.Inequalities are getting starkerDespite progress, persistent gaps and inequalities are on the rise. In 2022, 3 out of 4 people among the poorest segment of the populations faced financial hardship from health costs, compared with fewer than 1 in 25 among the richest.Women, people living in poverty, or in rural areas, or with less education, reported greater difficulty accessing essential health services. The gap between women in the richest and poorest quintiles narrowed slightly, from about 38 to 33 percentage points over the past decade. Even in high-performing regions such as Europe, vulnerable groups &ndash; including the poorest and people with disabilities &ndash; continue to report higher unmet health needs.These findings likely underestimate the true extent of health inequalities, as the most vulnerable groups &ndash; such as displaced populations and people living in informal settlements &ndash; are often missing in data sources used to monitor progress toward UHC.Actions leading to 2030Achieving the UHC goal by 2030 is central to realizing the human right to health. With five years remaining on the SDG agenda, urgent action is now needed to drive progress. The report underscores the critical role of political commitment in every country and community, and calls for action in six core areas:ensure essential health care is free at the point of care for people living in poverty and vulnerable situations;expand public investments in health systems;address high out-of-pocket spending on medicines;accelerate access to essential NCD services, especially as the disease burden rises;strengthen primary health care to promote equity and efficiency; and adopt multisectoral approaches, recognizing that determinants of health and UHC drivers extend beyond the health sector. Editor&rsquo;s noteThis edition of the UHC Global Monitoring Report 2025 reflects the first round of UHC tracking to incorporate revised SDG indicators for health service coverage (SDG 3.8.1) and financial hardship (SDG 3.8.2), introduced in 2025. Using the revised indicators, and reproduction of the full time series, the report has presented global and regional trends in service coverage from 2000 to 2023, based on time series data for 195 countries or territories, and global and regional trends in financial hardship from 2000 to 2022, based on primary country time series for 168 countries. More about monitoring universal health coverage.The Report is presented at the UHC High-Level Forum, jointly hosted by the Government of Japan, the World Bank Group, and WHO, in Tokyo, Japan. The Forum will also mark the official launch of the UHC Knowledge Hub in Tokyo, established by WHO and the World Bank Group with the support of the Government of Japan. The Hub offers capacity strengthening programmes for Ministries of Health and Finance to support health financing reforms. More about the Universal Health Coverage (UHC) High-level Forum 2025.WHO, the World Bank Group, UHC2030 and the Joint Learning Network for Universal Health Coverage will organize a technical webinar &ldquo;Tracking Universal Health Coverage: 2025 Global Monitoring Report&rdquo; on 8 December 2025, at 8:00&ndash;9:30am EST | 14:00&ndash;15:30 CET. You can join the webinar through this link. (Passcode: .W1MJT=@r3)', NULL, 'https://www.who.int/news/item/06-12-2025-most-countries-make-progress-towards-universal-health-coverage-but-major-challenges-remain-who-world-bank-report-finds', NULL, NULL, '2025-12-06 01:45:23', '2026-01-25 06:50:30.668393', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.668393', '2026-01-25 06:50:30.668393');
INSERT INTO public.radar_items VALUES ('f7fa54a1-690b-4141-a0df-1fff0c634cbc', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '9c1ef0f3116f6380943dc549f613b1f7', 'Countries to reconvene sooner to accelerate progress on WHO Pathogen Access and Benefit Sharing system negotiations', NULL, 'WHO Member States today ended their latest round of intensive negotiations on the world’s first Pathogen Access andBenefit Sharing (PABS) system. Countries decided to resume deliberations in January in a reflection of the shared commitment and urgency needed to help make the world safer from future pandemics. Countries convened for the fourth meeting of the Intergovernmental Working Group (IGWG) on the WHO Pandemic Agreement in Geneva from 1–5 December 2025. They requested to extend the current ', NULL, 'WHO Member States today ended their latest round of intensive negotiations on the world&rsquo;s first Pathogen Access andBenefit Sharing (PABS) system. Countries decided to resume deliberations in January in a reflection of the shared commitment and urgency needed to help make the world safer from future pandemics.Countries convened for the fourth meeting of the Intergovernmental Working Group (IGWG) on the WHO Pandemic Agreement in Geneva from 1&ndash;5 December 2025. They requested to extend the current fourth round of negotiations, agreeing to resume from 20&ndash;22 January 2026.The World Health Assembly established the IGWG to undertake several tasks, including, as a priority, to draft and negotiate the PABS annex to the WHO Pandemic Agreement. Member States requested the establishment of a PABS platform to operate as a global system to share pathogens and their genetic information, along with the benefits that arise from their use, in a timely, fair and transparent way. This would pave the way for a more effective and equitable response to the next pandemic.&ldquo;As we cross the halfway mark in negotiations on the Pathogen Access and Benefit-Sharing (PABS) system, I am encouraged by the progress we&rsquo;ve made towards enabling a faster and more equitable global response to future pandemics," said IGWG Bureau co-chair Mr Matthew Harpur of the United Kingdom. "Member States have demonstrated real commitment to finding common ground and bridging differences, as we work to deliver a strong PABS system by the next World Health Assembly.&rdquo;IGWG Bureau co-Chair Ambassador Tovar da Silva Nunes, of Brazil, said: &ldquo;WHO Member States have shown their dedication to finishing this important task. The progress achieved on access, benefit-sharing and core governance areas provides the foundation to move the process forward. We are confident we can build a strong and balanced PABS system that will benefit all people.&rdquo; WHO Director-General Dr Tedros Adhanom Ghebreyesus added: &ldquo;This is both a generational opportunity and a generational responsibility. I thank Member States and the IGWG Bureau for rising to the occasion. As we get ready to close out this year, we are in a strong position to forge consensus, finalize the draft, and prepare for adoption at next year&rsquo;s World Health Assembly. Together, we are moving toward a world that is better prepared for future pandemics." Before this fourth session, the IGWG Bureau organized informal dialogues with stakeholders, including representatives from the private sector, academia, laboratories and sequence information databases. Similar focused dialogues will continue over the following weeks, in preparation for the resumed session in January. The fifth IGWG meeting will take place on 9&ndash;14 February 2026.', NULL, 'https://www.who.int/news/item/05-12-2025-countries-to-reconvene-sooner-to-accelerate-progress-on-who-pathogen-access-and-benefit-sharing-system-negotiations', NULL, NULL, '2025-12-05 18:44:42', '2026-01-25 06:50:30.791009', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.791009', '2026-01-25 06:50:30.791009');
INSERT INTO public.radar_items VALUES ('d7a826ca-8885-40ab-b96f-7e604c30a2ef', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'ebfbf00c44903c00fe3acd0ac1fad5c6', 'New tools saved a million lives from malaria last year but progress under threat as drug resistance rises', NULL, 'This year’s report provides a critical and up-to-date snapshot of efforts to control and eliminate malaria across 80 countries. The report also presents the threat posed by antimalarial resistance and its impact.', NULL, 'This year’s report provides a critical and up-to-date snapshot of efforts to control and eliminate malaria across 80 countries. The report also presents the threat posed by antimalarial resistance and its impact.', NULL, 'https://www.who.int/news/item/04-12-2025-new-tools-saved-a-million-lives-from-malaria-last-year-but-progress-under-threat-as-drug-resistance-rises', NULL, NULL, '2025-12-04 08:23:36', '2026-01-25 06:50:30.914418', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:30.914418', '2026-01-25 06:50:30.914418');
INSERT INTO public.radar_items VALUES ('d6420b8a-422d-438c-9833-215203de125b', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'd8c928b4643e3ee3eb19718ca7cf53cb', 'WHO issues global guideline on the use of GLP-1 medicines in treating obesity', NULL, 'To address the growing global health challenge of obesity, which affects more than 1 billion people, WHO has released its first guideline on the use of Glucagon-Like Peptide-1 (GLP-1) therapies for treating obesity as a chronic, relapsing disease.', NULL, 'To address the growing global health challenge of obesity, which affects more than 1 billion people, WHO has released its first guideline on the use of Glucagon-Like Peptide-1 (GLP-1) therapies for treating obesity as a chronic, relapsing disease.', NULL, 'https://www.who.int/news/item/01-12-2025-who-issues-global-guideline-on-the-use-of-glp-1-medicines-in-treating-obesity', NULL, NULL, '2025-12-01 13:00:25', '2026-01-25 06:50:31.036872', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.036872', '2026-01-25 06:50:31.036872');
INSERT INTO public.radar_items VALUES ('efb573a9-6203-4ee2-ad9c-b3f87f4e6dba', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'ba3ff7c6adc0b48f17e08ddac33f52d6', 'New prevention tools and investment in services essential in the fight against AIDS', NULL, 'On World AIDS Day, the World Health Organization (WHO) calls on governments and partners to rapidly expand access to new WHO-approved tools including lenacapavir (LEN) to drive down infections and counter disruption to essential health services caused by cuts to foreign aid. Despite dramatic funding setbacks, the global HIV response has gained a remarkable momentum in 2025 with the introduction and WHO approval of twice-yearly injectable lenacapavir for HIV prevention. LEN, a highly effective, l', NULL, 'On World AIDS Day, the World Health Organization (WHO) calls on governments and partners to rapidly expand access to new WHO-approved tools including lenacapavir (LEN) to drive down infections and counter disruption to essential health services caused by cuts to foreign aid.Despite dramatic funding setbacks, the global HIV response has gained a remarkable momentum in 2025 with the introduction and WHO approval of twice-yearly injectable lenacapavir for HIV prevention. LEN, a highly effective, long-acting alternative to oral pills and other options, is a transformative intervention for people who face challenges with regular adherence and stigma in accessing health care. WHO released in July this year new guidelines recommending the use of lenacapavir as an additional pre-exposure prophylaxis (PrEP) option for HIV prevention.Sharp and sudden reductions in international funding this year led to disruptions in HIV prevention, treatment and testing services, with essential community-led programmes, including pre-exposure prophylaxis (PrEP) and harm reduction initiatives for people who inject drugs, being scaled back or shut down entirely in some countries. &ldquo;We face significant challenges, with cuts to international funding, and prevention stalling," said Dr Tedros Adhanom Ghebreyesus, WHO Director-General. &ldquo;At the same time, we have significant opportunities, with exciting new tools with the potential to change the trajectory of the HIV epidemic. Expanding access to those tools for people at risk of HIV everywhere must be priority number one for all governments and partners.&rdquo;Marking World AIDS Day under the theme &ldquo;Overcoming disruption, transforming the AIDS response&rdquo;, WHO is urging a dual track approach &ndash; solidarity and investment in innovations to protect and empower communities most at risk.After decades of progress, the HIV response stands at a crossroads. In 2024:HIV prevention efforts stagnated, with 1.3 million new infections, disproportionately impacting key and vulnerable populations; UNAIDS data reveal that almost half (49%) of new HIV infections occurred among key populations &ndash; including sex workers, men who have sex with men, transgender women, and people who inject drugs &ndash; and their sexual partners; while sex workers and transgender women face a 17-fold higher risk of acquiring HIV, men who have sex with men face an 18-fold higher risk, and people who inject drugs &ndash; a 34-fold higher risk; underlying drivers include stigma, discrimination, and legal, social and structural barriers these groups face to access HIV care; and globally, an estimated 40.8 million people were living with HIV, and 630 000 people died from HIV-related causes.While the full scale of the impact of foreign aid cuts is still being assessed, access to PrEP is believed to have declined dramatically. The AIDS Vaccine Advocacy Coalition estimates that, as of October 2025, 2.5 million people who used PrEP in 2024 lost access to their medications in 2025 due solely to donor funding cuts. Such disruptions could have far-reaching consequences for the global HIV response, jeopardizing efforts to end AIDS by 2030. Momentum for innovation &ldquo;We are entering a new era of powerful innovations in HIV prevention and treatment,&rdquo; said Dr Tereza Kasaeva, Director of WHO&rsquo;s Department for HIV, TB, Hepatitis and STIs. &ldquo;By pairing these advances with decisive action, supporting communities, and removing structural barriers, we can ensure that key and vulnerable populations have full access to life-saving services.&rdquo; WHO prequalified LEN for HIV prevention on 6 October 2025, followed by national regulatory approvals that will increase access in South Africa (on 27 October), Zimbabwe (27 November) and Zambia (4 November). WHO&rsquo;s Collaborative Registration Procedure (CRP) supported these approvals. WHO is also working closely with partners such as CIFF, the Gates Foundation, the Global Fund to Fight AIDS, Tuberculosis and Malaria and Unitaid to enable affordable access to LEN in countries. Ensuring that long-acting HIV medicines for prevention and treatment reach priority populations must be a global priority. Integrating HIV services into primary health careWHO emphasizes that ending the AIDS epidemic depends on a fully integrated, evidence-based and rights-driven approach under the umbrella of primary health care. WHO will continue working with partners and leaders to put those most affected at the centre of the HIV response. Despite funding setbacks, the resilience and leadership of communities offer a clear path forward. By strengthening health systems, increasing domestic investment, and protecting human rights, countries can safeguard gains and ensure no one is left behind.', NULL, 'https://www.who.int/news/item/01-12-2025-new-prevention-tools-and-investment-in-services-essential-in-the-fight-against-aids', NULL, NULL, '2025-11-30 17:04:40', '2026-01-25 06:50:31.159559', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.159559', '2026-01-25 06:50:31.159559');
INSERT INTO public.radar_items VALUES ('23cbb321-13d4-4ed2-b179-565dcdb45292', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '56f501719062be69fe1a715e3653cb67', 'Global gains in tuberculosis response endangered by funding challenges', NULL, 'Tuberculosis (TB) remains one of the world’s deadliest infectious killers, claiming over 1.2 million lives and affecting an estimated 10.7 million people last year, according to the WHO Global Tuberculosis Report 2025, released today.', NULL, 'Tuberculosis (TB) remains one of the world’s deadliest infectious killers, claiming over 1.2 million lives and affecting an estimated 10.7 million people last year, according to the WHO Global Tuberculosis Report 2025, released today.', NULL, 'https://www.who.int/news/item/12-11-2025-global-gains-in-tuberculosis-response-endangered-by-funding-challenges', NULL, NULL, '2025-11-12 14:08:15', '2026-01-25 06:50:32.258887', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:32.258887', '2026-01-25 06:50:32.258887');
INSERT INTO public.radar_items VALUES ('e61d73ba-b28f-49ae-b095-6924e3c98d94', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '79bec24ebc33eb529ce9dba8f6ac95ff', 'WHO issues first global guideline on infertility', NULL, 'The World Health Organization (WHO) today called on countries to make fertility care safer, fairer and more affordable for all in its first-ever global guideline for the prevention, diagnosis and treatment of infertility.Infertility is estimated to affect 1 in 6 people of reproductive age at some point in their lives.', NULL, 'The World Health Organization (WHO) today called on countries to make fertility care safer, fairer and more affordable for all in its first-ever global guideline for the prevention, diagnosis and treatment of infertility.Infertility is estimated to affect 1 in 6 people of reproductive age at some point in their lives.', NULL, 'https://www.who.int/news/item/28-11-2025-who-issues-first-global-guideline-on-infertility', NULL, NULL, '2025-11-28 08:12:14', '2026-01-25 06:50:31.282002', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.282002', '2026-01-25 06:50:31.282002');
INSERT INTO public.radar_items VALUES ('62e42019-4836-4f5b-aa52-1457bf850f2d', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'f9f996888af1cb6d399f378e6168a847', 'Measles deaths down 88% since 2000, but cases surge', NULL, 'Global immunization efforts have led to an 88% drop in measles deaths between 2000 and 2024, according to a new report from the World Health Organization (WHO). Nearly 59 million lives have been saved by the measles vaccine since 2000.', NULL, 'Global immunization efforts have led to an 88% drop in measles deaths between 2000 and 2024, according to a new report from the World Health Organization (WHO). Nearly 59 million lives have been saved by the measles vaccine since 2000.', NULL, 'https://www.who.int/news/item/28-11-2025-measles-deaths-down-88--since-2000--but-cases-surge', NULL, NULL, '2025-11-26 18:24:57', '2026-01-25 06:50:31.40416', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.40416', '2026-01-25 06:50:31.40416');
INSERT INTO public.radar_items VALUES ('07b9f264-2920-4b58-a03e-eb58afed978d', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'bfc99fc81b5ad298c432caaa5efb2ac3', 'Lifetime toll: 840 million women faced partner or sexual violence', NULL, 'Violence against women remains one of the world’s most persistent and under-addressed human rights crises, with very little progress in two decades, according to a landmark report released today by the World Health Organization (WHO) and UN partners. Nearly 1 in 3 women – estimated 840 million globally – have experienced partner or sexual violence during their lifetime, a figure that has barely changed since 2000. In the last 12 months alone, 316 million women – 11% of those aged 15 or older – w', NULL, 'Violence against women remains one of the world&rsquo;s most persistent and under-addressed human rights crises, with very little progress in two decades, according to a landmark report released today by the World Health Organization (WHO) and UN partners.Nearly 1 in 3 women &ndash; estimated 840 million globally &ndash; have experienced partner or sexual violence during their lifetime, a figure that has barely changed since 2000. In the last 12 months alone, 316 million women &ndash; 11% of those aged 15 or older &ndash; were subjected to physical or sexual violence by an intimate partner. Progress on reducing intimate partner violence has been painfully slow with only 0.2% annual decline over the past two decades.For the first time, the report includes national and regional estimates of sexual violence by someone other than a partner. It finds 263 million women have experienced non-partner sexual violence since age 15, a figure experts caution is significantly under-reported due to stigma and fear."Violence against women is one of humanity&rsquo;s oldest and most pervasive injustices, yet still one of the least acted upon," said Dr Tedros Adhanom Ghebreyesus, WHO Director-General. "No society can call itself fair, safe or healthy while half its population lives in fear. Ending this violence is not only a matter of policy; it is a matter of dignity, equality and human rights. Behind every statistic is a woman or girl whose life has been forever altered. Empowering women and girls is not optional, it''s a prerequisite for peace, development and health. A safer world for women is a better world for everyone."Efforts face funding cuts amidst mounting needsThe new report, released ahead of the International day for the elimination of violence against women and girls observed on 25 November, represents the most comprehensive study on the prevalence of these two forms of violence against women. It updates 2018 estimates released in 2021. It analyses data between 2000 and 2023 from 168 countries, revealing a stark picture of a deeply neglected crisis and critically underfunded response.Despite mounting evidence on effective strategies to prevent violence against women, the report warns that funding for such initiatives is collapsing &ndash; just as when humanitarian emergencies, technological shifts, and rising socio-economic inequality are further increasing risks for millions of women and girls. For instance, in 2022, only 0.2% of the global development aid was allocated to programmes focused on prevention of violence against women, and funding has further fallen in 2025.Widespread and lifelong risksWomen subjected to violence face unintended pregnancies, a higher risk of acquiring sexually transmitted infections and experiencing depression. Sexual and reproductive health services are an important entry point for survivors to receive the high-quality care they need.The report underscores the reality that violence against women begins early and risks persist throughout life. For example, in the past 12 months alone, 12.5 million adolescent girls 15-19 years of age or 16% have experienced physical and/or sexual violence from an intimate partner.While violence occurs in every country, women in least-developed, conflict-affected, and climate-vulnerable settings are disproportionately affected. For example, Oceania (excluding Australia and New Zealand) reports 38% prevalence of intimate partner violence in the past year &ndash; more than 3 times the global average of 11%.A call for action &ndash; and accountabilityMore countries than ever are now collecting data to inform policies, yet significant gaps remain &ndash; particularly on non-partner sexual violence, marginalized groups such as indigenous women, migrants, and women with disabilities, as well as data from fragile and humanitarian settings. Progress has been achieved in countries where there is political commitment to do so. For example, Cambodia is implementing a national project that will update legislation on domestic violence, improve service delivery, quality and access, refurbish shelters and leverage digital solutions in schools and communities to promote prevention especially with adolescents.Ecuador, Liberia, Trinidad and Tobago and Uganda have developed costed national action plans. Legislative and advocacy actions in these countries have contributed to some domestic financing for this issue, signalling increased political commitment at a time of decreasing aid budgets. To accelerate global progress and deliver meaningful change for the lives of affected women and girls, the report calls for decisive government action and funding to:scale up evidence-based prevention programmesstrengthen survivor-centred health, legal and social servicesinvest in data systems to track progress and reach the most at-risk groupsenforce laws and policies empowering women and girls.The report is accompanied by the launch of the second edition of the RESPECT Women: preventing violence against women framework, offering updated guidance for violence prevention, including for humanitarian contexts.There can be no more silence or inaction. We need leaders to commit and act towards ending violence against women and girls now.Quotes from partners"Ending violence against women and girls requires courage, commitment, and collective action. Advancing gender equality is how we build a more equal, safer world for everyone, where every woman and every girl can live a life free from violence.&rdquo; Dr Sima Bahous, Executive Director, UN Women "Violence against women inflicts deep and lasting harm that affects their lives, health and dignity. For many, violence is compounded by discrimination based on poverty, disability and other factors, exposing them to even higher risk. The devastating cycle of abuse often ripples through families and communities and across generations. The data paint a grim picture of the toll of inaction. This must change now. We must act urgently together to end this violence and ensure that every woman and girl, in all her diversity, can exercise her rights, realize her potential and contribute fully to more just, equal and prosperous societies.&rdquo; Diene Keita, Executive Director, UNFPA &ldquo;The data shows that many women first experience violence from a partner when they are adolescents. And many children grow up watching their mothers being pushed, hit or humiliated, with violence a part of daily life. The key is to break this pattern of violence against women and girls.&rdquo; UNICEF Executive Director Catherine Russell Notes to the editorsAbout the reportThe report, Global, regional and national prevalence estimates for intimate partner violence against women and non-partner sexual violence against women, 2023 was developed by WHO and the UNDP-UNFPA-UNICEF-WHO-World Bank Special Programme of Research, Development and Research Training in Human Reproduction (HRP) on behalf of, and with the United Nations Inter-Agency Working Group on Violence Against Women Estimation and Data. The Working Group includes representatives from WHO, UN Women, UNICEF, UNFPA, the United Nations Office on Drugs and Crime (UNODC) and the United Nations Statistics Division (UNSD).Modelling is used to enhance comparability of estimates across countries and regions to the extent allowed by existing data. All surveys likely underestimate the actual prevalence of violence against women as there will always be women who do not disclose these experiences, especially where this violence is highly stigmatized. Sexual violence is particularly underreported in many settings. Poorly designed or implemented surveys in some places further exacerbate this underestimation.About regional and country estimatesThe report and database present regional data in the following categories: Sustainable Development Goal (SDG) regions, WHO regions, Global Burden of Disease (GBD) regions, UNFPA regions and UNICEF regions. Data is also presented for 168 countries and areas for women aged 15-49 years old. The report presents data on both lifetime and past 12 months prevalence estimates.The rates of the Past 12 months prevalence of intimate partner violence among ever-married/-partnered women 15 years and older among the United Nations SDG regional and subregion classifications are ranked below from highest to lowest prevalence:Oceania (excluding Australia and New Zealand): 38%Central and Southern Asia: 18%Southern Asia &ndash; 19%Least Developed Countries &ndash; 18%Sub-Saharan Africa &ndash; 17%Small Island Developing States &ndash; 17%Northern Africa and Western Asia &ndash; 14%Northern Africa &ndash; 16%Oceania (including Australia and New Zealand) &ndash; 13%Eastern and South-Eastern Asia &ndash; 8%Latin American and the Caribbean &ndash; 7%Europe and Northern America &ndash; 5%About RESPECTRESPECT stands for: Relationship skills strengthening, Empowerment of women and girls, Services ensured, Poverty reduced, Enabling environments (i.e. schools, workplaces, public places), Child and adolescent abuse prevented, and Transformed gender attitudes, beliefs and norms. RESPECT women is endorsed by 13 agencies and is aimed at policy makers.', NULL, 'https://www.who.int/news/item/19-11-2025-lifetime-toll--840-million-women-faced-partner-or-sexual-violence', NULL, NULL, '2025-11-19 11:34:26', '2026-01-25 06:50:31.527039', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.527039', '2026-01-25 06:50:31.527039');
INSERT INTO public.radar_items VALUES ('dae4c4f1-7b92-4cb9-be04-812b10cc70e7', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '9a2f4e0d3902b3d51048f77c8ab8bc6c', 'More countries report rising levels of drug-resistant gonorrhoea, warns WHO', NULL, 'The World Health Organization (WHO) warns that gonorrhoea, a sexually transmitted infection, is becoming increasingly resistant to antibiotics, according to new data from its Enhanced Gonococcal Antimicrobial Surveillance Programme (EGASP), which monitors the spread of drug-resistant gonorrhoea. The report highlights the need to strengthen surveillance, improve diagnostic capacity and ensure equitable access to new treatments for sexually transmitted infections (STIs). The release of the new dat', NULL, 'The World Health Organization (WHO) warns that gonorrhoea, a sexually transmitted infection, is becoming increasingly resistant to antibiotics, according to new data from its Enhanced Gonococcal Antimicrobial Surveillance Programme (EGASP), which monitors the spread of drug-resistant gonorrhoea. The report highlights the need to strengthen surveillance, improve diagnostic capacity and ensure equitable access to new treatments for sexually transmitted infections (STIs). The release of the new data coincides with World Antimicrobial Resistance (AMR) Awareness Week, reinforcing the importance of global action against drug-resistant infections. EGASP, launched by WHO in 2015, collects laboratory and clinical data from sentinel sites around the world to track AMR and inform treatment guidelines.&ldquo;This global effort is essential to tracking, preventing, and responding to drug-resistant gonorrhoea and to protecting public health worldwide,&rdquo; said Dr Tereza Kasaeva, Director of the WHO Department for HIV, TB, Hepatitis & STIs. &ldquo;WHO calls on all countries to address the rising levels of sexually transmitted infections (STIs) and integrate gonorrhoea surveillance into national STI programmes.&rdquo; Between 2022 and 2024, resistance to ceftriaxone and cefixime, the primary antibiotics used to treat gonorrhoea, rose sharply from 0.8% to 5% and from 1.7% to 11% respectively, with resistant strains detected in more countries. Resistance to azithromycin remained stable at 4%, while resistance to ciprofloxacin reached 95%. Cambodia and Viet Nam reported the highest resistance rates.In 2024, 12 EGASP countries in five WHO regions provided data, an increase from just four countries in 2022. This is a positive development reflecting growing commitment to track and contain drug-resistant infections in countries and regions. The countries- Brazil, Cambodia, India, Indonesia, Malawi, the Philippines, Qatar, South Africa, Sweden, Thailand, Uganda and Viet Nam reported 3615 cases of gonorrhoea.Over half of all cases of symptomatic gonorrhoea in men (52%) were reported from countries in the WHO Western Pacific Region, including the Philippines (28%), Viet Nam (12%), Cambodia (9%) and Indonesia (3%). Countries of the WHO African Region accounted for 28% of cases, followed by countries in the South-East Asia Region (13%, Thailand), the Eastern Mediterranean Region (4%, Qatar) and the Region of the Americas (2%, Brazil).The median patient age was 27 years (range: 12&ndash;94). Among cases, 20% were men who have sex with men, and 42% reported multiple sexual partners within the past 30 days. Eight percent reported recent antibiotic use, and 19% had travelled recently. Strengthening and expanding global surveillanceIn 2024, WHO advanced genomic surveillance, with nearly 3000 samples sequenced from eight countries. Landmark studies on new treatments such as zoliflodacin and gepotidacin, as well as studies on tetracycline resistance, were conducted by WHO&rsquo;s Collaborating Centre on AMR in STI in Sweden, in coordination with WHO. These are helping guide future gonorrhoea control and doxycycline-based prevention (DoxyPEP) strategies. EGASP continued to expand its reach in 2024, with Brazil, C&ocirc;te d&rsquo;Ivoire and Qatar joining the programme, and India beginning implementation and data reporting starting in 2025 under its National AIDS and Sexually Transmitted Diseases Control Programme.Despite notable progress, EGASP faces challenges, including limited funding, incomplete reporting, and gaps in data from women and extragenital sites. WHO calls for urgent investment, particularly in national surveillance systems, to sustain and expand global gonococcal AMR surveillance.', NULL, 'https://www.who.int/news/item/19-11-2025-more-countries-report-rising-levels-of-drug-resistant-gonorrhoea--warns-who', NULL, NULL, '2025-11-19 10:01:44', '2026-01-25 06:50:31.64881', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.64881', '2026-01-25 06:50:31.64881');
INSERT INTO public.radar_items VALUES ('e3cd1f51-50ce-48b3-99a2-130a7d24b006', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '9b52e6dd256a70218398c24c6c6993b3', 'World marks cervical cancer elimination day as countries accelerate action', NULL, 'Today marks the first World Cervical Cancer Elimination Day – mandated by the World Health Assembly – a historic milestone in global efforts to end a preventable cancer.', NULL, 'Today marks the first World Cervical Cancer Elimination Day – mandated by the World Health Assembly – a historic milestone in global efforts to end a preventable cancer.', NULL, 'https://www.who.int/news/item/17-11-2025-world-marks-cervical-cancer-elimination-day-as-countries-accelerate-action', NULL, NULL, '2025-11-17 10:04:46', '2026-01-25 06:50:31.770387', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.770387', '2026-01-25 06:50:31.770387');
INSERT INTO public.radar_items VALUES ('d630dc96-c6ec-4d5b-8466-53bb62130745', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'f19723769976d20db7e360792fe66942', 'WHO promotes lifesaving intervention for small and preterm babies on first official World Prematurity Day', NULL, 'The World Health Organization (WHO) is marking its first official observance of World Prematurity Day with the launch of a new global clinical practice guide for Kangaroo Mother Care (KMC) – a simple, proven and life-saving intervention that significantly improves survival for preterm and low birth weight babies. Each year, an estimated 15 million babies are born too soon (before 37 weeks of pregnancy), and complications from preterm birth are the leading cause of death among children under five', NULL, 'The World Health Organization (WHO) is marking its first official observance of World Prematurity Day with the launch of a new global clinical practice guide for Kangaroo Mother Care (KMC) &ndash; a simple, proven and life-saving intervention that significantly improves survival for preterm and low birth weight babies.Each year, an estimated 15 million babies are born too soon (before 37 weeks of pregnancy), and complications from preterm birth are the leading cause of death among children under five years of age. In the poorest countries, most extremely preterm babies die within days &ndash; whereas in high-income countries, almost all survive.KMC &ndash; which combines prolonged skin to skin contact with breast-milk feeding &ndash; has been shown to dramatically improve outcomes for small and preterm newborns, and to be feasible and cost-effective in all settings. Among other positive impacts, it is associated with a more than 30% reduction in newborn deaths, a close to 70% reduction in hypothermia and a 15% reduction in severe infections &ndash; as well as improved weight gain and better longer-term health and cognitive development. &ldquo;KMC is not just a clinical intervention &ndash; it empowers mothers and families and transforms newborn care,&rdquo; said Dr Jeremy Farrar, WHO&rsquo;s Assistant Director-General for Health Promotion, Disease Prevention and Care. &ldquo;It should now be universal clinical practice for all small and preterm babies, ensuring they have the best chance to survive and thrive.&rdquo;A lifesaving intervention for all babies born early or smallGeared at health workers, facility managers as well as caregivers, the new WHO guide offers detailed, step-by-step, adaptable guidance for initiating, maintaining, and monitoring KMC. It states that all preterm or low birth weight newborns should receive KMC starting immediately after birth - unless they are unable to breathe on their own or their blood pressure and circulation drops to dangerously low levels, requiring urgent treatment. While mothers should typically be the primary providers, fathers and other family members can also give KMC if the mother is unable &ndash; as well as providing critical emotional and practical support. KMC can be practiced at all levels of health facilities &ndash; from the labour room or the operating theatre to postnatal wards and special or intensive newborn care units &ndash; and can be continued at home. The guide includes practical tips on how to secure the baby in the KMC position, whether using simple cloth wraps, elastic binders or specially designed garments. It also outlines how health facilities create enabling environments for KMC through supportive policies and training staff. Family-friendly approaches are crucial for successful implementation, the guide notes &ndash; including ensuring mothers can always be together in the same room as their babies.All small and sick newborns need dedicated medical care and attentionOn this World Prematurity Day, with the theme &lsquo;A strong start for a hopeful future&rsquo;, WHO is calling on governments, health systems and partners to prioritize quality care for preterm and low birth weight babies. This means ensuring dedicated wards or facilities with specially trained neonatal staff providing round-the-clock care for small and sick newborns, as well as universal access to essential equipment and medicines like antibiotics. Because they have less time in the womb, many preterm babies have underdeveloped lungs, brains, immune systems and capacity for temperature regulation. This increases risks from infections, hypothermia, heart problems, respiratory distress, and other life-threatening complications. &ldquo;No newborn should die from preventable causes,&rdquo; said Dr Per Ashorn, WHO&rsquo;s Unit Head for Newborn and Child Health and Development. &ldquo;It&rsquo;s time to ensure every baby gets the attention they need, by investing in special care for small or sick babies, alongside quality maternity services that can prevent many occurrences of preterm birth.&rdquo;', NULL, 'https://www.who.int/news/item/14-11-2025-who-promotes-lifesaving-intervention-for-small-and-preterm-babies-on-first-official-world-prematurity-day', NULL, NULL, '2025-11-14 17:39:52', '2026-01-25 06:50:31.892587', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:31.892587', '2026-01-25 06:50:31.892587');
INSERT INTO public.radar_items VALUES ('2c9d0d93-10b0-4f38-bd0e-7ab019d8750b', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '022af4941b65ebfec08b9295240a5a65', 'WHO and Brazil urge swift action on Belém Health Action Plan at COP30', NULL, 'The COP30 Special report on health and climate change: delivering the Belém Health Action Plan, notes that rising temperatures and collapsing health systems are claiming more lives, and calls for immediate and coordinated action to protect health in a rapidly warming world. It follows the launch of the Belém Health Action Plan, a flagship initiative of Brazil’s COP 30 Presidency, unveiled on the dedicated Health Day of COP30 – 13 November 2025.', NULL, 'The COP30 Special report on health and climate change: delivering the Belém Health Action Plan, notes that rising temperatures and collapsing health systems are claiming more lives, and calls for immediate and coordinated action to protect health in a rapidly warming world. It follows the launch of the Belém Health Action Plan, a flagship initiative of Brazil’s COP 30 Presidency, unveiled on the dedicated Health Day of COP30 – 13 November 2025.', NULL, 'https://www.who.int/news/item/14-11-2025-who-and-brazil-urge-swift-action-on-bel-m-health-action-plan-at-cop30', NULL, NULL, '2025-11-14 09:02:01', '2026-01-25 06:50:32.015214', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:32.015214', '2026-01-25 06:50:32.015214');
INSERT INTO public.radar_items VALUES ('686aa03c-9117-49f4-bfc1-82f8c63d54a3', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'd6b4a32b027f61e5f6615af3b633894d', 'WHO launches global guidelines on diabetes during pregnancy on World Diabetes Day', NULL, 'The World Health Organization (WHO) today released its first global guidelines for the management of diabetes during pregnancy, a condition affecting about one in six pregnancies – or 21 million women annually. The new recommendations provide a critical roadmap to tackle this growing health challenge and prevent serious complications for both women and their children.', NULL, 'The World Health Organization (WHO) today released its first global guidelines for the management of diabetes during pregnancy, a condition affecting about one in six pregnancies – or 21 million women annually. The new recommendations provide a critical roadmap to tackle this growing health challenge and prevent serious complications for both women and their children.', NULL, 'https://www.who.int/news/item/14-11-2025-who-launches-global-guidelines-on-diabetes-during-pregnancy-on-world-diabetes-day', NULL, NULL, '2025-11-14 08:01:45', '2026-01-25 06:50:32.136375', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:32.136375', '2026-01-25 06:50:32.136375');
INSERT INTO public.radar_items VALUES ('0af4ab10-898e-4259-bd4c-b9df351c46cf', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'ad4c163cb42f15511c3d074e4de80743', 'Egypt becomes the seventh country in the Eastern Mediterranean Region to eliminate trachoma as a public health problem', NULL, 'The World Health Organization (WHO) today announced that Egypt has successfully eliminated trachoma as a public health problem, marking a historic public health milestone for the country and WHO’s Eastern Mediterranean Region (WHO EMR). It is the seventh country in WHO EMR to achieve this milestone. The validation of Egypt’s achievement brings the total number of countries that have eliminated trachoma as a public health problem worldwide to 27.', NULL, 'The World Health Organization (WHO) today announced that Egypt has successfully eliminated trachoma as a public health problem, marking a historic public health milestone for the country and WHO’s Eastern Mediterranean Region (WHO EMR). It is the seventh country in WHO EMR to achieve this milestone. The validation of Egypt’s achievement brings the total number of countries that have eliminated trachoma as a public health problem worldwide to 27.', NULL, 'https://www.who.int/news/item/12-11-2025-egypt-becomes-the-seventh-country-in-the-eastern-mediterranean-region-to-eliminate-trachoma-as-a-public-health-problem', NULL, NULL, '2025-11-12 09:43:51', '2026-01-25 06:50:32.381131', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:32.381131', '2026-01-25 06:50:32.381131');
INSERT INTO public.radar_items VALUES ('aedb78ea-a661-4bb1-a7c9-668825d18ec8', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '583e6dc2851d1c07d3fc915b3c5073c7', 'What TV Gets Wrong About CPR and Why It Matters', NULL, 'Television shows often show CPR incorrectly or with outdated methods. Image Credit: Francesco Carta fotografo/Getty Images A recent analysis by the University of Pittsburgh found that scripted television shows often depict CPR incorrectly when performed by a layperson outside the hospital. The analysis also found that those who receive CPR and where they receive it are not depicted in a way that accurately reflects real life. The researchers noted that this inaccurate depiction of CPR may influe', NULL, 'Television shows often show CPR incorrectly or with outdated methods. Image Credit: Francesco Carta fotografo/Getty Images A recent analysis by the University of Pittsburgh found that scripted television shows often depict CPR incorrectly when performed by a layperson outside the hospital. The analysis also found that those who receive CPR and where they receive it are not depicted in a way that accurately reflects real life. The researchers noted that this inaccurate depiction of CPR may influence how the public reacts to real-life emergency situations. Scripted television shows often depict outdated CPR techniques for non-medical individuals. This can fuel misconceptions and potentially delay the response from bystanders in a real-life moment of cardiac arrest. This is according to a new analysis from the University of Pittsburgh that was recently published in Circulation: Population Health Outcomes. The American Heart Association (AHA) endorsed hands-only CPR in 2008. This is a simpler, faster intervention that was shown to be as effective as the previous process, which included rescue breathing. The American Red Cross also endorses and teaches hand-only CPR in its training for non-medical individuals. “People should be aware [that] what they see on TV regarding CPR may not always be accurate … Getting this right is important from a public health perspective to send the right message to families regarding the time and place for the most effective method to deliver lifesaving CPR: hands-only or chest compressions,” Robert Glatter, MD, Assistant Professor of Emergency Medicine at Zucker School of Medicine at Hofstra/Northwell, and Emergency Department Physician at Northwell Health, told Healthline. “Initiation of chest compressions is the single most important intervention that the public can initiate, particularly in the home setting, before 911 arrives,” he added. Glatter was not involved in the new analysis. How TV shows typically depict CPR incorrectly The researchers analyzed 169 United States television show episodes that portrayed hands-only CPR since 2008, when the AHA first endorsed this process. They found that fewer than 30% of the episodes correctly depicted the steps. Nearly half of the episodes demonstrated outdated practices: 48% showed mouth-to-mouth resuscitation, and 43% showed pulse checks. “There is no added value to [the] performance of mouth-to-mouth breathing or checking pulses when you see a person who is not breathing who has collapsed,” noted Glatter. He further added that &#8220;saving a life&#8221; should focus on &#8220;chest compressions only.&#8221; “This singular intervention has been shown to lead to the greatest chances for survival when a person suffers a cardiac arrest,” he explained. “In general, TV is not always representative of [the] real world of medicine and may depict inaccurate information.” The analysis also found other discrepancies between TV and real life, including who typically receives bystander CPR and where they receive it. The team found that 44% of recipients on TV were between the ages of 21 and 40. In reality, however, the average age of a person receiving CPR is 62. The shows also depicted that 80% of CPR recipients were in public, whereas in actuality, 80% of out-of-hospital cardiac arrests occur in the home. There may also be other ways that TV shows incorrectly depict CPR. “They show poor positioning, not the correct depth (2-2.5 inches), [and] the wrong rate,” noted Kevin Grant, retired Chief of EMS for Cooke County, Texas. Grant has 46 years of experience as a licensed paramedic and was not involved in the study. “All this leads to poor quality of CPR, which leads to poor circulation of blood and O2 [oxygen],” he added. How the way CPR is depicted on TV can impact public perceptions The research team noted that disparities in CPR portrayals on TV can skew public perceptions. “If viewers think cardiac arrest only happens in public or to young people, they may not see CPR training as relevant to their own lives,” Ore Fawole, BS, a recent Pitt graduate who spearheaded the coding and analysis for the study as lead author, stated in a press release. Glatter noted that the power of TV as a medium to “influence practices such as lifesaving medical interventions should not be understated.” He added that this is why it is so important for directors and medical advisors working on TV shows to “get it right.” People will “emulate what they see vs. what is correct,” said Grant. “When they show &#8216;TV CPR&#8217; with their elbows bent doing compressions at the wrong rate, the public will feel this is the correct way, and you cannot get the depth you need to move blood and O2 that is necessary.” While incorrectly showing CPR on TV may cause some issues, it may also have positive impacts just by being shown. “I would stress that any CPR is better than no CPR. If watching a show empowers somebody to attempt bystander CPR when they otherwise would not, I think that&#8217;s a win rather than a loss,” said Elizabeth Hewett Brumberg, MD, Pediatric emergency physician at Children’s Hospital of Pittsburgh of UPMC and member of the American Red Cross Scientific Advisory Council, who wasn&#8217;t involved in the study. How to prepare for an emergency with proper CPR training Being prepared for an emergency is important, especially since most out-of-hospital cardiac arrests happen in the home. Both the American Red Cross and the AHA offer CPR classes to the general public. Some of these courses can even be done online. You may never need to use CPR. However, knowing how to do it properly can be important if you ever find yourself in a situation where it is needed. “Absolutely, take a CPR class. Use your interest in that medical drama to take a CPR class and learn how to do it. Because, in real life, you might save somebody&#8217;s life,” noted Brumberg.', NULL, 'https://www.healthline.com/health-news/what-tv-gets-wrong-about-cpr-and-why-it-matters', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/TV-CPR-GettyImages-2194329836-Header.jpg', NULL, NULL, '2026-01-25 06:50:33.690542', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:33.690542', '2026-01-25 06:50:33.690542');
INSERT INTO public.radar_items VALUES ('04ac6cea-1e2b-46c5-ba35-8d599d7197b7', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'cd5c7337fc0b82f65a6d6f15661c2e4f', 'Heart Disease Deaths Decline, but Remain Leading Cause of Death in U.S.', NULL, 'Heart disease remains the leading cause of death in the United States, while stroke has climbed to the fourth main cause. Busà Photography/Getty Images Deaths from heart disease and stroke are declining, but still kill more Americans than any other cause. New data show progress since the pandemic, yet significant rates of obesity, diabetes, and kidney disease remain major public health obstacles. The findings underscore the importance of better prevention, risk awareness, and health equity. Deat', NULL, 'Heart disease remains the leading cause of death in the United States, while stroke has climbed to the fourth main cause. Busà Photography/Getty Images Deaths from heart disease and stroke are declining, but still kill more Americans than any other cause. New data show progress since the pandemic, yet significant rates of obesity, diabetes, and kidney disease remain major public health obstacles. The findings underscore the importance of better prevention, risk awareness, and health equity. Deaths from heart disease and stroke have declined since the COVID-19 pandemic, but they still kill more people in the United States than any other cause. Heart disease remains the leading cause of death in the United States, while stroke has climbed to the fourth main cause, according to the latest statistics from the American Heart Association (AHA). The report, which includes data up through 2023, marks the reversal of a five-year upward trend. Experts have attributed much of the increase in deaths from heart disease and stroke to effects from the COVID-19 pandemic. Overall, deaths from cardiovascular disease (CVD) — which includes heart disease, hypertension, stroke, and heart failure — declined to 915,973 in 2023, down from 941,652 in 2022, a decrease of about 26,000 deaths or 2.7%. “The revisions indicate to us that we are making some progress,” said Keith C. Ferdinand, MD, Gerald S. Berenson Chair in Preventive Cardiology at Tulane University School of Medicine, who was not involved in the study. But, he said, there is plenty more work to do. Contributing factors for heart disease, stroke The United States may finally be turning a corner, but it must tackle a number of serious contributing factors, including obesity, high cholesterol (hyperlipidemia), and type 2 diabetes, that continue to rise. The report also highlights kidney function as an indicator of cardiovascular health. Kidney disease, alongside these other conditions, is collectively part of a cluster of interconnected diseases known as cardiovascular-kidney-metabolic (CKM) syndrome. To address these challenges, the new report places greater emphasis on health equity — working with populations that have historically been underserved or have borne a disproportionate share of disease burden in the United States. “Heart disease [is] still the number one cause of death in the United States. So if we want to curb the overall increased death rates, then we need to pay more attention to health equity and try to help the people who are struggling to control their risk factors,” Ferdinand told Healthline. Recent decline in heart disease, stroke deaths Heart disease remains the leading cause of death for Americans, and has been for more than 100 years. Coronary heart disease is the most common form of heart disease. It occurs when plaque builds up in the arteries that supply blood to the heart and can lead to a heart attack. In 2023, there were 22,000 fewer deaths linked to coronary heart disease, about 6% less than the year before. But the number of deaths was still overwhelming: 350,000 Americans died from it that year, or about 2 people every 3 minutes. The number of deaths from stroke also fell subtly during that same time period. However, the report notes that for certain age groups, deaths from stroke actually increased. Among young adults ages 25 to 34, stroke deaths rose by more than 8% between 2013 and 2023. That rise is even more striking given that stroke death rates in this age group were flat in the preceding between 2012 and 2022. “This persistent increase that we see in younger people is a sign that we perhaps need to get the message out that in order to curtail the burden of strokes in middle age and older populations, we want young people to identify their risk prior to reaching those ages,” said Ferdinand. Adults ages 85 and older experienced the steepest rise in stroke deaths, increasing by more than 18%. The findings underscore the need for a targeted approach to prevention, especially for specific populations such as young adults who may not be aware of their risk. Obesity, hypertension, other risk factors remain high Despite the modest decrease in deaths from stroke and heart disease, other complications and comorbidities remain stubbornly high in the United States. Nearly half (47.3%) of U.S. adults have some form of hypertension, according to the latest statistics. Between 2022 and 2023, the prevalence of hypertension remained roughly the same. It remains the single most important modifiable risk factor for cardiovascular disease. Type 2 diabetes also remains a major risk factor. Today, nearly 30 million U.S. adults have type 2 diabetes, many of whom are untreated, a major red flag that can trigger a cascade of downstream cardiovascular risk. “Almost 10 million adults are not aware of a diabetes diagnosis. Only a minority of them have their risk factors controlled, with less than a quarter of adults having their blood pressure controlled,” said Sadiya S. Khan, MD, AHA volunteer vice-chair of the statistical update writing group, and professor of cardiology at Northwestern’s Feinberg School of Medicine. Khan wasn&#8217;t involved in the report. The obesity epidemic is also one of the most pressing public health concerns. Similar to hypertension, about half of adults have some form of obesity. But the condition is even more concerning in children. Obesity among children ages 2 to 19 rose from 25.4% to 28.1%. Childhood obesity signals that cardiovascular risk is beginning earlier in life and may compound as children age, increasing the likelihood of heart attack and stroke at younger ages. “There are multiple steps that can be taken in order to address obesity in children, which would then perhaps curtail what we see with obesity and severe obesity climbing in adulthood. But it&#8217;s not easy. There is no silver bullet,” Ferdinand said. The report also acknowledges kidney disease and CKM as indicators of cardiovascular health, and also as potential contributing factors. “We now know that the kidney is the canary in the coal mine,” Ferdinand said. CKM, which links a number of conditions — including heart disease, kidney disease, diabetes, and obesity — is present in the majority of U.S. adults. About 90% of adults have some form of CKM, which is graded on a severity scale from stage 1 to stage 4 based on the presence of different risk factors. More than 80% of young and middle-aged adults also show some early forms of CKM. Tips to promote cardiovascular health The AHA recommends its Life’s Essential 8 system as the foundation for improving cardiovascular health and decreasing risk of heart attack and stroke. The framework recommends how to make effective changes to modifiable risk factors, including: stopping smoking being more active getting healthy sleep managing weight controlling cholesterol managing blood sugar managing blood pressure eating better Making healthy changes is linked to a demonstrable decrease in CVD risk. The report found that across numerous studies, individuals with good cardiovascular health, as measured by Life’s Essential 8, had 74% lower risk of heart attack and stroke, as well as improved brain health and lower risk of dementia. In fact, the report estimates that up to 40% of U.S. deaths could be prevented with optimal scores. “The goal is to start with small, actionable steps,” Khan said, “Social factors are powerful drivers of health across the life course. We need to shift our approach from being reactive to proactive and think about ways to reshape policies and environments to promote lifelong health.&#8221; For individuals who have already had a heart attack or stroke, Life’s Essential 8 is even more important. Both Khan and Ferdinand also emphasize “knowing your numbers,” meaning understanding what your blood pressure, cholesterol, and A1C mean for your health. Ferdinand recommended an initial target goal of lowering blood pressure to less than 130, ideally 120, over 80. Ideally LDL cholesterol levels should be less than 100, or ideally less than 70. For those with diabetes, A1C levels should be less than seven, Ferdinand noted.', NULL, 'https://www.healthline.com/health-news/heart-disease-stroke-deaths-decline-but-remain-leading-cause-of-death', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Heart-disease-GettyImages-947396344-Header.jpg', NULL, NULL, '2026-01-25 06:50:33.870712', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:33.870712', '2026-01-25 06:50:33.870712');
INSERT INTO public.radar_items VALUES ('6aa40f24-acd0-4b0d-9b9f-4c7d5c42ca0e', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '972ac742007f95981bb3405dfe45f527', 'Colorectal Cancer Is Now Leading Cause of Cancer Deaths in People Under 50', NULL, 'Colorectal cancer is now the top cause of cancer-related deaths in the United States, according to a new report. Thomas Northcut/Getty Images Colorectal cancer is now the leading cause of death due to cancer for Americans under 50, rising annually, while deaths from other major cancers have declined over the past decade. Three out of four young patients are diagnosed at advanced stages, when the five-year survival rate drops from 89% to 16%. People at above-average risk should begin screening be', NULL, 'Colorectal cancer is now the top cause of cancer-related deaths in the United States, according to a new report. Thomas Northcut/Getty Images Colorectal cancer is now the leading cause of death due to cancer for Americans under 50, rising annually, while deaths from other major cancers have declined over the past decade. Three out of four young patients are diagnosed at advanced stages, when the five-year survival rate drops from 89% to 16%. People at above-average risk should begin screening before age 45. Stigma around discussing bowel habits and doctors dismissing symptoms in younger patients contribute to late diagnoses. Colorectal cancer has become the leading cause of death due to cancer for people under 50 in the United States. In the early 1990s, the disease ranked fifth. A new report from the American Cancer Society (ACS) examined cancer deaths in younger adults over three decades and found that while overall cancer mortality dropped 44% for this age group, colorectal cancer deaths moved in the opposite direction. It appears to be the only major cancer doing so. The five deadliest cancers for people under 50 are: brain cancer breast cancer leukemia lung cancer colorectal cancer From 2014 to 2023, the report found deaths from four of those cancers declined. Colorectal cancer, any cancer that develops in the colon or rectum, stands alone with mortality rising 1.1% each year since 2005. That steady increase pushed it past lung cancer in 2023 to become the number one cause of death due to cancer. Why is colon cancer rising in young people? Researchers don&#8217;t have a definitive answer on what&#8217;s behind young people developing colorectal cancer, but the evidence right now points to lifestyle and environmental factors. Arif Kamal, MD, chief patient officer for the American Cancer Society, said Americans don&#8217;t eat enough fruits, vegetables, and whole grains, while consuming too much red meat, particularly smoked or highly processed varieties. He noted how obesity increases colorectal cancer risk, and obesity rates are steadily climbing. Another factor, he told Healthline, is that the colon is uniquely vulnerable because &#8220;everything you put into your body, your colon will see.&#8221; Despite these clues, the full picture remains unclear. Anjee Davis, CEO of advocacy organization Fight Colorectal Cancer, told Healthline that answers wouldn&#8217;t be as elusive if cancer were more of a national priority. &#8220;We have to figure out why this keeps rising in young people because in our community, we hear it as young as 11 years old, 17 years old, 20 years old,&#8221; she said. &#8220;It really breaks my heart.&#8221; Early detection for colorectal cancer is crucial The report shows that three out of four patients under 50 receive their diagnosis after the disease has already reached an advanced stage. &#8220;Mortality has everything to do with when you find the cancer in its growth trajectory,&#8221; Kamal said. Early detection dramatically improves survival odds. The Centers for Disease Control and Prevention (CDC) reports that about 89% of people diagnosed at the earliest stage live at least five years. For those diagnosed at the most advanced stage, that figure drops to 16%. A 2024 study found that four to six months typically passed between symptoms appearing and patients receiving a diagnosis. The most common warning signs included: abdominal pain blood in stool changes in bowel habits (i.e., persistent diarrhea or constipation) Other red flags were unexplained weight loss, persistent fatigue, and feeling like a bowel movement isn&#8217;t quite finished. High risk groups: Who should get screened early? While most people should start screening at age 45, family history, genetic conditions, and certain symptoms push that timeline for many. Of those at average risk because of their age, under 30% of 45- to 49-year-olds are up to date on their screenings, according to the CDC and the ACS. That&#8217;s far below the more than 70% of older adults who keep up with screenings. Two demographic groups are at an increased risk. Native Americans and Alaska Natives lead the world in incidences of colorectal cancer, prompting some communities to encourage screenings to begin at 40. Black men die from colon cancer disproportionately, with ACS data showing a more than 40% higher risk of dying than whites, making early screening critical for this group. Family history and genetics Family history requires careful attention. Kamal noted that there is nuance in determining if someone is at an increased risk based on their family history and genetics. Anyone with a parent or sibling who had colon cancer carries an increased risk and should typically start screening 10 years before that family member&#8217;s diagnosis age. For example, someone whose mother was diagnosed at 45 should start screening at 35. The risk extends beyond direct links to colon cancer. Family histories of stomach, pancreatic, or breast cancer also elevate colorectal cancer risk, Kamal said. &#8220;There are certain cancers that run kind of with each other, and in different people show up in different ways.&#8221; Genetic conditions like BRCA2 mutations and inflammatory bowel diseases like Crohn&#8217;s disease or ulcerative colitis also put people in higher-risk categories, he said. Kamal recommended compiling family medical information and bringing it to a doctor&#8217;s appointment. &#8220;Write all that down. Go talk to your doctor,&#8221; he said. Colon cancer stigma may deter early detection Multiple forms of stigma may keep people from getting screened, which experts say helps explain why so many cases reach advanced stages before diagnosis. Lynn Durham, EdD, president and CEO of Georgia CORE and a cancer survivor, sees the reluctance to discuss bathroom habits causing real harm. Her organization recently completed a statewide awareness campaign about recognizing warning signs early. &#8220;People don&#8217;t want to talk about their poop. They don&#8217;t want to talk about anything indelicate like that,&#8221; Durham told Healthline. &#8220;If you have dramatic changes in your stool, there&#8217;s something going on, and you need to see your doctor right away.” Davis advocates for treating bowel health like any other health topic, starting with family conversations. &#8220;When you have a little baby, you&#8217;re talking about their poop all the time,&#8221; she said. &#8220;When&#8217;s the last time they pooped? When&#8217;s the last time you changed their diaper?” Those conversations typically end as children age, but Davis thinks people need to maintain that openness throughout life by asking straightforward questions: How regular are you? Is there a change in your bowel habits? Have you talked to your doctor about poop, rectal bleeding, gas, diarrhea, or constipation? &#8220;We can socialize that this is just a part of gut health&#8230; we just have to make it normalized.” Stigma also affects medical providers. Kamal said many doctors still associate cancer primarily with older adults, creating a blind spot when younger patients report symptoms. Providers rarely ignore a breast lump in a 35-year-old, he noted, but routinely dismiss belly pain and blood in stool as ordinary digestive issues. Doctors and individuals alike often dismiss colon cancer symptoms because they mimic common, minor ailments. Kamal said that&#8217;s part of what drives the mortality rate. Davis said those with symptoms or a higher risk shouldn’t accept dismissive explanations.“If a doctor says, ‘I think you&#8217;re fine. You should just, you know, eat fiber, do fruit shakes’ … Find another healthcare provider,” Davis said. “I really feel like our young onset patients need to be heard, and sometimes they are too scared to say, ‘you know, I need to go find somebody else that will listen to me,’” she said. Colorectal cancer prevention, lifestyle changes While research on cancer prevention continues to evolve, doctors know certain lifestyle changes can make a difference. Limiting red and processed meats and eating more vegetables, fruits, and whole grains may help lower your risk of developing colorectal cancer. Maintaining a healthy weight, exercising regularly, reducing alcohol consumption, and quitting tobacco use can also help. &#8220;It&#8217;s this idea that there are lifestyle changes you can make starting today that&#8217;ll affect your risk of colon cancer 10 years from now,&#8221; Kamal said. For Durham and Davis, the urgency is personal. Durham survived cancer three times. Davis has spent years advocating for patients who were diagnosed too late. &#8220;The fact that this is a preventable cancer makes it tragic,&#8221; Davis said. &#8220;We have it in our power to figure out why. I know we do.&#8221;', NULL, 'https://www.healthline.com/health-news/colorectal-cancer-leading-cause-cancer-related-death-young-adults', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Colorectal-Cancer-GettyImages-sb10069454g-001-Header.jpg', NULL, NULL, '2026-01-25 06:50:33.994785', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:33.994785', '2026-01-25 06:50:33.994785');
INSERT INTO public.radar_items VALUES ('9fd2e422-fe1a-4f33-a1b1-8aa626152f8c', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'f317f47df47605e1fcd77493b85115b3', 'Age Menopause Begins May Affect Stroke, Metabolic Syndrome Risk. Here''s How', NULL, 'Recent studies have shown that the age of menopause onset can influence various health outcomes. The Good Brigade/Getty Images One study found that early natural menopause may be associated with a 27% higher risk of metabolic syndrome. Another study shows that later-onset menopause may have a lower risk of heart attack and stroke. Recent research found that muscle health scores were lower in postmenopausal females than in non-menopausal individuals. Menopause is a natural part of the aging proce', NULL, 'Recent studies have shown that the age of menopause onset can influence various health outcomes. The Good Brigade/Getty Images One study found that early natural menopause may be associated with a 27% higher risk of metabolic syndrome. Another study shows that later-onset menopause may have a lower risk of heart attack and stroke. Recent research found that muscle health scores were lower in postmenopausal females than in non-menopausal individuals. Menopause is a natural part of the aging process. It marks the time in a person’s life when their period has been absent for 12 consecutive months, and they can no longer become pregnant. A large-scale 2025 study found that early natural menopause may be linked to a 27% higher risk of metabolic syndrome compared to later onset menopause. The findings were presented at the 2025 Annual Meeting of the Menopause Society. This research has not yet been published in a peer-reviewed scientific journal. However, the findings underline the importance of early screening and prevention. Another 2025 study found that those who begin menopause at age 55 years and older have healthier cardiovascular systems than those who stopped menstruating earlier. The findings help explain why females who enter menopause later have a lower risk of heart attack or stroke. Biomarkers in urine may be able to detect early stage sarcopenia (muscle loss) in menopausal females, according to a 2025 study. The findings of the study were presented at the 2025 Annual Meeting of the Menopause Society. This research has not yet been published in a peer-reviewed journal. Early menopause linked to metabolic syndrome The researchers analyzed the electronic health records from more than 234,000 females who had experienced natural menopause between the ages of 30 and 60. The team looked at the prevalence of metabolic syndrome and examined how this prevalence varied based on the age at which menopause began. Metabolic syndrome is a group of conditions that raise a person’s risk of serious health issues, such as: diabetes stroke coronary heart disease It has a combination of risk factors, such as obesity, high blood pressure, and elevated blood sugar. The researchers found that among those who began menopause early, 13.5% were diagnosed with metabolic syndrome. Whereas, only 10.8% of those with later menopause had the condition. The difference translated to a 27% increased relative risk of metabolic syndrome among those who experienced early menopause. “Recognizing early menopause as a marker for metabolic syndrome gives clinicians a crucial window to identify at-risk women sooner and intervene earlier to prevent heart disease, diabetes, and other complications,” Shefali Setia Verman, PhD, assistant professor of Pathology and Laboratory Medicine at the University of Pennsylvania, and co-author of the study, stated in a press release. Late onset menopause and cardiovascular risk The study offered insight into why females who experience menopause later have a lower risk of heart attack and stroke. The authors of the study explained that reduced levels of certain triglyceride-derived lipid metabolites contributed to lower oxidative stress, which leads to improved endothelial function. When there is endothelial dysfunction, blood flow to the heart is restricted, which may lead to heart attacks in females. Understanding these factors may help physicians personalize care for females throughout their lifetimes, reducing the risk of heart disease. This is significant because, according to the Centers for Disease Control and Prevention (CDC), heart disease is the leading cause of death among females in the United States, affecting more than 60 million. A female’s age at menopause can make a difference. If she begins menopause at 55 or older, her likelihood of developing heart disease is up to 20% lower than someone who stops having their menstrual cycle at a younger age. The researchers measured brachial artery flow-mediated dilation in 92 females to assess how the upper-arm artery dilates when blood flow increases. They also measured their mitochondrial health and ran hormone tests to confirm menopause. They also conducted analyses to determine what factors contributed to differences in mitochondrial reactive oxygen species bioactivity and endothelial function. There was a difference between the late-onset menopause group and those who stopped menstruating earlier. The late-onset group had 24% worse vascular function than premenopausal females. The normal-onset group had 51% worse vascular function than premenopausal females. This led the authors to suggest that females who go through later menopause are protected from the vascular dysfunction that can arise from oxidative stress. How menopause impacts muscle health Menopause is known to accelerate muscle loss due to hormonal changes, especially the reduction in estrogen levels. Current identification of the deterioration in the muscles is limited to DEXA scanning. This is expensive, often inaccessible, and not practical for routine monitoring. A research team from Dalhousie University in Halifax, Nova Scotia, Canada, identified a novel urine biomarker that showed significant differences in muscle health between menopausal and nonmenopausal individuals. This was based on data from 113 participants. The study results were presented in a poster at the Menopause Society 2025 Annual Meeting. They have not yet been published in a peer-reviewed scientific journal. The researchers collected urine samples from 85 individuals currently in menopause and 28 who were not menopausal after overnight fasting. They identified five key metabolites related to muscle metabolism. They then used a proprietary algorithm to combine biomarker concentrations into a single muscle health score for each participant. The results were 91% concordant with the DEXA scan results for sarcopenia detection. Muscle health scores based on biomarkers were significantly lower in menopausal individuals than in nonmenopausal individuals (44.21% vs. 53.98%). Menopausal individuals also showed lower levels of protein synthesis and higher levels of oxidative stress. “We know that there are bone and muscle changes associated with menopause and aging,” Stephanie Faubion, MD, medical director of North American Menopause Society, who was not involved in the study, noted in an interview for a press release. Faubion added that understanding the dynamic muscle changes that occur in midlife and menopause can be useful, she added. However, she cautioned that the study&#8217;s findings were limited by a small sample size. More research is needed to clarify the measurement of muscle health and ensure the results have clinical implications.', NULL, 'https://www.healthline.com/health-news/menopause-onset-stroke-metabolic-syndrome-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Age-Menopause-GettyImages-1305666141-Header.jpg', NULL, NULL, '2026-01-25 06:50:34.116389', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.116389', '2026-01-25 06:50:34.116389');
INSERT INTO public.radar_items VALUES ('cd5e2aa4-52e8-4853-9921-e666a9883915', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '0158c516c461c60155fd425a691148fc', 'Doctor Shares What ‘The Pitt’ Gets Right About Real Emergency Rooms', NULL, 'Does the hit TV series “The Pitt” accurately depict what it’s like to work in a real ER? Photograph by Warrick Page/HBO Max This month, “The Pitt” won a Golden Globe, including Best Drama Series and Best Actor for Noah Wyle. The Emmy-winning emergency medicine drama is driving conversation across entertainment and healthcare. One ER doctor in Connecticut shares what he thinks the show gets right and where it takes creative liberty. Over the past year, Steven Valassis, MD, Emergency Medicine Phys', NULL, 'Does the hit TV series &#8220;The Pitt&#8221; accurately depict what it&#8217;s like to work in a real ER? Photograph by Warrick Page/HBO Max This month, &#8220;The Pitt&#8221; won a Golden Globe, including Best Drama Series and Best Actor for Noah Wyle. The Emmy-winning emergency medicine drama is driving conversation across entertainment and healthcare. One ER doctor in Connecticut shares what he thinks the show gets right and where it takes creative liberty. Over the past year, Steven Valassis, MD, Emergency Medicine Physician at Hartford HealthCare, said he can’t get through a shift in the emergency department without a patient asking whether he has watched &#8220;The Pitt.&#8221; “Curious, I decided to watch &#8216;The Pitt&#8217; with my family. My children were immediately captivated. Suddenly, they had more questions than ever about my shifts, my experiences, and how the events in the first season compared to real life,” he told Healthline. “It has been remarkable to see how this show introduced a new generation to emergency medicine—and to witness my own family’s reactions to the raw, unfiltered story lines.” Healthline asked Valassis to share what he thinks the show gets right and wrong about working in the ER. This interview has been edited and condensed for clarity and length. How realistic is The Pitt’s portrayal of real ERs? Valassis: &#8220;The Pitt&#8221; offers a striking and compelling portrayal of emergency medicine, particularly within a busy urban emergency department. In conversations with my colleagues, I have found that people tend to fall into one of two camps: those who are captivated by how authentically the show reflects our experiences bringing the realities of emergency care to a broad audience, and those who find it almost too realistic—so much so that watching an episode can feel like being back on shift, making it hard to unwind. The first season alone touches a wide range of themes: overcrowded emergency departments trying to care for every patient in need, the profound challenges of mental health and substance abuse, and the escalating violence experienced in our world that often spills into our emergency departments. It also highlights how the very clinicians dedicated to easing suffering can themselves become victims. What does the show nail about real emergency departments? Valassis: &#8220;The Pitt&#8221; captures the authenticity of the emergency department remarkably well. It offers a true sense of what it is like to work in a fast-paced environment filled with interruptions and constantly shifting priorities. The show conveys the raw emotions of the patients and their loved ones as they traverse through their visit, while also highlighting the humanity of the caregivers navigating difficult and often heartbreaking situations. It shows how, after these intense moments, the staff must immediately pivot to the next emergency&#8211;often without the chance of processing the emotions of what they just experienced. The show recognizes this emotional burden and the consequences that can arise when it is not balanced with healthy coping mechanisms. The camera work in &#8220;The Pitt&#8221; immerses viewers in the experience of navigating a busy shift. The show goes to great lengths to ensure medical accuracy—from the physical layout to the medications, treatments, and procedures portrayed. Viewers get a tremendous sense of what it is like to perform these emergency procedures. The show also has an honest portrayal of difficult patient encounters. In many ways, it serves as a primer on patient care—highlighting both effective approaches to complex situations as well as those that fall short. It underscores that the education of the residents extends far beyond medical knowledge, capturing the importance of connecting with patients and trying to meet them where they are. While I firmly believe that working in the emergency department is one of the most rewarding vocations, the series accurately portrays the emotional toll it can take on the staff. The burnout is real, and the show does not shy away from that truth. Where does the show take creative liberties? Valassis: &#8220;The Pitt&#8221; understandably takes creative liberties in compressing many dramatic events that might unfold over several weeks in a real emergency department into the span of one single shift. Since each season represents just one emergency department shift, it is best viewed as a concentrated collection of the most intense and compelling moments encountered over time. That said, there are truly no dull days in the emergency department. Is the ER always as chaotic as it is on the show? Valassis: Of course not. While there is so much that is relatable, they take poetic license by packing so many dramatic events into a single shift. In the emergency department, we pride ourselves on creating calm in moments of chaos. There is nothing more impressive than watching the team work as a well-orchestrated unit while resuscitating a cardiac or trauma patient. In those moments, the resuscitation becomes remarkably quiet as each member carries out their role with precision, working together seamlessly to care for a critically ill patient. What is the truth about patient flow, staffing realities, and what a “typical” shift really looks like? Valassis: Emergency departments are busier than ever. There is a shortage of primary care doctors, limited access to timely care for those who are uninsured and underinsured, and a significant mental health crisis. Over my last two decades in practice, the advancement of medical care has grown exponentially. Additionally, through the pandemic, many exited healthcare. While most emergency departments can staff appropriately for much of the year, challenges intensify in times of surge. At Hartford HealthCare, we have a centralized center that has visibility to all the open beds across our health system, so that we can provide the best care for our patients. We also recognized the need to provide access to primary care by creating HHC 24/7, an app connecting patients to primary care providers anytime, anywhere. How are behavioral health emergencies reshaping emergency medicine? Valassis: There must be a stronger focus on mental health and substance abuse treatment in the U.S. These emergencies are common, yet there remains a shortage of inpatient behavioral health beds. When these specialized beds are full, patients requiring psychiatric admission are forced to remain in the emergency department. As you can imagine, a fast-paced, highly stimulating ED environment is far from the ideal for their recovery. I am blessed to be an emergency medicine physician at St. Vincent’s Medical Center. Our emergency department has a highly specialized behavioral health unit that is dedicated to the needs of the community. For patients requiring further treatment, St. Vincent’s Behavioral Health Services offers advanced care at our Westport, CT, campus. What do you wish more people understood about ERs and the healthcare professionals who work there? Valassis: I feel truly humbled to work alongside such a dedicated and talented team—people who take immense pride in caring for our community. We are here 24/7. Days and nights, weekdays and holidays, we are here. Our patients often arrive at their most vulnerable, in physical or psychological distress. We often meet them on one of the worst days of their lives—whether experiencing a stroke, a heart attack, an overwhelming infection, or a devastating accident. We diagnose tough conditions, manage critical situations, and support patients and their families through every step. We save lives, rule out emergency conditions, and we also strive to provide dignity and comfort to those who are dying. We take pride in being a true safety net for our community—we are here for everyone. Whether you come from an exclusive zip code or a tent under the highway, we are here for you.', NULL, 'https://www.healthline.com/health-news/the-pitt-tv-real-emergency-rooms', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/the-pitt-still-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:34.239753', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.239753', '2026-01-25 06:50:34.239753');
INSERT INTO public.radar_items VALUES ('7a363129-96f6-4949-8fd5-513207431f04', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '967d50ffb6b45eff372c8258fd2ab887', 'Pediatricians, Major Medical Groups Ignore RFK Jr.’s New Vaccine Schedule', NULL, 'Many children’s medical offices and state health departments aren’t in compliance with the CDC’s new child vaccine guidelines. Robert Michael/picture alliance via Getty Images Pediatric medical professionals are pushing back against new CDC recommendations that implemented major changes to the childhood immunization schedule. Many pediatricians rely on advice from the American Academy of Pediatrics (AAP), as major medical organizations have filed a lawsuit against the CDC. Healthline spoke with ', NULL, 'Many children&#8217;s medical offices and state health departments aren&#8217;t in compliance with the CDC&#8217;s new child vaccine guidelines. Robert Michael/picture alliance via Getty Images Pediatric medical professionals are pushing back against new CDC recommendations that implemented major changes to the childhood immunization schedule. Many pediatricians rely on advice from the American Academy of Pediatrics (AAP), as major medical organizations have filed a lawsuit against the CDC. Healthline spoke with pediatricians and physicians to learn more about the possible risks that could result from the changes to child vaccine guidelines. Pediatricians have raised serious concerns about the Centers for Disease Control and Prevention&#8217;s recent changes to its vaccination schedule for children, which cut vaccination against 16 diseases down to 11. The new CDC guidelines, released on January 6, now recommend hepatitis A, hepatitis B, and meningococcal vaccines only for higher-risk children. Rotavirus, COVID-19, and flu vaccines moved to a new &#8220;shared clinical decision-making&#8221; category, encouraging parents to consult their doctor before deciding. All vaccines remain available for families who want them, and insurance must cover the full cost. The Trump administration said the health policy shift fulfilled a campaign promise. &#8220;Americans voted for transparency and HHS is delivering it,&#8221; Emily Hilliard, press secretary for the U.S. Department of Health and Human Services, told Healthline. She said the new guidance relies on &#8220;trust, education, and strong doctor-patient relationships.” However, many children&#8217;s medical offices and state health departments aren&#8217;t in compliance with the new guidelines. Many are adhering to recommendations from the American Academy of Pediatrics (AAP) instead. Some major medical groups have also filed a lawsuit against the CDC to block the new recommendations. The plaintiffs include the AAP and its Massachusetts chapter, the American College of Physicians, the American Public Health Association, the Infectious Diseases Society of America, the Massachusetts Public Health Association, and the Society for Maternal-Fetal Medicine. Healthline spoke with pediatric healthcare professionals to learn more. New childhood vaccine schedule raises &#8216;everyone&#8217;s risk&#8217; For pediatricians who&#8217;ve seen these diseases firsthand, the changes are confusing. Amanda Furr, MD, chief medical officer of Zarminali Pediatrics, which operates clinics in 10 states, said her heart sank when she heard the news. She recalled working in hospitals when infants arrived severely dehydrated from rotavirus. &#8220;You&#8217;d do everything to try to even get an IV because they were so dehydrated.&#8221; Helena Bentley, MD, who owns Kid Care Pediatrics in Georgia, trained when these diseases were still common. &#8220;I saw the complications,&#8221; she said. &#8220;The reason I don&#8217;t see them now is because of vaccines.&#8221; She described a former employee&#8217;s son left severely disabled by meningitis, and children who lost limbs or died within 24 hours of infection. Benjamin Lopman, PhD, an epidemiologist at Emory University&#8217;s Rollins School of Public Health, has spent more than a decade researching rotavirus vaccines. He pointed to last year&#8217;s measles outbreaks in the Southwest, which began in communities with low vaccination rates. Measles is a disease that the CDC declared eliminated from the United States in 2000. However, ongoing U.S. outbreaks have put the nation at risk of losing its measles-free status. &#8220;If vaccine coverage goes down, it increases everyone&#8217;s risk, not just the kids who missed the vaccine,&#8221; Lopman said. Vaccine science hasn&#8217;t changed The medical professionals interviewed by Healthline say they can&#8217;t implement changes that aren&#8217;t backed by science. They emphasized that the scientific evidence supporting these vaccines remains strong. &#8220;Nothing has changed as far as our understanding of the science of these vaccines, how effective they are, how well they work,&#8221; Lopman said. &#8220;They&#8217;re the best tools we have for avoiding most of these infections. And nothing has changed about our understanding of the safety as well. These changing guidelines is not about new science. It&#8217;s about politics.&#8221; Furr said her organization is following AAP guidelines, not the CDC&#8217;s new recommendations. &#8220;Our patients deserve science and evidence,&#8221; she said. &#8220;I&#8217;m not going to be pressured from one more source to do what is not right for patients.&#8221; Some children&#8217;s hospitals have taken similar positions. The newly-formed West Coast Health Alliance — California, Oregon, and Washington — announced on January 5 that it would follow AAP recommendations. A week later, a coalition of eight northeastern states and jurisdictions followed suit, warning the changes could leave children &#8220;more vulnerable to preventable illness and death.&#8221; Patient care impacts Furr and Bentley said that since the COVID pandemic, parents&#8217; conversations about vaccines have increased, giving them the opportunity to talk through concerns. &#8220;I go over all the vaccines that are due, explain what they are,&#8221; Bentley said. &#8220;We have those conversations and it&#8217;s still up to the parents to get it.” Those conversations, though, are increasingly shaped by what parents see on social media and sometimes laced with misinformation. Parents know their children. Doctors know the science. For years, that partnership worked for the most part. But misinformation and political rhetoric appear to be disrupting a partnership both sides value. &#8220;The parents don&#8217;t want that. They want to trust us, and we want them to trust us and work together as a team,&#8221; Furr said. Bentley worried the current climate &#8220;is going to feed into the frenzy that people already have and their lack of confidence in what they&#8217;re doing and what we&#8217;re recommending.&#8221; Furr said the challenge is conveying urgency without seeming alarmist. &#8220;People don&#8217;t understand how bad this can be because vaccines work,&#8221; she said. &#8220;How do you tell those stories in an exam room without people thinking this is dramatic or you&#8217;re just trying to scare me? We&#8217;re trying to inform them.” Weakened herd immunity A major concern is weakening vaccine coverage. As states and local communities set their own vaccine mandates, Lopman predicts the country will see widening gaps in protection from these vaccine-preventable diseases. Lopman pointed to rotavirus as an example. &#8220;It doesn&#8217;t require the pathogen to be introduced. It’s here already circulating.&#8221; These diseases haven&#8217;t disappeared; they&#8217;re held in check by vaccination. &#8220;If there are more susceptible kids because they haven&#8217;t been vaccinated, we will see more disease, we will see more hospitalizations and we may even see some deaths occur,” he said. Shared clinical decision-making The vaccines moved to &#8220;shared clinical decision-making&#8221; protect against serious illnesses. Influenza and COVID-19 vaccines are the two vaccines in this new category that parents have more likely had conversations about with physicians. The others are less familiar. Meningococcal disease Meningitis is a contagious bacterial infection that can kill within hours, according to the CDC. Teenagers are especially vulnerable because of how they live: in close groups, away from parents who might recognize early symptoms. Two vaccines protect against it — Meningococcal ACWY, given at ages 11 and 16, and Meningococcal B, given at 16 or 17 as teens prepare to leave home. Survivors often face permanent consequences, including vision loss, hearing loss, and loss of motor function or speech. “Very few people recover from true bacterial meningitis without some consequence,&#8221; Furr said. Of all the changes, Furr said this one hit hardest. &#8220;No amount of healthy, athletic, well-balanced diet can protect you against meningitis. It comes for everybody the same.&#8221; Rotavirus Rotavirus is a contagious viral infection of the gut spread through hands and food contaminated with stool, according to the CDC. It causes severe diarrhea and dehydration. It can be fatal, especially for infants. An oral vaccine is given to babies starting at 2 months old, either as a two-dose series (RV1) or three-dose series (RV5). &#8220;Babies can become dehydrated in 24 to 48 hours with this disease and typically require a hospital stay in order to rehydrate them,&#8221; Furr said. Lopman worries the new classification will undermine the highly effective vaccine. &#8220;We&#8217;re going to see a reduction in coverage, and we know exactly what happens when vaccine coverage falls — especially for a virus like rotavirus, which is endemic. It&#8217;s always with us.&#8221; Hepatitis A and B Hepatitis A and B are contagious viral infections of the liver that can lead to liver failure and death, according to the CDC. Hepatitis B spreads through infected body fluids. A three-dose vaccine series is given to infants ages 2 to 18 months. According to the CDC, the shot can be given in 2, 3, or 4 doses, depending on the vaccine brand, your age, and overall health. The new CDC guidelines still recommend vaccination for high risk groups, but that assumes people know they&#8217;re in one. Many don’t. Cases have dropped dramatically since the vaccine was introduced. &#8220;20 years ago, we would see kids on the transplant list because of early exposure to Hep B,&#8221; Furr said. &#8220;It&#8217;s rare now, but the consequences are devastating.&#8221; Hepatitis A spreads through contaminated food or drink or close contact. A two-dose series is given between 12 and 23 months — &#8220;when everything is going in the mouth,&#8221; Furr said. Illness in infants can be more severe and prolonged. For both, she emphasized the even though infections are more rare, ”nobody cares about statistics when it&#8217;s your kid.&#8221;', NULL, 'https://www.healthline.com/health-news/doctors-pediatricians-ignoring-new-vaccine-guidelines', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Vaccine-Guidelines-GettyImages-1237584799-Header.jpg', NULL, NULL, '2026-01-25 06:50:34.363483', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.363483', '2026-01-25 06:50:34.363483');
INSERT INTO public.radar_items VALUES ('28b95627-81c1-40ac-a144-fda1918984f8', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'c677abdbbeb6e6021a4675f4ef7e6b58', 'U.S. Poised to Lose Measles Elimination Status Amid Ongoing Outbreaks', NULL, 'The United States recorded a 33-year high in measles cases in 2025, the highest level of U.S. measles cases since 1992. Jan Sonnenmair/Getty Images The United States is at risk of losing its measles elimination status, which it has held since 2000. The designation may be revoked because in 2025, the U.S. experienced its highest number of measles cases since 1992. Experts say the upward trend may continue in 2026 due to vaccination hesitancy and conflicting messaging from federal health officials', NULL, 'The United States recorded a 33-year high in measles cases in 2025, the highest level of U.S. measles cases since 1992. Jan Sonnenmair/Getty Images The United States is at risk of losing its measles elimination status, which it has held since 2000. The designation may be revoked because in 2025, the U.S. experienced its highest number of measles cases since 1992. Experts say the upward trend may continue in 2026 due to vaccination hesitancy and conflicting messaging from federal health officials. The United States may soon lose its measles exemption status, which it has held for the past quarter-century. The Pan American Health Organization (PAHO), an arm of the World Health Organization (WHO), is scheduled to evaluate U.S. measles data sometime in 2026. In November 2025, PAHO officials announced that Canada had lost its measles exemption status due to ongoing outbreaks. The U.S. measles exemption status has been in place since 2000, when only 86 cases were reported to the Centers for Disease Control and Prevention (CDC). By mid-January 2026, the CDC had confirmed 171 measles cases in 9 U.S. jurisdictions: Arizona, Florida, Georgia, North Carolina, Ohio, Oregon, South Carolina, Utah, and Virginia. So far, no cases among international visitors to the United States have been reported. The bulk of these cases have occurred in South Carolina, where 145 cases were reported to the CDC as of January 13. Since October, 585 measles cases were confirmed in the state. In 2025, the United States recorded a 33-year high in measles cases, with the CDC confirming 2,242 cases nationwide. That was the highest level of U.S. measles cases since 1992. CDC officials reported that 89% of the 2025 cases were associated with 49 outbreaks in various regions of the country. About a quarter of the cases were in children under 5 years of age. About 93% of cases occurred in unvaccinated people or those with unknown vaccination status. Three deaths and 245 hospitalizations were attributed to the measles outbreaks. Nathan Lo, MD, an assistant professor of medicine at Stanford University, said there&#8217;s a simple explanation for the sharp rise in measles cases in the United States. “Measles cases were high in 2025 due to declining vaccination in the U.S. and high measles circulation globally,” Lo told Healthline. Lo said the trend indicates that measles cases will continue their upward trend this year. “So far, measles cases continue to demonstrate sustained circulation in the U.S., which suggests the U.S. will have another year of high measles cases,” he continued. Federal health officials appeared to downplay the continued spread of measles. CDC principal deputy director Ralph Abraham claimed that the ongoing spread is &#8220;just the cost of doing business,&#8221; suggesting transmission was inevitable due to international travel to and from the United States. Why are measles cases rising? Experts say there is a simple reason why measles can spread so rapidly It’s one of the most contagious diseases on the planet. “It’s unbelievably contagious. It’s the most contagious disease we’ve ever seen,” said Danelle Fisher, MD, a pediatrician at Providence Saint John’s Health Center in Santa Monica, California. She noted that people with measles can be contagious 4 days before symptoms emerge and 7 to 10 days afterward. “Measles is a highly contagious disease that can turn deadly,” added Anne Liu, MD, a clinical associate professor of pediatrics, immunology, and allergy at Stanford University. “People who are unvaccinated and people who are immunocompromised should be quite concerned about the growing footprint of this outbreak,” Liu told Healthline. Experts say that vaccine misinformation and ongoing hesitancy are major factors in the sudden rise in measles cases in the United States. “With continued vaccine hesitancy, and the number of mistruths on social media and the community, and the confusing and conflicting recommendations coming from the FDA and CDC, there is every reason to suspect that more parents/guardians will decline routine childhood vaccinations, including measles vaccinations,” said Graham Tse, MD, a pediatrician and chief medical officer of MemorialCare Miller Children’s & Women’s Hospital in Long Beach, CA. “It is likely that measles outbreaks will continue, and the numbers could rise in 2026,&#8221; Tse told Healthline. Recent research has demonstrated the impacts of vaccine hesitancy. A 2025 study published in JAMA Network Open found that measles-mumps-rubella (MMR) vaccination rates remained below the 93% herd immunity threshold. The study examined 149,000 children in Ohio spanning 20 months from the initial onset of the 2025 measles outbreak. William Schaffner, MD, an infectious disease specialist and professor of medicine at Vanderbilt University in Nashville, Tennessee, reaffirmed the importance of measles vaccination. “Vaccination is the way to prevent measles. There are no other ways,” Schaffner told Healthline. Other experts agreed. “The vast majority of measles cases are in unvaccinated individuals, including in children too young to be vaccinated,” Lo said. “The best way to prevent measles and its spread is through vaccination.” “Measles is a highly contagious disease so one infected person can spread it to many others,” Tse added. Changes to childhood vaccine guidelines In early January, federal health officials released new vaccination recommendations for children. The guidelines reduce the number of primarily targeted diseases from 16 to what the Department of Health and Human Services (HHS) has described as the 11 “most serious infectious diseases.” Vaccination against measles is still recommended as are inoculations against chickenpox, polio, and whooping cough. The CDC, however, revised recommendations on six other diseases to include only children who are at higher risk of infection. Those diseases include hepatitis and respiratory syncytial virus (RSV). CDC officials added that vaccinations for children against influenza, COVID-19, and rotavirus should be based on “shared clinical decision-making,” which means parents must consult with a healthcare professional before their children receive the vaccinations. Experts say these new guidelines could led to confusion or skepticism that will further lower childhood vaccination rates. “The changes to the childhood vaccination schedule and subsequent conflicting recommendations with national organizations and states now create confusion with parents and guardians and ultimately may cause increased vaccine declination,” Tse said. What to know about measles Measles caused more than 3 million illnesses annually in the United States before the vaccine became widely available in the mid-1950s. Those cases resulted in 48,000 hospitalizations and 500 deaths annually. The virus is transmitted through the air or by direct contact with a surface that has droplets that contain the virus. Symptoms will usually appear within 14 days. Those symptoms include: widespread skin rash high fever cough sore throat About 30% of measles cases lead to some form of complication, the most common being ear infections and diarrhea. Serious complications are rare, but they include: pneumonia encephalitis subacute sclerosing panencephalitis Liu said there is also a long-term consequence to measles. “One of the lesser-known features of measles is that it can wipe out part of a person’s immune memory from prior infections, leaving them vulnerable to infections they have previously had and successfully battled,” she said. How to lower your risk of measles Experts say there are precautions you can take to lower your risk of contracting measles. The number one way is through vaccination. “The best way to prevent the spread of measles is through routine vaccination for measles,” said Tse. “Once enough of the population has immunity to measles through vaccination, the measles virus cannot spread easily and cause outbreaks. Fisher urges parents to ensure that children have received their recommended vaccines. She also recommended that adults who are unvaccinated or are unsure about their vaccination status get immunized. She said the vaccines not only protect an individual but also children and adults who can’t get vaccinated due to medical treatments or compromised immune systems. “It’s incumbent on all of us to protect the most vulnerable in our society,” Fisher said. Schaffner agreed. “There are many children and adults living among us who are immunocompromised. If they were to contract measles, they would get very sick,” he said. “We all protect them by being vaccinated and creating a ‘cocoon’ of protection around them, making it difficult for the virus to get past us to find them.” Fisher cautioned unvaccinated people from taking planes, trains, or any other form of mass transportation. She said this group should only consider essential travel. She added that you can also make adjustments at your job to lower the number of people you come into contact with. People who work at or visit schools or healthcare facilities should take extra precautions. In addition, Fisher advised everyone to be cautious around anyone with a cough or other symptoms of measles. “Be very wary of anyone with any kind of upper respiratory illness,” she said. Even going to the grocery store might be risky for those who aren’t vaccinated. Fisher added that people who have had the disease or are fully vaccinated don’t have much to worry about. “You’re not going to get sick and you’re not going to spread it,” she said.', NULL, 'https://www.healthline.com/health-news/us-measles-outbreak-2026', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Measles-Outbreak-GettyImages-2202122308-Header.jpg', NULL, NULL, '2026-01-25 06:50:34.488093', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.488093', '2026-01-25 06:50:34.488093');
INSERT INTO public.radar_items VALUES ('5122900d-865b-4c57-9f48-33094ac9c92b', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '958c08fc9dfeebfff630b51fcdd38007', 'Can TikTok’s 75 Medium Challenge Help You Lose Weight and Increase Fitness?', NULL, 'The 75 Medium challenge may help people build healthy, sustainable habits that lead to weight loss and improved fitness. Getty Images 75 Medium is a new trend that’s gaining popularity on social media platforms like TikTok. It’s designed as a more sustainable alternative to the 75 Hard challenge. It includes daily movement, flexible nutrition, and mindset habits. Experts say the 75 Medium challenge may help people lose weight and improve fitness by making sustainable, realistic lifestyle changes', NULL, 'The 75 Medium challenge may help people build healthy, sustainable habits that lead to weight loss and improved fitness. Getty Images 75 Medium is a new trend that&#8217;s gaining popularity on social media platforms like TikTok. It&#8217;s designed as a more sustainable alternative to the 75 Hard challenge. It includes daily movement, flexible nutrition, and mindset habits. Experts say the 75 Medium challenge may help people lose weight and improve fitness by making sustainable, realistic lifestyle changes. If you’ve scrolled TikTok recently, you might have seen #75Medium popping up in your feed The 75 Medium Challenge is the latest spin on the 75-day challenge trend that exploded with 75 Hard, but without the gruelling rules that made that version so intimidating. Unlike 75 Hard, which asks participants to complete two 45-minute workouts a day, follow a strict diet with no cheat meals or alcohol, and restart from day one if any task is missed, 75 Medium aims to be more sustainable for everyday life. It’s positioned as a middle ground between 75 Hard and the more flexible 75 Soft, which gained traction as a gentler alternative. Instead of extreme measures, 75 Medium includes 45 minutes of daily movement, a 90/10 diet approach, moderate hydration goals, no alcohol, 10 minutes of daily learning, and 10 minutes of daily meditation. The challenge is championed by many who advocate a more sensible and sustainable approach to fitness and weight loss, especially for beginners making new lifestyle changes. How the 75 Medium challenge can aid weight loss and boost fitness “The 75 Medium challenge sits in a far more realistic middle ground than 75 Hard, while still offering more structure than 75 Soft,” James Bickerstaff, a personal trainer at OriGym told Healthline. “Compared to 75 Hard, which many people find unsustainable due to its intensity and all-or-nothing rules, 75 Medium removes some of the extreme pressure while keeping daily consistency at the core,” he added. Bickerstaff said for many people this version will be more sustainable long term, because it recognizes that progress comes from repeatable habits, not perfection. Still, some might question if 45 minutes of daily movement is enough, but Bickersaff believes it is. “From a fitness perspective, 45 minutes of daily movement is a strong baseline for improving health, fitness, and body composition,” he noted. “For many, 45 minutes of daily exercise is enough to improve cardiovascular fitness, build routine, and support weight loss when it’s paired with healthy, moderate eating.” Kathrine Brown, certified coach and founder of Conscious Weight Loss, agreed. “45 minutes of daily movement will be enough if the movement is appropriate, enjoyable, and repeatable,” she told Healthline. “This is because weight loss doesn’t come from heroic workouts; it comes from reducing friction around consistency. A daily walk done with presence will always outperform sporadic, intense training.” 90/10 diet rule: a healthier approach to weight loss Another key component of the 75 Medium challenge is sticking to your chosen diet 90% of the time, leaving room for treats. But are people likely to see weight-loss results with this mindset? Bickerstaff said the 90/10 rule can remove the guilt cycle that derails most diets. “Allowing even the smallest bit of flexibility helps you stay consistent without feeling restricted or deprived, which is often why stricter challenges fail,” he explained. “Weight loss is still very achievable with this mindset, because consistency over a long time matters far more than short-term perfection.” Brown said this is one of the most positive aspects of the 75 Medium challenge. “The nervous system learns through repetition, not punishment. A 90/10 approach allows learning to occur while behaviour is still imperfect, while also reducing the “what-the-hell” effect after small setbacks,” she shared. However, Brown believes some people may be better off starting with even more flexibility around diet. “I would go further and say start with 67/33, where 2 out of 3 choices are leading you in a better direction. Then build to 90/10,” she said. “Will people lose weight this way? Often, yes, because they stay engaged long enough for patterns to actually shift. Weight loss comes from consistency, not moral purity around food,” she added. 75 Medium may also boost mental health The 75 Medium Challenge isn’t just about what you eat or how frequently you exercise. It also encourages mindfulness and mental health habits. Brown noted that this can positively influence some behaviors related to diet and exercise. “Daily learning and meditation build conscious windows between urge and action, and increase emotional regulation,” she said. Bikerstaff agreed. “Building mental routines alongside physical ones creates a more resilient approach to health rather than a short-term challenge mindset,” he said. “Think about it, how many times have you made [an unhealthy] eating choice after a stressful day? When you manage your stress better, you recover better, make smarter food choices, and miss fewer workouts.” How to make the 75 Medium challenge work for you If you’re considering trying 75 Medium, tailoring the challenge to fit your lifestyle and interests can help you stay consistent and see results. “My biggest advice is to treat 75 Medium as a framework you’re in charge of, not a test you pass or fail,” said Bickerstaff. “Choose exercises you genuinely enjoy so the 45 minutes feels achievable even on busy days and plan workouts and walks into your schedule like appointments,” he advised. A little planning around food can help, too. “Keep your nutrition on track by meal prepping for the week ahead. This will make it feel more convenient and remove any excuses,” Bickerstaff said. He also suggests using the learning and meditation time to &#8220;wind down and reflect on your day.” “The people who see results are the ones who focus on showing up consistently, not doing everything perfectly,” he said. Brown also noted that ensuring your approach to 75 Medium fosters self-trust rather than reinforces external control will likely help you achieve the best results. &#8220;If you use 75 Medium as temporary scaffolding to build awareness and momentum, it can be useful. If you treat it as what will finally &#8216;fix&#8217; you, you’re simply recreating the all-or-nothing thinking we see with every iteration of these challenges,” she said.', NULL, 'https://www.healthline.com/health-news/tiktok-75-medium-challenge-weight-loss', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/sport-woman-phone-1296x728-header.png', NULL, NULL, '2026-01-25 06:50:34.612206', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.612206', '2026-01-25 06:50:34.612206');
INSERT INTO public.radar_items VALUES ('4aeb2369-a9ab-4b5e-92b6-ce2d417fb6e5', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '3c068dc0e7777fb8fa637e5560ad6da4', 'Tylenol During Pregnancy Not Linked to Autism, ADHD Risk, Review Confirms', NULL, 'A new gold standard review confirms that paracetamol, also known as acetaminophen, is not linked to autism or ADHD. Dobrila Vignjevic/Getty Images The most rigorous review to date found that there is no evidence that acetaminophen (Tylenol), also known as paracetamol, use in pregnancy increases the risk of autism, ADHD, or intellectual disabilities. This contradicts the information the Trump administration previously suggested around the safety of Tylenol use during pregnancy. Experts recommend ', NULL, 'A new gold standard review confirms that paracetamol, also known as acetaminophen, is not linked to autism or ADHD. Dobrila Vignjevic/Getty Images The most rigorous review to date found that there is no evidence that acetaminophen (Tylenol), also known as paracetamol, use in pregnancy increases the risk of autism, ADHD, or intellectual disabilities. This contradicts the information the Trump administration previously suggested around the safety of Tylenol use during pregnancy. Experts recommend discussing safe options for pain relief with their doctor. A new gold-standard systematic review and meta-analysis found that there is no evidence to suggest that the use of acetaminophen (Tylenol) during pregnancy increases the risk of autism, ADHD, or intellectual disabilities. The research is the latest in a series of large-scale reviews to confirm that acetaminophen, also known as paracetamol, is not linked to developmental disorders in offspring. The results were recently published on January 16 in The Lancet Obstetrics, Gynaecology, & Women’s Health. In September 2025, the Trump administration suggested that taking Tylenol during pregnancy may raise the risk of autism in children. The Food and Drug Administration (FDA) then initiated label changes on Tylenol to include a mention of the possible association between the medication and the risk of autism and ADHD. Following the announcement, Texas Attorney General Ken Paxton and others nationwide filed lawsuits against the pharmaceutical industry, alleging that manufacturers misled consumers about the potential risks of Tylenol use during pregnancy. “The exaggerated hype and misrepresentation about acetaminophen [Tylenol] increasing the risk of autism and ADHD during pregnancy has been exploited, harmful to pregnant women, and causing unnecessary confusion,” Sherry Ross, MD, board certified OB-GYN and Women’s Health Expert at Providence Saint John’s Health Center in Santa Monica, CA, told Healthline. Ross wasn&#8217;t involved in the review. Despite the findings of the latest review, federal health officials upheld their position on the possible risks. In a statement shared with Healthline, the Department of Health and Human Services (HHS) said that experts have expressed concern about the use of acetaminophen during pregnancy. Federal health officials cited Andrea Baccarelli, MD, the Dean of the Harvard School of Public Health, who, according to HHS, has suggested a causal relationship between prenatal acetaminophen use and the neurodevelopmental disorders of ADHD and ASD, as well as related symptomology. Here&#8217;s what you need to know about the current evidence on acetaminophen use during pregnancy and the risk of neurodevelopmental disorders. No causal link between acetaminophen and autism The Lancet review examined 43 existing studies that had the highest quality and most rigorous research methods. These studies compared pregnancies where the individual had taken acetaminophen (Tylenol) to pregnancies where the individual had not taken the medication. They then pooled the results of sibling-comparison studies in which siblings born to the same mother were compared: one pregnancy included acetaminophen exposure, and the other didn’t. This helped control for genetics, family environment, and long-term parental characteristics that traditional studies have not been able to account for. The sibling-comparison studies included 262,852 children assessed for autism, 335,255 for ADHD, and 406,681 for intellectual disability. It was confirmed that taking acetaminophen in pregnancy was not linked to childhood autism, ADHD, or intellectual disability when compared to pregnancies with no acetaminophen exposure. “Our findings suggest that previously reported links are likely to be explained by genetic predisposition or other maternal factors such as fever or underlying pain, rather than a direct effect of the paracetamol (acetaminophen) itself,” Asma Khalil, professor of obstetrics and maternal fetal medicine at City St George’s, University of London and Consultant Obstetrician, who led the study, said in a press release. “The message is clear — paracetamol remains a safe option during pregnancy when taken as guided,” she added. Ross agreed. &#8220;Tylenol is commonly used to treat fever, headache, and pain during pregnancy,&#8221; she said. &#8220;It is safe to use in pregnancy for these common and potentially dangerous conditions. These frequent complaints during pregnancy are safely treated using Tylenol with minimal risks. The risks of untreated fevers, headaches, and pain during pregnancy may be dangerous for mother and baby and do outweigh the unsupported risks of using Tylenol to treat these harmful symptoms,&#8221; Ross continued. Federal health officials, however, disagreed with the study findings. HHS told Healthline that the authors engineered a finding rather than evaluating causality. Tylenol use during pregnancy and autism An umbrella review of systematic reviews published in November 2025 also found that individuals can safely take acetaminophen (Tylenol) during pregnancy to treat fever and pain. The researchers of this review noted that previous studies, which suggested a slight association between acetaminophen use during pregnancy and autism and ADHD, were flawed. “Existing evidence does not clearly link maternal [Tylenol] use during pregnancy with autism or ADHD in offspring,” the researchers wrote. This review was published just months after the U.S. government announcement regarding the risk of using Tylenol during pregnancy and showed there was not sufficient evidence to support this announcement. No link between vaccines and autism A large study of 1.2 million children published in July 2025 found no compelling evidence to suggest a link between childhood vaccines and autism or other chronic health conditions. This Danish study provides reassuring, compelling evidence on the safety of aluminum in vaccines. Experts who were not affiliated with the research told Healthline that there have been multitudes of reputable studies on vaccine safety in recent decades, and none have found a definitive link to autism. “The scientific community has researched this very thoroughly, and there’s no evidence that childhood vaccines cause autism,” said Danelle Fisher, MD, a pediatrician at Providence Saint John’s Health Center in Santa Monica, CA. Fisher wasn&#8217;t involved in the reviews. Experts reaffirm the importance of children receiving the recommended vaccination schedule to prevent the spread of potentially fatal illnesses, such as measles. The growing measles outbreak that began in West Texas has been linked to low vaccination rates. What actually causes autism? Autism spectrum disorder (ASD) is believed to be caused by a combination of genetic and environmental influences. However, the exact cause is still currently unknown. The exact cause(s) of autism is still to be determined,&#8221; Ross said. &#8220;Credible medical studies suggest autism is thought to be due to genetic and environmental factors. What is known about the cause of autism is [that] it results from a combination of influences.” “Autism has a strong genetic influence based on mutations of certain genes that impact brain development. Abnormal wiring of the brain in the early development of the baby is also thought to contribute to the case of autism. Maternal infections, exposure to toxins, and pregnancy and delivery complications are potential environmental factors,” Ross continued. According to the National Institute of Environmental Health Sciences (NIEHS), a growing area of research focuses on the interaction between environmental and genetic factors. Some genetic factors that may influence the development and diagnosis of ASD include: certain genetic conditions, such as Down syndrome, fragile X, and Rett syndrome a sibling or twin with autism older parents While progress has been made in understanding environmental factors, they alone are unlikely to cause ASD. Rather, they may be more likely to increase the risk of development when combined with genetic factors. Environmental factors may include: advanced parental age at the time of conception prenatal exposure to certain pesticides and air pollution maternal obesity, diabetes, or immune system disorders extreme prematurity or very low birth weight any difficulty during birth that may lead to periods of oxygen deprivation in the baby’s brain Research into the exact causes of ASD is ongoing.', NULL, 'https://www.healthline.com/health-news/no-link-tylenol-during-pregnancy-autism-adhd-major-review', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/pregnant-female-prenatal-vitamins-1296-728-header.jpg', NULL, NULL, '2026-01-25 06:50:34.73541', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.73541', '2026-01-25 06:50:34.73541');
INSERT INTO public.radar_items VALUES ('38a4baa0-721f-432f-84a5-2911d8a98e5e', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '4cbb631d7d4f9cfda73c656bf4b587cf', 'Daily 10-Minute Walk May Lower Risk of Early Death by 15%', NULL, 'A daily 10-minute walk may lower the risk of early death by 15%, according to a study. Image Credit: The Good Brigade/Getty Images A recent study found that walking for 10 minutes a day may lower the risk of early death by 15%. The study noted that a combination of sleep, nutrition, and physical activity aids in longevity. The study also suggested that reducing the time you spend sedentary by 30 minutes each day can help prevent about 4.5% of deaths. Physical activity, sleep, and nutrition are k', NULL, 'A daily 10-minute walk may lower the risk of early death by 15%, according to a study. Image Credit: The Good Brigade/Getty Images A recent study found that walking for 10 minutes a day may lower the risk of early death by 15%. The study noted that a combination of sleep, nutrition, and physical activity aids in longevity. The study also suggested that reducing the time you spend sedentary by 30 minutes each day can help prevent about 4.5% of deaths. Physical activity, sleep, and nutrition are key determinants of life span and health span. Life span is your life expectancy, while healthspan is the portion of your life span that is free of disease. “There is much evidence showing that staying active both physically and mentally is important for healthy later life,” stated Sarah Gray, GP specialist in Women’s Health at St. Erme Medical in Truro, United Kingdom. A new study published in eClinical Medicine, part of the Lancet Discovery Science, suggests that implementing these components together may extend life span by a year. However, the findings also showed that making larger changes could potentially extend life span by nine years. According to the study authors, combining these changes can also extend your health span. This means it can increase the number of years you may live without any major health complaints. “These findings highlight the importance of considering lifestyle behaviors as a package rather than in isolation,” lead study author Nick Koemel, PhD, a research fellow in physical activity, lifestyle, and population health at the University of Sydney&#8217;s main campus in Camperdown, Australia, said in a press release. “By targeting small improvements across multiple behaviors simultaneously, the required change for any single behavior is substantially reduced, which may help overcome common barriers to long-term behavior change.” Daily walks linked to longevity The research team studied 59,078 individuals from the UK Biobank, who were recruited between 2006 and 2010. The average age of the participants was 64 years, with 45.4% male. Between 2013 and 2015, a subsample of participants was invited to wear an accelerometer for a week. This measured their moderate-to-vigorous physical activity and sleep. Diet was assessed using a 10-item diet quality score, including their intake of: fruit and vegetables meat and fish grains dairy oils sugar-sweetened beverages Life span and health span were then estimated across 27 different combinations of sleep, physical activity, diet, and a composite score using life tables. The study estimated that walking for as little as five minutes a day can lower the risk of early death (before 75) by 10% for most of the general population. However, walking for 10 minutes a day could potentially cut the risk by 15%. For people who are the least active, a five-minute walk could reduce the risk of early death by 6%. The researchers suggested that reducing the amount of time people are sedentary (inactive and sitting) by 30 minutes each day could help prevent 4.5% of deaths. “We are keenly aware that patients who had colon cancer had fewer recurrences if they were part of an intense exercise regimen, as was shown in previous studies,&#8221; said Nilesh Vora, MD, board certified hematologist and medical oncologist and medical director of the MemorialCare Todd Cancer Institute at Long Beach Medical Center in Long Beach, CA, who was not part of the study. &#8220;This seems to fit in line with and support that hypothesis as well,” Vora told Healthline. The researchers also found that a combination of an additional 5 minutes of sleep per day, 2 minutes of moderate to vigorous physical activity per day, and five DQS points (i.e., ½ serving of vegetables per day or 1.5 servings of whole grains per day) was associated with an additional year of life. Whereas, an additional 24 minutes of sleep per day, four minutes of moderate to vigorous physical activity, and 23 DQS points (i.e., an additional 1 cup of vegetables, one serving of whole grains per day, and two servings of fish per week) were associated with an additional four years of healthspan. “The findings of the study reinforce the premise that implementing small and sustained changes in simple lifestyle behaviors such as walking, improved nutrition, and sleep collectively make a significant difference in not only lifespan but more importantly, healthspan — the key indicator that demonstrates improved quality of life-years, not just additional years of life,” said Robert Glatter, MD, assistant professor of emergency medicine at the Zucker School of Medicine at Hofstra/Northwell, and emergency department physician at Northwell Health, who was not involved in the study. Vora cautioned that, while these results are promising, more intensive research is needed before definitive conclusions can be drawn from this study. Lifestyle changes for longevity Glatter told Healthline that this study reinforces the concept that sleep, nutrition, and exercise “do not exist in a vacuum.” People need to optimize all three — in small amounts — to reap the benefits of a longer healthspan, he said. He added that starting small can make it feel more achievable. This may include walking just a few minutes a day or taking the stairs instead of the elevator or escalator. These small changes can help add up. Making small healthy changes to your eating habits can also help. This may include adding more fruits, vegetables, and legumes while eating fewer ultra-processed foods. Glatter noted that these changes can help improve your lipid profile and inflammatory markers. “These cardiovascular markers are indicative of improved vascular health, and [are] an important marker for longevity,” said Glatter. “The take-home message to the public is that small and incremental collective lifestyle changes in all three categories — nutrition, sleep, and exercise — have the greatest impact in improving healthspan, compared to a focus on only one category alone,” he added. Glatter advised that investing in midlife and earlier can pay off in not just additional years of life, but, more importantly, meaningful and active years that lead to independence, improved cognition, and stronger muscles that help prevent falls and other injuries as you age.', NULL, 'https://www.healthline.com/health-news/daily-short-walk-may-lower-early-death-risk-study', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/woman-sun-walk-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:34.858711', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.858711', '2026-01-25 06:50:34.858711');
INSERT INTO public.radar_items VALUES ('1c5541d0-1860-4ba1-ba0d-c8c5a809ba9c', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '83e75bdf25d66b1b503612290679d3a1', 'Hot Flash Treatment May Have Anti-Breast Cancer Properties', NULL, 'A progesterone-mimicking drug may help slow breast cancer tumor growth, according to research. Image Credit: Fiordaliso/Getty Images A recent study found that a synthetic progesterone drug used to manage hot flashes in females with breast cancer may also help slow tumor growth. A low dose of megestrol acetate is already currently used to help individuals manage hot flashes associated with anti-estrogen treatment. The PIONEER trial has found that combining this synthetic progesterone drug with th', NULL, 'A progesterone-mimicking drug may help slow breast cancer tumor growth, according to research. Image Credit: Fiordaliso/Getty Images A recent study found that a synthetic progesterone drug used to manage hot flashes in females with breast cancer may also help slow tumor growth. A low dose of megestrol acetate is already currently used to help individuals manage hot flashes associated with anti-estrogen treatment. The PIONEER trial has found that combining this synthetic progesterone drug with the conventional anti-estrogen treatment may also have a direct anticancer effect. A drug that mimics the hormone progesterone may have anticancer activity when paired with conventional anti-estrogen treatments for females with breast cancer. That&#8217;s according to a new trial led by the University of Cambridge. It&#8217;s already a proven treatment to provide a low dose of synthetic progesterone (megestrol acetate) to help manage side effects of anti-estrogen treatments, such as hot flashes. However, the trial, dubbed PIONEER, found that the addition of megestrol to this treatment may also have a direct anticancer effect. The results were recently published in Nature Cancer. “These findings could have significant clinical impact by improving treatment adherence while positively impacting tumor control. However, further studies will be required to substantiate these claims,” said Esha Sachdev, MD, a breast medical oncologist at the MemorialCare Todd Cancer Institute at Long Beach Medical Center in Long Beach, CA. Sachdev wasn&#8217;t involved in the study. Debra Patt, MD, PhD, MBA, executive vice president of Public Policy and Strategy for Texas Oncology, who was not involved in the study, agreed. “I think the study is exciting and should be expanded so we know how it might impact long-term outcomes in women with breast cancer,&#8221; Patt told Healthline. Anticancer properties of progesterone-like drug Around three-quarters of all breast cancers are ER-positive. This means that breast cancer has strong estrogen receptors, which are proteins located on or within cells that can bind to specific substances in the blood. Breast cancer cells that are taken out during a biopsy or surgery are tested for estrogen and progesterone receptors. If the cells have either of these receptors, it means that when the hormone attaches to the receptor, it stimulates cancer growth. Individuals with ER-positive breast cancer are often offered anti-estrogen medications to reduce the level of estrogen, depriving the cancer of estrogen and inhibiting its growth. However, reducing the estrogen levels can also lead to side effects that are similar to menopause symptoms, including: hot flashes potential bone loss joint and muscle pain “One proposed mechanism as to why the megestrol reduces tumor growth is through improving adherence to adjuvant endocrine therapy by alleviating hot flashes, which is achieved with megestrol 40 milligrams,” Sachdev said. “A second mechanism for the effectiveness of megestrol is the direct antiproliferative effect on tumor cells mediated by reduced ER genomic binding, subsequently antagonizing estrogen signaling. The lower dose may be sufficient to saturate receptors and therefore reduce ER chromatin binding,” she noted. In the PIONEER trial, a total of 198 postmenopausal females with ER-positive breast cancer were recruited from 10 hospitals in the United Kingdom. The participants were randomized into three groups: only received letrozole, a medication that blocks estrogen and is used as a treatment for ER-positive breast cancer received letrozole and 40 mg of megestrol daily received letrozole and 160 mg of megestrol daily The treatment was given to each participant for two weeks prior to surgery to remove the tumor. The percentage of actively growing tumor cells was assessed both at the start of the trial and then again just before surgery. After the two weeks, those who received the combination of medications saw a greater decrease in tumor growth rates compared to those who were only treated with the anti-estrogen medication. “In the two-week window that we looked at, adding a progestin made the anti-oestrogen treatment more effective at slowing tumour growth. What was particularly pleasing to see was that even the lower dose had the desired effect,&#8221; Rebecca Burrell, joint first author of the study and clinical research associate with Cambridge University Hospitals and Cancer Research UK Cambridge Institute, said in a press release, “Although the higher dose of progesterone is licensed as an anti-cancer treatment, over the long term it can have side effects, including weight gain and high blood pressure. But just a quarter of the dose was as effective, and this would come with fewer side effects,” she continued. Future of breast cancer treatment The PIONEER trial shows that the combination of megestrol and anti-estrogen medications may make a difference for certain females with ER-positive breast cancer. However, further research is required with larger cohorts and a longer time period. “Several additional studies are needed to strengthen and validate the results from this trial,&#8221; Sachdev told Healthline. &#8220;A longer duration is necessary to assess safety and tolerability in conjunction with efficacy.” “We are in a time of incredible research in breast cancer, and breast cancer patients have every reason to be optimistic about their future,&#8221; Pratt said. &#8220;As I have observed multidisciplinary cancer care evolve tremendously over time, we can do more and more to help women live a long and healthy life.&#8221;', NULL, 'https://www.healthline.com/health-news/hot-flash-treatment-may-have-anti-breast-cancer-properties', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/woman-hot-flush-kitchen-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:34.981798', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:34.981798', '2026-01-25 06:50:34.981798');
INSERT INTO public.radar_items VALUES ('563d44d5-bcc7-4300-84ae-957870df61c3', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'cd61344b25cd508e927c7ef6ceba4da4', 'Millions of Americans May Lose Their ACA Plans. What Are the Alternatives?', NULL, 'Millions of Americans are expected to lose their ACA plans amid rising premium costs. Fiordaliso/Getty Images Around 1.4 million fewer Americans have enrolled in Affordable Care Act (ACA) health insurance plans in 2026 due to the expiration of federal subsidies that help offset monthly premium costs. People who enroll in Obamacare programs will pay an average of 114% more in premiums. There are various alternative plans available for those who can’t afford ACA premiums, but experts say many are ', NULL, 'Millions of Americans are expected to lose their ACA plans amid rising premium costs. Fiordaliso/Getty Images Around 1.4 million fewer Americans have enrolled in Affordable Care Act (ACA) health insurance plans in 2026 due to the expiration of federal subsidies that help offset monthly premium costs. People who enroll in Obamacare programs will pay an average of 114% more in premiums. There are various alternative plans available for those who can’t afford ACA premiums, but experts say many are still expensive or do not provide adequate coverage. Fewer people will participate in Affordable Care Act (ACA) health insurance plans in 2026, and those who do will pay significantly more for their medical expenses. The window for enrolling in ACA programs closed on January 15. This year, it appears fewer people will be enrolled in ACA health plans. New data from the Centers for Medicare & Medicaid Services (CMS) show that 22.8 million people enrolled in ACA marketplace coverage in 2026, down from a record 24.2 million in 2025. That’s about 1.4 million fewer people. The numbers for 2026 enrollment include those who signed up for ACA plans via Healthcare.gov through January 3, and those who enrolled via state-operated ACA marketplaces through December 27. The downward enrollment trend this year is attributed to rising premium costs. In 2025, an estimated 22 million people used federal subsidies to lower their health insurance premiums. Some of them paid no premiums at all. However, in 2026, none of the ACA enrollees will receive federal subsidies to help them pay their premiums. That’s because Congress hasn’t renewed those assistance programs, which were approved in 2021 under the American Rescue Plan and then extended through 2025 under the Inflation Reduction Act of 2022. In early January, the House of Representatives voted to extend the subsidies for three years, but the Senate hasn’t yet approved the extension. President Donald Trump has said he may veto legislation extending the subsidies, even if Congress approves it. When the President unveiled &#8220;The Great Healthcare Plan&#8221; in mid-January, proposing lower costs and prescription drug pricing, experts said the affordability it promised is unlikely to be delivered. “We know President Trump wants his plan to be a great health plan, but unfortunately, his plan keeps in place the infrastructure that is hurting patients, doctors, and prices today,&#8221; Twila Brase, RN, PHN, co-founder and president of Citizens’ Council for Health Freedom, said in a statement. Here&#8217;s what you need to know about rising costs to ACA premiums and some of the available alternatives to Obamacare. How much will ACA premiums go up in 2026? Health insurers participating in the ACA marketplace are projected to raise their premiums by an average of 26%. It&#8217;s been estimated that nearly 5 million people in the United States will decide to forgo health insurance this year rather than pay the additional costs. Those who remain in the ACA system will pay an average of 114% more in health insurance premiums due to the lack of subsidies, according to a report by the organization KFF. The Bipartisan Policy Center estimates that a family of four with a household income of $45,000 per year that paid $0 in ACA insurance premiums in 2025 could pay as much as $1,600 in 2026. Many people won’t be able to afford those premium spikes and will look for policies outside the ACA for coverage. Experts say most of these plans will probably be too expensive for many people who have relied on federal subsidies. “A lot of people are going to lose coverage,” said Naomi Zewde, PhD, an assistant professor in the Department of Health Policy and Management at the UCLA Fielding School of Public Health, as well as a fellow at the UCLA Center for Health Policy Research in Los Angeles, CA. “There’s a big difference in your medical premiums going from zero to several hundred dollars a month,” she told Healthline. “The math on that isn’t going to add up for a lot of families.” Additionally, many alternative plans do not provide people with the medical coverage they truly need. “There will be a whole range of services they won’t be getting,” noted Zewde. “It’s going to change their lives substantially.” “All of these plans are cutting something. It’s important to know what,” she added. ACA alternatives If you&#8217;re shopping around for alternatives, the following is a snapshot of some available options. Short-term medical insurance Short-term health insurance are designed for people who need temporary coverage while they’re between jobs as well as gig workers and people who have retired but aren’t yet eligible for Medicare. Like most alternative plans, short-term coverage allows an individual to sign up and start coverage the following day. You can enroll for a period of a few months to a year, with renewal up to three years in some states. The monthly premiums typically range from $60 to $250. However, many of the plans do not cover pre-existing conditions and exclude benefits such as maternity care and mental health services. There are sometimes limits on prescription benefits. These plans are also only available in 36 states. Fixed benefit medical insurance These plans, sometimes called fixed indemnity health insurance, pay established cash amounts for specific services, such as hospital care, doctor visits, or lab tests. These plans generally don’t require deductibles and allow enrollees to utilize the healthcare provider of their choice. The benefits are generally paid directly to the consumer. Premiums can be as low as $25 per month. However, these plans may not cover all medical expenses, in particular those involving chronic conditions. It’s generally recommended they be paired with another insurance plan. High-deductible health insurance These plans generally have low premiums but high deductibles. They are often paired with a person’s health savings account (HSA). Premiums range from $150 to $400 a month or higher. There are also tax incentives for enrolling in an HSA, and the ability to roll over these funds from year to year. However, there can be high out-of-pocket costs and these plans may not be cost-effective for people who need frequent medical care. Catastrophic medical insurance Catastrophic health plans also have low premiums and high deductibles. They are primarily designed for people under 30 or consumers with hardship exemptions. Premiums generally range from $130 to $300 per month or higher, depending on various factors. They do cover preventive care and most programs covered under ACA plans, although specialists many times are not covered. They do have limited provider networks in some areas. Concierge health insurance Concierge health plans are a type of direct-pay model where the enrollee subscribes with a physician for routine medical services. These plans typically cost between $50 and $150 per month for individuals and $100 to $250 a month for families. They allow for unlimited visits as well as a personal relationship with a physician. There can also be discounts on lab tests and imaging exams. However, these plans are not insurance and many times don’t cover hospitalization and specialist care. It’s recommended that they be paired with a high deductible or catastrophic health insurance plan. Risks of inadequate health insurance Kevin Schulman, MD, a professor of medicine at Stanford University, said many of these options won’t make sense for lower-income households. “For low-income populations, none of these options will be affordable,” he said. “The major issue is to avoid low-cost ‘alternative’ plans such as primary-care coverage that provide minimal or no coverage for healthcare services, or dread disease policies which are very expensive and poor value.” David Cutler, MD, a family medicine physician in Santa Monica, CA, said that many of the alternative plans have significant flaws. “Non-ACA health plans may offer more affordable coverage,” he said. “However, limits to what is covered, pre-existing condition limitations, provider network restrictions, and the many other constraints which insurers can place on care which were addressed, eliminated, or at least made transparent in the Affordable Care Act would no longer be in place.” Experts interviewed by Healthline said that there are consequences for both individuals and society as a whole when people are either uninsured or underinsured. “The major impact is on low-income populations in states that did not expand Medicaid under the ACA,” said Schulman. “These populations may find that they are no longer eligible for ACA subsidies and will face a higher premium even if they are eligible for subsidies.” “This will increase the number of uninsured in the U.S., put financial pressure on physicians and hospitals for uncompensated care, and will result in worse health outcomes for patients,” he added. Cutler said the effects will be widespread. “The resulting fallout could be quite substantial,” Cutler said. “People with illnesses and diseases may not get cared for. Pregnant mothers may not receive prenatal care jeopardizing the health of their babies. Children may not receive vaccines such as measles.” “And the providers of these healthcare services may be deprived of their livelihood, which was supported by insurance payments now eliminated when these policies are no longer in place,” he added. Zewde noted the United States has the highest healthcare costs per person in the world. Yet, we have fewer doctors and fewer services than many high-income nations. “We use less healthcare, but we pay more overall,” she said. “The fact remains that the United States has the most expensive healthcare in the world and does not have better health to show for it,” Cutler noted.', NULL, 'https://www.healthline.com/health-news/affordable-care-act-alternative-health-insurance-plans', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/ACA-Plans-GettyImages-2157361694-Header.jpg', NULL, NULL, '2026-01-25 06:50:35.105309', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:35.105309', '2026-01-25 06:50:35.105309');
INSERT INTO public.radar_items VALUES ('ae768cf4-495d-46ae-a5f1-9a4652b0431e', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'da683a0040a795659d2aaaffbc1f0043', 'Age-Related Weight Gain May Start Earlier Than Menopause, Experts Say', NULL, 'Research indicates that age-related weight gain may begin around before menopause. Image Credit: ljubaphoto/Getty Images Weight gain is a common experience during menopause. Research indicates that midlife weight gain may actually begin earlier than previously thought. Experts suggest some diet and lifestyle tips to help prevent age-related weight gain. Menopause describes a life transition when menstrual periods have stopped for 12 consecutive months, and pregnancy is no longer possible. It is ', NULL, 'Research indicates that age-related weight gain may begin around before menopause. Image Credit: ljubaphoto/Getty Images Weight gain is a common experience during menopause. Research indicates that midlife weight gain may actually begin earlier than previously thought. Experts suggest some diet and lifestyle tips to help prevent age-related weight gain. Menopause describes a life transition when menstrual periods have stopped for 12 consecutive months, and pregnancy is no longer possible. It is a natural part of the aging process. The average age of menopause onset in the United States is 52, but this can vary widely. The time leading up to menopause is called perimenopause or the menopause transition, which typically occurs during your mid- to late-40s. Along with symptoms like hot flashes, night sweats, joint and muscle discomfort, and mood changes, menopause-related shifts may change how the body uses energy. The distribution of fat throughout the body can also shift, potentially leading to weight gain. Many people experience weight gain during menopause; however, new research suggests that weight gain could begin earlier than previously thought. A review of studies suggests that the menopause-related metabolic shift, which contributes to weight gain, may begin during perimenopause, or sooner. The findings were recently published in the Journal of Mid-Life Health. &#8220;Weight changes are not only characteristic of midlife or menopause. Data have shown that weight gain starts early in adulthood,&#8221; Daniela Hurtado Andrade, MD, PhD, an endocrinologist and obesity expert at Mayo Clinic in Jacksonville, FL, explained in a news release. Andrade wasn&#8217;t involved in the study. &#8220;Around age 30, your muscle mass starts decreasing gradually as part of the natural aging process, and this is exacerbated in midlife due to menopause,&#8221; Andrade continued. Here&#8217;s what you need to know about age-related weight gain before menopause, and what you can do to help prevent it. Hormonal, physiological shifts before menopause On average, individuals experience perimenopause for four years before their period stops completely, but this phase can last anywhere from two to eight years. During perimenopause, estrogen and progesterone begin to fluctuate unpredictably. These hormone shifts can affect nearly every metabolic system in the body. The metabolic system is the network of chemical reactions that convert food into energy. The new review notes that estrogen plays a role in controlling fat distribution, muscle repair, and insulin sensitivity. When these levels fluctuate significantly, the body changes how it stores fat, redistributing it from the hips and thighs to the abdomen. “It is well known that metabolism starts to slow down as we age. The frustrating effects on the body include weight gain, along with a loss of muscle and energy,” said Sherry Ross, MD, board certified OB-GYN and Women’s Health Expert at Providence Saint John’s Health Center in Santa Monica, CA, who wasn&#8217;t involved in the research. &#8220;These untimely and normal aging effects accelerate as estrogen levels fluctuate in perimenopause,&#8221; Ross told Healthline. “Estrogen has a significant influence on metabolism, affecting the body’s ability to properly regulate insulin production, glucose metabolism, and fat distribution.&#8221; Muscle protein synthesis can also slow down during perimenopause. This is the body’s natural metabolic process that builds and repairs muscle tissue by incorporating amino acids into muscle proteins. This can result in increased insulin resistance and gradual muscle loss even if you haven’t changed your eating or exercise habits. These hormone changes can also: disrupt sleep influence cortisol levels alter appetite All of these can influence changes in your weight. However, these changes may not only reflect weight gain. Even if your weight remains the same, it is not uncommon to lose muscle and gain belly fat, which may increase visceral fat. This deeper fat surrounds your vital organs and has been linked to inflammation. It can increase your risk of type 2 diabetes liver disease heart disease sleep disorders Fat increases during menopause transition The Study of Women’s Health Across the Nation (SWAN) has been tracking females of various backgrounds across several areas of the United States since 1994. The researchers have been investigating the physiological changes that occur in the female body during midlife years. One of the key findings of the study was that during perimenopause, long before the period stops, lean muscle mass declines and fat mass begins to increase. Once this accelerated redistribution of fat plateaus during menopause, it is much more difficult to reverse. This is why it may be important for people to view perimenopause as a window of opportunity. The new review notes that, during this time, the body is still much more adaptable. With the right strategies at this time, females can help offset the hormonal effects and help set themselves up for a healthier transition through menopause and beyond. “You are never too young to discuss making healthy lifestyle choices to help control unwanted weight gain. Dietary changes are important to reduce the chance of disruptive &#8230; weight gain,&#8221; Ross said. “Adjusting dietary behaviors should begin in their 30s to control weight gain and medical complications, including high blood pressure, heart disease, and cancer associated with obesity and aging,” she continued. Ross suggested adopting a well-balanced, plant-based diet that limits consumption of red meat and excessive dairy products. She cited the Mediterranean diet as an example. “Limiting ultra-processed packaged foods, fatty meats, sugary foods, refined oils and fried foods, carbonated beverages with sugar, and alcohol consumption during the sensitive hormonal transition of menopause should be a priority for weight control and long-term wellness,” Ross said. Talk with your doctor about age-related weight gain The standard concept of “eat less and move more” may not be sufficient for all females in their 40s. This advice generally ignores hormonal contexts and oversimplifies biology. You may wish to speak with your doctor for advice on how to mitigate the weight gain that may come as you near perimenopause and menopause. “The cultural stigma to aging that is attached to perimenopause is a hard topic to accept or share with a healthcare provider. But the time is now to have these courageous conversations with your provider,” Ross said. “Empowering yourself to talk openly about your health concerns must be your top priority. There are practical lifestyle choices and treatment options that will help ease this normal hormonal transition and avoid perimenopausal weight gain,” she added. You may wish to discuss hormone therapy as well. It is a common potential treatment for perimenopause and menopause symptoms. However, not everyone may be considered a potential candidate. On the other side, Ross also noted that conversations about female midlife weight gain should be individualized. She added that there are several considerations that healthcare professionals should discuss with each person: medical history dietary habits physical activity sleep issues stress management genetic history other disruptive symptoms of perimenopause or menopause Ross suggested working with a psychologist and a dietitian may also help with age-related weight gain. Sarah Gray, MD, general practitioner and women’s health specialist at St. Erme Medical, agreed, noting that “a good dietitian may be better” than just discussing these issues with your healthcare professional. Gray wasn&#8217;t involved in the review. Preventing weight gain during perimenopause Ross told Healthline that a healthy lifestyle can go a long way when a person enters perimenopause and menopause. She noted that certain harmful lifestyle habits can contribute to making the symptoms of perimenopause and menopause worse and weight gain more challenging, including: excessive alcohol consumption getting poor quality of sleep smoking eating an unhealthy diet having obesity living a sedentary lifestyle “Combining a well-balanced plant-based diet, limiting red meat and high fat dairy intake, and consuming &#8216;good&#8217; fats- monounsaturated and polyunsaturated fats reduces weight gain and other medical complications,” Ross said. &#8220;Simple lifestyle adjustments will not only make hormonal symptoms less disruptive but will also have a positive impact on weight control,&#8221; she added. These lifestyle modifications include: eating a balanced diet getting regular exercise limiting alcohol consumption getting at least 7 hours of sleep managing stress', NULL, 'https://www.healthline.com/health-news/age-related-weight-gain-may-start-earlier-than-menopause', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/exercising-women-legs-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:35.229203', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:35.229203', '2026-01-25 06:50:35.229203');
INSERT INTO public.radar_items VALUES ('3ea09bbf-a373-4750-a6b9-dd992bc8c45f', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'f3df5587918cbf8ca8a0ee07bcbc9333', 'Most Effective Hair Loss Treatments In 2026, According to Experts', NULL, 'Some treatments are recommended by experts for hair loss, while others are currently under research. Image Credit: agrobacter/Getty Images Several new medications to treat hair loss in males and females are currently in clinical trials. Stem cell and fatty acid treatments are also being studied as potential treatments for hair loss caused by androgenetic alopecia. Experts say other approved treatments, such as Rogaine and Propecia, are effective, affordable, and widely available. It’s estimated ', NULL, 'Some treatments are recommended by experts for hair loss, while others are currently under research. Image Credit: agrobacter/Getty Images Several new medications to treat hair loss in males and females are currently in clinical trials. Stem cell and fatty acid treatments are also being studied as potential treatments for hair loss caused by androgenetic alopecia. Experts say other approved treatments, such as Rogaine and Propecia, are effective, affordable, and widely available. It’s estimated that 85% of males and 33% of females will experience some form of hair loss during their lifetime. Approximately 25% of males and 12% of females will begin to lose their hair by the age of 30. About 95% of males who experience hair loss do so due to an inherited condition known as androgenetic alopecia, a common type of alopecia commonly referred to as male pattern baldness. In females, androgenetic alopecia usually results in hair thinning along the scalp, while the frontal hairline is usually retained. Alopecia areata, another type of hair loss, is an autoimmune disease in which the immune system attacks hair follicles. It typically results in patchy hair loss that affects the scalp and other parts of the body. An estimated 7 million people in the United States will experience this condition in their lifetime. Regardless of the type of hair loss a person may be experiencing, there are many effective treatment options available. Here&#8217;s what you need to know. Should you try hair loss treatment? Carolyn Goh, MD, an associate clinical professor in dermatology at the UCLA David Geffen School of Medicine in California, lives with hair loss. She told Healthline she has accepted her condition and doesn’t treat it. However, she said that route may not be the appropriate path for everyone. “I think acceptance can be liberating and must be part of the process, but it should not be expected as the only avenue for managing one&#8217;s hair loss,” Goh said. “Hair loss can have an impact on people&#8217;s lives beyond just their appearance,” she explained. “Hair loss can feel quite disfiguring for many people and is also stigmatized, in which people make assumptions based on one&#8217;s hair or lack thereof, and it likely impacts how one might be treated.” Spencer Kobren, the founder of the American Hair Loss Association, cautions those with hair loss to carefully consider treatments, especially ones that are new to the industry. “Several treatments are in development, but none have proven they will replace existing therapies,” he told Healthline. “Much of the attention surrounding future treatments is driven by online hype rather than long term clinical evidence.” Ken Williams Jr., DO, a surgeon and founder of Orange County Hair Restoration in California, advises those with hair loss to carefully select their medical professional. “Patients need to be aware that there are many doctors and clinics who call themselves ‘hair loss doctors’,” Williams told Healthline. “The reality is that short-term and long-term medical and surgical management for hair loss is best done by a board certified physician who is a diplomate of the American Board of Hair Restoration Surgery (ABHRS).” Current treatments for hair loss The following hair loss treatments are well-established, including Rogaine, Proscar, and Propecia, which have been available for years. Proscar and Propecia Proscar and Propecia both contain the active ingredient finasteride. Experts have said that the medications are effective, affordable, and readily available. They are approved for the treatment of male hair loss. Proscar, manufactured by Organon, is a tablet that is also prescribed to treat symptoms associated with an enlarged prostate. Propecia, manufactured by Merck, works by slowing hair loss in men. It does not help regrow hair. There are reports that it can diminish sex drive and also cause mood swings. There are some general warnings about finasteride. Officials say pregnant women should not come into contact with the ingredient. Finasteride is also associated with a higher risk of prostate cancer. In addition, a commentary published in October 2025 stated that FDA officials haven’t done enough to investigate the links between finasteride and mental health risks, including depression. Still, experts say the benefits of finasteride products outweigh the risks. “For men, finasteride remains the gold standard treatment for male pattern hair loss and one of the most studied and safest drugs in the Physicians’ Desk Reference,” Kobren said. Rogaine Rogaine is a topical treatment that contains the active ingredient minoxidil, which has been on the market since 1987 as a treatment for male and female pattern baldness. Rogaine reportedly works by partially enlarging hair follicles and elongating the growth phase of hair, although experts are unsure exactly how the medication accomplishes this. It can take up to four months to see results, and there can be some itching and redness associated with its use. Experts say finasteride and minoxidil are well-established treatments. “These two medications have been the mainstay of medical management for the last decades,” Williams said. “They have proven patient safety, tolerability, and efficacy.” “Topical minoxidil and oral finasteride are still the only two FDA-approved treatments for pattern hair loss. They are very effective for the treatment of hair loss,” added Goh. JAK inhibitors for alopecia areata There are three FDA-approved JAK inhibitor medications that help treat the autoimmune disorder alopecia areata. Brand names, such as Olumiant, Litfulo, and Leqselvi, are targeted anti-inflammatory drugs that target the immune system. An older JAK inhibitor, Xeljanz, is sometimes prescribed off-label to treat alopecia areata. Other inhibitors, such as Rinvoq, are currently in clinical trials as potential treatments for alopecia areata. Olumiant Olumiant, manufactured by Eli Lilly, is a tablet approved for use in adults 18 years and older. This prescription drug is also used to treat rheumatoid arthritis and COVID-19. Mild side effects include nausea. Serious side effects are uncommon but can occur, potentially causing low red blood cell levels and high cholesterol. The product has an FDA box label warning about risks involving cancer, blood clots, and heart-related events. Litfulo, manufactured by Pfizer, is a capsule approved for use in adults and children 12 years and older. The drug works by blocking the action of certain proteins that cause your immune system to attack hair follicles. Litfulo can cause mild side effects such as acne, headache, and dizziness. It also carries an FDA boxed warning label regarding risks associated with blood clots and cancer. Leqselvi, manufactured by Sun Pharmaceuticals, is a tablet approved by the FDA in July 2024 for use in adults 18 years and older. Mild side effects can include headache and acne. The product does carry a box label warning for infection and cardiovascular risk. “For alopecia areata, the approved JAK inhibitors are still very promising, with more and more data coming out on them. There may be some additional treatments for alopecia areata soon,” said Goh. New hair loss treatments on the horizon Some of the following hair loss treatments are still in the research stage and are not widely available to the public, while others can be discussed with your doctor. Clascoterone Clascoterone, sold under the brand names Winlevi and Breezula, was approved by the Food and Drug Administration (FDA) in 2020 to treat acne vulgaris in adults and children ages 12 and older. The prescription cream is a topical androgen receptor inhibitor that works by blocking certain receptors. It helps reduce oil production and inflammation in the skin, reducing the development of acne. Researchers are looking into clascoterone as a possible treatment for androgenetic alopecia. The medication is currently in phase III clinical trials. So far, it has shown promising results for hair growth with mild side effects. It’s expected that Cosmo Pharmaceuticals will submit its product for regulatory approval in the United States and Europe in spring 2026. “Clascoterone is the most advanced of the newer treatments and may become a useful topical option, particularly for women, but it is not a cure and is unlikely to replace existing treatments,” Kobren said. PP405 PP405 is a topical treatment being developed by Pelage Pharmaceuticals to treat androgenetic alopecia. It works by targeting hair follicle stem cells, addressing the root cause of dormancy. In phase II clinical trials, 31% of men who used PP405 ointment showed hair density increases of more than 20%. PP405 was listed by Time magazine as one of the best inventions of 2025. Pelage plans to begin phase III clinical trials in 2026. “The… exciting value to PP405 is that it appears to induce or stimulate dormant hair follicles into the anagen phase of the hair cycle, suggesting the potential for regeneration,” said Williams. Kobren expressed caution, however. “PP405 and ET-02 are very early, and the level of online excitement surrounding them is far ahead of the actual data,” he said. “Durability, real-world effectiveness, and long-term safety are still unknown for all of these.” ET-02 ET-02 is a topical ointment being studied as a potential treatment for hair loss and graying hair. The product, being developed by Eirion Therapeutics, works by correcting defective hair follicle stem cells. It has only been tested so far in phase I clinical trials. In that early research, ET-02 has demonstrated promise by encouraging rapid hair growth as well as reducing graying without serious side effects. Eirion plans to conduct phase II trials in the near future. “ET-02 is in very early stages, so while there may be some promise, it is too early to know at this time,” said Goh. Stem cells Other new treatments for hair loss are non-topical. ET-02 is one part of the growing science of using stem cells to treat hair loss. Early research suggests that stem cells may be utilized as a potential treatment for pattern baldness in both males and females through hair transplants. In this procedure, a small skin sample is removed, and hair follicles are harvested from it. The follicles are treated in a lab and then implanted back into the scalp. However, experts caution that this use of stem cells and other technologies is in the early stages of research and could be expensive if and when they are approved. “Stem cell therapy is unfortunately frequently seen in social media advertising as science and proven fact,” said Williams. “The science and validity of stem cells, however, still need to be studied and evaluated.” “These are very attractive options, but the data are limited. As with any treatments using cell products, safety is a concern,” added Goh. Fatty acid treatments Fatty acids such as omega-3 and monounsaturated fatty acids have been studied as potential hair loss treatments. They work in a variety of ways, from blocking enzymes that cause hair thinning to activating dormant hair follicle cells. Experts warn, however, that like stem cell therapies, fatty acid treatments for hair loss have not been proven effective yet. “These approaches are scientifically interesting for both men and women, but the clinical evidence remains limited,” said Kobren. “The bigger issue is unregulated clinics and aggressive marketing running far ahead of the science.” Early intervention for hair loss is best While there are many options to treat hair loss, experts emphasize considering all possible avenues. “Acceptance is ultimately the only true cure, but it is far easier said than done for most people,” said Kobren. “I often tell young men that if they can shave their heads and truly move on, they may save themselves a lifetime of trying to manage a progressive condition that is as much emotional as it is physical, and not everyone will respond well to treatment,&#8221; he said. “The reality is that most people want to do whatever they can to treat hair loss and, in that case, early intervention with evidence-based medication matters,” he added. Williams said it’s it&#8217;s important to be aware of the most accurate and reliable information. “I believe that ABHRS-certified physicians can offer hope for all hair loss sufferers. No one should suffer the emotional impact of hair loss,” he said. “Men and women need to have the proper diagnosis and treatment that is best rendered by an ABHRS physician.”', NULL, 'https://www.healthline.com/health-news/best-hair-loss-treatments-2026-experts', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/bald-man-mirror-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:35.353664', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:35.353664', '2026-01-25 06:50:35.353664');
INSERT INTO public.radar_items VALUES ('25be3140-0bdc-4f25-bb34-847520806289', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'c7464f023883895a1140701a8f7b75a0', 'Matt Damon Says Gluten-Free Diet Helped Him Lose Weight for ‘The Odyssey’', NULL, 'The actor credits cutting gluten from his diet with helping him lose weight for his role in director Christopher Nolan’s upcoming film “The Odyssey.” Getty Images Actor Matt Damon has credited a gluten-free diet with helping him lose weight. The star said it helped return him to his “high school” weight. However, experts say there’s nothing magical about a gluten-free diet. Eating a healthy, balanced diet including grains is still best for most people. During an episode of the “New Heights” podc', NULL, 'The actor credits cutting gluten from his diet with helping him lose weight for his role in director Christopher Nolan’s upcoming film “The Odyssey.” Getty Images Actor Matt Damon has credited a gluten-free diet with helping him lose weight. The star said it helped return him to his &#8220;high school&#8221; weight. However, experts say there&#8217;s nothing magical about a gluten-free diet. Eating a healthy, balanced diet including grains is still best for most people. During an episode of the &#8220;New Heights&#8221; podcast, actor Matt Damon revealed how he got in shape and shed pounds for his new movie, &#8220;The Odyssey.&#8221; Speaking with hosts Travis and Jason Kelce, the star said that director Christopher Nolan wanted him &#8220;lean but strong.&#8221; To achieve this goal, he said he made one big change: cutting gluten out of his diet. Gluten is a family of proteins called prolamins that are found in various grains, such as wheat, barley, and rye. Some individuals need to exclude gluten from their diet due to Celiac disease or non-celiac gluten sensitivity. Some, like Damon, also claim that avoiding gluten helps with weight loss. &#8220;I used to walk around between 185 and 200,&#8221; he told the Kelce brothers. &#8220;I did that whole movie at 167.&#8221; Damon further noted that he hadn&#8217;t been that weight since high school. &#8220;So it was a lot of training and a really strict diet,&#8221; he said. Can cutting gluten really help you lose weight? Shelley Balls, a registered dietitian and nutritionist for Flawless Bloom, said, &#8220;Unless you have celiac disease or a non-celiac gluten sensitivity, I don’t recommend you follow a gluten-free diet because you will be eliminating a bunch of potentially healthful foods, spending more money on gluten-free foods, sacrificing enjoyment of food, and it makes eating in social situations more challenging.&#8221; Noting that weight loss still requires a calorie deficit, she said there isn&#8217;t currently any research indicating that a gluten-free diet causes weight loss. &#8220;[H]owever, it can help decrease your intake of refined grains that are more inflammatory, which can be an obstacle for weight loss,&#8221; she said. &#8220;&#8230;But you don’t have to go gluten-free to cut back on refined carbohydrates.&#8221; Balls additionally noted that if you are living with Celiac disease, an autoimmune disease where your immune system reacts to gluten, a gluten-free diet might actually cause you to gain a few pounds as your body begins to better absorb nutrients. Bonnie Taub-Dix, RDN, host of the Media Savvy Podcast, creator of BetterThanDieting.com, and author of &#8220;Read It Before You Eat It: Taking You from Label to Table,&#8221; did acknowledge the actor&#8217;s success, saying, &#8220;I think it’s great that Damon found an approach that worked for him while training for a specific role, especially since he did it under doctor and trainer guidance and paired it with a disciplined workout routine.&#8221; She said, however, that she was disappointed that he didn&#8217;t consult a dietitian who could have given more balanced and realistic dietary advice. &#8220;[I]t’s important to recognize that what works for one person in a short-term, goal-specific context isn’t a universal solution,&#8221; said Taub-Dix. Echoing Balls, she added, &#8220;There’s no clear scientific evidence saying gluten must be cut out for weight loss in people without gluten-related disorders.&#8221; Potential drawbacks of a gluten-free diet Balls said that there can be some drawbacks to cutting gluten from your diet. &#8220;Gluten-free products can still be high in calories and solid fats,&#8221; she explained, &#8220;so just because the product is gluten-free doesn’t mean you don’t need to eat mindfully.&#8221; Cutting out gluten can also increase the risk of under-eating or an unbalanced diet, according to Balls, especially if you cut out all grains, so you need to plan your meals carefully. She advises making sure you still take in good fiber sources, lean protein, and healthy fats. Well-balanced meals are essential for blood sugar management and satiety. On the other hand, Balls said that going gluten-free could help you reduce your intake of refined grains, which lack the protein and fiber of whole grains. &#8220;Simple carbohydrates and unbalanced meals can make it harder to manage blood sugar levels, which is important if you’re trying to lose weight,&#8221; she said. Healthier diet changes that can aid with weight loss If weight loss is your goal, Balls suggests focusing on balanced nutrition and making sure to include enough protein and fiber at every meal — around 25 grams and 8 grams, respectively. You also don&#8217;t have to cut out grains entirely. Whole grains such as Quinoa, black and brown rice, oats, and popcorn can all be a part of a healthy weight-loss diet. Balls also noted that if you&#8217;re cutting out gluten or reducing your intake, be sure to replace it with gluten-free grains. &#8220;Including gluten-free grains and replacing simple carbohydrates with whole grains like quinoa, brown rice, etc., along with eating an abundance of fruits and veggies, can ensure you’re getting adequate vitamin, mineral, and carbohydrate intake.&#8221; It&#8217;s additionally important to consume enough complex carbohydrates, she said. These contain prebiotic fibers, polyphenols, and nutrients that support gut health. Taub-Dix added that the goal is sustainable weight loss over the long term. In addition to focusing on your eating pattern, pay attention to portion sizes, food quality, activity level, and the creation of habits you can maintain over time. Finally, Taub-Dix said it&#8217;s important to know that cutting out gluten isn&#8217;t a magic bullet.&#8220;You can fill yourself with gluten-free pastries or gluten-free pizza and never lose an ounce,&#8221; she said.', NULL, 'https://www.healthline.com/health-news/matt-damon-weight-loss-gluten', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/matt-damon-1296x728-header.png', NULL, NULL, '2026-01-25 06:50:35.47661', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:35.47661', '2026-01-25 06:50:35.47661');
INSERT INTO public.radar_items VALUES ('0951d3c5-c980-4ac3-a331-06373033dcd3', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '8ac07da7a74e3e8a9cd57f0f4d0e6491', 'No Link Between Menopause Hormone Therapy and Dementia, Review Says', NULL, 'There is no link between MHT and dementia risk, according to a new review. Image Credit: SVPhilon/Getty Images A new analysis is easing long-standing fears about menopause hormone therapy and dementia. Reviewing data from more than a million women, researchers found MHT neither raises nor lowers dementia risk. Experts say that decisions about hormone therapy should focus on symptom relief and quality of life, not fear of cognitive decline. Menopause hormone therapy is not associated with an incr', NULL, 'There is no link between MHT and dementia risk, according to a new review. Image Credit: SVPhilon/Getty Images A new analysis is easing long-standing fears about menopause hormone therapy and dementia. Reviewing data from more than a million women, researchers found MHT neither raises nor lowers dementia risk. Experts say that decisions about hormone therapy should focus on symptom relief and quality of life, not fear of cognitive decline. Menopause hormone therapy is not associated with an increased risk of dementia in postmenopausal women, according to new research. Menopause hormone therapy (MHT), previously known as hormone replacement therapy (HRT), is used to manage menopause symptoms, but for decades, women have been warned about serious associated risks. These products carried the FDA’s most stringent boxed, or “black box,” warnings, citing potential complications including cardiovascular disease, cancer, and dementia. Evidence now suggests that some of these concerns were likely overstated. In a major about-face, the Food and Drug Administration (FDA) removed its black box warning labels on MHT products in November of last year. “We are returning to evidence-based medicine and giving women control over their health again,” Health and Human Services Secretary Robert F. Kennedy Jr. said in a statement. But the strongest signal of that shift may be coming not from regulators, but from the data, or the lack thereof. In a new meta-analysis commissioned by the World Health Organization (WHO) that included health data from more than a million women, researchers found that MHT neither increased nor decreased dementia risk. The study was recently published in The Lancet Healthy Longevity. “The World Health Organisation currently provides no guidance on MHT and dementia risk, leaving a critical gap for women, clinicians, and policymakers. Our work will help inform upcoming WHO guidelines on reducing the risk of cognitive decline and dementia,” Melissa Melville, a PhD Candidate and Ageing Researcher in the Department of Clinical Health Psychology at the University College London and first author of the study, told Healthline. Melville stressed that the work&#8217;s importance is twofold: for clinicians, there is an urgent need for higher-quality research; for patients, decisions about MHT should be guided by symptoms and well-established benefits and risks. Hormone therapy&#8217;s controversial, complicated history The history of MHT is both complex and controversial. The practice began in the 1960s and peaked in the United States in the 1990s. However, in 2002, results from the Women’s Health Initiative (WHI), the first and only large randomized controlled trial of MHT, suggested that the risks outweighed the benefits. Participants in the study had an increased risk of breast cancer, stroke, pulmonary embolism, and heart attack. Following the publication of these results, MHT therapy declined by 45%. A subgroup study known as the Women’s Health Initiative Memory Study (WHIMS) later published findings on dementia and Alzheimer’s disease among women taking MHT. The study reported a substantially increased risk of dementia and overall cognitive decline. That study alone effectively cemented the perception that MHT increased dementia risk and had a chilling effect on both patient use and subsequent research. “A lot of other research was halted at that point, which led to only really having this study as our data point for many years. That’s what happens when a landmark paper suggests that we’re doing something potentially unsafe,” said Caroline Just, MD, program lead for women’s neurology and neuro-obstetrics at the Cleveland Clinic. Just wasn&#8217;t involved in the study. Despite its outsized and decades-long impact on women’s health, experts say the WHI’s methodology, and even the types of hormones used, are a far cry from modern practice. “[The WHI] is not reflective of our practice patterns now, nor the hormone therapy regimens that we use now,” said Karen Adams, MD, Farwell Family Director of the Stanford Program in Menopause & Healthy Aging at Stanford Medicine, who wasn’t involved in the research. WHIMS remains the only randomized controlled trial to examine hormone therapy and dementia risk. Most other studies have been observational and therefore more susceptible to bias. Of the ten studies reviewed in the new meta-analysis, nine were observational. Over the years since WHIMS was published, evidence of the association between MHT has been conflicting, with some studies also concluding that it increases the risk of dementia, while others suggest that it may be protective against cognitive decline. The new review suggests that neither is true. “When you put all the data together, as is common when something shows one way and other studies show the other way, the effects cancel out. So, there was no convincing difference in terms of protection or increased risk from menopause hormone therapy,” Just said. “The depth of this review is extremely reassuring to people who prescribe menopause hormone therapy.” Just told Healthline. Adams emphasized the limitations of current evidence. “We just don&#8217;t have good studies,&#8221; she told Healthline, &#8220;The best thing we can say right now based on the data that we have is that hormone therapy probably does not increase the risk of dementia, but it probably doesn&#8217;t prevent it either.” Women&#8217;s dementia risk and how to improve it Women are disproportionately affected by dementia, even after accounting for their longer life expectancy. Almost two-thirds of Americans living with Alzheimer’s disease, the most common cause of dementia, are women. Given that disparity, it is understandable to be concerned about ways to reduce this risk. For now, the available evidence suggests that MHT is not one of those risk factors. The apparently neutral effects of MHT on dementia risk suggest one clear takeaway for patients: decisions about using the therapy should be guided by symptom relief and quality-of-life considerations — not fear. “Dementia should not drive MHT decisions,” Melville said. For women under 60 or within 10 years of their last menstrual period, there is a “window of opportunity” to start MHT, Adams said. “To the best of our knowledge, if you start at the right time, you can continue indefinitely without significant risk,” she added. There are also a number of well-established lifestyle habits to reduce dementia risk for women of all ages. These include: being active eating a heart-healthy diet (like the Mediterranean diet) not smoking maintaining healthy blood pressure and cholesterol keeping socially active prioritizing sleep “Many cases of dementia are likely modifiable, meaning there&#8217;s something that the patients can do to alter or reduce their risk that is not genetic,” Just said.', NULL, 'https://www.healthline.com/health-news/menopause-hormone-therapy-not-linked-dementia-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/appyling-hormone-patch-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:35.600908', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:35.600908', '2026-01-25 06:50:35.600908');
INSERT INTO public.radar_items VALUES ('c23b9b90-47e2-4bc4-a73b-6f9e21fa731e', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'ac7d2704bd4302c509a43ab6e615ea2e', 'U.S. Cancer Survival Rates Reach Historic High of 70%. Here''s Why', NULL, 'A new report shows that more Americans are surviving cancer than ever before. Getty Images Cancer survival rates have reached a record high, according to a new report from the American Cancer Society (ACS). The positive trend is attributed to innovations in precision treatment, expanded screening, and reduced tobacco use. Despite the overall improvement in survival rates, Native Americans, Black Americans, and rural populations continue to face higher rates of death from cancer. People are livin', NULL, 'A new report shows that more Americans are surviving cancer than ever before. Getty Images Cancer survival rates have reached a record high, according to a new report from the American Cancer Society (ACS). The positive trend is attributed to innovations in precision treatment, expanded screening, and reduced tobacco use. Despite the overall improvement in survival rates, Native Americans, Black Americans, and rural populations continue to face higher rates of death from cancer. People are living longer after a cancer diagnosis than ever before. According to a new report from the American Cancer Society (ACS), 70% of those who receive a cancer diagnosis survive for five or more years compared to 49% in the mid-1970s. People diagnosed with historically deadly cancers are also now living much longer than they would have in the mid-1990s. For myeloma, survival jumped from 32% to 62%; for liver cancer, from 7% to 22%; and for lung cancer, from 15% to 28%. The findings of this report are based on people diagnosed from 2015 to 2021 and point to cancer shifting from &#8220;a death sentence to a chronic disease,&#8221; Rebecca Siegel, MPH, the American Cancer Society&#8217;s senior scientific director of surveillance research and the report&#8217;s lead author, said in a news release. Three key factors are driving this progress: Research-driven innovations, expanded screening efforts, and decades of declining tobacco use. Here&#8217;s what you need to know. Cancer research, treatment innovations Research played a pivotal role in making cancer treatment more targeted and effective. Speaking on a call with journalists, William Dahut, MD, the American Cancer Society&#8217;s chief scientific officer, said that in the 1990s, doctors used &#8220;very blunt instruments&#8221; to treat patients. Today, therapies target specific cancer mutations and harness the body&#8217;s immune system to fight the disease. &#8220;Being able to understand the cancer genome really, totally changed the way we began to think of cancer treatment,&#8221; Dahut said. He added that layering targeted therapies with immunotherapy has had &#8220;the most dramatic effect&#8221; on survival rates. Improved cancer screening, early detection Early detection through screening has dramatically improved survival rates for breast, cervical, prostate, colorectal, and lung cancers, according to the new ACS report. Catching cancer early makes it far more treatable — yet screening rates for lung cancer, the most deadly form of the disease, remain low. “The screening numbers are abysmal for a screening test that has been shown to actually change survival,” Dahut said. According to the ACS, doctors only screen nearly 19% of eligible Americans for lung cancer. The organization cites a lack of access to screening and education about eligibility as the reason so few people are screened. Current eligibility guidelines also exclude a growing number of patients, particularly people who have never smoked or have only smoked lightly. Suresh Ramalingam, MD, executive director of Emory University&#8217;s Winship Cancer Institute, said early detection &#8220;has the ability to reduce deaths related to lung cancer by 20%.&#8221; He told Healthline that lung cancer screening has been available for only about 15 years, and new guidelines expanding eligibility could be issued within the next five years. Christine Lovly, MD, PhD, who leads the national thoracic oncology program at City of Hope, is among those advocating for expanded screening. She emphasized that &#8220;lung cancer is dozens of unique types of cancer&#8221; triggered by different factors — smoking, environmental exposures, age, and genetics—each potentially requiring its own screening approach. The U.S. Preventive Services Task Force determines screening eligibility and says the potential harms outweigh the benefits for that group. Still, doctors and advocacy groups hope that more research will lead to expanded screening guidelines. Lung cancer kills twice as many Americans as any other cancer, according to the National Cancer Institute. Lovly argued that it&#8217;s time to discard the stigma that only smokers get the disease. &#8220;We need to think about other environmental factors that may cause lung cancer and honestly do away with this stigma that lung cancer is only associated with prior tobacco use,&#8221; she told Healthline. Declining tobacco use led to fewer deaths Plummeting smoking rates have directly improved cancer survival. Smoking dropped from 42% in the 1960s to 11% today, according to the ACS. The Centers for Disease Control and Prevention (CDC) reports that tobacco causes 80–90% of lung cancer deaths. A recent Yale study found that nearly half of those diagnosed with cancer in 2023 were current or former smokers. “A lot of what we’re seeing is related to a lower burden of tobacco-related cancers,” Ramalingam said. 20 million cancer survivors Nearly 20 million Americans now live with a cancer diagnosis — and with lasting effects that persist long after treatment ends. Survivors face ongoing physical side effects, financial burdens from long-term care, and the emotional weight of a disease that permanently changes you. Lynn Durham, EdD, president and CEO of Georgia CORE and a cancer survivor, understands this reality firsthand. &#8220;Cancer treatment is horrible&#8230; You can&#8217;t make that pretty,&#8221; she told Healthline, though she credits treatment advances for her full remission. Still, she said she carries the weight of uncertainty. &#8220;As a three-time cancer survivor, I can&#8217;t have back pain without thinking I have some form of cancer,&#8221; she said. Durham added that the mental health impact on survivors needs more attention. &#8220;We need to not only celebrate that there are more cancer survivors, but we also need to give them access to the continued treatment, resources, and guidance that they need to live a full life,&#8221; she said. Childhood cancer survivors also face unique challenges. While childhood leukemia now has a nearly 90% cure rate, the aggressive treatments that saved their lives can cause lasting damage. &#8220;We see a three times greater cancer mortality from children who have survived leukemia, with deaths coming from cardiovascular disease and oftentimes a second cancer,&#8221; Dahut said. But access to quality survivorship care isn&#8217;t equal for everyone, and racial health disparities persist. The rising survival rate masks a troubling inequity: not everyone benefits equally from better treatments and screenings. Native Americans and Black Americans face significantly higher cancer death rates than White Americans. Alaska Native people experience the world&#8217;s highest rates of colorectal cancer—two to three times higher than any other racial or ethnic group in the United States, according to the ACS report. Health disparities in cancer care, treatment Systemic obstacles like distance from providers, inability to take time off work, lack of childcare and the crushing costs prevent many from accessing care. “Transportation is a huge issue when you live in a rural area, just trying to get 50, 60, 70 miles to a doctor,” Durham said. Lovly echoed the need for equitable access. &#8220;As we&#8217;re excited about technology and all these new drugs — because we are at such an inflection point with our capabilities — we need to make sure we&#8217;re giving access to everyone,&#8221; she said. &#8220;It should not be the select few that have access to cutting-edge cancer care.” Steps to prevent or survive cancer Smoking, drinking, and obesity are the leading causes of most cancers. Three key actions can help prevent cancer or improve survival: Quit smoking and limit alcohol: Tobacco causes one in three cancer deaths and over 80% of lung cancers. Reducing alcohol intake also lowers your risk. Maintain a healthy weight: Diet and regular exercise can significantly reduce cancer risk. Get screened: Regular screening for breast, colon, cervical, lung, and prostate cancers catches the disease when it&#8217;s most treatable.', NULL, 'https://www.healthline.com/health-news/u-s-cancer-survival-rates-reach-historic-high-acs-report', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/female-patient-doctor-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:35.723091', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:35.723091', '2026-01-25 06:50:35.723091');
INSERT INTO public.radar_items VALUES ('75cebb86-fcae-4bc2-bea2-b2d0e911fdb7', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '784ee17300c8e332510d4b31b92d6752', 'How RFK Jr.’s New Drinking Policy Redefines Moderate Alcohol Consumption', NULL, 'Health and Human Services Secretary RFK Jr. announced new policy changes to dietary guidelines, including those related to alcohol. Image Credit: Anna Moneymaker/Getty Images RFK Jr., the U.S. Secretary of Health and Human Services, recently announced new dietary guidelines, which include guidance on alcohol consumption. The new guidelines remove the old standard guidance of 2 drinks per day for males and 1 drink per day for females, are are less clear about limits. Experts caution that removing', NULL, 'Health and Human Services Secretary RFK Jr. announced new policy changes to dietary guidelines, including those related to alcohol. Image Credit: Anna Moneymaker/Getty Images RFK Jr., the U.S. Secretary of Health and Human Services, recently announced new dietary guidelines, which include guidance on alcohol consumption. The new guidelines remove the old standard guidance of 2 drinks per day for males and 1 drink per day for females, are are less clear about limits. Experts caution that removing a specific threshold leaves Americans without a yardstick for what constitutes moderate consumption. The U.S. Secretary of Health and Human Services, RFK Jr., recently released new dietary guidelines. These new Dietary Guidelines for Americans 2025–2030 inverted the food pyramid, prioritizing proteins, fruits, and vegetables. It also emphasizes the importance of limiting added sugars, refined carbohydrates, and highly processed foods. They also changed the long-standing guidance for alcohol consumption. Prior recommendations for moderate alcohol consumption were 2 drinks per day for males and 1 drink per day for females. “So there is alcohol [in] these dietary guidelines, but the implication is, don&#8217;t have it for breakfast. There should be something done, a small amount,” commented Mehmet Oz, MD, administrator of the Centers for Medicare & Medicaid Services (CMS), in a news conference on January 7. However, the new guidelines are not clear about exactly how &#8220;a small amount&#8221; should be measured. New alcohol consumption guidelines are less clear The new guidance for alcohol consumption states, “Consume less alcohol for better overall health.” “The simple message to ‘consume less alcohol for better overall health’ is well-intentioned but could be interpreted in different ways,” noted Michelle Routhenstein, MS, RD, Preventive Cardiology Dietitian at EntirelyNourished. She continued by stating that some may see this guidance as vague or optional, while others may underestimate the risk. “Without clear numbers, there’s also a chance that social or cultural messaging around drinking could overshadow health considerations,” she added. No amount of alcohol consumption is safe for your health The World Health Organization (WHO) notes that even low levels of alcohol consumption can bring health risks. Alcohol can play at least a casual role in over 200 injuries, diseases, and other health conditions. Drinking alcohol has been associated with various conditions, such as: liver disease heart disease various types of cancer, such as breast, colorectal, and liver “The health effects of drinking alcohol have been well studied and include increased risk of many cancers (including colorectal, liver, and breast cancers), fatty liver disease and cirrhosis, heart disease (including cardiomyopathy and stroke), pancreatitis, and obesity,” said Cheng-Han Chen, MD, board certified interventional cardiologist and medical director of the Structural Heart Program at MemorialCare Saddleback Medical Center in Laguna Hills, CA. “I will still be advising my patients to drink as little as possible, and preferably not at all,” he told Healthline. Routhenstein recommended that people who choose to drink alcohol should have a practical approach in the same way they would with any other substance that carries risk. For example, aim for as many alcohol-free days as possible. She also encouraged people to stay within the previous low risk limits (2 drinks per day for males and 1 drink per day for females), as this is a reasonable guide. However, consuming none or fewer than those limits is always better. “Trying a temporary break from alcohol, like a 30-day pause, can be revealing. Many notice improvements in sleep, mood, weight, or lab markers that may help them reduce their alcohol intake in subsequent months,” noted Routhenstein. Groups at higher risk should avoid alcohol The new guidance still lists certain people who are encouraged to avoid alcohol altogether, including: people who are pregnant people who are recovering from alcohol use disorder people who find it difficult to control the amount they drink people who are taking medications that may interact with alcohol people who have a medical condition that may react negatively to alcohol The guidelines also encourage people with a family history of alcohol use disorder to be mindful of alcohol consumption and the associated behaviors. “While &#8216;consume less&#8217; is backed by evidence, pairing it with practical examples and a reminder that no amount of alcohol is completely risk-free can help people make better choices without feeling confused or overwhelmed,” stated Routhenstein. “Numeric thresholds still have value in clinical and counseling settings, helping people understand their own risk and track progress,” she added.', NULL, 'https://www.healthline.com/health-news/rkf-jr-controversial-new-drinking-policy-experts-react', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Alcohol-chaos-GettyImages-2255260434-Header.jpg', NULL, NULL, '2026-01-25 06:50:35.84613', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:35.84613', '2026-01-25 06:50:35.84613');
INSERT INTO public.radar_items VALUES ('6730d394-e1c7-42f3-a8f4-32c53272fc36', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'd3730ebed49fb6cb236e00e3f5e7cab7', 'Stopping GLP-1s May Lead to Weight Regain In Less Than 2 Years, Review Finds', NULL, 'Research shows that people who stop taking GLP-1 medications regain weight within 2 years. Image Credit: Tatsiana Volkava/Getty Images A new study has found that people regain weight within 2 years of stopping a GLP-1 drug. Metabolic improvements also tend to fade within that time, researchers found. Experts advise that slowly tapering off the medication is better than quitting abruptly. It’s also important to incorporate supportive changes in diet, exercise, and lifestyle for long-term weight m', NULL, 'Research shows that people who stop taking GLP-1 medications regain weight within 2 years. Image Credit: Tatsiana Volkava/Getty Images A new study has found that people regain weight within 2 years of stopping a GLP-1 drug. Metabolic improvements also tend to fade within that time, researchers found. Experts advise that slowly tapering off the medication is better than quitting abruptly. It&#8217;s also important to incorporate supportive changes in diet, exercise, and lifestyle for long-term weight management. Many people looking to lose weight and improve their health turn to medications like semaglutide (Ozempic, Wegovy) or tirzepatide (Mounjaro, Zepbound). As noted by the authors of a recent review published in The BMJ, glucagon-like peptide-1 (GLP-1) drugs can help patients lose between 15% and 20% of their body weight. However, their findings indicate that despite the success of these medications, people who stop them tend to regain quickly, returning to their original weight within an average of 1.7 years. During that timeframe, people also experience a reversal of the cardiometabolic health benefits seen while on the medications. The researchers suggest that a &#8220;more comprehensive&#8221; approach may be needed in order to achieve lasting weight loss with GLP-1s. Assessing weight management after GLP-1s The team of researchers conducted a review of the available evidence to determine the amount of weight people regain when they stop taking GLP-1 medications. They additionally wanted to examine how they compare to when people lose weight via diet and exercise. To answer these questions, they searched for and combined results from all available studies to get an overall picture. Altogether, data from 37 studies involving 9,341 adults with overweight or obesity were included. The studies included randomized controlled trials (considered the gold standard), non-randomized trials, and observation studies. All participants tested the medications for a minimum of 8 weeks, and were followed for at least 4 weeks after ceasing treatment. Medications included popular GLP-1s, such as semaglutide, tirzepatide, and liraglutide, as well as other anti-obesity medications, including orlistat. Some studies combined drug treatments with behavioral supports such as diet and exercise. For comparison purposes, the research team utilized data from a prior review of behavioral weight management programs and employed statistical models to estimate the average rate at which individuals regained weight after discontinuing medication. They also examined changes in blood sugar levels, cholesterol, and blood pressure to determine if participants maintained the improvements they experienced while on the medication. Most people regained all their weight after GLP-1s When they reviewed the data, they found that people lost an average of 8.3 kilograms (about 18 pounds) while they were using medication. However, once they stopped treatment, they regained their lost weight at a rate of about 0.4 kilograms (nearly 1 pound) per month. And, within an average of about 1.7 years, most had regained all of their weight. They additionally noted that newer drugs like semaglutide and tirzepatide were associated with an even faster rate of regain: about 2 pounds per month with a return to baseline in about 1.5 years. When the researchers compared weight regain after stopping medication to weight regain following the cessation of behavioral weight management programs, people generally lost less weight with behavioral techniques. However, weight regain was slower, at approximately 0.1 kilograms (one-quarter pound) per month. Furthermore, it took approximately 3.9 years for them to return to their starting weight. The study also examined various markers of metabolic health, including blood sugar (HbA1c and fasting glucose), cholesterol, triglycerides, and blood pressure. While these values had improved on the medications, they gradually returned to their original levels within around 1.4 years. The team also found no clear evidence that the continuation of behavioral supports after quitting weight loss drugs helped slow down the regain. According to the study authors, their findings show that while GLP-1 medications can provide tremendous benefits, those benefits may only last as long as you are using them. While behavioral programs may provide smaller results to GLP-1s, weight loss may be more sustainable. Tapering off GLP-1s can help your body adjust &#8220;Stopping GLP-1 medications often reveals something we don’t talk about enough: the drug was doing part of the physiological work that lifestyle alone may not yet be prepared to sustain,&#8221; said Flávio Mitidieri Ramos, MD, MSc, director of EndoDiagnostic Advanced Treatment for Obesity. According to Ramos, who wasn&#8217;t involved in the study, GLP-1s suppress appetite and food noise, but the body adapts to them over time. &#8220;When the medication is reduced or stopped abruptly, hunger signals, reward pathways, and metabolic efficiency tend to rebound,&#8221; he told Healthline. &#8220;Weight regain is not a personal failure; it is a predictable biological response.&#8221; Ramos added GLP-1s should almost never be stopped without a gradual taper, both by reducing the dose and by extending the interval between dosing. &#8220;This gradual step-down allows the brain, gut, and metabolic system time to recalibrate,&#8221; he explained. Ramos further noted the importance of close follow-up during this phase. &#8220;This is not about rushing off the medication, but about preparing the physiology for the next step,&#8221; he said. It involves eating structure, protein intake, movement, and behavioral awareness so that the patient is able to manage appetite and weight with each lower dose. Tips for long-term weight management Brian Parana, a health and nutrition coach, shared how he assists clients as they exit treatment with GLP-1s. Prana wasn&#8217;t involved in the study. &#8220;The first actionable step is rebuilding eating structure before appetite fully returns,&#8221; he told Healthline. &#8220;I have clients move to three planned meals per day, each built around a clear protein anchor.&#8221; According to Parana, protein increases satiety and slows digestion during a time when hunger signals can often overshoot. It also supports the preservation of muscle mass. &#8220;Strength training should also be introduced or reinforced before stopping GLP-1s,&#8221; he advised, adding that many lose muscle along with fat, especially if they are not doing strength training. &#8220;Muscle tissue plays a major role in daily calorie burn and glucose regulation,&#8221; said Parana. Regular movement is another key piece of the puzzle. &#8220;Walking improves insulin sensitivity, helps regulate appetite hormones, and lowers stress, all of which matter more once appetite suppression is removed,&#8221; he said. Parana said that sleep and stress management must also be addressed, since lack of sleep and chronic stress raise cortisol, a hormone that drives cravings and fat regain. &#8220;Simple routines like consistent bedtimes, morning light exposure, and reducing late-night screen use make a measurable difference in appetite control,&#8221; he said. Finally, Parana suggested viewing GLP-1s as a bridge rather than your final destination. &#8220;Clients who treat the medication as time to practice eating structure, movement, and recovery habits are far more successful long term than those who rely on appetite suppression alone,&#8221; he said. Adding to these tips, Ramos advised that you ultimately need to be realistic, keeping in mind that obesity is a chronic, relapsing condition. As such, some individuals may require ongoing medical treatment to achieve success. &#8220;The goal should not be to come off GLP-1s at any cost, but to integrate medication, behavior, and physiology in a way that patients can actually sustain in real life,&#8221; he said.', NULL, 'https://www.healthline.com/health-news/stopping-glp-weight-regain-review', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/holding-glp-1-pen-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:36.09116', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.09116', '2026-01-25 06:50:36.09116');
INSERT INTO public.radar_items VALUES ('299596af-9831-42a7-8b33-114d6e4a066a', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '56be32fef1b65fabf4b0fbd6ac123518', 'Why Experts Are Divided Over RFK Jr.''s Inverted Food Pyramid', NULL, 'The 2025–2030 dietary guidelines include a new inverted food pyramid. Experts have mixed reactions to these changes. Smith Collection/Gado/Getty Images New federal dietary guidelines recommend increasing protein and full-fat dairy intake while reducing consumption of ultra-processed foods, added sugars, and alcohol. Some experts argue that the protein recommendations place too much emphasis on meat and not enough on nuts, beans, and legumes. Other experts say that dairy products offer some healt', NULL, 'The 2025–2030 dietary guidelines include a new inverted food pyramid. Experts have mixed reactions to these changes. Smith Collection/Gado/Getty Images New federal dietary guidelines recommend increasing protein and full-fat dairy intake while reducing consumption of ultra-processed foods, added sugars, and alcohol. Some experts argue that the protein recommendations place too much emphasis on meat and not enough on nuts, beans, and legumes. Other experts say that dairy products offer some health benefits, but caution that daily intake of these foods should be moderate. Federal officials have released their 2025–2030 Dietary Guidelines for Americans, which emphasize the importance of protein, fruits, vegetables, and whole grains. The new inverted food pyramid urges Americans to sharply limit their intake of added sugars or non-nutritive sweeteners, saying “no amount” is considered part of a healthy diet. The nutrition guidelines state that no meal should consist of more than 10 grams, or about 2 teaspoons, of added sugar. Federal health officials have also targeted “highly processed” foods and refined carbohydrates, recommending that consumers avoid “packaged, prepared, ready-to-eat or other foods that are salty or sweet, such as chips, cookies and candy.” The 10-page guidelines encourage Americans to “eat the right amount for you” with daily caloric intake based on age, sex, height, weight, and level of physical activity. It highlights portion size and hydration as key components. “These guidelines return us to the basics,” said Health and Human Services Secretary Robert F. Kennedy Jr. in a press release. “American households must prioritize whole, nutrient-dense foods — protein, dairy, vegetables, fruits, healthy fats, and whole grains — and dramatically reduce highly processed foods.” The Dietary Guidelines for Americans are a federal nutrition recommendation that is updated every five years. Here&#8217;s what experts think of the latest changes. Who benefits from consuming more protein? One of the key recommendations in the new guidelines is to increase Americans’ daily protein consumption from 0.36 grams per pound of body weight to between 0.54 and 0.73 grams per pound of body weight. Federal health officials recommend that Americans include protein-rich foods in every meal. They encourage people to “prioritize high quality, nutrient-dense protein foods as part of a healthy dietary pattern.” They say the protein can come from a variety of foods, including: eggs poultry seafood red meat You can also obtain protein from plant-based protein foods, such as beans, peas, lentils, legumes, nuts, seeds, and soy. Dalia Perelman, a research dietitian at Stanford University, said higher levels of protein can be beneficial for older adults and people undergoing weight loss, but she isn’t sure “these higher levels are necessary for the general population, especially given that most Americans already consume more than the minimum protein requirement.” “We’re in a food environment where protein is aggressively marketed and added to many foods,” Perelman told Healthline. “Broadly increasing protein recommendations risks reinforcing that imbalance rather than addressing true nutritional gaps. Americans already consume insufficient fiber, and elevating protein as the dominant dietary goal may unintentionally displace fiber-rich foods.” She added that red meat and processed meats have been linked to increased risks of cardiovascular disease and certain cancers. Mir Ali, MD, a general surgeon, bariatric surgeon, and medical director of the MemorialCare Surgical Weight Loss Center at Orange Coast Medical Center in California, told Healthline that there are plenty of protein-rich choices. “Red meat isn’t necessarily bad as long as it’s not overdone,” Ali said, adding that other sources of protein, such as chicken, fish, lentils, beans, and nuts, might be better choices. “These are all good sources of protein,” he said. Should you increase your full-fat dairy intake? The guidelines encourage Americans to consume full-fat dairy products with no added sugars. They recommend “3 servings per day as part of a 2,000-calorie dietary pattern, adjusting as needed based on your individual caloric requirements.” The guidelines note that “dairy is an excellent source of protein, healthy fats, vitamins, and minerals.” Perelman said moderate levels of fermented dairy products, such as cheese, can produce some favorable cardiometabolic outcomes. However, she adds that one serving per day, about 1 to 1½ ounces, is sufficient to achieve those health goals. “The evidence supports moderation, not escalation, as we don’t have the kind of long-term trial data needed to justify population-wide recommendations for higher consumption,” Perelman said. “Given that multiple daily servings of full-fat cheese can quickly exceed recommended saturated fat and sodium limits, I think it’s premature to elevate cheese so prominently in dietary guidance without clearer evidence on long-term health effects and appropriate intake levels,” she added. Healthy fats still encouraged The guidelines encourage the incorporation of healthy fats, which are &#8220;plentiful in many whole foods such as meats, poultry, eggs, omega-3-rich seafood, nuts, seeds, full-fat dairy, olives, and avocados” into the daily diet. “When cooking with or adding fats to meals, prioritize oils with essential fatty acids, such as olive oil. Other options can include butter or beef tallow,” the guidelines state. They add that “saturated fat consumption should not exceed 10% of total daily calories.” Perelman said the saturated fat goal could be unrealistic, especially given the other recommendations in the guidelines. “The guidelines contain internal contradictions,” she said. “They retain a numeric recommendation to limit saturated fat to 10% of calories, while simultaneously emphasizing meat and full-fat dairy and allowing portion sizes that make it very difficult to stay within that limit in real-world diets.” Not all fruits, vegetables are equal The guidelines recommend that Americans eat vegetables and fruits throughout the day, focusing on their whole forms. They recommend “colorful, nutrient-dense vegetables and fruit” with 3 servings of vegetables per day and 2 servings of fruit per day. Ali noted that vegetables in general are a good component of a healthy diet, although he added that “starchy” vegetables, such as potatoes and corn, should be consumed in moderation. He added that fruits contain a lot of good nutrients, but they also can contain high levels of sugar. He said berries are often a better choice compared to apples and bananas. Best advice for a balanced diet Experts say the key to a healthy diet is a variety of nutritious foods consumed in moderate portions. “My overall advice is to focus on simple, well-established dietary patterns that are supported by a large body of evidence,” said Perelman. “Eat a wide variety of plant foods (fruits, vegetables, legumes, nuts, and seeds), prioritize whole grains over refined grains, and choose protein sources like fish, poultry, beans, and nuts while being more mindful about portions of red meat, processed meats, and cheese.” “Rather than focusing on specific nutrients or rigid targets, the goal should be building balanced, flexible eating patterns that people can maintain over time,” she added.', NULL, 'https://www.healthline.com/health-news/dietary-guidelines-new-food-pyramid', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/food-pyramind-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:36.214571', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.214571', '2026-01-25 06:50:36.214571');
INSERT INTO public.radar_items VALUES ('49949d20-9d87-4e99-8976-e6694e921bbe', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '4d6bc983d0dd1e8a56665fbeae0aa8c9', 'Exercise for Depression Yields Similar Results to Therapy, Research Says', NULL, 'A recent review shows that exercise may be nearly as effective as therapy for depression. Image Credit: Oleg Breslavtsev/Getty Images A recently updated Cochrane review found that exercise may provide similar results for depression as therapy. Exercise is a low cost, widely available option that has various other benefits. This makes it an attractive option for helping to manage symptoms of depression. Research indicates that exercise can have a positive impact on overall mental health. Regular ', NULL, 'A recent review shows that exercise may be nearly as effective as therapy for depression. Image Credit: Oleg Breslavtsev/Getty Images A recently updated Cochrane review found that exercise may provide similar results for depression as therapy. Exercise is a low cost, widely available option that has various other benefits. This makes it an attractive option for helping to manage symptoms of depression. Research indicates that exercise can have a positive impact on overall mental health. Regular exercise offers numerous benefits, particularly for mental health. Now, researchers say exercise may help reduce depression symptoms as effectively as other first-line treatments. A recently updated Cochrane review found that exercise yielded similar results to psychological therapy. When compared to antidepressants, however, the evidence was less clear. Depression is one of the most common mental health conditions in the United States, affecting around 21 million adults. In 2021, approximately 61% of U.S. adults experiencing depression received treatment. Exercise is a low cost option for symptom management that is widely available, making it an ideal treatment option for individuals and their prescribing healthcare team. “Our findings suggest that exercise appears to be a safe and accessible option for helping to manage symptoms of depression,&#8221; lead study author Andrew Clegg, PhD, professor of geriatric medicine at the University of Leeds said in a press release. &#8220;This suggests that exercise works well for some people, but not for everyone, and finding approaches that individuals are willing and able to maintain is important,” Clegg continued. Effects of exercise on depression symptoms The review examined 73 randomized controlled trials that included nearly 5,000 adults with depression. The examined studies compared exercise with control interventions or no treatment, as well as with antidepressant medications and psychological therapies. The results showed a moderate benefit of reducing symptoms of depression when compared to no treatment or controlled intervention. When exercise was compared to psychological therapy, it had a similar effect. This was based on moderate-certainty evidence from 10 trials. The evidence in comparison to antidepressants was limited and of low certainty. However, it did show there may be similar effects on depression symptoms. The long-term effects are still unclear, as few studies have followed participants after treatment. “While it seems that long-term studies need to be done to further study this complex topic, this review can provide encouragement on the benefits of additional tools, such as exercise, in managing depression,” said Menije Boduryan-Turner, PsyD, licensed psychologist and founder of Embracing You Therapy, who wasn&#8217;t involved in the review. Rod Mitchell, MC, MSc, a registered psychologist and founder of Emotions Therapy Calgary, in Alberta, Canada, who wasn&#8217;t involved in the review, agreed. &#8220;The certainty is rated &#8216;low&#8217; to &#8216;moderate&#8217; due to methodological challenges — many studies lacked blinded assessors, adequate randomisation concealment, or intention-to-treat analysis,&#8221; Mitchell told Healthline. “I&#8217;d caution against reading this as &#8216;exercise is just as good as therapy,''&#8221; he continued. &#8220;Therapy rewires thought patterns and processes underlying wounds. Medication adjusts neurochemistry. Exercise resets the nervous system. These aren&#8217;t interchangeable tools competing for the same job,” he added. This review allows clinicians permission to take exercise seriously as a frontline intervention, rather than simply a “lifestyle recommendation” that is tacked on to the end of a session, Mitchell noted. Other research supports the notion that physical activity can be beneficial for depressive symptoms. People with high levels of activity may have a 17% lower risk of depression. Those with low cardiorespiratory fitness may also have a 64% higher risk of developing depression. This shows that a sedentary lifestyle may lead to a greater potential for developing symptoms of depression. A 2024 systematic review suggested that there are three potential ways that regular exercise can help manage depression: reducing inflammation, which can be associated with symptoms of depression regulating circadian rhythms, which are often disrupted in people with depression improving sleep patterns, which can help regulate mood and energy levels “Exercise can help people with depression, but if we want to find which types work best, for who and whether the benefits last over time, we still need larger, high-quality studies,&#8221; Clegg said in the news release. &#8220;One large, well-conducted trial is much better than numerous poor quality small trials with limited numbers of participants in each.” Exercise vs. other treatments for depression The general recommendation is to use exercise in conjunction with other first-line treatments for depression. “I believe that a combination of therapy, medication, and other methods, such as meditation and exercise, would lead to a more wholesome treatment plan,&#8221; Boduryan-Turner told Healthline. &#8220;Most often, people feel the pressure to manage their depression with a single method, such as &#8216;just need medication&#8217; or &#8216;just need to go to therapy.&#8217; However, incorporating multiple modalities increases our chances of effectively overcoming our struggles,&#8221; she said. Depression affects everyone differently, and committing to regular exercise may be more difficult for some people than others. Still, the National Institute of Mental Health (NIMH) states that just 30 minutes of walking or jogging each day can help boost mood. “It depends entirely on where someone is in their depression. For mild to moderate presentations — especially when someone still has some motivational fuel in the tank — exercise can absolutely be a primary intervention,” Mitchell said. “However, depression is essentially a disorder of initiative. Telling someone in a deep depressive episode to exercise is like handing someone with two broken arms a life raft and telling them to swim,” he said. Mitchell added that for people with moderate to severe depression, he would typically recommend therapy first to help build positive momentum so that exercise feels possible. He noted that a person can then layer in movement as they stabilize their moods. It&#8217;s about sequencing interventions to meet the person where they are, not where they wish to be, he said. Exercise can help manage symptoms of depression in physiological and psychological ways. Physical activity releases endorphins, neurotransmitters associated with positive moods and feelings of well-being. Exercise can also: reduce stress and anxiety enhance self-esteem improve social support “I recommend that individuals planning to incorporate exercise into their mental health treatment focus on quality over quantity, so that it is not so much about how long they have exercised as about engaging in some form of exercise consistently,” Boduryan-Turner said. She added that she would encourage people to “engage in an exercise that aligns with the interests you used to have.” Mitchell agreed. “The type of exercise matters less than we think. Walking, dancing, gardening, gentle yoga — they all send the same signal to a stuck nervous system: &#8216;we&#8217;re not trapped, we can still move through the world,''&#8221; he said. When should you seek help for depression? If you&#8217;re experiencing symptoms of depression, you may wish to seek help from a mental health or healthcare professional if: symptoms of depression last longer than 2 weeks you feel you aren’t able to function like you used to you feel as though you are withdrawing from life you feel hopeless you are thinking about harming yourself If you feel that you may be in immediate danger or you are having suicidal thoughts, contact the Suicide & Crisis Lifeline in the U.S. by calling or texting 988, or visit the nearest emergency room.', NULL, 'https://www.healthline.com/health-news/exercise-depression-treatment-similar-results-therapy', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Exercise-depression-GettyImages-1407932503-Header.jpg', NULL, NULL, '2026-01-25 06:50:36.338795', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.338795', '2026-01-25 06:50:36.338795');
INSERT INTO public.radar_items VALUES ('cb7edc8b-799f-4632-9b58-bf23647e8bf6', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '2b0a87caa554f267f52a82358786d64a', 'How Ultra-Processed Meats, Foods Can Affect Type 2 Diabetes Risk', NULL, 'Ultra-processed meats and foods are linked to a higher risk of developing type 2 diabetes. Image Credit: Juan Moyano/Stocksy Research shows that ultra-processed foods can affect type 2 diabetes risk. A recent study found that eating the equivalent of 2 slices of ham a day can increase the risk of type 2 diabetes by 15%. Another study has shown that replacing ultra-processed foods with healthier options can lower the risk of developing type 2 diabetes. There is no singular universally agreed-upon', NULL, 'Ultra-processed meats and foods are linked to a higher risk of developing type 2 diabetes. Image Credit: Juan Moyano/Stocksy Research shows that ultra-processed foods can affect type 2 diabetes risk. A recent study found that eating the equivalent of 2 slices of ham a day can increase the risk of type 2 diabetes by 15%. Another study has shown that replacing ultra-processed foods with healthier options can lower the risk of developing type 2 diabetes. There is no singular universally agreed-upon definition of ultra-processed foods. However, the most commonly used definition is the NOVA classification. This classification discusses foods that contain formulations of ingredients, which are mostly of exclusive industrial use, and are typically created by a series of industrial processes and techniques. Another definition for ultra-processed foods is those containing ingredients not typically found in your kitchen cupboard, such as emulsifiers, additives, or stabilizers. Ultra-processed foods account for over 50% of the total dietary energy intake in developed countries, such as the United States. Recent research has shown that consuming ultra-processed foods can have various health effects. This includes increasing your risk of developing type 2 diabetes (T2D). However, research has also indicated that replacing ultra-processed foods with healthier options may lower your risk of developing diabetes and other chronic health conditions. Processed meats linked to type 2 diabetes risk A large 2024 study found that eating red meat and processed meats was associated with a higher risk of developing type 2 diabetes. The research team for this study analyzed 31 studies from 20 different countries. Altogether, this research included around 1.97 million people, 107,271 of whom were diagnosed with type 2 diabetes during the 10-year follow-up period. When the researchers examined the diets of the participants, they found that those who typically consumed around 50 grams of processed meat per day (equivalent to 2 slices of ham) had a 15% higher risk of developing type 2 diabetes within the next 10 years. Eating 100 grams of unprocessed red meat each day (the equivalent of a small steak) was associated with a 10% higher risk of type 2 diabetes. “This is an important study that has confirmed, with a much more comprehensive analysis of a large cohort of older studies, that there is an association between higher intake of red meat or processed meat and increased risk of type 2 diabetes,&#8221; Silvana Obici, MD, Chief of the Division of Endocrinology at Stony Brook Medicine and Interim Medical Director of the Stony Brook University Hospital Diabetes Center, who was not involved in the research, told Healthline. Still, Obici noted it&#8217;s essential to keep in mind that statistical association does not necessarily imply causation. Jennifer Pallian, a registered dietitian and owner of Foodess, said that processed meats often contain high levels of: saturated fats sodium preservatives, such as nitrates These have been associated with insulin resistance. “In particular, researchers believe that nitrosamines — chemicals that form from nitrites and nitrates used in processed meats — might damage DNA and harm the cells in the pancreas that produce insulin, leading to lower insulin levels,” Pallian, who wasn&#8217;t involved in the study, told Healthline. “Additionally, red meats are rich in heme iron, which may contribute to oxidative stress and inflammation, both of which are implicated in the development of diabetes,” she added. Ultra-processed food swaps may lower diabetes risk A 2024 study found that replacing ultra-processed foods with healthier options can help reduce the risk of type 2 diabetes. The researchers noted that for every 10% increase in ultra-processed foods in a person’s diet, there was a 17% increased risk of type 2 diabetes. However, this risk can be lowered by consuming minimally processed foods. The groups of ultra-processed foods that showed the highest risk were: savory snacks animal-based products, such as processed meats ready meals sugar-sweetened and artificially sweetened beverages Nichola Ludlam-Raine, a specialist dietitian and author of &#8220;How Not To Eat Ultra-Processed,&#8221; wasn&#8217;t involved in the study but told Healthline she wasn&#8217;t surprised by the findings. “The findings align with previous research linking ultra-processed foods with an increased risk of chronic diseases, including type 2 diabetes,” she said. “This is not surprising, as UPFs are often high in refined sugars, unhealthy fats, and low in essential nutrients as well as fiber.” However, only certain groups of ultra-processed foods were found to increase the risk of type 2 diabetes in this study, suggesting that further investigation is warranted. “Some groups in this study lowered the risk of type 2 diabetes, including bread, biscuits, breakfast cereals, dessert, and plant-based alternatives,&#8221; noted Priya Tew, a specialist dietitian at Dietitian U.K., who wasn&#8217;t involved in the study. Tew told Healthline that the foods in the highest-risk ultra-processed foods group “tend to be high in salt, saturated fat, and sugar” and may “displace other more nutritious food items.” When considering replacing ultra-processed foods, small swaps are generally the most effective approach. “Replace sugary snacks with whole fruit or nuts, or instead of a sweetened yogurt, opt for plain yogurt and add your own fruit or honey for sweetness,&#8221; Ludlam-Raine said. &#8220;These small changes add up.” Other tips include cooking more meals from scratch and opting for more minimally processed foods. &#8220;You can swap processed (red) meats like ham for leaner, minimally processed cuts like chicken breasts or fish,&#8221; Ludlam-Raine said. &#8220;Or, instead of packaged snacks, try homemade options like roasted chickpeas or wholegrain crackers with hummus.&#8221;', NULL, 'https://www.healthline.com/health-news/ultra-processed-foods-type-2-diabetes-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/ultra-processed-meat-slices-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:36.46222', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.46222', '2026-01-25 06:50:36.46222');
INSERT INTO public.radar_items VALUES ('f763f383-e110-445a-8dda-49066a46cc9f', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'd4aa8390e17d0cbd9c4e07a2aa6bebf5', 'Should Cannabis Have Standard Units Like Alcohol? What Experts Think', NULL, 'Researchers say that standard units for cannabis use, similar to those set for alcohol, could help guide safer consumption. Image credit: Wizemark/Stocksy Similar to alcohol consumption, cannabis users could benefit from a similar “standard drink” framework, researchers say. A new study suggests that setting limits could help guide safer consumption among those who frequently use cannabis. Clearer dose guidance could help cannabis users and clinicians better understand risks associated with heav', NULL, 'Researchers say that standard units for cannabis use, similar to those set for alcohol, could help guide safer consumption. Image credit: Wizemark/Stocksy Similar to alcohol consumption, cannabis users could benefit from a similar “standard drink” framework, researchers say. A new study suggests that setting limits could help guide safer consumption among those who frequently use cannabis. Clearer dose guidance could help cannabis users and clinicians better understand risks associated with heavy use, particularly among young people. Standardized dose units for cannabis could help establish clearer limits for safer use, according to new research. The United States has a clear definition of a “standard drink” to guide safe alcohol consumption, but for cannabis, it&#8217;s more of a gray area. A well-defined and standardized unit of measurement is crucial for cannabis users and healthcare professionals, researchers say. A new study published on January 12 in Addiction used a standardized unit system to identify thresholds at which cannabis use was associated with cannabis use disorder (CUD) in adults and adolescents. About 30% of cannabis users develop CUD, and those who start using cannabis during youth or adolescence have a higher risk of developing it. If you use cannabis on a regular basis, being aware of your consumption can help support healthier decisions. For doctors, a framework for cannabis use could facilitate consistent research methods and more reliable diagnoses. “The aim of this work is harm reduction,” said first study author Rachel Lees Thorne, PhD, associate director of the Addiction and Mental Health Group (AIM) at the University of Bath, United Kingdom. &#8220;No level of cannabis use is completely safe; however, clearer information about THC intake could help people who use cannabis regularly to potentially reduce their risk,&#8221; Thorne told Healthline. Setting limits for cannabis use: How much is too much? Rather than relying on typical measures of cannabis use, such as frequency or weight, the researchers focused on total THC intake. THC is the primary psychoactive compound in cannabis and is responsible for the “high” feeling people may associate with cannabis. Cannabis doses are often subjective and difficult to measure accurately. Not only does the potency of cannabis products — including flower, edibles, vapes, and even beverages — vary widely, but colloquial measures like “one joint” can also vary from user to user. Instead, the study uses 5 milligrams (mg) of THC as a standard unit. This specific quantity was first implemented by the National Institute on Drug Abuse (NIDA) in 2021 as a requirement to help standardize cannabis research. The study used data from the CannTeen study, a year-long observational study that tracked cannabis use patterns among adults and adolescents. The study included 150 participants, comprising 65 adults in their twenties and 85 adolescents. These cohorts were intentionally monitored separately to identify potential differences in how cannabis use affects adolescents and adults. Over a 1-year period, participants regularly checked in and reported on their cannabis use, including product type (such as flower or hash), potency, and frequency. This data was then combined and converted into an estimated number of weekly standard (5mg THC) doses. After one year of observation and data collection, participants were assessed for CUD symptoms and severity. The researchers found that in adults, the risk of CUD increased at around 8 units (40mg THC) per week. Adults who used 13 or more units per week had a greater risk of moderate to severe CUD. Cannabis’ effects on adolescents were even more pronounced, requiring just 6 units to increase their risk of CUD. It also took less THC to increase adolescents’ risk of more severe CUD: just an additional half unit per week. In an additional analysis, the 8-unit threshold proved to be a reliable predictor of which adult participants had CUD. Roughly 80% of adult participants who used fewer than 8 units per week did not have CUD, whereas around 70% of those who used more than 8 units per week did. For George Singletary, MD, assistant professor of addiction medicine at the Tulane University School of Medicine, the message is clear: “The more you use, the riskier your use is.” Singletary wasn’t involved in the research. Is a standard unit of cannabis feasible? If we have a standard unit for alcohol, why not cannabis? The answer to that question is complex, according to Paul Armentano, deputy director of the National Organization for the Reform of Marijuana Laws (NORML). Armentano wasn&#8217;t involved in the study. &#8220;Ideally, there exists a need for health professionals and others to have greater specificity when delineating cannabis use versus misuse,&#8221; Armentano told Healthline. &#8220;However, given the wide variety of formulations of cannabis products available and the uniquely poor bioavailability of many of these products, there remain serious questions as to the practicality, feasibility, and real-world application of the methods proposed in this paper,” he said. Unlike alcohol, which is almost uniformly ingested, cannabis products can be consumed in a number of ways, like smoking, eating, vaping, and topical use. The absorption and bioavailability of THC — the amount that actually makes it into your bloodstream — is also heavily dependent on how you consume it. Smoking and vaping have the highest bioavailability (between 10 to 35%) while oral has a lower bioavailability (4 to 12%). How cannabis is consumed can also affect the onset (how long it takes to feel the effects) and duration. Additionally, in the United States, recreational and medical cannabis laws are set at the state level rather than federally, creating a patchwork of regulations that makes it difficult to establish a single, nationwide standard. Singletary said that a unit standard would be beneficial, but establishing one would be an uphill battle against the cannabis industry. “I think it&#8217;s really hard to get marijuana users to really quantify how much they&#8217;re using. And that&#8217;s the first thing I tell anybody with an addiction problem: if you can&#8217;t measure it, then you can&#8217;t manage it,” Singletary said.', NULL, 'https://www.healthline.com/health-news/should-cannabis-have-standard-units-like-alcohol', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Cannabis-Use-Stocksy_txpac9a092cv0E400_Medium_2649563-Header.jpg', NULL, NULL, '2026-01-25 06:50:36.587572', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.587572', '2026-01-25 06:50:36.587572');
INSERT INTO public.radar_items VALUES ('d9deceb7-95a2-49f4-a721-05744412a6f8', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '8d2ad390336df4db0fe551cecf92c175', 'Coffee''s Surprising Health Benefits: What the Latest Research Says', NULL, 'Research suggests that coffee may offer more benefits than initially thought. Image Credit: Juan Moyano/Stocksy A 2025 study found that coffee drinkers may have a 40% lower risk of AFib recurrence. More research from 2025 shows that drinking black coffee daily can lower a person’s overall mortality risk and their risk of death from cardiovascular disease. Another study from 2025 found that the polyphenols in black coffee may lower the risk of type 2 diabetes. Many people enjoy starting their day', NULL, 'Research suggests that coffee may offer more benefits than initially thought. Image Credit: Juan Moyano/Stocksy A 2025 study found that coffee drinkers may have a 40% lower risk of AFib recurrence. More research from 2025 shows that drinking black coffee daily can lower a person’s overall mortality risk and their risk of death from cardiovascular disease. Another study from 2025 found that the polyphenols in black coffee may lower the risk of type 2 diabetes. Many people enjoy starting their day with a cup (or two) of coffee. Approximately 66% of adults in the United States drink coffee on a daily basis. Recent research has shown that coffee may be better for your heart than originally thought. Studies have also found that daily coffee consumption may also help reduce your risk of type 2 diabetes. There are various potential health benefits associated with drinking coffee, including boosting energy, aiding in weight management, and potentially reducing the risk of depression. However, it is essential to note that these benefits may diminish if you add significant amounts of sugar and saturated fats, such as cream, to your coffee. Experts recommend reducing your caffeine intake if you are pregnant or nursing. Is coffee linked to AFib risk? Conventional medical wisdom has generally advised people who have atrial fibrillation (AFib) or who are at risk of it to cut back or avoid coffee. However, the idea that coffee can lead to an increased risk of AFib has been scrutinized in recent years. A recent clinical trial further challenged this idea. It suggested that instead of potentially triggering AFib, coffee may actually reduce the frequency. The trial results were published in JAMA near the end of 2025. The randomized controlled trial, called DECAF, found that among 200 adults diagnosed with AFib or a related condition, atrial flutter, and with a history of AFib, those who drank coffee daily had fewer recurrent episodes than those who avoided caffeine entirely over a 6-month period. “There have been conflicting thoughts about whether coffee affects atrial fibrillation,” Gregory Marcus, MD, a cardiologist and professor of medicine at the University of California, San Francisco, and senior author of the research, told Healthline. “To our knowledge, this is the only long-term randomized trial of caffeinated coffee on any cardiovascular endpoint. It suggests that caffeinated coffee may protect against atrial fibrillation, at least among people that otherwise enjoy and tolerate caffeinated coffee,” he added. At the end of the trial, the researchers saw a 40% lower risk of AFib recurrence among the individuals who regularly consumed coffee. The exact reasoning behind this reduction is still unclear. The authors suggest that blocking adenosine may confer antiarrhythmic properties to caffeine. Adenosine is a naturally occurring chemical in the body that makes you feel drowsy. It’s part of how the body regulates energy and sleep cycles, but it’s also known to trigger AFib. Another suggestion relates to the anti-inflammatory properties in coffee that may protect against AFib. “Coffee, as we know, naturally contains antioxidant properties, such as chlorogenic acids and melanoidins, which may act as protective effects for our body and our heart,” said Alyssa Kwan, a clinical dietitian in Cardiology at Stanford Medicine who wasn’t affiliated with the research. However, the study did not provide direct evidence for this or any other reasoning behind the AFib reduction. Coffee may help preserve heart health A 2025 observational study concluded that coffee may be beneficial for your heart and overall health, especially when consumed black. The researchers reported that individuals who drank 1 to 3 cups of caffeinated black coffee per day with little to no sugar or saturated fats had a 14% lower overall mortality risk and a lower risk of death due to cardiovascular disease compared to those who drank no coffee. However, they also noted that drinking more than 3 cups of coffee a day did not have an association with additional risk reduction. There was also no risk reduction for those who added significant amounts of sugar or fats to their coffee. “It’s an interesting analysis in a nationally representative sample of U.S. adults that is largely consistent with existing studies finding the benefits of moderate coffee intake,&#8221; said Maya Vadiveloo, PhD, associate professor in the Department of Nutrition at the University of Rhode Island, chair of the American Heart Association (AHA) Nutrition Committee, and a registered dietitian, who wasn’t involved in the study. Kristin Kirkpatrick, a registered dietitian and the president of KAK Consulting, as well as a dietitian at the Cleveland Clinic Department of Wellness & Preventive Medicine in Ohio, echoed these remarks. Kirkpatrick wasn’t involved in the study. “The study is in line with previous studies showing mortality benefits to coffee consumption,&#8221; she told Healthline. &#8220;I also think that highlighting the fact that what we put in our coffee is often the culprit for a less healthy drink is a critical point for consumers.” Still, the study may have some limitations. Zhaoping Li, MD, a professor of clinical medicine at the University of California, Los Angeles, said that the research utilized older databases, which were based on self-reported information by the participants. Li wasn’t involved in the study. “You shouldn’t think that if you drink black coffee that it’s going to extend your life. That’s not what the study says,&#8221; said David Cutler, MD, a family medicine physician at Providence Saint John’s Health Center in Santa Monica, CA, who wasn&#8217;t involved in the study. Cutler told Healthline that other factors may influence the results, such as the fact that people who drink coffee tend to be generally healthier than those who don’t. Coffee and type 2 diabetes risk A 2025 research analysis suggested that caffeinated or decaffeinated black coffee may help lower the risk of type 2 diabetes. Researchers affiliated with universities in the Republic of Korea noted that individuals who drink 3 to 5 cups of black coffee daily may benefit from natural compounds called polyphenols. The research showed that daily consumption of black coffee can have various benefits, including: modulating blood sugar levels suppressing inflammation enhancing insulin sensitivity providing antioxidant properties improving glucose metabolism The results were similar for both caffeinated and decaffeinated coffee. This suggests that the benefits may derive from compounds other than caffeine. These benefits included a 20% to 30% decrease in the risk for type 2 diabetes in coffee drinkers. Marilyn Tan, MD, a clinical associate professor of medicine at Stanford University in California, who was not involved in the study, had some cautions about the findings. Tan told Healthline that the findings are notable, but added that some of the research reviewed was conducted in lab settings. She noted that observational studies often fail to account for external factors, such as the overall health of coffee drinkers. The researchers of the analysis also note that further research is needed. Zhaoping Li, MD, a professor of medicine and the chief of the Division of Clinical Nutrition at the University of California, Los Angeles, who was also not involved in the study, noted that people should be aware of their caffeine intake. She said 3 cups daily is probably fine for most people, but some folks may not be able to handle the caffeine load from 4 or 5 servings per day. People with certain heart conditions should also carefully monitor their caffeine intake. “Everybody is different,” Li said.', NULL, 'https://www.healthline.com/health-news/coffee-may-improve-heart-health-lower-diabetes-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/pouring-coffee-pot-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:36.709859', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.709859', '2026-01-25 06:50:36.709859');
INSERT INTO public.radar_items VALUES ('020e954a-b586-41f4-9d31-4c85e48f89e3', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '17a45cc3650c4ba7177ca3e2da909ef6', 'Best Foods to Help You Live a Longer, Healthier Life, According to Research', NULL, 'Foods found in the Mediterranean diet, such as fruits and vegetables, may contribute to a longer life span. Image Credit: Adrian Rodd/Stocksy Nutrition is believed to play an important role in longevity. Foods like those found in the Mediterranean diet, as well as coffee, can contribute to a longer life span. Red meat, sugary beverages, and ultra-processed foods can reduce life expectancy. Looking to boost longevity in 2026? A Mediterranean diet may be the best place to start. Numerous studies i', NULL, 'Foods found in the Mediterranean diet, such as fruits and vegetables, may contribute to a longer life span. Image Credit: Adrian Rodd/Stocksy Nutrition is believed to play an important role in longevity. Foods like those found in the Mediterranean diet, as well as coffee, can contribute to a longer life span. Red meat, sugary beverages, and ultra-processed foods can reduce life expectancy. Looking to boost longevity in 2026? A Mediterranean diet may be the best place to start. Numerous studies indicate the Mediterranean diet affords many health benefits, including promoting longevity. “This diet is anti-inflammatory, it’s cardio-protective [and] protects our heart and other organs,&#8221; said Dana Hunnes, PhD, a senior clinical dietitian at UCLA Health. &#8220;It is full of unprocessed, whole foods,&#8221; Hunnes said of the Mediterranean diet. &#8220;It is high in fiber, which helps keep us regular and can help decrease inflammation. It has heart-healthy fats, primarily monounsaturated fats and some polyunsaturated omegas from plant sources. It’s full of water from the high amount of plant-based foods, and it’s a lifestyle, so the calorie intake is within reason to keep us maintaining our weight properly,” she noted. Mediterranean diet linked to lower mortality rates The Mediterranean diet consists of fruits, vegetables, legumes, tree nuts, and whole grains. It emphasizes minimally processed, plant-based foods, along with lean meats or fish, and olive oil. &#8220;In the weekly nutrition fight club, it’s a team event, not an ingredient or micronutrient one-on-one,&#8221; said Marily Opezzo, PhD, an Instructor of Medicine at the Stanford Prevention Research Center and head of the nutrition pillar at Stanford Lifestyle Medicine. &#8220;Every team wins with fruits and vegetables as the starting lineup,&#8221; Opezzo told Healthline. &#8220;They have a ton of healthy phytochemicals we can’t even name, fiber, micronutrients, and they are filling without a ton of calories if that is your goal.&#8221; Of all diets, the Mediterranean diet is one of the most extensively studied, and the science supports it as a good choice for health promotion. Research indicates that following a Mediterranean eating pattern is associated with a 25% reduction in overall mortality rates as well as significant reductions in rates of cardiovascular disease. The foods eaten in a Mediterranean diet pattern have omega-3 fatty acids, monounsaturated fats, and polyphenols, which all provide antioxidant and anti-inflammatory benefits. “Reducing oxidation, inflammation, and maintaining a healthy gut microbiome promotes health and longevity,” Mir Ali, MD, board certified general surgeon, bariatric surgeon, and medical director of MemorialCare Surgical Weight Loss Center at Orange Coast Medical Center in Fountain Valley, CA, told Healthline. “Foods that promote life expectancy include proteins, non-starchy vegetables, some fruits like berries, whole grains, nuts, legumes, and seeds. These types of foods promote cardiovascular health, reduce insulin resistance, decrease inflammation, and help to maintain a healthy weight.” Dietary patterns, such as the Mediterranean diet, are popular in countries like Greece, southern Italy, and Spain, as well as in some &#8220;Blue Zones,&#8221; which have high concentrations of centenarians or people living to 100 and beyond. How nutrition impacts the life span It is believed that diet can play a significant role in longevity. “Food in general has a huge impact on health and longevity; eating foods that can promote adverse health effects like diabetes, hypertension, and obesity will decrease a person&#8217;s lifespan; whereas, foods that help someone avoid adverse health conditions, and maintain a healthy weight and lifestyle will increase lifespan,” Ali said. Research suggests that nutrition plays a crucial role in mitigating the effects of aging mechanisms on the body and enhancing longevity. Diet can influence the level of oxidative stress in the body, age-related damage, inflammation, and cellular function. “There are foods [and] diet patterns that keep us healthier, decrease inflammation in the body, and may decrease the rate at which our DNA [telomeres] shortens or gets damaged,” Hunnes said. Coffee may play a role in longevity Along with the foods that form part of the Mediterranean diet, coffee may also be beneficial for improving longevity. Around 60% of Americans drink coffee every day, and research suggests that may be a good thing. Moderate coffee intake (about three to five cups of coffee per day) is associated with reduced overall mortality. It may also reduce the risk of major diseases like diabetes, stroke, cardiovascular disease, respiratory conditions, cognitive decline, and some types of cancers like uterine and liver cancer. “Coffee is rich in antioxidants and does have a positive metabolic effect as well. It also may improve glucose control and slow DNA breakdown (which can lead to early cell death),” Ali said. Coffee can also improve lung function and increase fat oxidation. However, Hunnes warns that adding too many ingredients to a cup of coffee could reverse some of its benefits. “It has many antioxidants in it and phytonutrients (nutrients derived from plants) that may reduce inflammation and therefore morbidity (illness), chronic disease, and mortality. Reducing inflammation in the body is associated with longevity, so, the more we can do to reduce inflammation, the better. Coffee benefits aside, what you put into your coffee is also important. Heavy cream or excess sugar could negate some of the health benefits, Hunnes said. Red meat may accelerate aging Whilst coffee and the Mediterranean diet are believed to boost longevity, red meat is believed to do the opposite. Research suggests that red meat can accelerate aging and is associated with a variety of adverse health outcomes. “Red meats are higher in saturated fats and nitrites, which has been shown to have a negative effect on cardiovascular health as well as cancer, which will decrease life expectancy,” Ali said. However, research on saturated fats has been inconclusive so far. Research also shows that nitrites may only be problematic when they are additives, not when they are from natural sources. Along with red meat, sugary beverages are also believed to have a negative impact on aging. Recent research suggests an inverse association between sugary beverages and healthy aging. “Drinks high in sugar lead to weight gain, diabetes, and cardiovascular disease, all of which contribute to decreasing life expectancy,” Ali said. In the standard Western diet, sugary drinks are a leading cause of added sugars. Data from the Centers for Disease Control and Prevention (CDC) suggests that roughly half of adults consume a sugar-sweetened beverage every day, while more than 60% of kids do the same. “(Sugary beverages) replace healthier foods/beverages in the diet that don’t add calories (and nothing else healthy) to the diet. They increase insulin need, inflammation, increase the risk for fatty liver, diabetes, heart disease, metabolic syndrome, and do not provide vitamins or minerals (naturally occurring). We don’t need empty calories in our diets,” Hunnes said. Ultra-processed foods may raise death risk Sugary drinks are just one of many ultra-processed foods that can have a negative impact on overall health and longevity. In the United States, 73% of the food supply consists of ultra-processed foods. However, these foods are linked to numerous health issues. &#8220;Ultra-processed foods are high in preservatives and unhealthy chemical additives to promote shelf life and increase taste. They are also high in sugar, low in fiber, and low in critical nutrients. All of this promotes cardiovascular disease, diabetes, and cancer, thus leading to a decreased life expectancy,” Ali said. Making dietary swaps from ultra-processed foods to whole foods is a good starting point toward improved longevity, but experts acknowledge that, at an individual level, this is a process that takes time. “The biggest health concern in the U.S. and most westernized countries is obesity, and implementing healthy foods, as discussed, can reduce obesity, and thereby increase longevity,” Ali said. “This has been known for some time; however, implementing significant dietary changes and educating many people remains a challenge.”', NULL, 'https://www.healthline.com/health-news/best-foods-longer-healthier-life-research', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Foods-Live-Stocksy_txp149b6bb3AxD400_Medium_6501265-Header.jpg', NULL, NULL, '2026-01-25 06:50:36.831783', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.831783', '2026-01-25 06:50:36.831783');
INSERT INTO public.radar_items VALUES ('ed20f68e-9e88-48f3-9369-298ac680fa1c', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'e4ed340e49b4ee011b9323c2f9707ae6', 'RFK Jr.''s New Dietary Guidelines Reduce Added Sugars, Processed Foods', NULL, 'Federal health officials say the inverted food pyramid structure in the new dietary guidelines will help make Americans healthier. Mapodile/Getty Images Federal officials have released the 2025–2030 Dietary Guidelines for Americans. The new food pyramid recommends increasing daily consumption of protein, fruits, vegetables, and whole grains, while decreasing the amount of refined carbohydrates, sugars, and highly processed foods. Experts say the revised guidelines offer helpful nutrition advice,', NULL, 'Federal health officials say the inverted food pyramid structure in the new dietary guidelines will help make Americans healthier. Mapodile/Getty Images Federal officials have released the 2025–2030 Dietary Guidelines for Americans. The new food pyramid recommends increasing daily consumption of protein, fruits, vegetables, and whole grains, while decreasing the amount of refined carbohydrates, sugars, and highly processed foods. Experts say the revised guidelines offer helpful nutrition advice, but they are concerned about the inclusion of red meat as a primary protein source. Federal officials have released the 2025–2030 Dietary Guidelines for Americans, which emphasize the importance of protein, fruits, vegetables, and whole grains. The new inverted food pyramid structure places dairy products, such as cheese, near the top, while encouraging a reduction in highly processed foods, carbohydrates, and sugars, which are positioned near the bottom. The 10-page guidelines also mark a shift from current alcohol recommendations, making them more generalized as opposed to specific limits on how many drinks per day males and females should have. “These guidelines return us to the basics,” said Health and Human Services Secretary Robert F. Kennedy Jr. in a statement. “American households must prioritize whole, nutrient-dense foods — protein, dairy, vegetables, fruits, healthy fats, and whole grains — and dramatically reduce highly processed foods. This is how we Make America Healthy Again.” What doctors think of the &#8216;new&#8217; food pyramid The new MAHA guidelines have been met with both widespread criticism and general praise. In a statement, the Physicians Committee for Responsible Medicine commended the new guidelines for limiting certain fats and alcohol consumption while emphasizing the importance of fruits and vegetables. However, the group expressed concerns about the recommendations regarding meat and dairy products. They said they are also worried about the influence certain industries may have had on the guideline decisions. “The guidelines are right to limit cholesterol-raising saturated (“bad”) fat,” said Neal Barnard, MD, president of the Physicians Committee for Responsible Medicine. “But they should spell out where it comes from: dairy products and meat, primarily. And here the guidelines err in promoting meat and dairy products, which are principal drivers of cardiovascular disease, diabetes, and obesity.” The American Heart Association (AHA) generally found RFK Jr.&#8217;s new guidelines to be on the right track. “The American Heart Association welcomes the new dietary guidelines and commends the inclusion of several important science-based recommendations, notably the emphasis on increasing intake of vegetables, fruits, and whole grains while limiting consumption of added sugars, refined grains, highly processed foods, saturated fats, and sugary drinks,” the association said in a statement. Mir Ali, MD, a general surgeon, bariatric surgeon, and medical director of the MemorialCare Surgical Weight Loss Center at Orange Coast Medical Center in California, said he generally supports the guidelines. “I like that they emphasize proteins and vegetables over carbohydrates and sugars,” Ali told Healthline. “Overall, they’re a step in the right direction.” New dietary guidelines: How much protein? The Dietary Guidelines for Americans are a federal nutrition recommendation that is updated every five years. The federal nutrition guidelines also help inform the National School Lunch Program, which provides meals to nearly 30 million children on a typical school day. The dietary guidelines outline several recommendations. Among them: Prioritize protein at every meal. Consume full-fat dairy with no added sugars. Eat vegetables and fruits throughout the day, focusing on whole foods. Incorporate healthy fats from whole foods such as meats, seafood, eggs, nuts, seeds, olives, and avocados. Focus on whole grains while sharply reducing refined carbohydrates. One of the key recommendations in the new guidelines is to increase Americans&#8217; daily protein consumption from 0.36 grams per pound of body weight to 0.54 to 0.73 grams per pound of body weight. Federal health officials urge Americans to include protein-rich foods in every meal. The American Heart Association (AHA), however, stated that more research is needed on protein consumption before people begin changing their diets. “Pending that research, we encourage consumers to prioritize plant-based proteins, seafood, and lean meats and to limit high fat animal products, including red meat, butter, lard, and tallow, which are linked to increased cardiovascular risk,” the AHA said in its statement. What about sugar and alcohol? The new guidelines also urged Americans to sharply limit their intake of added sugars or non-nutritive sweeteners, saying “no amount” is considered part of a healthy diet. It states that no meal should consist of more than 10 grams, or about 2 teaspoons, of added sugar. The federal officials also targeted “highly processed” foods and refined carbohydrates, urging Americans to avoid “packaged, prepared, ready-to-eat or other foods that are salty or sweet, such as chips, cookies and candy.” Ali said this recommendation is “a very good addition” to the guidelines. The new guidelines alter previous recommendations that limited alcohol to one drink or less per day for females and two drinks or less per day for males. The new recommendations advise Americans to “consume less alcohol for better health.” The guidelines also state that alcohol should be avoided by pregnant people, people recovering from alcohol use disorder, those who are taking medications or have medical conditions that can interact with alcohol, and those who are unable to control the amount they drink. Ali said it’s best to avoid alcohol in general, but believes that abstinence is unrealistic drinking is often synonymous with socialization. “Minimizing alcohol is a good goal,” he said. Best foods for a healthy, balanced diet Ali said that consumers can make informed choices within the guidelines to achieve a balanced diet. He noted that protein can help build muscle, but it’s important to choose good sources. “Red meat isn’t necessarily bad as long as it’s not overdone,&#8221; Ali said, adding that other sources of protein, such as chicken, fish, lentils, beans, and nuts, might be better choices. “These are all good sources of protein,” he said. Ali noted that vegetables in general are a good component of a healthy diet, although he added that “starchy” vegetables, such as potatoes and corn, should be consumed in moderation. He added that fruits contain a lot of good nutrients, but they also can contain high levels of sugar. He said berries are often a better choice compared to apples and bananas. Ali further recommended limiting the intake of carbohydrate-laden foods such as bread, pasta, and rice. “It’s important to emphasize lean protein and non-starchy vegetables,” he said. “The new guidelines deliver a clear, common-sense message to the American people: eat real food,” HHS officials wrote in their statement.', NULL, 'https://www.healthline.com/health-news/2025-2030-dietary-guidelines-for-americans-key-changes', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/healthy-food-eating-groceries-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:36.955833', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:36.955833', '2026-01-25 06:50:36.955833');
INSERT INTO public.radar_items VALUES ('244d563f-eff9-4715-b76c-400db0b97de8', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '66990ca7c3c072e7ff7de4d9231d65f4', 'Drugmakers Raise Prices on 350 Medications Amid Pressure to Cut Costs', NULL, 'U.S. drug manufacturers are expected to raise prices on at least 350 prescription medications. Anna Moneymaker/Getty Images A new report states that U.S. drugmakers will increase prices on at least 350 medications. This is despite pressure from President Trump to bring drug prices down. Experts say the reality is that there are tariffs and higher labor and material costs. To maintain shareholder satisfaction, pharmaceutical companies must increase prices. This disconnect with actual practice may', NULL, 'U.S. drug manufacturers are expected to raise prices on at least 350 prescription medications. Anna Moneymaker/Getty Images A new report states that U.S. drugmakers will increase prices on at least 350 medications. This is despite pressure from President Trump to bring drug prices down. Experts say the reality is that there are tariffs and higher labor and material costs. To maintain shareholder satisfaction, pharmaceutical companies must increase prices. This disconnect with actual practice may ultimately lead to the policy&#8217;s failure. U.S. drug manufacturers are expected to raise prices on at least 350 medications in 2026. The increase coincides with pressure from the Trump administration to lower consumer costs. The detailed analysis, conducted by Reuters, was based on data from the healthcare research firm 3 Axis Advisors, which found a median increase of approximately 4%, in line with the previous year. They additionally note that important drugs such as vaccines for COVID-19, RSV, and shingles, as well as the cancer treatment Ibrance, will be among those with higher price tags. Experts say this seeming contradiction arises from the fact that pharmaceutical companies must balance inflationary pressures with government negotiations. Prescription drugs cost more in the U.S. As explained in Executive Order 14297, Americans have been paying significantly more for prescription drugs than consumers in other developed nations. However, the Trump administration feels that Americans should not be subsidizing the costs for the rest of the world. The document explains that many countries impose strict price controls, which are offset by higher prices in the United States. By taking a &#8220;most favored nation&#8221; approach, the administration aims to tie American prices to the lowest price paid by other developed nations. The administration further states that this will lower consumers&#8217; out-of-pocket costs and encourage foreign governments to contribute more to drug development costs. This could be particularly beneficial for individuals facing economic hardship, especially those with severe and chronic conditions. Additionally, it could reduce reliance on foreign supply chains, increasing the nation&#8217;s security. Why are drug prices increasing? David E. Williams, President and co-founder of Health Business Group, suggested that President Trump wants drug prices to drop to show Americans that he&#8217;s taking action on healthcare costs, particularly as Affordable Care Act (ACA) subsidies are being phased out. &#8220;It&#8217;s easy for the average voter to understand and it&#8217;s a change that individual companies can make unilaterally,&#8221; he told Healthline. &#8220;Also, U.S. prices are the highest in the world, and it&#8217;s easy to compare prices in the U.S. with benchmarks elsewhere.&#8221; However, drug companies want to boost profits and meet earnings goals, Williams said. Price increases have been the primary mechanism for doing this since it&#8217;s easier than launching a new drug. &#8220;Shareholders matter more than the President,&#8221; he said, &#8220;and the companies assume they can get away with continuing their increases especially if they make concessions on individual, high-profile products.&#8221; Williams added that drug prices are also rising for the same reason that many other prices are going up: higher labor costs, higher materials costs, and tariffs. What higher drug prices mean for consumers Zachary W. Schulz, PhD, a public health historian and senior lecturer at Auburn University, said what he finds most striking about the drug price hike isn&#8217;t the number of drugs involved, but which drugs are. &#8220;Vaccines and specialty cancer therapies sit at the intersection of individual health and population health,&#8221; he explained. Schulz said that when prices rise for products like vaccines, this can suppress uptake, widen disparities, and undermine preventive strategies that public health relies on. &#8220;From a public-health perspective, raising prices on vaccines and specialty drugs is uniquely risky,&#8221; he said. &#8220;These are products whose value depends on widespread access.&#8221; According to Schulz, while price increase may help protect corporate revenue, they can erode population-level benefits that exist when uptake is high. He additionally noted that higher list prices often translate into higher out-of-pocket costs, even if insurers negotiate discounts behind the scenes. &#8220;Patients with high-deductible plans or no insurance are especially exposed to these increases,&#8221; he explained. Rising drug prices also &#8220;ripple outward,&#8221; said Schulz, contributing to higher insurance premiums, tighter formularies, and more administrative barriers, which can delay or restrict access. &#8220;The disconnect many patients experience — being told prices are ‘coming down’ while their pharmacy bill goes up — reflects the gap between political messaging and how the U.S. drug-pricing system actually works,&#8221; said Schulz, who described it as not so much a contradiction as &#8220;a structural reality.&#8221; &#8220;Without broad price-control authority or systemic reform, political pressure alone is unlikely to change the underlying incentives that drive drug pricing in the United States,&#8221; he concluded. Impacts of higher drug prices The Trump administration’s push to level U.S. drug prices to those in other wealthy nations reflects an effort to address persistent and long-standing healthcare disparities. At the same time, the Reuters analysis highlights the deep-seated nature of the current pricing system, with manufacturers continuing to raise prices on hundreds of drugs despite public pressure to the contrary. For pharmaceutical companies, incremental price hikes remain a familiar and reliable way to offset rising costs, satisfy shareholders, and protect earnings, even as they negotiate selective concessions on highly visible products. And, as experts point out, these increases are often driven by the same inflationary pressures affecting other industries, compounded by the unique dynamics of drug development and market exclusivity. The result is a system in which prices can rise broadly even while certain patients see targeted discounts. For consumers, the impact is uneven but often tangible. Higher list prices can translate into higher out-of-pocket costs, particularly for individuals with high deductibles, limited coverage, or no insurance. However, when vaccines and specialty drugs are involved, the stakes extend beyond individual wallets to public health and access more broadly. Ultimately, the gap between political messaging and pharmacy receipts underscores a crucial reality: without sweeping reforms or direct price-control authority, efforts to rein in drug costs are likely to remain partial and contentious. Until the underlying incentives change, Americans may continue to hear rhetoric about falling prices while still paying more for their medications at the pharmacy counter.', NULL, 'https://www.healthline.com/health-news/drugmakers-raise-prices-on-350-medications-report', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Drugmakers-prices-GettyImages-1431083160-Header.jpg', NULL, NULL, '2026-01-25 06:50:37.080348', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.080348', '2026-01-25 06:50:37.080348');
INSERT INTO public.radar_items VALUES ('ddc8e45a-c7e8-4cc3-98f9-3621afffe0e3', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '80538a2cad1e9f0bac59e4f05b3b66fd', 'HHS Overhauls Childhood Vaccine Schedule, Recommending Fewer Shots', NULL, 'The CDC has issued new vaccination guidelines for children that significantly reduce the number of recommended shots. Image credit: RONALDO SCHEMIDT/Getty Images Federal health officials at the CDC have released a new childhood vaccination schedule. The new recommendations indicate that all children should be vaccinated against 11 diseases, while vaccinations for six other diseases are recommended only for children at higher risk. Experts say the new recommendations will discourage some parents ', NULL, 'The CDC has issued new vaccination guidelines for children that significantly reduce the number of recommended shots. Image credit: RONALDO SCHEMIDT/Getty Images Federal health officials at the CDC have released a new childhood vaccination schedule. The new recommendations indicate that all children should be vaccinated against 11 diseases, while vaccinations for six other diseases are recommended only for children at higher risk. Experts say the new recommendations will discourage some parents from getting their children inoculated, which could lead to higher rates of childhood diseases. Many health experts are harshly criticizing the new childhood vaccination schedule unveiled this week by the Centers for Disease Control and Prevention (CDC). On Monday, federal health officials released new vaccination recommendations for children. The guidelines reduce the number of primarily targeted diseases from 16 to what the Department of Health and Human Services (HHS) has described as the 11 &#8220;most serious infectious diseases.&#8221; Vaccinations against the following diseases are still recommended for all children: measles mumps rubella chickenpox polio diphtheria tetanus whooping cough haemophilus influenzae type b (Hib) pneumococcal conjugate (pneumonia) human papillomavirus (HPV) (one dose only) The CDC is revising its recommendations on six other diseases to include only children who are at higher risk of infection. Those diseases include: hepatitis A hepatitis B meningococcal ACWY meningococcal B respiratory syncytial virus (RSV) CDC officials added that vaccinations for children against influenza, COVID-19, and rotavirus should be based on “shared clinical decision-making,” which means parents must consult with a healthcare professional before their children receive the vaccinations. Vaccines for hepatitis A, hepatitis B, meningococcal ACWY, and meningococcal B for children at average risk also fall under the domain of shared clinical decision making. The officials emphasized that all vaccinations are still available for families who wish to receive them. They also noted that the guidelines still require insurance companies to fully cover all vaccinations. “After an exhaustive review of the evidence, we are aligning the U.S. childhood vaccine schedule with international consensus while strengthening transparency and informed consent. This decision protects children, respects families, and rebuilds trust in public health,” said HHS Secretary Robert F. Kennedy Jr. in a statement. Health experts react to new vaccination schedule The new recommendations are receiving the support of at least one medical professional interviewed by Healthline. Monique Yohanan, MD, a senior fellow for health policy at Independent Women, said the new schedule is good policy. “This is a positive development,&#8221; Yohanan told Healthline. &#8220;It is a more focused, risk-proportionate schedule. It preserves vaccines with clear herd immunity and community protective value, and it removes only those with limited population benefit. From an epidemiologic standpoint, it is more coherent than the prior schedule,&#8221; said Yohanan, who recently wrote a paper, &#8220;Rethinking Vaccine Policy.&#8221; “The real opportunity is that it has the potential to improve trust and re-engage families who had reached a threshold and opted out of vaccination entirely,” she added. Inderpal Randhawa, MD, a pediatrician and immunologist as well as the medical director of the Children’s Pulmonary Institute at MemorialCare Miller Children’s & Women’s Hospital Long Beach and the founder of Food Allergy Institute in Long Beach, CA, said the new guidelines could restore confidence in some sectors of the public, However, he expressed concern about the lack of scientific data behind the findings. “The shift toward a more ‘focused’ immunization approach by categorizing vaccines based on risk and parental decision alongside physician counsel reflects an effort to rebuild trust and engage families in shared decision-making,” Randhawa told Healthline. “However, public health policy must be grounded in rigorous scientific evidence and epidemiological data to ensure children are protected against serious infectious diseases,” he added. Other health experts are more sharply critical, saying the new recommendations will erode public confidence in vaccinations and cause an increase in childhood diseases. “This is a terrible, terrible, terrible idea,” said Danelle Fisher, MD, a pediatrician at Providence Saint John’s Health Center in Santa Monica, CA. “This adds a barrier to childhood vaccinations and sends the message that these diseases aren’t so bad,” Fisher told Healthline. “It also adds more fuel to anti-vaccination people.” Risk of disease spread without vaccinations Experts say the new CDC regulations may discourage parents from getting their children vaccinated, or at least make it more difficult. Paul Krogstad, MD, a pediatric infectious disease expert at UCLA Health in Los Angeles, said that parents may now have to make separate appointments to ensure “shared decision making” on certain immunizations. “People may need to make a specific time to get these,” he told Healthline. Krogstad said a decrease in overall vaccinations could lead to an upsurge in all diseases. He notes that we have seen this lack of herd immunity in measles cases, which rose to more than 2,000 in the United States (including 1,400 in children) in 2025 after being nearly eradicated through vaccination two decades ago. “This will allow nature to take its course,” Krogstad said. “This will create an impediment to preventing disease. It takes everything to a whole new level.” William Schaffner, MD, an infectious disease expert and professor of medicine at Vanderbilt University in Tennessee, also sees a rise in many diseases under the new policy. “I, and my colleagues in public health, pediatrics, and family medicine, were dismayed and concerned by the newly recommended infant/childhood vaccination schedule,” Schaffner told Healthline. “It is not based in science or sound public health,” he added. “It will turn back the clock to the bad old days. If followed, the new recommendations will result in children suffering infectious diseases that could have been prevented completely.” “There is legitimate concern that relaxing universal recommendations could reduce vaccine uptake for diseases that are currently rare but still pose real risks,” added Randhawa. “Historical data show that when vaccination rates drop, even uncommon diseases like measles can resurge. This is why the evidence base behind each change must be transparent, robust, and clearly communicated to clinicians and families alike.” There are several diseases, however, that are key concerns for health experts. One is hepatitis A, a viral infection that is usually transmitted through contaminated food and water or close physical contact with someone who has the disease. Fisher noted that hepatitis A can cause liver damage and “is not a benign disease.” There is no cure, although many people recover on their own within a few months. Another concern is rotavirus, a highly contagious disease most common in children under 5 years of age. Dehydration is a major concern for people with rotavirus. Krogstad said rotavirus can cause severe diarrhea in children and lead to hospitalization. He said it can be prevented with the current “well-tested” oral vaccine given to children. Another concern for Krogstad is the flu. He said children 6 months to 23 months of age have the same serious risks with the flu as older adults do. “People really underestimate the danger influenza poses to young children,” he said. Fisher said all this misery can be avoided with widespread vaccinations. “Kids are going to suffer. Families are going to suffer,” she said. “There is no need to make people and families suffer.” New vaccine policy modeled after Denmark In developing their recommendations, Trump administration officials reviewed the vaccination policies of 20 other developed nations. They concluded that the United States is a “global outlier among developed nations in both the number of diseases addressed in its routine childhood vaccination schedule and the total number of recommended doses.” The officials noted that the U.S. vaccination schedule doesn’t necessarily produce better results. “Many peer nations that recommend fewer routine vaccines achieve strong child health outcomes and maintain high vaccination rates through public trust and education rather than mandates,” they wrote. The officials said they came up with a vaccination schedule that closely resembles the one now in place in Denmark. “President Trump directed us to examine how other developed nations protect their children and to take action if they are doing better,” Kennedy said. However, experts caution that comparing the United States to Denmark is a misguided approach. Fisher said out that Denmark’s population is about 6 million people compared to the nearly 350 million people who live in the United States. She notes that the United States population is far more diverse than Denmark&#8217;s. The northern European country also has a universal health system that provides preventive care as well as immunization coverage. In addition, Fisher noted that Denmark has a much colder climate than most of the United States. She said that limits the type of diseases as well as their spread. Schaffner agrees the comparison is not valid. “European countries are smaller, less diverse, and provide universal medical care to their populations,” he said. “Among the European countries, Denmark is the outlier, recommending fewer routine vaccines than the other countries. They are not an optimal model for the U.S. to follow.” Always talk with your doctor about vaccinations Experts interviewed by Healthline said they will now encourage people to seek advice from their doctors about childhood vaccinations rather than rely on the federal government. “It deeply saddens me to say that the U.S. public and its medical providers can no longer rely on our federal government’s vaccine recommendations,” said Schaffner. “Ignore them; rather, look to recommendations from professional organizations to provide solid, science-based vaccine recommendations,&#8221; he continued. Fisher also advocates that people talk to their doctors about vaccinations rather than listen to the federal government. “The medical community doesn’t just cure diseases, we also try to prevent them,” she said.', NULL, 'https://www.healthline.com/health-news/new-cdc-childhood-vaccination-guidelines', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/child-vaccine-clinic-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:37.204718', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.204718', '2026-01-25 06:50:37.204718');
INSERT INTO public.radar_items VALUES ('2bb9cf66-7146-4759-b320-9ce5ed6fcc00', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'd2feaa262f73d6d95117fa2486cdbb45', 'FDA Approves Wegovy Weight Loss Pill: How It Compares to Injectables', NULL, 'The Food and Drug Administration (FDA) recently approved a tablet version of the GLP-1 drug Wegovy for weight loss. Image courtesy of Novo Nordisk Novo Nordisk officials said a new pill version of its weight loss drug Wegovy is now available in the United States. The Food and Drug Administration recently approved the Wegovy tablet as a prescription treatment for obesity and weight management. Experts say a pill version of a GLP-1 drug could make it easier for people to stay on a weight loss regi', NULL, 'The Food and Drug Administration (FDA) recently approved a tablet version of the GLP-1 drug Wegovy for weight loss. Image courtesy of Novo Nordisk Novo Nordisk officials said a new pill version of its weight loss drug Wegovy is now available in the United States. The Food and Drug Administration recently approved the Wegovy tablet as a prescription treatment for obesity and weight management. Experts say a pill version of a GLP-1 drug could make it easier for people to stay on a weight loss regimen, but they added that diet and exercise still remain the most important components of these types of programs. A well-known weight loss medication is now available in the United States in pill form. The availability comes just weeks after the Food and Drug Administration (FDA) approved the tablet version of the GLP-1 drug Wegovy for weight loss. Officials at Novo Nordisk, the manufacturer of the medication, said a “starter dose” of 1.5 milligrams (mg) can now be purchased with a prescription at pharmacies and other facilities in the United States. Higher doses of the Wegovy pill will be available by the end of this week, company officials said. They note that the new pill is the only medication that is specifically prescribed for weight loss that can be taken as a tablet as opposed to an injection. They reported that the Wegovy pill produced an average of 16% weight loss in people who took the medication over a 64-week period in a phase III clinical trial. &#8220;We know there are people who are interested in addressing their weight but have been waiting on the sidelines for a medicine that was right for them. For many of them, that wait is over as we can now offer the powerful efficacy of Wegovy in a once-daily pill,” said Ed Cinca, senior vice president of marketing and patient solutions at Novo Nordisk, in a statement. Eli Lilly is currently seeking FDA approval for an oral weight loss medication it has developed and tested in phase III clinical trials. Experts say a pill form of GLP-1 medication could help people adhere to a weight loss routine that also involves a healthy diet and regular exercise. “The advent of a weight loss pill certainly has some advantages,” said Mir Ali, MD, a general surgeon, bariatric surgeon, and medical director of MemorialCare Surgical Weight Loss Center at Orange Coast Medical Center in California. “People are more used to taking pills than they are taking injections.” “I think this will be a great option for individuals who have not considered taking these drugs… due to them being injectables,” added Kristin Kirkpatrick, RD, the president of KAK Consulting and a dietitian at the Cleveland Clinic Department of Wellness & Preventive Medicine in Ohio. What to know about the Wegovy pill Novo Nordisk officials said the Wegovy pill is now available in more than 70,000 U.S. pharmacies, including CVS and Costco, as well as select telehealth providers. They said the medication will cost about $149 for a month’s supply without insurance coverage or special savings under an agreement between the company and the Trump administration. With insurance, the Wegovy starter dose could cost as little as $25 per month. A 4 mg dose of the pill will also cost $149 per month until April 15. After that, the monthly price will rise to $199. The 9 mg and 25 mg doses are projected to cost $299 a month. The Wegovy pill must be taken on an empty stomach with a small amount of water. Patients are directed not to eat, drink, or ingest other medications for 30 minutes after taking the pill. It is intended to be prescribed along with a reduced calorie diet and daily exercise routine to help people lose weight. “Patients will have a convenient, once-daily pill that can help them lose as much weight as the original Wegovy injection,” said Mike Doustdar, president and chief executive officer of Novo Nordisk, in a statement to Healthline. “The Wegovy pill provides patients with a new, convenient treatment option that can help patients start or continue their weight loss journey,” he added. Benefits, drawbacks of a weight loss pill Experts say tablet forms of weight loss drugs do provide some conveniences. They said they are generally cheaper than injections and don’t need to be refrigerated. In addition, the pills don’t involve needles. “[The pill] may open up the option for many more people,” Kirkpatrick told Healthline. “It also appears that the price may be more affordable taking away yet another potential barrier to consideration for taking these drugs.” However, Sun Kim, MD, an associate professor of medicine at Stanford University in California, said once-a-week injections can be considered more convenient for some people than remembering to take a pill each day. “I also think it may be easier to quit or delay an oral medication when faced with side effects like nausea, which is common with GLP-1 medications,” she told Healthline. Some experts note that the costs of the new medication could continue to be a barrier. Ali said insurance companies may be reluctant to cover these medications, at least initially, as they have been in the past with other weight loss treatments. “These kinds of issues aren’t going to change dramatically,” he told Healthline. “Companies may not be inclined to offer insurance coverage.” “I’m concerned about access as coverage of GLP-1 medications will be reduced for patients, especially those who rely on Medicaid,” noted Kim. Kirkpatrick shared similar concerns. “This will probably differ based on a case-by-case basis, but the price may still be too high for some individuals to consider — especially if their diagnosis is not covered by insurance,” she said. “The other factor I see with some of my patients is the length in which insurance will cover the medication as well, with many patients stopping the medication once they have to pay out of pocket,” Kirkpatrick added. Recap of current weight loss medications There are a number of options for people seeking treatment for type 2 diabetes or obesity. Most of these medications are approved only for adults. Wegovy has been available as an injection medication since receiving FDA approval in June 2021. It now costs $349 per month for the higher doses for consumers who don’t use insurance. The lower doses are available for $199 per month until March. Wegovy contains the active ingredient semaglutide in both pill and injectable form. Ozempic, which is also manufactured by Novo Nordisk, is also a semaglutide-based GLP-1 medication. Wegovy has been approved for use as a treatment for obesity or weight management issues. Ozempic is approved only for use as a treatment for diabetes. Ozempic is also only available as an injection. Another Novo Nordisk product, Rybelsus, has been available as a tablet since September 2019 as a treatment for type 2 diabetes. It also is semaglutide-based. Eli Lilly also has two GLP-1 medications, both of which contain the active ingredient tirzepatide. Mounjaro is approved as a treatment for type 2 diabetes while Zepbound is approved for weight loss treatment. Eli Lilly is currently developing a weight loss medication in pill form called orforglipron. That drug doesn’t contain the active ingredient tirzepatide. It is a GLP-1 medication that affects different receptors than Zepbound and Mounjaro. Eli Lilly officials reported that a recent phase III clinical trial indicated that orforglipron helped people maintain weight loss after they switched to the daily pill from injectable medications Zepbound and Wegovy. The company has submitted an application to the FDA to have orforglipron approved for use as a treatment for weight management. “If approved for the treatment of obesity, orforglipron could provide a convenient alternative for the millions of individuals living with obesity around the globe to continue their long-term health journey,” said Kenneth Custer, PhD, executive vice president and president of Lilly Cardiometabolic Health, in a statement. Tips for successful weight loss Most experts agree that weight loss medications do not magically melt away fat or burn off calories. The medications work by suppressing the body’s hunger and appetite responses, prompting people to eat less. Experts say these medications only assist a person in developing and maintaining a healthy diet and a regular exercise program. “GLP-1-based medications, including the Wegovy pill, have been revolutionary to the care of patients living with obesity,” Kim said. “However, it is important to also continue to focus on eating a quality diet and exercising regularly.” Ali said that 90% of a person’s weight is the result of what they eat. Exercise, he said, can help burn off calories, but diet is the most important component. He said he advises his patients to reduce their consumption of carbohydrates and sugars while increasing their intake of proteins and vegetables. “There are no magic solutions,” he said. “You must eat well and exercise regularly.” Kirkpatrick said her advice remains the same no matter what type of weight loss medication a person is taking. “Lifestyle change also has to accompany the pharmacological approach. Diet and exercise will still be strong predicators of long-term success,” she said.', NULL, 'https://www.healthline.com/health-news/fda-approves-wegovy-weight-loss-pill', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/wegovy-pills-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:37.329142', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.329142', '2026-01-25 06:50:37.329142');
INSERT INTO public.radar_items VALUES ('fcc4f39e-73a4-46bd-b3ec-78a79dc2c9b9', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'c59ab81b227a3b8c0491cad53ac79f3a', 'Weight Loss: What I Wish I’d Known Before Taking Compounded Semaglutide', NULL, 'Semaglutide erased the constant mental chatter about food that had ruled her life, but along with it went her awareness of basic needs. Writer Kristen Reed shares her weight loss journey with compounded semaglutide. Photography courtesy of Kristen Reed Health and wellness touch everyone’s life differently. This is one person’s story. The views and opinions expressed are those of the speaker and do not necessarily reflect the views or positions of Healthline Media. It hit me at a Mexican restaura', NULL, 'Semaglutide erased the constant mental chatter about food that had ruled her life, but along with it went her awareness of basic needs. Writer Kristen Reed shares her weight loss journey with compounded semaglutide. Photography courtesy of Kristen Reed Health and wellness touch everyone’s life differently. This is one person’s story. The views and opinions expressed are those of the speaker and do not necessarily reflect the views or positions of Healthline Media. It hit me at a Mexican restaurant. The chips and salsa were on the table — warm, salty, delicious — and after enjoying just a few, I was done. Not because I was being “good” or disciplined, but because I was satisfied. In the past, I would have eaten my way to the bottom of the basket. Then it dawned on me: the food noise was gone. Six months before that chips-and-salsa moment, I started taking compounded semaglutide after leaving an abusive marriage and learning my A1C was nearing prediabetic. The next 16 months reshaped my body and my relationships with food, my kids, and myself. The &#8220;food noise&#8221; disappeared, but so did my awareness of some basic needs. For instance, I&#8217;d forget to drink water and cook meals for my kids. I had learned the hard way that you need medical oversight when taking GLP-1 drugs, which I&#8217;d obtained compounded versions of through medical professionals at a local medspa and a compounding pharmacy. I weighed 180 pounds when I started GLP-1 drugs in November 2023 and stopped at 135 pounds in July 2025. If I could go back to that first shot of semaglutide, I&#8217;d know I&#8217;d need a timeline and an exit strategy. I would also know that I&#8217;d need community support from people who understand this particular weight loss journey. I don&#8217;t regret taking GLP-1 drugs, but here’s what I wish I&#8217;d known before starting them. Food noise went silent Before I started GLP-1s, food noise was a constant state of mind. My thoughts swirled around the next snack or meal as if they were a close companion. Food noise was ever-present and then, surprisingly and suddenly, absent. One unexpected casualty was my baking hobby. A few months into my weight loss journey, I stopped baking. The desire simply dissipated. Before I started the injections, I’d been on a pound cake kick, baking weekly just for the fun of it. In hindsight, food noise may have been driving the hobby, even though I really enjoyed the process of baking. At some point, I just stopped baking and didn’t seem to miss it. The food noise that&#8217;d prompted weekly fixes for pound cakes was gone. The absence of that noise — the silence, really — was deafening. Dehydration snuck up on me As the mental chatter around food quieted, I realized I had missed other signals my body was sending. Painful constipation forced me to confront how little water I was drinking. Turns out dehydration can be a side effect of GLP-1 drugs. I spoke with Mir B. Ali, MD, a bariatric surgeon and medical director of the MemorialCare Surgical Weight Loss Center at Orange Coast Medical Center in California, to gain a better understanding of what happened. He explained that the medication slows your digestive system. That slowdown, combined with even mild dehydration, can create intense constipation. Ali advises his patients to drink water and other non-sugary liquids throughout the day, aiming for 48 ounces. Severe dehydration is rare with GLP-1 use, he said, but the problem is more subtle. &#8220;Patients just forget to drink, and you can&#8217;t gulp a whole bunch at once because your stomach is emptying slower, and it might make you nauseous,” Ali said. That was my experience. I simply forgot to drink water. Staying hydrated is about more than avoiding discomfort. Research suggests that chronic dehydration can cause serious health risks as we age. When you forget to eat or drink, those risks can accumulate silently. So, I tracked my water bottle refills, sometimes adding electrolyte powders. My dehydration wasn&#8217;t just an uncomfortable side effect. It had the potential to derail everything I worked toward. This would have been helpful to know up front. I didn’t want to work out anymore Doctors advise people taking GLP-1 drugs — and most people in general — to exercise at least 30 minutes daily. Regular exercise helps your body maintain metabolism and muscle, which are both at risk while taking GLP-1 drugs. However, I&#8217;d lost the motivation to exercise. When I started taking GLP-1s, I found I had very little energy. At times, I could barely summon the energy for even the most mundane tasks, such as answering an email, folding laundry, or taking my toddler to the playground. Exercising definitely wasn’t going to happen, which was confusing since I&#8217;d always been athletic and loved being active. When I asked Ali about this, he said he wasn’t surprised. He explained that the body has less energy when it&#8217;s burning calories. I also learned I likely wasn&#8217;t eating enough protein. “When patients are low in energy, they&#8217;re probably not getting enough protein. Protein is necessary for muscle preservation, as well as for general energy needs. So, we emphasize protein and vegetables in the diet and reducing carbohydrate intake,&#8221; Ali said. &#8220;That kind of directs your body toward burning fat more.” My kids were on their own for dinner I routinely forgot to cook meals for my kids. Judge me if you must, but I was rarely thinking about food for myself, let alone anyone else. I have a teen and a toddler who’d get home and ask, “What&#8217;s for dinner?” and I&#8217;d be like, “Oh, right, dinner!” I felt guilty because food was so far from my mind, but my kids still needed to eat. I remember my 2-year-old opening the freezer one evening and pulling out a bag of frozen vegetables. That smart baby was telling me she was ready for dinner. Ouch. I prepared a quick meal and she devoured the whole thing. That night, I realized I needed better systems in place to prevent this from happening again. I relied on air-fryer meals for my toddler and encouraged my teen to cook, which worked out great because he enjoys being in the kitchen — but not the part where he has to do the dishes. We also ordered takeout quite a bit. Cooking for my kids reminded me that I still had to eat, too. Stopping cold turkey led to weight regain About a year after I&#8217;d started GLP-1s, I was 15 pounds from my goal weight. However, I stopped losing weight. My weight plateaued for months, so my primary care physician (who didn&#8217;t prescribe my semaglutide injections) recommended I stop cold turkey. In hindsight, I should have planned an exit strategy. There was no dramatic shift. My appetite returned gradually, almost imperceptibly. A little more interest in food one week, a basket of tortilla chips the next. Five months passed, and 10 pounds returned. I remember looking at vacation pictures and realizing my hard-earned body was slipping away. I decided to try semaglutide again, but I knew I couldn’t just restart the injections and expect different results. My goal weight wasn&#8217;t worth risking my health Compounded semaglutide kept my appetite consistently low, even during my second run with it. On many days, I ate one meal a day. However, this eating pattern was setting the stage for a potentially dangerous side effect. I simply wasn&#8217;t getting enough nutrition. My nails were brittle, and my beautician noticed my hair was dry and weak, cutting off two inches of what looked like straw on the salon floor. I blamed work stress. I mentioned it casually during my annual physical, prompting my doctor to ask questions like: What was I eating daily? Was I tracking protein? How often was I actually eating? My doctor wasn’t managing my GLP-1 treatment; I did my own thing while keeping her informed. But she connected the dots I missed. The hair loss, brittle nails, and my diet: we suspected malnutrition. I stopped the compounded medication at 135 pounds, which was 5 lbs from my target. I set the target weight low because experience taught me I’d likely settle at a higher weight once off the meds. I later learned that malnutrition while taking GLP-1s is rare. Ali said that what I experienced could have been triggered by a hormonal shift resulting from rapid weight loss. Fat loss decreases estrogen, which can contribute to hair loss, he explained. I learned you need someone watching more than the scale — a medical professional who can see patterns you’re too close to recognize. Weight loss was never supposed to be the only metric that mattered. I needed a weight loss support system My girlfriends were on GLP-1 drugs before me, and understood the experience in ways research couldn’t capture. We quickly became each other&#8217;s sounding board at different stages on different medications and with different goals, like weight regain when I plateaued. We traded practical strategies: Pepto-Bismol pills before injections helped alleviate nausea, intermittent fasting worked for maintenance, and long walks were easier when done together. The tips helped, but that wasn&#8217;t the real gift. This community gave me permission. After years in survival mode, I needed to see women prioritizing themselves — taking up space, investing time and money, asking for what they needed. They showed me what that looked like. Watching them showed me I was allowed to want it, too. How I maintain a healthy weight without GLP-1s I’ve been off semaglutide since August and am maintaining my new healthy weight. For me, intermittent fasting, deliberate daily movement, and a balanced diet rich in protein and fiber help me stay strong, healthy, and motivated. I still choose only the carbs worth eating — good bread, not mediocre bread. And the food noise? Well, it’s back, but I’m keenly aware of it now. When I open the pantry, I pause and ask: Does my body actually feel hungry right now? Sometimes the answer is no, and I eat anyway. But the difference is the pause. The awareness. The choice. GLP-1 didn’t cure my relationship with food — it gave me the silence I needed to start listening to my body again after years of survival mode had trained me to ignore it. Now, when I sit down at that Mexican restaurant, the chips and salsa in front of me, I don’t always make the choice to be “good,” but in that split second between impulse and action — I make a choice. That little moment of agency before my hand reaches my mouth is the gift I’m going to hold onto.', NULL, 'https://www.healthline.com/health-news/glp-1-compounded-semaglutide-weight-loss-first-hand-experience', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/GLP-1-before-after-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:37.452847', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.452847', '2026-01-25 06:50:37.452847');
INSERT INTO public.radar_items VALUES ('55df9ea8-d0e4-4b7c-ada6-2aea000988d4', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '92031eff6f9799ad36289f43911d0388', '3 Young Adults Share How They Learned to Thrive With Cardiovascular Disease', NULL, 'Three young adults with cardiovascular disease share their stories. From left: Crystal Davis, Ally Lavalley, and Chad Witheridge. Design by Healthline; Photography courtesy of subjects Younger adults may face higher risks of cardiovascular disease due to factors like obesity or inactivity. Three younger individuals share their journeys with cardiovascular disease and the steps they take to stay heart healthy. Experts explain why cardiovascular disease can occur in younger individuals and how ado', NULL, 'Three young adults with cardiovascular disease share their stories. From left: Crystal Davis, Ally Lavalley, and Chad Witheridge. Design by Healthline; Photography courtesy of subjects Younger adults may face higher risks of cardiovascular disease due to factors like obesity or inactivity. Three younger individuals share their journeys with cardiovascular disease and the steps they take to stay heart healthy. Experts explain why cardiovascular disease can occur in younger individuals and how adopting certain lifestyle habits can help maintain a strong and healthy heart. More than 28 million adults in the United States live with cardiovascular disease, according to the American Heart Association (AHA). Yet, older adults aren’t the only individuals comprising this statistic; younger adults are affected as well. A recent study by Northwestern University found that 1 in 7 adults ages 30 to 59 has a high 30-year risk for cardiovascular disease (CVD). Blair Suter, MD, a cardiologist at The Ohio State University Wexner Medical Center, explained the factors driving these early onset cases. “The main reasons that younger adults experience heart disease is due to risk factors for heart disease, such as smoking, drug use, family history of heart disease, as well as uncontrolled medical problems such as diabetes, obesity, and hypertension,” Suter told Healthline. To maintain heart health, experts recommend following the AHA&#8217;s Life’s Essential 8, which focuses on managing heart disease risk factors. These include: managing high blood pressure managing diabetes maintaining healthy cholesterol levels smoking cessation maintaining a healthy weight getting proper sleep exercising regularly (including both cardio and resistance training) eating a healthy, balanced diet emphasizing whole foods, fruits and vegetables, and lean proteins “One of the areas that I have made the most impact in patients’ lives is my meeting them where they are to encourage movement and find ways that people can be active,” Suter said. “It’s important to follow the advice of a doctor for medication therapy as well as work with your doctor or others to engage in a healthy lifestyle to reduce your risk of worsening heart disease,&#8221; he added. Since heart disease is all too common in younger adults, Healthline spoke with three individuals who&#8217;ve been affected to raise awareness about early onset and inspire others to pay attention to their heart health. 3 heart disease survivors share their stories Each of the following cardiovascular disease survivors experienced the traditional risk factor of elevated low-density lipoprotein cholesterol (LDL-C) levels, which quietly raised their risk profiles for certain heart conditions. Each of these individuals maintains their cholesterol levels with the PCSK9 inhibitor evolocumab (Repatha). They also practice healthy lifestyle habits to maintain a strong heart. Crystal Davis, 52 Davis was 48 when she was diagnosed with cardiovascular disease and elevated LDL-C. Design by Healthline; Photography courtesy of Crystal Davis “I had pain in my chest and back, went to the ER, and was told I wasn’t having a heart attack but checked with my cardiologist,” she said. Because she already had high blood pressure, her doctor ran labs and performed an ultrasound that found a small blockage in her carotid artery. In addition to medication, Davis maintains healthy living through diet, exercise, and “happiness.” She is in medical school administration and, as a health advocate for the Partnership to Advance Cardiovascular Health, she shares her story to inspire others to prioritize heart health, prevention, and awareness. “[I like] letting others see they are not alone [and encouraging them] to be proactive and watch [their] numbers,” she said. “Educate yourself on a healthy lifestyle.” Ally Lavalley, 36 When Lavalley was 31, she was diagnosed with familial hypercholesterolemia, a genetic condition that caused her to have high cholesterol. Design by Healthline; Photography courtesy of Ally Lavalley In addition to treatment, she utilizes HEB Meal Simples, which helps her create a meal plan while navigating work and caring for her children. She also walks a lot and moves heavy packages regularly for work. “I also make use of the indoor track at work to get in my steps. I turn on a true crime podcast and walk for 30 minutes,” Lavalley said. She advocates with the Family Heart Foundation and PACH to empower others, and even shared her story on Capitol Hill to advocate for health legislation. She especially wants Latinas to know their risks by knowing their blood pressure and cholesterol levels and to demand answers about their health. “Working in partnership with your physician, you can develop a game plan for lowering your risk of cardiovascular events whether it be through lifestyle changes or medications,” she said. “The Latin American community is a matriarchal community — our women are mothers, sisters, tías, abuelas — we take care of the family. The best way to take care of our families is to take care of ourselves so we can be there for years to come.” Chad Witheridge, 42 While running his daughter’s soccer tournament, Witheridge suffered a major heart attack on the field. Design by Healthline; Photography courtesy of Chad Witheridge “I felt dizzy, nauseous, and had bad discomfort. It progressed into feeling like someone hit me with a metal bar on my back,” he said. “A friend took me to the fire station. I was upgraded to 100% blockage on my way to the hospital.” In addition to taking medication for high cholesterol, he focuses on his diet, exercise, and his mental wellness by spending time with family. “I also share my story on a regular basis to others, and it helps me discuss other real-life events with my care team to help the fight against heart disease,” Witheridge said. He wants others to get their cholesterol checked regularly and to ask their family members about their heart history. “I do not want another family to go through what my family had to go through,” he said.', NULL, 'https://www.healthline.com/health-news/cardiovascular-disease-3-young-adults-share-their-stories', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Cardiovascular-Disease-stories-1296x728-header.png', NULL, NULL, '2026-01-25 06:50:37.576409', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.576409', '2026-01-25 06:50:37.576409');
INSERT INTO public.radar_items VALUES ('6a35a4dd-2b46-45cb-ac4c-7d313e4b92cb', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '99905da55e8b4b8e7ac0d93689412c37', '''Wellness Stacking'' May Help Build Healthy Habits', NULL, '“Wellness stacking” combines several simple self-care practices together to complete them in one intentional block of time. Image by: Olga Pankova/Getty Images A new trend known as wellness stacking involves combining small self-care habits into a single, intentional routine. Experts say this approach supports mental health and habit-building. Research indicates that associating new habits with existing cues enhances follow-through and promotes long-term habit formation. While effective, wellnes', NULL, '&#8220;Wellness stacking&#8221; combines several simple self-care practices together to complete them in one intentional block of time. Image by: Olga Pankova/Getty Images A new trend known as wellness stacking involves combining small self-care habits into a single, intentional routine. Experts say this approach supports mental health and habit-building. Research indicates that associating new habits with existing cues enhances follow-through and promotes long-term habit formation. While effective, wellness stacking works best when kept realistic and flexible. Trying to add too much at once can lead to overwhelm. When you’re busy, taking care of yourself often falls to the bottom of the to-do list. But a new viral social media trend promises to help you make self-care a habit. Known as &#8220;wellness stacking,&#8221; the premise is simple: pair several small and easy self-care practices together and complete them in one intentional block of time. Instead of treating wellness as a long list of separate tasks you have to squeeze into your day, wellness stacking bundles them into a short, manageable routine. It’s about using existing good habits to promote new healthy habits. In short? Taking something you’re already doing and adding another feel-good action on top. In a video series, TikTok user @hummusbirrd experimented with different wellness stacks. Combinations included walking while listening to an audiobook, journaling under a red panel light, and wearing vision therapy glasses and teeth whitening strips while lying on a PEMF mat. So, is this an effective and realistic way to make self-care a valuable part of your day? How effective is wellness stacking? As far as wellness trends on social media go, this one seems relatively sensible and grounded. “From a mental-health perspective, wellness stacking is one of the more sustainable trends online because it centers on small, realistic habits rather than extreme routines,” Andrea Gleim, PsyD, a psychologist and founder of Mindfully Mine Counseling Center, told Healthline. “It gives us those small wins throughout the day that actually build momentum,” she explained. Gleim said pairing simple behaviors together aligns with what we already know in psychology: that small, consistent actions are far more effective than trying to overhaul your life all at once. “When done intentionally, wellness stacking can reduce decision fatigue, increase follow-through, and create a sense of structure that genuinely supports emotional well-being,” she noted. Wellness stacking uses what some experts have described as &#8220;habit cueing.&#8221; “This is where one behavior naturally leads into the next, making the routine feel more predictable and easier to keep up with,” Gleim explained. “It also reduces cognitive load by removing that constant &#8216;What should I do next?’ decision-making that can stop people from following through,” she continued. On a neurological level, wellness stacking taps into the brain’s reward system. “Those small habits create small wins, which boost motivation and reinforce the behavior over time,” Gleim said. “Our brains love patterns, and wellness stacking turns self-care into a simple, repeatable rhythm instead of a long list of disconnected tasks.” Possible mental health benefits Wellness stacking certainly seems to be worth the effort. A randomized trial demonstrated that linking a new behavior to either a routine-based cue (such as “after breakfast”) or a time-based cue increased habit automaticity and plan execution over an 84-day period. Both cue types worked, which suggests habit-cueing (the core of wellness stacking) is effective. Meanwhile, a meta-analysis found that activity-scheduling and activation techniques increase well-being and reduce adverse mental health symptoms. “Today, people are busier than ever with work, family, and social obligations. Wellness stacking offers the ability to stop, be mindful, and ground yourself, promoting emotional regulation and mental wellness,” said Victoria Romanyuk, a therapist at Serenium Therapy and Wellness. “This, in turn, reduces levels of stress, anxiety, and impulsivity, allowing better control of one&#8217;s own behaviors,” Romanyuk told Healthline. Wellness Stacking can also create a feeling of accomplishment. “Psychologically, it builds momentum like starting with one small, attainable habit increases the likelihood that someone will follow through with the next,” Gleim noted. “These small, repeated actions strengthen self-efficacy, the belief in one’s ability to succeed or accomplish a task, which is strongly linked to better emotional regulation, higher self-esteem, and overall well-being,” she continued. Emotionally, Gleim noted that wellness stacking can also create a sense of grounding and predictability, which can help reduce stress and overwhelm in daily life. Build healthy wellness slowly It’s important to be aware of your limitations. While wellness stacking can be beneficial for your mental health, attempting to change too much of your routine at once can be overwhelming. “As with anything new, we have to be mindful and set up realistic expectations,” Romanyuk said. It’s important to consider what tasks feel manageable and realistic for you, as well as where they might fit in your day. “You’ll need to consider what time of day will work best for you to practice wellness stacking,” Romanyuk pointed out. Wellness stacking in the morning, right before work, for example, could be counterproductive. Getting started with wellness stacking Getting started is about building momentum. One of Gleim’s top tips is to start your day with intention. “How you begin your day sets the tone for your nervous system. A sunrise alarm clock can ease you into the morning without the cortisol spike that comes from a harsh, disruptive alarm. Pair that with 30 seconds as soon as you get out of bed to gently wake up your body,” she suggested. The trick is to anchor a new habit to something you already do. “Habit cueing makes routines much easier to maintain. For example, take three deep breaths while your coffee is brewing or right after brushing your teeth. Attaching a new behavior to an existing one removes the guesswork,” Gleim advised. To make a new habit stick, you can also use sensory cues. “A specific playlist, scent, or designated spot in your home can signal to your brain that it’s time to transition into your wellness moment. These kinds of sensory anchors help the habit feel familiar and grounded,” Gleim explained. One important mindset shift is recognizing that wellness is about support, not perfection. “It’s easy to fall into the idea that &#8216;more is better,’ but sustainable wellness is rooted in consistency and self-compassion, not intensity or flawless follow-through,” Gleim pointed out. “If someone starts feeling anxious when they miss a habit, loses flexibility, or treats the routine like a rigid checklist, that’s a sign the practice is moving toward perfectionism instead of support.” The goal is to build small, reliable systems that help you feel more grounded, regulated, and cared for.', NULL, 'https://www.healthline.com/health-news/wellness-stacking-self-care-trend-healthy-habits', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/yoga-doorway-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:37.700788', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.700788', '2026-01-25 06:50:37.700788');
INSERT INTO public.radar_items VALUES ('1a3dce89-8581-4a19-a4c3-50a27678d239', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'd72fc07835510ae23f5e8a770392d696', 'How Happy Do You Need to Be to Lower the Risk of Chronic Disease?', NULL, 'Research suggests that being happier may help you avoid developing common chronic diseases. Image Credit: Anna Malgina/Stocksy Research suggests that being happier may help you avoid developing common chronic diseases. However, the benefits only seem to kick in above a certain level on the “Life Ladder.” Experts say “meaningful happiness” is about a sense of safety and social connection. Personal choices as well as public policy decisions may encourage greater happiness. Can being happier actual', NULL, 'Research suggests that being happier may help you avoid developing common chronic diseases. Image Credit: Anna Malgina/Stocksy Research suggests that being happier may help you avoid developing common chronic diseases. However, the benefits only seem to kick in above a certain level on the &#8220;Life Ladder.&#8221; Experts say &#8220;meaningful happiness&#8221; is about a sense of safety and social connection. Personal choices as well as public policy decisions may encourage greater happiness. Can being happier actually help you live a longer and healthier life? A recent global study, published in Frontiers in Medicine, suggests that it can — but only once you reach a certain “tipping point” of well-being. Below that point, extra happiness doesn’t seem to make much difference to health, according to the researchers. They suggest that these findings hint at a sweet spot where improving life satisfaction could become a powerful public health tool, alongside addressing known risks such as obesity, alcohol use, and pollution. What&#8217;s the link between happiness and health? The research team wanted to see if the link between happiness and health follows a straight line or if it has a curve with a threshold where the effect kicks in. To do this, they turned to a globally recognized measure of life satisfaction called the “Life Ladder.” This survey asks people to imagine a ladder from 0 at the bottom (“worst possible life”) to 10 at the top (“best possible life”) and place themselves on it. They gathered national average scores from 123 countries between 2006 and 2021, alongside official health statistics on deaths from non-communicable diseases (NCDs) among adults ages 30 to 70. NCDs include heart disease, cancer, diabetes, and chronic respiratory conditions — illnesses responsible for about three-quarters of deaths worldwide, according to estimates cited by the authors. To make sure their results didn’t just reflect other health influences, the researchers included a range of factors in their analysis: alcohol consumption, obesity rates, urbanization, air pollution levels, health spending, national income, and governance quality. They employed a sophisticated statistical model called panel smooth transition regression, which can detect changes in relationships based on the level of a key variable. In this case, the Life Ladder score served as the “transition variable,” enabling the team to determine if the impact of happiness shifted once a specific score was reached. They also tested for dynamic feedback using another method, panel vector autoregression. This helped them explore whether happiness and NCD mortality influence each other over time. For example, they could determine whether happier populations not only have fewer deaths from chronic disease, but also whether healthier populations become happier. Other factors shaping health outcomes The analysis revealed a clear threshold: Happiness only began to have a protective effect on health once a country’s average Life Ladder score rose above roughly 2.7 out of 10. Below that level, extra happiness didn’t significantly change death rates from chronic disease. But above it, every small increase in happiness was linked to a steady drop in NCD mortality. The researchers found no upper limit within the observed range. In other words, there was no evidence that “too much happiness” could be harmful to health. Happiness wasn’t the only factor shaping health outcomes. Across all levels of well-being, higher rates of obesity and alcohol use were strongly linked to more deaths from NCDs. Air pollution also played a role, especially in lower-happiness countries, where its impact was more pronounced. Urban living showed an interesting twist: in countries below the happiness threshold, greater urbanization was tied to worse NCD outcomes, likely due to lifestyle changes and environmental stress. However, in happier countries, urbanization was linked to better health, perhaps reflecting improved infrastructure, access to healthcare, and healthier city design. Economic and policy factors mattered too. Health spending consistently reduced NCD mortality in both happiness regimes, suggesting that investing in care and prevention works regardless of well-being levels. GDP per capita — a measure of national wealth — only showed a protective effect in higher-happiness countries, hinting that income gains may translate into better health mainly when social and psychological conditions are already favorable. The team also discovered that happiness and health seem to reinforce each other. Higher happiness was associated with lower NCD mortality, and lower mortality was associated with greater happiness in future years. According to the researchers, this means that once a population’s well-being crosses the tipping point, improvements in health can help sustain and even boost happiness over time, which in turn may further reduce chronic disease deaths. Taken together, the findings suggest that happiness can act as a kind of health asset, but only once basic well-being is secured. For countries below the threshold, the researchers say public health strategies might need to focus first on structural improvements: better healthcare access, tackling poverty and inequality, reducing corruption, and cleaning up the environment. For those above it, enhancing happiness through social connection, mental health support, and community investment could provide an extra boost to longevity, especially when combined with efforts to cut obesity, alcohol misuse, and pollution. How happiness could shape public health Many factors influence physical and mental health outcomes. &#8220;Meaningful happiness has to include, at minimum, a sense of safety, social connection, and being able to have your basic needs met,&#8221; Blen Tesfu, MD, a physician and Medical Advisor with Welzo, told Healthline. Tesfu wasn&#8217;t involved in the happiness study. &#8220;Once you&#8217;ve established this base, then happiness can help establish the conditions for making healthy decisions and for dealing with the stresses we experience daily,&#8221; she explained. Tesfu said that a consistent feeling of fulfillment is most strongly linked with better health outcomes and lower rates of chronic disease. Mary Kate &#8220;MK&#8221; Clarkin, executive clinical director at LifeStance Health, noted that a range of strategies can help boost happiness at both the individual and macro levels. Clarkin wasn&#8217;t involved in the research. &#8220;Social connections and community are critical elements in a happy and healthy lifestyle. Individuals can prioritize time with support networks-family, friends, neighbors, colleagues, etc.,&#8221; she told Healthline. &#8220;Engage in activities meaningful to you.&#8221; Clarkin suggested building emotional regulation and psychological flexibility through mindfulness practices or working with a counselor or therapist. &#8220;I&#8217;d be remiss if I didn&#8217;t mention paying attention to health-promoting habits: improving sleep hygiene, practicing yoga, starting strength-training, incorporating walks into your daily routine, cooking meals with more whole foods, and more,&#8221; Clarkin said. She added that on the community level, shared public spaces, such as libraries, and fostering collaborative and safe workplaces can enhance happiness. She also stressed the value of nature and green spaces. &#8220;Capitalizing every opportunity to create access to nature, such as well-lit walking trails, safe biking paths, and public parks, improves mood, decreases stress, and boosts health and life satisfaction,&#8221; Clarkin said. Efforts to provide safe neighborhoods, housing security, and reliable transportation can also contribute to higher scores on the Life Ladder. At the policy level, Clarkin said high-ranking countries share a few common characteristics, including strong social protection systems, such as paid family leave, affordable childcare, and unemployment support. Expanded access to mental healthcare also supports feelings of well-being, she said. Finally, Clarkin said that happier countries tend to prioritize green infrastructure.&#8220;Policies that protect clean air and water standards and that protect walkable spaces as well as public transit and bike lanes tend to have higher life evaluations and increased emotional wellbeing,&#8221; she concluded.', NULL, 'https://www.healthline.com/health-news/happiness-helps-lower-chronic-disease-mortality-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/happy-woman-field-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:37.825062', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.825062', '2026-01-25 06:50:37.825062');
INSERT INTO public.radar_items VALUES ('bf2cf58b-97fe-497d-80e6-d779d19c6014', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '31b582f665378975258bae11fba267d7', 'How Your Sleep Position Can Impact Heart Health, Metabolism, and More', NULL, 'Experts say that sleeping on your side may be better for your health. Image Credit: Amor Burakova/Stocksy Certain sleeping positions, like side sleeping, may be better for your health. Sleeping on your stomach or sleeping on your back may affect your health in various ways, according to experts. There are some ways you can help retrain your body to sleep differently. Quality sleep is vital for overall health and well-being. During sleep, your body works hard to maintain your physical health and ', NULL, 'Experts say that sleeping on your side may be better for your health. Image Credit: Amor Burakova/Stocksy Certain sleeping positions, like side sleeping, may be better for your health. Sleeping on your stomach or sleeping on your back may affect your health in various ways, according to experts. There are some ways you can help retrain your body to sleep differently. Quality sleep is vital for overall health and well-being. During sleep, your body works hard to maintain your physical health and support healthy brain function. The amount and quality of sleep you get can impact various aspects of your health, including your heart, metabolism, respiratory system, and immune system. The position you sleep in may also affect your health. Some experts suggest that certain positions may be better for your health, while others may have negative effects. Healthline spoke to sleep experts about what may be considered the best and worst sleeping positions for your health. Why sleep positions matter The position you sleep in can affect your body in various ways. For example, some positions may lead to back pain and stiffness. Other positions, such as sleeping on your back, may aggravate symptoms of sleep apnea or indigestion. Nancy Collop, MD, a professor of medicine and neurology and director of Emory Sleep Center, explained how your sleep position can impact your respiratory health. “If the upper airway (nasal passage to larynx) [is] vulnerable to collapse (narrow or congested, say due to allergies, URI [upper respiratory infection], then when sleeping on your back, you are more prone to snore or have sleep apnea,&#8221; Collop told Healthline. &#8220;This is likely because the jaw drops back and [the] airway narrows. Also, if you are prone to reflux, that might be worsened when sleeping flat, either on [your] back or left side.” Sarathi Bhattacharyya, MD, a pulmonologist and sleep medicine specialist, and medical director of the MemorialCare Sleep Disorders Center in Long Beach, CA, noted that sleep positions can affect people differently depending on any underlying medical conditions. “Common considerations that may influence your choice of sleeping position include chronic pain, sleep apnea, and pregnancy,&#8221; Bhattacharyya told Healthline. &#8220;Certain positions can make these conditions more challenging or worsen their impact on the quality of your sleep.&#8221; Best sleep positions Sleeping positions are often a personal preference. However, some experts may recommend certain sleeping positions based on medical needs. For instance, a recent systematic review found that supported side sleeping and back sleeping (supine) may be more beneficial for spine health in individuals with lower back pain. Collop agreed that side sleeping, especially on the right side, may be one of the best sleeping positions. Bhattacharyya said that the “best” sleep position also depends on the individual medical context. He gave the following examples: The best sleeping position for back and neck pain is typically sleeping on your back. This can help achieve better alignment of the spine and neck, preventing strain on the neck muscles. The best sleeping position for patients with sleep apnea is often on their sides. This may not be necessary if the sleep apnea is treated, for example, with a CPAP machine. During pregnancy, medical providers often encourage side sleeping during the later trimesters. The left side is usually the most recommended sleeping position to prevent compression of one of the large veins in the neck. You may want to consult with your healthcare professional to discuss the best sleeping positions for addressing your specific health concerns. Worst sleep positions Collop said that sleeping on your back may be the worst sleeping position, as it can cause breathing issues. However, she also noted that this can be alleviated by elevating your head. Bhattacharyya agreed that sleeping on your back can aggravate sleep apnea and affect breathing. He added that side sleeping can be detrimental if you have neck or back pain issues. “Sleeping on your stomach can contribute to worsening of both conditions and is generally not a recommended sleeping position to address any chronic medical condition,” he added, referring to sleep apnea and chronic pain. Stomach sleeping can also lead to an increased likelihood of back, neck, and shoulder pain. How to adjust your sleeping position Both Collop and Bhattacharyya agreed that retraining your body to sleep differently can be difficult. “Training yourself to sleep in a different position can take several weeks,” Bhattcharyya said. He gave the following advice: Placing pillows under your knees and lower back can help with alignment if you are trying to sleep on your back. Side sleeping can be maintained by placing a pillow between your legs to help align your spine and hips. “Start the night in your desired sleeping position, even if you may not maintain that position all night,&#8221; he recommended. &#8220;Supporting your body with pillows, wedges, and the right mattress can also help with retraining your body to sleep in your desired position.” Collop said that there are “trainers” you can buy to help keep you from rolling onto your back. “You can also buy fancy beds that elevate the head or a wedge pillow,&#8221; she said. &#8220;There are devices that have a &#8216;bumper&#8217; that runs up your spine, so if you roll to your back, it is uncomfortable — I have also seen people sew a tennis ball or similar object in the pajama top back for a similar effect.”', NULL, 'https://www.healthline.com/health-news/best-worst-sleeping-positions-health-experts', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/woman-side-sleeping-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:37.946699', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:37.946699', '2026-01-25 06:50:37.946699');
INSERT INTO public.radar_items VALUES ('a8e6b748-4fa2-4716-b6b2-7124166f4f43', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'a0936836f03099cdf0cce713176895fc', 'How Nick Jonas'' Diabetes Management Has Changed Over 20 Years', NULL, 'As the Jonas Brothers celebrate their 20th year as a band, it’s also been 20 years since Nick Jonas’ type 1 diabetes diagnosis. Photo courtesy of Dexcom Lead singer Nick Jonas has been living with type 1 diabetes for 20 years. The Jonas Brothers band “JONAS20: Greetings from Your Hometown Tour” celebrates its 20th anniversary alongside Nick Jonas’s 20-year journey with diabetes. Nick Jonas shares how both milestones have impacted his life and how he uses his music to raise awareness for type 1 d', NULL, 'As the Jonas Brothers celebrate their 20th year as a band, it&#8217;s also been 20 years since Nick Jonas&#8217; type 1 diabetes diagnosis. Photo courtesy of Dexcom Lead singer Nick Jonas has been living with type 1 diabetes for 20 years. The Jonas Brothers band “JONAS20: Greetings from Your Hometown Tour” celebrates its 20th anniversary alongside Nick Jonas&#8217;s 20-year journey with diabetes. Nick Jonas shares how both milestones have impacted his life and how he uses his music to raise awareness for type 1 diabetes. This year, the number 20 holds special significance for iconic singer Nick Jonas. As the Jonas Brothers celebrate their 20th year as a band, 2025 also marks 20 years since their lead singer’s type 1 diabetes diagnosis. “It’s crazy how it lined up,” Jonas told Healthline. “It’s been a wild journey in both… in the Brothers sense, it’s been the ride of a lifetime, and we’ve been so fortunate to be able to do this for 20 years now and to have the support of the world’s greatest fans.” Parallel to the band’s experience over the last two decades, he said he has had great and tough moments living with diabetes. The struggles of managing his condition have been the lows, while advocating and connecting with others as a spokesperson for Dexcom and through his non-profit, Beyond Type 1, have brought him joy. “Overall, I’m really grateful to have been able to be transparent about [type 1] and to connect with all these wonderful people from all regions of the world who are experiencing their own diabetes journey, and it’s a really big thing to feel like you’re a little less alone in it,” said Jonas. Nick Jonas&#8217; A1C shoutout to fans To thank his fans, on World Diabetes Day (November 14), he took to the stage during a Jonas Brothers concert and surprised his audience by sharing an inspiring message of hope, accompanied by a shout-out to his A1C. “My A1C, which is a collection of numbers over a three-month period, was the best it’s ever been, actually, most recently,” said Jonas. The show was attended by members of the Dexcom Warrior community — a group of more than 30,000 people globally who share their experiences with diabetes to help spread a message of strength, perseverance, and optimism. “It was really special for me to get to use the Jonas Brothers’ platform as a place to speak about something that’s obviously very personal to me and on World Diabetes Day, I think it’s natural to get reflective and to tap into kind of what life looks like for me as a now 33-year-old person living with this disease,” he said. Jonas dedicated the song &#8220;A Little Bit Longer&#8221; — a tune he wrote early in his career and diabetes journey, to those living with the disease. “It’s a really important time for me to get to speak on stage like that and play a song that I wrote about these experiences when I was 14 and to see the impact it still has to this day with the fan base,” he said. While the song has taken on a new meaning for him as an adult, he said it is still relevant. “Now I [have] this great, big community that I belong to that has lifted me up in so many different moments. I think my outlook is perhaps a lot more positive now. It is possible to live a big, busy life while living with this disease and outlook and perspective and all that is an important piece to powering through.” Advancements in type 1 diabetes Not long ago, life with type 1 diabetes meant more than five insulin injections a day and finger sticks 10 or more times daily. This was a constant cycle of needles, guesswork, and vigilance, said Victoria Finn, MD, board certified endocrinologist with Medical Offices of Manhattan and Labfinder.com contributor. “Insulin pumps replaced multiple daily insulin injections. With time, insulin pumps became lighter and smarter, and eventually learned to ‘talk’ with the glucose monitors,” Finn told Healthline. “Algorithms began adjusting insulin automatically, creating hybrid ‘artificial pancreas’ systems that lift some of the mental burden people with type 1 carry every day.” Jonas is impressed with how far technology has improved since he was first diagnosed. “The fact that I can receive real time readings of my glucose straight to my phone or smart watch or it can be [shared with] my wife or other family members who I’m traveling away from that’s just an amazing thing,” he said. In addition to technology, new treatments aimed at managing diabetes and slowing or altering the disease itself are in development. “The first immune-therapy capable of delaying type 1’s onset was approved, and research into preserving or even replacing the body’s insulin-producing cells gained real momentum. In labs around the world, scientists are growing stem-cell–derived pancreatic beta cells and experimenting with ways to protect them from immune attack,” said Finn. “Smart insulin” is also being engineered to activate only when blood sugar rises, promising a future where insulin works as intuitively as the body once did. “More advancements will absolutely continue to develop. We’re no longer just improving tools; we’re getting closer to changing the disease itself,” Finn said. However, while Sean Oser, MD, a family physician and member of the American Academy of Family Physicians, agrees that further advancements will continue to develop, he notes that managing type 1 diabetes remains an intensive undertaking — physically, cognitively, and emotionally. &#8220;I sincerely hope that we’ll see more and more attention to talking about and helping with the burdens and the demands of living with and managing T1D. We need far more of that, too,&#8221; he told Healthline. Jonas turns to self-care to manage his diabetes In addition to medication and technology, Jonas shared some strategies he leans on to manage his diabetes. First, he said he learned to take pressure off himself. “You’re never going to have the perfect day living with this disease and even if you’re super on top of your diabetes management, there are just things that are a little out of your control and being able to take a deep breath, reset, and know that it’s going to be OK on the other side is really important,” he said. While this is hard to do at times, he said he learned to practice this early during his diagnosis. Recently, he has focused on taking vitamins, caring for his skin, and staying hydrated. “It’s a simple thing, but the more water I drink, my glucose levels are better. I don’t know exactly why, but I just find that hydrating has a lot of health benefits,” said Jonas. “I didn’t put as much focus on it earlier in my life as I do now, and it’s been really beneficial.” He also walks daily for 30 minutes or longer for his physical, mental, and emotional health. “It really centers me and even when it’s cold out, getting out in the fresh air is really important when a lot of my day too, is spent indoors for hours at venue or on a film set or something,” he said. He leans on his therapist regularly, too. “I think it’s really important to do that self-work,” Jonas said. Most of all, he encourages everyone living with type 1 diabetes to take part in the diabetes community. “There will be good days, there will be tough days, but you can climb this mountain, and there’s some incredible people out there whose stories will really inspire anybody that’s going through tough moments,” said Jonas.', NULL, 'https://www.healthline.com/health-news/nick-jonas-type-1-diabetes-disease-management-20-years-later', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Nick-Jonas-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:38.069613', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:38.069613', '2026-01-25 06:50:38.069613');
INSERT INTO public.radar_items VALUES ('90a64971-cff5-490e-93a6-06fedb70a265', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '7317beb5760202ce0126ecc81b8a6a9f', 'Cannabis Reclassification Means Some Coverage For Medicare Recipients', NULL, 'Reclassification of cannabis will offer certain coverage for Medicare recipients. Image credit: Virginian Pilot/Getty Images A White House directive is ordering federal authorities to speed up the reclassification of a form of cannabis as a less dangerous drug. The action may also establish a pilot program that allows Medicare recipients to be reimbursed for some cannabis-related products. Experts say the reclassification should also improve scientific research on the cannabis plant. The term “c', NULL, 'Reclassification of cannabis will offer certain coverage for Medicare recipients. Image credit: Virginian Pilot/Getty Images A White House directive is ordering federal authorities to speed up the reclassification of a form of cannabis as a less dangerous drug. The action may also establish a pilot program that allows Medicare recipients to be reimbursed for some cannabis-related products. Experts say the reclassification should also improve scientific research on the cannabis plant. The term &#8220;cannabis&#8221; refers to a group of plants that includes both marijuana and hemp. While &#8220;marijuana&#8221; has historical associations—including racist origins dating back nearly a century—it is also often linked to concerns about addiction, primarily due to the presence of THC, the plant’s psychoactive compound. For these reasons, many prefer using the broader term &#8220;cannabis&#8221; when discussing marijuana-related topics. Older adults who are covered under Medicare may be among the first people to see benefits from a White House directive to speed up the reclassification of a form of cannabis under federal law. Last week, President Donald Trump issued an executive order directing Justice Department officials to quicken the approval process to change marijuana, a form of cannabis, from a Schedule I drug to a Schedule III drug. As a Schedule I drug, cannabis is officially considered a substance with “no currently accepted medical use and a high potential for abuse.” Other Schedule I substances include heroin, LSD, and MDMA. As a Schedule III drug, cannabis would be considered a compound with “a moderate to low potential for physical and psychological dependence.” Other Schedule III substances include ketamine, anabolic steroids, and testosterone. Experts say that even if this schedule change takes place in the near future, it will likely be subject to legal challenges, judicial review, and a lengthy implementation period that could span years. “The process is not designed to be expeditious,” said Paul Armentano, the deputy director for the National Organization for the Reform of Marijuana Laws (NORML). However, there is one aspect of the proposed changes that could provide some financial relief for adults 65 years and older who use cannabis-based products. Older adults and cannabis The executive order that could benefit adults 65 years and older as early as April. This would allow older adults on Medicare to be given medical marijuana if deemed necessary and recommended by a medical doctor. It would also allow qualifying Medicare recipients to be reimbursed by Medicare for up to $500 per year for qualifying cannabinoid (CBD)-based products. This program could start as early as April 1. The reimbursements may not be available under Medicare Advantage (Part C) plans. You should check with your specific insurance provider for more information. The financial relief could be a boon as cannabis-based products are becoming more popular among older adults. A 2024 study stated that 14% of people 65 years and older reported using a CBD product in the prior year. Sherry Yafai, MD, an emergency medicine physician and founder and medical director of The RELEAF Institute in Los Angeles, said the reimbursements would be highly beneficial for this older portion of the U.S. population. “Seniors who are most often impacted by pain, sleep disturbances, and chronic illness will now have a cost-effective option to treat these issues. Up until now, these options have been expensive and out of pocket,” she told Healthline. Armentano noted that there are many details that still need to be worked out regarding this reimbursement program. “The federal government is going to have to offer a few more specifics on what products are eligible,” he told Healthline. Yafai added that older adults will need to be careful about using CBD products while they are taking other medications. “Seniors are often on multiple prescription medications that can interact with cannabis medications,” she said. “They often require physician counseling on dose, mode of administration, and potentially lowering of other medications.” An October 2025 report issued by Stanford Medicine in California issued some other cautions. The Stanford scientists pointed out that marijuana in the 1970s contained between 1% and 4% tetrahydrocannabinol, or THC, the psychoactive component of the plant. That figure today is now around 20% with some cannabis flowers containing up to 35% THC. Other formulations, such as concentrates, oils, or edibles, can have concentrations up to 90%, the scientists reported. They said these higher THC concentrations can increase the risk of accidental over-consumption by older adults. In addition, the scientists stated that past research has indicated that there may be a link between cannabis use and some forms of heart disease, a high risk factor for older adults. Nonetheless, the Stanford medical professionals said there is some anecdotal evidence that cannabis can be effective in helping ease chronic pain. “THC has gotten a bad rap over the years, but in very small doses it can be therapeutic,” wrote Eloise Theisen, MSN, a nurse practitioner at Stanford Medicine. “There’s also a lot of stigma around its effects of euphoria. In our patients who may have months to a few years to live, still being able to experience joy is really important.” What to know about reclassifying &#8216;marijuana&#8217; Armentano said switching cannabis from a Schedule I to a Schedule III drug won’t produce significant changes for most people who use the drug. Medical marijuana is now legal in 40 states, 24 of which have also approved cannabis for recreational use. It is also legal medically in the District of Columbia and 3 territories. You can check the current law in your area on the NCSL website. However, it is still illegal under federal law. Armentano said that means that technically, federal agents can arrest a person for possessing or using cannabis, even in states where it’s legal. He notes the conflict between federal and state laws will remain even if cannabis is reclassified as a Schedule III drug. Even under a reclassification, doctors cannot prescribe medical marijuana, although they can recommend it in states where it’s legal. Armentano said the scheduling reclassification could have minor impacts. For example, people in federal housing may no longer be subject to eviction for possession of cannabis. It could also mean that it would no longer be illegal for a person who possesses cannabis to own a firearm. It might also give medical personnel at the Veterans Administration more flexibility in recommending cannabis. “Over time, we could see a lot of changes on the margins,” he said. Armentano noted that with a classification change, companies that produce cannabis products and services would be able to take advantage of tax breaks. They’d also be able to receive funding from investment firms as well as do business with banks, which are currently prohibited under federal law from dealing with cannabis-related firms. “It will level the playing field a bit,” he said. These changes, he added, could lower the price as well as the availability of cannabis products. Armentano added that it appears the executive order may undo, at least in part, some of the restrictions placed on hemp-derived CBD products in an agricultural bill approved last month. Questions remain on cannabis reclassification Yafai said there are still a number of other issues that need to be ironed out. Among them: How will the reclassification actually be implemented? Will pharmacies be required to dispense cannabis, or will distribution remain in the hands of dispensaries? Will age limits be better enforced? Will there be limitations placed on how much THC will be in products? Will there be any uniformity among states with the reclassification? Yafai added that there will be opposition, including potential objections from pharmaceutical companies as well as the alcohol and tobacco industries. Indeed, criticism has already been leveled at the president’s executive order. The non-profit organization Smart Approaches to Marijuana issued a statement, calling the reclassification a “public health disaster.” Keith Humphreys, PhD, a professor of health policy at Stanford University in California, issued a number of objections to the reclassification. “The declassification shows the impact of the campaign donations and lobbying by industry, which succeeded in giving them a rescheduling that produces an enormous tax break for them,” Humphreys told Healthline. “The public should expect increased marketing of marijuana, which the public will now subsidize through the tax system,” he added. Armentano said the public’s opinion may indeed shift now that a Republican-led White House has proclaimed that marijuana should no longer be classified as a highly dangerous drug. “I do think it changes the conversation. I do think that is significant,” he said. “It’s a significant reversal of the federal government’s position.” Yafai said she is looking forward to a new era for cannabis use. “I look forward to the medical ‘perks,’ including easier access to research, potential medical coverage from insurance companies, increased usage from physicians, and potential increase [in] education across the U.S.,” she said. The impact on cannabis research There’s no shortage of research on cannabis. Armentano estimates there have been 37,000 scientific papers on the topic published in recent decades. The conclusions have been varied. There has been research that has concluded that cannabis and its related products can be helpful in treating chronic pain, cancer pain, psoriasis, and lupus. However, cannabis use has been linked to severe vomiting known as ‘scromiting’ as well as sleep disturbances, an increased risk of type 2 diabetes, and a higher risk of cardiovascular disease death. Armentano points out that all this research has been hampered by cannabis’s classification as a Schedule I drug. The classification means researchers are limited in providing cannabis to study participants in a controlled environment. So, most research has been observational, with scientists only able to analyze data from people who use cannabis on their own. Under the reclassification, researchers should be able to conduct double-blind clinical trials. In addition, the reclassification will allow scientists to use cannabis dispensed by state-approved facilities as opposed to a federal supply that may not be similar to what most people use. Yafai said these changes should result in better research. “Researchers will be able to more rapidly access cannabis for studies,” she said. “There will be more funding for research as well. Lastly, this would allow researchers to potentially use cannabis that is available locally as opposed to research-only grade cannabis, giving research more real-world outcomes. Ultimately, this will give us faster and more access to high quality medical research on cannabis.”', NULL, 'https://www.healthline.com/health-news/cannabis-reclassification-cbd-coverage-medicare', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Cannabis-warehouse-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:38.317158', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:38.317158', '2026-01-25 06:50:38.317158');
INSERT INTO public.radar_items VALUES ('75bfb5e2-cd59-41fb-abf5-1feeb3e034c2', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'da665b142f4710e278fe06db84be678a', 'What Foods Make You Happiest? Hint: It’s Not What You Think', NULL, 'Research shows that certain foods can affect your mood in different ways, including making you happier. Image Credit: Ani Dimi/Stocksy Research shows that certain foods can affect your mood in different ways. A recent study notes that a diet that is high in ultra-processed foods and refined carbohydrates can increase a person’s risk of depression. Other research has shown that the fermentable fiber in whole grains can improve the health of the gut microbiome, leading to an improved mood and a de', NULL, 'Research shows that certain foods can affect your mood in different ways, including making you happier. Image Credit: Ani Dimi/Stocksy Research shows that certain foods can affect your mood in different ways. A recent study notes that a diet that is high in ultra-processed foods and refined carbohydrates can increase a person’s risk of depression. Other research has shown that the fermentable fiber in whole grains can improve the health of the gut microbiome, leading to an improved mood and a decreased risk of mood disorders. Over the years, extensive research has been conducted on the impact of various foods on physical health and their effects on the body. However, some researchers have been investigating how food may affect mood and mental health. There is a recently developed field of psychiatry known as &#8220;nutritional psychiatry.&#8221; This specialized branch focuses on examining the relationship between eating habits, dietary factors, and mental health disorders. This is to help form methods of prevention and treatment for mental health disorders. “The field of nutritional psychology, which evolved almost ten years ago, has gained traction due to a tremendous amount of high quality data linking food to beneficial (or worsening) mental health outcomes,” Kristin Kirkpatrick, a registered dietitian. Research has found that certain foods can help uplift a person’s mood and help protect them from depression. However, other foods can negatively affect mood and increase the risk of depression. How food affects mood There is a lot of evidence to show that sweets and ultra-processed foods can negatively affect mood and even increase the risk of depression. “Studies show associations for multiple reasons, including but not limited to an increased risk of inflammation, high sugar / low fiber, which can negatively impact the microbiome, exclusion of antioxidant foods, [and the] inclusion of additives,” Kirkpatrick told Healthline. In the long term, such as months or years, too many of these types of foods can begin to affect your mental health. A recent study published in the Journal of the Academy of Nutrition and Dietetics found that a diet high in ultra-processed foods and refined carbohydrates can raise a person’s risk of developing depression. This finding aligns with a 2023 study published in JAMA Network. This study found that a higher intake of ultra-processed foods, particularly artificial sweeteners and artificially sweetened beverages, may lead to an increased risk of depression in some people. Indeed, a 2019 study notes that people who replace ultra-processed foods in their diet with more whole and minimally processed foods, such as in a Mediterranean diet, saw a decrease in their depression. However, a 2021 study found that people who believe that ultra-processed foods make them feel happier tend to eat more. Mood-boosting microbes Scientists are still trying to identify exactly which foods can make people the happiest. However, at this point, some experts list whole grains as a top candidate. This is because whole grains show some minor evidence for potentially boosting mood. Kirkpatrick noted that a plant-based Mediterranean diet has been associated with lower depression scores. “Noteworthy in this diet was the inclusion of omega-3 fatty acids, colorful plants like berries, extra virgin olive oil, leafy greens, and lean sources of protein,&#8221; she said. &#8220;In addition to this, supplementation with vitamin D and fish oil (especially if marine-based foods are low in the diet) has been shown to assist with both depression and anxiety.” The idea that the gut and the brain operate in continuous and bidirectional communication has been around since ancient Greece. Modern brain imaging has been able to show that gut stimuli can activate certain areas of the brain that are involved with emotional regulation. Kirkpatrick added that it is essential to recognize the role the microbiome plays in influencing mental health outcomes. This means a diet high in fiber, probiotics, and prebiotics should also be focused on. Whole grains contain fermentable fiber, which bacteria in the gut can digest. Fermentable fiber can help improve the health of your microbiome. The microbiome is the collection of microbes, including bacteria, viruses, and fungi, that naturally reside on and within our bodies. Michelle Routhenstein, a registered dietitian nutritionist and founder of Entirely Nourished, suggested the following additional foods that may improve mood. “Fatty fish like salmon, sardines, and mackerel provide long-chain omega-3 fatty acids, EPA and DHA, which are incorporated into brain cell membranes, improving fluidity and communication between neurons,&#8221; she told Healthline. &#8220;EPA and DHA also have anti-inflammatory effects that may protect against neuroinflammation, which is linked to depressive symptoms.” Routhenstein offered the following suggestions: Fermented foods like yogurt or kefir: may promote a healthy gut microbiome, which communicates with the brain and can influence mood regulation. Nuts and seeds, especially pumpkin seeds: rich in magnesium, a mineral that plays a key role in supporting brain function and mood. Polyphenol-rich foods such as dark chocolate, wild blueberries, black elderberries, nuts, seeds, apples, artichokes, red onions, and herbs like peppermint: contain antioxidants and anti-inflammatory compounds that may help support brain health and mood. Tips to boost your mood with food Experts say there are various ways food can help boost your mood. “Food plays a big role, of course, but it’s not [just] about what you should have but also about what you should limit. Limits should be made on sugar, refined grains, UPF [ultra-processed foods], and alcohol, while an attention to getting plenty of color and high nutrient density should be focused on,&#8221; Kirkpatrick said. &#8220;In addition to this, managing stress, exercise, and adequate, high quality sleep are also important.&#8221; She offered the following tips: If you&#8217;re going to get desserts during the holidays, focus on ones that actually may help you, like dark chocolate and berries When at a party, limit alcohol to help with portion control. Then eat until you are no longer hungry, not till you&#8217;re full. This may look like trying everything, but having just a bite. Substitute when you can at holiday meals, for example: Use extra virgin olive oil instead of butter Use yogurt instead of cream Use cauliflower puree instead of white potatoes Have wild fatty fish instead of red meat Drink seltzer water with fresh lemon or lime instead of sugary drinks Routhenstein noted the following ways you may be able to support your mood and mental health with food during the holidays: Plan ahead: Think about meals, gatherings, and activities in advance to reduce last-minute stress. Maintain your routine: Try not to stray too far from your regular sleep, movement, and eating habits. Small consistency matters. Set boundaries: Protect your time and energy, say no when needed, and carve out moments for rest or self-care. Mindful indulgence: Enjoy holiday treats in a way that feels satisfying without feeling extreme or restrictive. “Combining mindful nutrition with stress management can help you feel more balanced, energized, and emotionally resilient during the holidays,” said Routhenstein.', NULL, 'https://www.healthline.com/health-news/mood-boosting-happiness-foods', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/foods-holiday-Stocksy_txpf65b009668D400_Medium_2507945-Header.jpg', NULL, NULL, '2026-01-25 06:50:38.440818', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:38.440818', '2026-01-25 06:50:38.440818');
INSERT INTO public.radar_items VALUES ('6dd913fb-9886-431a-ad26-ae9a9c46b8ca', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'd1209cafbf788c2cf0d8898af17953f9', 'Strangers With Vitamins? Amy Sedaris Shares How She Boosts Her Brain Health', NULL, 'From multivitamins to crafting with friends, the ‘Strangers With Candy’ star shares her recipe for staying mentally sharp and young at heart. Actor and comedian Amy Sedaris shares her approach to healthy aging and cognitive well-being. Image credit: Axelle/Bauer-Griffin/Getty Images The macabre humor of Amy Sedaris may not be for the faint of heart, but it has kept the award-winning actor, writer, and comedian young at heart. Best-known for her role as Jerri in “Strangers With Candy,” which rece', NULL, 'From multivitamins to crafting with friends, the &#8216;Strangers With Candy&#8217; star shares her recipe for staying mentally sharp and young at heart. Actor and comedian Amy Sedaris shares her approach to healthy aging and cognitive well-being. Image credit: Axelle/Bauer-Griffin/Getty Images The macabre humor of Amy Sedaris may not be for the faint of heart, but it has kept the award-winning actor, writer, and comedian young at heart. Best-known for her role as Jerri in “Strangers With Candy,” which recently celebrated the 25-year anniversary of its cancellation, Sedaris, 64, is determined to keep her mind sharp. From juggling multiple projects, including roles in a television series (“Elsbeth”) and new feature films (“Is This Thing On” and &#8220;Office Romance&#8221;), to partnering with a multivitamin campaign for Centrum Silver to promote brain health in aging adults, Sedaris is no stranger to brain candy if it means supporting healthy cognition. A recent consumer survey conducted by Centrum and Talker Research polled 2,000 U.S. adults ages 50 and older, revealing that 78% of respondents are concerned about cognitive aging, and 96% consider maintaining cognitive abilities and memory essential. Research from the COSMOS-Mind clinical trial suggests that daily use of a multivitamin, such as Centrum Silver, may slow cognitive aging by up to 60%. For Sedaris, a one-and-done approach to vitamins and supplements to support her brain health suits her lifestyle best. “You see one ad on TV, and then you buy it, and then your whole countertop turns into vitamins, and it&#8217;s like, too much,” Sedaris told Healthline. “Like, I didn&#8217;t know there were so many Bs,” she said of B vitamins, “but I like taking vitamins, I want extra. I&#8217;m just lucky nothing major has happened yet, where I&#8217;ve had to have surgeries and things like that. So, I will do and take anything to prevent that from happening.” Can multivitamins support brain health? Most experts recommend a food-first approach to nutrition, meaning that supplements are only necessary if there is a deficiency. “You can get all the nutrients you need for optimal brain health from a healthy diet,” said David Cutler, MD, board certified family medicine physician at Providence Saint John’s Health Center in Santa Monica, CA. “The science of brain health is new, evolving, and controversial. There are many studies [that] have yielded conflicting findings. But some things seem apparent regarding basic nutrients, overall diet composition, and non-dietary factors to enhance cognitive function. There is no proven general benefit for any dietary supplement when no nutritional deficiency exists,” Cutler told Healthline. Candy Calderon, a certified brain health professional, agreed that a balanced diet emphasizing whole foods can support brain health. However, she added that supplementation can help fill any nutritional gaps. “For aging adults, a high quality multivitamin formulated for their age group, plus omega-3s (salmon, sardines, chia seeds), antioxidants (blueberries and dark leafy greens), and key vitamins [and minerals] like B12, D, magnesium, and E can make a measurable difference in cognitive function, mood, and overall brain resilience,” Calderon told Healthline. Cutler noted that the strongest evidence for a diet supporting brain health is associated with the MIND diet, a “Mediterranean diet twist” on the DASH diet, which is linked to improved cardiovascular outcomes. For example: Eating plenty of vegetables, fruits, and whole grains. Including low fat dairy products. Moderate consumption of fish, poultry, beans, and nuts. Limiting foods that are high in saturated fat, such as fatty meats, full-fat dairy products, and tropical oils such as coconut, palm kernel, and palm oils. Limiting sugar-sweetened beverages and sweets. No more than 2,300 milligrams per day of sodium (salt). Using olive oil as your main source of fat. Limiting processed meats and sweets. “Maintaining brain health is more than just about diet. Certainly, managing your diet and medications to prevent and control high blood pressure, diabetes, obesity, and high cholesterol are all essential,” Cutler said. Self-care and social connection support brain health For aging adults, a healthy diet and regular exercise are essential for supporting brain health; however, other strategies can also be beneficial. Studies have shown that engaging in hobbies, socializing, and practicing self-care can help prevent cognitive decline. Sedaris gets a monthly facial, for instance, and is always on the move due to her fast-paced New York City lifestyle, which she said keeps her mind stimulated. “I complain a lot about living in a city, but I always think at least I&#8217;m paying attention,” she said. In addition to memorizing her lines for her roles, Sedaris shared that she also enjoys making things with her hands. “I get a group together, and we&#8217;ll make a little crafting circle, especially now with Christmas coming up. I&#8217;ll make dinner, and we sit around, and we chit-chat and make things,” she said. “I like to engage with people. I&#8217;m a good listener, and I like to meet people. And I think that kind of stuff keeps you young, so I don&#8217;t think about aging that much.” Calderon described social connections as “brain food” and a “biological necessity for brain health.” “Studies consistently show that loneliness and social isolation increase the risk of cognitive decline and dementia. Our brains are wired for connection and thrive on it,” Calderon said. The power of connection “Every conversation, laugh, affection, and shared experience (even small moments like chatting with your neighbor or calling a friend) literally stimulates neural circuits that keep cognitive pathways active and strong. When we engage socially, we activate multiple regions of the brain simultaneously (memory, language, emotional regulation, and executive function). This acts like ‘cross-training’ for your mind. It also boosts oxytocin and serotonin, which help reduce stress and inflammation, two major drivers of cognitive aging.”— Candy Calderon, brain health expert Calderon recommended the following activities to help keep the mind sharp: Games and puzzles — whether by yourself or with friends (i.e., trivia nights, sudoku, crosswords, puzzles, card games, brain-powered screen games via phone or tablet apps) Movement-based activities that increase blood flow to the brain (i.e., Zumba, pickleball, walking clubs, pool aerobics, or yoga). Learning something new in a group (i.e., cooking, dancing, or a new language class). “Novelty challenges the brain, while group settings add accountability and emotional engagement,” Calderon said. Book clubs or discussion circles — these help with comprehension, critical thinking, and communication, which can aid in maintaining cognitive function. “My dad, who lived to be 98, was sharp as a tack. I would say for everyone in my family, our brains are on 24 hours a day. We&#8217;re thinkers, we&#8217;re talkers,&#8221; said Sedaris, whose brother is the acclaimed writer and humorist David Sedaris. &#8220;The thing that&#8217;s difficult for me is getting my brain and my heart to work together. There&#8217;s nothing really great about getting older, but a benefit is not feeling my age,&#8221; she continued. &#8220;It&#8217;s a world for young people. But then when you hang out with older people, you don&#8217;t feel that so much, and you&#8217;re like, oh, this is great — we&#8217;re all older, and we&#8217;re all hanging out together, and we&#8217;re all doing pretty great.”', NULL, 'https://www.healthline.com/health-news/amy-sedaris-talks-brain-health', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Amy-Sedaris-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:38.689033', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-25 06:50:38.689033', '2026-01-25 06:50:38.689033');
INSERT INTO public.radar_items VALUES ('14b7ddda-662c-4d75-a658-161dce9eebc3', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'b78c60de99df32e229e1b43f5a7721fa', 'FDA OKs Addyi, a Libido-Enhancing Drug for Women After Menopause', NULL, 'Addyi, sometimes referred to as “female Viagra,” is now approved for use to treat low sex drive in postmenopausal women. MoMo Productions/Getty Images The FDA expanded its approval of Addyi, a pill to treat low libido in women, to include postmenopausal women up to age 65. The approval will open up new treatment options for older women, but experts caution that treating low libido requires a “whole body approach.” It’s recommended to avoid taking Addyi within two hours of consuming alcohol to av', NULL, 'Addyi, sometimes referred to as “female Viagra,” is now approved for use to treat low sex drive in postmenopausal women. MoMo Productions/Getty Images The FDA expanded its approval of Addyi, a pill to treat low libido in women, to include postmenopausal women up to age 65. The approval will open up new treatment options for older women, but experts caution that treating low libido requires a &#8220;whole body approach.&#8221; It&#8217;s recommended to avoid taking Addyi within two hours of consuming alcohol to avoid potential interactions and dangerous side effects. The Food and Drug Administration (FDA) expanded its approval of a daily pill to treat low libido in females to include postmenopausal women up to age 65. Prior to the announcement this week, the pill, Addyi (flibanserin), was only approved to treat hypoactive sexual desire disorder (HSDD) in premenopausal females. The drug was first approved by the FDA in 2015, following a lengthy and contentious review process. The FDA previously rejected the drug on two separate occasions, in 2010 and 2013. In both cases, the agency raised concerns about safety, efficacy, and an unfavorable risk–benefit profile. Today, Addyi is the only FDA-approved oral medication for HSDD, though the FDA approved Vyleesi (bremelanotide), an as-needed injectable treatment, in 2019. Cindy Eckert, founder and CEO of Sprout Pharmaceuticals, the maker of Addyi, praised the FDA’s decision to expand the drug’s approval in a press release, calling it a “milestone” in understanding and prioritizing female sexual health. Other women’s health experts expressed support for the decision. “There was nothing really for me to prescribe because everything was for women who were menstrual and not menopausal,” said G. Thomas Ruiz, MD, an OB-GYN at MemorialCare Orange Coast Medical Center in Fountain Valley, CA. “Getting the FDA approval for this patient population could be very important to address postmenopausal women who want to have sexual activity and enjoy sex, but sometimes have issues with libido.” Mary Jane Minkin, MD, a clinical professor in the department of obstetrics, gynecology, and reproductive sciences at Yale University, told Healthline that the approval was “quite reasonable” given the available data. &#8220;The studies showed statistical significance of the drug over the placebo, but the magnitude of the improvement is not overwhelming,&#8221; Minkin said. What is Addyi, the &#8216;female Viagra&#8217;? Addyi, which is sometimes referred to as “female Viagra,” has little in common with the medication from which it draws its nickname. The drug was originally developed as an antidepressant but was deemed ineffective during early studies. However, researchers observed improvements in measures of sexual function and shifted focus to the drug’s potential as a treatment for low libido. After two rejections, Addyi was approved in 2015 to treat HSDD, following additional research and a considerable lobbying effort by Even the Score, a group linked to Sprout Pharmaceuticals. Addyi carries a warning for potential side effects when combined with alcohol, including low blood pressure (hypotension) and fainting (syncope). The label recommends waiting at least two hours after drinking alcohol before taking Addyi to reduce the risk of fainting. If a person consumes three or more alcoholic drinks on a single occasion, the label advises skipping the dose entirely. Claims about the effects of combining Addyi and alcohol eventually prompted Sprout Pharmaceuticals to fund additional studies examining the interaction. The studies, though small in scale, demonstrated no additional risk of syncope. “There have been side effects like the syncopal episodes and dizziness especially in persons who have had an alcoholic beverage within two hours of [Addyi] treatment,&#8221; said Darwanna Todd, MD, an OB-GYN at the Kirk Kerkorian School of Medicine at the University of Nevada, Las Vegas. &#8220;When you get older, you become more sensitive to things like that,” she told Healthline. Treating low libido after menopause Addyi could expand treatment options for HSDD to a new population of females who may benefit. “I do think it will serve this population better as long as they have no other health issues,” said Todd. But it&#8217;s not a magic bullet. The experts interviewed by Healthline acknowledged that the female libido is complex and multifaceted. Addressing HSDD means engaging with everything from relationship dynamics to hormonal changes. Postmenopausal females navigate a wide variety of symptoms that can affect sexual desire. Symptoms of menopause include: hot flashes vaginal dryness pain during intercourse insomnia urinary incontinence According to Minkin, treating these symptoms is often a first step toward sexual wellness. “If somebody came to me with libido issues, my first question is: How&#8217;s your vagina feeling? Are you comfortable?&#8221; she said. Minkin recommended both vaginal estrogen and hormone replacement therapy (HRT) as options to treat the symptoms of menopause, particularly vaginal dryness. She hopes that the FDA’s recent removal of its “black box” warning on HRT will lead more females to feel less apprehensive about it and to consider it as a treatment option. Testosterone is also sometimes prescribed off-label to treat low libido in females, although it is not indicated for it. But besides medication, experts say that lifestyle should also be factored in. Minkin told Healthline that conversations about libido almost always begin by focusing on relationships and intimacy. “I would have no problem prescribing Addyi after discussing it with a patient. But I would also encourage them to talk about some of the psychosocial issues going on,” she said. Other recommendations for increasing libido include: getting more sleep exercising staying active using over-the-counter lubricants engaging in extended foreplay using vibrators or dilators “You have to take an entire whole body approach to sexuality and menopause in older age,” said Ruiz. “That means understanding how your body works, your anatomy, and your sexual needs — in other words, what makes you feel good, what allows you to get aroused, and ultimately to have a climax of orgasm.”', NULL, 'https://www.healthline.com/health-news/fda-approves-addyi-postmenopausal-women', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/senior-couple-embracing-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:38.932023', 'en', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'approved', NULL, '2026-01-29 13:47:21.963', NULL, '["FDA", "Addyi", "female Viagra", "postmenopausal women", "low libido", "HSDD", "sexual health"]', '{"topics": ["FDA drug approvals", "women''s health", "sexual health treatments", "postmenopausal care"], "summary": "وافقت إدارة الغذاء والدواء الأمريكية (FDA) على توسيع استخدام دواء Addyi لعلاج انخفاض الرغبة الجنسية لدى النساء بعد انقطاع الطمث حتى سن 65. يُعتبر هذا القرار خطوة مهمة في تعزيز خيارات العلاج لصحة المرأة الجنسية، مع تحذيرات بشأن التفاعل مع الكحول.", "entities": ["FDA", "Addyi", "Sprout Pharmaceuticals", "Cindy Eckert", "G. Thomas Ruiz"], "credibilityScore": 90}', '2026-01-25 06:50:38.932023', '2026-01-29 13:47:21.963');
INSERT INTO public.radar_items VALUES ('a25629c4-0b02-4fa2-a33b-4285d2a5da27', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '2abc94e2afc223803844c87362de2bcb', 'Journalists Mine News for Insights on Tylenol, Obamacare Credits, and Rural Health Funding', NULL, 'KFF Health News journalists made the rounds on national and local media recently to discuss topical stories. Here’s a collection of their appearances.', NULL, 'C&#233;line Gounder, KFF Health News&#8217; editor-at-large for public health, discussed a year of changes at the Department of Health and Human Services and its Centers for Disease Control and Prevention on NPR&#8217;s 1A on Jan. 22. On CBS News 24/7&#8217;s The Daily Report on Jan. 16 and CBS Saturday Morning&#8217;s HealthWatch on Jan. 17, Gounder also discussed a study that found no link between acetaminophen use during pregnancy and autism or attention-deficit/hyperactivity disorder. She also commented on rising measles cases and decreasing vaccination rates on CBS News 24/7&#8217;s The Daily Report on Jan. 15. Click here to hear Gounder on 1A. Click here to watch Gounder discuss acetaminophen use during pregnancy and autism on The Daily Report. Click here to watch Gounder on HealthWatch. Click here to watch Gounder discuss vaccines and measles on The Daily Report. KFF Health News California correspondent Christine Mai-Duc discussed the expiration of enhanced Affordable Care Act subsidies on LAist&#8217;s AirTalk on Jan. 20. Click here to hear Mai-Duc on AirTalk (begins ~18:00). KFF Health News chief rural correspondent Sarah Jane Tribble discussed the new Rural Health Transformation Program on Community Health Center Inc.&#8217;s Conversations on Health Care on Jan. 8. Click here to watch Tribble on Conversations on Health Care. Read the KFF Health News series &#8220;Rural Health Payout: Tracking the $50B Rural Health Fund.&#8221; KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/on-air-january-24-2026-tylenol-pregnancy-study-measles-aca-subsidies-rural-health/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2023/04/2023_kffhealthnews-on-air_weekly.jpg?w=1024', NULL, '2026-01-24 10:00:00', '2026-01-25 06:50:40.298739', 'ar', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["Tylenol", "Obamacare", "rural health funding", "vaccination rates", "acetaminophen", "autism", "Affordable Care Act", "measles"]', '{"topics": ["public health", "health policy", "vaccination", "maternal health", "rural health", "health subsidies"], "summary": "صحفيون من KFF Health News ناقشوا مواضيع صحية متنوعة مثل تأثير استخدام الأسيتامينوفين أثناء الحمل، انخفاض معدلات التطعيم، وتمويل الصحة الريفية. كما تناولوا انتهاء صلاحية إعانات قانون الرعاية بأسعار معقولة (Obamacare).", "entities": ["KFF Health News", "Céline Gounder", "Christine Mai-Duc", "Sarah Jane Tribble", "Department of Health and Human Services", "Centers for Disease Control and Prevention"], "credibilityScore": 90}', '2026-01-25 06:50:40.298739', '2026-01-29 13:36:30.616');
INSERT INTO public.radar_items VALUES ('0812a499-3d2f-44fb-b834-e769075ad917', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '1fc99f9ad224f5cdc650e7dfb29e3a76', 'Your Favorite Holiday Beverage May Weaken Your Bones, Experts Say', NULL, 'Many popular holiday beverages are high in sugar and may damage bone health. Image Credit: Tamara Evsiukova/Stocksy Many popular holiday drinks, such as hot chocolate, are high in sugar. Sugar can affect bone health by causing increased calcium loss. Having strong bones is important in preventing osteoporosis and fractures. Dietitians recommend limiting your sugar intake to protect your bone health. Each winter, as the holidays draw near, many people enjoy treating themselves to popular seasonal', NULL, 'Many popular holiday beverages are high in sugar and may damage bone health. Image Credit: Tamara Evsiukova/Stocksy Many popular holiday drinks, such as hot chocolate, are high in sugar. Sugar can affect bone health by causing increased calcium loss. Having strong bones is important in preventing osteoporosis and fractures. Dietitians recommend limiting your sugar intake to protect your bone health. Each winter, as the holidays draw near, many people enjoy treating themselves to popular seasonal beverages, such as rich hot chocolate, spiced cider or wine, creamy eggnog, and frothy lattes. However, while these beverages may taste like tradition, comfort, and celebration, our festive favorites may not be doing our health any favors. Beyond the obvious effects they can have on weight management — the average American gains 5 pounds between Thanksgiving and Christmas — there may be some other not-so-sweet side effects to consider. For example, all that sugar that you&#8217;re consuming could, in the long run, actually be detrimental to your bone health. Excess sugar consumption affects bone health Your bones have several important functions, including acting as calcium storage depots, providing support to your body, protecting your organs, and housing your bone marrow. When your bones are weakened by osteoporosis, you become more prone to fractures and may develop changes in your posture, like a hunched back. This means it is essential to protect yourself from bone loss. Kezia Joy, RDN, medical advisor at Welzo, explained that consuming high levels of sugar can indirectly affect bone health by increasing the amount of calcium lost in urine. As a result, less calcium is available to maintain bone density. &#8220;Frequent spikes in blood sugar may disrupt the normal functioning of vitamin D,&#8221; she told Healthline, &#8220;making it less likely that the body will be able to effectively absorb calcium from the foods we eat.&#8221; Research is limited on how high blood sugar may affect vitamin D functioning. However, a 2022 animal study suggests that vitamin D deficiency may impact blood sugar levels. Joy said that frequent consumption of sugary drinks during the holidays could worsen this effect, especially if your overall diet is not good. Additionally, excess sugar in your diet may contribute to low-grade chronic inflammation. This might affect bone remodelling over time, she said. &#8220;Therefore, it is crucial to consume high calorie [and] high-sugar items in moderation throughout the holiday season.&#8221; How holiday drinks can impact bone health Hannah Anderson, a registered dietitian at WellTheory, noted that while sugar can impact bone health, each drink has its own unique profile due to its other ingredients. &#8220;Hot chocolate made with milk does provide calcium,&#8221; she told Healthline, &#8220;which can help offset some adverse effects of sugar, though the benefit depends on how much sugar is added; store-bought versions often contain 20 to 30 grams per serving.&#8221; Anderson added that eggnog is especially calorie-dense due to its sugar and saturated fat content, with a typical cup containing over 300 calories and more than 20 grams of sugar. However, its milk and eggs do provide beneficial calcium and protein. &#8220;Mulled wine and cider offer antioxidants from spices but contain alcohol (which impairs calcium absorption) and added sugars,&#8221; she said. &#8220;At the same time, popular seasonal coffee drinks like peppermint mochas or gingerbread lattes can pack 50 grams of sugar [or more] in a large size with minimal nutritional benefits beyond the small amount of milk used,&#8221; said Anderson. How much sugar is too much? While recommendations vary slightly by organization, the American Heart Association (AHA) advises consuming no more than 6% of your daily calories as added sugar. For males, this is equivalent to about 9 teaspoons (36 grams), while for females, it&#8217;s about 6 teaspoons (25 grams). Added sugar is the sugar that&#8217;s added to foods during their preparation. It differs from the sugars naturally found in sweet foods, such as fruit. Added sugars may be listed in ingredient lists as syrup, nectar, juice, sugar, sweetener, or honey. They often have names ending in &#8220;ose,&#8221; such as fructose, dextrose, or sucrose. Additionally, the nutrition label will clearly state the amount of added sugar present in a food. Healthier alternatives to sugary holiday drinks As tempting as those holiday beverages may be, they&#8217;re best consumed in moderation or swapped with healthier options. &#8220;For healthier hot chocolate alternatives that support bone health, try making hot chocolate with unsweetened cocoa powder, low fat milk, and a small amount of honey, maple syrup, or a non-nutritive sweetener like stevia or monk fruit, to control sugar content,&#8221; said Anderson. On the other hand, if you&#8217;re using a store-bought mix, pick one with less sugar. Or, you can add a chocolate-flavored bone broth or collagen powder to hot water or milk to create a high protein, low-sugar option, Anderson suggested. &#8220;Other healthy hot cocoa variations include functional mushroom blends for further health benefits without compromising taste,&#8221; said Anderson. If you enjoy the flavors of mulled apple cider, you can replicate the experience with apple cider tea blends that don&#8217;t contain added sugar, she said. Or try preparing your own using warming spices like cinnamon, cloves, and star anise along with lemon juice and apple cider vinegar. &#8220;When ordering coffee drinks, ask for your desired level of sweetness (&#8216;one pump&#8217; or &#8216;half sweet,&#8217; etc.), ask for no whipped cream, choose non-fat or low fat milk for calcium without excess saturated fat, and consider adding a sprinkle of cinnamon or cocoa powder for flavor without the sugar,&#8221; Anderson said. Joy added that eggnog can also be lightened by reducing the amount of added sugars. She further noted that fortified unsweetened plant-based milks, lower-sugar hot beverages, and herbal teas are all good options for experiencing the flavors of the season without harming bone density. &#8220;By choosing beverages containing proteins and minerals as opposed to beverages containing excessive amounts of sugar, you can help regulate your nutrient levels at a steady level and minimize excessive calcium loss,&#8221; said Joy. &#8220;Therefore, these alternatives can allow you to experience the festivities of the holiday season while maintaining overall bone health,&#8221; she said.', NULL, 'https://www.healthline.com/health-news/favorite-holiday-beverage-bone-health-damage', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Holiday-Beverage-Stocksy_txp83d421d6GQD400_Medium_1482312-Header.jpg', NULL, NULL, '2026-01-25 06:50:39.424077', 'en', 'health-news', 'nutrition', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["sugar", "bone health", "holiday beverages", "calcium loss", "osteoporosis"]', '{"topics": ["sugar impact on health", "bone density", "holiday diet", "osteoporosis prevention"], "summary": "تناول المشروبات الموسمية الغنية بالسكر، مثل الشوكولاتة الساخنة واللاتيه، قد يضر بصحة العظام عن طريق زيادة فقدان الكالسيوم. ينصح خبراء التغذية بتقليل استهلاك السكر للحفاظ على كثافة العظام ومنع هشاشتها.", "entities": ["Kezia Joy", "Welzo", "Healthline"], "credibilityScore": 90}', '2026-01-25 06:50:39.424077', '2026-01-29 13:36:59.497');
INSERT INTO public.radar_items VALUES ('8dad70ac-1102-4354-b7b9-f8dd02955d15', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'fb4db5543a4430ab3b65eeec456d3981', 'Dems See Opportunities in Republican Embrace of MAHA Movement', NULL, 'Get our weekly newsletter, The Week in Brief, featuring a roundup of our original coverage, Fridays at 2 p.m. ET.', NULL, 'There&#8217;s a lot going on in Washington right now. While President Donald Trump has been grabbing for Greenland, he&#8217;s also talked in the White House about health policy — whether it&#8217;s the Rural Health Transformation Program, ways to address the nation&#8217;s spiraling health costs, or an effort to promote whole milk in schools. At the same time, congressional Republicans are eyeing health issues from the &#8220;Make America Healthy Again&#8221; perspective, hoping it will provide a boost in the midterm elections. Here&#8217;s why. Republicans see the MAHA constituency as critical in the midterms and beyond because its supporters include desirable voting demographics: independents and some Democrats, many of whom are women, younger voters, or suburbanites. The strategy risks backfiring, though, because polls show voters care more about reducing health care costs than about MAHA&#8217;s war on junk food or efforts to roll back access to vaccines. The affordability issue was thrust center stage last year when enhanced subsidies for Affordable Care Act marketplace plans expired. As a result, many of the roughly 23 million people who buy coverage on the health law&#8217;s marketplaces are now facing premium payments more than double what they faced last year. Congress is continuing to wrestle with what has emerged as a key kitchen table issue. Democrats are strategizing about how to use public support for MAHA priorities to their own advantage. They&#8217;re hoping to expose GOP policies that run counter to MAHA priorities; trumpet Democrats&#8217; efforts to tackle health care costs; and highlight their own party&#8217;s work on such MAHA goals as cracking down on pesticide-makers, according to some Democratic strategists. Democrats are talking about their continuing fight to address health care costs while largely avoiding direct attacks on Health and Human Services Secretary Robert F. Kennedy Jr. or MAHA, because the movement resonates with the public. Meanwhile, cracks are starting to threaten the Make America Great Again coalition and the lockstep support Trump has enjoyed from Capitol Hill Republicans. For Republicans, the next batch of MAHA events and summits is already scheduled. After taking a political back seat in recent years, health care may dominate the 2026 election races. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/the-week-in-brief-gop-embrace-maha-movement-elections/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2025/01/the-week-in-brief-thumbnail.jpg?w=1024', 'Stephanie Armour', '2026-01-23 19:30:00', '2026-01-25 06:50:40.545173', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["MAHA Movement", "health policy", "Affordable Care Act", "health care costs", "Republicans", "Democrats"]', '{"topics": ["health care affordability", "political strategies in health", "health movements"], "summary": "الخبر يناقش استراتيجيات الجمهوريين والديمقراطيين في التعامل مع حركة MAHA المتعلقة بالصحة، مع التركيز على قضايا مثل تكاليف الرعاية الصحية وسياسات الغذاء. يتم تحليل تأثير هذه السياسات على الانتخابات المقبلة.", "entities": ["Donald Trump", "Robert F. Kennedy Jr.", "Democratic strategists", "Republican Party"], "credibilityScore": 80}', '2026-01-25 06:50:40.545173', '2026-01-29 13:36:20.508');
INSERT INTO public.radar_items VALUES ('11f1108f-e597-488d-8166-61dbc342b6ef', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'cd3ea158e7a808cf09ea7ef45fd7aa92', 'Eating Nuts May Help Reduce Food Cravings, Promote Weight Management', NULL, 'Young adults with a higher risk of metabolic syndrome may benefit from eating nuts, researchers say. fcafotodigital/Getty Images A new study suggests that swapping high carb snacks for nuts can help curb sweet cravings. Participants at risk for metabolic syndrome who made the switch also tended to increase their protein intake. Nuts are high in satiating nutrients like healthy fats, protein, and fiber. If you’re allergic to tree nuts, seeds can make a good substitute. Swapping your usual between', NULL, 'Young adults with a higher risk of metabolic syndrome may benefit from eating nuts, researchers say. fcafotodigital/Getty Images A new study suggests that swapping high carb snacks for nuts can help curb sweet cravings. Participants at risk for metabolic syndrome who made the switch also tended to increase their protein intake. Nuts are high in satiating nutrients like healthy fats, protein, and fiber. If you&#8217;re allergic to tree nuts, seeds can make a good substitute. Swapping your usual between-meal snacks for a handful of mixed tree nuts could help cut cravings for sweets and fast food and improve the overall quality of your diet. That&#8217;s according to a new study published on December 2 in Nutrients. Researchers found that young adults at higher risk for metabolic syndrome who snacked on nuts daily for 16 weeks reported fewer urges for sugary and salty treats, ate more protein-rich foods, and scored better on a measure of diet quality. Here&#8217;s what you need to know about the metabolic health benefits of nut consumption. Nuts vs. high carb snacks The research team at Vanderbilt University Medical Center recruited 84 males and females between the ages of 22 and 36. All participants had at least one risk factor for metabolic syndrome — a cluster of conditions, such as high blood pressure, excess belly fat, and abnormal cholesterol levels, that raise the risk for heart disease and diabetes. To qualify, participants had to have maintained a stable weight for at least three months and fall within a specific body mass index (BMI) range. Those with nut allergies, chronic diseases like diabetes, or certain lifestyle factors such as smoking were excluded. Before the main part of the trial began, everyone went through a two-week “run-in” period, eating a balanced diet that included typical high-carbohydrate snacks but no nuts. After that, participants were randomly assigned to one of two groups: Tree nuts snack group: Ate a 33.5-gram mix of unsalted raw almonds, walnuts, pecans, macadamia nuts, hazelnuts, pistachios, and cashews twice a day. High-carbohydrate snack group: Ate snacks such as pretzels, animal crackers, graham crackers, or granola bars twice a day. Both snack types were similar in calories, protein, fiber, and sodium, and were eaten between 6:00 a.m. and 6:00 p.m. Participants met with registered dietitians every two weeks to receive counseling and their pre-portioned snacks. The study lasted 16 weeks, during which researchers measured food cravings, daily food intake, and overall diet quality at both the start and end. They also collected blood samples to look at hormones related to appetite. Nuts led to fewer sweet cravings, higher protein intake By the end of the study, the nut-snacking group showed notable changes in their eating habits and cravings. Participants who ate tree nuts reported: Less craving for sweets and fast food: Ratings for cravings dropped for items like cookies, brownies, donuts, candy, ice cream, chips, and pizza. For example, cravings for brownies fell by nearly half a point on a five-point scale, and cravings for cookies dropped by more than 0.6 points. Reduced preference for sweet taste: About 12.5% fewer people in the nut group said they preferred sweet flavors compared to at the start of the study. Eating fewer sugary and salty snacks: The frequency of eating frozen desserts and salty snacks went down. Eating more protein-rich foods: On average, they increased their daily servings of protein foods, especially from seafood and plant-based sources, by more than four servings. These changes were linked to shifts in certain appetite-related hormones. In the nut group, levels of GLP-1 — a hormone that can help regulate appetite — increased, and this rise was associated with reduced cravings for cakes, brownies, candy, and ice cream. Furthermore, the nut group’s overall score on the Healthy Eating Index (HEI), which measures how well a person’s diet aligns with national dietary guidelines, improved by 19%. This bump reflected a higher intake of healthy unsaturated fats and protein-rich foods, as well as a lower intake of sodium and refined grains. In contrast, the high-carbohydrate snack group did not see significant changes in food cravings or diet quality. In fact, they showed a small decrease in fruit consumption, an increase in daily calorie intake of approximately 350 calories, and an average weight gain of roughly 0.8 kilograms (about 1.8 pounds) over the 16-week period. The nut group, on the other hand, did not gain weight, even though they were eating calorie-dense snacks. While they ate about 468 grams less total food by weight each day, their overall calorie intake stayed about the same. Hunger and fullness ratings did not change significantly in the nut group, suggesting they felt just as satisfied as before. The findings suggest that replacing typical snack foods with a modest portion of mixed tree nuts may help young adults at risk for metabolic syndrome steer away from less healthy foods and make choices that improve the overall quality of their diets, without unwanted weight gain. How nuts help reduce cravings for sweets Kezia Joy, a registered dietitian and medical advisor with Welzo, noted that replacing higher-carbohydrate snack foods with nuts can help reduce cravings due to the balanced nutrients within nuts. Joy wasn&#8217;t involved in the new study. They contain a high amount of fat, protein, and fiber. &#8220;The slow digestion of these nutrients creates steady blood sugar and enhances feelings of being satisfied for longer periods,&#8221; she told Healthline. Joy additionally noted that eating nuts helps regulate blood sugar. &#8220;Steady blood sugars are associated with fewer or no fluctuations in blood glucose (spikes [and] drops), and the less frequent the spikes and dips, the less likely your body is to send signals of &#8216;urgent&#8217; need for energy via hunger/cravings,&#8221; she said. Joy concluded by saying that chewing nuts also requires more time and effort relative to other foods. &#8220;[T]his additional time, along with providing a greater feeling of fullness, contributes to enhanced satisfaction post-meal and supports better long-term appetite regulation,&#8221; she said. Guidelines for healthy nut consumption Jacqueline A. Vernarelli, associate professor of Public Health and Director of Research Education and Consultation, College of Health Professions, Sacred Heart University, suggested aiming for about a quarter cup of nuts. &#8220;Mix it up, literally and figuratively,&#8221; said Vernarelli, who wasn&#8217;t involved in the new study. Vernarelli told Healthline that there are a variety of nuts — including almonds, cashews, walnuts, Brazil nuts, and macadamia nuts — that make a great high protein, satiating snack. &#8220;Be sure to choose whole, raw or dry-roasted varieties,&#8221; she said, &#8220;and choose unsalted nuts when possible, as salted or flavored varieties are typically high in sodium.&#8221; Allergic to tree nuts? &#8220;Seeds are a great protein-packed option,&#8221; said Vernarelli, &#8220;especially sunflower and pumpkin seeds.&#8221; They also contain healthy fats and fiber. According to Joy, other alternatives to tree nuts include roasted legumes, such as roasted chickpeas and roasted edamame. &#8220;Other balanced options that will help you feel full and aid your metabolism without the risk of an allergic reaction [from nuts] are Greek yogurt, hummus with vegetables, and whole grain foods eaten with a spread made from seeds,&#8221; she said.', NULL, 'https://www.healthline.com/health-news/nuts-reduce-cravings-promote-weight-management', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/pouring-nuts-hand-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:38.564929', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'published', NULL, '2026-01-25 08:21:44.298', NULL, '[]', NULL, '2026-01-25 06:50:38.564929', '2026-01-25 08:21:44.298');
INSERT INTO public.radar_items VALUES ('9d8f2338-b19f-442c-b4ac-60b76ff46a09', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'ecf2a05c9356403f6e43156c0debf81b', 'These 3 Policy Moves Are Likely To Change Health Care for Older People', NULL, 'Two Trump administration regulatory rollbacks affect nursing home staffing and home care workers, and a new AI experiment in Medicare has alarmed eldercare advocates and congressional Democrats.', NULL, 'Month after month, Patricia Hunter and other members of the Nursing Home Reform Coalition logged onto video calls with congressional representatives, seeking support for a proposed federal rule setting minimum staff levels for nursing homes. Finally, after decades of advocacy, the Biden administration in 2023 tackled the problem of perennial understaffing of long-term care facilities. Officials backed a Medicare regulation that would mandate at least 3.48 hours of care from nurses and aides per resident, per day, and would require a registered nurse on-site 24 hours a day, seven days a week. The mandated hours were lower than supporters hoped for, said Hunter, who directs Washington state&#8217;s long-term care ombudsman program. But &#8220;I&#8217;m a pragmatic person, so I thought, this is a good start,&#8221; she said. &#8220;It would be helpful, for enforcement, to have a federal law.&#8221; In 2024, when the Centers for Medicare & Medicaid Services adopted the standards, advocates celebrated. But industry lawsuits soon blocked most of the rule, with two federal district courts finding that Medicare had exceeded its regulatory authority. And after the 2024 elections, Hunter said, &#8220;I was concerned about the changing of the guard.&#8221; Her concerns proved well founded. In July, as part of Republicans&#8217; One Big Beautiful Bill Act, Congress prohibited Medicare from implementing the staffing standards before 2034. Last month, CMS repealed the standards altogether. They never took effect. &#8220;It was devastating,&#8221; Hunter said. As with environmental law and consumer protections, the Trump administration&#8217;s enthusiasm for deregulation has undone long-sought rules to improve care for the aged. And it has introduced a Medicare experiment for prior authorizations, now getting underway in six states, that has alarmed advocates, congressional Democrats, and a good number of older Americans. Taken together, the moves will affect many of the facilities and workers providing care and introduce complications in health coverage in several states. On the nursing home front, &#8220;it&#8217;s clear CMS has no interest in ensuring adequate staffing,&#8221; said Sam Brooks, the director of public policy for the National Consumer Voice for Quality Long-Term Care. &#8220;They&#8217;re repealing a regulation that could have saved 13,000 lives a year,&#8221; he added, citing an analysis by University of Pennsylvania researchers. Industry groups argued that nursing homes, with high rates of staff turnover, were already struggling to fill vacancies. The staffing mandate &#8220;was requiring nursing homes to hire an additional 100,000 caregivers that simply don&#8217;t exist,&#8221; said Holly Harmon, a senior vice president at the American Health Care Association. The organization had brought one of the suits that largely vacated the rule. &#8220;Facilities would have been forced to limit admissions or downsize to comply with the requirements, or close altogether,&#8221; Harmon said. For supporters, the action is now likely to shift to updating requirements in 35 states, along with the District of Columbia, that have already established some nursing home staff standards, and to developing them in those that haven&#8217;t. Rules for Home Help A second rescinded regulation, this one more unexpected, brought about upheaval in July, when the Labor Department announced a return to a policy excluding home care workers from the federal Fair Labor Standards Act. Some history: Dating back to the New Deal, the FLSA mandated that workers receive the federal minimum wage (currently $7.25 an hour) and overtime pay. It exempted most &#8220;domestic service workers&#8221; until 1975, when a new Labor Department regulation included them — with the exception of home care workers. &#8220;There was a misinterpretation of home care work as being casual, nonprofessional, non-skilled,&#8221; the equivalent of teenage babysitting, said Kezia Scales, a vice president at PHI, a national research and advocacy organization. &#8220;Just someone popping into your mother&#8217;s house now and then and keeping her company.&#8221; For almost 40 years, workers and their supporters lobbied to change the rule, seeing it as a contributor to the low wages and meager benefits of a swiftly growing workforce, one made up primarily of women and minority groups, with many immigrants. In 2013, the Labor Department responded with a rule that brought home care workers under the labor act, entitled to minimum wage, time and a half for overtime work, and payment for travel time between clients. After industry lawsuits failed to overturn it, &#8220;everything settled down,&#8221; Scales said. &#8220;It was in place successfully for a decade.&#8221; Home care workers brought hundreds of compliance complaints annually. In 87% of them, the Labor Department found violations of the labor act, according to a 2020 Government Accountability Office report. Since 2013, home care agencies have paid about $158 million in back wages, PHI has calculated. Then in July, the Labor Department abruptly announced that it would return to the 1975 regulations and stop enforcing the 2013 rule, which it said &#8220;had negative effects on the ground&#8221; and hindered consumer access to care. The agencies employing most home care workers, primarily funded through Medicaid, would agree. &#8220;Many workers never got any benefit from this,&#8221; said Damon Terzaghi, a vice president at the National Alliance for Care at Home. &#8220;States made a lot of moves to essentially absolve themselves of any responsibility,&#8221; he said. A 2020 federal report, for example, found that 16 states had capped Medicaid-covered home care hours at 40, thus averting overtime payment. The alliance, which estimates that the number of impacted agencies and businesses has declined by 30% since 2013, supported the rescission. Scales, who hopes for congressional action, called it &#8220;a shocking step backward.&#8221; Where they concur is that the United States has never really committed to sufficiently funding long-term care at home. With the July legislation setting the stage for a $914 billion cut to Medicaid over the coming decade, that seems unlikely to change anytime soon. Medicare&#8217;s AI Referee Beyond rolling back policies for care of the aged, the Trump administration has established a pilot program to introduce one to traditional Medicare: prior authorization, using artificial intelligence and machine learning technologies. Touting it as a boon to taxpayers, Medicare calls it WISeR — Wasteful and Inappropriate Service Reduction. Prior authorization, in which private insurers review proposed treatments before agreeing to pay for them, is widely used in Medicare Advantage plans despite its unpopularity with patients, doctors, and health care organizations. It has rarely been used in traditional Medicare. This month, however, WISeR debuts in six states (Arizona, New Jersey, Ohio, Oklahoma, Texas, Washington) in a six-year trial to determine whether review by tech companies can reduce costs and improve efficiency, while maintaining or improving quality of care. Initially, WISeR targets 17 items and services that CMS said &#8220;historically have had a higher risk of waste, fraud and abuse.&#8221; The list includes knee arthroscopy for arthritis, electrical nerve stimulation devices for several conditions, and treatment for impotence. The pilot program excludes emergency services and inpatient hospital care, or care where delay poses &#8220;a substantial risk.&#8221; Algorithmic denials will trigger review by &#8220;an appropriately licensed human clinician.&#8221; The tech companies get &#8220;a share of averted expenditures.&#8221; &#8220;It injects some of the worst of Medicare Advantage into traditional Medicare,&#8221; said David Lipschutz, co-director of the Center for Medicare Advocacy. The six vendors that approve or reject treatments &#8220;have a financial stake in the outcomes,&#8221; he said, and therefore &#8220;an incentive to deny care.&#8221; Moreover, the CMS Innovation Center overseeing the pilot could theoretically bypass Congress and expand prior authorization to include more medical services in more states. The agency did not respond to questions about what kind of human clinicians would review denials, except to say that they would have &#8220;relevant experience&#8221; and that tech companies would be &#8220;financially penalized for inappropriate denials, high appeal rates or poor performance.&#8221; It plans an &#8220;independent, federally funded evaluation&#8221; and will release public reports annually. Democrats in Congress have introduced bills in both houses to repeal WISeR. &#8220;We should be reducing red tape in Medicare, not creating new hurdles that second-guess health care providers,&#8221; said Rep. Suzan DelBene of Washington, one of the bill&#8217;s sponsors. For now, though, WISeR has opened for business, receiving prior authorization requests through its electronic portals. &#8220;The New Old Age&#8221; is produced through a partnership with The New York Times. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/long-term-care-nursing-homes-medicare-ai-prior-authorization/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-113864963.jpg?w=1024', 'Paula Span', '2026-01-23 10:00:00', '2026-01-25 06:50:40.790941', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["nursing homes", "Medicare", "eldercare", "staffing standards", "health policy"]', '{"topics": ["healthcare policy", "eldercare regulations", "Medicare reforms", "nursing home staffing"], "summary": "تتناول المقالة تغييرات في السياسات الصحية التي تؤثر على رعاية كبار السن، بما في ذلك إلغاء معايير الحد الأدنى لتوظيف دور الرعاية وإدخال تجربة جديدة في برنامج Medicare. هذه التغييرات أثارت قلق المدافعين عن حقوق كبار السن وبعض المشرعين.", "entities": ["Patricia Hunter", "Nursing Home Reform Coalition", "Centers for Medicare & Medicaid Services", "Trump administration", "Biden administration"], "credibilityScore": 90}', '2026-01-25 06:50:40.790941', '2026-01-29 13:36:11.405');
INSERT INTO public.radar_items VALUES ('8f3afec1-aa95-4af4-8071-fd3f7abe1f76', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '41fef5471f505147db72bc5c72520647', 'How the ''Portfolio Diet'' May Help Lower Cholesterol, Heart Disease Risk', 'حمية «بورتفوليو» تخفض الكوليسترول ومخاطر الوفاة القلبية حتى 18%', 'Adherence to the Portfolio Diet may reduce the risk of death from heart disease by 18%. Image Credit: Ina Peters/Stocksy Research has linked adherence to the Portfolio Diet with a reduction in the risk of death from heart disease by up to 18%. The diet’s success comes from combining four specific cholesterol-lowering food categories for a powerful “additive effect.” Starting the portfolio diet at an earlier age could delay the onset of cardiovascular events by as much as 13 years. Experts say co', 'دراسات من جامعة تورنتو تربط حمية «بورتفوليو» النباتية بانخفاض وفيات أمراض القلب حتى 18%، عبر تأثير تراكمي لأربع فئات غذائية مخفضة للكوليسترول، وقد تؤخر الأحداث القلبية الوعائية حتى 13 عاماً.', 'Adherence to the Portfolio Diet may reduce the risk of death from heart disease by 18%. Image Credit: Ina Peters/Stocksy Research has linked adherence to the Portfolio Diet with a reduction in the risk of death from heart disease by up to 18%. The diet&#8217;s success comes from combining four specific cholesterol-lowering food categories for a powerful &#8220;additive effect.&#8221; Starting the portfolio diet at an earlier age could delay the onset of cardiovascular events by as much as 13 years. Experts say consistent, small additions (like nuts or beans) offer great results, even with moderate adherence. The Mediterranean and DASH diets have gained widespread recognition for their health benefits, particularly in promoting heart health. Yet a lesser-known heart-healthy diet is drawing attention for its ability to seemingly reduce the risk of death from cardiovascular disease and other chronic health conditions. It’s known as the Portfolio Diet, and a pair of recent studies shows that the benefits of the plant-based regimen may go beyond lowering the risk or delaying the onset of cardiovascular disease: it could potentially lower the risk of mortality, too. According to researchers from the Temerty Faculty of Medicine at the University of Toronto, this is the first time the Portfolio Diet has been linked to a reduction in cardiovascular disease mortality and all-cause mortality. What to know about the Portfolio Diet The Portfolio Diet was developed in 2003 by University of Toronto professor David Jenkins. The plant-based eating pattern gets its name because it calls for substituting foods already in someone’s diet with those from a “portfolio” of cholesterol-lowering ingredients that fall into four categories: Soy/plant proteins that displace saturated fat Plant sterols that block cholesterol absorption Tree nuts that provide heart-healthy, unsaturated fats Soluble fiber that binds and removes bile/cholesterol It’s through this combination of ingredients, which creates an “additive” effect in lowering cholesterol, that Wellstar cardiovascular dietitian Erin Sheehan has said sets the portfolio diet apart from others. “When it comes to looking specifically at lowering (bad) LDL cholesterol, that&#8217;s where the portfolio diet really shines,” Sheehan told Healthline. “What we&#8217;re doing with this diet is combining a whole bunch of these foods to compound on top of each other and maximize that LDL-lowering effect.” Like with any diet looking to improve heart health, people should avoid foods that are highly processed and contain added sugar. Long-term health effects of the Portfolio Diet Researchers have already demonstrated that adherence to the portfolio diet can positively impact heart health. A 2023 peer-reviewed study published in the American Heart Association (AHA) journal Circulation can help lower a person’s risk of cardiovascular disease, including stroke and heart disease. Two recent studies by the University of Toronto Temerty Faculty of Medicine delved deeper into the lasting effects of following this eating plan. In a study published in BMC Medicine in May 2025, researchers collected data from nearly 15,000 racially diverse Americans over a two-decade period. Participants documented their daily food intake and completed supplemental questionnaires, earning positive points for consuming foods from the portfolio diet and negative points for eating foods high in saturated fat and cholesterol. The study found that moderate adherence to the portfolio diet could decrease the risk of mortality from cardiovascular disease and coronary heart disease by 12% and 14%, respectively. That level decreased overall mortality by 12%. However, the closer someone followed the diet, the higher those numbers increased, to 16% and 18% reductions in mortality for cardiovascular and coronary heart disease, respectively. Overall mortality dropped by 14%. It’s a surprising and “impressive” result, said Chandan Devireddy, MD, an interventional cardiologist with Emory Healthcare in Atlanta. Devireddy wasn&#8217;t involved in the studies. “Reducing mortality is not an easy thing to demonstrate,” he told Healthline. “When you see the kind of numbers that are suggested in reduction with these dietary changes, it&#8217;s fairly impressive.” Portfolio diet as early prevention In a second study, also conducted by the University of Toronto and recently published in BMC Medicine, researchers examined the effects of starting the portfolio diet at a younger age. They found that the benefits of early adherence to the diet among “ethnoculturally diverse young adults” were two-fold: it could limit exposure to the “bad” LDL cholesterol over their lifetime and delay the onset of cardiovascular events. Adhering to the diet 50% of the time may delay the onset of cardiovascular events by 6 years, and adhering to the diet 100% of the time could expand that to 13 years. Those results elicited by the dietary changes were similarly impressive, Devireddy said. “It does provide some evidence that paying attention to the type of foods that we expose school and college kids to may have a huge impact in both their exposure to cholesterol and also potentially in their long-term dietary preferences,” Devireddy said. Sheehan agreed that the study&#8217;s results among young adults were particularly “exciting” from a dietitian’s perspective, as they provide a pathway to lifelong prevention rather than just intervention. Sheehan wasn&#8217;t involved in the study. “There are things that we can do to prevent cardiovascular disease and other chronic diseases, and I think it&#8217;s exciting to think about the delay of that age-related rise in LDL cholesterol, which in turn delays our cardiovascular risk,” she said. “I think it should be a very motivating argument for anybody.” In both studies, the inclusion of racially diverse and younger participants was significant, as earlier studies had tended to focus on older, predominantly white, and male populations. But in looking at a wider swath of the population, researchers not only showed that the benefits are realized across the different groups, “but in these minority subsets, there may even be a bigger impact of the portfolio diet realized within those groups,” Devireddy said. Overcoming barriers to the Portfolio Diet While there appear to be benefits to following the Portfolio Diet, experts note that there are also hurdles. Devireddy said that changing eating habits can be difficult to overcome. “Dietary choices and instincts are so ingrained after a lifetime that it may be very challenging for many to suddenly make a 180-degree turn in the type of diet that they find palatable, and that they know how to cook and prepare, and whether they have the resources to obtain these type of foods when they&#8217;re walking the grocery store aisle,” he said. Sheehan acknowledged that current grocery store prices are certainly a barrier, but she challenged shoppers to take a second look. “A lot of the foods that are recommended in this diet, and others, are actually pretty affordable when you really look,” she said. “Look at beans. You can get a can of beans or even a bag of dried beans for very, very cheap compared to some of the chicken and ground beef that you see.” Canned or frozen fruits and veggies — without the added sugars and salt — are also cost-effective, Sheehan said. “So, I kind of back patients into thinking that way: What can we find that works with that budget?” Once committed to the Portfolio Diet, Sheehan recommended taking a slow approach and focusing on adding, rather than taking away, to help make the transition a little easier — one of the benefits of the diet. “You can have a handful of nuts every day, and you can have a couple of meatless meals throughout a week, and that&#8217;s still enough to see great results,” she said. “It really is just about consistency, not just perfection.&#8221;', 'أظهرت دراسات حديثة أن الالتزام بحمية «بورتفوليو» النباتية يرتبط بانخفاض خطر الوفاة بسبب أمراض القلب بنسبة تصل إلى 18%، ويعزو الباحثون ذلك إلى «تأثير تراكمي» ناتج عن دمج أربع فئات غذائية مخفضة للكوليسترول. كما تشير النتائج إلى أن البدء بهذه الحمية في سن مبكرة قد يؤخر حدوث الأحداث القلبية الوعائية لمدة قد تصل إلى 13 عاماً، وأن حتى الالتزام المعتدل يحقق فوائد واضحة.

ورغم شهرة حميتي البحر المتوسط و«داش» بفوائد قلبية مثبتة، تبرز «بورتفوليو» كنمط أقل شهرة لكنه واعد. صُممت الحمية عام 2003 على يد البروفيسور ديفيد جنكينز في جامعة تورنتو، وتعتمد على استبدال أطعمة مألوفة بمكونات من «محفظة» غذائية مخفضة للكوليسترول ضمن أربع مجموعات رئيسية:
- بروتينات الصويا/البروتينات النباتية التي تزاحم الدهون المشبعة.
- الستيرولات النباتية التي تُعطل امتصاص الكوليسترول.
- المكسرات الغنية بالدهون غير المشبعة المفيدة للقلب.
- الألياف الذائبة التي ترتبط بالأحماض الصفراوية والكوليسترول وتساعد على طرحهما.

يؤكد اختصاصيو التغذية القلبية أن الجمع بين هذه العناصر يعظم خفض كوليسترول LDL «الضار»، مع ضرورة تجنب الأطعمة فائقة المعالجة والمضافات السكرية ضمن أي نمط غذائي يهدف لصحة القلب.

وعلى صعيد الآثار طويلة المدى، أظهر بحث مُحكّم نُشر عام 2023 في دورية «سيركيوليشن» التابعة لجمعية القلب الأمريكية أن الحمية قد تقلل مخاطر الأمراض القلبية الوعائية، بما فيها السكتة الدماغية ومرض القلب التاجي. كما أفاد باحثو كلية «تيمرتي» للطب بجامعة تورنتو بأن هذه هي المرة الأولى التي تُربط فيها «بورتفوليو» بانخفاض وفيات أمراض القلب والوفيات لجميع الأسباب.

وفي دراسة نُشرت في «بي إم سي ميديسن» في مايو/أيار 2025، جُمعت بيانات قرابة 15 ألف مشارك من أمريكيين متنوعين عرقياً على مدى عقدين. سجّل المشاركون استهلاكهم اليومي، ونالوا نقاطاً إيجابية لأطعمة من «بورتفوليو» وسلبية لأطعمة غنية بالدهون المشبعة والكوليسترول. أظهرت النتائج أن الالتزام المتوسط بالحمية خفّض خطر الوفاة من أمراض القلب والأوعية الدموية بنسبة 12%، ومن مرض القلب التاجي بنسبة 14%، وخفّض الوفيات العامة بنسبة 12%. ومع ارتفاع درجة الالتزام، زادت الفوائد إلى انخفاض بنسبة 16% و18% في وفيات الأمراض القلبية الوعائية ومرض القلب التاجي على التوالي، وانخفضت الوفيات العامة بنسبة 14%.

يشير الخبراء إلى أن إضافات صغيرة ومتسقة—مثل حفنة مكسرات يومية أو حصة من البقول—قد تمنح نتائج ملموسة حتى مع التزام معتدل بالحمية، فيما يمنح البدء المبكر فرصة أكبر لتأخير الأحداث القلبية الوعائية لسنوات.', 'https://www.healthline.com/health-news/portfolio-diet-improve-heart-health-lower-cholesterol', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Portfolio-Diet-Stocksy_txp395ca629ewC400_Medium_1764645-Header.jpg', NULL, NULL, '2026-01-25 06:50:38.193323', 'en', 'health-news', NULL, 8, NULL, false, false, NULL, 'published', NULL, '2026-01-25 08:24:00.171', NULL, '["حمية بورتفوليو", "الكوليسترول", "أمراض القلب", "نظام نباتي", "ألياف ذائبة", "الستيرولات النباتية", "مكسرات", "جامعة تورنتو"]', NULL, '2026-01-25 06:50:38.193323', '2026-01-25 08:24:00.171');
INSERT INTO public.radar_items VALUES ('953ebf5a-a34b-4716-935c-c070e9f27c38', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '164a353ccdb6bc08f48a8495ba4f7c77', 'Her Son’s Injury Never Got Its Day in Vaccine Court. Their Lawyer Is Now Advising RFK on Its Overhaul.', NULL, 'The federal government’s Vaccine Injury Compensation Program was supposed to help patients with their medical bills while protecting vaccine supply. But allies of Health and Human Services Secretary Robert F. Kennedy Jr. are routinely transferring cases from that program to launch lawsuits against drugmakers.', NULL, 'JACKSONVILLE, Fla. — In 2019, after a routine vaccination, 11-year-old Keithron Thomas felt a sharp pain in his shoulder and down his arm. His mother, Melanie Bostic, thought it would go away after a few days. But days turned to weeks, then months, and years. Bostic learned of a federal program designed to help people who suffer rare vaccine reactions. The Vaccine Injury Compensation Program was created in 1986 after a flood of vaccine injury lawsuits drove drugmakers from the market. Congress aimed to offer a faster and more generous path to compensation for people injured by vaccines, while shielding manufacturers from liability. The VICP, commonly known as vaccine court, is taxpayer-funded. The government pays any award to claimants as well as attorneys fees. Bostic filed a claim in 2022 for compensation to cover her son&#8217;s spiraling medical bills. She then contacted the Carlson Law Firm, which referred her to Arizona-based attorney Andrew Downing — who now serves as a senior adviser to Health and Human Services Secretary Robert F. Kennedy Jr. Downing declined to comment and HHS did not respond to requests for comment for this article. Downing, who has represented hundreds of plaintiffs in vaccine court in Washington, D.C., signed on to take their case, according to a contract reviewed by KFF Health News. They agreed Downing would pursue the claim before the VICP. Bostic shared documents and medical records as he requested them. Months passed as she waited for news on her son&#8217;s case. After several months of making court filings, Downing told her it was time to opt out of the vaccine program and sue the drugmaker. When she refused to opt out, he withdrew from the case. The government paid Downing $445 an hour for representing Bostic, which is typical for program attorneys with his experience, according to court records. Three years later, Bostic said, she hasn&#8217;t received a dime for her son&#8217;s injury. Thomas, now 18, endures debilitating pain that doctors say may never go away. Rather than help them work through the program, Bostic feels that Downing steered them away from it and toward a lawsuit against the manufacturer. The VICP ultimately dismissed her case. Bostic was furious that the court paid Downing anything. &#8220;Y&#8217;all could&#8217;ve gave that to me for my son,&#8221; she said. &#8220;How dare y&#8217;all.&#8221; In Business With Washington In June, Kennedy&#8217;s HHS also awarded Downing&#8217;s law firm, Brueckner Spitler Shelts, a sole-source federal contract to consult on an overhaul of the VICP. The contract has grown to $410,000. Downing is the only attorney listed on the firm&#8217;s website who has practiced in vaccine court. Kennedy has routinely questioned vaccine safety and called the VICP &#8220;broken,&#8221; saying it shields drug companies from some liability &#8220;no matter how negligent they are.&#8221; As a personal injury lawyer, Kennedy previously spearheaded civil litigation against vaccine maker Merck. Downing and about a dozen other lawyers have transferred hundreds of clients from the vaccine program to civil suits, where the financial rewards — for patients and their lawyers — could run far higher, according to a KFF Health News analysis of court records and program data. They&#8217;ve collected millions of taxpayer dollars in attorneys fees from vaccine court while launching precisely what it was designed to avoid: lawsuits against vaccine manufacturers. This shift in legal strategy has fueled Kennedy&#8217;s crusade against Merck, and it could end up hurting some vaccine-injured clients, several experts said. University of California Law-San Francisco professor Dorit Reiss has studied vaccine court for over a decade and has tracked the rise of anti-vaccine forces in American politics. She said VICP attorneys who are also suing vaccine makers have &#8220;incentives to direct more people&#8221; to lawsuits, &#8220;when it might not be in their best interest.&#8221; A Delicate Balance Kennedy has criticized the VICP as a barrier to accountability. But for Bostic, vaccine court offered an opportunity to hold the government to its promise of caring for casualties of widespread immunization. Like any medication, vaccines can have side effects. Serious reactions to routine shots are rare, but for the unlucky few who bear this burden, the government promises recourse through its administrative program. Vaccine court aims to strike a balance between protecting public health and helping individuals who may pay its price. The no-fault program allows claimants with vaccine-related injuries to get help without showing that the vaccine maker did anything wrong, even when the evidence doesn&#8217;t meet courtroom standards. The program has made more than 12,500 awards, totaling roughly $5 billion in compensation. Historically, nearly half of claims have been resolved with some kind of award. If patients aren&#8217;t satisfied with the outcome or don&#8217;t get a ruling within 240 days, they may leave the administrative program and sue the vaccine maker in civil court. Plaintiffs could potentially win larger awards. Lawyers could obtain higher fees, which they can&#8217;t in vaccine court. But winning a civil suit is far more difficult, in part because plaintiffs have a greater burden of showing the vaccine caused their injury and that the maker was at fault. Since the VICP was created, no vaccine injury lawsuit has won a judgment in regular court, records show. That hasn&#8217;t stopped some lawyers from trying. After the requisite 240 days, they have transferred hundreds of VICP claims into civil litigation against HPV vaccine manufacturer Merck, the KFF Health News analysis found. The lawyers who represented those claims include Downing and other VICP attorneys with ties to Kennedy, court records show. Those include Kennedy advisers and people who work in the law office of his longtime personal lawyer Aaron Siri or with Children&#8217;s Health Defense, the anti-vaccine outfit Kennedy founded, as well as a former Kennedy co-counsel in suits against Merck over its HPV vaccine, Gardasil. Downing, whose law firm biography describes him as &#8220;one of the preeminent litigation attorneys in the Court of Federal Claims,&#8221; has not won an HPV vaccine injury claim in the past five years, records show. Vaccine court did compensate dozens of HPV vaccine claims in that time, but most — including nearly all of Downing&#8217;s — were withdrawn upon reaching the opt-out period. VICP data and court records show that over the past five years, Downing and other lawyers withdrew roughly 400 Gardasil claims from vaccine court before a ruling was issued. The plaintiffs received nothing from the program. Hundreds of these cases joined the litigation against Merck, according to court records. Once the opt-out period arrived in Bostic&#8217;s case, Downing informed her that he was preparing to withdraw her son&#8217;s claim and move the case back to the original law firm for a lawsuit against Merck. &#8220;That,&#8221; he wrote in an email, &#8220;was the plan all along.&#8221; Fighting for Compensation Thomas, who hopes to enroll in community college and become a computer programmer, has intermittent numbness in his fingers and stabbing sensations in his arm nearly every day. The pain often radiates across his back or up his neck, and he&#8217;s developed migraines. Once an active kid who dreamed of playing basketball professionally, he now spends his time playing video games and trying to sleep during lulls in his pain. Bostic&#8217;s claim on behalf of her son made him one of about 1,000 people who have filed with vaccine court for HPV vaccine injuries. More than 200 have received compensation — just over one for every million shots given. Court records show program awards were typically $50,000 to $100,000, with some also covering past medical bills or future health care expenses. Richard Hughes IV, a health care attorney and former pharmaceutical executive who teaches vaccine law at George Washington University Law School, reviewed Thomas&#8217; records and said cases like his were exactly what the vaccine program was designed to address. &#8220;That just seems straightforward,&#8221; Hughes said of Thomas&#8217; claim. &#8220;That should have gotten compensated.&#8221; Bostic wanted the federal agencies that had approved and recommended Gardasil to answer for her son&#8217;s injuries. The single mother hoped compensation from the program would allow Thomas to see specialists including neurologists, afford natural treatments, and enroll in physical therapy. &#8220;He would have had the best of the best health care,&#8221; she said. When Downing took their case, Bostic said, he told her during a phone call that vaccine court&#8217;s $250,000 limit on pain and suffering was too low for her son&#8217;s injury. Bostic said Downing advised she could get more money by suing Merck, though that could take longer. &#8220;I said, ‘No, that will take years. My son needs help now,&#8217;&#8221; Bostic recalled. Bostic said she told Downing she wanted a fund set up for Thomas&#8217; health care as soon as possible. In the following weeks, Bostic sent paperwork to Downing&#8217;s office but had difficulty getting in touch with him, email and text messages show. Downing&#8217;s billing records show a gap in his work on the case from late September until mid-November. In November 2022, Downing emailed Bostic, &#8220;The opt out date for K.T.&#8217;s case is set for April 23, 2023. At that point, we will be in a position to opt K.T.&#8217;s case out of the Vaccine Program and move the case back over to the Carlson Law Firm for handling in the Merck litigation.&#8221; Bostic said she was confused at the time by that language. But she remembers being emphatic in a follow-up phone call with Downing, repeatedly telling him she would not opt out. After that, Bostic said, she didn&#8217;t hear from Downing for months despite calling his office and leaving messages with secretaries. Downing&#8217;s billing records show that he and his paralegals spent fewer than nine hours on Bostic&#8217;s case in that stretch. This included time spent requesting, reviewing, and filing medical records, as well as drafting and filing extension requests. The billing records did not include any communication with Bostic during that time. The court granted each of Downing&#8217;s extension requests, pushing back the deadline a month at a time. In April 2023, Downing sent Bostic an email noting that 240 days had passed, so he could drop their government claim and they could sue Merck. &#8220;Gardasil cases do not receive very fair treatment in the Vaccine Program,&#8221; Downing wrote, adding that he would withdraw as her attorney if Bostic stayed in the program. Bostic chose to stick with vaccine court, later telling the vaccine court judge by email that she&#8217;d advised her attorney &#8220;I was not trying to become a millionaire.&#8221; That exchange of emails in April is when Bostic said she learned Downing was already representing plaintiffs in lawsuits over Gardasil. The litigation encompassed hundreds of other patients who — most of them under Downing&#8217;s counsel — had filed VICP claims in recent years. Running out the 240-day clock, critics say, is allowed but subverts the program&#8217;s intent. Some legal experts criticize the way Downing handled Bostic&#8217;s case. &#8220;They trusted him to file the VICP case,&#8221; Reiss said. &#8220;It&#8217;s his job to zealously advocate for his clients. In this case, his clients want to go through VICP. It&#8217;s his job to fight for them in VICP, not to wait for 240 days.&#8221; When Downing joined HHS as a senior adviser to Kennedy, court records show, he handed off his remaining vaccine court cases to other attorneys in firms involved in the litigation against Merck. A New Approach The vaccine program has long faced criticism for giving claimants too little, too late. Even VICP advocates see the need for reform, with eight officials deciding a growing backlog of claims, driving up wait times. The cap on pain and suffering payments has not changed since 1986. But the court can award further compensation like a fund for lifetime medical care that can reach millions. Most vaccine-injured individuals are better off in the administrative program than in civil litigation, legal experts said. Ren&#233;e Gentry, director of GWU&#8217;s Vaccine Injury Litigation Clinic and a founding member of the Vaccine Injured Petitioners Bar Association, has represented hundreds of families alleging vaccine injuries. Most of them, she said, aren&#8217;t focused on big payouts; rather, they &#8220;want their kid taken care of or they want to be taken care of.&#8221; For claims that often fail in vaccine court, however, Gentry said a lawsuit may be the best option. According to Gentry, HPV vaccine claims like Thomas&#8217; are particularly challenging to win in the VICP. &#8220;If you&#8217;re not going to win, then you want those clients to have at least an opportunity at something,&#8221; she said. For Mark Sadaka, a prominent vaccine court lawyer representing some claims in Merck litigation, sending clients to regular court is a last resort. Sadaka said certain Gardasil injury claimants, such as those alleging mental rather than physical harm, might be better off in litigation. But by sticking it out in the VICP, Sadaka has won HPV vaccine injury claims that were the first of their kind, including for narcolepsy, alopecia, and even a deadly arrhythmia. &#8220;He&#8217;s going to get taken care of for the rest of his life,&#8221; Sadaka said of his client who won compensation for narcolepsy in 2023. &#8220;And he doesn&#8217;t have to pay me anything.&#8221; Sadaka, like all program lawyers, gets an hourly rate from the VICP. He said that he could make much more money representing the same claims in traditional litigation, since he could get a cut of any awards. &#8220;It&#8217;s a better thing for me to file in regular court and get a higher fee, but for the client, sometimes it makes sense, sometimes it doesn&#8217;t,&#8221; Sadaka said. &#8220;My role is to explain both sides in gross detail for them and give them as much information as possible so they can make an informed decision.&#8221; According to Sadaka, some lawyers in the VICP automatically advise their clients to leave vaccine court and file a lawsuit. &#8220;If they can extract settlements, they&#8217;re going to be very happy to put that money in their pockets,&#8221; Hughes noted. Winning a lawsuit or reaching a major settlement could also spell trouble for nationwide vaccine access, replaying the events that gave rise to vaccine court in the 1980s. Some vaccine lawyers and policymakers believe Kennedy and his colleagues might welcome a return to those days. &#8220;If they can bring down the system, that&#8217;s a feather in their cap,&#8221; Hughes said. Lawyers cannot win contingency fees in vaccine court. They get paid for time spent on reasonable claims whether they win or lose. Downing made more than $1 million representing clients before the VICP in recent years, according to court records. A January VICP report shows that since fiscal year 2020, the program has paid scores of attorneys about $280 million — including over $43 million for cases they did not win. In each of the last two fiscal years, lawyers got roughly $9 million for VICP claims in which their clients got nothing. That was more than the program had ever previously paid to attorneys for unsuccessful claims, according to vaccine court data. ‘Learning How To Cope&#8217; After discovering her attorney would not pursue VICP compensation for her son, Bostic decided to advocate for Thomas herself. &#8220;Please help me,&#8221; she wrote in a letter to the court. VICP staff gave Bostic extra time to find a new lawyer and gather records. The following months proved difficult for the family. Bostic was hospitalized with a life-threatening condition. Her mother&#8217;s health declined. She was laid off and lost her family&#8217;s health insurance. By the time Bostic could take Thomas to a pediatric neurologist to get medical records for his VICP case, she said, the doctor had moved hours away to Orlando. Bostic repeatedly missed deadlines and failed to communicate with program staff as required, court records show. Emails, docket entries, and letters suggest she may have misunderstood some court orders and not received others. When Thomas&#8217; medical records remained incomplete for another year, the presiding official dismissed Bostic&#8217;s claim, writing that while he had sympathy for what she and her son had endured, &#8220;the case cannot be allowed to remain pending indefinitely.&#8221; Thomas said he can no longer play basketball with friends. He can&#8217;t even help his mother carry groceries into the house. &#8220;I got to live with this, and there&#8217;s pain,&#8221; he said. Bostic now works from home as a bank fraud analyst. With an income just above the cutoff for government assistance, she puts in overtime in hopes of affording health insurance for Thomas and her six other children. &#8220;People are asking, ‘How&#8217;s your son doing?&#8217;&#8221; Bostic said. &#8220;I normally say, ‘Still the same. We just learning how to cope with it.&#8217;&#8221; Methodology The KFF Health News analysis began with court records for cases in the U.S. Court of Federal Claims, which includes vaccine court. We first identified all cases since 2006 (when the HPV vaccine was introduced) in which the &#8220;nature of suit&#8221; field explicitly mentioned human papillomavirus, or in which &#8220;nature of suit&#8221; was categorized as &#8220;other&#8221; vaccine injury/death and the case text included the word &#8220;papillomavirus.&#8221; The latter made up about 10% of identified cases, mostly claims filed before the HPV vaccine was added to the program or claims involving multiple vaccines. We cross-referenced the number of cases with data from VICP reports to verify completeness. After identifying the relevant vaccine court cases, we pulled these claims&#8217; filing and closing dates and took the difference to find the number of days that each case spent in vaccine court. To estimate total attorneys fees awarded for these claims, we added the fee amounts recorded in dozens of the VICP rulings and derived a minimum estimate based on the number of such cases. We then searched federal court records for litigation over Merck&#8217;s HPV vaccine, Gardasil, and pulled the names of the plaintiffs and attorneys involved. To gauge the scale of claims diverted from the VICP to litigation, we searched for each attorney in the Gardasil-related vaccine court cases and searched for the last name of each plaintiff in the titles of those cases. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/vicp-vaccine-court-cases-moved-lawsuits-lawyers-merck-hpv-rfk-allies-hhs/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/Vaccine_Lawyers_03-3840.jpg?w=1024', 'Maia Rosenfeld', '2026-01-29 10:00:00', '2026-01-29 13:36:34.514366', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["Vaccine Injury Compensation Program", "vaccine court", "Robert F. Kennedy Jr.", "vaccine lawsuits", "medical bills"]', '{"topics": ["vaccine injury", "legal disputes", "health policy", "patient compensation"], "summary": "برنامج تعويض إصابات اللقاحات الفيدرالي يواجه انتقادات بسبب تحويل بعض القضايا إلى دعاوى ضد شركات الأدوية. القضية تشمل طفلًا يعاني من إصابة طويلة الأمد بعد التطعيم، ولم يتم تعويضه حتى الآن.", "entities": ["Robert F. Kennedy Jr.", "Andrew Downing", "Melanie Bostic", "Health and Human Services"], "credibilityScore": 75}', '2026-01-29 13:36:34.514366', '2026-01-31 08:07:25.486');
INSERT INTO public.radar_items VALUES ('90063ad5-64b3-4eb9-b5f8-eff35cc7d608', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '32dbdd72ab889494e17ea021b4131bee', 'Low-Calorie, Fasting-Mimicking Diet May Benefit Those With Crohn''s Disease', 'حمية منخفضة السعرات تحاكي الصيام تخفف أعراض مرض كرون', 'A fasting-mimicking diet may help improve symptoms of Crohn’s disease. Image Credit: Lawren Lu/Stocksy A short-term calorie deficit may be beneficial for people with Crohn’s disease. Research suggests that a calorie deficit for five consecutive days out of every month for three consecutive months could improve symptoms and biological indicators of the disease. Experts say some people with Crohn’s disease would not benefit from such an approach due to risks like malnutrition, weight loss, and deh', 'بحث من ستانفورد يشير إلى أن حمية منخفضة السعرات تحاكي الصيام لمدة خمسة أيام شهرياً على مدى ثلاثة أشهر قد تحسن أعراض ومؤشرات الالتهاب لدى مرضى كرون، مع ضرورة الحذر من مخاطر سوء التغذية والجفاف.', 'A fasting-mimicking diet may help improve symptoms of Crohn&#8217;s disease. Image Credit: Lawren Lu/Stocksy A short-term calorie deficit may be beneficial for people with Crohn&#8217;s disease. Research suggests that a calorie deficit for five consecutive days out of every month for three consecutive months could improve symptoms and biological indicators of the disease. Experts say some people with Crohn&#8217;s disease would not benefit from such an approach due to risks like malnutrition, weight loss, and dehydration. A short term, calorie-restricted diet may provide significant improvement to physical symptoms for people with Crohn’s disease. Researchers from Stanford found that following a fasting-mimicking diet (FMD) also improved biological indicators of the disease. The results were published on January 13 in Nature Medicine. “We were very pleasantly surprised that the majority of patients seemed to benefit from this diet,” Sidhartha R. Sinha, MD, an assistant professor of gastroenterology and hepatology at Stanford and the senior author on the paper, said in a news release. “We noticed that even after just one FMD cycle, there were clinical benefits. We have been very limited in what kind of dietary information we can provide patients. This study will give physicians evidence to support recommendations in an area that patients are very curious about,&#8221; Sinha continued. Calorie-deficit improves Crohn&#8217;s symptoms The study involved 97 people living with mild to moderate Crohn’s disease from across the United States and examined both symptoms and biological indicators of the condition. The fasting mimicking group involved 65 study participants, while 32 were in a control group and followed their usual diet. Those in the fasting-mimicking group ate a significant calorie deficit for five consecutive days out of the month for three consecutive months. They consumed between 700 and 1,100 calories per day and were given plant-based meals. For the rest of the month, they continued to eat their usual diet. The researchers found that, at the conclusion of the three months, two-thirds of those in the fasting-mimicking group experienced an improvement in their symptoms. By comparison, at the end of the three months, less than half of those in the control group experienced an improvement in their symptoms. The researchers concluded that any improvement in this group was likely due to natural fluctuations of Crohn’s disease and following their standard care regimen. Fasting-mimicking improves gut inflammation Among those who followed the fasting-mimicking diet, there were also significant changes in biological indicators of disease. These were determined by samples of both stool and blood. “Our goal in collecting these and other biospecimens was to dig deeper into why there’s this differential response,” Sinha said. “Can we find mechanisms to explain the findings and signatures that might help predict patients who will respond to the diet?” They found that those who followed the fasting-mimicking diet had less calprotectin protein in their stool, indicating less gut inflammation. They also found that the immune cells of this group produced less of several different types of inflammatory molecules. Emeran Mayer, MD, PhD, a gastroenterologist at UCLA, who wasn&#8217;t involved in the study, said the results are interesting. “The study was done by a group of highly respected dietary experts and was well designed. Even though at first glance the results with the FMD seem surprising, there are multiple biological reasons to explain the benefit of the diet in this patient population,” he told Healthline. “It is remarkable, but it is also important to remember that the majority of patients had mild disease and that such patients can show placebo responses of up to 40%. The control group, without any dietary intervention, showed a response rate of 40%. As the diet group was not blinded to the diet change, it is plausible that part of the surprising effectiveness could be related to a placebo effect.” Mayer continued. Calorie deficit not always appropriate for Crohn&#8217;s In the United States, roughly 1 million people live with Crohn’s disease, a type of inflammatory bowel disease. The most common symptoms of Crohn’s disease include cramping, pain in the abdomen, diarrhea, and weight loss. There were no serious adverse events reported among the participants of the calorie restriction study. However, some in the fasting mimicking group reported headaches and fatigue. Experts say that while a calorie-restricted diet may be helpful for some living with Crohn’s disease, for others it would be inappropriate. “That&#8217;s a very low calorie intake, even if brief,&#8221; Rudolph Bedford, MD, board certified gastroenterologist at Providence Saint John’s Health Center in Santa Monica, CA, told Healthline. Bedford wasn&#8217;t involved in the study. &#8220;In selected well-nourished adults, it can be tolerable. But Crohn&#8217;s patients usually are a special population because of unintentional weight loss, nutrient deficiency, some of them are at risk of dehydration,” he said. “Safety depends on who&#8217;s doing it and how it&#8217;s supervised. So people who are already underweight, malnourished, pregnant, frail… have various eating disorders… diabetics, or they have frequent flares, are not really good candidates for this type of treatment. So I certainly would not self-prescribe this. It should be co-managed with a GI team and a dietitian with hydration guidance,&#8221; Bedford continued. Fasting may reduce inflammatory markers Prior research has shown that a fasting-mimicking diet in individuals with Crohn’s disease can reduce levels of a marker of systemic inflammation, known as C-reactive protein. “The effects seen on inflammatory markers made this an appealing diet to study in Crohn’s disease since many patients with this disease also have elevated inflammatory markers,” Sinha said. The study is the latest in a growing body of research examining the link between calorie restriction, fasting, and inflammation. “There have been studies and research showing that low calorie/fasting-mimicking days can decrease inflammation in the body, which is some of what they were looking at in this study too. So, if fasting mimicking/calorie reduction can aid in Crohn’s remission, it is definitely worth looking deeper into,” Dana Hunnes, PhD, senior dietitian at UCLA Health, told Healthline. Hunnes wasn&#8217;t involved in the study. “Over the last few years, this is an area of research that is burgeoning, and I look forward to seeing how much more we learn.” The researchers say they are now doing more work to determine whether changes to the gut microbiome may be part of the reason some people with Crohn’s disease see a benefit from a fasting mimicking diet. “There’s still a lot more to be done to understand the biology behind how this and other diets work in patients with Crohn’s disease,” Sinha said.', '<p>أظهرت دراسة جديدة أن اتباع <strong>حمية منخفضة السعرات تحاكي الصيام</strong> لفترات قصيرة قد يسهم في تحسين أعراض مرض كرون، مع تأثيرات ملحوظة على مؤشرات الالتهاب في الأمعاء. الدراسة التي قادها باحثون من جامعة ستانفورد ونُشرت في <strong>13 يناير بمجلة Nature Medicine</strong> تقدّم أدلة أولية على فائدة هذا النهج الغذائي لبعض المرضى.</p><p>شملت الدراسة 97 شخصاً مصاباً بمرض كرون بدرجة خفيفة إلى متوسطة من مختلف مناطق الولايات المتحدة، وقارنت بين مجموعة اتّبعت الحمية المحاكية للصيام وأخرى واصلت نظامها الغذائي المعتاد.</p><p><strong>تفاصيل الحمية والدراسة:</strong></p><ul><li>عدد المشاركين: 97 مصاباً بكرون (خفيف إلى متوسط)</li><li>مجموعة الحمية: 65 مشاركاً؛ مجموعة الضبط: 32 مشاركاً</li><li>السعرات اليومية: بين 700 و1100 سعرة حرارية لمدة خمسة أيام متتالية كل شهر</li><li>نوع الوجبات: نباتية خلال أيام الحمية</li><li>المدة الإجمالية: ثلاثة أشهر، مع العودة للنظام المعتاد بقية الشهر</li></ul><p>عند نهاية الأشهر الثلاثة، سجّل نحو <strong>ثلثي</strong> أفراد مجموعة الحمية تحسناً في الأعراض، مقابل أقل من <strong>النصف</strong> في مجموعة الضبط، وهو ما يرجّحه الباحثون بتقلّبات طبيعية في مسار المرض والالتزام بالرعاية القياسية. وقال سيدهارتا س. سينها، أستاذ مساعد أمراض الجهاز الهضمي والكبد في ستانفورد وكبير مؤلفي الدراسة: «فوجئنا بسرور بأن غالبية المرضى بدت عليهم استفادة من هذه الحمية، ولاحظنا فوائد سريرية حتى بعد دورة واحدة منها. هذه النتائج تمنح الأطباء أدلة تدعم التوصيات في مجال يثير فضول المرضى».</p><p>على المستوى البيولوجي، سجّل المشاركون الذين اتّبعوا الحمية انخفاضاً في <strong>بروتين الكالبروتكتين</strong> في البراز، وهو مؤشر على تراجع التهاب الأمعاء، كما أظهرت تحاليل الدم أن خلاياهم المناعية أنتجت كميات أقل من عدة جزيئات التهابية.</p><p>ورغم أن النتائج واعدة، يشير خبراء إلى ضرورة الحذر. يرى إميران ماير، اختصاصي أمراض الجهاز الهضمي في جامعة كاليفورنيا لوس أنجلوس (لم يشارك في الدراسة)، أن التصميم قوي والنتائج مثيرة للاهتمام، لكنه يلفت إلى أن معظم المشاركين كانوا بمرض خفيف، حيث يمكن أن تصل الاستجابات الوهمية إلى 40%، وأن المجموعة الضابطة حققت بالفعل نحو 40% تحسناً دون تدخل غذائي. كما أن عدم تعمية مجموعة الحمية قد يؤثر في تقارير الأعراض.</p><p>ويؤكد المختصون أن هذا النهج <strong>قد لا يناسب جميع مرضى كرون</strong>، خاصة المعرضين لمخاطر مثل سوء التغذية، فقدان الوزن، والجفاف. لذلك ينبغي مناقشة أي تغيير غذائي مع الطبيب، وأن يُنظر إلى الحمية المحاكية للصيام كخيار تكميلي محتمل ضمن خطة العلاج، مع الحاجة لمزيد من الدراسات لتحديد الفئات الأكثر استفادة والآثار طويلة المدى.</p>', 'https://www.healthline.com/health-news/fasting-mimicking-diet-improves-crohns-disease', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Crohns-Diet-Stocksy_txp8bc11ae6E7E400_Medium_6396304-Header.jpg', NULL, NULL, '2026-01-25 06:50:35.968378', 'en', 'health-news', NULL, 7, NULL, false, false, NULL, 'published', NULL, '2026-01-25 08:52:55.26', NULL, '["مرض كرون", "حمية تحاكي الصيام", "منخفضة السعرات", "التهاب الأمعاء", "الكالبروتكتين", "مؤشرات حيوية", "نظام نباتي", "ستانفورد"]', '{"topics": ["مرض كرون", "حمية تحاكي الصيام", "منخفضة السعرات", "التهاب الأمعاء", "الكالبروتكتين", "مؤشرات حيوية", "نظام نباتي", "ستانفورد"], "summary": "بحث من ستانفورد يشير إلى أن حمية منخفضة السعرات تحاكي الصيام لمدة خمسة أيام شهرياً على مدى ثلاثة أشهر قد تحسن أعراض ومؤشرات الالتهاب لدى مرضى كرون، مع ضرورة الحذر من مخاطر سوء التغذية والجفاف.", "entities": [], "seoTitle": "حمية منخفضة السعرات تحاكي الصيام تخفف أعراض كرون", "subtitle": "دراسة أمريكية ترصد تحسن الأعراض ومؤشرات الالتهاب", "seoDescription": "دراسة من ستانفورد: حمية تحاكي الصيام خمسة أيام شهرياً لثلاثة أشهر قد تقلل أعراض ومؤشرات الالتهاب لدى مرضى كرون، مع تحذيرات للمعرضين لسوء التغذية والجفاف.", "credibilityScore": 70}', '2026-01-25 06:50:35.968378', '2026-01-25 08:52:55.26');
INSERT INTO public.radar_items VALUES ('a6ce4b83-fcb5-435e-90d3-b8583c962ef5', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '8c2988a84002bb3528e736f01a1f50c6', 'Cervical Cancer Screening Guidelines Expand to Include Self-Swab HPV Test', 'إدراج الفحص الذاتي ضمن إرشادات سرطان عنق الرحم', 'New cervical cancer screening guidelines endorse self-collection methods for HPV testing for average-risk individuals in clinical settings. Svetlana Repnitskaya/Getty Images New federal guidelines announced updated cervical cancer screening guidelines to include self-collection methods for HPV testing for females ages 30 to 65 with an average risk. The American Cancer Society updated its guidelines in December to include self-collection of vaginal specimens for HPV testing in clinical settings f', 'تحديثات اتحادية وإرشادات الجمعية الأميركية للسرطان تعتمد الفحص الذاتي لفيروس HPV ضمن فحص سرطان عنق الرحم لتحسين الوصول وتقليص العوائق، مع فواصل متابعة أقصر وتشديد معايير إيقاف الفحص.', 'New cervical cancer screening guidelines endorse self-collection methods for HPV testing for average-risk individuals in clinical settings. Svetlana Repnitskaya/Getty Images New federal guidelines announced updated cervical cancer screening guidelines to include self-collection methods for HPV testing for females ages 30 to 65 with an average risk. The American Cancer Society updated its guidelines in December to include self-collection of vaginal specimens for HPV testing in clinical settings for females ages 25 to 65 with an average risk. Changes have also been made in the exit criteria for older females, and more stringent cancer screening is now required for females to cease testing. The Health Resources & Services Administration (HRSA), a department of the U.S. Department of Health and Human Services (HHS), announced updated guidance to its cervical cancer screening guidelines on January 5. The new guidelines include a recommendation that offers females ages 30 to 65 with an average risk the option to self-collect samples for testing. The current guidelines recommend screenings every 3 to 5 years for these age groups. Over 90% of cervical cancer cases are caused by the human papillomavirus (HPV), according to the U.S. Centers for Disease Control and Prevention (CDC). Almost all cases of the disease can be prevented by HPV vaccination. This update follows the recent update from the American Cancer Society (ACS) on its guidelines in December. ACS updated guidelines The American Cancer Society (ACS) updated its cervical cancer screening guidelines in December 2025 to endorse self-collected vaginal specimens for HPV testing, marking a major shift in U.S. screening practices. The guidelines were published in CA: A Cancer Journal for Clinicians, ACS&#8217;s flagship journal. The changes allow average-risk individuals ages 25 to 65 to collect their own samples in clinical settings — or, in limited cases, at home — using FDA-approved kits. The update aims to improve screening access and equity by removing barriers for underserved populations, while also revising exit criteria to require HPV testing at ages 60 and 65 to address persistently high cancer rates in people over 65. It followed recent Food and Drug Administration (FDA) approvals of several HPV tests and collection devices for use in clinical settings, as well as one option for at-home collection. Self-collection improves cervical cancer screening rates Historically, cervical cancer screening relied on clinician-collected samples obtained during a pelvic exam, either for a Pap smear alone, HPV testing, or a combination of both. While effective, this approach can be a barrier for those who face discomfort, limited access to care, or other obstacles to in-person screening. HPV testing using self-collected vaginal specimens has now been shown to have sensitivity and specificity comparable to clinician-collected samples when PCR-based assays are used. Multiple studies and meta-analyses reviewed by the ACS Guideline Development Group (GDG) found high agreement between the two methods, particularly for detecting high risk HPV types linked to cervical precancer. Under the new ACS guidance, average-risk individuals may self-collect vaginal specimens for HPV testing using FDA-approved kits. These widely available kits are currently designed for use within healthcare settings under the guidance of a primary care physician or gynecologist, according to the ACS guidelines. The only FDA-approved option for at-home self-collection is currently the Teal Wand, which has limited availability and is only offered through a proprietary telehealth service. If the result is negative, repeat screening is advised in three years, which is a shorter interval than the five years recommended for clinician-collected HPV tests. The ACS refers to this as a “margin of safety” while awaiting more long-term U.S. data on self-collection performance. Approved options include: Roche cobas HPV test with FLOQSwab or Evalyn Brush BD Onclarity HPV test with FLOQSwab Abbott Alinity m with Evalyn Brush or Qvintip swab Teal Wand for at-home use with the Roche cobas HPV test (through a proprietary telehealth service) Self-collection cannot replace clinician collection for certain higher-risk groups, however, such as those with HIV, immunosuppression, prior cervical cancer, or in utero exposure to diethylstilbestrol (DES). These patients require both HPV and cytology testing, and cytology cannot be performed on self-collected specimens. Clearer rules for cervical cancer screening The guideline update also addresses another long-standing issue: unclear and hard-to-implement criteria for exiting screening at age 65 and beyond. About one-quarter of cervical cancers in the U.S. occur in females over 65, with mortality twice that of younger females — a problem linked to inadequate screening in the years before stopping. Previously, the ACS advised ending screening at age 65 if an individual had a documented history of adequate negative tests in the prior 10 years. In practice, this proved difficult because medical records were often incomplete, leading to missed screenings. The new recommendation takes a forward-looking approach: average-risk individuals should have negative primary HPV tests (preferred) or negative co-tests at both ages 60 and 65 before stopping screening. If these are not available, three consecutive negative Pap tests at the recommended interval, with the last test administered at age 65, are also acceptable. For those using self-collected HPV testing, the three-year interval applies. Screening should continue past age 65 for anyone with certain risk factors, including HIV, immunosuppression, abnormal results in the past 10 years, cervical precancer in the past 25 years, or any history of cervical cancer. By adding self-collection as an evidence-based option and simplifying exit criteria, the ACS aims to make cervical cancer screening more flexible, accessible, and effective, while maintaining safety through clear follow-up protocols and risk-based decision making. What at-risk individuals need to know Ryan Kahn, MD, a gynecologic oncologist at Baptist Health Miami Cancer Institute, part of Baptist Health South Florida, said that those with an average risk for cervical cancer should begin screening at age 25 and continue until at least age 65. Kahn wasn&#8217;t affiliated with the ACS guidelines. After this, screening can be done every three to five years, depending on the test used. &#8220;Patients need to understand that they now have the option to collect their own vaginal specimen for HPV testing at home or in a clinical setting,&#8221; Kahn told Healthline, &#8220;but this requires more frequent screening than traditional clinician-collected samples.&#8221; Ryan added that while self-collection using FDA-approved devices and HPV assays is acceptable, clinician-collected cervical specimens are still preferred. &#8220;Additionally, patients should know that the criteria for stopping screening have changed — they now need negative HPV tests at both ages 60 and 65 years to safely exit screening, rather than the previous less stringent requirements,&#8221; he said. Improvements to care and access Jennifer Lincoln, MD, an author, women’s health advocate, and board certified OB-GYN, said that the ACS&#8217;s updates represent progress in cervical cancer screening, especially when it comes to reducing barriers to care. Lincoln wasn&#8217;t involved in the new guidelines. Speaking about the allowance for self-collected samples for HPV testing, she said, &#8220;This is significant because over 1 in 4 U.S. females are behind on screening, with 32% citing discomfort as a barrier.&#8221; Lincoln further noted that several groups of females, including those in rural areas, those without easy healthcare access, trauma survivors, and anyone who feels uncomfortable with speculum exams, can benefit from these changes. This is especially noteworthy, she added, because females in rural areas face higher cervical cancer mortality. &#8220;Multiple testing options also increase the likelihood that patients will actually get screened by meeting them where they are,&#8221; said Lincoln.', '<p><strong>خطوة لزيادة الوصول للفحص:</strong> أعلنت إدارة الموارد والخدمات الصحية الأميركية (HRSA) في 5 يناير تحديث إرشادات فحص سرطان عنق الرحم، لتتيح للنساء بين 30 و65 عامًا ممن لديهن خطر متوسط خيار جمع العينات ذاتيًا لفحص فيروس الورم الحليمي البشري (HPV) داخل العيادات. وتوصي الإرشادات الحالية بإجراء الفحص كل 3 إلى 5 سنوات لهذه الفئات العمرية.</p><p><strong>تحول كبير في ممارسة الفحص:</strong> كانت الجمعية الأميركية للسرطان (ACS) قد حدّثت إرشاداتها في ديسمبر 2025 لتدعم جمع عينات مهبلية ذاتيًا لفحص HPV، ونُشرت الإرشادات في مجلة "CA: A Cancer Journal for Clinicians". وتشمل التحديثات السماح للنساء بين 25 و65 عامًا بجمع العينات داخل المنشآت الصحية، وفي حالات محدودة من المنزل باستخدام مجموعات معتمدة من إدارة الغذاء والدواء الأميركية (FDA). وتستهدف هذه الخطوة تحسين الوصول والعدالة الصحية عبر إزالة العوائق أمام الفئات المحرومة، مع تعديل معايير إيقاف الفحص لتشترط إجراء اختبار HPV عند عمرَي 60 و65 قبل التوقف، نظرًا لاستمرار ارتفاع معدلات السرطان بعد 65 عامًا.</p><p><strong>فعالية الفحص الذاتي مثبتة:</strong> تاريخيًا، كان الفحص يعتمد على عينات يجمعها الطبيب أثناء الفحص الحوضي (لطاخة باب، أو اختبار HPV، أو كليهما)، وهو ما قد يعيق البعض بسبب الانزعاج أو صعوبة الوصول للرعاية. وتُظهر الأدلة أن اختبار HPV باستخدام عينات مهبلية تُجمع ذاتيًا يقدم حساسية ونوعية مماثلتين لعينات الطبيب عند استخدام اختبارات تعتمد على تفاعل البوليميراز المتسلسل (PCR)، مع اتفاق مرتفع خصوصًا في اكتشاف الأنماط عالية الخطورة المرتبطة بمقدمات سرطان عنق الرحم.</p><p><strong>تفاصيل التطبيق والفواصل الزمنية:</strong> وفق إرشادات ACS، تُستخدم مجموعات الجمع المعتمدة على نطاق واسع داخل المنشآت الصحية وتحت إشراف طبيب الرعاية الأولية أو طبيب النساء. أما الخيار الوحيد المعتمد حاليًا للجمع المنزلي فهو جهاز Teal Wand، ويُتاح بشكل محدود عبر خدمة طبّية افتراضية خاصة. وإذا جاءت نتيجة اختبار HPV سلبيّة بعد جمع ذاتي، يُنصح بإعادة الفحص بعد 3 سنوات، وهي فترة أقصر من فاصل الـ5 سنوات الموصى به لاختبارات HPV التي يجمعها الطبيب؛ وتُسمي ACS ذلك "هامش أمان" ريثما تتوفر بيانات أميركية طويلة الأمد عن أداء الجمع الذاتي. كما جاءت هذه التحديثات عقب موافقات FDA لعدة اختبارات HPV وأجهزة جمع للاستخدام في العيادات، إضافةً إلى خيار منزلي واحد.</p><p><strong>الوقاية أولوية:</strong> يشير مركز السيطرة على الأمراض الأميركي (CDC) إلى أن أكثر من 90% من حالات سرطان عنق الرحم تُعزى لفيروس HPV، وأن التطعيم ضد الفيروس يمكن أن يمنع تقريبًا جميع الحالات. لذا يبقى الجمع بين التطعيم والفحص الدوري وفق العمر ومستوى الخطر حجر الزاوية في خفض عبء المرض.</p><ul><li>الفئات المستهدفة: نساء بعمر 30–65 وفق إرشادات HRSA، و25–65 وفق إرشادات ACS للخطر المتوسط.</li><li>الخيار الجديد: جمع ذاتي للعينات المهبلية في العيادات؛ والمنزلي متاح بشكل محدود.</li><li>فواصل المتابعة: 3 سنوات لنتيجة HPV سلبية بجمع ذاتي، مقابل 5 سنوات لعينة يجمعها الطبيب.</li><li>معايير الإيقاف: تشديد الإرشادات بإجراء اختبار HPV عند 60 و65 عامًا قبل وقف الفحص.</li><li>الوقاية: التطعيم ضد HPV مع الفحص الدوري يقلل معظم الحالات.</li></ul>', 'https://www.healthline.com/health-news/new-cervical-cancer-screening-guidelines-endorse-self-collection-hpv', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Cervical-Cancer-GettyImages-2206082309-Header.jpg', NULL, NULL, '2026-01-25 06:50:39.791999', 'en', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["cervical cancer", "HPV testing", "self-swab", "screening guidelines", "American Cancer Society"]', '{"topics": ["cervical cancer prevention", "HPV testing methods", "health guidelines updates"], "summary": "تم تحديث إرشادات فحص سرطان عنق الرحم لتشمل إمكانية جمع العينات ذاتياً لاختبار فيروس الورم الحليمي البشري (HPV) للنساء بين 30 و65 عاماً. الهدف من التحديث هو تحسين الوصول إلى الفحوصات والوقاية من سرطان عنق الرحم.", "entities": ["American Cancer Society", "Health Resources & Services Administration", "U.S. Department of Health and Human Services", "Centers for Disease Control and Prevention"], "credibilityScore": 90}', '2026-01-25 06:50:39.791999', '2026-01-29 13:36:46.142');
INSERT INTO public.radar_items VALUES ('b917854f-1a51-4607-9057-088a600957da', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'e5c426c99c653592513bf85d206fd674', 'And Just Like That... Sarah Jessica Parker Realized Her Vision Was Changing', 'سارة جيسيكا باركر تواجه تشوش الرؤية القريبة بقطرات عين', 'Sarah Jessica Parker says she won’t let age-related blurry vision get in the way of her love for reading. Photography courtesy of Lenz Therapeutics Sarah Jessica Parker reveals how she is addressing age-related blurry vision. The “And Just Like That…” and “Sex and the City” star is raising awareness of age-related near-vision blur and how she copes. Parker shares that she’s putting down her reading glasses and opting for prescription eye drops. Iconic actress, producer, and fashion designer Sara', 'سارة جيسيكا باركر تستبدل نظارات القراءة بقطرات عين موصوفة لعلاج تشوش الرؤية القريبة، مع شرح طبي لأسباب قصور البصر الشيخي وأعراضه وخيارات العلاج.', 'Sarah Jessica Parker says she won&#8217;t let age-related blurry vision get in the way of her love for reading. Photography courtesy of Lenz Therapeutics Sarah Jessica Parker reveals how she is addressing age-related blurry vision. The &#8220;And Just Like That&#8230;&#8221; and &#8220;Sex and the City&#8221; star is raising awareness of age-related near-vision blur and how she copes. Parker shares that she&#8217;s putting down her reading glasses and opting for prescription eye drops. Iconic actress, producer, and fashion designer Sarah Jessica Parker was recently honored with the Carol Burnett Award from the Golden Globes. The award stacks next to the six Golden Globes she won for her work on &#8220;Sex and the City.&#8221; Aside from all her accolades, SJP is also known as an avid reader and lover of books. In 2025, Parker read 153 books as a Booker Award judge, and the 2026 documentary she executive-produced, called &#8220;The Librarians,&#8221; has been shortlisted by BAFTA for Best Documentary. Now, Parker is opening up about how her favorite hobby was affected by age-related near-vision blur, a loss of clear close-up vision that typically begins in your 40s. Also known as presbyopia, the condition develops when the eye loses its ability to change focus, making it hard to see close-up objects and text. Parker began noticing changes in her eyesight about 15 years ago. “I was in Ireland, and I was reading, and it occurred to me that it wasn’t pleasant. And my guess is that it had been happening for a bit,” Parker told Healthline. “[By] the time I stopped reading, I thought to myself, ‘Now, wait a minute, this is not the way it was.’ [My] eyes had been gently and politely trying to tell me for a little bit, hey, can you just help us out? We have been here for you for so long. Maybe you can now be here for us.” Parker relied on reading glasses for a while, but found herself always misplacing them and having to think about putting them on. “It’s just like a cliche. You think you’re above that. You think you’re better than that, but you’re not. And it just changes the way you can perform in a day. And some things are about pleasure, and some things are about necessity and need to be done,” she said. Age-related blurry vision is common Parker is among the 128 million Americans living with age-related near-vision blur. In fact, Randy McLaughlin, OD, associate professor of clinical ophthalmology at The Ohio State University Wexner Medical Center, said presbyopia is a normal, expected aging change. While it’s not preventable, he said, “In a few cases, an individual may have ‘natural mono vision’ where one eye is clear at distance, and the other is nearsighted and clear at near.” Common signs of age-related blurry near vision include: difficulty viewing things up close having to hold reading materials farther away to focus on them eyestrain or tiredness headache McLaughlin said presbyopia occurs when the crystalline lens, a variable-focusing ocular system, hardens over time with age. “The crystalline lens is what could eventually develop into cataract formation as we age,” McLaughlin told Healthline. “The lens ‘hardens’ throughout our life and hardens enough approximately between age 40 to 45, resulting in loss of near focusing vision. We then hold reading material further away.” Adults lose their ability to focus their vision starting around age 40, which may persist to around 60 years of age. A clear solution beyond reading glasses Reading glasses or multifocal spectacles are often the go-to for people experiencing age-related blurry near vision. That worked for a time for Parker, until she sought another solution. Now she uses a prescription for Vizz, a once-daily eye drop that treats blurry near vision for up to 10 hours. The drops work by making the pupil smaller, which improves the ability to focus on nearby objects without affecting distance vision. Parker heard about the drops but turned to her husband, Matthew Broderick, for his thoughts. “I asked him about it because he tends to know more and I [wasn’t] surprised to learn he’s been reading about this prior to me ever asking this question — he’s been researching it on his own,” Parker said. After their conversation, she visited her eye doctor to learn more. “[He] was really excited coincidentally, because he, too, had been hearing about this product, hearing about Vizz,” she said. “He gave me all the proper tests and asked all the right questions, and then, said, ‘Yeah, you’re a really good candidate.’” McLaughlin said drops like Vizz are best suited for people in the early stages of presbyopes. “Age 45-50 would be the better candidates,” he said. Common side effects of the eyedrop include irritation at the instillation site, blurred vision, and headache. For Parker, the eye drop has made reading enjoyable. The longer she&#8217;s used them, the more her vision has improved, she said. “You’re hyper vigilant the first day that you’re using it, you’re like constantly trying to find ways of challenging the product,” Parker said. “But the more you use it… in my experiences, is that your eye sort of adapts to this new relationship.” She recommended visiting your eye doctor to see if it’s right for you. To ensure healthy eyes as you age, McLaughlin said, have your eyes examined at least once a year to test the refractive state of your vision and ocular health, &#8220;ensuring there is no medical cause of any decrease in vision at distance or near.”', '<p>أكدت سارة جيسيكا باركر أنها لن تسمح لتشوش الرؤية القريبة المرتبط بالعمر بأن ينتزع منها متعة القراءة؛ إذ اختارت وضع نظارات القراءة جانباً والاعتماد على قطرات عين موصوفة طبياً، في إطار حملة توعية بهذه الحالة الشائعة.</p><p>النجمة التي حصدت جائزة كارول بورنيت من الغولدن غلوب إلى جانب ست جوائز غولدن غلوب عن «Sex and the City»، معروفة بنهمها للكتب؛ فقد قرأت 153 كتاباً عام 2025 بصفتها حكماً لجائزة بوكر، كما رُشح الوثائقي الذي أنتجته «The Librarians» عام 2026 لجائزة بافتا. لكنها تكشف أن هوايتها تأثرت عندما بدأت تُلاحظ منذ نحو 15 عاماً صعوبة مريحة في قراءة النصوص عن قرب، قائلة إن عينيها كانت «تطلب المساعدة بلطف».</p><p>طبياً، يُعرف هذا التشوش باسم <strong>قصور البصر الشيخي</strong>، وهو فقدان تدريجي لقدرة العين على تركيز الرؤية القريبة يبدأ عادة بين سن الأربعين والخامسة والأربعين ويستمر حتى ستينيات العمر. يوضح راندي ماكلوغلين، أستاذ مساعد في طب العيون السريري بمركز ويكسنر في جامعة ولاية أوهايو، أن السبب هو تَصَلُّب عدسة العين البلورية مع التقدم في السن؛ وهي العدسة نفسها التي قد تتطور لاحقاً إلى إعتام عدسة (ماء أبيض). ويضيف أن الحالة غير قابلة للوقاية، وإن كان بعض الأشخاص يمتلكون «رؤية أحادية طبيعية» تجعل عيناً أكثر وضوحاً للقريب وأخرى للبعيد.</p><p>وتشمل العلامات الشائعة لتشوش الرؤية القريبة المرتبط بالعمر:</p><ul><li>صعوبة رؤية الأشياء القريبة بوضوح</li><li>الحاجة لإبعاد مواد القراءة عن العين للتركيز</li><li>إجهاد العين أو الإحساس بالتعب</li><li>الصداع بعد القراءة أو العمل القريب</li></ul><p>وغالباً ما تكون نظارات القراءة أو العدسات متعددة البؤر الحلّ الأول. غير أن باركر لجأت مؤخراً إلى وصفة لقطرات يومية تُعرف باسم Vizz، تمنح وضوحاً أفضل للرؤية القريبة لمدة تصل إلى 10 ساعات عبر <strong>تضييق حدقة العين</strong> لتحسين القدرة على التركيز على الأجسام القريبة دون التأثير في رؤية البعيد. وينبغي استخدام هذه القطرات وغيرها من الخيارات الدوائية تحت إشراف طبيب العيون؛ كما قد تختلف توافُر العلاجات بين البلدان.</p><p>بحسب التقديرات، فإن نحو 128 مليون شخص في الولايات المتحدة يعيشون مع تشوش الرؤية القريبة المرتبط بالعمر، ما يؤكد شيوع الحالة والحاجة للتوعية بخيارات العلاج المتاحة.</p>', 'https://www.healthline.com/health-news/sarah-jessica-parker-talks-age-related-blurry-vision-treatment', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Sarah-Jessica-Parker-1296x728-header.jpg', NULL, NULL, '2026-01-26 06:17:50.297858', 'en', 'health-news', NULL, 6, NULL, false, false, NULL, 'published', NULL, '2026-01-26 06:22:51.445', NULL, '["سارة جيسيكا باركر", "قصور البصر الشيخي", "تشوش الرؤية القريبة", "قطرات عين وصفية", "نظارات القراءة", "عدسة العين البلورية", "الشيخوخة والبصر", "علاج ضعف النظر القريب"]', '{"topics": ["سارة جيسيكا باركر", "قصور البصر الشيخي", "تشوش الرؤية القريبة", "قطرات عين وصفية", "نظارات القراءة", "عدسة العين البلورية", "الشيخوخة والبصر", "علاج ضعف النظر القريب"], "summary": "سارة جيسيكا باركر تستبدل نظارات القراءة بقطرات عين موصوفة لعلاج تشوش الرؤية القريبة، مع شرح طبي لأسباب قصور البصر الشيخي وأعراضه وخيارات العلاج.", "entities": [], "seoTitle": "سارة جيسيكا باركر تكشف علاج تشوش الرؤية القريبة بوصفة طبية", "subtitle": "تسلّط الضوء على قصور البصر الشيخي وخيارات العلاج", "seoDescription": "سارة جيسيكا باركر تتحدث عن قصور البصر الشيخي وتستبدل نظارات القراءة بقطرات عين موصوفة تعمل حتى 10 ساعات. تعرف على الأعراض والأسباب وخيارات العلاج المتاحة.", "credibilityScore": 60}', '2026-01-26 06:17:50.297858', '2026-01-26 06:22:51.445');
INSERT INTO public.radar_items VALUES ('3570a569-23d2-42c0-b2fd-596c5b536bf7', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '1177b2d93efaaf1e474967d3a438626c', 'Most People Aren''t Getting Enough Omega-3: What Are the Health Impacts?', NULL, 'According to research, most people may not be getting enough omega-3 fatty acids in their diet. Image Credit: Tanja Ivanova/Getty Images A new research review reports that most people do not consume the recommended amounts of omega-3 fatty acids. These acids are considered beneficial for brain, skin, and heart health. Experts say it’s preferable for a person to obtain omega-3s through foods, but supplements can be considered if a person’s diet doesn’t contain enough fatty acids. The majority of ', NULL, 'According to research, most people may not be getting enough omega-3 fatty acids in their diet. Image Credit: Tanja Ivanova/Getty Images A new research review reports that most people do not consume the recommended amounts of omega-3 fatty acids. These acids are considered beneficial for brain, skin, and heart health. Experts say it’s preferable for a person to obtain omega-3s through foods, but supplements can be considered if a person’s diet doesn’t contain enough fatty acids. The majority of people worldwide are not consuming a sufficient amount of omega-3 fatty acids, according to new research. Researchers report that 76% of the global population is not consuming the daily recommended levels of omega-3 fatty acids, specifically eicosapentaenoic acid (EPA) and docosahexaenoic acid (DHA). They said the health benefits from these fatty acids are “too important to ignore.” They recommend that health officials develop official policies on omega-3 consumption and advise the public on how to best obtain these fatty acids through diet, as well as through supplements such as fish oil. “We hope this work will help inform nutritional scientists, clinicians, food and supplement industries, policy makers, and consumer communities,” said Anne-Marie Minihane, a nutrigenomics professor at the Norwich Medical School at the University of East Anglia in England, in a statement. The researchers emphasized that the health benefits of omega-3 fatty acids are important at every stage of life, particularly for pregnant individuals, infants, and young children. The researchers reached their conclusions after reviewing the recommended daily levels of omega-3 fatty acids in over 100 countries. They noted that the recommendations vary significantly from country to country, creating confusion among the public and highlighting the importance of consistent, evidence-based guidance. They reported that the most frequently recommended intake for adults is 250 mg per day of combined EPA and DHA, with an additional 100 to 200 mg of DHA advised for pregnant people. They said these levels can be achieved by eating more oily fish, such as salmon or mackerel, or through supplementation where needed. The researchers recently shared their findings in Nutrition Research Reviews, a publication of Cambridge University Press. The authors also acknowledged they have ties to companies such as Holland & Barrett that are involved in the supplement industry. Experts not involved in the research said the review sheds light on an important issue. “It highlights the inconsistencies in how much fatty acid intake is necessary,” said Cheng-Han Chen, MD, an interventional cardiologist and medical director of the Structural Heart Program at MemorialCare Saddleback Medical Center in Laguna Hills, CA. “The overall message is clear that people should incorporate fatty acids in their diet,” Chen told Healthline. “It’s a good overview of some of the challenges with getting enough omega 3s through diet alone as well as a look into how various age groups are doing with getting enough omega 3s, recommendations for amount, and unique deficiency risk factors based on age,” added Kristin Kirkpatrick, RD, the president of KAK Consulting as well as a dietitian at the Cleveland Clinic Department of Wellness & Preventive Medicine in Ohio. Health benefits from omega-3 fatty acids Omega-3s are a family of essential fatty acids. In addition to EPA and DHA types, there is also alpha-linolenic acid (ALA). These acids are not produced by the human body, so they must be absorbed through diet or supplementation. David Cutler, MD, a family medicine physician at Providence Saint John’s Health Center in Santa Monica, California, explains that fats, such as omega-3s, are important because they help our bodies absorb other fat-soluble nutrients, including vitamins A, E, D, and K. Cutler wasn&#8217;t involved in the new review. Omega-3s, in particular the DHA type, are considered essential for brain, skin, and eye health. Research has been mixed on what other health benefits are provided by adequate levels of omega-3 fatty acids. However, past research has reported that these fatty acids can improve heart health by lowering triglyceride levels and increasing HDL, or “good cholesterol,” levels. “The benefits of these omega-3 fatty acids are mostly attributed to lowering triglyceride levels in the bloodstream,” Cutler told Healthline. “This is important if you have abnormally high triglycerides and probably not so important if your triglyceride levels are normal.” There has been other research that reported that omega-3 fatty acids may help improve blood sugar levels and lower inflammation. Experts say omega-3s are particularly important for pregnant and nursing women as these fatty acids are vital for the brain health of fetuses as well as infants. “Fatty acids are important,” Chen said. “In particular, they’re important for infant health.” “In pregnancy, [omega-3] deficiency may have an impact on overall cognitive and neurological health of the baby,” added Kilpatrick. Chen adds that omega-3s may be more important for older adults simply because they are at higher risk of some of the health problems that fatty acids can help prevent. “They’re susceptible to the same issues as people with omega-3 deficiencies,” he said. There are some symptoms that indicate a low level of omega-3 fatty acids in the body. They include: skin irritation and dryness dry eyes joint pain changes in hair texture Omega-3 fatty acids: Diet vs. supplements Health and nutrition experts agree that the most effective way to absorb omega-3 fatty acids is through a balanced diet. Some foods that contain omega-3 acids are: fatty fish (i.e., salmon, herring, oysters) fish oils (i.e., cod liver oil) flax seeds chia seeds flaxseed oil soybeans walnuts The American Heart Association (AHA) recommends two servings of fatty fish per week. Those who are unable to consume sufficient omega-3 acids through their diet may wish to consider omega-3 supplements that include fish oil and algal oil. Cutler offered a word of caution about fish oil capsules. He noted that supplements are not regulated by government agencies like medications and other products. He also said there can be side effects such as nausea and diarrhea. Additionally, fish oil supplements may increase the risk of bleeding. He noted that it&#8217;s particularly important for anyone taking blood-thinning medications. “Any benefits to omega-3 supplements should be weighed against potential side effects and risks,” Cutler said. Chen doesn’t generally recommend supplements to boost omega-3 counts. He says the research doesn’t support the notion that supplements effectively boost fatty acid levels. “In general, the recommendation is to get fatty acids through diet,” Chen said. “All supplements affect is your wallet.” How to know if you&#8217;re getting enough omega-3 The total recommended daily allotment of omega-3 fatty acids for adults in the United States for females is 1,100 milligrams (mg). For males, the recommended dosage is 1,600 mg. During pregnancy, it’s recommended a person absorb an extra 300 mg combined EPA and DHA per day. The recommendation for infants is 500 mg per day. This can be gradually increased annually until age 14, when an adult dosage is recommended. What dosage of supplement you take will depend on how much omega-3 fatty acids you consume in your regular diet. While some experts may not recommend supplements for fatty acids, Kilpatrick told Healthline: “Due to low intake of fatty fish consumption, as well as high intake of omega-6 fats, supplementation is often warranted in most populations.” However, she noted that there are several factors to consider. They include: Is the supplement truly needed given a person’s diet, risk factors, and health goals? Is supplementation safe for this particular individual? What dosage is needed, given a person’s circulatory levels? What type of supplement works best for this individual? Can the person’s diet be changed to increase omega-3 levels?', NULL, 'https://www.healthline.com/health-news/omega-3-deficiency-health-impacts', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/omega-3-pills-table-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:39.669963', 'en', 'health-news', 'nutrition', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["omega-3", "fatty acids", "diet", "health benefits", "EPA", "DHA", "supplements"]', '{"topics": ["omega-3 deficiency", "dietary recommendations", "health policy", "nutrition science"], "summary": "بحث جديد يكشف أن 76% من سكان العالم لا يستهلكون الكميات الموصى بها يومياً من أحماض أوميغا-3 الدهنية، المهمة لصحة الدماغ والقلب والجلد. ينصح الخبراء بالحصول على هذه الأحماض من الطعام أو المكملات الغذائية عند الحاجة، مع الدعوة لوضع سياسات غذائية واضحة لتعزيز استهلاكها.", "entities": ["Anne-Marie Minihane", "University of East Anglia", "global population"], "credibilityScore": 90}', '2026-01-25 06:50:39.669963', '2026-01-29 13:36:50.718');
INSERT INTO public.radar_items VALUES ('62ec7f16-5855-4505-bb77-f30fc19b7a28', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '22b16e8b2018d95cac38e3fe2a271771', 'Why Medication Abortion Is the Top Target for Anti-Abortion Groups in 2026', NULL, 'With abortions still on the rise nationwide despite widespread bans, curtailing the use of pregnancy-terminating medication is a top priority for abortion opponents — and they’re frustrated that the Trump administration isn’t doing more to limit its use.', NULL, 'This week would have marked the 53rd anniversary of Roe v. Wade, the 1973 Supreme Court decision that legalized abortion nationwide — that is, until 2022, when the court overturned it. Since then, abortion has been banned in 13 states and severely limited in 10 others. Yet anti-abortion activists remain frustrated, in some cases even more so than before Roe was overturned. Why? Because despite the new legal restrictions, abortions have not stopped taking place, not even in states with complete bans. In fact, the number of abortions has not dropped at all, according to the latest statistics. &#8220;Indeed, abortions have tragically increased in Louisiana and other pro-life states,&#8221; Liz Murrill, Louisiana&#8217;s attorney general, said at a Senate Health, Education, Labor, and Pensions Committee hearing this month. That&#8217;s due in large part to the easier availability of medication abortion, which uses a combination of the drugs mifepristone and misoprostol, and particularly to the pills&#8217; availability via mail after a telehealth visit with a licensed health professional. Allowing telehealth access was a major change originally made on a temporary basis during the covid pandemic, when visits to a doctor&#8217;s office were largely unavailable. Before that, unlike most medications, mifepristone could be dispensed only directly, and only by a medical professional individually certified by the Food and Drug Administration. The Biden administration later permanently eliminated the requirement for an in-person visit — a change the second Trump administration has not undone. While the percentage of abortions using medication had been growing every year since 2000, when the FDA first approved mifepristone for pregnancy termination, the Biden administration&#8217;s decision to drop the in-person dispensing requirement supercharged its use. More than 60% of all abortions were done using medication rather than a procedure in 2023, the most recent year for which statistics are available. More than a quarter of all abortions that year were managed via telehealth. Separately, President Donald Trump&#8217;s FDA in October approved a second generic version of mifepristone, angering abortion opponents. FDA officials said at the time that they had no choice — that as long as the original drug remains approved, federal law requires them to OK copies that are &#8220;bioequivalent&#8221; to the approved drug. It&#8217;s clear that reining in, if not canceling, the approval of pregnancy-terminating medication is a top priority for abortion opponents. This month, Susan B. Anthony Pro-Life America called abortion drugs &#8220;America&#8217;s New Public Health Crisis,&#8221; referencing their growing use in ending pregnancies as well as claims of safety concerns — such as the risk a woman could be given the drugs unknowingly or suffer serious complications. Decades of research and experience show medication abortion is safe and complications are rare. Another group, Students for Life, has been trying to make the case that the biological waste from the use of mifepristone is contaminating the nation&#8217;s water supply, though environmental scientists refute that claim. Yet the groups are most frustrated not with supporters of abortion rights but with the Trump administration. The object of most of their ire is the FDA, which they say is dragging its feet on a promised review of the abortion pill and the Biden administration&#8217;s loosened requirements around its availability. President Joe Biden&#8217;s covid-era policy allowing abortion drugs to be sent via mail &#8221;should&#8217;ve been rescinded on day one of the administration,&#8221; SBA Pro-Life America&#8217;s president, Marjorie Dannenfelser, said in a recent statement. Instead, almost a year later, she continued, &#8220;pro-life states are being completely undermined in their ability to enforce the laws that they passed.&#8221; Lawmakers who oppose abortion access are also pressing the administration. &#8220;At an absolute minimum, the previous in-person safeguards must be restored immediately,&#8221; Senate HELP Committee Chairman Bill Cassidy said during the hearing with Murrill and other witnesses who want to see abortion pill availability curtailed. Sen. Jim Banks (R-Ind.) said at the hearing that he hoped &#8220;the rumors are false&#8221; that &#8220;the agency is intentionally slow-walking its study on mifepristone&#8217;s health risks.&#8221; The White House and spokespeople at the Department of Health and Human Services have denied the review is being purposely delayed. &#8220;The FDA&#8217;s scientific review process is thorough and takes the time necessary to ensure decisions are grounded in gold-standard science,&#8221; HHS spokesperson Emily Hilliard said in an emailed response to KFF Health News. &#8220;Dr. Makary is upholding that standard as part of the Department&#8217;s commitment to rigorous, evidence-based review.&#8221; That&#8217;s a reference to Marty Makary, the FDA commissioner. Revoking abortion pill access may not be as easy as advocates hoped when Trump moved back into the White House. While the president delivered on many of the goals of his anti-abortion backers during his first term, especially the confirmation of Supreme Court justices who made overturning Roe possible, he has been far less doctrinaire in his second go-round. Earlier this month, Trump unnerved some of his supporters by advising House Republicans that lawmakers &#8220;have to be a little flexible&#8221; on the Hyde Amendment to appeal to voters, referring to a decades-old appropriations rule that bans most federal abortion funding and that some Republicans have been pushing to enforce more broadly. And while the anniversary of Trump&#8217;s inauguration has many analysts noting how much of the Heritage Foundation&#8217;s Project 2025 blueprint has been realized, the most headline-grabbing portions on reproductive health have yet to be enacted. The Trump administration has not, for example, revoked the approval of mifepristone for pregnancy termination, nor has it invoked the 1873 Comstock Act, which could effectively ban abortion nationwide by stopping not just the mailing of abortion pills but also anything else used in providing abortions. Still, abortion opponents have decades of practice at remaining hopeful — and playing a long game. HealthBent, a regular feature of KFF Health News, offers insight into and analysis of policies and politics from KFF Health News chief Washington correspondent Julie Rovner, who has covered health care for more than 30 years. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/mifepristone-medication-abortion-pill-trump-fda/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/Rovner-HealthBent_2026.jpg?w=1024', 'Julie Rovner, KFF Health News', '2026-01-23 10:00:00', '2026-01-25 06:50:40.668567', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["medication abortion", "anti-abortion groups", "mifepristone", "misoprostol", "telehealth"]', '{"topics": ["abortion laws", "medication access", "reproductive health", "telehealth services"], "summary": "تناقش المقالة استهداف مجموعات مناهضة للإجهاض لاستخدام الأدوية المخصصة للإجهاض كأولوية رئيسية، خاصة مع تزايد استخدامها عبر خدمات التطبيب عن بعد. يشير التقرير إلى تأثير التغييرات في القوانين والسياسات على توفر هذه الأدوية وزيادة نسب الإجهاض باستخدامها.", "entities": ["Liz Murrill", "Biden administration", "Trump administration", "FDA"], "credibilityScore": 80}', '2026-01-25 06:50:40.668567', '2026-01-29 13:36:15.655');
INSERT INTO public.radar_items VALUES ('aa1733cd-936a-4fb0-b1b2-1db8acce333c', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '123eb02b5aca1f882103f811ad4d9969', 'Estados Unidos podría perder su estatus de país libre de sarampión', NULL, 'Esto marca un cambio importante desde que Estados Unidos eliminara el sarampión en el año 2000. Hasta ahora, el virus aparecía de manera esporádica, con personas infectadas en el extranjero, pero rara vez provocaba brotes locales debido a las altas tasas de vacunación.', NULL, 'Luego de un a&#241;o de brotes continuos de sarampi&#243;n que han enfermado a m&#225;s de 2.400 personas, Estados Unidos est&#225; a punto de perder su estatus como pa&#237;s libre de sarampi&#243;n. Sin embargo, el reci&#233;n nombrado subdirector principal de los Centros para el Control y la Prevenci&#243;n de Enfermedades (CDC, por sus siglas en ingl&#233;s), Ralph Abraham, no se mostr&#243; preocupado por esa posibilidad durante una reciente rueda de prensa. &#8220;Es simplemente el costo de hacer negocios en un pa&#237;s con fronteras algo porosas debido a los viajes globales e internacionales&#8221;, dijo Abraham. &#8220;Tenemos comunidades que eligen no vacunarse. Esa es su libertad personal&#8221;. Pero las infecciones provenientes de otros pa&#237;ses representaron solo alrededor del 10% de los casos de sarampi&#243;n detectados desde el 20 de enero de 2025, fecha oficial del inicio del brote mortal en el oeste de Texas que luego se propag&#243; a otros estados y a M&#233;xico. El resto de los casos se adquirieron dentro del pa&#237;s. Esto marca un cambio importante desde que Estados Unidos eliminara el sarampi&#243;n en el a&#241;o 2000. Hasta ahora, el virus aparec&#237;a de manera espor&#225;dica, con personas infectadas en el extranjero, pero rara vez provocaba brotes locales debido a las altas tasas de vacunaci&#243;n. Dos dosis de la vacuna contra el sarampi&#243;n, las paperas y la rub&#233;ola previenen fuertemente la infecci&#243;n y detienen la propagaci&#243;n del virus. Para mantener su estatus de pa&#237;s libre de sarampi&#243;n, el pa&#237;s debe demostrar que el virus no ha circulado de manera continua en sus territorios durante un a&#241;o, entre el 20 de enero de 2025 y el 20 de enero de 2026. Para responder a esa pregunta, los cient&#237;ficos est&#225;n investigando si los principales brotes en Carolina del Sur, Utah, Arizona y Texas est&#225;n relacionados entre s&#237;. Funcionarios de salud confirmaron que la cepa principal del virus del sarampi&#243;n en cada uno de estos brotes es la D8-9171. Pero dado que esta cepa tambi&#233;n circula en Canad&#225; y M&#233;xico, los cient&#237;ficos de los CDC ahora est&#225;n analizando los genomas completos de los virus del sarampi&#243;n —de aproximadamente 16.000 &#8220;letras&#8221; gen&#233;ticas— para determinar si los detectados en Estados Unidos est&#225;n m&#225;s relacionados entre s&#237; que con los de otros pa&#237;ses. Se espera que los CDC completen estos estudios en un par de meses y publiquen los datos. Luego, la Organizaci&#243;n Panamericana de la Salud (OPS), que supervisa a las Am&#233;ricas como parte de la Organizaci&#243;n Mundial de la Salud, decidir&#225; si Estados Unidos pierde su estatus como pa&#237;s libre de sarampi&#243;n. Esto implicar&#237;a que los brotes —costosos, potencialmente mortales y totalmente prevenibles— podr&#237;an volverse algo com&#250;n nuevamente. &#8220;Cuando escuchas a alguien como Abraham decir que es ‘el costo de hacer negocios&#8217;, ¿c&#243;mo se puede ser tan insensible?&#8221;, dijo el doctor Paul Offit, pediatra y especialista en vacunas, durante una charla en l&#237;nea organizada por el blog de salud Inside Medicine el 20 de enero. &#8220;Tres personas murieron de sarampi&#243;n el a&#241;o pasado en este pa&#237;s&#8221;, agreg&#243; Offit. &#8220;Eliminamos este virus en el a&#241;o 2000 —lo eliminamos de verdad. Eliminamos la circulaci&#243;n de la infecci&#243;n humana m&#225;s contagiosa. Eso era algo para sentirse orgulloso&#8221;. Abraham afirm&#243; que la vacunaci&#243;n sigue siendo la forma m&#225;s eficaz de prevenir el sarampi&#243;n, pero insisti&#243; en que los padres deben tener la libertad de decidir si vacunan a sus hijos. Desde 2020, varios estados han flexibilizado los requisitos de vacunaci&#243;n escolar y las tasas de vacunaci&#243;n han disminuido. Una cifra r&#233;cord de ni&#241;os de jard&#237;n de infantes —alrededor de 138.000— obtuvo exenciones a la vacuna para el ciclo escolar 2024-25. La informaci&#243;n sobre las vacunas se ha vuelto confusa por el secretario de Salud y Servicios Humanos (HSS, por sus siglas en ingl&#233;s), Robert F. Kennedy Jr., quien antes de ser funcionario fund&#243; una organizaci&#243;n antivacunas. Durante todo su mandato, Kennedy ha puesto en duda los beneficios de las vacunas. En televisi&#243;n nacional, ha repetido rumores ya desmentidos por la ciencia, como que las vacunas pueden causar autismo, inflamaci&#243;n del cerebro y hasta la muerte. Jennifer Nuzzo, directora del Centro de Pandemias de la Universidad Brown, critic&#243; que la administraci&#243;n Trump se enfoque en encontrar tecnicismos gen&#233;ticos que podr&#237;an permitir al pa&#237;s conservar su estatus de libre de sarampi&#243;n. &#8220;Esto es en lo que menos deber&#237;amos estar mirando. Nuestra atenci&#243;n debe enfocarse en frenar los brotes&#8221;, afirm&#243;. &#8220;Si mantenemos el estatus, debe ser porque hemos detenido la propagaci&#243;n del sarampi&#243;n&#8221;, agreg&#243;. &#8220;Es como si estuvieran pidiendo que los eval&#250;en con menos exigencias&#8221;. Seg&#250;n investigaciones de KFF Health News, el gobierno de Trump obstaculiz&#243; la capacidad de los CDC para ayudar al oeste de Texas durante las primeras semanas cr&#237;ticas del brote y retras&#243; la entrega de fondos federales de emergencia. Sin embargo, la agencia intensific&#243; su actividad el a&#241;o pasado, proporcionando vacunas contra el sarampi&#243;n, materiales informativos y pruebas de laboratorio a los departamentos de salud locales. Abraham inform&#243; que el HHS otorgar&#225; $1,5 millones a Carolina del Sur para responder a su brote, que comenz&#243; hace casi cuatro meses y para el 20 de enero ya hab&#237;a alcanzado los 646 casos. Si los an&#225;lisis gen&#243;micos de los CDC demuestran que los brotes del a&#241;o pasado fueron causados por distintos casos importados desde el extranjero, es probable que los funcionarios pol&#237;ticos atribuyan a Kennedy el m&#233;rito de haber salvado el estatus del pa&#237;s, seg&#250;n Demetre Daskalakis, ex director del centro nacional de inmunizaci&#243;n de los CDC, quien renunci&#243; en agosto en protesta por las acciones de Kennedy. Y si los estudios sugieren que los brotes est&#225;n relacionados entre s&#237;, Daskalakis predijo que la administraci&#243;n pondr&#225; en duda los hallazgos y minimizar&#225; la p&#233;rdida del estatus del pa&#237;s: &#8220;Dir&#225;n que no importa&#8221;. De hecho, durante la rueda de prensa, Abraham le dijo a un reportero de Stat que la p&#233;rdida de la condici&#243;n de pa&#237;s libre de sarampi&#243;n no ser&#237;a algo significativo: &#8220;Perder ese estatus no significa que el sarampi&#243;n se vaya a propagar ampliamente&#8221;. Los datos muestran lo contrario. El n&#250;mero de casos el a&#241;o pasado fue el m&#225;s alto desde 1991, antes de que el gobierno implementara pol&#237;ticas de vacunaci&#243;n para garantizar que todos los ni&#241;os estuvieran protegidos contra el sarampi&#243;n. Lauren Sausser colabor&#243; con este art&#237;culo. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/estados-unidos-podria-perder-su-estatus-de-pais-libre-de-sarampion/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2201702057.jpg?w=1024', 'Amy Maxmen', '2026-01-23 20:46:03', '2026-01-25 06:50:40.422652', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["الولايات المتحدة", "الحصبة", "التطعيم", "مراكز السيطرة على الأمراض", "تفشي الأمراض"]', '{"topics": ["تفشي الحصبة", "التطعيمات", "الصحة العامة", "الأمراض المعدية"], "summary": "الولايات المتحدة تواجه خطر فقدان وضعها كدولة خالية من الحصبة بعد تفشي مستمر للفيروس منذ عام 2025. يعود ذلك إلى انخفاض معدلات التطعيم وانتشار العدوى محلياً ودولياً.", "entities": ["الولايات المتحدة", "مراكز السيطرة على الأمراض (CDC)", "Ralph Abraham"], "credibilityScore": 90}', '2026-01-25 06:50:40.422652', '2026-01-29 13:36:26.761');
INSERT INTO public.radar_items VALUES ('a99bc670-6001-4ab9-8b10-7bf560f8d683', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'be3f6e2bdaae5322764e6100143c65ab', '''Beer Belly'' Linked to Higher Risk of Heart Damage, Especially in Men', NULL, 'A new study found that a “beer belly” may be linked to harmful changes in the heart structure, especially in men. Image Credit: master1305/Getty Images A new study found that abdominal fat, or a “beer belly,” may be linked to harmful changes in heart structure, particularly in males. The researchers say that a high waist-to-hip ratio may be associated with more concerning cardiac remodeling than BMI scores alone. The study utilized advanced cardiac MRI imaging to identify subtle changes in heart', NULL, 'A new study found that a &#8220;beer belly&#8221; may be linked to harmful changes in the heart structure, especially in men. Image Credit: master1305/Getty Images A new study found that abdominal fat, or a “beer belly,” may be linked to harmful changes in heart structure, particularly in males. The researchers say that a high waist-to-hip ratio may be associated with more concerning cardiac remodeling than BMI scores alone. The study utilized advanced cardiac MRI imaging to identify subtle changes in heart tissue that wouldn’t otherwise be visible. Abdominal obesity, often referred to as a “beer belly,” is an accumulation of visceral fat that is stored around the internal organs. Visceral fat is a type of fat stored within the abdominal cavity that can accumulate in the arteries, contributing to the development of cardiovascular disease. A new study found that abdominal obesity is not only linked to harmful changes in heart structure, but that these effects were more apparent among males. The researchers used advanced cardiac MRIs to detect beer belly-associated heart changes that could signal early heart stress before the onset of cardiovascular disease or symptoms. The study, however, did not examine beer consumption among the subjects. The findings were recently presented at the annual meeting of the Radiological Society of North America (RSNA), held from November 29 to December 3, in Chicago, IL. The study has not yet been published in a peer-reviewed scientific journal. “Abdominal obesity, a high waist-to-hip ratio, is associated with more concerning cardiac remodeling patterns than high body mass index (BMI) alone,&#8221; lead study author Jennifer Erley, MD, a radiologist resident at the University Medical Center Hamburg-Eppendorf, Germany, said in a press release. Abdominal obesity and cardiac remodeling For the study, researchers examined MRI scans of 2,244 adults ages 46 to 78. The study found that obesity, as measured by BMI scores, was more strongly associated with enlarged heart chambers across all participants, regardless of sex. Abdominal obesity, or &#8220;beer belly,&#8221; was more associated with a thickening of the heart muscle and smaller heart chambers. These abdominal obesity-related changes were more prominent in males, particularly in the right ventricle. The right ventricle pumps blood to the lungs. The researchers suggested their findings may reflect early cardiac stress related to how abdominal fat affects breathing and lung pressure. &#8220;It appears to lead to a potentially pathological form of cardiac remodeling, concentric hypertrophy, where the heart muscle thickens, but the overall size of the heart doesn’t increase, leading to smaller cardiac volumes,&#8221; Erley said in the press release. &#8220;In fact, the inner chambers become smaller, so the heart holds and pumps less blood. This pattern impairs the heart’s ability to relax properly, which eventually can lead to heart failure,&#8221; she continued. The researchers suggest that the more extensive heart damage seen in males may be an earlier onset of more severe abdominal obesity, but more research is needed ot confirm this theory. Mir Ali, MD, medical director at MemorialCare Weight Loss Center in Fountain Valley, CA, who was not involved in the study, said the study&#8217;s findings reaffirm that abdominal obesity has a negative impact on cardiovascular disease. Ali wasn&#8217;t involved in the study. &#8220;Though there is no one clear explanation for this, it is surmised that abdominal fat increases inflammation throughout the body, affects normal hormonal balance, and leads to insulin resistance, to name a few,&#8221; Ali told Healthline. &#8220;All of these changes affect all organs, but the heart and blood vessels are particularly sensitive to these changes.” Kevin Shah, MD, program director at MemorialCare Heart Failure Outreach in Long Beach, CA, who wasn&#8217;t involved in the study, echoed these remarks. “Visceral fat drives inflammation, insulin resistance, and abnormal cholesterol patterns — all of which accelerate cardiovascular disease,&#8221; Shah told Healthline. Waist-to-hip ratio vs. BMI BMI is a calculation of a person’s weight in kilograms divided by the square of their height in meters. For adults ages 20 and older, a BMI of 30 or more is considered obesity. Your waist-to-hip ratio can be calculated by dividing the measurement of your waist circumference at its narrowest point by the measurement of your hips at their widest point. The World Health Organization (WHO) uses cut-off points, or maximum waist-to-hip ratios, to determine obesity. A ratio of 0.90 for males and 0.85 for females is an indicator of abdominal obesity and may be associated with an increased risk of cardiovascular disease. BMI does not account for fat distribution in the body. The waist-to-hip ratio can better indicate any increase in abdominal fat. It may also be easier to calculate than BMI. “Waist-to-hip ratio — and even simple waist circumference — adds important information that BMI alone misses. BMI cannot distinguish between muscle and fat, and it doesn’t capture fat distribution,” Shah said. He added that the waist-to-hip ratio and waist circumference should be included in routine assessments. BMI, while useful, should not be the only measure guiding risk discussions. Tips for preventing &#8216;beer belly&#8217; Not only is visceral fat associated with cardiovascular disease, but it&#8217;s also linked to higher risks of other chronic conditions, including: type 2 diabetes heart disease stroke Alzheimer’s disease certain cancers (i.e., breast and colorectal) While it can be difficult to target abdominal obesity, there are some strategies that may help you lose weight and lower your risk of other chronic diseases. &#8220;Doing abdominal exercises does not necessarily lead to weight loss in the abdomen,&#8221; Ali said. &#8220;Losing weight overall, whether it&#8217;s with diet, medications, or surgery, can lead to a reduction in abdominal fat.” Shah emphasized the importance of nutrition quality, resistance training, and overall physical activity. He offered the following tips and suggestions: strength training 2 to 3 times per week adding 20–30 minutes of daily walking reducing refined carbohydrates and increasing protein intake “Small, consistent lifestyle changes have a measurable impact on waist size and long-term heart health,” Shah said.', NULL, 'https://www.healthline.com/health-news/beer-belly-linked-to-heart-damage-in-men', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/Beer-belly-GettyImages-1175032012-Header.jpg', NULL, NULL, '2026-01-25 06:50:39.547261', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["beer belly", "abdominal obesity", "heart damage", "cardiac remodeling", "visceral fat"]', '{"topics": ["cardiovascular health", "obesity", "heart disease prevention", "medical imaging"], "summary": "دراسة جديدة تربط بين السمنة البطنية أو ما يعرف بـ''كرش البيرة'' وتغيرات ضارة في بنية القلب، خاصة لدى الرجال. استخدمت الدراسة تصوير القلب بالرنين المغناطيسي لتحديد هذه التغيرات التي قد تشير إلى إجهاد مبكر للقلب قبل ظهور أعراض أمراض القلب.", "entities": ["Jennifer Erley", "Radiological Society of North America (RSNA)", "University Medical Center Hamburg-Eppendorf"], "credibilityScore": 70}', '2026-01-25 06:50:39.547261', '2026-01-29 13:36:56.642');
INSERT INTO public.radar_items VALUES ('332d0627-2cc6-4262-a5bd-d430684433a9', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '7487fa8475d0037c8a1af500ff175de4', 'Does Medical Cannabis Really Have Any Benefit? Experts Discuss', NULL, 'Research suggests that there’s a lack of evidence for some of the common uses of medical cannabis. Image Credit: JENS SCHLUETER/Getty Images A recent review found that many of the common uses of medical cannabis are not scientifically based. There may be anecdotal evidence to support various uses. However, clinical evidence is lacking partly due to limitations on the ability to effectively study cannabis. The review also indicates there may be risks associated with long-term medical cannabis use', NULL, 'Research suggests that there&#8217;s a lack of evidence for some of the common uses of medical cannabis. Image Credit: JENS SCHLUETER/Getty Images A recent review found that many of the common uses of medical cannabis are not scientifically based. There may be anecdotal evidence to support various uses. However, clinical evidence is lacking partly due to limitations on the ability to effectively study cannabis. The review also indicates there may be risks associated with long-term medical cannabis use. Many people rely on medical cannabis for pain management or to ease symptoms associated with chronic conditions, but new research questions whether there&#8217;s any real benefit. A recent review published in JAMA found that the evidence to support the use of cannabis and cannabinoids for most medical indications is insufficient. The authors state that only specific pharmaceutical-grade cannabinoid products approved by the Food and Drug Administration (FDA) have demonstrated clear clinical benefits. Michael Hsu, MD, a health sciences clinical assistant professor at the UCLA Health Department of Psychiatry and Biobehavioral Sciences and the first author of the review, said in a press release that many people assume cannabis provides reliable medical benefits. However, recent research doesn’t support these assumptions. “While many people turn to cannabis seeking relief, our review highlights significant gaps between public perception and scientific evidence regarding its effectiveness for most medical conditions,” he said. Hsu added that it&#8217;s important for clinicians to give clear guidance to individuals in order to support safe and evidence-based decision making when discussing the use of medical cannabis. “This is not a one-size-fits-all product,&#8221; said Sherry Yafai, MD, a board certified emergency medicine physician and Medical Director of Integrative Health at Women’s Health & Wellness Clinic at Providence Saint John’s Health Center in Santa Monica, CA. Yafai wasn&#8217;t involved in the research. “Based on my clinical experience and review of the literature over the last decade, I find that the lay public grossly overemphasizes the benefits of cannabis, while the media/scientific world grossly underestimates the benefits of medical cannabis,&#8221; she told Healthline. Medical cannabis benefits lack clinical evidence There is insufficient evidence for the use of cannabis to treat various health ailments. The American College of Physicians does not recommend cannabis-based treatment as the first option for pain management, despite that many people rely on cannabis to treat chronic pain. Other professional medical organizations have guidance against the use of cannabis-based treatment for the management of symptoms and conditions ranging from MS spasticity, insomnia, dementia, and cancer pain. While cannabis may not be recommended as a first-line treatment for &#8220;off-label&#8221; use, there are some possible benefits of medical cannabis that have been approved by the FDA. “These have been proven since Marinol (a synthetic THC) became FDA approved [in 1985], and Epidiolex (plant-based CBD) became FDA approved in the 2010s,&#8221; Yafai said. &#8220;My patients thank me routinely for treatment strategies implemented with cannabis.&#8221; Yafai added that while there are many small studies on the benefits of medical cannabis, large studies are lacking. This is mostly due to the fact that cannabis is still illegal at the federal level in the United States. Possible health risks of cannabis use The authors of the review examined safety concerns and risks associated with the use of cannabis and cannabinoids. Long-term research in adolescents has shown that high-potency cannabis can be associated with higher rates of psychotic symptoms and generalized anxiety disorder. Around 29% of medical cannabis users also met the criteria for cannabis use disorder. The review found that daily consumption, especially of high-potency or inhaled products, can be associated with cardiovascular issues, including: heart attack stroke higher risk of coronary heart disease “Anything that we put in our bodies comes with risk; this is no different,&#8221; Yafai said. &#8220;Furthermore, anything abused comes at higher risks. Teens who think this is [a] &#8216;healthy&#8217; option, just because it is a plant, often don’t realize they are consuming multiple plants&#8217; worth of THC in one sitting or in a day,” she continued. Zergabachew Asfaw, MD, clinical advisory committee member at Enable Healthcare and physician at A Z Medical in the Bronx, New York, agreed that medical cannabis use may come with risks. Asfaw wasn&#8217;t involved in the new review. “There is also the possibility of adverse drug interactions due to the effects of cannabis on other drugs, where patients without medical cannabis supervision may be precipitating adverse drug reaction scenarios or scenarios where the drugs prescribed lose their efficacy or therapeutic effects,&#8221; he told Healthline. Prescription cannabis vs. &#8216;off-label&#8217; use Cannabis refers to the entire plant, including the dried flowers, leaves, and extracts. Cannabinoids, such as delta-9-tetrahydrocannabinol (THC) and cannabidiol (CBD), are the chemicals of the cannabis plant that interact with the body’s endocannabinoid system and produce physiological effects. Certain cannabinoids, such as dronabinol and cannabidiol, are available as FDA-approved medications for specific indications. Dronabinol is a synthetic form of THC. It is important to remember that, unlike FDA-approved pharmaceutical cannabinoids, most cannabis products that are sold through dispensaries remain federally illegal under the U.S. Controlled Substances Act. However, most states have legalized medical cannabis, and many have even legalized recreational use. Pharmaceutical-grade cannabinoids are FDA-approved for specific uses, including: HIV-induced anorexia chemotherapy-induced nausea and vomiting various pediatric seizure disorders Any use for non-approved conditions is considered “off-label” use. Some of the off-label uses include: chronic pain not associated with cancer multiple sclerosis (MS) associated spasticity cancer pain insomnia dementia psychiatric disorders However, the American Psychiatric Association (APA) recommends against the use of cannabinoids or cannabis in the treatment of any psychiatric disorder. It emphasizes that cannabis may actually exacerbate or precipitate mental illness, particularly depression. Should you use cannabis for medical purposes? The authors of the review acknowledge the various limitations of their research. For example, the analysis was not a systematic review, and no formal risk-of-bias assessment was conducted. Other limitations include, some of the included research was observational and may have been influenced by confounding factors. The authors of the study recommend further research for a full understanding of the benefits and risks of medical cannabis. “We must stress here that medical cannabis is not without its limitations,&#8221; Asfaw said. &#8220;Its effects vary depending on dosage and particular medical condition, and the therapy is best customized and adjusted according to the patient as part of more comprehensive therapy,&#8221; Asfaw told Healthline. Yafai gave the following recommendations for those who might be considering medical cannabis: “Consult a physician who is well-versed on medical cannabis, as all products are not the same. All gummies are not the same. What works for your friend may not work for you. Physicians who focus on cannabis are more likely to get you on a regimen that will yield better outcomes more quickly than trying this on your own.” Asfaw added that clinically studied medical cannabis has both benefits and limitations. &#8220;Making patients aware of both benefits and limitations shapes their expectations and helps to mitigate disappointment or avoid overuse,&#8221; he said.', NULL, 'https://www.healthline.com/health-news/does-medical-cannabis-really-have-any-benefit-experts-discuss', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/holding-Medical-Cannabis-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:39.054673', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["medical cannabis", "clinical evidence", "cannabinoids", "FDA", "pain management"]', '{"topics": ["medical cannabis effectiveness", "scientific evidence gaps", "long-term risks of cannabis use"], "summary": "دراسة حديثة تشير إلى نقص الأدلة العلمية لدعم العديد من الاستخدامات الشائعة للقنب الطبي، مع وجود فجوات بين التصورات العامة والحقائق العلمية. كما تحذر الدراسة من المخاطر المحتملة للاستخدام طويل الأمد للقنب الطبي.", "entities": ["Michael Hsu", "FDA", "Sherry Yafai", "UCLA Health Department of Psychiatry and Biobehavioral Sciences"], "credibilityScore": 90}', '2026-01-25 06:50:39.054673', '2026-01-29 13:37:14.333');
INSERT INTO public.radar_items VALUES ('9abbd12d-5621-4c96-8fea-98c601b76882', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'df1fec9943ea54f2ffc98527597ebca8', 'Medicaid Tries New Approach With Sickle Cell: Companies Get Paid Only if Costly Gene Therapies Work', NULL, 'The government is using sickle cell treatments to test a new strategy: paying only if the therapies benefit patients. With more expensive treatments on the horizon, the program — created by the Biden administration and continued under President Trump — could help Medicaid save money and treat more patients.', NULL, 'Serenity Cole enjoyed Christmas last month relaxing with her family near her St. Louis home, making crafts and visiting friends. It was a contrast to how Cole, 18, spent part of the 2024 holiday season. She was in the hospital — a frequent occurrence with sickle cell disease, a genetic condition that damages oxygen-carrying red blood cells and for years caused debilitating pain in her arms and legs. Flare-ups often would force her to cancel plans or miss school. &#8220;With sickle cell it hurts every day,&#8221; she said. &#8220;It might be more tolerable some days, but it&#8217;s a constant thing.&#8221; In May, Cole completed a several-months-long gene therapy treatment that helps reprogram the body&#8217;s stem cells to produce healthy red blood cells. She was one of the first Medicaid enrollees nationally to benefit from a new payment model in which the federal government negotiates the cost of a cell or gene therapy with pharmaceutical companies on behalf of state Medicaid programs — and then holds them accountable for the treatment&#8217;s success. Under the agreement, participating states will receive &#8220;discounts and rebates&#8221; from the drugmakers if the treatments don&#8217;t work as promised, according to the Centers for Medicare & Medicaid Services. That&#8217;s a stark difference from how Medicaid and other health plans typically pay for drugs and therapies — the bill usually gets paid regardless of the treatments&#8217; benefits for patients. But CMS has not disclosed the full terms of the contract, including how much the drug companies will repay if the therapy doesn&#8217;t work. The treatment Cole received offers a potential cure for many of the 100,000 primarily Black Americans with sickle cell disease, which is estimated to shorten lifespans by more than two decades. But the treatment&#8217;s cost presents a steep financial challenge for Medicaid, the joint state-federal government insurer for people with low incomes or disabilities. Medicaid covers roughly half of Americans with the condition. There are two gene therapies approved by the Food and Drug Administration on the market, one costing $2.2 million per patient and the other $3.1 million, with neither cost including the expense of the long hospital stay. The CMS program is one of the rare health initiatives started under President Joe Biden and continued during the Trump administration. The Biden administration signed the deal with the two manufacturers, Vertex Pharmaceuticals and Bluebird Bio, in December 2024, opening the door for states to join voluntarily. &#8220;This model is a game changer,&#8221; Mehmet Oz, the CMS administrator, said in a July statement announcing that 33 states, Washington, D.C., and Puerto Rico had signed onto the initiative. Asked for further details on the contracts, Catherine Howden, a CMS spokesperson, said in a statement that the terms of the agreements are &#8220;confidential and have only been disclosed to state Medicaid agencies.&#8221; &#8220;Tackling the high cost of drugs in the United States is a priority of the current administration,&#8221; the statement said. Citing confidentiality, two state Medicaid directors and the two manufacturers declined to reveal the financial terms of agreements. New Therapies The gene therapies, approved in December 2023 for people 12 or older with sickle cell disease, offer a chance to live without pain and complications, which can include strokes and organ damage, and avoid hospitalizations, emergency room visits, and other costly care. The Biden administration estimated that sickle cell care already costs the health system almost $3 billion a year. With many more expensive gene therapies on the horizon, the cost of the sickle cell therapies presages financial challenges for Medicaid. Hundreds of cell and gene therapies are in clinical trials, and dozens could get federal approval in the next few years. If the sickle cell payment model works, it will probably lead to similar arrangements for other pricey therapies, particularly for those that treat rare diseases, said Sarah Emond, president and CEO of the Institute for Clinical and Economic Review, an independent research institute that evaluates new medical treatments. &#8220;This is a worthy experiment,&#8221; she said. Setting up payment for drugs based on outcomes makes sense when dealing with high treatment costs and uncertainty about their long-term benefits, Emond said. &#8220;The juice has to be worth the squeeze,&#8221; she said. Clinical trials for the gene therapies included fewer than 100 patients and followed them for only two years, leaving some state Medicaid officials eager for reassurance they were getting a good deal. &#8220;What we care about is whether services actually improve health,&#8221; said Djinge Lindsay, chief medical officer for the Maryland Department of Health, which runs the state&#8217;s Medicaid program. Maryland is expected to begin accepting patients for the new sickle cell program this month. Medicaid is already required to cover almost all FDA-approved drugs and therapies, but states have leeway to limit access by restricting which patients are eligible, setting up a lengthy prior authorization process, or requiring enrollees to first undergo other treatments. While the gene therapy treatments are limited to certain hospitals around the country, state Medicaid officials say the federal model means more enrollees will have access to the therapies without other restrictions. The manufacturers also pay for fertility preservation such as freezing reproductive cells, which could be damaged by chemotherapy during the treatment. Typically, Medicaid doesn&#8217;t cover that cost, said Margaret Scott, a principal with the consulting firm Avalere Health. Emond said pharmaceutical companies were interested in the federal deal because it could lead to quicker acceptance of the therapy by Medicaid, compared with signing individual contracts with each state. States are attracted to the federal program because it offers help monitoring patients in addition to negotiating the cost, she said. Despite some secrecy around the new model, Emond said she expects a federally funded evaluation will track the number of patients in the program and their results, allowing states to seek rebates if the treatment is not working. The program could run for as long as 11 years, according to CMS. &#8220;This therapy can benefit many sickle cell patients,&#8221; said Edward Donnell Ivy, chief medical officer for the Sickle Cell Disease Association of America. He said the federal model will help more patients access the treatment, though he noted utilization will depend in part on the limited number of hospitals that offer the multimonth therapy. Hope for Sickle Cell Patients Before gene therapy, the only potential cure for sickle cell patients was a bone marrow transplant — an option available only to those who could find a suitable donor, about 25% of patients, Ivy said. For others, lifelong management includes medications to reduce the disease&#8217;s effects and manage pain, as well as blood transfusions. About 30 of Missouri&#8217;s 1,000 Medicaid enrollees with sickle cell disease will get the therapy in the first three years, said Josh Moore, director of the state&#8217;s Medicaid program. So far, fewer than 10 enrollees have received it since the state began offering it in 2025, he said. Less than a year into the federal program, Moore said it&#8217;s too early to tell its rate of success — defined as an absence of painful episodes that lead to a hospital visit. But he hopes it will be close to the 90% rate seen over the course of a couple of years in clinical trials. Moore said the federal program based on how well the treatment works was preferred over cutting fees for a new and promising therapy, which would put the manufacturers&#8217; ability to develop new drugs at risk. &#8220;We want to be good stewards of taxpayer dollars,&#8221; he said. He declined to comment on how much the state may save from the arrangement or disclose other details, such as how much the drug companies might have to pay back, citing confidentiality of the contracts. Lately Cole, who underwent gene therapy at St. Louis Children&#8217;s Hospital, has been able to focus on her hobbies — playing video games, drawing, and painting &#8211; and earning her high school diploma. She said she was glad to get the treatment. The worst part was the chemotherapy, she said, which left her unable to talk or eat — and entailed getting stuck with needles. She said that her condition is &#8220;way better&#8221; and that she has had no pain episodes leading to a hospital stay since completing the therapy last spring. &#8220;I&#8217;m just grateful I was able to get it.&#8221; KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/sickle-cell-disease-gene-therapy-medicaid-vertex-bluebird-bio/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/Sickle-cell-drugs-05-lo.jpg?w=1024', 'Phil Galewitz, KFF Health News', '2026-01-21 10:00:00', '2026-01-25 06:50:41.526652', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["Medicaid", "sickle cell disease", "gene therapy", "payment model", "healthcare costs"]', '{"topics": ["innovative healthcare payment models", "gene therapy for sickle cell", "Medicaid reforms", "healthcare affordability"], "summary": "Medicaid is testing a new payment model for treating sickle cell disease, where pharmaceutical companies are paid only if gene therapies prove effective. This approach aims to reduce costs and improve access to expensive treatments for low-income patients.", "entities": ["Centers for Medicare & Medicaid Services", "Serenity Cole", "Biden administration", "pharmaceutical companies"], "credibilityScore": 90}', '2026-01-25 06:50:41.526652', '2026-01-31 08:07:44.349');
INSERT INTO public.radar_items VALUES ('7ea41678-0c75-43ff-b02b-3f5562c88d3c', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '78d217c7ffdc0d386a8050fcd8045269', 'Farmers Now Owe a Lot More for Health Insurance', NULL, 'More than a quarter of the agricultural workforce purchases health insurance through the individual marketplace, a much larger share than the overall percentage of U.S. adults. After a tough year for farmers, the loss of enhanced ACA subsidies is putting health insurance out of reach for many.', NULL, 'Last year was a tough one for farmers. Amid falling prices for commodity crops such as corn and soybeans, rising input costs for supplies like fertilizer and seeds, as well as the Trump tariffs and the dismantling of USAID, many farms weren&#8217;t profitable last year. And now, the enhanced Affordable Care Act subsidies that many Americans, including farmers, relied on to purchase health insurance are gone, having expired at the end of December. James Davis, 55, who grows cotton, soybeans, and corn in northern Louisiana, said he didn&#8217;t know how he and his wife would afford coverage. Their share of their insurance premium quadrupled for 2026, jumping to about $2,700 a month. &#8220;You can&#8217;t afford it,&#8221; Davis said. &#8220;Bottom line. There&#8217;s nothing to discuss. You can&#8217;t afford it without the subsidies.&#8221; More than a quarter of the agricultural workforce purchases health insurance through the individual marketplace, according to an analysis from KFF, a health information nonprofit that includes KFF Health News. That 27% rate is much higher than the overall population&#8217;s — only 6% of U.S. adults have non-group coverage. Farmers are used to facing challenges such as unpredictable weather and fluctuating commodity prices. But the loss of the enhanced subsidies, coupled with challenging economic conditions, will make coverage unaffordable for many. Without major intervention from Washington, farmers say they&#8217;ll have to choose between being uninsured or leaving the farm work behind for a job that offers health insurance. A Gamble for Farmers Farming is dangerous work. Agricultural workers spend much of their time outside and exposed to the elements. Many of their duties can lead to injury or illness. They drive and operate heavy machinery, work with toxic chemicals, and handle large animals. The rate of work-related deaths for farmers is seven times the national average. The financial toll of non-fatal farm injuries is also significant. A study from the University of Nebraska Medical Center found that the average cost of a farming injury was $10,878 in medical care and $4,735 in lost work. It&#8217;s essential that farmers can purchase comprehensive insurance, said Florence Becot, a rural sociologist and associate professor of agricultural health and safety at Pennsylvania State University, where she studies the social and economic needs of farm households. In a 2022 study, Becot found that more than 20% of U.S. farm households had medical debt exceeding $1,000 and that more than half were not confident they could cover the costs of a major illness or injury. &#8220;That shows you the level of vulnerability and concerns that farmers are facing,&#8221; she said. Mental health is also a concern. Farmers are roughly twice as likely to die by suicide compared with the general population. Mental health hotlines that serve rural communities have seen an uptick in calls. These concerns around farmers&#8217; increased emotional distress, coupled with a rise in bankruptcies, conjures memories of the farm crisis of the 1980s, said Michael Klein, a vice president at the industry group USA Rice. During that decade, there was a raft of foreclosures, and hundreds of farmers took their own lives. &#8220;We&#8217;re really afraid of what&#8217;s going to happen,&#8221; Klein said. Farmers can be reluctant to acknowledge that they rely on government-subsidized insurance, said Meghan Palmer, 43, who runs a dairy farm in northeastern Iowa with her husband, John, 45. &#8220;We&#8217;re not handout-takers,&#8221; Palmer said. More than 40% of dairy farmers lack health insurance — one of the highest rates among all agricultural sectors. But going uninsured is not an option for the Palmers. During their first year of marriage, the couple recalled, they were uninsured and had to pay out-of-pocket for two unexpected health crises: Palmer had an appendectomy, and her husband needed stitches after getting kicked in the face by one of his cows. &#8220;It was stupid of us,&#8221; Palmer said of the decision to forgo coverage. But this year, the combined out-of-pocket monthly cost of their plans is increasing by more than 90%, to $368.18. Their total 2026 deductible is $7,200. Palmer is a registered nurse who picks up shifts on an as-needed basis, allowing her the flexibility to prioritize her work on the farm. She&#8217;s now searching for a job with health benefits. But she worries a job that doesn&#8217;t allow her to keep up with the farm work will create a greater burden for her husband. &#8220;John is working exhausted most of the time,&#8221; she said. &#8220;That&#8217;s when mistakes get made and you end up in the ER.&#8221; Political Consequences Even after the enhanced subsidies expired at the end of 2025, the Palmers estimate their income will still be low enough that they&#8217;ll qualify for some tax credits to purchase coverage. However, under the GOP&#8217;s One Big Beautiful Bill Act, repayment limits are being eliminated, so if the Palmers have a surprisingly profitable 2026, they&#8217;ll be forced to pay some, or even all, of that subsidy back at tax time. A farmer&#8217;s income can vary drastically year to year, Becot said, partly because commodity prices can fluctuate rapidly. Some farmers might deliberately choose to not expand their businesses, because too much profit might mean they lose access to health care subsidies. Farmers who are insured through Medicaid have similar concerns, Becot said. But prioritizing health care affordability by suppressing operational growth can have long-term consequences for a farm&#8217;s success. Palmer, in Iowa, and Davis, in Louisiana, are both upset that lawmakers aren&#8217;t more sensitive to the economic demands of farming and how those have coincided with rising health costs. President Donald Trump recently pledged $12 billion in one-time bridge payments to row crop farmers, but that&#8217;s not going to stop health care costs from ballooning. Republicans are aware that health care affordability is a problem and have put forth proposals, said Donna Hoffman, a political scientist at the University of Northern Iowa. But most don&#8217;t support extending the enhanced ACA subsidies, because they don&#8217;t see them as a good solution to the problem of rising health care costs. This article is from a partnership that includes the Gulf States Newsroom, NPR, and KFF Health News. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/farmers-health-insurance-costs-aca-obamacare-subsidies/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/Palmer-Farm-thumb.jpg?w=1024', 'Sarah Boden and Drew Hawkins, Gulf States Newsroom', '2026-01-22 10:00:00', '2026-01-25 06:50:41.282405', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["farmers", "health insurance", "ACA subsidies", "agriculture workforce", "economic challenges"]', '{"topics": ["Affordable Care Act", "health insurance affordability", "agriculture and health", "economic impact on health"], "summary": "انتهاء دعم قانون الرعاية الصحية الميسرة (ACA) يهدد قدرة المزارعين الأمريكيين على تحمل تكاليف التأمين الصحي، مما قد يدفع البعض للتخلي عن العمل الزراعي أو البقاء بدون تأمين صحي. هذا يأتي في ظل تحديات اقتصادية صعبة تواجه القطاع الزراعي.", "entities": ["James Davis", "KFF Health News", "USAID", "Trump tariffs"], "credibilityScore": 90}', '2026-01-25 06:50:41.282405', '2026-01-31 08:07:49.848');
INSERT INTO public.radar_items VALUES ('fc99d447-5022-4cfb-9efa-f7f2a2d06b5c', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '2145f55b2eb933f5aa5efa982ac57c11', 'WHO urges schools worldwide to promote healthy eating for children', NULL, 'Healthy food in schools can help children develop healthy dietary habits for life, according to the World Health Organization (WHO), which released a new global guideline on evidence-based policies and interventions to create healthy school food environments.', NULL, 'Healthy food in schools can help children develop healthy dietary habits for life, according to the World Health Organization (WHO), which released a new global guideline on evidence-based policies and interventions to create healthy school food environments.', NULL, 'https://www.who.int/news/item/27-01-2026-who-urges-schools-worldwide-to-promote-healthy-eating-for-children', NULL, NULL, '2026-01-27 15:26:20', '2026-01-29 13:36:21.433293', 'en', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["WHO", "healthy eating", "children", "schools", "dietary habits", "guideline"]', '{"topics": ["healthy eating", "child nutrition", "school food policies"], "summary": "منظمة الصحة العالمية تدعو المدارس حول العالم لتعزيز الأكل الصحي للأطفال. أصدرت المنظمة إرشادات جديدة حول سياسات غذائية قائمة على الأدلة لتحسين بيئة الغذاء في المدارس.", "entities": ["World Health Organization (WHO)"], "credibilityScore": 95}', '2026-01-29 13:36:21.433293', '2026-01-31 08:07:40.487');
INSERT INTO public.radar_items VALUES ('383588f1-06ca-434b-b731-d5b84e43a2f2', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'fb84ffec16b9197115adf6043fde5853', 'Make Us Swoon: Send In Your Health Policy Valentines', NULL, 'Affordable health care is our love language. We want to see your most clever, heartfelt, or hilarious tributes to the policies that shape health care. And we''ve sweetened the deal with prizes.', NULL, 'Affordable health care is our love language. Stoke the fire by submitting your sweetest &#8220;Health Policy Valentines.&#8221; We want to see your clever, heartfelt, or hilarious tributes to the policies that shape health care. An esteemed panel of editors will review entries. We&#8217;ll share favorites on our social media channels, and our staff will pick the winners, announced on Friday, Feb. 13, just in time for Valentine&#8217;s Day. Rules: Submit your poem — whether conventional, free-form, or haiku — using the form below. Please include the link to a related KFF Health News article. Like KFF Health News on Facebook, and follow @KFFHealthNews on X, @kffhealthnews.org on Bluesky, and @kffhealthnews on Instagram. (Optional) Include your X, Bluesky, Instagram, or other social handle in the submission and let us know if it&#8217;s OK to give you a shoutout on social media. Submit your poem by noon ET on Wednesday, Feb. 4. To win, the poem must meet the following criteria: Contain information related to health care and/or health policy that follows the love/valentines theme. Tag KFF Health News and use the hashtag #HealthPolicyValentines if shared on social media. Reference a KFF Health News article in the poem — our preference, not mandatory. Be written without the help of artificial intelligence. Entries created or modified by AI will not be considered. Submissions may be lightly edited for style and clarity. Prizes: Julie Rovner will read the winning submission on the What the Health? From KFF Health News podcast on Feb. 12. The top poem will be announced with a custom comic illustration drawn by staff illustrator Oona Zenda. That poem will also be featured in the KFF Health News &#8220;Morning Briefing&#8221; on Feb. 13, and we will show the winner some love on our social media pages, with the hashtag #HealthPolicyValentines. Health Policy Valentines Submission Form Submissions are due by noon ET on Wednesday, Feb. 4. X/TwitterThis field is for validation purposes and should be left unchanged.Your name:(Required)Your email address:(Required) Your poem:(Required)Related KFF Health News article URL: Your social media handle(s) and platform: (OPTIONAL)Example: @KFFHealthNews on Instagram, etc.Is it OK to give you a shout-out on social?(Required) Yes No Submission requirement:(Required) I confirm this poem was not created using AI (artificial intelligence). Δ KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/health-policy-valentines-annual-contest/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2024/02/2024_Valentine_Winner-3x2-thumbnail.jpg?w=1024', 'KFF Health News Staff', '2026-01-22 10:00:00', '2026-01-25 06:50:41.158914', 'ar', 'health-news', 'health-community', 60, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["health policy", "valentines", "KFF Health News", "affordable health care", "poetry contest"]', '{"topics": ["health policy", "community engagement", "creative expression"], "summary": "KFF Health News invites the public to submit creative Valentine''s-themed poems about health policy for a chance to win prizes. The winning entry will be featured on their podcast and social media, promoting engagement with health care topics.", "entities": ["KFF Health News", "Julie Rovner", "Oona Zenda"], "credibilityScore": 85}', '2026-01-25 06:50:41.158914', '2026-01-31 08:07:51.699');
INSERT INTO public.radar_items VALUES ('98388bab-be37-4b6b-8d39-9bb7be3acd6e', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '9d83b73421a95b422754f6f1a057b7e7', 'CBD, THC May Provide New Ovarian Cancer Treatments, Study Finds', NULL, 'Cannabis derivatives may lead to new treatments for ovarian cancer. Image Credit: Bloomberg Creative Photos/Getty Images Early lab research shows that two cannabis compounds, THC and CBD, have potent anti-ovarian cancer properties. The study found that CBD and THC work synergistically, reducing cancer cell growth, spread, and survival in multiple ways. The findings could one day pave the way for new adjunct therapies that support both treatment effectiveness and patient quality of life. Two comp', NULL, 'Cannabis derivatives may lead to new treatments for ovarian cancer. Image Credit: Bloomberg Creative Photos/Getty Images Early lab research shows that two cannabis compounds, THC and CBD, have potent anti-ovarian cancer properties. The study found that CBD and THC work synergistically, reducing cancer cell growth, spread, and survival in multiple ways. The findings could one day pave the way for new adjunct therapies that support both treatment effectiveness and patient quality of life. Two compounds found in cannabis show potent anti-tumor effects when exposed to ovarian cancer cells, suggesting they could play a role in future therapeutic research. Tetrahydrocannabinol (THC) and cannabidiol (CBD) are the two most widely studied compounds found in cannabis. THC is the primary psychoactive compound, while CBD is a non-intoxicating compound. Cannabis is used therapeutically for conditions ranging from nausea to chronic pain. Both THC and CBD belong to a class of compounds known as cannabinoids, which work on the body’s endocannabinoid system. Cancer treatment is one of the most active areas of research for CBD, THC, and cannabis more broadly. These compounds are powerful antiemetics, particularly useful for easing chemotherapy-induced nausea. They have also demonstrated promising anticancer effects in laboratory studies across several cancer types, including brain, breast, lung, and prostate. One noticeable gap in research has been studies focused on gynecologic cancers, including ovarian cancer. However, new laboratory research, published in Frontiers, is beginning to address that gap and may help lay the groundwork for future therapies. Researchers found that, as in other laboratory cancer models, CBD and THC killed ovarian cancer cells and slowed markers of tumor growth. “Our findings are generally consistent with existing literature showing that CBD and THC can act as potential adjuncts to cancer therapy,&#8221; said Siyao Tong, MD, an attending obstetrician and gynecologist at First Affiliated Hospital of Jinzhou Medical University, China, and first author of the study. &#8220;Both CBD and THC demonstrated clear inhibitory effects on ovarian cancer cells, and their combination, particularly at a 1:1 ratio, showed the strongest anticancer activity,” Tong told Healthline. Other experts have hailed the research as a compelling step forward in the search for new cancer treatments. “This is a field that is very much looking for new approaches,” said Elena Ratner, MD, a professor of obstetrics, gynecology, and reproductive sciences at Yale School of Medicine, and co-chief of gynecologic oncology at Yale Cancer Center and Smilow Cancer Hospital. Ratner wasn’t involved in the research. “This is all very early in the research, so we don’t know exactly what this will mean, but we are increasingly thinking of newer agents and newer ways of targeting cancer and understanding the biology of disease, so this absolutely has potential,” she told Healthline. Cannabis compounds targeted cancer cells Tong’s team conducted a variety of in vitro studies exposing ovarian cancer cells to CBD and THC in laboratory experiments. Notably, they experimented with two different ovarian cancer cell lines — one platinum-resistant and one platinum-sensitive. Platinum sensitivity reflects how well a cancer cell responds to platinum-based chemotherapy drugs, such as cisplatin and carboplatin, which are standard treatments for ovarian cancer. Both lines respond to exposure to CBD and THC, though the platinum-resistant line responded better at higher doses. Both THC and CBD also demonstrated “selective cytotoxicity,” meaning they were able to kill ovarian cancer cells at significantly lower doses than those required to harm healthy cells. In other words, the compounds selectively targeted cancer cells while sparing normal ones. Such a finding is key to demonstrating their potential therapeutic viability. CBD and THC were also synergistic in the study. When used in a 1:1 ratio with each other, they were more effective than when used independently. This type of synergy between cannabinoids has been noted in other areas of medical research and is often referred to as the “entourage effect.” Prior to their work, the researchers noted that the exact mechanism through which THC and CBD elicited their anticancer effects was not clear, but their investigation identified several cellular effects that may help explain these findings, including: Reducing cancer cells’ “clonogenic potential,” or their ability to divide and regrow. Triggering apoptosis, programmed cell death, in roughly 25% of cancer cells. Decreasing metastatic potential, or the cancer cells’ ability to spread. Inhibiting key signaling pathways involved in cell growth. “CBD and THC appear to inhibit the expression of key proteins within one of these pathways, thereby slowing down or blocking the pathway’s activity. By suppressing this cancer-promoting signaling, CBD and THC help reduce the growth and survival of ovarian cancer cells,” Tong said. Implications for ovarian cancer treatment Though these findings are promising, researchers would need to conduct extensive studies in animals and, eventually, in humans before any therapy could be approved. Nonetheless, Tong asserts that these cannabis-derived compounds could one day make for promising adjunct therapies to treat ovarian cancer. “It is likely that CBD and THC would be used alongside standard chemotherapeutic agents. They may help reduce chemoresistance in difficult-to-treat cases while exerting their own anti-tumor effects. Additionally, because CBD and THC have known benefits such as anti-inflammatory, anti-nausea, and analgesic properties, they may also improve patients’ quality of life during treatment,” Tong said. Ovarian cancer is the second most common gynecological cancer in the United States and results in more deaths than any other cancer of the female reproductive system. Approximately 20,000 cases were estimated, and more than 12,000 deaths were attributed to it in 2025. This form of cancer can be difficult to diagnose, with individuals often presenting with non-specific symptoms, resulting in late-stage diagnosis and worse outcomes. For Ratner, a clinician who manages ovarian cancer patients and routinely utilizes medical marijuana for symptom relief, research into new therapeutic possibilities is exciting. “The key to treatment in oncology right now, at least in my hands, is to allow women to live their lives while I&#8217;m taking care of the cancer,” she said. “There is really almost no toxicity with cannabis, and it has great benefits for symptom management. So, if there are additional benefits in terms of cancer biology, that would be amazing.”', NULL, 'https://www.healthline.com/health-news/cannabis-cbd-thc-may-help-treat-ovarian-cancer-study', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/cannabis-plants-growing-greenhouse-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:39.301695', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["CBD", "THC", "ovarian cancer", "cannabis", "cancer treatment"]', '{"topics": ["cancer research", "cannabis in medicine", "gynecologic oncology"], "summary": "أظهرت دراسة مخبرية أن مركبات القنب THC وCBD تمتلك خصائص قوية مضادة لسرطان المبيض، حيث تقلل من نمو وانتشار الخلايا السرطانية. النتائج قد تمهد الطريق لعلاجات داعمة جديدة تعزز فعالية العلاج وتحسن جودة حياة المرضى.", "entities": ["CBD", "THC", "Siyao Tong", "Frontiers"], "credibilityScore": 90}', '2026-01-25 06:50:39.301695', '2026-01-29 13:37:05.641');
INSERT INTO public.radar_items VALUES ('b923eff5-785e-44bc-85b3-9c7d1fde7955', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'c5c566954656710692ec22ba3a8e556d', 'FDA Says It''s Time to Ease Restrictions on Testosterone Replacement Therapy', NULL, 'An FDA panel has called for an easing of restrictions on testosterone replacement therapy (TRT). Image Credit: Malorny/Getty Images A Food and Drug Administration (FDA) expert panel is urging loosened restrictions and expanded access to testosterone replacement therapy (TRT). The recommendations follow new large clinical trials suggesting TRT does not raise heart attack, stroke, or prostate cancer risk in appropriately selected males. If adopted, the changes could make TRT more accessible for mi', NULL, 'An FDA panel has called for an easing of restrictions on testosterone replacement therapy (TRT). Image Credit: Malorny/Getty Images A Food and Drug Administration (FDA) expert panel is urging loosened restrictions and expanded access to testosterone replacement therapy (TRT). The recommendations follow new large clinical trials suggesting TRT does not raise heart attack, stroke, or prostate cancer risk in appropriately selected males. If adopted, the changes could make TRT more accessible for millions of males, but also raise new questions about oversight and prescribing practices. An FDA expert panel that convened this month has called for loosening regulations and expanding access to testosterone replacement therapy. FDA Commissioner Martin Makary signaled that the agency would be open to such revisions. Just one month after the FDA removed black box warnings for menopausal hormone replacement therapy (HRT), they are now eyeing regulatory changes to testosterone replacement therapy (TRT). The 13-member panel expressed strong support for TRT, arguing that the therapy could benefit a broader group of individuals than those currently covered by its approved indications. “We are failing men,” Helen L. Bernie, DO, a urologist at Indiana University and member of the expert panel, said during the hearing. “If we want to improve the health of American men, if we want to close the mortality gap, we must recognize testosterone deficiency for what it is: a public health issue,” Bernie continued. Current uses for TRT TRT is only approved for low testosterone (hypogonadism) associated with specific medical causes, such as: testicular dysfunction pituitary disorders hypothalamic disease TRT is not approved for age-related testosterone deficiency, which occurs naturally as males get older. The FDA’s indications are misaligned with guidance from professional groups such as the American Urological Association, which recommends considering testosterone therapy in males with confirmed low testosterone levels and clinical symptoms. In addition to limited clinical indications, TRT has historically been underutilized amid concerns about a purported increased risk of cardiovascular disease and prostate cancer. But panelists argued that such claims are no longer accurate in light of recent trial data. TRT has also been heavily scrutinized because of its association with performance-enhancing drug use and high-profile doping scandals in the 1980s and 1990s, a legacy reflected in testosterone’s current classification as a Schedule III controlled substance. New FDA recommendations The expert panel recommended sweeping regulatory changes for TRT, including: expanding FDA-approved indications to include age-related low testosterone removing its Schedule III controlled substance designation The panel also made clinical recommendations, including an emphasis on routine screening for low testosterone, similar to lipid panels and other commonly ordered blood tests. Franck Mauvais-Jarvis, MD, PhD, a professor of medicine at Tulane University and director of the VA hormone therapy clinic at New Orleans Medical Center, said that he unequivocally supported the panel’s recommendations. He has no association with the FDA panel. “I completely agree with them,” he told Healthline. “They wanted to show that testosterone deficiency is no longer part of this prehistoric paradigm wherein only men with testicular pathology or genetic cause have testosterone deficiency. In 2025, with the increased prevalence of obesity, metabolic disease, and sedentary behavior, a lot of people are testosterone-deficient,” Mauvais-Jarvis continued. TRT risks vs. benefits The FDA panel’s recommendations follow revisions to TRT safety warnings issued earlier this year. In February 2025, the FDA recommended changes to TRT labeling to remove a black-box warning related to the increased risk of cardiovascular disease. The FDA first implemented the boxed warning in 2015. The decision followed the results of the TRAVERSE trial, a large randomized, placebo-controlled trial, the results of which were published in NEJM in 2023. That study found that in males with hypogonadism and preexisting or high risk of CVD, TRT was not associated with a higher rate of heart attack or stroke than placebo. However, TRT was still linked with a small increase in blood pressure and a higher incidence of atrial fibrillation (AFib). Concerns about an increased risk of prostate cancer have also been reevaluated in recent years, with many experts concluding that the risk has likely been overstated. “The bottom line is no, testosterone does not increase the risk of prostate cancer,” Mauvais-Jarvis said. The results of a Harvard-led trial, published in JAMA Network Open in 2023, generally support this assertion. The study, which involved more than 5,000 males, concluded that among middle-aged and older males with hypogonadism — excluding those at high risk for prostate cancer — there was no significant difference in prostate cancer incidence between patients receiving TRT and those receiving placebo. “In the last several years, new data from large trials have emerged that warrant an update to the known risks of T therapy. Several concerns regarding cardiovascular risks and prostate cancer risk have largely been disproven in the latest trials,” said Michael Eisenberg, MD, a professor of urology at Stanford University who has no association with the FDA panel. Despite these findings, TRT is not risk-free and is still associated with side effects, including: worsening sleep apnea testicular atrophy and decreased sperm production polycythemia (excess red blood cell production that can lead to blood clots) However, recent data on the two biggest concerns related to TRT suggest that proponents argue that for many males, the benefits far outweigh the risks. Testosterone has a wide range of effects on the body. Potential health benefits include: muscle gain prevention of muscle wasting maintaining bone density improving sex drive fat loss “People who have low testosterone have a major risk of mortality. It&#8217;s the best biological marker of poor health,” said Mauvais-Jarvis. Debate over rescheduling testosterone The FDA panel was also critical of testosterone’s placement as a Schedule III controlled substance, where it is classified alongside codeine, an opioid, and ketamine, a dissociative anesthetic. Scheduled drugs are tracked by the DEA and state-run prescription monitoring databases, which some physicians and pharmacies say have made them more cautious about prescribing or dispensing these medications. “Such a designation places a burden on both the patient and provider. Without the same level of concern as other medications in this category, this seems an appropriate step to ease treatment for hypogonadism,” said Eisenberg. Testosterone’s classification as a controlled substance has, in some experts’ opinions, contributed to the rise of testosterone prescribing via telehealth platforms and “optimization” clinics — some of which may have dubious prescribing patterns or financial incentives “If you remove it from Schedule III, then doctors won&#8217;t be afraid. I believe you&#8217;ll have more patients going through appropriate channels to get TRT, because urologists, endocrinologists, people qualified in sexual medicine will be prescribing it,” Mauvais-Jarvis said. However, not all experts agreed on this point. “I don&#8217;t understand how rescheduling it and making it easier to prescribe gets it into the hands of endocrinologists and urologists, as opposed to any anti-aging or longevity clinic that can write a prescription,” said Philip Werthman, MD, a board certified urologist and director of the Center for Male Reproductive Medicine and Vasectomy Reversal in Los Angeles. He has no association with the FDA panel. Werthman expressed serious concerns that rescheduling testosterone might, in fact, lead to more illicit use, not less. “I see the other end of the stick, which is the guy who comes in in his thirties with his wife, and they&#8217;ve been trying to have a baby for a year, and no one told him it will make him sterile,” he told Healthline. “That’s where the harm is.”', NULL, 'https://www.healthline.com/health-news/fda-panel-restrictions-testosterone-replacement-therapy', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/FDA-Testosterone-Medication-Pharmacy-Shelves-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:39.177797', 'en', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["FDA", "testosterone replacement therapy", "TRT", "health regulations", "clinical trials"]', '{"topics": ["testosterone therapy", "FDA regulations", "men''s health", "clinical trials"], "summary": "لجنة خبراء إدارة الغذاء والدواء الأمريكية (FDA) توصي بتخفيف القيود على علاج استبدال التستوستيرون (TRT) بعد دراسات تشير إلى عدم زيادة خطر الإصابة بأمراض القلب أو السرطان. التوصيات قد توسع نطاق استخدام العلاج ليشمل المزيد من الرجال مع تحسين الصحة العامة.", "entities": ["FDA", "Martin Makary", "Helen L. Bernie", "Indiana University", "American Urological Association"], "credibilityScore": 90}', '2026-01-25 06:50:39.177797', '2026-01-29 13:37:08.945');
INSERT INTO public.radar_items VALUES ('9046eb74-4fe1-4092-be53-eae3d0ba0a24', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '14f33a970b76aa4cfd871f0b0f6cc672', '7 Ways to Improve Heart Health for Longevity After Cancer Diagnosis', NULL, 'A heart-healthy lifestyle can help promote longevity following cancer treatment. Tatiana Maksimova/Getty Images Researchers say that people who have undergone cancer treatment can decrease their mortality risk by adopting a heart-healthy lifestyle. They suggest following the guidelines listed in the American Heart Association’s Life’s Simple 7 plan. Experts say heart health is particularly important for cancer survivors, especially those who have undergone treatments that can increase cardiovasc', NULL, 'A heart-healthy lifestyle can help promote longevity following cancer treatment. Tatiana Maksimova/Getty Images Researchers say that people who have undergone cancer treatment can decrease their mortality risk by adopting a heart-healthy lifestyle. They suggest following the guidelines listed in the American Heart Association’s Life’s Simple 7 plan. Experts say heart health is particularly important for cancer survivors, especially those who have undergone treatments that can increase cardiovascular risks. People who have been treated for cancer can improve their chances for longevity by adopting seven principles of a heart healthy lifestyle, according to a new study. Researchers say cancer survivors can significantly reduce their risk of early mortality by maintaining healthy habits such as eating a balanced diet, exercising regularly, avoiding tobacco, and keeping their body weight and blood pressure at healthy levels. The study, published on December 16 in the European Heart Journal, noted that cardiovascular disease and cancer “share modifiable risk factors and potential molecular mechanisms.” “The findings underscore the importance of integrating cardiovascular health promotion into cancer care,” the study authors wrote. “Our study further supports the emerging field of cardio-oncology that focuses on the intersection of [cardiovascular disease] and cancer to improve the prevention, diagnosis, and management of cardiovascular issues in cancer patients and survivors,&#8221; they continued. Experts not involved in the study told Healthline that this new research backs up the notion that healthy heart habits for the general population are particularly important for people who have had cancer. “This observational study adds to growing evidence that cardiovascular health remains critically important after a cancer diagnosis,” said Rohan Khera, MD, a specialist in cardiovascular medicine at Yale Medicine in Connecticut. “While the study cannot prove causation, it provides evidence to support a focus on cardiovascular prevention into cancer survivorship care,” added Khera, who is also vice chair of the American Heart Association’s recent scientific statement on Artificial Intelligence to Enhance Precision Medicine in Cardio-Oncology. The experts also noted that some cancer treatments can produce cardiovascular health risks, making these healthy heart habits even more important for many oncology patients. “While heart health is obviously important for everybody, I believe it is more important for cancer survivors to be vigilant about healthy habits to protect their heart because of the increased risk of cardiovascular disease associated with cancer and cancer therapy,” said Christopher Berg, MD, a non-interventional cardiologist specializing in cardio-oncology at MemorialCare Heart and Vascular Institute at Orange Coast Medical Center in California. &#8216;Life&#8217;s Simple 7&#8217; for cancer survivors For their study, the researchers evaluated the medical records of 779 adults in the Molise region of Italy who were participants in the Moli-Sani study that began in 2005. The study subjects had all been diagnosed with cancer when they enrolled in the study and were followed for a median of around 15 years. The researchers utilized the Life’s Simple 7 (LS7) guidelines developed by the American Heart Association (AHA) to evaluate the study participants. The AHA guidelines list seven factors involved in cardiovascular health. They are: diet exercise smoking body weight blood pressure cholesterol blood glucose The participants were awarded two points for each of the seven categories where they maintained healthy habits and good health. The researchers ranked the LS7 scores as follows: 0-6: Poor cardiovascular health 7-9: Intermediate cardiovascular health 10-14: Ideal cardiovascular health They reported that people in the ideal heart health group had a 38% lower risk of mortality compared to people in the poor heart health category. They added that each one-point improvement in the LS7 score was associated with a 10% reduction in cancer mortality. They concluded that cardiovascular disease and cancer have three biological factors in common. They are: low-grade inflammation heart rate blood vitamin D levels Experts said the study reaffirms the belief that heart health is vital for people who have been treated for cancer. “It is important for cancer survivors to maintain their heart health, as cardiovascular disease would still independently be a significant cause of morbidity and mortality in this population,” said Cheng-Han Chen, MD, an interventional cardiologist and medical director of the Structural Heart Program at Saddleback Medical Center in California. “In addition, it appears that many of the risk factors for heart disease may also contribute to increased cancer risk as well, possibly through a shared biological milieu,” Chen told Healthline. “What this study also showed is that both cardiovascular mortality and cancer mortality were significantly reduced, which supports the hypothesis that there are shared risk factors for both cancer and cardiovascular disease,” added Berg. “The healthy habits that protect our heart also protects us from cancer.” Why a balanced diet, other healthy habits matter The researchers noted that the link between healthy behaviors and mortality risk became even stronger when the LS7 diet score was replaced by a special adherence to the Mediterranean diet. This eating plan emphasizes fruits, vegetables, whole grains, and lean proteins while limiting the consumption of processed foods. Experts said there is no doubt that diet is a crucial factor for people after they’ve been treated for cancer. However, they added that all of the LS7 components are important to adopt after successful cancer treatment. “Diet is an important component, but the key message from this study is that overall cardiovascular health matters most,” Khera said. “The strongest associations with survival were seen when multiple factors, including diet, physical activity, body weight, blood pressure, and metabolic health, were considered together.” Berg agreed. “It is important to maintain good habits in each health domain,” he said. “Having either positive or negative habits can directly impact the chance of maintaining and nurturing healthy habits in other domains.” “For example, if you have consistently poor sleep, it can be much harder to get up for your exercise program or stick to a diet,” Berg explained. “Conversely, healthy habits build momentum and can strengthen other beneficial routines.” “Eating a heart-healthy diet is just one of the many aspects of maintaining cardiovascular health,” added Chen. “It is just as important to get regular physical activity, avoid tobacco and alcohol, lower stress levels, and get an adequate amount of quality sleep.” Healthy lifestyle habits after cancer There are various ways to adopt healthy heart habits after cancer treatment. For diet, Khera said the best plan is the one that a person will stick with in the long term. “The most effective approach is to focus on sustainable eating patterns rather than rigid rules,” he said. “Diets emphasizing vegetables, fruits, whole grains, legumes, fish, and healthy fats such as olive oil are well supported by evidence and are easier to maintain long term.” “For cancer survivors, dietary changes should be individualized based on symptoms, energy levels, and personal preferences, with an emphasis on sustainability,” Khera added. Chen said that there are several dietary approaches that can be successful. “There are many ways people can adopt a heart-healthy diet,” he said. “It is important to be mindful of what you put on your plate. It is best to eat more vegetables, whole grains, lean meat, fish, and less saturated fat, sodium, and processed foods,&#8221; he said. “Avoiding beverages high in added sugar can help stabilize blood sugar levels and avoid empty calories. Being conscious of portion sizes can go a long way toward avoiding overeating,” Chen added. Berg suggested starting with small steps when making lifestyle changes after cancer treatment. “One of the takeaways from this study is that small incremental changes towards healthy behavior can pay dividends towards the future,” he said. “When patients make the transition from ‘cancer patient’ to ‘cancer survivor’, I advise them that now is the time to invest in small, sustainable, easily achievable alterations to their diet that they can seem themselves keeping for years to come.” “That may be as easy as switching from whole milk to skim milk, butter to plant-based fats, or switching out a steak for that chicken or fish recipe,” Berg continued. “Aiming toward a Mediterranean diet and keeping the ultra-processed foods to a minimum, watching the added sugar and saturated fat intake, are all easy, tangible changes to make.”', NULL, 'https://www.healthline.com/health-news/heart-healthy-strategies-longevity-after-cancer', 'https://media.post.rvohealth.io/wp-content/uploads/2025/12/senior-woman-exercise-park-1296x728-header.jpg', NULL, NULL, '2026-01-25 06:50:38.811098', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["heart health", "cancer survivors", "cardio-oncology", "American Heart Association", "Life’s Simple 7"]', '{"topics": ["cardiovascular health", "cancer treatment", "healthy lifestyle", "longevity"], "summary": "دراسة جديدة تشير إلى أهمية اتباع نمط حياة صحي للقلب لتحسين فرص البقاء على قيد الحياة لدى الناجين من السرطان. الخبر يبرز أهمية التداخل بين صحة القلب ورعاية مرضى السرطان في مجال الطب المعروف بـ ''cardio-oncology''.", "entities": ["American Heart Association", "European Heart Journal", "Rohan Khera", "Yale Medicine"], "credibilityScore": 90}', '2026-01-25 06:50:38.811098', '2026-01-29 13:37:29.787');
INSERT INTO public.radar_items VALUES ('814089a9-b7e1-43af-9081-25d1410e0743', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '67fc349d38a6e623b32f4b77f807e5f7', 'Listen to the Latest ‘KFF Health News Minute’', NULL, 'The "KFF Health News Minute” brings original health care and health policy reporting from our newsroom to the airwaves each week.', NULL, 'Jan. 22 Arielle Zionts reads the week&#8217;s news: Some states are cutting public funding for a type of autism therapy, and older adults are more likely than younger ones to stop taking GLP-1 drugs such as Ozempic. Jan. 15 Jackie Forti&#233;r reads the week&#8217;s news: Parents are confused by an overhaul of U.S. childhood immunization guidelines, and while people 65 and older make up the fastest-growing homeless population in the country, traditional homeless shelters often can&#8217;t accommodate them. Jan. 8 Zach Dyer reads the week&#8217;s news: Instead of extending extra Affordable Care Act subsidies that would keep monthly premiums more affordable, some Republicans are pushing health savings accounts. Plus, people seeking cheaper health insurance options outside the ACA marketplaces may find some, but they come with downsides. Jan. 1 Katheryn Houghton reads the week&#8217;s news: AI voices can help patients who have had their voice boxes removed sound like themselves again, and many state-run psychiatric hospitals don&#8217;t have enough beds to treat patients unless they&#8217;ve been charged with a crime. The KFF Health News Minute is available every Thursday on CBS News Radio. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/listen-to-the-latest-kff-health-news-minute-2026/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2023/04/2023_kffhealthnews-minute.png?w=1024', NULL, '2026-01-27 15:00:00', '2026-01-29 13:36:34.89176', 'ar', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["KFF Health News Minute", "health policy", "autism therapy", "GLP-1 drugs", "childhood immunization", "homeless population", "Affordable Care Act", "AI voices", "psychiatric hospitals"]', '{"topics": ["healthcare policy", "autism therapy funding", "elderly health", "childhood immunization guidelines", "homelessness and health", "health insurance", "AI in healthcare", "psychiatric care"], "summary": "برنامج ''KFF Health News Minute'' يقدم تقارير صحية وسياسات صحية أسبوعية عبر الإذاعة. يناقش قضايا مثل تمويل علاج التوحد، أدوية GLP-1، إرشادات التطعيم للأطفال، والتحديات الصحية للمشردين وكبار السن.", "entities": ["KFF Health News", "CBS News Radio"], "credibilityScore": 90}', '2026-01-29 13:36:34.89176', '2026-01-31 08:07:17.319');
INSERT INTO public.radar_items VALUES ('4471dae9-2703-4a47-8164-c1aee8def137', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'aa429c7c8d377702ede9679d60cffc5c', 'Medicare Advantage Insurers Face New Curbs on Overcharges in Trump Plan That Reins in Payments', NULL, 'Proposed Trump administration changes to federal Medicare Advantage payments would stop health insurers from mining patient data for extra medical diagnoses that generate more bills to taxpayers even without treatment.', NULL, 'Medicare Advantage health plans are blasting a government proposal this week that would keep their reimbursement rates flat next year while making other payment changes. But some health policy experts say the plan could help reduce billions of dollars in overcharges that have been common in the program for more than a decade. On Jan. 26, Centers for Medicare & Medicaid Services officials announced they planned to raise rates paid to health plans by less than a tenth of a percent for 2027, far less than the industry expected. Some of the largest, publicly traded insurers, such as UnitedHealth Group and Humana, saw their stock prices plummet as a result, while industry groups threatened that people 65 and older could see service cuts if the government didn&#8217;t kick in more money. In Medicare Advantage, the federal government pays private insurance companies to manage health care for people who are 65 and older or disabled. But less noticed in the brouhaha over rates: CMS also proposed restricting plans from conducting what are called &#8220;chart reviews&#8221; of their customers. These reviews can result in new medical diagnoses, sometimes including conditions patients haven&#8217;t even asked their doctors to treat, that increase government payments to Medicare Advantage plans. The practice has been criticized for more than a decade by government auditors who say it has triggered billions of dollars in overpayments to the health plans. Earlier this month, the Justice Department announced a record $556 million settlement with the nonprofit health system Kaiser Permanente over allegations the company added about half a million diagnoses to its Advantage patients&#8217; charts from 2009 to 2018, generating about $1 billion in improper payments. KP did not admit any wrongdoing as part of the settlement. &#8220;I do think the administration is serious about cracking down on overpayments,&#8221; said Spencer Perlman, a health care policy analyst in Bethesda, Maryland. Perlman said that while the Trump administration strongly supports Medicare Advantage, officials are &#8220;troubled&#8221; by plans that rake in undue profits by using chart reviews to bill the government for medical conditions even when no treatment was provided. In a news release, CMS Administrator Mehmet Oz said curbing this practice would ensure more accurate payments to the plans while &#8220;protecting taxpayers from unnecessary spending that is not oriented towards addressing real health needs.&#8221; &#8220;These proposed payment policies are about making sure Medicare Advantage works better for the people it serves,&#8221; Oz said. Richard Kronick, a former federal health policy researcher and a professor at the University of California-San Diego, called the proposal &#8220;at least a mildly encouraging sign,&#8221; though he said he suspected health plans might eventually find a way around it. Kronick has argued that switching seniors to Medicare Advantage plans has cost taxpayers tens of billions of dollars more than keeping them in the government-run Medicare program, because of unbridled medical coding excesses. The insurance plans have grown dramatically in recent years and now enroll about 34 million members, or more than half of people eligible for Medicare. David Meyers, an associate professor at the Brown University School of Public Health, called the proposed restriction on chart reviews &#8220;a step in the right direction.&#8221; &#8220;I think the administration has been signaling pretty strongly they want to cut back on inefficiencies,&#8221; he said. The outcry from industry, mostly directed at the proposal to essentially hold Medicare Advantage payment rates flat, was quick and sharp. &#8220;If finalized, this proposal could result in benefit cuts and higher costs for 35 million seniors and people with disabilities when they renew their Medicare Advantage coverage in October 2026,&#8221; said Chris Bond, a spokesperson for AHIP, formerly known as America&#8217;s Health Insurance Plans. CMS is accepting public comments on the proposal and says it will issue a final decision on the payment rates and other provisions by early April. Meyers said health plans often claim they will be forced to slash benefits when they aren&#8217;t satisfied with CMS payments. But that rarely happens, he said. &#8220;The plans can still make money,&#8221; he said. &#8220;They mostly are very profitable, just not as profitable as shareholders expected.&#8221; The government pays Medicare Advantage plans higher rates to cover sicker patients. But over the past decade, dozens of whistleblower lawsuits, government audits, and other investigations have alleged that health plans exaggerate how sick their customers are to pocket payments they don&#8217;t deserve, a tactic known in the industry as &#8220;upcoding.&#8221; Many Medicare Advantage health plans have hired medical coding and analytics consultants to review patients&#8217; medical charts to find new diagnoses that they then bill to the government. Medicare rules require that health plans document — and treat — all medical conditions they bill. Yet federal audits have shown for years that many health plans&#8217; billing practices don&#8217;t hold up to scrutiny. A December 2019 report by the Department of Health and Human Services inspector general found that the health plans &#8220;almost always&#8221; used chart reviews to add, rather than delete, diagnoses. &#8220;Over 99 percent of chart reviews in our review added diagnoses,&#8221; investigators said. The report found that diagnoses reported only on chart reviews — and not on any service records — resulted in an estimated $6.7 billion in payments for 2017. This week&#8217;s proposal is not the first time CMS has tried to crack down on chart reviews. In January 2014, federal officials drafted a plan to restrict the practice, only to abruptly back off a few months later amid what one agency official described as an &#8220;uproar&#8221; from the industry. The health insurance industry has for years relied on aggressive lobbying and public relations campaigns to fight efforts to rein in overpayments or otherwise reduce taxpayers&#8217; costs for Medicare Advantage. What happens this time will say a lot about whether the Trump administration is serious about cracking down on controversial, long-standing payment practices in the program. Perlman, the policy analyst, said it is &#8220;quite common&#8221; for CMS to partially backtrack when faced with opposition from the industry, such as by phasing in changes over several years to soften the blow on health plans. David Lipschutz, an attorney with the Center for Medicare Advocacy, a nonprofit public interest law firm, said finalizing the chart review proposal &#8220;would be a meaningful step towards reining in overpayments to Medicare Advantage plans.&#8221; But in the past, he said, even a minor change to Advantage payments has led the industry to protest that &#8220;the sky will fall as a result, and the proposal is usually dropped.&#8221; &#8220;It&#8217;s hard to tell at this stage how this will play out,&#8221; Lipschutz said. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/medicare-advantage-overcharging-chart-reviews-trump-federal-rate-hike/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2205908047-DHS_CMS.jpg?w=1024', 'Fred Schulte, KFF Health News', '2026-01-29 10:00:00', '2026-01-29 13:36:34.641205', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["Medicare Advantage", "Trump administration", "health insurers", "overcharges", "CMS", "chart reviews", "health policy"]', '{"topics": ["Medicare policy changes", "health insurance overpayments", "government healthcare regulations"], "summary": "تسعى إدارة ترامب إلى فرض قيود جديدة على مدفوعات Medicare Advantage للحد من المبالغ الزائدة التي يتم تحصيلها من خلال تشخيصات طبية إضافية. تشمل التغييرات المقترحة منع شركات التأمين من إجراء مراجعات للملفات الطبية التي تزيد من المدفوعات الحكومية دون تقديم علاج فعلي.", "entities": ["Trump administration", "Centers for Medicare & Medicaid Services (CMS)", "UnitedHealth Group", "Humana", "Kaiser Permanente", "Spencer Perlman"], "credibilityScore": 90}', '2026-01-29 13:36:34.641205', '2026-01-31 08:07:23.36');
INSERT INTO public.radar_items VALUES ('f3396ec1-8f7b-45c0-be15-6e8defd85ea1', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'f360dde0e8b85b7b6d20c17c4e49308c', 'Doctors Increasingly See AI Scribes in a Positive Light. But Hiccups Persist.', NULL, 'Patients say they find AI summaries of doctor visits user-friendly, but it’s not clear if their appointments are improving. In any case, doctors appear to be embracing the high-tech innovation.', NULL, 'When Jeannine Urban went in for a checkup in November, she had her doctor&#8217;s full attention. Instead of typing on her computer keyboard during the exam, Urban&#8217;s primary care physician at the Penn Internal Medicine practice in Media, Pennsylvania, had an ambient artificial intelligence scribe take notes. At the end of the 30-minute visit, Urban&#8217;s doctor showed her the AI summary of the appointment, neatly organized into sections for her medical history, the physical exam findings, and an assessment and treatment plan for her rheumatoid arthritis and hot flashes, among other details. The clinical note, which Urban could also review on the patient portal at home, was incredibly thorough, she said. It summarized all of her questions and concerns and the doctor&#8217;s responses. The scribe &#8220;made sure we didn&#8217;t miss anything,&#8221; Urban said. Ambient AI scribes are being hailed by physicians as a game changer that helps free them to focus on their patients rather than their computer keyboard. By releasing doctors from the onerous and time-consuming task of documenting what happens during every patient encounter, early studies show, AI scribes may help reduce physician burnout and after-hours &#8220;pajama time&#8221; catching up on work in the evening. The potential of AI to transform every aspect of the health care system — from patient care to clinical efficiency to medical innovation — is an area of intense focus, including by the Trump administration. Last January, President Donald Trump issued an executive order to remove barriers to American leadership in AI. Later in the year, a press release from the federal Department of Health and Human Services invited stakeholders to weigh in on how the department can accelerate the adoption of AI in health care. Several startup vendors in recent years have introduced ambient AI scribe products that can be integrated into electronic health records. EHR market leader Epic is piloting its own AI scribe technology, which it expects to release widely early this year, according to Jackie Gerhart, a family medicine physician who is chief medical officer and vice president of clinical informatics at Epic. Health tech experts estimate that a third of providers have access to ambient AI scribe technology. As adoption looks likely to grow rapidly over the next few years, many expect it to become more of a recruiting tool, a minimum requirement for incoming clinicians, who reports indicate are increasingly prioritizing work-life balance. &#8220;It&#8217;s part of keeping doctors happy,&#8221; said Robert Wachter, a professor and the chair of the Department of Medicine at the University of California-San Francisco, whose forthcoming book, A Giant Leap, explores how AI is transforming health care. &#8220;Health systems that initially might have done a hard-nosed return-on-investment calculation — many are softening on that and realizing that the cost of recruiting and retaining doctors is pretty high.&#8221; But many questions remain. Does the use of ambient AI scribes improve patient care and health outcomes? Will doctors use time they gain by employing an AI scribe to improve the quality of the time they spend with their patients or just boost the number of patients they see? To what extent will expanding the amount of detail available from a patient visit lead to bigger bills if the AI scribe is integrated with a coding app that optimizes provider charges? For now, these questions remain mostly unanswered. Urban said that the AI scribe didn&#8217;t change her experience as a patient very much. Typically, after a patient gives verbal permission, the AI scribe records the visit on a phone and organizes the conversation into the structure of a clinical note, filtering out small talk that isn&#8217;t pertinent to the medical visit but incorporating relevant details about a family member&#8217;s recent cancer diagnosis, for example. The scribe&#8217;s note is often then integrated into the provider&#8217;s EHR. The doctor later reviews the note and signs off on it. Even though the visit may not feel very different to patients, some clinicians report that ambient AI scribes are changing patient encounters in unanticipated ways. &#8220;Now, when I&#8217;m doing a physical exam, I have to say what I&#8217;m doing and what I&#8217;m finding out loud in order for the AI scribe to document it,&#8221; said Dina Capalongo, Urban&#8217;s primary care doctor. &#8220;People find that very interesting,&#8221; she said. When Capalongo places her stethoscope over the carotid artery under a patient&#8217;s jaw, for example, she might say that she doesn&#8217;t hear a &#8220;bruit,&#8221; or vascular murmur, whose presence could indicate atherosclerosis. Patients have told her, &#8220;I never knew why a doctor would listen there,&#8221; she said. Saying things out loud for the AI scribe that would typically appear only in a clinical note can create its own set of challenges, particularly during sensitive physical exams. Doctors may feel it&#8217;s important to adjust their conversation accordingly. &#8220;Sometimes patients are anxious and scared and my saying things that they don&#8217;t understand or they may worry about during an uncomfortable examination does not help the situation and honestly is insensitive to what the patient is going through,&#8221; said Genevieve Melton-Meaux, a professor in the Division of Colon and Rectal Surgery at the University of Minnesota, who is also chief health informatics and AI officer at Fairview Health Services in Minneapolis. &#8220;I&#8217;ll keep that top of mind and make sure I record it&#8221; after the visit. &#8220;How we have conversations with patients about these tools is really important, in particular for maintaining trust and ensuring accurate information,&#8221; Melton-Meaux said. Studies have found that, across a range of measures such as completeness, timeliness, and coherence, the notes created by ambient AI scribes are generally at least as good as, and sometimes better than, traditional documentation, said Kevin Johnson, a pediatrician who is vice president for applied informatics at the University of Pennsylvania Health System. An ongoing concern is around AI &#8220;hallucinations,&#8221; in which false, sometimes fabricated information appears in an AI output. Kaiser Permanente, an early adopter of ambient AI scribe technology, provides it to more than 25,000 doctors, advanced practice providers, and pharmacists systemwide. It has found hallucinations to be &#8220;quite rare,&#8221; said Daniel Yang, an internist who is vice president of AI and emerging technologies at KP. But they happen. An AI-scribe-generated note, for instance, might say that the doctor planned to refer someone to a neurologist or to follow up in two weeks. The problem? The doctor might not have said that. &#8220;The technology is not perfect, and that&#8217;s why physicians are reviewing it,&#8221; Yang said. It&#8217;s learning from regular physician visits as it goes, he said. That&#8217;s why having a person check the work product is critical. Still, even such a &#8220;human-in-the loop&#8221; system is fraught, Wachter said. &#8220;Humans stink at maintaining vigilance over time,&#8221; he said. As the use of ambient AI scribes becomes routine, some clinicians worry that the technology will widen the divide between health care haves and have-nots. Large health systems are able to move forward with the technology, Melton-Meaux said. But what about critical access hospitals or small private practices? &#8220;There need to be more resources,&#8221; she said. Physicians&#8217; enthusiasm for ambient AI scribes stands in sharp contrast to their negative reaction to electronic health record systems that have become widely adopted in recent years to replace paper charts. &#8220;During the last 10 years, when EHRs became a thing, we all became very grumpy, overworked data scribes,&#8221; Wachter said. The introduction of AI scribes makes physicians feel like technology is working for them rather than the other way around, health care AI experts said. And AI scribes are &#8220;training wheels&#8221; for more consequential adoption of AI in health care, Wachter said. To improve health care value and save costs, Wachter said, we need a system that makes it more likely that physicians will practice evidence-based medicine to order the right tests and prescribe the right medications. &#8220;It&#8217;s a few years away, but it&#8217;s all AI-dependent,&#8221; he said. Epic has introduced roughly 60 AI use cases for patients, clinicians, and administration, with over 100 more in the works. &#8220;It&#8217;s so much bigger than a scribe,&#8221; said Epic&#8217;s Gerhart. &#8220;It&#8217;s literally listening and acting in a way that tees things up for me so that I can take action.&#8221; KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/ambient-ai-scribes-doctor-appointments-note-taking-ehr-epic/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2034703933-resized.jpg?w=1024', 'Michelle Andrews', '2026-01-27 10:00:00', '2026-01-29 13:36:35.143394', 'ar', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["AI scribes", "physician burnout", "healthcare technology", "patient care", "electronic health records"]', '{"topics": ["Artificial Intelligence in healthcare", "Physician efficiency", "Patient experience"], "summary": "الأطباء يبدون اهتمامًا متزايدًا باستخدام الذكاء الاصطناعي لتوثيق المواعيد الطبية، مما يتيح لهم التركيز بشكل أكبر على المرضى. ومع ذلك، لا تزال هناك تحديات في تحسين تجربة المرضى بشكل كامل.", "entities": ["Jeannine Urban", "Penn Internal Medicine", "Donald Trump", "Epic", "Department of Health and Human Services"], "credibilityScore": 90}', '2026-01-29 13:36:35.143394', '2026-01-31 08:07:08.464');
INSERT INTO public.radar_items VALUES ('f892b607-1b97-4107-93c2-7232ec13748e', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'a7b6ef5182b210f998ca2827201884b3', 'Trump Policies at Odds With Emerging Understanding of Covid’s Long-Term Harm', NULL, 'Studies increasingly offer insights into the health risks and burdens faced by people who have had covid infections. Meanwhile, the Trump administration has narrowed covid vaccine recommendations and cut research.', NULL, 'Possible risk of autism in children. Dormant cancer cells awakening. Accelerating aging of the brain. Federal officials in May 2023 declared an end to the national covid pandemic. But more than two years later, a growing body of research continues to reveal information about the virus and its ability to cause harm long after initial infections resolve, even in some cases when symptoms were mild. The discoveries raise fresh concerns about the Trump administration&#8217;s covid policies, researchers say. While some studies show covid vaccines offer protective benefits against longer-term health effects, the Department of Health and Human Services has drastically limited recommendations about who should get the shot. The administration also halted Biden-era contracts aimed at developing more protective covid vaccines. The federal government is curtailing such efforts just as researchers call for more funding and, in some cases, long-term monitoring of people previously infected. &#8220;People forget, but the legacy of covid is going to be long, and we are going to be learning about the chronic effects of the virus for some time to come,&#8221; said Michael Osterholm, an epidemiologist who directs the University of Minnesota&#8217;s Center for Infectious Disease Research and Policy. The Trump administration said that the covid vaccine remains available and that individuals are encouraged to talk with their health providers about what is best for them. The covid vaccine and others on the schedule of the Centers for Disease Control and Prevention remain covered by insurance so that individuals don&#8217;t need to pay out-of-pocket, officials said. &#8220;Updating CDC guidance and expanding shared clinical decision-making restores informed consent, centers parents and clinicians, and discourages ‘one size fits all&#8217; policies,&#8221; said HHS spokesperson Emily Hilliard. Although covid has become less deadly, because of population immunization and mutations making the virus less severe, researchers say the politicization around the infection is obscuring what science is increasingly confirming: covid&#8217;s potential to cause unexpected, possibly chronic health issues. That in turn, these scientists say, drives the need for more, rather than less, research, because over the long term, covid could have significant economic and societal implications, such as higher health care costs and more demands on social programs and caregivers. The annual average burden of the disease&#8217;s long-term health effects is estimated at $1 trillion globally and $9,000 per patient in the U.S., according to a report published in November in the journal NPJ Primary Care Respiratory Medicine. In this country, the annual lost earnings are estimated to be about $170 billion. One study estimates that the flu resulted in $16 billion in direct health costs and $13 billion in productivity losses in the 2023-2024 season, according to a Dec. 30 report in medRxiv, an online platform that publishes work not yet certified by peer review. Covid&#8217;s Growing Reach Much has been learned about covid since the virus emerged in 2019, unleashing a pandemic that the World Health Organization reports has killed more than 7 million people. By the spring of 2020, the term &#8220;long covid&#8221; had been coined to describe chronic health problems that can persist post-infection. More recent studies show that infection by the virus that causes covid, SARS-CoV-2, can result in heightened health risks months to more than a year later. For example, researchers following children born to mothers who contracted the virus while pregnant have discovered they may have an increased risk for autism, delayed speech and motor development, or other neurodevelopmental challenges. Another study found babies exposed to covid in utero experienced accelerated weight gain in their first year, a possible harbinger of metabolic issues that could later carry an increased risk for cardiovascular disease. These studies suggest avoiding severe covid in pregnancy may reduce risk not just during pregnancy but for future generations. That may be another good reason to get vaccinated when pregnant. &#8220;There are other body symptoms apart from the developing fetal brain that also may be impacted,&#8221; said Andrea Edlow, an associate professor of obstetrics, gynecology, and reproductive biology at Harvard Medical School who was involved in both studies. &#8220;We definitely need more research.&#8221; Epidemiologists point to some specific, emerging challenges. A U.K. study in the New England Journal of Medicine found people who fully recovered from mild covid infections experienced a cognitive deficit equal to a three-point drop in IQ. Among the more than 100,000 participants, deficits were greater in people who had persistent symptoms and reached the equivalent of a nine-point IQ drop for individuals admitted to intensive care. Ziyad Al-Aly, a clinical epidemiologist who has studied longer-term health effects from covid, did the math. He estimated covid may have increased the number of adults in the U.S. with an IQ of less than 70 from 4.7 million to 7.5 million — a jump of 2.8 million adults dealing with &#8220;a level of cognitive impairment that requires significant societal support,&#8221; he wrote. &#8220;People get covid-19, some people do fine and bounce back, but there are people who start experiencing problems with memory, cognition, and fuzzy brain,&#8221; he said. &#8220;Even people with mild symptoms. They might not even be aware.&#8221; Diane Yormark, 67, of Boca Raton, Florida, can relate. She got covid in 2022 and 2023. The second infection left her with brain fog and fatigue. &#8220;I felt like if you had a little bit too much wine the night before and you&#8217;re out of it,&#8221; said Yormark, a retired copywriter, who said the worst of her symptoms lasted for about three months after the infection. &#8220;Some of the fog has lifted. But do I feel like myself? Not like I was.&#8221; Data from more than a dozen studies suggests covid vaccines can help reduce risk of severe infection as well as longer-lasting health effects, although researchers say more study is needed. But vaccination rates remain low in the U.S., with only about 17% of the adult population reporting that they got the updated 2025-2026 shot as of Jan. 16, based on CDC data. Trump administration officials led by Health and Human Services Secretary Robert F. Kennedy Jr. have reduced access to covid vaccines despite the lack of any new, substantiated evidence of harm. Though the shots were a hallmark achievement of the first Trump administration, which led the effort for their development, Kennedy has said without evidence that they are &#8220;the deadliest vaccine ever made.&#8221; In May he said on X that the CDC would stop recommending covid shots for healthy children and pregnant women, citing a lack of clinical data. The Food and Drug Administration has since issued new guidelines limiting the vaccine to people 65 or older and individuals 6 months or older with at least one risk factor, though many states continue to make them more widely available. The Trump administration also halted almost $500 million in funding for mRNA-based vaccines. Administration officials and a number of Republicans question the safety of the Nobel Prize-winning technology — heralded for the potential to treat many diseases beyond covid — even though clinical trials with tens of thousands of volunteers were performed before the covid mRNA vaccines were made available to the public. And numerous studies, including new research in 2025, show covid vaccine benefits include a reduction in the severity of disease, although the protective effects wane over time. Following the Findings Researchers say more and broader support is important because much remains unknown about covid and its impact on the body. The growing awareness that, even in mild covid cases, the possibility exists for longer-term, often undetected organ damage also warrants more examination, researchers say. A study published this month in eBioMedicine found people with neurocognitive issues such as changes in smell or headaches after infection had significant levels of a protein linked to Alzheimer&#8217;s in their blood plasma. EBioMedicine is a peer-reviewed, open-access journal published by The Lancet. In the brain, the virus leads to an immune response that triggers inflammation, can damage brain cells, and can even shrink brain volume, according to research on imaging studies that was published in March 2022 in the journal Nature. An Australian study of advanced brain images found significant alterations even among people who had already recovered from mild infections — a possible explanation for cognitive deficits that may persist for years. Lead study author Kiran Thapaliya said the research suggests the virus &#8220;may leave a silent, lasting effect on brain health.&#8221; Al-Alay agreed. &#8220;We don&#8217;t know what will happen to people 10 years down the road,&#8221; he said. &#8220;Inflammation of the brain is not a good thing. It&#8217;s absolutely not a good thing.&#8221; That inflammatory response has also been linked to blood clots, arrhythmias, and higher risk of cardiovascular issues, even following a mild infection. A University of Southern California study published in October 2024 in the journal Arteriosclerosis, Thrombosis, and Vascular Biology found the risk for a major cardiac event remains elevated nearly three years after covid infection. The findings held even for people who were not hospitalized. &#8220;We were surprised to see the effects that far out&#8221; regardless of individual heart disease history, said James R. Hilser, the study&#8217;s lead author and a postdoctoral fellow at the UCLA David Geffen School of Medicine. Covid can also reactivate cancer cells and trigger a relapse, according to research published in July in the journal Nature. Researchers found that the chance of dying from cancer among cancer survivors was higher among people who&#8217;d had covid, especially in the year after being infected. There was nearly a twofold increase in cancer mortality in those who tested positive compared with those who tested negative. The potential of the covid virus to affect future generations is yielding new findings as well. Australian researchers looked at male mice and found that those who had been infected with and then recovered from covid experienced changes to their sperm that altered their offspring&#8217;s behavior, causing them to exhibit more anxiety. Meanwhile, many people are now living — and struggling — with the virus&#8217; after-effects. Dee Farrand, 57, of Marana, Arizona, could once run five miles and was excelling at her job in sales. She recovered from a covid infection in May 2021. Two months later, her heart began to beat irregularly. Farrand underwent a battery of tests at a hospital. Ultimately, the condition became so severe she had to go on supplemental oxygen for two years. Her cognitive abilities declined so severely she couldn&#8217;t read, because she&#8217;d forget the first sentence after reading the second. She also had to leave herself reminders that she is allergic to shrimp or that she likes avocados. She said she lost her job and returned to her previous occupation as a social worker. &#8220;I was the person who is like the Energizer bunny and all of a sudden I&#8217;d get so tired getting dressed that I had to go back to bed,&#8221; Farrand said. While she is better, covid has left a mark. She said she&#8217;s not yet able to run the five miles she used to do without any problems. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/covid-long-term-effects-risks-trump-policies-vaccines-research-hhs-rfk/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2206524485-covid-research.jpg?w=1024', 'Stephanie Armour', '2026-01-27 10:00:00', '2026-01-29 13:36:35.018626', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["Covid-19", "long-term effects", "Trump policies", "vaccines", "health risks"]', '{"topics": ["Covid-19 long-term health impacts", "vaccine policy", "public health research"], "summary": "أبحاث جديدة تكشف عن آثار طويلة الأمد لفيروس كوفيد-19، بما في ذلك تأثيرات محتملة على الدماغ والجهاز العصبي. في المقابل، تواجه سياسات إدارة ترامب انتقادات لتقليص توصيات اللقاح وتمويل الأبحاث المتعلقة بالفيروس.", "entities": ["Trump administration", "Michael Osterholm", "University of Minnesota", "Department of Health and Human Services", "Centers for Disease Control and Prevention"], "credibilityScore": 80}', '2026-01-29 13:36:35.018626', '2026-01-31 08:07:11.478');
INSERT INTO public.radar_items VALUES ('26f741ee-e1eb-49bc-8637-f768d932ec40', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'db736a8fd0dadc17f665b8a4ab327656', 'Cada vez más médicos ven con buenos ojos a los asistentes de IA. Pero aún hay tropiezos', NULL, 'Los médicos están considerando a estos asistentes de IA ambiental como una herramienta revolucionaria que les permite concentrarse en sus pacientes en lugar de en el teclado.', NULL, 'Cuando Jeannine Urban fue a un chequeo m&#233;dico en noviembre, tuvo toda la atenci&#243;n de su doctora. En lugar de teclear en su computadora durante la consulta, la m&#233;dica de atenci&#243;n primaria de Urban, en la pr&#225;ctica Penn Internal Medicine en Media, Pennsylvania, us&#243; un asistente de inteligencia artificial (IA) conocido como ambiental para tomar notas. Al final de los 30 minutos de la visita, la doctora le mostr&#243; a Urban el resumen que gener&#243; el programa: un documento claramente organizado por secciones con su historial m&#233;dico, los hallazgos del examen f&#237;sico y un plan de evaluaci&#243;n y tratamiento para su artritis reumatoide y los sofocos, entre otros detalles. La nota cl&#237;nica —que Urban tambi&#233;n pudo revisar m&#225;s tarde en el portal para pacientes— fue incre&#237;blemente detallada, dijo. Resum&#237;a todas sus preguntas y preocupaciones, as&#237; como las respuestas de la doctora. El asistente &#8220;se asegur&#243; de que no se nos pasara nada&#8221;, dijo Urban. Los m&#233;dicos est&#225;n considerando a estos asistentes de IA ambiental como una herramienta revolucionaria que les permite concentrarse en sus pacientes en lugar de en el teclado. Estudios preliminares indican que, al liberar a los doctores de la tarea tediosa y que consume tiempo, de documentar cada encuentro con un paciente, estos asistentes podr&#237;an ayudar a reducir el agotamiento profesional y el llamado &#8220;tiempo en pijama&#8221;: horas extra en casa para ponerse al d&#237;a con el trabajo. El potencial de la inteligencia artificial para transformar todos los aspectos del sistema de salud —desde la atenci&#243;n directa hasta la eficiencia cl&#237;nica y la innovaci&#243;n m&#233;dica— es un tema de gran inter&#233;s, incluso dentro de la administraci&#243;n Trump. En enero de 2025, el presidente Donald Trump emiti&#243; una orden ejecutiva para eliminar barreras al liderazgo estadounidense en inteligencia artificial. M&#225;s tarde ese mismo a&#241;o, el Departamento de Salud y Servicios Humanos (HHS, por sus siglas en ingl&#233;s) public&#243; un comunicado invitando a distintos sectores a opinar sobre c&#243;mo acelerar la adopci&#243;n de la IA en el sistema de salud. En los &#250;ltimos a&#241;os, varias empresas emergentes han lanzado asistentes de IA ambiental que pueden integrarse a los registros m&#233;dicos electr&#243;nicos (EHR, por sus siglas en ingl&#233;s). Epic, el proveedor l&#237;der del mercado de EHR, est&#225; probando su propia tecnolog&#237;a de asistente de IA, que planea lanzar de forma m&#225;s amplia a principios de este a&#241;o, seg&#250;n Jackie Gerhart, m&#233;dica de medicina familiar, directora m&#233;dica y vicepresidenta de inform&#225;tica cl&#237;nica en Epic. Expertos en tecnolog&#237;a estiman que un tercio de los proveedores ya tiene acceso a esta tecnolog&#237;a. A medida que su adopci&#243;n se acelera, muchos anticipan que se convertir&#225; en una herramienta de reclutamiento, un requisito b&#225;sico para nuevos profesionales cl&#237;nicos, quienes, indican informes, cada vez valoran m&#225;s el equilibrio entre vida laboral y personal. &#8220;Es parte de mantener felices a los m&#233;dicos&#8221;, dijo Robert Wachter, profesor y jefe del Departamento de Medicina en la Universidad de California en San Francisco. Su pr&#243;ximo libro, A Giant Leap, explora c&#243;mo la IA est&#225; transformando la atenci&#243;n de salud. &#8220;Muchos sistemas de salud que inicialmente hac&#237;an c&#225;lculos estrictos sobre el retorno de la inversi&#243;n ahora est&#225;n flexibilizando su postura y reconociendo que el costo de contratar y retener m&#233;dicos es bastante alto&#8221;. Pero a&#250;n hay muchas preguntas. ¿Mejora la atenci&#243;n m&#233;dica y los resultados en salud el uso de asistentes de IA ambiental? ¿Usar&#225;n los m&#233;dicos el tiempo que ganan para ofrecer mejor atenci&#243;n o solo para ver a m&#225;s pacientes? ¿Hasta qu&#233; punto podr&#237;a aumentar el costo de una consulta si el asistente de IA se conecta a un sistema de codificaci&#243;n que optimiza los cobros? Por ahora, estas preguntas siguen sin respuesta. El papel del asistente Urban dijo que la presencia del asistente de IA no cambi&#243; mucho su experiencia como paciente. Normalmente, luego de tener el permiso verbal del paciente, el asistente graba la visita con un tel&#233;fono y organiza la conversaci&#243;n en el formato de una nota cl&#237;nica, omitiendo los comentarios sin relevancia m&#233;dica, pero incluyendo informaci&#243;n importante como el diagn&#243;stico reciente de c&#225;ncer de un familiar, por ejemplo. La nota del asistente suele integrarse en la Historia Cl&#237;nica Electr&#243;nica (HCE) del proveedor. Luego, el m&#233;dico revisa y firma el documento. Aunque para los pacientes la consulta puede no sentirse muy diferente, algunos profesionales aseguran que los asistentes de IA ambiental est&#225;n cambiando los encuentros con los pacientes de formas inesperadas. &#8220;Ahora, cuando hago un examen f&#237;sico, tengo que decir en voz alta lo que estoy haciendo y lo que estoy encontrando para que el asistente lo documente&#8221;, dijo Dina Capalongo, la m&#233;dica de atenci&#243;n primaria de Urban. &#8220;A la gente le parece muy interesante&#8221;, a&#241;adi&#243;. Por ejemplo, cuando Capalongo coloca su estetoscopio sobre la arteria car&#243;tida, debajo de la mand&#237;bula de un paciente, puede decir en voz alta que no escucha un &#8220;soplo&#8221;, un sonido vascular que puede indicar aterosclerosis. Los pacientes le han dicho: &#8220;Nunca supe por qu&#233; un m&#233;dico escuchaba ah&#237;&#8221;. Decir en voz alta cosas que normalmente solo estar&#237;an en la nota cl&#237;nica puede representar un desaf&#237;o, especialmente durante ex&#225;menes f&#237;sicos delicados. Algunos m&#233;dicos consideran importante adaptar la conversaci&#243;n seg&#250;n el contexto. &#8220;Hay pacientes que est&#225;n ansiosos o asustados, y que yo diga cosas que no entienden, o que les pueden preocupar durante un examen inc&#243;modo, no ayuda y, la verdad, es insensible frente a lo que est&#225;n viviendo&#8221;, dijo Genevieve Melton-Meaux, profesora de la Divisi&#243;n de Cirug&#237;a de Colon y Recto en la Universidad de Minnesota, y directora de inform&#225;tica en salud e inteligencia artificial en Fairview Health Services, en Minneapolis. &#8220;Tengo eso muy presente y me aseguro de registrarlo despu&#233;s de la consulta&#8221;. &#8220;La manera en que hablamos con los pacientes sobre estas herramientas es muy importante, especialmente para mantener la confianza y asegurar que la informaci&#243;n sea precisa&#8221;, a&#241;adi&#243; Melton-Meaux. Notas m&#225;s completas, pero con desaf&#237;os Seg&#250;n Kevin Johnson, pediatra y vicepresidente de inform&#225;tica aplicada en el sistema de salud de la Universidad de Pennsylvania, estudios han encontrado que, en aspectos como integridad, claridad y puntualidad, las notas creadas por asistentes de IA ambiental son generalmente tan buenas como —y a veces mejores que— las notas tradicionales. Sin embargo, persiste la preocupaci&#243;n por las llamadas &#8220;alucinaciones&#8221; de la IA, cuando la herramienta genera informaci&#243;n falsa o inventada. Kaiser Permanente, una de las primeras organizaciones en adoptar esta tecnolog&#237;a, la ha puesto a disposici&#243;n de m&#225;s de 25.000 m&#233;dicos, profesionales avanzados y farmac&#233;uticos en todo su sistema. Seg&#250;n Daniel Yang, internista y vicepresidente de IA y tecnolog&#237;as emergentes en Kaiser, las alucinaciones &#8220;son bastante raras&#8221;. Pero ocurren. Por ejemplo, una nota generada por IA podr&#237;a indicar que el m&#233;dico planea derivar a un paciente a neurolog&#237;a o hacer un seguimiento en dos semanas, cuando en realidad eso nunca se dijo. &#8220;La tecnolog&#237;a no es perfecta, y por eso los m&#233;dicos la revisan&#8221;, se&#241;al&#243; Yang. El sistema aprende de las consultas m&#233;dicas habituales, agreg&#243;. Por eso es clave que una persona verifique el contenido generado. Aun as&#237;, incluso ese modelo de &#8220;humano editando&#8221; tiene sus limitaciones, dijo Wachter. &#8220;Los humanos no somos buenos para mantener la vigilancia constante&#8221;, afirm&#243;. ¿Mayor desigualdad tecnol&#243;gica? A medida que el uso de estos asistentes se vuelve m&#225;s com&#250;n, algunas personas en el sector temen que la tecnolog&#237;a profundice la brecha entre quienes tienen acceso y quienes no. Los grandes sistemas de salud pueden avanzar con estas tecnolog&#237;as, dijo Melton-Meaux. &#8220;¿Pero qu&#233; pasa con los hospitales rurales o los consultorios peque&#241;os? Se necesitan m&#225;s recursos&#8221;. El entusiasmo por los asistentes de IA contrasta con la frustraci&#243;n generalizada que causaron los registros m&#233;dicos electr&#243;nicos cuando se implementaron hace una d&#233;cada para reemplazar los historiales en papel. &#8220;Durante los &#250;ltimos 10 a&#241;os, cuando se adoptaron los HCE, todos nos convertimos en escribas gru&#241;ones y sobrecargados&#8221;, record&#243; Wachter. Con la llegada de los asistentes de IA, los m&#233;dicos sienten que la tecnolog&#237;a ahora trabaja para ellos, y no al rev&#233;s, seg&#250;n expertos en IA aplicada a la salud. Adem&#225;s, estos asistentes funcionan como &#8220;entrenamiento&#8221; para una adopci&#243;n m&#225;s amplia de la inteligencia artificial en la atenci&#243;n m&#233;dica, se&#241;al&#243; Wachter. Para mejorar el valor del sistema de salud y reducir costos, explic&#243;, necesitamos un sistema que aumente las probabilidades de que los m&#233;dicos ejerzan una medicina basada en evidencia, ordenando los estudios adecuados y recetando los medicamentos correctos. &#8220;Eso a&#250;n est&#225; a unos a&#241;os de distancia, pero depender&#225; totalmente de la IA&#8221;, dijo. Epic ha desarrollado alrededor de 60 herramientas de IA para pacientes, profesionales cl&#237;nicos y la administraci&#243;n, y tiene m&#225;s de 100 en desarrollo. &#8220;Esto es mucho m&#225;s que un asistente&#8221;, dijo Gerhart, de Epic. &#8220;Literalmente escucha y act&#250;a de una manera que me prepara todo para que yo pueda tomar decisiones&#8221;. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/cada-vez-mas-medicos-ven-con-buenos-ojos-a-los-asistentes-de-ia-pero-aun-hay-tropiezos/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2034703933-resized.jpg?w=1024', 'Michelle Andrews', '2026-01-27 09:59:00', '2026-01-29 13:36:35.522699', 'ar', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["الذكاء الاصطناعي", "الأطباء", "التكنولوجيا الصحية", "الاحتراق الوظيفي", "الملاحظات الطبية"]', '{"topics": ["الذكاء الاصطناعي في الطب", "تحسين تجربة المرضى", "تقليل الإجهاد المهني للأطباء"], "summary": "يتزايد استخدام الأطباء لمساعدي الذكاء الاصطناعي لتحسين تجربة المرضى وتقليل الإجهاد المهني. تُظهر الدراسات أن هذه التقنية تساعد الأطباء على التركيز على المرضى بدلاً من الأعمال الكتابية.", "entities": ["Jeannine Urban", "Penn Internal Medicine", "Donald Trump"], "credibilityScore": 80}', '2026-01-29 13:36:35.522699', '2026-01-31 08:07:02.546');
INSERT INTO public.radar_items VALUES ('b6746707-695c-4ad7-9979-b98483f25ed1', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '6e75307a679ee2d3452d2ed658e0b0dc', 'Nearly Half of U.S. Adults Will Have Obesity by 2035. What Can Be Done?', NULL, 'Obesity rates in the U.S. are projected to rise over the next decade, but lifestyle strategies that may help reverse the trend. Robert DEYRAIL/Gamma-Rapho via Getty Images Researchers predict that the obesity rate among U.S. adults will rise to 47% of the population by 2035. They say the increases will be particularly significant among certain ethnicities as well as certain ages. Experts say this trend can be reversed if people are educated about lifestyle changes and healthy food is made more a', NULL, 'Obesity rates in the U.S. are projected to rise over the next decade, but lifestyle strategies that may help reverse the trend. Robert DEYRAIL/Gamma-Rapho via Getty Images Researchers predict that the obesity rate among U.S. adults will rise to 47% of the population by 2035. They say the increases will be particularly significant among certain ethnicities as well as certain ages. Experts say this trend can be reversed if people are educated about lifestyle changes and healthy food is made more accessible. A new report predicts that close to half of U.S. adults will be diagnosed with obesity a decade from now. The analysis, published as an original investigation in the Journal of the American Medical Association (JAMA), projects that 126 million U.S. adults will be living with obesity by 2035. That would be almost 47% of the population. That compares with the 107 million U.S. adults currently estimated to have obesity. They comprise about 42% of the population. The researchers said the increase would also be a significant increase over the 34 million U.S. adults who comprised about 20% of the population who had obesity in 1990. The predicted trend runs counter to a Gallup poll published in October 2025 that proclaimed that obesity rates have actually decreased slightly the past three years. That survey credited the utilization of GLP-1 weight-loss drugs for the decline. The numbers, however, were based on participants’ self-reported height and weight measurements. The researchers of the current study said the obesity trend has become a “large public health burden” and urged the country’s leaders to use the information to craft health policies to combat the increase. “Given the association between obesity and adverse health outcomes, and the resulting rapidly rising healthcare costs, these findings underscore the importance of addressing the burden of obesity in the U.S.,” the study authors wrote. What&#8217;s causing rising obesity rates? Kristin Kirkpatrick, RD, the president of KAK Consulting and a dietitian at the Cleveland Clinic Department of Wellness & Preventive Medicine in Ohio, said the obesity rate has been increasing the past three decades for a variety of reasons. “The reasons are multifaceted,” Kirkpatrick told Healthline. “Our food has changed, which is a major factor. However, it’s not the only aspect of the story. Added stress, screen time (sedentary behavior), sleep patterns, and concurrent increases in poor mental and physical health have all contributed.” David Cutler, MD, a family medicine physician at Providence Saint John’s Health Center in Santa Monica, CA, agreed there are a multitude of factors. “This rise in obesity rates is largely attributable to changes in our diet,” he told Healthline. “But there are factors other than diet also contributing to increasing obesity. Factors other than diet impacting obesity include the intestinal microbiome, exercise, other behaviors like tobacco, alcohol, and drug use, behavioral disorders like anxiety, depression, [attention deficit disorder], and the drug treatments of many disorders.” “It’s a combination of things,” added Mir Ali, MD, a general surgeon, bariatric surgeon, and the medical director of MemorialCare Surgical Weight Loss Center at Orange Coast Medical Center in California. “There is more of a sedentary lifestyle with people staying inside their homes and not being active,” he told Healthline. “There’s also been a great increase in the amounts of processed foods. Foods that aren’t healthy have exploded in use.” Obesity rates differ among ethnicities, age groups To reach their conclusions, the researchers in the newly released report utilized body mass index (BMI) data from the National Health and Nutrition Examination Survey (NHANES). They also examined self-reported height and weight data from the Behavioral Risk Factor Surveillance System and information from the Gallup Daily Survey. In all, the researchers analyzed data from more than 11 million U.S. adults. They reported there is an overall upward trend across the country, leading them to project a 47% obesity rate by 2035. The researchers stated that projections vary substantially from state to state with the highest prevalence in Midwestern and Southern areas. They also noted differences in certain ethnic and racial groups. The researchers reported that 40% of U.S. white male adults now have obesity compared to 42% of Hispanic males as well as nearly 50% of Hispanic females and 57% of non-Hispanic Black female adults. They also said that obesity prevalence is highest among adults 45 years to 64 years old with the largest increases in the youngest adult ages, especially for females under the age of 35. “While there are large differences by race and ethnicity, sex, age, and state, the prevalence of obesity is high and forecasted to continue increasing for all groups,” the researchers wrote. Kirkpatrick said it will be a tough challenge for the country to reverse this trend. “It’s hard to predict, but if we continue to see increases in easy-to-access, cheap processed foods alongside reductions in physical activity, these numbers are probably not far off,” she said. Health dangers of obesity Obesity is considered a long-term chronic condition that progresses over time. It’s defined as excess body fat that can impair health. Obesity has been associated with a higher risk of developing certain conditions. They include: type 2 diabetes heart disease high blood pressure high cholesterol cancer arthritis The primary cause of obesity is described as simply taking in more calories than are burned in daily activities and physical exercise. There are other factors that can increase the risk of obesity. They include: genetics age inadequate sleep high stress pregnancy weight A report from the American Heart Association published last week stated that nearly half of U.S. adults live with heart disease, largely due to the increases in rates of obesity, diabetes, and high blood pressure. Researchers in the latest study said the obesity epidemic has had a substantial impact on individuals as well as on society in general. “Obesity is associated with an increased risk of mortality and morbidity, including all-cause mortality, cancers, cardiovascular diseases and diabetes, musculoskeletal conditions, and Alzheimer disease,” the researchers wrote. “Obesity has led to higher disease burden and higher costs for the health care system,” they added. Cutler agrees the impacts from obesity are significant. “Obesity affects both the risk of developing many conditions and the severity of existing diseases,” he said. “Major health problems linked to obesity include diseases affecting nearly every organ system.” “Many musculoskeletal conditions are also worsened by obesity such as osteoarthritis (especially weight-bearing joints: knees, hips, spine), chronic back, and overall joint pain,” Cutler added. “Respiratory diseases such as obstructive sleep apnea, COPD, and asthma are also worse when obesity is present. So is chronic kidney disease.&#8221; Lifestyle choices may help prevent obesity The introduction of GLP-1 weight loss drugs has helped people manage obesity and control their weight. The most commonly prescribed of these medications are Ozempic and Wegovy, which contain the active ingredient semaglutide, and Mounjaro and Zepbound, which contain the active ingredient tirzepatide. Gastric bypass surgery is also an option for some people. Experts point out that these treatments do not magically cause weight loss. They simply suppress a person’s appetite, causing them to consume fewer calories on a daily basis. “GLP-1s are also only one side of the story — being on one alone does not guarantee success,” said Kirkpatrick. Ali also noted that GLP-1 drugs are not widely available and aren’t covered by a number of insurance companies. “These drugs are very expensive to pay for out of pocket,” he said. Experts stress that a person still needs to adopt healthy lifestyle habits to lose weight, whether or not they have surgery or continue using GLP-1 drugs. “Other lifestyle factors need to be adhered to alongside use of the medication, such as a nutrient-dense diet meeting optimal macronutrients, physical activity, including both resistance training and aerobic training, and work toward improved relationship with food as well,” said Kirkpatrick. Experts encourage people with weight management issues to eat a balanced, heart healthy diet consisting mostly of fruits, vegetables, whole grains, and lean protein. They also recommend a minimum of 20 to 30 minutes of moderate daily exercise that can include walking, swimming, or bicycling. Kirkpatrick said it’s important to make healthy eating accessible and convenient. “Better access to fresh, nutrient-dense foods may be the next logical next step as well as focusing on factors such as sleep, stress and physical activity,” she said. “Education is always key but real change needs to start with making nutrient-dense foods affordable and easy to obtain for everyone.” Cutler said the challenge to lower obesity rates is daunting. “My guess is that obesity rates will continue to rise,” he said. “My basis for this conclusion is that human behavior is very difficult to change. Altering eating behaviors will be very challenging.” “As far as medical treatment goes, while GLP1 drugs are generally safe and effective, historically people have been poorly compliant with medical therapies when they don’t see immediate benefits,” Cutler added. Ali said early education about weight management in all sectors of society is key. “There needs to be a concerted effort to introduce education at an early age,” he said. Ali said this information at a young age will help people form healthy habits in terms of diet and regular exercise on their own. “It’s easy to tell people what they should do, but it’s more difficult to get them to do it,” he said.', NULL, 'https://www.healthline.com/health-news/rising-obesity-rates-united-states-2035', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/US-obesity-GettyImages-2255858361-Header.jpg', NULL, NULL, '2026-01-29 13:36:30.580514', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["obesity", "U.S. adults", "health policies", "lifestyle changes", "public health"]', '{"topics": ["Obesity trends", "Public health burden", "Health policy", "Lifestyle and nutrition"], "summary": "تتوقع دراسة حديثة أن تصل معدلات السمنة بين البالغين في الولايات المتحدة إلى 47% بحلول عام 2035، مما يشكل عبئًا صحيًا كبيرًا. الخبراء يشددون على أهمية التوعية بالتغييرات في نمط الحياة وتوفير الغذاء الصحي للحد من هذه الظاهرة.", "entities": ["Journal of the American Medical Association (JAMA)", "Kristin Kirkpatrick", "Gallup poll"], "credibilityScore": 90}', '2026-01-29 13:36:30.580514', '2026-01-31 08:07:38.444');
INSERT INTO public.radar_items VALUES ('38abdcdb-ca7e-48b9-b675-1e4b94d7d992', '89e63f8a-9027-490f-bd18-a16d11dc2d26', 'a3e3d28010e4971861078f87758ab4b7', 'Communities unite to address stigma and discrimination affecting people with neglected tropical diseases', NULL, 'Marking World Neglected Tropical Diseases (NTDs) Day, the World Health Organization (WHO) warns that millions of people living with NTDs continue to face profound and often unseen suffering due to discrimination, social stigma and untreated mental health conditions. Under the rallying theme "Unite. Act. Eliminate.", WHO and partners urge governments to integrate mental health care into NTD elimination efforts, ensuring that no one is left behind in pain or isolation.', NULL, 'Marking World Neglected Tropical Diseases (NTDs) Day, the World Health Organization (WHO) warns that millions of people living with NTDs continue to face profound and often unseen suffering due to discrimination, social stigma and untreated mental health conditions. Under the rallying theme "Unite. Act. Eliminate.", WHO and partners urge governments to integrate mental health care into NTD elimination efforts, ensuring that no one is left behind in pain or isolation.', NULL, 'https://www.who.int/news/item/30-01-2026-communities-unite-to-address-stigma-and-discrimination-affecting-people-with-neglected-tropical-diseases', NULL, NULL, '2026-01-29 19:06:53', '2026-01-31 08:09:33.41102', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:33.41102', '2026-01-31 08:09:33.41102');
INSERT INTO public.radar_items VALUES ('df003222-9075-4b73-a87a-b2c5caa0b3ff', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '8eeae1ff623d10825a80aed476952d18', 'Healthgrades Names America’s Best Hospitals for 2026', NULL, 'Healthgrades has announced the Best Hospitals in the U.S. for 2026. Image Credit: Vero/Stocksy Healthgrades has recently released its annual list of the top 250 hospitals in the United States. To compile their rankings, Healthgrades evaluated the clinical performance of 4,500 hospitals. The research team graded each hospital based on more than 30 common conditions and procedures. When it comes time to seek medical care, knowing where to turn can feel daunting, especially when differences in qual', NULL, 'Healthgrades has announced the Best Hospitals in the U.S. for 2026. Image Credit: Vero/Stocksy Healthgrades has recently released its annual list of the top 250 hospitals in the United States. To compile their rankings, Healthgrades evaluated the clinical performance of 4,500 hospitals. The research team graded each hospital based on more than 30 common conditions and procedures. When it comes time to seek medical care, knowing where to turn can feel daunting, especially when differences in quality aren&#8217;t always easy to see. That&#8217;s where Healthgrades can help. On January 27, Healthgrades, a leading website for finding a doctor, announced the winners of its 2026 Best Hospitals Awards, recognizing the nation&#8217;s top-performing hospitals based on clinical outcomes. The annual awards highlight the top 1%, 2%, and 5% of hospitals nationwide with the following distinctions: America&#8217;s 50 Best Hospitals America&#8217;s 100 Best Hospitals America&#8217;s 250 Best Hospitals To determine these rankings, Healthgrades evaluated clinical performance data from more than 4,500 hospitals across more than 30 common procedures and conditions, using clinically validated methodology focused on patient outcomes. “Patients are taking a more active role in their care than ever before, but real empowerment comes from having choices and access to information they can trust,&#8221; Alana Biggers, MD, MPH, FACP, and a medical advisor at Healthgrades, noted in a press release. &#8220;This year&#8217;s America’s Best Hospitals list gives patients a clearer picture of where high quality care is delivered most consistently, helping them understand their options and feel confident in choosing the care that&#8217;s right for them.” What to consider when choosing a hospital or doctor Consumers are beginning to take a more active role in their care. Healthgrades notes that nearly two-thirds of people say they are more likely to choose a hospital with a quality award than one without one. This highlights the importance of having access to objective quality data. A lack of access to quality care still poses a major challenge to informed healthcare decision making for around half of the United States population. Recent research shows that around 46% of people in the United States live more than 25 miles from one of America’s 250 Best Hospitals. It also revealed major gaps in access that span major metropolitan areas and entire states. Healthgrades’ annual analysis also shows that if every hospital in the United States performed similarly to America’s 250 Best Hospitals, 211,370 lives could be saved. America’s top 50 hospitals by state The best 50 hospitals were from 19 different states. California was the home of nine of these medical facilities, while Florida had seven. Pennsylvania and Ohio had five each. Below is the list of America&#8217;s 50 Best Hospitals for 2026. You can find the full list of America&#8217;s 250 Best Hospitals on the Healthgrades website. Arizona Mayo Clinic Hospital, Phoenix California Alta Bates Summit Medical Center, Oakland Cedars-Sinai Medical Center, West Hollywood Mills-Peninsula Medical Center, Burlingame Northridge Hospital Medical Center, Northridge Providence Holy Cross Medical Center, Mission Hills Scripps Memorial Hospital Encinitas, Encinitas Scripps Mercy Hospital San Diego, San Diego Stanford Hospital, Stanford Sutter Roseville Medical Center, Roseville Colorado HCA HealthONE SKY Ridge, Lone Tree Connecticut Norwalk Hospital, Norwalk Florida AdventHealth Orlando, Orlando Cape Coral Hospital, Cape Coral Gulf Coast Medical Center, Fort Myers HCA Florida Kendall Hospital, Miami Lee Memorial Hospital, Fort Myers Mayo Clinic in Florida, Jacksonville Naples Comprehensive Health, Naples Georgia Emory St. Joseph’s Hospital, Atlanta Emory University Hospital Midtown, Atlanta Illinois Advocate Lutheran General Hospital, Park Ridge Maryland Johns Hopkins Bayview Medical Center, Baltimore Michigan Ascension Providence Hospital — Southfield Campus, Southfield Beaumont Hospital, Troy Minnesota Mayo Clinic Health System Mantako, Mantako Mayo Clinic Hospital, St. Mary’s Campus, Rochester New Jersey Morristown Medical Center, Morristown Overlook Medical Center, Summit New York Lenox Hill, New York NYU Langone Hospitals, New York Stony Brook University Hospital, Stony Brook Vassar Brothers Medical Center, Poughkeepsie North Carolina Mission Hospital, Asheville Ohio Mercy Health — Fairfield Hospital, Fairfield Mercy Health-St. Elizabeth Youngstown Hospital, Youngstown Mercy Health-West Hospital, Cincinnati Summa Health System-Akron Campus, Akron The Jewish Hospital-Mercy Health, Cincinnati Pennsylvania Chester County Hospital, West Chester Lancaster General Hospital, Lancaster Lankenau Medical Center, Wynnewood Milton S Hershey Medical Center, Hershey Reading Hospital, Reading Riddle Memorial Hospital, Media St. Luke&#8217;s Hospital- Bethlehem Campus, Bethlehem Texas Houston Methodist Hospital, Houston Virginia Inova Loudoun Hospital, Leesburg Washington Evergreenhealth Medical Center-Kirkland, Kirkland West Virginia Cabell Huntington Hospital, Huntington *Healthgrades and Healthline are part of the RVO Health portfolio of brands.', NULL, 'https://www.healthline.com/health-news/healthgrades-names-best-hospitals-for-2026', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Best-Hospital-Stocksy_txp2cbed03ffYE400_Medium_443382-Header.jpg', NULL, NULL, '2026-01-31 08:09:36.780022', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:36.780022', '2026-01-31 08:09:36.780022');
INSERT INTO public.radar_items VALUES ('46cc054e-fe46-4205-869c-cd9375fa2723', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'a6992fe4f47ac348ae959d3ca47efb8f', 'Younger Males May Face Higher Heart Attack Risk, 7 Years Before Females', NULL, 'New research indicates that men in their 30s may have a higher risk of heart attack compared to females. Image Credit: Thomas Barwick/Getty Images A recent study found that younger males develop a slight risk of cardiovascular disease seven years before females. The risk of coronary heart disease began to diverge between males and females around age 35. This earlier risk profile in males suggests that factors beyond high blood pressure and diabetes may be at play. Cardiovascular disease is an um', NULL, 'New research indicates that men in their 30s may have a higher risk of heart attack compared to females. Image Credit: Thomas Barwick/Getty Images A recent study found that younger males develop a slight risk of cardiovascular disease seven years before females. The risk of coronary heart disease began to diverge between males and females around age 35. This earlier risk profile in males suggests that factors beyond high blood pressure and diabetes may be at play. Cardiovascular disease is an umbrella term for coronary artery disease, cerebrovascular disease, peripheral artery disease, and aortic atherosclerosis. Each of these conditions comprise other cardiovascular events like heart attack and stroke. A recent large, long-term study found that young males may develop coronary heart disease years earlier than females. The findings, published on January 28 in the Journal of the American Heart Association (JAHA), show that sex-based differences in cardiovascular risk emerged among male participants during their mid-30s. “These changes begin insidiously in the 30s and can remain symptomless,” said Timur Alptunear, MD, RN, who wasn&#8217;t involved in the study. &#8220;Along the continuum of cardiovascular disease, this earlier risk is a result of accumulation, not due to the emergence of disease,&#8221; he told Healthline. According to this research, heart disease screening and prevention should begin earlier in adulthood, especially for males. The recommendation is based on more than three decades of follow-up research. “That timing may seem early, but heart disease develops over decades, with early markers detectable in young adulthood,” Alexa Freedman, PhD, assistant professor of preventive medicine at Northwestern University Feinberg School of Medicine, and senior author of the study, said in a press release. “Screening at an earlier age can help identify risk factors sooner, enabling preventive strategies that reduce long-term risk,” she continued. Coronary heart disease risk in males develops in mid-30s According to Freedman, standard risk factors, such as smoking, high blood pressure, and diabetes, have become more similar among males and females in recent decades. However, the gap for cardiovascular disease hasn’t narrowed. Because of this, Freedman and her research team said that it’s important to look beyond these factors, such as blood pressure and cholesterol, and consider a broader range of social and biological factors. The researchers analyzed data from the Coronary Artery Risk Development in Young Adults (CARDIA) study. The CARDIA study enrolled 5,100 adults between the ages of 18 and 30 in the mid-1980s and followed them through 2020. Participants were healthy young adults at enrollment. This enabled the scientists to pinpoint when cardiovascular disease risk first began to diverge between males and females. Males reached 5% incidence of cardiovascular disease around seven years before females. Incidence of cardiovascular disease is broadly defined to include heart attack, stroke, and heart failure. The difference between males and females was largely driven by coronary heart disease. During the study, males reached 2% incidence of coronary heart disease more than 10 years before females. Rates of stroke were similar, and any differences in heart failure showed later in life. Cardiovascular risk may extend beyond traditional factors The researchers looked at whether differences in the following factors could explain the earlier onset of heart disease in males: cholesterol blood pressure blood sugar diet smoking physical activity body weight Certain factors, such as high blood pressure, explained part of the gap. However, overall cardiovascular health did not account for the difference. This suggests that other biological or social factors may play a role. “Risk factors are crucial in understanding cardiovascular health, but younger men are a unique case,” Alptunear said. He added that hormonal differences between males and females may affect how lipids are handled and how stable or unstable atheroma are. Males also have a propensity to gain more visceral fat than pre-menopausal females. This can increase the risk of insulin resistance, inflammation, and cardiovascular disease, according to Alptunear. Cheng-Han Chen, MD, board certified interventional cardiologist and medical director of the Structural Heart Program at MemorialCare Saddleback Medical Center in Laguna Hills, CA, who wasn&#8217;t involved in the study, agreed. “It is not clear what the driving factors are for the earlier development of heart disease in men,&#8221; he told Healthline. &#8220;It may be related to differences in the levels of estrogen, which appears to be protective of heart disease in women.” Alptuner said that social and behavioral factors may influence cardiovascular risk. &#8220;Men are more prone to postpone preventive measures, screen less often for health problems, and overlook early warning signs of fatigue, shortness of breath, or chest pain that occurs sporadically,” he said. Cardiovascular risk in young males increases around age 35 One of the biggest findings from the study was the age in which the risk gap between males and females widened. The researchers found that males and females had similar cardiovascular risks through their early 30s. However, around age 35, the risk for males began to rise more rapidly and remained higher through midlife. Historically, heart disease screening and prevention efforts have focused on people over the age of 40. However, this study suggests that this may be missing an important window. “It may also be related to men not getting check-ups as often as women, thereby missing out on opportunities to improve their cardiac risk factors,” Chen said. The researchers also suggested that females may be more likely to attend routine check-ups than males. This may be due in part to gynecologic and obstetric visits. This unevenness in preventive care rates is a major challenge in closing the gap. “The most vital step is early detection and proactive risk management. Men shouldn’t take cardiovascular health seriously only after symptoms have started,” said Alptunear. “I advocate for early adulthood routine screening of blood pressure, cholesterol, blood sugar, and familial history, particularly for individuals with risk factors or strong familial histories.” Reducing cardiovascular risk In the press release, Freedman emphasized that cardiovascular disease remains the leading cause of death for both males and females. She added that prevention is critical for everyone. “Lifestyle changes are key. This means regular aerobic and resistance exercise, good sleep, stress management, no tobacco, and a heart-healthy diet high in fiber and unsaturated fats, lean protein,” said Alptunear. “Equally as important is establishing care with a provider who focuses on prevention, not just treatment,” he said.', NULL, 'https://www.healthline.com/health-news/heart-attack-risk-younger-males-higher-than-females', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/young-male-heart-screening-1296x728-header.jpg', NULL, NULL, '2026-01-31 08:09:36.950021', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:36.950021', '2026-01-31 08:09:36.950021');
INSERT INTO public.radar_items VALUES ('e389be81-d113-452b-842a-6f5eb4fbb205', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '5fcc3734e479b4513fe98043dcf4f3f2', 'Low Dose Aspirin Not Tied to Cancer, but May Raise Cancer-Related Death Risk', NULL, 'A new study shows daily aspirin use doesn’t impact cancer incidence but may raise the risk of cancer-related mortality. coldsnowstorm/Getty Images Researchers say that a daily routine of low dose aspirin does not appear to reduce the risk of cancer in older adults. However, the findings suggest that daily aspirin use may increase the risk of cancer-related mortality in older adults. Experts say older adults can lower their risk of cancer by eating a plant-based diet, abstaining from tobacco use,', NULL, 'A new study shows daily aspirin use doesn&#8217;t impact cancer incidence but may raise the risk of cancer-related mortality. coldsnowstorm/Getty Images Researchers say that a daily routine of low dose aspirin does not appear to reduce the risk of cancer in older adults. However, the findings suggest that daily aspirin use may increase the risk of cancer-related mortality in older adults. Experts say older adults can lower their risk of cancer by eating a plant-based diet, abstaining from tobacco use, and limit their intake of alcohol. In a new study, researchers say aspirin should not be given to older adults as a cancer prevention strategy. They say that the results of their research indicate that a daily routine of low dose aspirin actually increased the risk of cancer-related mortality among adults 65 years and older during a 10-year study period. They added that the daily aspirin regimen did not impact the overall risk of cancer incidence. Their findings were published on January 29 in JAMA Oncology. “Results of this study suggest that initiating a multi-year aspirin strategy for prevention of cancer is not recommended in older adults,” the researchers wrote. The researchers suggested that longer-term studies be done to examine the “legacy” effects on cancer prevention in people over the age of 65. Katherine Van Loon, MD, a specialist in gastrointestinal cancers at the University of California San Francisco, wasn&#8217;t involved in the study but said it presents some interesting questions. “This is contradictory to data previously reported in younger groups, which suggests there may be some biological factor related to age that results in a differential effect of aspirin,” she told Healthline. “Further study is warranted to further understand this.” Aspirin and cancer risk The researchers said they launched their study due to the fact that almost two-thirds of cancer diagnoses worldwide happen in people age 60 and older. More than 70% of cancer deaths are attributable to this age group. In the United States, the median age for a cancer diagnosis is 67 years. More than 1,000 cancer cases per 100,000 individuals is diagnosed in U.S. adults 60 to 64 years old. It’s more than 2,000 cases per 100,000 individuals in U.S. adults aged 75 and older. To examine the effectiveness of aspirin on cancer risk, the researchers used data from the Aspirin in Reducing Events in the Elderly (ASPREE) randomized clinical trial conducted from 2010 to 2017 where daily low dose aspirin routines were prescribed for a median of 4.7 years. The researchers then added a follow-up study period for those participants from 2018 to 2024. They analyzed the data from May 2025 to November 2025. In all, researchers examined data from more than 19,000 individuals from Australia and the United States. The Australian participants were at least 70 years old while the U.S. subjects were at least 65 years and consisted of Black and Latino individuals. Overall, the median age of the Australian and U.S. participants was 75 years. About 56% of the subjects studied were female. The participants were given either a 100 milligrams (mg) aspirin or a placebo on a daily basis. None of the participants were diagnosed with cardiovascular disease, dementia, or independence-limiting physical disability during the median follow-up period of 8.6 years. During the follow-up time period, researchers reported a total of 3,448 cancer incidences and 1,173 cancer deaths among study participants. The researchers reported that during the extended follow-up period, low dose aspirin “was not associated with incident cancer among older adults but cancer mortality risk was significantly elevated.” However, they noted that “the elevated cancer mortality risk seen with aspirin for participants in the [random control trial] period did not persist into the RCT post-observation period, suggesting no legacy effect.” Nonetheless, the researchers still concluded that a low dose aspirin routine was not effective as a cancer prevention tool in older adults. Safety of low dose aspirin Van Loon said there are a number of takeaways from this most recent study. “I think patients will need an individualized assessment of risks and benefits of aspirin use,” she said. “Only patients without cardiovascular disease were included in this study, so we can really only extrapolate this to patients who are not otherwise being recommended to receive aspirin for a cardiovascular condition.” “Age of aspirin initiation also seems to play a role and younger patients may benefit more,” she added. “For now, I think we can say that we shouldn&#8217;t initiate aspirin therapy in an older adult for the sole purpose of cancer prevention.” “I would advise that if a patient&#8217;s dominant life-limiting medical comorbidity is cardiovascular disease and his/her physicians are recommending aspirin use to modify that risk, I would heed that advice,” Van Loon noted. Rigved Tadwalkar, MD, a consultative cardiologist and medical director of the Cardiac Rehabilitation Center at Providence Saint John’s Health Center in Santa Monica, CA, said the American College of Cardiology and the American Heart Association (AHA) advise against the routine use of aspirin as primary prevention in older adults without a history of cardiovascular disease. Tadwalkar wasn&#8217;t involved in the study. However, he said there are exceptions, including those at risk of developing atherosclerotic cardiovascular disease who do not have a high risk of internal bleeding. He added that the same is true for those with a prior history of: acute coronary syndrome percutaneous coronary intervention coronary artery bypass surgery stroke “As a cardiologist, my recommendations for aspirin use depend entirely on the individual patient&#8217;s situation. There is no blanket approach,” Tadwalkar told Healthline. “The key point is that daily aspirin for heart health is no longer a straightforward decision,” he added. “It is definitely recommended for most who have already had a cardiovascular event like a heart attack. However, for people without that history, it gets more nuanced.” To that end, most people should only take aspirin if it&#8217;s recommended by their doctor, even after a heart attack. Debate over health benefits of aspirin The issue of whether a daily routine of low dose aspirin is beneficial has been researched and debated for years. The American Cancer Society (ACS) states that daily aspirin use is sometimes prescribed as a blood thinner for people who are at risk of blood clots or at higher risk for heart attack and stroke. However, the organizations cautions that daily aspirin use can increase the risk of bleeding as well as cause inflammation in the stomach and small intestine. A 2024 study concluded that daily low dose aspirin does not affect the incidence or progression of age-related macular degeneration. A 2023 study reported that daily low dose aspirin could increase the risk of brain bleeding in older adults. In 2020, doctors at the University of Texas (UT) Health Science Center in Houston advised pregnant people to take low dose aspirin to help reduce the risk of preeclampsia, although they noted that there was an increased risk of bleeding. The recommendation, however is only for those at risk for developing this pregnancy complication. There are indications that higher doses of aspirin can help relieve migraine pain. In the past, experts have said that aspirin should not be taken daily by people who utilize blood thinners. In 2022, the U.S. Preventive Services Task Force updated its recommendations on aspirin use, stating that the agency was “against initiating low dose aspirin use for the primary prevention of [cardiovascular disease] in adults 60 years or older.” The recommendations note that daily aspirin use for people ages 40 to 59 as a primary preventive tool against cardiovascular disease should be an individual choice. “Evidence indicates that the net benefit of aspirin use in this group is small,” the task force wrote. “Persons who are not at increased risk for bleeding and are willing to take low dose aspirin daily are more likely to benefit.” How older adults can lower their cancer risk The National Council on Aging (NCOA) states that there are a number of ways older adults can reduce their risk of cancer. One of the primary measures is staying up-to-date on cancer screenings. They note that early detection can result in “less extensive treatment, more treatment options, and better chances of survival.” They also urge older adults to: abstain from tobacco use limit alcohol use eat a plant-based diet maintain a healthy weight apply sunscreen while outside The organization also notes it’s important to know your family’s history of cancer. Van Loon agreed with NCOA&#8217;s advice. “We recommend avoiding tobacco use, maintaining a healthy weight, exercising, and consuming a diet that is low in red meat, processed meats, sugar, and ultra-processed foods,” she said. “In addition, participation in routine age-appropriate cancer screening is important.”', NULL, 'https://www.healthline.com/health-news/low-dose-aspirin-may-increase-cancer-mortality-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/senior-woman-holding-aspirin-1296x728-header.jpg', NULL, NULL, '2026-01-31 08:09:37.122392', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:37.122392', '2026-01-31 08:09:37.122392');
INSERT INTO public.radar_items VALUES ('a7dcc109-e9a7-4979-83b5-c6d32da3f7ba', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'f1a1e754632a04cfa3fae0aca3fb9bd9', 'U.S. May Lose Measles-Free Status Amid Outbreaks In South Carolina, Other States', NULL, 'The United States recorded a 33-year high in measles cases in 2025, the highest level of U.S. measles cases since 1992. Jan Sonnenmair/Getty Images The United States is at risk of losing its measles elimination status, which it has held since 2000. The United Kingdom, several European countries, and Canada have all recently lost their measles-free statuses. The designation may be revoked in the U.S. as cases climb, particularly in South Carolina, which has the highest number of cases since measl', NULL, 'The United States recorded a 33-year high in measles cases in 2025, the highest level of U.S. measles cases since 1992. Jan Sonnenmair/Getty Images The United States is at risk of losing its measles elimination status, which it has held since 2000. The United Kingdom, several European countries, and Canada have all recently lost their measles-free statuses. The designation may be revoked in the U.S. as cases climb, particularly in South Carolina, which has the highest number of cases since measles was declared eliminated. Experts say the upward trend may continue in 2026 due to vaccination hesitancy and conflicting messaging from federal health officials. The United States may soon lose its measles exemption status, which it has held for the past quarter-century. The Pan American Health Organization (PAHO), an arm of the World Health Organization (WHO), is scheduled to evaluate U.S. measles data sometime in 2026. The U.S. measles exemption status has been in place since 2000, when only 86 cases were reported to the Centers for Disease Control and Prevention (CDC). As of January 22, the CDC confirmed 413 measles cases in 14 U.S. jurisdictions: Arizona, California, Florida, Georgia, Idaho, Kentucky, Minnesota, North Carolina, Ohio, Oregon, South Carolina, Utah, Virginia, and Washington. So far, three cases among international visitors to the United States have been reported. The bulk of these cases have occurred in South Carolina, where 338 cases were reported to the CDC. On January 27, the South Carolina Department of Public Health confirmed 789 cases, the highest number of measles cases since the disease was declared eliminated. This number is expected to grow as the outbreak continues. In 2025, the United States recorded a 33-year high in measles cases, with the CDC confirming 2,242 cases nationwide. That was the highest level of U.S. measles cases since 1992. Three deaths and 245 hospitalizations were attributed to the measles outbreaks last year. About a quarter of the cases in 2025 were in children under 5 years of age. Around 93% of cases occurred in unvaccinated people or those with unknown vaccination status. CDC officials reported that 89% of the 2025 cases were associated with 49 outbreaks in various regions of the country. It&#8217;s too soon to say for certain whether these trends will continue in 2026, but experts remain wary. Last year, PAHO officials announced that Canada had lost its measles exemption status due to ongoing outbreaks. On January 26, the WHO announced that the United Kingdom and five European countries lost their measles elimination statuses after rising infection rates were reported across the continent. Many experts believe that the United States is next. Nathan Lo, MD, an assistant professor of medicine at Stanford University, said there&#8217;s a simple explanation for the sharp rise in measles cases in the United States. “Measles cases were high in 2025 due to declining vaccination in the U.S. and high measles circulation globally,” Lo told Healthline. He said the trend indicates that measles cases will continue their upward trend this year. “So far, measles cases continue to demonstrate sustained circulation in the U.S., which suggests the U.S. will have another year of high measles cases,” Lo said. Federal health officials appeared to downplay the continued spread of measles. CDC principal deputy director Ralph Abraham claimed that the ongoing spread is &#8220;just the cost of doing business,&#8221; suggesting transmission was inevitable due to international travel to and from the United States. Why are measles cases rising? Experts say there is a simple reason why measles can spread so rapidly It’s one of the most contagious diseases on the planet. “It’s unbelievably contagious. It’s the most contagious disease we’ve ever seen,” said Danelle Fisher, MD, a pediatrician at Providence Saint John’s Health Center in Santa Monica, California. She noted that people with measles can be contagious 4 days before symptoms emerge and 7 to 10 days afterward. “Measles is a highly contagious disease that can turn deadly,” added Anne Liu, MD, a clinical associate professor of pediatrics, immunology, and allergy at Stanford University. “People who are unvaccinated and people who are immunocompromised should be quite concerned about the growing footprint of this outbreak,” Liu told Healthline. Experts say that vaccine misinformation and ongoing hesitancy are major factors in the sudden rise in measles cases in the United States. “With continued vaccine hesitancy, and the number of mistruths on social media and the community, and the confusing and conflicting recommendations coming from the FDA and CDC, there is every reason to suspect that more parents/guardians will decline routine childhood vaccinations, including measles vaccinations,” said Graham Tse, MD, a pediatrician and chief medical officer of MemorialCare Miller Children’s & Women’s Hospital in Long Beach, CA. “It is likely that measles outbreaks will continue, and the numbers could rise in 2026,&#8221; Tse told Healthline. Recent research has demonstrated the impacts of vaccine hesitancy. A 2025 study published in JAMA Network Open found that measles-mumps-rubella (MMR) vaccination rates remained below the 93% herd immunity threshold. The study examined 149,000 children in Ohio spanning 20 months from the initial onset of the 2025 measles outbreak. William Schaffner, MD, an infectious disease specialist and professor of medicine at Vanderbilt University in Nashville, Tennessee, reaffirmed the importance of measles vaccination. “Vaccination is the way to prevent measles. There are no other ways,” Schaffner told Healthline. Other experts agreed. “The vast majority of measles cases are in unvaccinated individuals, including in children too young to be vaccinated,” Lo said. “The best way to prevent measles and its spread is through vaccination.” “Measles is a highly contagious disease so one infected person can spread it to many others,” Tse added. Changes to childhood vaccine guidelines In early January, federal health officials released new vaccination recommendations for children. The guidelines reduce the number of primarily targeted diseases from 16 to what the Department of Health and Human Services (HHS) has described as the 11 “most serious infectious diseases.” Vaccination against measles is still recommended as are inoculations against chickenpox, polio, and whooping cough. The CDC, however, revised recommendations on six other diseases to include only children who are at higher risk of infection. Those diseases include hepatitis and respiratory syncytial virus (RSV). CDC officials added that vaccinations for children against influenza, COVID-19, and rotavirus should be based on “shared clinical decision-making,” which means parents must consult with a healthcare professional before their children receive the vaccinations. Experts say these new guidelines could led to confusion or skepticism that will further lower childhood vaccination rates. “The changes to the childhood vaccination schedule and subsequent conflicting recommendations with national organizations and states now create confusion with parents and guardians and ultimately may cause increased vaccine declination,” Tse said. What to know about measles Measles caused more than 3 million illnesses annually in the United States before the vaccine became widely available in the mid-1950s. Those cases resulted in 48,000 hospitalizations and 500 deaths annually. The virus is transmitted through the air or by direct contact with a surface that has droplets that contain the virus. Symptoms will usually appear within 14 days. Those symptoms include: widespread skin rash high fever cough sore throat About 30% of measles cases lead to some form of complication, the most common being ear infections and diarrhea. Serious complications are rare, but they include: pneumonia encephalitis subacute sclerosing panencephalitis Liu said there is also a long-term consequence to measles. “One of the lesser-known features of measles is that it can wipe out part of a person’s immune memory from prior infections, leaving them vulnerable to infections they have previously had and successfully battled,” she said. How to lower your risk of measles Experts say there are precautions you can take to lower your risk of contracting measles. The number one way is through vaccination. “The best way to prevent the spread of measles is through routine vaccination for measles,” said Tse. “Once enough of the population has immunity to measles through vaccination, the measles virus cannot spread easily and cause outbreaks. Fisher urges parents to ensure that children have received their recommended vaccines. She also recommended that adults who are unvaccinated or are unsure about their vaccination status get immunized. She said the vaccines not only protect an individual but also children and adults who can’t get vaccinated due to medical treatments or compromised immune systems. “It’s incumbent on all of us to protect the most vulnerable in our society,” Fisher said. Schaffner agreed. “There are many children and adults living among us who are immunocompromised. If they were to contract measles, they would get very sick,” he said. “We all protect them by being vaccinated and creating a ‘cocoon’ of protection around them, making it difficult for the virus to get past us to find them.” Fisher cautioned unvaccinated people from taking planes, trains, or any other form of mass transportation. She said this group should only consider essential travel. She added that you can also make adjustments at your job to lower the number of people you come into contact with. People who work at or visit schools or healthcare facilities should take extra precautions. In addition, Fisher advised everyone to be cautious around anyone with a cough or other symptoms of measles. “Be very wary of anyone with any kind of upper respiratory illness,” she said. Even going to the grocery store might be risky for those who aren’t vaccinated. Fisher added that people who have had the disease or are fully vaccinated don’t have much to worry about. “You’re not going to get sick and you’re not going to spread it,” she said.', NULL, 'https://www.healthline.com/health-news/us-measles-outbreak-2026', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Measles-Outbreak-GettyImages-2202122308-Header.jpg', NULL, NULL, '2026-01-31 08:09:38.548467', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:38.548467', '2026-01-31 08:09:38.548467');
INSERT INTO public.radar_items VALUES ('a1b35a6e-8d60-42ef-a95d-080cc6775d29', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'b8e227e027505720b4ec11929efbf869', 'Physical Activity May Reduce Breast Cancer Risk, Study Shows', NULL, 'Research shows that being more physically active at a younger age may help reduce breast cancer risk. Image Credit: Getty Images/Vasily Pindyurin A recent study found that recreational physical activity earlier in life may help lower breast cancer risk. Breast tissue composition and stress biomarkers may be indicative of the risk of breast cancer later in life. Regular physical activity may help mitigate these markers. As breast cancer rises in younger females, these results highlight the import', NULL, 'Research shows that being more physically active at a younger age may help reduce breast cancer risk. Image Credit: Getty Images/Vasily Pindyurin A recent study found that recreational physical activity earlier in life may help lower breast cancer risk. Breast tissue composition and stress biomarkers may be indicative of the risk of breast cancer later in life. Regular physical activity may help mitigate these markers. As breast cancer rises in younger females, these results highlight the importance of regular exercise for cancer prevention. Research has long shown that adult females who are more physically active may have a lower risk of developing breast cancer than those who are not. However, new research published in Breast Cancer Research has found that more physical activity during adolescence may affect breast cancer risk markers later in life. Previous research has found that adult females who are more physically active may be able to lower their risk of breast cancer by up to 21% compared to those who are less active. Breast cancer is the second most common cancer among females in the United States, according to the American Cancer Society (ACS). It accounts for around 30% of all new cancer cases in females each year. Adopting strategies to reduce breast cancer risk earlier in life can influence health outcomes later on. Physical activity earlier in life may lower breast cancer risk The study analyzed data from 191 Black and Hispanic girls between the ages of 11 to 20 years old. Participants reported the number of hours they engaged in both organized and unorganized recreational physical activity. They measure three breast cancer biomarkers: breast tissue composition (BTC) oxidative stress inflammation The participants reported that 51% had no past-week engagement in any recreational physical activity, 73% reported no participation in organized activities, and 66% reported no participation in unorganized activities. The study found an association among recreational physical activity, BTC, and oxidative stress. This was true regardless of body fat levels. The study authors noted that additional research is needed to verify the implications of these findings regarding the risk of breast cancer later in life. “This study is consistent with our understanding of the relationship between physical activity and risk of breast cancer. Many other studies demonstrate the same association. It appears physical activity is protective,” noted Debra Patt, MD, PhD, MBA, executive vice president of Public Policy and Strategy for Texas Oncology, who was not involved in the study. She noted that the surprising aspect of this study is that it appears to show this connection even after controlling for obesity. Exercise during adulthood lowers breast cancer later in life Research indicates that around 90% of breast cancer cases can be attributed to non-genetic factors. A healthy diet and regular physical activity can potentially prevent around 25% of cases. “Encouraging a healthy lifestyle with regular physical activity will likely positively influence the risk of breast cancer, other obesity related cancers, and other chronic diseases,” noted Patt. Daniel Ganjian, MD, FAAP, board certified pediatrician at Providence Saint John’s Health Center in Santa Monica, CA, who was not involved in the study, agreed. “Encouraging young girls to stay active is one of the best things we can do for their long-term health,&#8221; he told Healthline. “We should make it fun rather than a chore, so my advice is for parents to lead by example and find activities they actually enjoy,” he added. According to a 2018 study, regular physical activity may help reduce the risk of breast cancer by reducing the levels of estrogen and insulin in the body. These are both key factors in the development of breast cancer. A study from 2022 found that higher levels of physical activity can reduce the overall risk of breast cancer by 23%. It also showed that physical activity has the highest levels of benefits among females during or after menopause, or those who have a body composition of the upper-normal-to-overweight range. Other breast cancer risk factors The American Cancer Society (ACS) notes that there are certain risk factors for breast cancer that you can’t control. These include: being born female aging inheriting certain gene changes having a personal or family history of breast cancer starting periods early starting menopause later Lifestyle factors that you can control and that can affect your risk of breast cancer include: having overweight or obesity drinking alcohol leading a sedentary lifestyle having never had children having never nursed taking certain hormonal types of birth control using certain menopausal hormone therapies “Cancer prevention (and chronic disease prevention) is comprised of many healthy behaviors, and a healthy diet and regular physical activity are important components of preventing chronic disease,” noted Patt. If you have any concerns about your risk for breast cancer or you notice any changes to your breast shape, tissue, or look, speak with a healthcare professional.', NULL, 'https://www.healthline.com/health-news/physical-activity-may-reduce-breast-cancer-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Activity-Girls-GettyImages-683739095-Header.jpg', NULL, NULL, '2026-01-29 13:36:31.273649', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["breast cancer", "physical activity", "cancer prevention", "adolescence", "health markers"]', '{"topics": ["breast cancer prevention", "exercise and health", "adolescent health"], "summary": "دراسة حديثة تشير إلى أن النشاط البدني في سن مبكرة قد يقلل من خطر الإصابة بسرطان الثدي. النتائج تؤكد أهمية التمارين الرياضية في تقليل المؤشرات الحيوية المرتبطة بالسرطان لدى النساء.", "entities": ["American Cancer Society", "Breast Cancer Research"], "credibilityScore": 90}', '2026-01-29 13:36:31.273649', '2026-01-31 08:07:27.956');
INSERT INTO public.radar_items VALUES ('0147ced2-3acc-406a-8484-71fd8c550141', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '7849baba70800e9630334ba7c5f49925', 'Trump’s Covid Views Don’t Track With Reality That Recent Studies Suggest', NULL, 'Get our weekly newsletter, The Week in Brief, featuring a roundup of our original coverage, Fridays at 2 p.m. ET.', NULL, 'More than two years since the official end of the covid pandemic, a growing body of research continues to reveal information about the virus and its ability to cause harm long after initial infections resolve. The findings raise fresh concerns about the Trump administration&#8217;s decision to reduce recommendations about who should get covid vaccines and halt funding for the development of more-protective shots. Covid, for instance, is now linked in studies to possible autism in children of mothers who were infected during pregnancy, as well as a decline in mental cognition and greater risk of heart problems. It&#8217;s even been shown to trigger the awakening of dormant cancer cells in people who are in remission. Policies around covid and vaccination have economic ramifications. The annual average burden of the disease&#8217;s long-term health effects is estimated at $9,000 per patient in the U.S., according to a report published in November in the journal NPJ Primary Care Respiratory Medicine. In this country, the annual lost earnings are estimated to be about $170 billion. The virus that causes covid, SARS-CoV-2, leaves damage that can linger for months and sometimes years. In the brain, the virus leads to an immune response that triggers inflammation, can damage brain cells, and can even shrink brain volume, according to research on imaging studies published in March 2022 in the journal Nature. Ziyad Al-Aly, a clinical epidemiologist who has studied longer-term health effects from covid, estimated the virus may have increased the number of adults in the U.S. with an IQ less than 70 from 4.7 million to 7.5 million — a jump of 2.8 million adults dealing with &#8220;a level of cognitive impairment that requires significant societal support,&#8221; he wrote. Meanwhile, data from more than a dozen studies suggests covid vaccines can help reduce risk of severe infection as well as longer-lasting health effects, although researchers say more study is needed. But last May, Health and Human Services Secretary Robert F. Kennedy Jr. said on X that the Centers for Disease Control and Prevention would stop recommending covid shots for healthy children and pregnant women, citing a lack of clinical data. The FDA has since issued new guidelines limiting the vaccines to people 65 and older and individuals 6 months or older with at least one risk factor, though many states continue to make them more widely available. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/the-week-in-brief-covid-19-research-long-term-effects/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2025/01/the-week-in-brief-thumbnail.jpg?w=1024', 'Stephanie Armour', '2026-01-30 19:30:00', '2026-01-31 08:09:41.801654', 'ar', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:41.801654', '2026-01-31 08:09:41.801654');
INSERT INTO public.radar_items VALUES ('aa7806b2-0557-4d8c-a834-4adc289beba1', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '6ea1821f9c4b9b74970eefc9e4c6328d', '“No sabemos dónde están”. Abogados y familiares enfrentan obstáculos para encontrar a detenidos por el ICE hospitalizados', NULL, 'Enfrentan grandes barreras para localizar a los pacientes, saber cómo están de salud y brindarles apoyo legal y emocional.', NULL, 'Lydia Romero se esforzaba por escuchar la voz d&#233;bil de su esposo al tel&#233;fono. Una semana antes, agentes de inmigraci&#243;n apresaron a Julio C&#233;sar Pe&#241;a delante de su casa en Glendale, California, y se lo llevaron. Ahora estaba en un hospital, despu&#233;s de haber sufrido un mini derrame cerebral. Le dijo a Romero que lo ten&#237;an esposado a la cama, de una mano y un pie, y que hab&#237;a agentes en la habitaci&#243;n escuchando la llamada. Ten&#237;a miedo de morir y quer&#237;a que su esposa estuviera con &#233;l. &#8220;¿En qu&#233; hospital est&#225;s?&#8221;, le pregunt&#243; Romero. &#8220;No te puedo decir&#8221;, respondi&#243; &#233;l. Viridiana Chabolla, abogada de Pe&#241;a, tampoco pudo obtener una respuesta. El oficial de deportaci&#243;n asignado al caso y la empresa m&#233;dica contratada en el Centro de Procesamiento del ICE en Adelanto se negaron a decirle d&#243;nde estaba internado. Frustrada, intent&#243; llamar a un hospital cercano, el Providence St. Mary Medical Center. &#8220;Me dijeron que aunque tuvieran bajo su cuidado a una persona detenida por el ICE, no podr&#237;an confirmar si estaba all&#237; o no, que solo el ICE puede darme esa informaci&#243;n&#8221;, cont&#243; Chabolla. El hospital confirm&#243; esa pol&#237;tica a KFF Health News. Familiares y abogados de personas internadas tras ser detenidas por autoridades federales de inmigraci&#243;n dijeron que enfrentan grandes obst&#225;culos para localizar a los pacientes, saber c&#243;mo est&#225;n de salud y brindarles apoyo legal y emocional. Aseguran que muchos hospitales se niegan a dar informaci&#243;n o permitir el contacto con las personas detenidas. En cambio, dejan que los agentes de inmigraci&#243;n decidan cu&#225;nto contacto se permite, si es que se permite alguno. Esto, seg&#250;n los abogados, les arrebata a los pacientes su derecho constitucional a recibir asesor&#237;a legal, y los deja vulnerables a abusos. Los hospitales dicen que buscan proteger la seguridad y privacidad de los pacientes, el personal y las autoridades, aunque empleados de centros de salud en Los &#193;ngeles, Minneapolis y Portland, Oregon —ciudades donde el ICE ha realizado redadas— afirman que eso les ha dificultado su trabajo. Algunos hospitales aplican lo que llaman &#8220;procedimientos de apag&#243;n&#8221; o blackout —a veces llamado &#8220;c&#243;digo negro&#8221;— que pueden incluir registrar al paciente con un seud&#243;nimo, eliminar su nombre del directorio del hospital o prohibir al personal confirmar si la persona est&#225; hospitalizada. &#8220;Sabemos de varios casos en los que se us&#243; este procedimiento de apag&#243;n en hospitales del estado, y es muy preocupante&#8221;, dijo Shiu-Ming Cheer, subdirectora de justicia migratoria y racial en el California Immigrant Policy Center, una organizaci&#243;n de defensa de los inmigrantes. Estados gobernados por dem&#243;cratas, como California, Colorado y Maryland, han aprobado leyes para proteger a pacientes de operativos de inmigraci&#243;n dentro de hospitales. Sin embargo, esas leyes no cubren a quienes ya est&#225;n bajo custodia del ICE. M&#225;s detenidos hospitalizados Pe&#241;a es una de las m&#225;s de 350.000 personas arrestadas por autoridades migratorias desde que el presidente Donald Trump regres&#243; a la Casa Blanca. A medida que aumentan los arrestos y detenciones, tambi&#233;n lo hacen los reportes de personas trasladadas a hospitales por agentes de inmigraci&#243;n debido a enfermedades o lesiones, ya sea por condiciones preexistentes o derivadas del arresto o la detenci&#243;n. El ICE ha recibido cr&#237;ticas por utilizar t&#225;cticas agresivas y mortales, y por reportes de maltrato y atenci&#243;n m&#233;dica deficiente en sus centros de detenci&#243;n. El senador Adam Schiff, dem&#243;crata de California, dijo el 20 de enero, en una conferencia de prensa, frente a un centro de detenci&#243;n en California City, que habl&#243; con una mujer con diabetes detenida all&#237; que no hab&#237;a recibido tratamiento en dos meses. No hay estad&#237;sticas p&#250;blicas sobre cu&#225;ntas personas enferman o se lesionan bajo custodia del ICE, pero comunicados de prensa de la agencia indican que 32 personas murieron bajo custodia migratoria en 2025. En lo que va del a&#241;o, han muerto seis m&#225;s. El Departamento de Seguridad Nacional, que supervisa al ICE, no respondi&#243; a solicitudes de informaci&#243;n sobre sus pol&#237;ticas ni sobre el caso de Pe&#241;a. Seg&#250;n las propias directrices del ICE, las personas bajo su custodia deben tener acceso a un tel&#233;fono, visitas de familiares y amigos, y consultas privadas con sus abogados. La agencia puede tomar decisiones administrativas, incluyendo el tema de las visitas, cuando un detenido est&#225; hospitalizado; pero, seg&#250;n las directrices, debe respetar las pol&#237;ticas del hospital para contactar a familiares si la persona est&#225; gravemente enferma. Consultado sobre las pr&#225;cticas hospitalarias con personas bajo custodia migratoria, y sobre si existen protocolos recomendados, Ben Teicher, vocero de la Asociaci&#243;n Estadounidense de Hospitales, no quiso comentar. David Simon, vocero de la Asociaci&#243;n de Hospitales de California, expres&#243; que &#8220;en algunos casos, a pedido de las autoridades, los hospitales mantienen la confidencialidad de los nombres de los pacientes y otra informaci&#243;n que los identifique&#8221;. Aunque las pol&#237;ticas var&#237;an, por lo general cualquier persona puede llamar a un hospital y preguntar por un paciente dando su nombre, y con frecuencia se le transfiere la llamada a la habitaci&#243;n, dijo William Weber, m&#233;dico de emergencias en Minneapolis y director m&#233;dico de Medical Justice Alliance, una organizaci&#243;n que defiende los derechos m&#233;dicos de personas bajo custodia. Los familiares y personas autorizadas por el paciente pueden visitarlo. El personal m&#233;dico tambi&#233;n suele llamar a los familiares para informarles que alguien est&#225; hospitalizado o para pedir informaci&#243;n que ayude en su atenci&#243;n. Pero cuando se trata de personas bajo custodia de autoridades, los hospitales frecuentemente acceden a restringir el acceso y dar informaci&#243;n, se&#241;al&#243; Weber. El argumento es que estas medidas evitan que personas no autorizadas amenacen al paciente o al personal, ya que los hospitales no tienen la infraestructura de seguridad de una c&#225;rcel. Algunos pacientes famosos tambi&#233;n solicitan este tipo de medidas. Abogados y trabajadores de salud cuestionan que esas restricciones sean realmente necesarias. La detenci&#243;n migratoria es una detenci&#243;n civil, no criminal. Aunque el gobierno de Trump afirma que su prioridad es arrestar y deportar criminales, la mayor&#237;a de los detenidos no tiene antecedentes penales, seg&#250;n datos del centro Transactional Records Access Clearinghouse y varios medios de comunicaci&#243;n. Detenido delante de su casa Seg&#250;n su esposa, Pe&#241;a no tiene antecedentes penales. Lleg&#243; a Estados Unidos desde M&#233;xico cuando cursaba sexto grado, y tiene un hijo adulto en el ej&#233;rcito estadounidense. Tiene 43 a&#241;os, padece enfermedad renal terminal y sobrevivi&#243; a un infarto en noviembre. Camina con dificultad y tiene p&#233;rdida parcial de la vista, explic&#243; Romero. Fue detenido el 8 de diciembre, mientras descansaba en el exterior de su casa tras un tratamiento de di&#225;lisis. Al principio, Romero logr&#243; ubicar a su esposo con el sistema en l&#237;nea para localizar detenidos del ICE. Lo visit&#243; en un lugar de detenci&#243;n temporal en el centro de Los &#193;ngeles, donde le llev&#243; sus medicinas y un su&#233;ter. Luego vio que lo trasladaron al centro de detenci&#243;n en Adelanto. Pero despu&#233;s de que fue hospitalizado, ya no apareci&#243; en la base de datos. Cuando ella y otros familiares fueron al centro de detenci&#243;n para preguntar por &#233;l, les negaron el acceso. Romero recib&#237;a llamadas ocasionales de su esposo desde el hospital, pero duraban menos de 10 minutos y estaban monitoreadas por el ICE. Ella quer&#237;a saber en qu&#233; hospital estaba para poder estar con &#233;l, tomarle la mano, asegurarse de que lo atendieran bien y darle &#225;nimos. Dijo que mantenerlo esposado y sin ver a su familia era injusto e innecesario.&#8220;Est&#225; d&#233;bil&#8221;, dijo Romero. &#8220;No existe riesgo de que pueda escaparse&#8221;. Las directrices del ICE indican que debe permitirse el contacto y las visitas de familiares &#8220;dentro de las limitaciones de seguridad y operativas&#8221;. Las personas detenidas tienen derecho constitucional a hablar en privado con su abogado. Weber explic&#243; que las autoridades migratorias deben informar a los abogados d&#243;nde est&#225;n sus clientes y permitirles hablar con ellos en persona o mediante una l&#237;nea telef&#243;nica sin vigilancia. Sin embargo, los hospitales est&#225;n en una zona gris respecto a c&#243;mo hacer cumplir estos derechos, ya que su enfoque principal es la atenci&#243;n m&#233;dica, dijo Weber. Aun as&#237;, agreg&#243;, deben asegurarse de que sus pol&#237;ticas est&#233;n alineadas con la ley. Familia sin acceso Varios abogados de inmigraci&#243;n han pasado semanas intentando localizar a clientes detenidos por el ICE, y en ocasiones sus esfuerzos han sido frustrados por los hospitales. Nicolas Thompson-Lleras, abogado de Los &#193;ngeles que representa a personas en proceso de deportaci&#243;n, cont&#243; que, el a&#241;o pasado, dos de sus clientes fueron registrados con nombres falsos en distintos hospitales del condado de Los &#193;ngeles. Inicialmente, los hospitales negaron que los pacientes estuvieran ah&#237; y no permitieron que el abogado los viera. Tambi&#233;n se les neg&#243; el acceso a los familiares. Uno de esos clientes fue Bayron Rovidio Mar&#237;n, trabajador de un negocio de lavado de autos, que result&#243; herido durante una redada en agosto. Agentes migratorios lo vigilaron por m&#225;s de un mes en el hospital Harbor-UCLA, un centro p&#250;blico, sin presentar cargos. En noviembre, la Junta de Supervisores del condado de Los &#193;ngeles vot&#243; a favor de limitar el uso de pol&#237;ticas de apag&#243;n en hospitales p&#250;blicos para pacientes bajo custodia civil de inmigraci&#243;n. En un comunicado, Arun Patel, director de seguridad del paciente y gesti&#243;n de riesgos cl&#237;nicos del Departamento de Servicios de Salud del condado, dijo que estas pol&#237;ticas buscan reducir riesgos para pacientes, m&#233;dicos, enfermeros y agentes. &#8220;En algunos casos, puede haber preocupaciones sobre amenazas al paciente, intentos de interferir con la atenci&#243;n m&#233;dica, visitantes no autorizados o el ingreso de objetos prohibidos&#8221;, dijo Patel. &#8220;Nuestro objetivo no es restringir la atenci&#243;n, sino permitir que se brinde de forma segura y sin interrupciones&#8221;. Pacientes m&#225;s vulnerables Thompson-Lleras expres&#243; preocupaci&#243;n de que los hospitales est&#233;n colaborando con autoridades migratorias a costa de los pacientes y sus familias, lo que los deja vulnerables a abusos. &#8220;Permite que las personas reciban atenci&#243;n deficiente&#8221;, dijo. &#8220;Permite que los traten de forma acelerada, sin supervisi&#243;n, sin intervenci&#243;n familiar y sin defensa alguna. Estas personas est&#225;n solas, desorientadas, siendo interrogadas —al menos en el caso de Bayron— bajo dolor y efectos de medicamentos&#8221;. Estas situaciones tambi&#233;n alarman al personal de salud. En Los &#193;ngeles, dos trabajadores de hospitales —que pidieron no ser identificados por temor a sufrir represalias— dijeron a KFF Health News que el ICE y administradores de hospitales p&#250;blicos y privados bloquean con frecuencia el contacto entre el personal m&#233;dico y los familiares de personas detenidas, incluso para obtener informaci&#243;n m&#233;dica necesaria. Eso, afirmaron, va contra la &#233;tica m&#233;dica. Los procedimientos de apag&#243;n son otra preocupaci&#243;n. &#8220;Facilitan, aunque no sea intencionalmente, la desaparici&#243;n de pacientes&#8221;, dijo una de las personas, m&#233;dica en el Departamento de Servicios de Salud del condado y parte de una coalici&#243;n de trabajadores preocupados en la regi&#243;n. En el Legacy Emanuel Medical Center, en Portland, enfermeras expresaron p&#250;blicamente su indignaci&#243;n por lo que vieron como cooperaci&#243;n con el ICE y violaciones de los derechos de los pacientes. La red Legacy Health envi&#243; una carta al sindicato de enfermeras para que frenara esto, acus&#225;ndolo de hacer declaraciones falsas o enga&#241;osas. &#8220;Me dio asco&#8221;, dijo Blaire Glennon, una enfermera que renunci&#243; en diciembre. Afirm&#243; que muchos pacientes fueron llevados por el ICE al hospital con lesiones graves sufridas durante la detenci&#243;n. &#8220;Sent&#237; que Legacy estaba cometiendo enormes violaciones a los derechos humanos&#8221;. Esposado estando inconsciente Dos d&#237;as antes de Navidad, Chabolla, la abogada de Pe&#241;a, recibi&#243; una llamada de ICE con la informaci&#243;n que ella y Romero llevaban semanas esperando. Pe&#241;a estaba en el hospital Victor Valley Global Medical Center, a unas 10 millas de Adelanto, y estaba a punto de ser dado de alta. Emocionados, Romero y su familia manejaron m&#225;s de dos horas desde Glendale hasta el hospital para recogerlo. Pero al llegar, encontraron a Pe&#241;a intubado e inconsciente, todav&#237;a esposado de un brazo y una pierna a la cama. Hab&#237;a tenido una fuerte convulsi&#243;n el 20 de diciembre, pero nadie inform&#243; a su familia ni a su abogada, dijo Chabolla. Tim Lineberger, vocero del grupo KPC Health —propietario del hospital—, dijo que no pod&#237;a comentar sobre casos espec&#237;ficos por razones de privacidad. Afirm&#243; que las pol&#237;ticas del hospital sobre divulgaci&#243;n de informaci&#243;n cumplen con las leyes estatales y federales. Pe&#241;a fue dado de alta finalmente el 5 de enero. A&#250;n no tiene fecha de audiencia y su familia present&#243; una petici&#243;n para modificar su estatus migratorio en funci&#243;n del servicio militar de su hijo. Por ahora, sigue en proceso de deportaci&#243;n. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/no-sabemos-donde-estan-abogados-y-familiares-enfrentan-obstaculos-para-encontrar-a-detenidos-por-el-ice-hospitalizados/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/Hospital-blackouts-02.jpg', 'Claudia Boyd-Barrett', '2026-01-30 18:49:11', '2026-01-31 08:09:41.973313', 'ar', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:41.973313', '2026-01-31 08:09:41.973313');
INSERT INTO public.radar_items VALUES ('a8057d0d-fbff-4a3b-b51f-15cdacbfbe42', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '4410a216fa9f9cb5bf0d1f214943bd98', '‘I Can’t Tell You’: Attorneys, Relatives Struggle To Find Hospitalized ICE Detainees', NULL, 'Some hospitals are registering patients detained by federal immigration officers under pseudonyms and prohibiting staff from contacting family members. Attorneys and health care workers say the practices facilitate rights violations and create ethical concerns. Hospitals say they’re trying to protect patients.', NULL, 'Lydia Romero strained to hear her husband&#8217;s feeble voice through the phone. A week earlier, immigration agents had grabbed Julio C&#233;sar Pe&#241;a from his front yard in Glendale, California. Now, he was in a hospital after suffering a ministroke. He was shackled to the bed by his hand and foot, he told Romero, and agents were in the room, listening to the call. He was scared he would die and wanted his wife there. &#8220;What hospital are you at?&#8221; Romero asked. &#8220;I can&#8217;t tell you,&#8221; he replied. Viridiana Chabolla, Pe&#241;a&#8217;s attorney, couldn&#8217;t get an answer to that question, either. Pe&#241;a&#8217;s deportation officer and the medical contractor at the Adelanto ICE Processing Center refused to tell her. Exasperated, she tried calling a nearby hospital, Providence St. Mary Medical Center. &#8220;They said even if they had a person in ICE custody under their care, they wouldn&#8217;t be able to confirm whether he&#8217;s there or not, that only ICE can give me the information,&#8221; Chabolla said. The hospital confirmed this policy to KFF Health News. Family members and attorneys for patients hospitalized after being detained by federal immigration officials said they are facing extreme difficulty trying to locate patients, get information about their well-being, and provide them emotional and legal support. They say many hospitals refuse to provide information or allow contact with these patients. Instead, hospitals allow immigration officers to call the shots on how much — if any — contact is allowed, which can deprive patients of their constitutional right to seek legal advice and leave them vulnerable to abuse, attorneys said. Hospitals say they are trying to protect the safety and privacy of patients, staff, and law enforcement officials, even while hospital employees in Los Angeles, Minneapolis, and Portland, Ore., cities where Immigration and Customs Enforcement has conducted immigration raids, say it&#8217;s made their jobs difficult. Hospitals have used what are sometimes called blackout procedures, which can include registering a patient under a pseudonym, removing their name from the hospital directory, or prohibiting staff from even confirming that a patient is in the hospital. &#8220;We&#8217;ve heard incidences of this blackout process being used at multiple hospitals across the state, and it&#8217;s very concerning,&#8221; said Shiu-Ming Cheer, the deputy director of immigrant and racial justice at the California Immigrant Policy Center, an advocacy group. Some Democratic-led states, including California, Colorado, and Maryland, have enacted legislation that seeks to protect patients from immigration enforcement in hospitals. However, those policies do not address protections for people already in ICE custody. More Detainees Hospitalized Pe&#241;a is among more than 350,000 people arrested by federal immigration authorities since President Donald Trump returned to the White House. As arrests and detentions have climbed, so too have reports of people taken to hospitals by immigration agents because of illness or injury — due to preexisting conditions or problems stemming from their arrest or detention. ICE has faced criticism for using aggressive and deadly tactics, as well as for reports of mistreatment and inadequate medical care at its facilities. Sen. Adam Schiff (D-Calif.) told reporters at a Jan. 20 news conference outside a detention center he visited in California City that he spoke to a diabetic woman held there who had not received treatment in two months. While there are no publicly available statistics on the number of people sick or injured in ICE detention, the agency&#8217;s news releases point to 32 people who died in immigration custody in 2025. Six more have died this year. The Department of Homeland Security, which oversees ICE, did not respond to a request for information about its policies or Pe&#241;a&#8217;s case. According to ICE&#8217;s guidelines, people in custody should be given access to a telephone, visits from family and friends, and private consultation with legal counsel. The agency can make administrative decisions, including about visitation, when a patient is in the hospital, but should defer to hospital policies on contacting next of kin when a patient is seriously ill, the guidelines state. Asked in detail about hospital practices related to patients in immigration custody and whether there are best practices that hospitals should follow, Ben Teicher, a spokesperson for the American Hospital Association, declined to comment. David Simon, a spokesperson for the California Hospital Association, said that &#8220;there are times when hospitals will — at the request of law enforcement — maintain confidentiality of patients&#8217; names and other identifying characteristics.&#8221; Although policies vary, members of the public can typically call a hospital and ask for a patient by name to find out whether they&#8217;re there, and often be transferred to the patient&#8217;s room, said William Weber, an emergency physician in Minneapolis and medical director for the Medical Justice Alliance, which advocates for the medical needs of people in law enforcement custody. Family members and others authorized by the patient can visit. And medical staff routinely call relatives to let them know a loved one is in the hospital, or to ask for information that could help with their care. But when a patient is in law enforcement custody, hospitals frequently agree to restrict this kind of information sharing and access, Weber said. The rationale is that these measures prevent unauthorized outsiders from threatening the patient or law enforcement personnel, given that hospitals lack the security infrastructure of a prison or detention center. High-profile patients such as celebrities sometimes also request this type of protection. Several attorneys and health care providers questioned the need for such restrictions. Immigration detention is civil, not criminal, detention. The Trump administration says it&#8217;s focused on arresting and deporting criminals, yet most of those arrested have no criminal conviction, according to data compiled by the Transactional Records Access Clearinghouse and several news outlets. Taken Outside His Home According to Pe&#241;a&#8217;s wife, Romero, he has no criminal record. Pe&#241;a came to the United States from Mexico in sixth grade and has an adult son in the U.S. military. The 43-year-old has terminal kidney disease and survived a heart attack in November. He has trouble walking and is partially blind, his wife said. He was detained Dec. 8 while resting outside after coming home from dialysis treatment. Initially, Romero was able to find her husband through the ICE Online Detainee Locator System. She visited him at a temporary holding facility in downtown Los Angeles, bringing him his medicines and a sweater. She then saw he&#8217;d been moved to the Adelanto detention center. But the locator did not show where he was after he was hospitalized. When she and other relatives drove to the detention facility to find him, they were turned away, she said. Romero received occasional calls from her husband in the hospital but said they were less than 10 minutes long and took place under ICE surveillance. She wanted to know where he was so she could be at the hospital to hold his hand, make sure he was well cared for, and encourage him to stay strong, she said. Shackling him and preventing him from seeing his family was unfair and unnecessary, she said. &#8220;He&#8217;s weak,&#8221; Romero said. &#8220;It&#8217;s not like he&#8217;s going to run away.&#8221; ICE guidelines say contact and visits from family and friends should be allowed &#8220;within security and operational constraints.&#8221; Detainees have a constitutional right to speak confidentially with an attorney. Weber said immigration authorities should tell attorneys where their clients are and allow them to talk in person or use an unmonitored phone line. Hospitals, though, fall into a gray area on enforcing these rights, since they are primarily focused on treating medical needs, Weber said. Still, he added, hospitals should ensure their policies align with the law. Family Denied Access Numerous immigration attorneys have spent weeks trying to locate clients detained by ICE, with their efforts sometimes thwarted by hospitals. Nicolas Thompson-Lleras, a Los Angeles attorney who counsels immigrants facing deportation, said two of his clients were registered under aliases at different hospitals in Los Angeles County last year. Initially, the hospitals denied the clients were there and refused to let Thompson-Lleras meet with them, he said. Family members were also denied access, he said. One of his clients was Bayron Rovidio Marin, a car wash worker injured during a raid in August. Immigration agents surveilled him for over a month at Harbor-UCLA Medical Center, a county-run facility, without charging him. In November, the Los Angeles County Board of Supervisors voted to curb the use of blackout policies for patients under civil immigration custody at county-run hospitals. In a statement, Arun Patel, the chief patient safety and clinical risk management officer for the Los Angeles County Department of Health Services, said the policies are designed to reduce safety risks for patients, doctors, nurses, and custody officers. &#8220;In some situations, there may be concerns about threats to the patient, attempts to interfere with medical care, unauthorized visitors, or the introduction of contraband,&#8221; Patel said. &#8220;Our goal is not to restrict care but to allow care to happen safely and without disruption.&#8221; Leaving Patients Vulnerable Thompson-Lleras said he&#8217;s concerned that hospitals are cooperating with federal immigration authorities at the expense of patients and their families and leaving patients vulnerable to abuse. &#8220;It allows people to be treated suboptimally,&#8221; Thompson-Lleras said. &#8220;It allows people to be treated on abbreviated timelines, without supervision, without family intervention or advocacy. These people are alone, disoriented, being interrogated, at least in Bayron&#8217;s case, under pain and influence of medication.&#8221; Such incidents are alarming to hospital workers. In Los Angeles, two health care professionals who asked not to be identified by KFF Health News, out of concern for their livelihoods, said that ICE and hospital administrators, at public and private hospitals, frequently block staff from contacting family members for people in custody, even to find out about their health conditions or what medications they&#8217;re on. That violates medical ethics, they said. Blackout procedures are another concern. &#8220;They help facilitate, whether intentionally or not, the disappearance of patients,&#8221; said one worker, a physician for the county&#8217;s Department of Health Services and part of a coalition of concerned health workers from across the region. At Legacy Emanuel Medical Center in Portland, nurses publicly expressed outrage over what they saw as hospital cooperation with ICE and the flouting of patient rights. Legacy Health has sent a cease and desist letter to the nurses&#8217; union, accusing it of making &#8220;false or misleading statements.&#8221; &#8220;I was really disgusted,&#8221; said Blaire Glennon, a nurse who quit her job at the hospital in December. She said numerous patients were brought to the hospital by ICE with serious injuries they sustained while being detained. &#8220;I felt like Legacy was doing massive human rights violations.&#8221; Handcuffed While Unconscious Two days before Christmas, Chabolla, Pe&#241;a&#8217;s attorney, received a call from ICE with the answer she and Romero had been waiting for. Pe&#241;a was at Victor Valley Global Medical Center, about 10 miles from Adelanto, and about to be released. Excited, Romero and her family made the two-hour-plus drive from Glendale to the hospital to take him home. When they got there, they found Pe&#241;a intubated and unconscious, his arm and leg still handcuffed to the hospital bed. He&#8217;d had a severe seizure on Dec. 20, but no one had told his family or legal team, his attorney said. Tim Lineberger, a spokesperson for Victor Valley Global Medical Center&#8217;s parent company, KPC Health, said he could not comment on specific patient cases, because of privacy protections. He said the hospital&#8217;s policies on patient information disclosure comply with state and federal law. Pe&#241;a was finally cleared to go home on Jan. 5. No court date has been set, and his family is filing a petition to adjust his legal status based on his son&#8217;s military service. For now, he still faces deportation proceedings. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/ice-immigrants-hospitals-detainees-patients-rights-family-blackout-policies-california/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/ILLUSTRATION_Hospital_ICE_Blackout_vertical-3x2-1.jpg?w=1024', 'Claudia Boyd-Barrett and Oona Zenda', '2026-01-30 10:00:00', '2026-01-31 08:09:42.143215', 'ar', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:42.143215', '2026-01-31 08:09:42.143215');
INSERT INTO public.radar_items VALUES ('ad4d9d38-4028-413d-8ad7-19563145deea', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'a03adf489711808d8f8cea41a7bfd71f', 'What the Health? From KFF Health News: The Hazards of ICE for Public Health', NULL, 'The Trump administration’s immigration crackdown is not just roiling politics but also directly affecting the provision of health care, medical groups say. Meanwhile, in Washington, federal spending bills have been stalled by the fight over immigration enforcement funding after the shooting death of a second person in Minneapolis this month. Maya Goldman of Axios, Alice Miranda Ollstein of Politico, and Rachel Roubein of The Washington Post join KFF Health News’ Julie Rovner to discuss those sto', NULL, 'The Host Julie Rovner KFF Health News @jrovner @julierovner.bsky.social Read Julie''s stories. Julie Rovner is chief Washington correspondent and host of KFF Health News&#8217; weekly health policy news podcast, "What the Health?" A noted expert on health policy issues, Julie is the author of the critically praised reference book "Health Care Politics and Policy A to Z," now in its third edition. The actions of federal Immigration and Customs Enforcement agents are having ramifications far beyond immigration. Medical groups say that ICE agents in health facilities in Minneapolis and other cities are imperiling patient care, while in Washington, the backlash from a second fatal shooting by agents in Minnesota has stalled action on an eleventh-hour suite of spending bills. Meanwhile, anti-abortion groups remain unhappy with the Trump administration over what they see as its reluctance to scale back the availability of the abortion pill mifepristone. This week&#8217;s panelists are Julie Rovner of KFF Health News, Maya Goldman of Axios, Alice Miranda Ollstein of Politico, and Rachel Roubein of The Washington Post. Panelists Maya Goldman Axios @mayagoldman_ @maya-goldman.bsky.social Read Maya''s stories. Alice Miranda Ollstein Politico @AliceOllstein @alicemiranda.bsky.social Read Alice''s stories. Rachel Roubein The Washington Post @rachel_roubein Read Rachel''s stories. Among the takeaways from this week&#8217;s episode: Concerns intensified this week over President Donald Trump&#8217;s immigration sweep after federal agents killed a second citizen in the midst of the crackdown in Minneapolis. Democrats in Congress are blocking approval of government spending as they call for renegotiating Department of Homeland Security funding, potentially forcing a partial government shutdown this weekend. In Minnesota and elsewhere, there are reports of patients postponing medical care and doctors pushing back on the presence of federal agents in hospitals. After the Department of Health and Human Services cut off some federal funding to Minnesota over allegations of Medicaid fraud, other Democratic-led states in particular are fearing HHS could do the same to them. Typically the federal government conducts investigations and imposes sanctions in response to concerns of fraud; it&#8217;s unusual that HHS has opted to halt some funding instead. Abortion opponents last week held their annual March for Life in Washington. The Trump administration marked the occasion by reinstating and expanding policies imposed during the president&#8217;s first term, including a ban on fetal tissue research and what&#8217;s known as the Mexico City Policy. Still, the administration has not made notable progress on a key goal of the anti-abortion movement: barring access to medication abortion. Meanwhile, senators are still trying to sort out a bipartisan compromise to restart the enhanced Affordable Care Act premium subsidies that expired last year. And insurance company executives appeared before House lawmakers last week to answer questions about affordability as the Trump administration announced a plan to keep reimbursement rates nearly flat next year for private Medicare Advantage plans. And KFF Health News&#8217; annual Health Policy Valentine contest is open. You can enter the contest here. Plus, for &#8220;extra credit&#8221; the panelists suggest health policy stories they read this week that they think you should read, too: Julie Rovner: Science&#8217;s &#8220;U.S. Government Has Lost More Than 10,000 STEM Ph.D.s Since Trump Took Office,&#8221; by Monica Hersher and Jeffrey Mervis. Maya Goldman: NBC News&#8217; &#8220;Many Obamacare Enrollees Have Switched to Cheaper Bronze Plans. Here&#8217;s Why That Could Be Risky,&#8221; by Berkeley Lovelace Jr. Alice Miranda Ollstein: The New York Times&#8217; &#8220;After Donations, Trump Administration Revoked Rule Requiring More Nursing Home Staff,&#8221; by Kenneth P. Vogel and Christina Jewett. Rachel Roubein: Stat&#8217;s &#8220;HHS Appoints 21 New Members to Federal Autism Advisory Committee,&#8221; by O. Rose Broderick. Also mentioned in this week&#8217;s episode: Axios&#8217; &#8220;Fear of ICE Is Driving Patients Away From Medical Care,&#8221; by Maya Goldman. Annals of Internal Medicine&#8217;s &#8220;Unexplained Pauses in Centers for Disease Control and Prevention Surveillance: Erosion of the Public Evidence Base for Health Policy,&#8221; by Jeremy W. Jacobs, Garrett S. Booth, Noel T. Brewer, and Janet Freilich. Politico&#8217;s &#8220;Trump Asks Federal Court To Hit Pause on Abortion Pill Case, Citing Ongoing Study,&#8221; by Alice Miranda Ollstein. The Washington Post&#8217;s &#8220;Freeze of Public Health Funds for States, Then Reversal, Sows Confusion,&#8221; by Lena H. Sun and Rachel Roubein. The Georgetown University Center for Children and Families&#8217; &#8220;CMS Weaponizes Fraud Against Medicaid in Minnesota,&#8221; by Andy Schneider. KFF&#8217;s &#8220;KFF Health Tracking Poll: Health Care Costs, Expiring ACA Tax Credits, and the 2026 Midterms,&#8221; by Shannon Schumacher, Audrey Kearney, Mardet Mulugeta, Isabelle Valdes, Ashley Kirzinger, and Liz Hamel. [Clarification: This article was revised at 12:30 p.m. ET on Jan. 30, 2026, to clarify that the agents involved in the Trump administration&#8217;s immigration crackdown represent not only the U.S. Immigration and Customs Enforcement agency but also the broader Department of Homeland Security.] Click to open the transcript Transcript: The Hazards of ICE for Public Health [Editor&#8217;s note: This transcript was generated using transcription software. It has been edited for style and clarity.] Julie Rovner: Hello from KFF Health News and WAMU public radio in Washington, D.C. Welcome to What the Health? I&#8217;m Julie Rovner, chief Washington correspondent for KFF Health News, and I&#8217;m joined by some of the best and smartest health reporters in Washington. We&#8217;re taping this week on Thursday, Jan. 29, at 10 a.m. As always, news happens fast and things might have changed by the time you hear this. So, here we go. Today we are joined via videoconference by Alice Miranda Ollstein of Politico. Alice Miranda Ollstein: Hello. Rovner: Maya Goldman of Axios News. Maya Goldman: Hi. Rovner: And Rachel Roubein of The Washington Post. Rachel Roubein: Hi, everyone. Rovner: No interview this iced-in week here in Washington, but still lots of news. So last week at this time, Congress was busy patting itself on the back for being poised to pass all 12 annual appropriation bills before their Jan. 30 deadline, including the two biggest ones, those funding the Departments of Defense and Health and Human Services. Still, as I believe I said at the time, it&#8217;s not done until it&#8217;s done, and, well, it&#8217;s not done. What happened, of course, is that after the House passed the remaining six spending bills and left for a week&#8217;s recess, on Saturday, federal [Border Patrol] officers shot and killed a VA [Department of Veterans Affairs] ICU nurse, Alex Pretti, on the streets of Minneapolis, where he was participating in an ICE [Immigration and Customs Enforcement] protest. That second killing of a civilian in three weeks turned Senate Democrats, who were supposed to approve the spending package this week, unanimously against the spending bill for the Department of Homeland Security, which includes ICE and which is included within the appropriations package passed by the House last week. But it&#8217;s not as easy as splitting off the Homeland Security bill and passing the other five. If the Senate changes anything about the package, it has to go back to the House, which, as I mentioned, isn&#8217;t even in town this week. So where are we? And how likely is it that we&#8217;re going to look at a partial government shutdown come Saturday? Ollstein: So it&#8217;s really a mess right now. You have some in both parties who are calling for passing the rest of the bills and pulling out the Homeland Security funding to keep negotiating. Some people are saying they should do a very short-term CR [continuing resolution] — a week, a couple weeks — in order to give Congress more time to negotiate these reforms and restrictions that Democrats are demanding. But then you have House Republicans who are saying, Oh, if we&#8217;re opening this all back up again, we have some demands, too, and we want more of this and more of that and XYZ. And so they&#8217;re saying, We&#8217;re gonna defund all sanctuary cities. So, like you said, once you open this back up, it opens up a whole can of worms. That said, the Democrats&#8217; base is really saying don&#8217;t give one penny more to this agency that they see as completely running amok and violating life and civil liberties. And so we&#8217;re really at kind of an impasse right now. Rovner: This is a classic never-count-your-chickens in Congress. Maya, you want to add something. Goldman: Yeah, I was going to say, it seems like the health care package is collateral damage here, right? There&#8217;s a lot of agreement, bipartisan agreement, that these changes that they&#8217;re trying to make, PBM [pharmacy benefit manager] changes, things like that, should be passed. But then, like you said, Julie, it&#8217;s never over till it&#8217;s over, and more time between getting a bill negotiated and actually passing it just gives interest groups more time to get things changed. So that will be interesting to see. Rovner: And just a reminder for those who aren&#8217;t following this as closely as we are, there is this health package that&#8217;s riding along in this spending-bill package that includes the PBM reform and extensions for things like home health care and telehealth and other things that are not technically spending-bill issues but that need to be renewed periodically by Congress. So that&#8217;s also sitting out there waiting to see what the Senate decides to do and then what the House decides to do, depending on what the Senate decides to do. Roubein: And the last government shutdown, in the fall, was based on health care. But as you mentioned, the fight was over Affordable Care Act subsidies, which is not part of this package that Julie mentioned. Rovner: That&#8217;s right. So that will continue. But I want to talk about ICE. We have tiptoed into the immigration debate as it impacts health care in recent months, but now it&#8217;s really front and center, and I&#8217;m talking about more than just the fight over ICE tactics in Minnesota and blocking the spending bill for the entire Department of Health and Human Services. Maya, you have a story about how ICE presence in hospitals and other health care facilities is having an impact on patient care. Tell us what you found. Goldman: Yeah, a lot of physicians and nurses in Minneapolis, Twin Cities, and also across the country are saying that this is approaching, or has already become, a public health crisis. And the problem is twofold. It&#8217;s, Part 1, patients aren&#8217;t coming to get the care that they need, because they&#8217;re worried about leaving their homes. And one doctor during a press conference said she even has patients who don&#8217;t want to take telehealth appointments, because they&#8217;re afraid of getting on the phone or getting on the computer, because they&#8217;re worried they&#8217;re being surveilled. So that&#8217;s a huge problem. And then some doctors are also saying that ICE presence in and around hospitals is making it harder for them to do their jobs of providing care, because there are reports of agents being aggressive and sort of being in places where they are not supposed to be, or are physically impeding care. So two sides of the coin. Rovner: Yeah, a reminder that ICE was largely forbidden from operating in, quote, &#8220;sensitive&#8221; areas like schools and churches and health facilities, in both Republican and Democratic administrations, until [President Donald Trump] changed it last January. We&#8217;ve heard a lot since then about ICE being in all of these sensitive locations, right? Goldman: Yeah, yeah. And I think it&#8217;s important to note the Department of Homeland Security, when I reached out to them, said that they are not conducting enforcement operations in hospitals, even though they are now allowed to. If they take a patient who&#8217;s in custody to the hospital, they are in the hospital. They can get a warrant to come into the hospital. They can be in public spaces like parking lots and waiting rooms, waiting for people. Rovner: And as we&#8217;re hearing, that&#8217;s exactly what they&#8217;ve been doing. Goldman: Exactly. Rovner: Even though they&#8217;re not, quote-unquote, &#8220;conducting enforcement operations&#8221; there. Doesn&#8217;t mean they&#8217;re not there. So even the American Medical Association, not exactly a left-wing group, issued a statement expressing concern about ICE activity in and around hospital emergency rooms, which it called a, quote, &#8220;tactic fueling fear among patients and hospital staff alike.&#8221; Are we starting to turn a corner here? I feel like this is, maybe it was a combination of what happened last week, coincided with the big snowstorm in half the country and people were stuck inside watching TV. I do feel like there&#8217;s way more awareness than there was even two or three weeks ago of this stuff. Ollstein: I think it remains to be seen whether there is a meaningful policy and practice change or just a sort of symbolic or rhetorical change. There&#8217;s a different tone being struck. There&#8217;s sort of backpedaling on the immediate reaction from government officials we heard, which was to blame the people who were killed for their own killings. There are calls for investigations coming from both sides of the aisle. There are calls for some top officials&#8217; resignations. But again, we&#8217;re hearing from people on the ground that things have not actually shifted in the enforcement behavior of these agents. And so I think it really remains to be seen what happens in Congress in terms of passing policies. There&#8217;s discussion of putting limitations in the spending bill on what ICE can do. But again, there is a lot of concern that I&#8217;ve heard from the advocacy community that they&#8217;re going to set up some government official — whether it&#8217;s [Homeland Security Secretary] Kristi Noem or [Trump deputy chief of staff] Stephen Miller or, already we&#8217;ve seen [Border Patrol official Gregory] Bovino — to be a fall guy and then nothing will actually change substantially beyond that. And so there&#8217;s continued anxiety around that. Rovner: Yeah, and just a reminder that even if the spending bill doesn&#8217;t, for the Department of Homeland Security, didn&#8217;t pass and they didn&#8217;t even do a continuing resolution, ICE has I believe it&#8217;s $75 billion from the budget bill that passed last year. So they have a big chunk of money to keep operating regardless. Talk about collateral damage — it would be all of these other agencies that would have to sort of stop operating if there is some kind of a shutdown. Well, meanwhile, it&#8217;s not just ICE that&#8217;s going after the state of Minnesota. The Centers for Medicare & Medicaid Services earlier this month cut off a chunk of the state&#8217;s Medicaid funding going forward. They&#8217;re charging that the state is, quote, &#8220;operating its program in substantial noncompliance&#8221; with rules to detect waste, fraud, and abuse. This is not how this is supposed to work. CMS can sanction states for their anti-fraud efforts being lacking, but there&#8217;s supposed to be a lot of due process first, with lots of hearings and appeals and fact-finding and all kinds of mumbo jumbo that we do go through before people actually get sanctioned. That&#8217;s apparently not what&#8217;s happening here. Although the ICE headlines are overshadowing the other punitive measures the federal government is taking toward Minnesota, I&#8217;m kind of surprised this aspect of the story isn&#8217;t getting more attention. Might it when other governors realize that this could happen to them, too, even if they didn&#8217;t happen to be on the ballot against Trump in the last election, like Minnesota Gov. [Tim] Walz was? Goldman: Yeah, I was talking to somebody in the Medicaid space from a different blue state who was saying this feels like a turning point, something that they are scared of happening in their state as well. And, yeah, I think there are a lot of things that we need to see how they&#8217;ll play out, but this is definitely raising eyebrows. Rovner: Yeah, and I will post in the show notes a link to a piece by Andy Schneider — who&#8217;s at Georgetown University and who wrote, when he worked on the Hill, wrote a lot of the Medicaid statute — explaining how this is all supposed to work and quite how different this is. But I would expect to be hearing more about this in the coming days and weeks, particularly if the administration doesn&#8217;t back off, because it&#8217;s a lot of money and, as we know, Medicaid is a huge, huge piece of every single state&#8217;s budget. Well, meanwhile, on the abortion front, last week was the annual March for Life, marking the anniversary of the now overturned Supreme Court decision Roe v. Wade, and it&#8217;s fair to say that the anti-abortion movement is not happy with the Trump administration&#8217;s actions so far on the issue. Let&#8217;s start with what the administration did do to prove its devotion to the anti-abortion cause, To mark the movement&#8217;s big day in D.C., the Department of Health and Human Services reinstated its first-Trump-term ban on the use of fetal tissue in biomedical research, which President [Joe] Biden had reversed, and it expanded pretty dramatically the so-called Mexico City Policy that bans U.S. funding for international groups that, quote, &#8220;perform&#8221; or &#8220;promote&#8221; abortion. Now things like DEI [diversity, equality, and inclusion] and gender-affirming care are included, too. Alice and Rachel, you guys cover this. What should we know about these two new policies? It doesn&#8217;t seem like much, because they had both been in effect before, but it&#8217;s pretty big. Ollstein: So the fetal tissue ban is also, research, is also an expansion of the first-term version, just like the Mexico City Policy. It goes further than before. And so the new version bans not only in-house government research but also government funding of research at outside institutions that use fetal tissue that was donated from abortions, and that has been used in all kinds of really important medical research, development of vaccines, etc. And so there is a lot of concern about that. They also imposed new restrictions on accepting new stem cell lines. There are lots of existing stem cell lines that they just keep propagating over and over from a long time ago, but they&#8217;re pausing accepting new ones while, they say, they&#8217;re exploring alternatives that they find more ethical. All of this has really rattled the research community. And as for the Mexico City Policy, the expansion there is far beyond the issue of abortion. It&#8217;s banning funding going to groups that promote what they consider DEI and what they consider gender ideology. And so this is groups that serve the trans community in other countries and have programs for specific marginalized groups. So again, a lot of concern in the public health world because in order to tackle big public health problems, you often need to direct resources to the communities most at risk, and often that is the trans community, that is racial minorities. And so there&#8217;s a fear of this really impeding the delivery of services in a way that will impact the broader population. Rovner: All right, so now to what the administration didn&#8217;t do that makes the anti-abortion movement so unhappy — anything further to restrict the abortion pill mifepristone. In fact, as expected, the Justice Department filed its brief in a closely watched lawsuit out of Louisiana this week, urging the court to pause the suit while the FDA [Food and Drug Administration] finishes its study of mifepristone, a study that abortion opponents say is the FDA purposely using to drag its feet on any action. So what the heck is going on here? Rachel, you start. Roubein: Yeah, basically the Department of Justice asked for a stay in this lawsuit in Louisiana, and basically their justification was that: The Food and Drug Administration is reviewing mifepristone. We need time to do that. So that was basically what their ask was, was, like: Put this on pause. We will do this review that, as you said, anti-abortion advocates have been upset and said that it has been moving too slowly. Ollstein: So I really saw the legal brief was kind of a Rorschach test that people could see different things and signs in it, because you had the pro-abortion-rights community looking at them saying: Look, they&#8217;re saying that the FDA didn&#8217;t properly review this in the past, and that&#8217;s why they&#8217;re doing this rigorous review now. That&#8217;s a sign that they&#8217;re going to impose restrictions. Also, the anti-abortion side looked at it and they were upset, one, that the Justice Department is arguing that the FDA allowing telemedicine doesn&#8217;t harm the states, and the states believe that it does, and so they&#8217;re saying: You can&#8217;t prove harm. You don&#8217;t have standing to bring this case. I think really the common theme in this filing and in some other ones last year related to these state abortion lawsuits is that the Trump administration is defending federal power and federal decision-making, and that can cut both ways. And so they&#8217;re saying, Leave it to us. And the anti-abortion groups are saying: We don&#8217;t trust you. We don&#8217;t want to leave it to you. We want to let these state lawsuits move forward. Just to very quickly go back, the Trump administration did one other thing around the March for Life as a bone to the anti-abortion community, throwing them a bone, and that is they are attempting to claw back tens of millions of dollars in covid loans that went to Planned Parenthood affiliates. A lot of these loans were already forgiven by the Biden administration, but they are trying anyways to claim there was fraud going on and to get their money back. This boils down to sort of wonky arguments of whether the specific state Planned Parenthood chapters are considered enough part of national Planned Parenthood that they can&#8217;t claim to be a small business. This is going to be a legal fight. Planned Parenthood maintains they did absolutely nothing wrong. The state affiliates are separate from the national group, but— Rovner: Which they are, by the way. Ollstein: They are. They are. And courts have found that they are in the past. However, the anti-abortion movement was very excited about this. They see it as the first step towards declaring all Planned Parenthoods ineligible for any government funding, something they&#8217;re calling debarment, which they&#8217;ve been pushing for for a while. So that&#8217;s one other thing to keep an eye on. Rovner: And a reminder, many, many Planned Parenthoods don&#8217;t and never have offered abortion. Well we won&#8217;t get as far into the weeds as we could here, but if you press me, I will. All right, we&#8217;re going to take a quick break. We will be right back. So over at the Department of Health and Human Services, we have yet another mysterious case of stopping funding and then almost immediately restarting it. Earlier this month, the Substance Abuse and Mental Health Services Administration cut off nearly $2 billion worth of grants to drug abuse and mental health providers, only to reverse that decision a day later. Now, nearly the same thing has basically happened with about $5 billion worth of grants from the Centers for Disease Control and Prevention to all 50 state health departments for things like community outreach, emergency preparedness, and disease outbreaks. According to The Washington Post, which broke the story, notices to states were sent out Friday and barely 12 hours later, an HHS official told the Post the funding pause, quote, &#8220;had been lifted.&#8221; Still, it apparently took several more days for states to be able to access their funding portals. You can&#8217;t help but think that at least some of this is an actual effort to destabilize the nation&#8217;s public health infrastructure, right? They can&#8217;t be that sort of disorganized that they&#8217;re going to cut off funding and put it back. There has to be a reason here. Rachel, you&#8217;re smiling. Roubein: My colleague Lena Sun and I were hearing about this on Saturday, ahead of the big storm. State officials were trying to kind of figure out what&#8217;s going on. With the mental health grants, you saw a very kind of concerted push from the advocacy community, from Republicans and Democrats on the Hill, to push for, that was a termination of those grants, to be rescinded, and they were within about a day. This happened sort of over the weekend, and it happened very quickly. So, I can&#8217;t say what the result of sort of the change was, because the notices were dated Friday, but state officials didn&#8217;t really start getting them till on Saturday. And then we&#8217;d heard sort of midday Saturday that the temporary pause was lifted. But it definitely threw, sort of, state and local health departments that we were talking about into sort of a state of confusion trying to figure out sort of what they needed to do and by when. Rovner: Yeah, and we have seen this repeatedly from this administration. These are sort of two dramatic cases just this month, but the stopping and starting of grant funding is making it impossible to do any planning and figure out what you can do when. It&#8217;s just, it feels like just a matter of, Let&#8217;s make it as hard as possible for these people to do their jobs. Goldman: Yeah, and— Rovner: By &#8220;these,&#8221; yeah, I&#8217;d say by &#8220;these people&#8221; I mean the grant recipients, not the people who are overseeing the money. Goldman: I can&#8217;t claim to know exactly what&#8217;s going on behind the scenes, but I think, what do you expect to happen when you gut all of the administrative functions of these agencies, which is what HHS did earlier this year? And of course, some of those people have come back, but there&#8217;s a lot of instability in HHS&#8217; rank-and-file workforce itself, and so that naturally will trickle down to their grantees. Rovner: Right, and particularly at the CDC. Well, adding to that, elsewhere at the CDC, some key databases, mostly concerning vaccines, are not being updated. That&#8217;s according to a study in this week&#8217;s Annals of Internal Medicine medical journal. The study found what the authors called &#8220;unexplained pauses&#8221; in nearly half of the 82 databases they studied that are normally updated monthly. Eighty-seven percent of those databases were on vaccination-related topics. Now, this could be political. It could also be due, as Maya was just saying, to the budget and personnel cuts at CDC that we&#8217;ve talked about so much over the past year. But it does seem that we&#8217;re continuing to fly ever more blind on things like disease surveillance, right? Goldman: Yeah, and then when you couple that with the state and local public health divisions are the ones who would be the backstop there, but if their funding is in question now, that is even more concerning for public health surveillance. Rovner: Yeah, and of course, we are in the middle of big measles outbreaks in South Carolina and Texas and trying to watch that closely, but it&#8217;s hard to do if you only have sort of state-by-state backups to look at. All right. Well, before we go, we need to talk about the Affordable Care Act. Remember the Affordable Care Act? Before it was subsumed by all the other headlines? Apparently, the Senate is still working on a bipartisan compromise that could restart lapsed subsidies that have spiked health insurance premiums for millions of Americans. And apparently things aren&#8217;t going all that well. And to add to it, here&#8217;s the headline on the press release for the latest KFF poll, hot off the presses just this morning — quote, &#8220;Health Care Costs Tops the Public&#8217;s Economic Worries as the Runup to the Midterms Begin; Independent Voters Are More Likely to Trust Democrats than Republicans on the Issue.&#8221; On the other hand, the poll did find that Republicans still trust Republicans more. And while the ACA remains pretty popular overall, it is less popular with Republicans than it was before last fall&#8217;s campaign by Republicans to blame all of the health care system&#8217;s ills on the 2010 health law. So where does that leave us? We&#8217;re with — this is the end of January. People who have been sort of reenrolled in the ACA are starting to get these huge premium notices that they may or may not be able to pay. Has Congress just kind of moved onto the next crisis? Ollstein: So some people in Congress are still trying to resolve this crisis, even as new crises pile up. The bipartisan talks are still going on, but there is just not a lot of optimism here. There is not really agreement on lots of aspects of extending the subsidies, and all of this is really discussing, at most, sort of a one-year extension. And so they would just have to have this whole fight all over again. But yes, I would say things are looking more bleak on that front than even a few weeks ago. I don&#8217;t know what my fellow panelists think. Rovner: And any anybody have optimism for getting these subsidies extended? I&#8217;m not seeing anybody raising their hand. Well, we will continue, obviously, to watch this space. All right. Lastly, health insurers are starting to get the same heartburn as the pharmaceutical industry. Last week, in back-to-back hearings at the House Energy and Commerce and Ways and Means committees, the heads of five of the biggest health insurers got pretty much filleted by members of both parties. Then this week, the Trump administration kind of shocked the markets by offering a much-smaller-than-expected increase for private Medicare Advantage plans. Those have been the darlings of Republicans for a couple of decades now. Maybe Republicans do really mean it when they say they want to stop giving so much taxpayer money to health insurers? Goldman: I was a little bit struck by how surprised everybody was at this, because I think [CMS Administrator] Dr. Mehmet Oz has been hinting that he&#8217;s much more amenable to cracking down on reported improper behavior among Medicare Advantage plans than people anticipated the next Trump administration would be. And there&#8217;s really this groundswell in the House of Representatives as well among Republicans to sort of rein in improper spending in Medicare Advantage. Rovner: Sen. Bill Cassidy has been pretty— Goldman: Yes. Rovner: —outspoken on it, which surprised a lot of people. Now his, the committee that he&#8217;s the chairman of doesn&#8217;t have jurisdiction over this, but he is also a member of the Finance Committee, which does have jurisdiction over this. Goldman: Exactly. Exactly. And so to me it wasn&#8217;t that surprising, I have to say. But it sent shock waves through the markets? Obviously, insurers are saying that if this is finalized as proposed, they&#8217;re going to have to cut benefits for seniors even more, they&#8217;re going to have to raise premiums and things like that. And of course this could be a bad political move, potentially, for Republicans. But I think— Rovner: Because there are lots of Republican voters who are in Medicare Advantage plans— Goldman: Absolutely. Rovner: —and don&#8217;t want to see their benefits cut. Goldman: Absolutely, and Medicare Advantage insurers have been saying this over and over again. The Biden administration was also pretty conservative on Medicare Advantage. I guess maybe &#8220;conservative&#8221; is a funny word choice, but— Rovner: Light-handed. Goldman: Yes. Rovner: Were light-handed. Goldman: Yes, I think, and insurers were largely able to weather that. Of course, there are some changes that they&#8217;re making this year. We&#8217;re seeing some market realignment. So it, another year of that, who knows what would happen. But I think it still remains to be seen how impactful this will actually be for beneficiaries. Rovner: Yeah, well, another constituency to get riled up in the run-up to the midterms. All right, that is this week&#8217;s news. Now it&#8217;s time for our extra-credit segment. That&#8217;s where we each recognize the story we read this week we think that you should read, too. Don&#8217;t worry if you miss it. We&#8217;ll post the links in our show notes on your phone or other mobile device. Alice, why don&#8217;t you start us off this week? Ollstein: Yeah. So I have this fascinating investigation from The New York Times. The headline is &#8220;After Donations, Trump Administration Revoked Rule Requiring More Nursing Home Staff.&#8221; So this is a story about these nursing home industry groups making massive donations to Trump&#8217;s super PAC and, after that, gaining a lot of access to him and using that access to lobby for the scrapping of a rule that required minimum staffing in nursing homes. And that rule was already not really being enforced, but now they are getting rid of it formally. And so I think the story does a good job of saying, Look, we can&#8217;t prove exactly that they got rid of this rule because of the donations, but it is part of a pattern where people who have given a lot of money to the president&#8217;s various groups have gotten just an incredible amount of access to him and other top officials. And the story also stresses why we should care about all of this. There&#8217;s just been a lot of horrific data coming out of nursing homes of problems caused by understaffing, patients experiencing preventable injuries, infections and other health problems that go unnoticed until it&#8217;s too late or it gets way more serious, and even facilities using, basically drugging patients to keep them easy to control and complacent, because there just isn&#8217;t enough staff to attend to them. People who have dementia and other things need a lot of care and can get upset and disoriented. And instead of taking care of them, they&#8217;re putting them on heavy psychotropic drugs. And so it&#8217;s a really sad and serious situation, and this article shows some potential pay to play. Rovner: Yeah, I tend to be, in general, skeptical of administrations doing things that we thought they were going to do anyway and someone else happened to give them money. But this draws a pretty clear line. They did do what they were going to do anyway, which was going to sort of not really enforce these regulations. Anyway it&#8217;s really good story. Should read it. Maya. Goldman: My extra credit this week is &#8220;Many Obamacare Enrollees Have Switched to Cheaper Bronze Plans. Here&#8217;s Why That Could Be Risky,&#8221;on NBC News by Berkeley Lovelace Jr. And it&#8217;s one of those stories that, wow, I wish I had written this. It&#8217;s a really great explanation of one of the sort of lesser-talked-about side effects of losing enhanced ACA subsidies, which is that people are going into plans that are — they&#8217;re still opting to be in insurance, but they&#8217;re taking plans that are lower premiums but much higher deductibles, which means that their coverage is less valuable. And they might still have to pay a lot of money out-of-pocket for most services, and then they might not seek those services, which sort of negates the purpose of having health insurance and its effect on public health. And this story shows that Kentucky, Idaho, Massachusetts, New York, Virginia, Rhode Island, California are all seeing decreases in &#8220;silver&#8221; plan enrollment, which is sort of that lower-deductible, higher-premium tier, and increases in &#8220;bronze&#8221; enrollment, which is super-high-deductible. So huge thing to watch. Rovner: Really, really good explanation. Rachel. Roubein: My extra credit is by Stat News. The headline is &#8220;HHS Appoints 21 New Members to a Federal Autism Advisory Committee,&#8221; by O. Rose Broderick. And the story lays out how the Department of Health and Human Services yesterday, on Wednesday, announced the appointment of new members to a federal committee that will advise Secretary [Robert F.] Kennedy [Jr.] on autism. Broderick reports that many of the new members of the committee, which is called the Interagency Autism Coordinating Committee, have publicly expressed or belonged to groups that have publicly expressed a belief in the debunked claim that vaccines can cause autism. Stat had also reported earlier this week that the members of the committee had met in secret and that some members of the kind of broader autism community were worried about the panel. And just kind of for sort of the big-picture point of view, Kennedy, last year, pledged to find the causes of autism. And during his tenure as HHS secretary, he&#8217;s challenged years of public health messaging on vaccines, such as instructing the CDC to contradict the long-settled scientific conclusion that vaccines do not cause autism. Kennedy, in a press release yesterday, called the researchers &#8220;the most qualified experts — leaders with decades of experience studying, researching, and treating autism.&#8221; Rovner: Yet another piece of this. There&#8217;s a lot of advisory committees at HHS, and there are many of them worth keeping a close eye on. All right, my extra credit this week is from Science magazine, by Monica Hersher and Jeffrey Mervis. It&#8217;s called &#8220;U.S. Government Has Lost More Than 10,000 Stem Ph.D.s Since Trump Took Office,&#8221; and it puts some actual numbers to the science brain drain that we&#8217;ve been talking about. The authors looked at 14 agencies across the federal government, including the NIH [National Institutes of Health], FDA, and CDC at HHS. They noted that those 10,000-plus experts represented only 3% of the more than 300,000 federal workers who&#8217;ve left employment since Trump took office, but they represent 14% of the total number of Ph.D.s in science, technology, engineering, math, and health fields. Most quit or retired after taking buyouts rather than being fired, according to the data. But as the authors noted, quote, &#8220;these departing Ph.D.s took with them a wealth of subject matter expertise and knowledge about how these agencies operate.&#8221; Certainly a win for the Trump administration, which wants to remake the federal government&#8217;s approach to science. For the rest of us, we will have to wait and see. OK, that&#8217;s this week&#8217;s show. Before we go, a reminder that our annual KFF Health Policy Valentine contest is open. We want to see your clever, heartfelt, or hilarious tributes to the policies that shape health care. Submit your poem, whether conventional, free-form, or haiku, by noon Eastern on Wednesday, Feb. 4. The winning poem will receive a custom comic illustration in the Morning Briefing on Feb. 13. I will post a link to the formal announcement in our show notes. As always, thanks to our editor, Emmarie Huetteman, and our producer-engineer, Francis Ying. A reminder: What the Health? is now available on WAMU platforms, the NPR app, and wherever you get your podcasts, as well as, of course, kffhealthnews.org. Also, as always, you can email us your comments or questions. We&#8217;re at whatthehealth@kff.org, or you can still find me on X, @jrovner, or on Bluesky, @julierovner. Where are you folks these days? Maya? Goldman: You can find me on LinkedIn under my name or on X, @mayagoldman_. Rovner: Alice. Ollstein: Still on X, @AliceOllstein, and on Bluesky, @alicemiranda. Rovner: Rachel. Roubein: LinkedIn under my name. Bluesky, @rachelroubein. X, @rachel_roubein. Rovner: We will be back in your feed next week. Until then, be healthy. Credits Francis Ying Audio producer Emmarie Huetteman Editor Click here to find all our podcasts. And subscribe to &#8220;What the Health? From KFF Health News&#8221; on Apple Podcasts, Spotify, the NPR app, YouTube, Pocket Casts, or wherever you listen to podcasts. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/podcast/what-the-health-431-ice-immigration-minneapolis-shootings-january-29-2026/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2025/12/WTH-3x2_2025.jpg?w=1024', NULL, '2026-01-29 20:20:00', '2026-01-31 08:09:42.560033', 'ar', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:42.560033', '2026-01-31 08:09:42.560033');
INSERT INTO public.radar_items VALUES ('f7914c38-dcf4-4a71-84bf-b565c7d2da00', 'dfe2763e-0ec2-48cb-94cf-458dca898861', 'e80ee4d60e748f6ac250b212a041668a', 'Watch: A Strange Checkup Bill Revealed a Firefighter’s Kids Were Mistakenly Uninsured', 'فاتورة مفاجئة تكشف خطأً أسقط تأمين أطفال رجل إطفاء', 'This installment of InvestigateTV and KFF Health News’ “Costly Care” series explores how administrative errors can leave patients on the hook for bills they shouldn’t owe — sometimes with few options to correct a problem they didn’t create.', 'تحقيق أمريكي يكشف كيف أسقط خطأ إداري تغطية تأمينية لأطفال رجل إطفاء، تاركاً الأسرة في مواجهة فاتورة غير مستحقة ومطالباً بتنظيمات أكثر صرامة.', 'After Susannah Reed-McCullough&#8217;s husband died in 2018, she and their young daughters continued to receive health insurance through his job as a firefighter in Maryland. Then, in 2024, she got an unexpected medical bill: $377 for a checkup for one of her children the previous fall. Reed-McCullough said she called the doctor&#8217;s billing department and learned the insurance company had dropped the children&#8217;s coverage. The drop turned out to be a mistake. But Reed-McCullough said she was forced to act as the go-between for her late husband&#8217;s human resources department and their insurer — all while worried about her daughters&#8217; being uninsured. In this installment of InvestigateTV and KFF Health News&#8217; &#8220;Costly Care&#8221; series, Caresse Jackman, InvestigateTV&#8217;s national consumer investigative reporter, explores how administrative errors can leave patients on the hook for medical bills they shouldn&#8217;t owe, sometimes with few options to correct a problem they didn&#8217;t create. Jackman interviewed Elisabeth Rosenthal, senior contributing editor at KFF Health News, who said accidental coverage drops are &#8220;a common problem&#8221; in need of attention from state regulators. &#8220;People make mistakes, systems make mistakes, and they should be held responsible for them, not the patient,&#8221; Rosenthal said. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', '<p>بعد وفاة زوجها عام 2018، واصلت سوزانا ريد-مكولو وزوجتاها الصغيرتان الاستفادة من التأمين الصحي عبر جهة عمله كرجل إطفاء في ولاية ماريلاند. لكن في عام 2024 تلقت سوزانا فاتورة غير متوقعة بقيمة <strong>377 دولاراً</strong> مقابل كشف روتيني لإحدى ابنتيها في خريف العام السابق.</p><p>اتصلت سوزانا بقسم الفوترة لدى الطبيب لتكتشف أن شركة التأمين <strong>أسقطت تغطية الطفلتين بالخطأ</strong>. وبينما تأكد لاحقاً أن الأمر مجرد خلل إداري، اضطرت الأم للتنقل بين قسم الموارد البشرية في جهة عمل زوجها الراحل وشركة التأمين لتصحيح الوضع، وسط قلق حقيقي من بقاء ابنتيها من دون تأمين.</p><p>القصة تندرج ضمن سلسلة "رعاية مكلفة" التي تنتجها InvestigateTV وKFF Health News، والتي تسلط الضوء على كيف يمكن للأخطاء الإدارية أن تترك المرضى أمام فواتير لا ينبغي أن يدفعوها، مع خيارات محدودة لتصحيح مشكلات لم يتسببوا بها.</p><p>وفي حديثها للسلسلة، قالت إليزابيث روزنثال، كبيرة المحررين المشاركين في KFF Health News، إن إسقاط التغطية بالخطأ يعد <strong>"مشكلة شائعة"</strong> تستدعي اهتمام الجهات التنظيمية في الولايات. وأضافت: "الناس يخطئون، والأنظمة تخطئ، ويجب تحميلهم المسؤولية عن ذلك، لا المريض".</p><p>توضح هذه الحالة أن خللاً بسيطاً في الأنظمة يمكن أن ينعكس بتبعات مالية ونفسية كبيرة على الأسر، وتعيد طرح السؤال حول دور الرقابة والتنظيم في حماية حقوق المؤمن عليهم ومنع تكرار مثل هذه الثغرات.</p>', 'https://kffhealthnews.org/news/article/watch-costly-care-checkup-surprise-bill-line-of-duty-health-insurance-benefits-children/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/investigate-tv-uninsured-firefighter-surprise-bill.jpg?w=1024', 'Caresse Jackman, InvestigateTV', '2026-01-27 10:00:00', '2026-01-29 13:36:35.269126', 'ar', 'health-reports', 'health-reports', 6, NULL, false, false, NULL, 'published', NULL, '2026-01-29 13:48:13.843', NULL, '["التأمين الصحي", "أخطاء إدارية", "فواتير طبية", "حقوق المرضى", "KFF Health News", "InvestigateTV", "الولايات المتحدة", "تنظيم التأمين"]', '{"topics": ["التأمين الصحي", "أخطاء إدارية", "فواتير طبية", "حقوق المرضى", "KFF Health News", "InvestigateTV", "الولايات المتحدة", "تنظيم التأمين"], "summary": "تحقيق أمريكي يكشف كيف أسقط خطأ إداري تغطية تأمينية لأطفال رجل إطفاء، تاركاً الأسرة في مواجهة فاتورة غير مستحقة ومطالباً بتنظيمات أكثر صرامة.", "entities": [], "seoTitle": "خطأ إداري أسقط تأمين أطفال رجل إطفاء وفاتورة مفاجئة", "subtitle": "سهو إداري يرهق أسرة ويثير دعوات للتنظيم", "seoDescription": "تحقيق من InvestigateTV وKFF Health News يوضح كيف تقود الأخطاء الإدارية لإسقاط تغطية التأمين مؤقتاً وترك الأسر تدفع فواتير لا تُستحق، مع دعوات لتعزيز الرقابة.", "credibilityScore": 60}', '2026-01-29 13:36:35.269126', '2026-01-29 13:48:13.843');
INSERT INTO public.radar_items VALUES ('f913d943-6db8-4243-9334-4b154eb21d8b', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '57d95eeda0153b4ad5ae99333e675ff0', 'This Teen Never Got His Day in Vaccine Court. His Former Lawyer Now Advises RFK on Its Overhaul.', 'فتى يفقد فرصته في «محكمة اللقاحات» ومستشار كينيدي يقود التغيير', 'The federal government’s Vaccine Injury Compensation Program was supposed to help patients with their medical bills while protecting vaccine supply. But allies of Health and Human Services Secretary Robert F. Kennedy Jr. are routinely transferring cases from that program to launch lawsuits against drugmakers.', 'تحقيق يكشف نقل ملفات من «محكمة اللقاحات» إلى دعاوى مدنية ضد شركات الأدوية، بعقود واستشارات مثيرة للجدل ومحامين يتقاضون رسوماً بينما يتعثر تعويض المصابين.', 'JACKSONVILLE, Fla. — In 2019, after a routine vaccination, 11-year-old Keithron Thomas felt a sharp pain in his shoulder and down his arm. His mother, Melanie Bostic, thought it would go away after a few days. But days turned to weeks, then months, and years. Bostic learned of a federal program designed to help people who suffer rare vaccine reactions. The Vaccine Injury Compensation Program was created in 1986 after a flood of vaccine injury lawsuits drove drugmakers from the market. Congress aimed to offer a faster and more generous path to compensation for people injured by vaccines, while shielding manufacturers from liability. The VICP, commonly known as vaccine court, is taxpayer-funded. The government pays any award to claimants as well as attorneys fees. Bostic filed a claim in 2022 for compensation to cover her son&#8217;s spiraling medical bills. She then contacted the Carlson Law Firm, which referred her to Arizona-based attorney Andrew Downing — who now serves as a senior adviser to Health and Human Services Secretary Robert F. Kennedy Jr. Downing declined to comment and HHS did not respond to requests for comment for this article. Downing, who has represented hundreds of plaintiffs in vaccine court in Washington, D.C., signed on to take their case, according to a contract reviewed by KFF Health News. They agreed Downing would pursue the claim before the VICP. Bostic shared documents and medical records as he requested them. Months passed as she waited for news on her son&#8217;s case. After several months of making court filings, Downing told her it was time to opt out of the vaccine program and sue the drugmaker. When she refused to opt out, he withdrew from the case. The government paid Downing $445 an hour for representing Bostic, which is typical for program attorneys with his experience, according to court records. Three years later, Bostic said, she hasn&#8217;t received a dime for her son&#8217;s injury. Thomas, now 18, endures debilitating pain that doctors say may never go away. Rather than help them work through the program, Bostic feels that Downing steered them away from it and toward a lawsuit against the manufacturer. The VICP ultimately dismissed her case. Bostic was furious that the court paid Downing anything. &#8220;Y&#8217;all could&#8217;ve gave that to me for my son,&#8221; she said. &#8220;How dare y&#8217;all.&#8221; In Business With Washington In June, Kennedy&#8217;s HHS also awarded Downing&#8217;s law firm, Brueckner Spitler Shelts, a sole-source federal contract to consult on an overhaul of the VICP. The contract has grown to $410,000. Downing is the only attorney listed on the firm&#8217;s website who has practiced in vaccine court. Kennedy has routinely questioned vaccine safety and called the VICP &#8220;broken,&#8221; saying it shields drug companies from some liability &#8220;no matter how negligent they are.&#8221; As a personal injury lawyer, Kennedy previously spearheaded civil litigation against vaccine maker Merck. Downing and about a dozen other lawyers have transferred hundreds of clients from the vaccine program to civil suits, where the financial rewards — for patients and their lawyers — could run far higher, according to a KFF Health News analysis of court records and program data. They&#8217;ve collected millions of taxpayer dollars in attorneys fees from vaccine court while launching precisely what it was designed to avoid: lawsuits against vaccine manufacturers. This shift in legal strategy has fueled Kennedy&#8217;s crusade against Merck, and it could end up hurting some vaccine-injured clients, several experts said. University of California Law-San Francisco professor Dorit Reiss has studied vaccine court for over a decade and has tracked the rise of anti-vaccine forces in American politics. She said VICP attorneys who are also suing vaccine makers have &#8220;incentives to direct more people&#8221; to lawsuits, &#8220;when it might not be in their best interest.&#8221; A Delicate Balance Kennedy has criticized the VICP as a barrier to accountability. But for Bostic, vaccine court offered an opportunity to hold the government to its promise of caring for casualties of widespread immunization. Like any medication, vaccines can have side effects. Serious reactions to routine shots are rare, but for the unlucky few who bear this burden, the government promises recourse through its administrative program. Vaccine court aims to strike a balance between protecting public health and helping individuals who may pay its price. The no-fault program allows claimants with vaccine-related injuries to get help without showing that the vaccine maker did anything wrong, even when the evidence doesn&#8217;t meet courtroom standards. The program has made more than 12,500 awards, totaling roughly $5 billion in compensation. Historically, nearly half of claims have been resolved with some kind of award. If patients aren&#8217;t satisfied with the outcome or don&#8217;t get a ruling within 240 days, they may leave the administrative program and sue the vaccine maker in civil court. Plaintiffs could potentially win larger awards. Lawyers could obtain higher fees, which they can&#8217;t in vaccine court. But winning a civil suit is far more difficult, in part because plaintiffs have a greater burden of showing the vaccine caused their injury and that the maker was at fault. Since the VICP was created, no vaccine injury lawsuit has won a judgment in regular court, records show. That hasn&#8217;t stopped some lawyers from trying. After the requisite 240 days, they have transferred hundreds of VICP claims into civil litigation against HPV vaccine manufacturer Merck, the KFF Health News analysis found. The lawyers who represented those claims include Downing and other VICP attorneys with ties to Kennedy, court records show. Those include Kennedy advisers and people who work in the law office of his longtime personal lawyer Aaron Siri or with Children&#8217;s Health Defense, the anti-vaccine outfit Kennedy founded, as well as a former Kennedy co-counsel in suits against Merck over its HPV vaccine, Gardasil. Downing, whose law firm biography describes him as &#8220;one of the preeminent litigation attorneys in the Court of Federal Claims,&#8221; has not won an HPV vaccine injury claim in the past five years, records show. Vaccine court did compensate dozens of HPV vaccine claims in that time, but most — including nearly all of Downing&#8217;s — were withdrawn upon reaching the opt-out period. VICP data and court records show that over the past five years, Downing and other lawyers withdrew roughly 400 Gardasil claims from vaccine court before a ruling was issued. The plaintiffs received nothing from the program. Hundreds of these cases joined the litigation against Merck, according to court records. Once the opt-out period arrived in Bostic&#8217;s case, Downing informed her that he was preparing to withdraw her son&#8217;s claim and move the case back to the original law firm for a lawsuit against Merck. &#8220;That,&#8221; he wrote in an email, &#8220;was the plan all along.&#8221; Fighting for Compensation Thomas, who hopes to enroll in community college and become a computer programmer, has intermittent numbness in his fingers and stabbing sensations in his arm nearly every day. The pain often radiates across his back or up his neck, and he&#8217;s developed migraines. Once an active kid who dreamed of playing basketball professionally, he now spends his time playing video games and trying to sleep during lulls in his pain. Bostic&#8217;s claim on behalf of her son made him one of about 1,000 people who have filed with vaccine court for HPV vaccine injuries. More than 200 have received compensation — just over one for every million shots given. Court records show program awards were typically $50,000 to $100,000, with some also covering past medical bills or future health care expenses. Richard Hughes IV, a health care attorney and former pharmaceutical executive who teaches vaccine law at George Washington University Law School, reviewed Thomas&#8217; records and said cases like his were exactly what the vaccine program was designed to address. &#8220;That just seems straightforward,&#8221; Hughes said of Thomas&#8217; claim. &#8220;That should have gotten compensated.&#8221; Bostic wanted the federal agencies that had approved and recommended Gardasil to answer for her son&#8217;s injuries. The single mother hoped compensation from the program would allow Thomas to see specialists including neurologists, afford natural treatments, and enroll in physical therapy. &#8220;He would have had the best of the best health care,&#8221; she said. When Downing took their case, Bostic said, he told her during a phone call that vaccine court&#8217;s $250,000 limit on pain and suffering was too low for her son&#8217;s injury. Bostic said Downing advised she could get more money by suing Merck, though that could take longer. &#8220;I said, ‘No, that will take years. My son needs help now,&#8217;&#8221; Bostic recalled. Bostic said she told Downing she wanted a fund set up for Thomas&#8217; health care as soon as possible. In the following weeks, Bostic sent paperwork to Downing&#8217;s office but had difficulty getting in touch with him, email and text messages show. Downing&#8217;s billing records show a gap in his work on the case from late September until mid-November. In November 2022, Downing emailed Bostic, &#8220;The opt out date for K.T.&#8217;s case is set for April 23, 2023. At that point, we will be in a position to opt K.T.&#8217;s case out of the Vaccine Program and move the case back over to the Carlson Law Firm for handling in the Merck litigation.&#8221; Bostic said she was confused at the time by that language. But she remembers being emphatic in a follow-up phone call with Downing, repeatedly telling him she would not opt out. After that, Bostic said, she didn&#8217;t hear from Downing for months despite calling his office and leaving messages with secretaries. Downing&#8217;s billing records show that he and his paralegals spent fewer than nine hours on Bostic&#8217;s case in that stretch. This included time spent requesting, reviewing, and filing medical records, as well as drafting and filing extension requests. The billing records did not include any communication with Bostic during that time. The court granted each of Downing&#8217;s extension requests, pushing back the deadline a month at a time. In April 2023, Downing sent Bostic an email noting that 240 days had passed, so he could drop their government claim and they could sue Merck. &#8220;Gardasil cases do not receive very fair treatment in the Vaccine Program,&#8221; Downing wrote, adding that he would withdraw as her attorney if Bostic stayed in the program. Bostic chose to stick with vaccine court, later telling the vaccine court judge by email that she&#8217;d advised her attorney &#8220;I was not trying to become a millionaire.&#8221; That exchange of emails in April is when Bostic said she learned Downing was already representing plaintiffs in lawsuits over Gardasil. The litigation encompassed hundreds of other patients who — most of them under Downing&#8217;s counsel — had filed VICP claims in recent years. Running out the 240-day clock, critics say, is allowed but subverts the program&#8217;s intent. Some legal experts criticize the way Downing handled Bostic&#8217;s case. &#8220;They trusted him to file the VICP case,&#8221; Reiss said. &#8220;It&#8217;s his job to zealously advocate for his clients. In this case, his clients want to go through VICP. It&#8217;s his job to fight for them in VICP, not to wait for 240 days.&#8221; When Downing joined HHS as a senior adviser to Kennedy, court records show, he handed off his remaining vaccine court cases to other attorneys in firms involved in the litigation against Merck. A New Approach The vaccine program has long faced criticism for giving claimants too little, too late. Even VICP advocates see the need for reform, with eight officials deciding a growing backlog of claims, driving up wait times. The cap on pain and suffering payments has not changed since 1986. But the court can award further compensation like a fund for lifetime medical care that can reach millions. Most vaccine-injured individuals are better off in the administrative program than in civil litigation, legal experts said. Ren&#233;e Gentry, director of GWU&#8217;s Vaccine Injury Litigation Clinic and a founding member of the Vaccine Injured Petitioners Bar Association, has represented hundreds of families alleging vaccine injuries. Most of them, she said, aren&#8217;t focused on big payouts; rather, they &#8220;want their kid taken care of or they want to be taken care of.&#8221; For claims that often fail in vaccine court, however, Gentry said a lawsuit may be the best option. According to Gentry, HPV vaccine claims like Thomas&#8217; are particularly challenging to win in the VICP. &#8220;If you&#8217;re not going to win, then you want those clients to have at least an opportunity at something,&#8221; she said. For Mark Sadaka, a prominent vaccine court lawyer representing some claims in Merck litigation, sending clients to regular court is a last resort. Sadaka said certain Gardasil injury claimants, such as those alleging mental rather than physical harm, might be better off in litigation. But by sticking it out in the VICP, Sadaka has won HPV vaccine injury claims that were the first of their kind, including for narcolepsy, alopecia, and even a deadly arrhythmia. &#8220;He&#8217;s going to get taken care of for the rest of his life,&#8221; Sadaka said of his client who won compensation for narcolepsy in 2023. &#8220;And he doesn&#8217;t have to pay me anything.&#8221; Sadaka, like all program lawyers, gets an hourly rate from the VICP. He said that he could make much more money representing the same claims in traditional litigation, since he could get a cut of any awards. &#8220;It&#8217;s a better thing for me to file in regular court and get a higher fee, but for the client, sometimes it makes sense, sometimes it doesn&#8217;t,&#8221; Sadaka said. &#8220;My role is to explain both sides in gross detail for them and give them as much information as possible so they can make an informed decision.&#8221; According to Sadaka, some lawyers in the VICP automatically advise their clients to leave vaccine court and file a lawsuit. &#8220;If they can extract settlements, they&#8217;re going to be very happy to put that money in their pockets,&#8221; Hughes noted. Winning a lawsuit or reaching a major settlement could also spell trouble for nationwide vaccine access, replaying the events that gave rise to vaccine court in the 1980s. Some vaccine lawyers and policymakers believe Kennedy and his colleagues might welcome a return to those days. &#8220;If they can bring down the system, that&#8217;s a feather in their cap,&#8221; Hughes said. Lawyers cannot win contingency fees in vaccine court. They get paid for time spent on reasonable claims whether they win or lose. Downing made more than $1 million representing clients before the VICP in recent years, according to court records. A January VICP report shows that since fiscal year 2020, the program has paid scores of attorneys about $280 million — including over $43 million for cases they did not win. In each of the last two fiscal years, lawyers got roughly $9 million for VICP claims in which their clients got nothing. That was more than the program had ever previously paid to attorneys for unsuccessful claims, according to vaccine court data. ‘Learning How To Cope&#8217; After discovering her attorney would not pursue VICP compensation for her son, Bostic decided to advocate for Thomas herself. &#8220;Please help me,&#8221; she wrote in a letter to the court. VICP staff gave Bostic extra time to find a new lawyer and gather records. The following months proved difficult for the family. Bostic was hospitalized with a life-threatening condition. Her mother&#8217;s health declined. She was laid off and lost her family&#8217;s health insurance. By the time Bostic could take Thomas to a pediatric neurologist to get medical records for his VICP case, she said, the doctor had moved hours away to Orlando. Bostic repeatedly missed deadlines and failed to communicate with program staff as required, court records show. Emails, docket entries, and letters suggest she may have misunderstood some court orders and not received others. When Thomas&#8217; medical records remained incomplete for another year, the presiding official dismissed Bostic&#8217;s claim, writing that while he had sympathy for what she and her son had endured, &#8220;the case cannot be allowed to remain pending indefinitely.&#8221; Thomas said he can no longer play basketball with friends. He can&#8217;t even help his mother carry groceries into the house. &#8220;I got to live with this, and there&#8217;s pain,&#8221; he said. Bostic now works from home as a bank fraud analyst. With an income just above the cutoff for government assistance, she puts in overtime in hopes of affording health insurance for Thomas and her six other children. &#8220;People are asking, ‘How&#8217;s your son doing?&#8217;&#8221; Bostic said. &#8220;I normally say, ‘Still the same. We just learning how to cope with it.&#8217;&#8221; Methodology The KFF Health News analysis began with court records for cases in the U.S. Court of Federal Claims, which includes vaccine court. We first identified all cases since 2006 (when the HPV vaccine was introduced) in which the &#8220;nature of suit&#8221; field explicitly mentioned human papillomavirus, or in which &#8220;nature of suit&#8221; was categorized as &#8220;other&#8221; vaccine injury/death and the case text included the word &#8220;papillomavirus.&#8221; The latter made up about 10% of identified cases, mostly claims filed before the HPV vaccine was added to the program or claims involving multiple vaccines. We cross-referenced the number of cases with data from VICP reports to verify completeness. After identifying the relevant vaccine court cases, we pulled these claims&#8217; filing and closing dates and took the difference to find the number of days that each case spent in vaccine court. To estimate total attorneys fees awarded for these claims, we added the fee amounts recorded in dozens of the VICP rulings and derived a minimum estimate based on the number of such cases. We then searched federal court records for litigation over Merck&#8217;s HPV vaccine, Gardasil, and pulled the names of the plaintiffs and attorneys involved. To gauge the scale of claims diverted from the VICP to litigation, we searched for each attorney in the Gardasil-related vaccine court cases and searched for the last name of each plaintiff in the titles of those cases. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', '<p>بعد تلقي لقاح روتيني في 2019، شعر الفتى كيثرون توماس، وكان حينها في الحادية عشرة، بألم حاد في كتفه امتد إلى ذراعه. ظنّت والدته ميلاني بوستيك أن الألم سيزول خلال أيام، لكنه طال أسابيع ثم شهوراً وسنين. ومع تراكم الفواتير الطبية، اكتشفت برنامجاً اتحادياً للتعويض عن إصابات اللقاحات النادرة يُعرف باسم «محكمة اللقاحات».</p><p>أُنشئ <strong>برنامج تعويض إصابات اللقاح (VICP)</strong> عام <strong>1986</strong> بعد موجة دعاوى قضائية كادت تخرج مصنّعي اللقاحات من السوق. هدفه توفير مسار أسرع وأكثر سخاءً للتعويض عن الإصابات، مع حماية الإمدادات من خلال تحصين الشركات من جزء من المسؤولية القانونية. البرنامج ممول من دافعي الضرائب، والحكومة هي من تدفع تعويضات المستحقين ورسوم أتعاب محاميهم.</p><p>في 2022 قدّمت بوستيك مطالبة لتعويض تكاليف علاج ابنها. تواصلت مع «كارلسون لو فيرم» التي أحالتها إلى المحامي أندرو داونينغ في أريزونا—الذي أصبح لاحقاً كبير مستشاري <strong>وزير الصحة والخدمات الإنسانية روبرت ف. كينيدي الابن</strong>. وفق عقد اطّلعت عليه KFF Health News، تولّى داونينغ القضية وسلّمته بوستيك مستندات وتقارير طبية كما طلب.</p><p>لكن بعد أشهر من الانتظار وتبادل المذكرات، قال لها داونينغ إن الوقت حان للانسحاب من البرنامج ورفع دعوى مباشرة على الشركة المصنّعة. وعندما رفضت الانسحاب، تنحّى عن القضية. وبحسب سجلات المحكمة، دفعت الحكومة له <strong>445 دولاراً في الساعة</strong> مقابل تمثيلها—وهو أجر معتاد لمحامي البرنامج بخبرته—بينما تؤكد بوستيك أنها لم تحصل على أي تعويض حتى اليوم، وقد صار ابنها، الآن في الثامنة عشرة، يعاني ألماً مزمناً قد لا يزول أبداً.</p><p>داونينغ رفض التعليق، ووزارة الصحة والخدمات الإنسانية لم ترد على طلبات التعليق بشأن هذه القضية.</p><p>وفي يونيو، منحت الوزارة—برئاسة كينيدي—شركة داونينغ القانونية «برُويكنر سبِتلِر شيلتس» عقداً اتحادياً مباشراً للاستشارة في <strong>إعادة هيكلة برنامج VICP</strong>، ارتفعت قيمته إلى <strong>410 آلاف دولار</strong>. يُذكر أن داونينغ هو المحامي الوحيد على موقع الشركة الذي مارس فعلياً أمام «محكمة اللقاحات». كينيدي وصف البرنامج مراراً بأنه «معطّل»، معتبراً أنه يحمي الشركات «مهما بلغت درجة الإهمال»، وهو محامٍ للتعويضات قاد سابقاً دعاوى مدنية ضد «ميرك».</p><p>وتُظهر مراجعة سجلات المحاكم وبيانات البرنامج التي أجرتها KFF Health News أن داونينغ ونحو عشرات من المحامين نقلوا <strong>مئات</strong> الملفات من «محكمة اللقاحات» إلى القضاء المدني، حيث تبدو المكاسب المحتملة أكبر للمرضى ومحاميهم. وفي الوقت نفسه، تقاضوا <strong>ملايين الدولارات</strong> من أتعاب ممولة حكومياً ضمن «محكمة اللقاحات»، بينما يدفعون نحو ما صُمم البرنامج أصلاً لتجنبه: دعاوى مباشرة ضد مصنّعي اللقاحات.</p><p>يرى خبراء أن هذا التحوّل في الاستراتيجية يعزز حملة كينيدي ضد «ميرك»، وقد يلحق الضرر ببعض المصابين. تقول دوريت رايس، أستاذة القانون بجامعة كاليفورنيا في سان فرانسيسكو والتي درست «محكمة اللقاحات» لأكثر من عقد وتتبع صعود التيارات المناهضة للتطعيم في السياسة الأمريكية، إن المحامين الذين يجمعون بين العمل في البرنامج ومقاضاة الشركات «لديهم حوافز لتوجيه مزيد من الناس» إلى الدعاوى المدنية «حتى عندما لا يكون ذلك في مصلحتهم».</p><p>بالنسبة لبوستيك، انتهت مطالبتها في «محكمة اللقاحات» بالرفض. وتقول بغضب إن الأموال المدفوعة لأتعاب محاميها كان الأولى أن تُصرف لعلاج ابنها: «كان ينبغي أن تذهب تلك الأموال إلى ابني… كيف تجرؤون؟»</p><p>المادة مستندة إلى تقرير KFF Health News.</p>', 'https://kffhealthnews.org/news/article/vicp-vaccine-court-cases-moved-lawsuits-lawyers-merck-hpv-rfk-allies-hhs/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/Vaccine_Lawyers_03-3840.jpg?w=1024', 'Maia Rosenfeld', '2026-01-29 10:00:00', '2026-01-31 08:09:42.812496', 'ar', 'health-reports', NULL, 7, NULL, false, false, NULL, 'published', NULL, '2026-01-31 08:12:23.958', NULL, '["محكمة اللقاحات", "برنامج تعويض إصابات اللقاح", "روبرت كينيدي الابن", "دعاوى ضد شركات الأدوية", "ميرك", "تعويضات طبية", "إصابات اللقاح النادرة", "السياسة الصحية الأمريكية"]', '{"topics": ["محكمة اللقاحات", "برنامج تعويض إصابات اللقاح", "روبرت كينيدي الابن", "دعاوى ضد شركات الأدوية", "ميرك", "تعويضات طبية", "إصابات اللقاح النادرة", "السياسة الصحية الأمريكية"], "summary": "تحقيق يكشف نقل ملفات من «محكمة اللقاحات» إلى دعاوى مدنية ضد شركات الأدوية، بعقود واستشارات مثيرة للجدل ومحامين يتقاضون رسوماً بينما يتعثر تعويض المصابين.", "entities": [], "seoTitle": "من محكمة اللقاحات إلى القضاء: مستشار كينيدي تحت المجهر", "subtitle": "تحويل قضايا التعويض إلى دعاوى ضد الشركات يثير جدلاً", "seoDescription": "قصة فتى فقد تعويضه تكشف تحوّل قضايا «محكمة اللقاحات» إلى دعاوى ضد الشركات، بعقد استشاري بقيمة 410 آلاف دولار ورسوم 445 دولاراً للساعة، وفق KFF Health News.", "credibilityScore": 70}', '2026-01-31 08:09:42.812496', '2026-01-31 08:14:09.053');
INSERT INTO public.radar_items VALUES ('b24929e5-2767-4f06-bb58-b9690fc8db98', '89e63f8a-9027-490f-bd18-a16d11dc2d26', '89de8f280ee491940b219033731a56f8', 'WHO statement on notification of withdrawal of the United States', NULL, 'WHO regrets the United States’ notification of withdrawal from WHO – a decision that makes both the United States and the world less safe. The notification of withdrawal raises issues that will be considered by the WHO Executive Board at its regular meeting starting on 2 February and by the World Health Assembly at its annual meeting in May 2026.', NULL, 'WHO regrets the United States’ notification of withdrawal from WHO – a decision that makes both the United States and the world less safe. The notification of withdrawal raises issues that will be considered by the WHO Executive Board at its regular meeting starting on 2 February and by the World Health Assembly at its annual meeting in May 2026.', NULL, 'https://www.who.int/news/item/24-01-2026-who-statement-on-notification-of-withdrawal-of-the-united-states', NULL, NULL, '2026-01-24 20:09:49', '2026-01-26 06:17:36.680625', 'en', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["WHO", "United States", "withdrawal", "global health", "World Health Assembly"]', '{"topics": ["global health policy", "international relations", "WHO governance"], "summary": "منظمة الصحة العالمية تعرب عن أسفها لقرار الولايات المتحدة بالانسحاب من المنظمة، مشيرة إلى تأثيره السلبي على الأمن الصحي العالمي. سيتم مناقشة هذا القرار في اجتماعات مجلس المنظمة والجمعية العامة القادمة.", "entities": ["World Health Organization", "United States"], "credibilityScore": 90}', '2026-01-26 06:17:36.680625', '2026-01-31 08:07:42.475');
INSERT INTO public.radar_items VALUES ('133951b2-3b64-4bcf-be70-ad16485333c2', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '84c4b2deb67f4f6938d59345e1659c74', 'Blurry Line Between Medical and Vision Insurance Leaves Patient With Unexpected Bill', 'التباس التأمين الطبي والبصري يكلّف متقاعدة فاتورة مفاجئة', 'A Wisconsin retiree with glaucoma needed her eyes examined. Her Medicare Advantage plan from UnitedHealthcare listed her optometrist’s clinic as in-network, but she learned the hard way that a clinic can be in-network and out-of-network at the same time.', 'متقاعدة في ويسكونسن اكتشفت أن عيادة عيونها داخل الشبكة للبصريات لكنها خارجها للعلاج الطبي، فتلقّت فاتورة قدرها 340 دولاراً قبل أن توافق شركة التأمين على تغطيتها لاحقاً.', 'Barbara Tuszynski was concerned about her vision but confident in her insurance coverage when she went to an eye clinic last May. The retiree, 70, was diagnosed with glaucoma in her right eye in 2019. She had a laser procedure to treat it in 2022, and she uses medicated drops in both eyes to prevent more damage. She is supposed to be checked regularly, she said. During the May appointment, Tuszynski&#8217;s optometrist examined her eyes and reassured her that the glaucoma had not worsened. Tuszynski, who lives in central Wisconsin, had looked up beforehand whether the clinic in nearby Madison participated in her insurance plan. The insurer&#8217;s website listed the optometrist&#8217;s name with a green check mark and the words &#8220;in-network.&#8221; She assumed that meant her policy would cover the appointment. Then the bill came. The Medical Procedure An optometrist tested Tuszynski&#8217;s vision and took pictures of her optic nerves. The Final Bill $340, which included $120 for vision testing and $100 for optic nerve imaging. The Billing Problem: Vision Coverage vs. Medical Coverage Tuszynski&#8217;s UnitedHealthcare Medicare Advantage plan declined to pay for her eye appointment. &#8220;The member has no out of network benefits,&#8221; the company&#8217;s denial letter said. Tuszynski felt like she was seeing double. How could an eye doctor be in-network and out-of-network at the same time? She said she sent the insurer a screenshot of its own webpage showing the clinic listed as in-network. She said that after she complained, UnitedHealthcare representatives explained that the eye clinic was in-network under her vision plan, so her policy would cover the clinic&#8217;s services related to glasses or contact lenses. But they said the clinic was not in-network for her medical insurance plan, and glaucoma treatment is considered a medical issue. Tuszynski was baffled that care for a patient&#8217;s eyes would not be covered by vision insurance. She said she didn&#8217;t realize that insurers can have contracts with eye clinics to provide some services but not others. UnitedHealthcare spokesperson Meg Sergel said such arrangements are common, including with non-Medicare insurance provided by employers or purchased by individuals. &#8220;I looked up my eye doctor, and it&#8217;s the same thing,&#8221; she said in an interview with KFF Health News. Sergel said she understood how a customer could mistakenly think vision insurance would cover all care for the eyes. She said UnitedHealthcare recommends that before undergoing treatment, patients ask care providers whether they are in-network for specific services. Otherwise, she said, to know whether a test or treatment is covered by vision insurance, &#8220;you&#8217;d have to read the nitty-gritty&#8221; of a policy. Leaders at Steinhauer Family Eye Clinic, where Tuszynski saw the optometrist, declined to comment. Casey Schwarz, senior counsel for education and federal policy at the nonprofit Medicare Rights Center, said such complications frequently come up when Medicare Advantage members try to use their insurance at eye clinics or dental offices. The federal government pays insurers to run Medicare Advantage plans for people who choose them instead of traditional Medicare. More than half of Medicare beneficiaries sign up for the private plans. Many offer routine vision and dental coverage that isn&#8217;t included with traditional Medicare. &#8220;We hear from people who choose these plans because of those supplemental benefits, but there is not a lot of transparency around them,&#8221; Schwarz said. The Resolution After receiving the rejection letter, Tuszynski repeatedly contacted UnitedHealthcare to question the decision and filed an appeal with the company. Then, she said, she called a Medicare hotline to complain to federal officials. She also wrote to KFF Health News, which asked the insurer about the case. UnitedHealthcare eventually agreed to cover the bill as if the service had been in-network. &#8220;In good faith, we made an exception,&#8221; Sergel said. However, Tuszynski was warned that if she received medical care from the clinic again, it would not be covered, because the clinic remains out-of-network for such services, Sergel said. &#8220;It doesn&#8217;t sound like that pleased her.&#8221; Tuszynski confirmed that she is not pleased. She said she lost sleep over the dispute and felt that it shouldn&#8217;t have taken so much effort to obtain a fair outcome. &#8220;It&#8217;s just been a horrible, difficult whirlwind,&#8221; she said. The Takeaway Schwarz said regulators should require insurance companies to clearly explain to customers and care providers how different procedures and services will be covered under vision, dental, and health plans. &#8220;They&#8217;re tricky,&#8221; she said. In an ideal world, Schwarz said, Medicare would consider things like dental cleanings, eye checkups, and hearing aids as basic health care that would be covered in the same way as other medical care. But until that happens, she said, patients with any doubt should call their insurers beforehand to check whether services will be covered. Tricia Neuman, a senior vice president with KFF, a health information nonprofit that includes KFF Health News, noted that Medicare&#8217;s website now includes a tool that can help people determine whether their doctors participate in a Medicare Advantage plan. &#8220;This is helpful and a step forward, but information about provider networks is not always correct,&#8221; Neuman said. &#8220;Errors can come at a cost to enrollees, unless they are willing and able to take on their insurer.&#8221; Tuszynski worked for 30 years as a secretary in hospitals and at doctors&#8217; offices, so she&#8217;s familiar with billing issues, she said. &#8220;If I can&#8217;t sort through all this, how can anybody else do it?&#8221; She knows her $340 bill was much smaller than the medical debts many other people face. But she said it was a serious amount of money to her, and she was glad she objected to the insurer&#8217;s contention that the bill shouldn&#8217;t be covered. &#8220;I have a strong feeling about right and wrong — and this is just wrong,&#8221; she said. For 2026, she decided to shift out of her Medicare Advantage plan. She now is enrolled in traditional Medicare, plus a supplemental plan to help with copays and other costs. She pays $184 a month for that plan, compared with paying no separate premium for her old Medicare Advantage plan. Now she won&#8217;t have to worry about private insurers&#8217; limited networks of contracted care providers, she said. Her glaucoma treatment will be covered at the Madison eye clinic. However, she no longer has insurance coverage for eyeglasses, just a discount plan if she buys glasses from certain stores. She used her Medicare Advantage insurance to buy new glasses shortly before switching. &#8220;Hopefully, those will last me a while,&#8221; she said. Bill of the Month is a crowdsourced investigation by KFF Health News and The Washington Post&#8217;s Well+Being that dissects and explains medical bills. Since 2018, this series has helped many patients and readers get their medical bills reduced, and it has been cited in statehouses, at the U.S. Capitol, and at the White House. Do you have a confusing or outrageous medical bill you want to share? Tell us about it! KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', '<p>ذهبت المتقاعدة باربرا توشينسكي (70 عاماً) إلى عيادة للعيون في مايو الماضي مطمئنة إلى أن تأمينها سيغطي الزيارة. فقد شُخِّصت بالغلوكوما (الزرق) في عينها اليمنى عام 2019، وخضعت لإجراء ليزري عام 2022، وتستخدم قطرات طبية لوقف التدهور، ما يستلزم متابعة دورية. قبل الموعد، بحثت عبر موقع شركة التأمين ورأت علامة خضراء تفيد بأن العيادة ضمن الشبكة، فافترضت أن الزيارة مغطاة.</p><p>لكن الفاتورة وصلت. ورغم أن طبيب البصريات طمأنها بأن حالتها مستقرة، تبيّن أن التغطية ليست كما توقعت. الفاتورة بلغت 340 دولاراً، بينها 120 دولاراً لاختبار الرؤية و100 دولار لتصوير العصب البصري.</p><ul><li><strong>الإجراء الطبي:</strong> فحص نظر وتصوير للعصب البصري.</li><li><strong>الفاتورة النهائية:</strong> 340 دولاراً (120 لاختبار الرؤية، 100 للتصوير).</li><li><strong>جوهر الإشكال:</strong> تغطية بصريات مقابل تغطية طبية.</li></ul><p>رفضت خطة «ميديكير أدفانتج» من UnitedHealthcare دفع التكاليف، بدعوى أن المستفيدة لا تمتلك مزايا خارج الشبكة. تساءلت توشينسكي: كيف تكون العيادة داخل الشبكة وخارجها في الوقت نفسه؟ وبعد احتجاجها وإرسالها لقطة شاشة تُظهر أن العيادة «داخل الشبكة»، أوضح ممثلو الشركة أن العيادة ضمن شبكة <strong>خطة البصريات</strong> فقط (للنظارات والعدسات)، لكنها <strong>ليست ضمن شبكة الخطة الطبية</strong>، فيما تُعامل علاجات الغلوكوما كخدمات طبية.</p><p>متحدثة باسم UnitedHealthcare قالت إن هذا الترتيب شائع حتى في الخطط غير المرتبطة بميديكير، وإن التباس المرضى مفهوم. ونصحت بالسؤال مسبقاً عمّا إذا كان مقدم الخدمة «داخل الشبكة» للخدمة المحددة، وإلا فعلى المستفيد قراءة التفاصيل الدقيقة للوثيقة. عيادة Steinhauer Family Eye Clinic امتنعت عن التعليق.</p><p>بحسب مركز حقوق ميديكير، تتكرر هذه التعقيدات مع مستفيدي «ميديكير أدفانتج» في عيادات العيون والأسنان. فهذه الخطط الخاصة، التي تديرها شركات تأمين بتمويل حكومي مقابل ميديكير التقليدي، تجتذب أكثر من نصف المستفيدين بعروض تشمل الرعاية الروتينية للعيون والأسنان، لكن شفافية تفاصيل التغطية تبقى محدودة.</p><p>بعد طعون واتصالات بخط ميديكير وتواصل إعلامي، وافقت UnitedHealthcare في النهاية على تغطية الفاتورة ومعاملتها كخدمة داخل الشبكة. وتقدم هذه الحالة درساً عملياً للمرضى:</p><ul><li>اسأل مقدّم الخدمة صراحة: هل هذه الخدمة مغطاة ضمن شبكتي الطبية أم البصرية؟</li><li>اطلب تأكيد التغطية أو تقديراً مسبقاً للتكلفة قبل الإجراء.</li><li>تحقق من رموز الفوترة المستخدمة لأنها تحدد ما إذا كانت الخدمة «طبية» أو «بصرية».</li><li>احتفظ بأدلة مثل لقطات شاشة تُظهر حالة «داخل الشبكة».</li><li>في حال الرفض، قدّم استئنافاً وتواصل مع الجهة المنظمة المختصة.</li></ul>', 'https://kffhealthnews.org/news/article/medicare-advantage-eye-care-wisconsin-bill-of-the-month-january-2026/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/Jan_BOTM_Tuszynski_10-resized.jpg?w=1024', 'Tony Leys', '2026-01-30 10:00:00', '2026-01-31 08:09:42.310938', 'ar', 'health-reports', NULL, 5, NULL, false, false, NULL, 'approved', NULL, '2026-01-31 08:20:12.945', NULL, '["التأمين الصحي", "تأمين البصر", "الغلوكوما", "ميديكير أدفانتج", "شبكة مقدمي الخدمة", "فواتير طبية", "الولايات المتحدة", "حقوق المرضى"]', '{"topics": ["التأمين الصحي", "تأمين البصر", "الغلوكوما", "ميديكير أدفانتج", "شبكة مقدمي الخدمة", "فواتير طبية", "الولايات المتحدة", "حقوق المرضى"], "summary": "متقاعدة في ويسكونسن اكتشفت أن عيادة عيونها داخل الشبكة للبصريات لكنها خارجها للعلاج الطبي، فتلقّت فاتورة قدرها 340 دولاراً قبل أن توافق شركة التأمين على تغطيتها لاحقاً.", "entities": [], "seoTitle": "التباس التأمين الطبي والبصري يترك مريضة بفاتورة مفاجئة", "subtitle": "عيادة داخل الشبكة للبصريات وخارجها لعلاج الغلوكوما", "seoDescription": "قصة متقاعدة أمريكية اكتشفت أن عيادتها داخل الشبكة للبصريات لكنها خارجها للعلاج الطبي، فصدرت لها فاتورة 340 دولاراً. كيف تتجنب الالتباس والنصائح قبل زيارة العيون؟", "credibilityScore": 50}', '2026-01-31 08:09:42.310938', '2026-01-31 08:20:12.945');
INSERT INTO public.radar_items VALUES ('2f059482-7413-4421-b05d-4ccfcb196c53', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'd1e3a2040985d777f38665c499bed84b', 'Pediatricians Release Child Vaccine Recommendations That Break With CDC', NULL, 'The AAP has released new vaccine guidance that counteracts the recent CDC updates. Image Credit: FatCamera/Getty Images The American Academy of Pediatrics (AAP) issued an updated childhood vaccine schedule, which clashes with recently revised recommendations set by the CDC. The AAP’s vaccine guidance more closely aligns with a standard vaccine schedule. Medical experts express relief over the AAP’s recommendations, which they say are best for preventing the spread of infectious diseases. Scienti', NULL, 'The AAP has released new vaccine guidance that counteracts the recent CDC updates. Image Credit: FatCamera/Getty Images The American Academy of Pediatrics (AAP) issued an updated childhood vaccine schedule, which clashes with recently revised recommendations set by the CDC. The AAP&#8217;s vaccine guidance more closely aligns with a standard vaccine schedule. Medical experts express relief over the AAP&#8217;s recommendations, which they say are best for preventing the spread of infectious diseases. Scientists uphold the position that vaccine recommendations should be based on reliable scientific evidence. The American Academy of Pediatrics (AAP) released an updated childhood vaccine schedule on January 27 that contrasts with the Center for Disease Control and Prevention&#8217;s (CDC) controversial changes from earlier this month. The CDC reduced its universally recommended vaccines, moving six vaccinations into conditional categories. The AAP continues recommending all vaccines previously on the schedule. Aaron Milstone, MD, MHS, is a member of the AAP Committee on Infectious Diseases that drafted the new recommendations and the Pediatric Director of Infection Prevention at Johns Hopkins Health System. He told Healthline that the committee&#8217;s guidance reflects the realities of American healthcare. “We&#8217;re living in the real world of the United States,&#8221; he said. &#8220;Our health system is strong, but it&#8217;s imperfect, and the recommendations we make are in the context of some of those imperfections.” The AAP&#8217;s updated vaccine guidance marks a significant break in decades of collaboration with the CDC. Here&#8217;s what you need to know. What&#8217;s different in the AAP guidelines The CDC now recommends hepatitis A, hepatitis B, and meningococcal vaccines only for &#8220;higher-risk&#8221; children. It placed rotavirus, COVID-19, and flu shots in a new &#8220;shared clinical decision making&#8221; category, requiring doctor-patient discussions rather than universal recommendations. The AAP continues recommending all previously scheduled vaccines for children and advises pediatricians to maintain their existing vaccination practices. Milstone said vaccination recommendations should be based on science and what public health experts understand about the community. He pointed to how Hepatitis B is now only recommended for babies who are at a higher risk. “Although we would love all moms to have prenatal care during pregnancy, we know that, unfortunately, some moms don&#8217;t get prenatal care during pregnancy, or they don&#8217;t get tested during pregnancy, or that some kids aren&#8217;t able to show up for some of their vaccine visits,&#8221; Milsone said. &#8220;So recognizing that, we make recommendations to protect the community at large, knowing that our health system doesn&#8217;t have all the safety nets of some other health systems.&#8221; AAP breaks longstanding collaboration with CDC The AAP has issued vaccine recommendations since the 1930s, while the CDC began publishing its schedule in 1964. The organizations have historically worked together to create unified guidance. This divergence leaves parents and pediatricians navigating conflicting recommendations from two major health authorities on childhood immunizations. The AAP&#8217;s new schedule aligns with its August 2025 update, which followed the previous CDC guidelines. The U.S. Department of Health and Human Services defended the CDC&#8217;s position. Press Secretary Emily Hilliard told Healthline the new guidelines align &#8220;U.S. guidance with international norms&#8221; at President Donald Trump&#8217;s request. Other health systems like Denmark, a country that the Trump administration has repeatedly highlighted, recommend fewer vaccines than the United States. But Benjamin Lopman, PhD, an epidemiologist at Emory University’s Rollins School of Public Health who has researched rotavirus vaccines for more than a decade, said the changes are not based on new science. “In the last several months, there has been no new data on how well these vaccines work,” he told Healthline. “It’s very clear that anything on the schedule has shown to be the best way to prevent infection.” Milstone said that comparing the U.S. to countries with universal healthcare misses a crucial point: those systems can catch what vaccines prevent because everyone has access to care. The U.S. can&#8217;t make that assumption. Lopman said rotavirus illustrates why the U.S. needs broader vaccine coverage than some other countries. “This is a disease that, if properly treated with great access, easy access to healthcare, there should be no mortality, no long-term health consequences. But we know there are barriers in this country,” Lopman told Healthline. These barriers include getting to a healthcare professional in a timely manner and the high price of care. Before the rotavirus vaccine was added to the routine schedule in 2006, nearly every child was infected before age five, CDC data shows. Between 55,000 and 70,000 children were hospitalized, and 20 to 60 died each year. After vaccine adoption, hospitalizations dropped nearly 80%. Lopman told Healthline that’s what concerns him about the possibility of rotavirus vaccine coverage decreasing. “There’s no way to prevent getting infected with this virus aside from vaccination. Without it, every kid will get infected by their fifth birthday and probably earlier for most kids, and that’s true for many other of these viruses we can prevent with vaccines,” Lopman said. Doctors &#8216;relieved&#8217; to follow AAP&#8217;s vaccine schedule Amanda Furr, MD, chief medical officer of Zarminali Pediatrics, which operates clinics in 10 states, said doctors were relieved to learn their offices would continue to follow the existing AAP guidelines. Furr told Healthline that she appreciates the AAP’s updated schedule and said it’ll be a trusted reference point for physicians. “The standard vaccine chart assumes that you&#8217;re on track for all of your vaccines at an age-appropriate time frame, which is what we want. But in the real world, that doesn&#8217;t always happen,” she said. Furr said having the additional detail on how to catch children up and how to approach specific patient populations is “extremely valuable” and something pediatricians use every day. The CDC schedule previously included detailed protocols, but the new schedule changes the format. “Since we&#8217;re no longer looking to the CDC to provide that information, everyone is very grateful for the direction and the initiative AAP has taken to fill that void.” Navigating competing recommendations Jasjit Singh, MD, a pediatric infectious diseases sub-specialist and medical epidemiologist at Rady Children’s Health in Orange County, CA, said parents should trust their pediatricians. “Their pediatrician really is an expert on this, and they know the science behind the vaccines, they know the evidence for why recommendations are made and when children are most vulnerable to vaccine-preventable illnesses,” she told Healthline. Her advice to parents is to ask their pediatrician what vaccines they would give to their own child. All vaccines remain available and fully covered by insurance regardless of which guidelines families follow. Doctors concerned about mixed messages Doctors worry that competing guidelines could undermine the parent-pediatrician relationship and lead to worse outcomes. Singh expressed concern that parents who previously trusted their pediatricians may now wonder if they&#8217;ve made the right call. That breakdown of trust could lead to parents delaying or skipping vaccines, putting more kids at risk of serious complications from vaccine-preventable diseases, she said. She pointed to the 2024-25 flu season, which saw at least 280 pediatric deaths, the highest non-pandemic number since the CDC began tracking in 2004. About 90% of the children who died and were eligible for vaccination were not fully vaccinated, according to CDC data. That flu season also saw the lowest pediatric vaccination rate in roughly 15 seasons, 50.2% according to the CDC. “That’s a lot of children dying from a vaccine-preventable illness,” Singh said. Milstone said doctors have always engaged in shared decision making with families—that&#8217;s nothing new. What concerns him is the framing of the new guidance. &#8220;What&#8217;s changing now is the phrasing to cast doubt,&#8221; he said. &#8220;A lot of what&#8217;s changing is raising doubt and fear that the advice people have been given is not in the best interest of their child.&#8221; He emphasized that pediatricians&#8217; goals haven&#8217;t changed. “The pediatricians are doing what&#8217;s best for kids and their health. That is our goal,” he said.', NULL, 'https://www.healthline.com/health-news/aap-child-vaccine-recommendations-break-with-cdc', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/child-vaccine-1296x728-header-copy.jpg', NULL, NULL, '2026-01-29 13:36:30.768826', 'en', 'health-news', 'health-news', 90, NULL, false, false, NULL, 'approved', NULL, '2026-01-29 13:44:29.516', NULL, '["AAP", "CDC", "childhood vaccines", "vaccine recommendations", "infectious diseases"]', '{"topics": ["vaccination guidelines", "child health", "public health policy"], "summary": "أصدرت الأكاديمية الأمريكية لطب الأطفال (AAP) جدولاً محدثًا لتطعيمات الأطفال يتعارض مع التوصيات الأخيرة لمراكز السيطرة على الأمراض (CDC). يهدف الجدول الجديد إلى تعزيز الوقاية من الأمراض المعدية بناءً على أدلة علمية موثوقة.", "entities": ["American Academy of Pediatrics", "CDC", "Aaron Milstone", "Johns Hopkins Health System"], "credibilityScore": 85}', '2026-01-29 13:36:30.768826', '2026-01-29 13:44:29.516');
INSERT INTO public.radar_items VALUES ('5a83a613-2d9d-4894-b4dc-09d3021d6508', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '4f24164e0aef7bb5925e41bca7017f5b', 'Políticas del gobierno chocan con el conocimiento emergente sobre los daños a largo plazo de covid', NULL, 'Estos hallazgos generan nuevas preocupaciones sobre las políticas relacionadas con covid durante la administración Trump, según investigadores.', NULL, 'Posible riesgo de autismo en ni&#241;os. C&#233;lulas cancer&#237;genas latentes que se reactivan. Envejecimiento acelerado del cerebro. En mayo de 2023, funcionarios federales declararon el fin de la pandemia nacional de covid. Pero m&#225;s de dos a&#241;os despu&#233;s, un n&#250;mero creciente de investigaciones sigue revelando informaci&#243;n sobre el virus y su capacidad de causar da&#241;o mucho tiempo despu&#233;s de que se resuelve la infecci&#243;n inicial, incluso en algunos casos en los que los s&#237;ntomas fueron leves. Estos hallazgos generan nuevas preocupaciones sobre las pol&#237;ticas relacionadas con covid durante la administraci&#243;n Trump, seg&#250;n investigadores. Aunque algunos estudios muestran que las vacunas contra covid ofrecen beneficios protectores frente a efectos a largo plazo en la salud, el Departamento de Salud y Servicios Humanos (HHS, por sus siglas en ingl&#233;s) ha limitado dr&#225;sticamente las recomendaciones sobre qui&#233;nes deben vacunarse. Adem&#225;s, la administraci&#243;n fren&#243; contratos impulsados durante el gobierno de Joe Biden que buscaban desarrollar vacunas contra covid m&#225;s protectoras. El gobierno federal est&#225; reduciendo estos esfuerzos justo cuando investigadores piden m&#225;s fondos y, en algunos casos, seguimiento a largo plazo de personas previamente infectadas. &#8220;La gente lo olvida, pero el legado de covid ser&#225; duradero, y estaremos aprendiendo sobre sus efectos cr&#243;nicos por mucho tiempo&#8221;, dijo el epidemi&#243;logo Michael Osterholm, director del Centro de Investigaci&#243;n y Pol&#237;tica de Enfermedades Infecciosas de la Universidad de Minnesota. La administraci&#243;n Trump afirm&#243; que la vacuna contra covid sigue estando disponible y que se alienta a las personas a hablar con sus proveedores de salud sobre lo que es mejor para ellas. La vacuna contra covid y otras del calendario de vacunaci&#243;n de los Centros para el Control y la Prevenci&#243;n de Enfermedades (CDC,por sus siglas en ingl&#233;s) siguen estando cubiertas por los seguros, de modo que no es necesario pagar del propio bolsillo, indicaron funcionarios. &#8220;Actualizar la gu&#237;a de los CDC y ampliar la toma de decisiones cl&#237;nicas compartidas restaura el consentimiento informado, da protagonismo a padres y proveedores de salud, y desalienta pol&#237;ticas ‘iguales para todos&#8217;&#8221;, dijo Emily Hilliard, vocera del HHS. Aunque covid se ha vuelto menos letal, debido a la inmunizaci&#243;n de la poblaci&#243;n y a mutaciones que han debilitado al virus, investigadores se&#241;alan que la politizaci&#243;n en torno a la infecci&#243;n est&#225; oscureciendo lo que la ciencia confirma cada vez m&#225;s: el potencial de covid de causar problemas de salud inesperados y posiblemente cr&#243;nicos. Esto, a su vez, seg&#250;n los cient&#237;ficos, impulsa la necesidad de m&#225;s investigaci&#243;n, no menos, ya que a largo plazo covid podr&#237;a tener importantes consecuencias econ&#243;micas y sociales, como mayores costos en el sistema de salud y m&#225;s demandas sobre programas sociales y personas cuidadoras. El impacto econ&#243;mico promedio anual de los efectos prolongados de covid se estima en $1.000 millones a nivel global y $9.000 por paciente en Estados Unidos, seg&#250;n un informe publicado en noviembre en la revista NPJ Primary Care Respiratory Medicine. En este pa&#237;s, las p&#233;rdidas anuales por ingresos no percibidos se calculan en unos $170.000 millones. Un estudio estima que la gripe gener&#243; $16.000 millones en costos directos de salud y $13.000 millones en p&#233;rdidas de productividad durante la temporada 2023-2024, seg&#250;n un informe del 30 de diciembre publicado en medRxiv, una plataforma en l&#237;nea que difunde trabajos a&#250;n no revisados por colegas. El alcance creciente de covid Desde que surgi&#243; en 2019, desatando una pandemia que, seg&#250;n la Organizaci&#243;n Mundial de la Salud, ha causado la muerte de m&#225;s de 7 millones de personas, se ha aprendido mucho sobre covid. Para la primavera de 2020, ya se usaba el t&#233;rmino &#8220;covid prolongado&#8221; para describir problemas de salud cr&#243;nicos que pueden persistir tras la infecci&#243;n. Estudios m&#225;s recientes muestran que la infecci&#243;n por el virus que causa el covid, el SARS-CoV-2, puede generar riesgos elevados para la salud desde varios meses hasta m&#225;s de un a&#241;o despu&#233;s. Por ejemplo, investigadores que han seguido a ni&#241;os nacidos de madres que contrajeron el virus durante el embarazo han descubierto que podr&#237;an tener mayor riesgo de autismo, retrasos en el habla y el desarrollo motor, u otros desaf&#237;os del neurodesarrollo. Otro estudio hall&#243; que los beb&#233;s expuestos a covid en el &#250;tero experimentaron un aumento de peso acelerado durante su primer a&#241;o de vida, lo cual podr&#237;a ser un indicador temprano de problemas metab&#243;licos y un mayor riesgo de enfermedades cardiovasculares en el futuro. Estos estudios sugieren que evitar una infecci&#243;n grave por covid durante el embarazo puede reducir riesgos no solo durante la gestaci&#243;n, sino tambi&#233;n para futuras generaciones. Eso podr&#237;a ser otra buena raz&#243;n para vacunarse durante el embarazo. &#8220;Hay otros sistemas del cuerpo, adem&#225;s del cerebro fetal en desarrollo, que tambi&#233;n pueden verse afectados&#8221;, dijo Andrea Edlow, profesora asociada de obstetricia, ginecolog&#237;a y biolog&#237;a reproductiva en la Facultad de Medicina de Harvard, quien particip&#243; en ambos estudios. &#8220;Definitivamente necesitamos m&#225;s investigaci&#243;n&#8221;. Los epidemi&#243;logos se&#241;alan algunos desaf&#237;os emergentes espec&#237;ficos. Un estudio del Reino Unido publicado en la revista New England Journal of Medicine encontr&#243; que personas que se hab&#237;an recuperado por completo de infecciones leves de covid presentaban un d&#233;ficit cognitivo equivalente a una disminuci&#243;n de tres puntos en el coeficiente intelectual. Entre los m&#225;s de 100.000 participantes, estos problemas fueron mayores en quienes ten&#237;an s&#237;ntomas persistentes, llegando a una ca&#237;da de nueve puntos en quienes fueron hospitalizados en cuidados intensivos. Ziyad Al-Aly, epidemi&#243;logo cl&#237;nico que ha estudiado los efectos a largo plazo de covid, hizo c&#225;lculos y estim&#243; que el virus pudo haber aumentado el n&#250;mero de adultos con un coeficiente intelectual menor a 70 en Estados Unidos de 4,7 millones a 7,5 millones, es decir, un incremento de 2,8 millones de personas con un nivel de deterioro cognitivo que requiere apoyo social significativo, escribi&#243;. &#8220;La gente se contagia y desarrolla covid-19, algunas personas se recuperan bien, pero otras empiezan a tener problemas de memoria, concentraci&#243;n o confusi&#243;n mental&#8221;, dijo. &#8220;Incluso personas con s&#237;ntomas leves. Puede que ni siquiera se den cuenta&#8221;. Diane Yormark, de 67 a&#241;os, residente de Boca Raton, Florida, lo entiende bien. Tuvo covid en 2022 y en 2023. La segunda vez, le quedaron secuelas como fatiga y una mente nublada. &#8220;Me sent&#237;a como cuando tomas un poco m&#225;s de vino de la cuenta la noche anterior y no est&#225;s del todo bien&#8221;, dijo Yormark, redactora publicitaria retirada, quien afirm&#243; que los peores s&#237;ntomas duraron unos tres meses tras la infecci&#243;n. &#8220;Algo de la mente nublada ha desaparecido. ¿Pero me siento como antes? No como era yo&#8221;. Datos de m&#225;s de una docena de estudios sugieren que las vacunas contra covid pueden ayudar a reducir el riesgo de infecciones graves, as&#237; como efectos de salud a largo plazo, aunque los investigadores indican que se necesitan m&#225;s estudios. Pero las tasas de vacunaci&#243;n siguen siendo bajas en Estados Unidos: solo alrededor del 17% de la poblaci&#243;n adulta report&#243; haberse aplicado la dosis actualizada para 2025-2026, seg&#250;n datos de los CDC al 16 de enero. Funcionarios de la administraci&#243;n Trump, encabezados por el secretario de Salud y Servicios Humanos Robert F. Kennedy Jr., han reducido el acceso a las vacunas contra covid a pesar de la falta de evidencia nueva que respalde posibles da&#241;os. Aunque las vacunas fueron uno de los logros clave de la primera administraci&#243;n Trump, que lider&#243; su desarrollo, Kennedy ha afirmado sin pruebas que son &#8220;la vacuna m&#225;s mortal jam&#225;s creada&#8221;. En mayo, escribi&#243; en X (antes Twitter) que los CDC dejar&#237;an de recomendar la vacuna contra covid para ni&#241;os sanos y mujeres embarazadas, citando la falta de datos cl&#237;nicos. Desde entonces, la Administraci&#243;n de Alimentos y Medicamentos (FDA, por sus siglas en ingl&#233;s) emiti&#243; nuevas directrices que limitan la vacuna a personas de 65 a&#241;os o m&#225;s y a individuos de 6 meses o m&#225;s con al menos un factor de riesgo, aunque muchos estados siguen ofreci&#233;ndola de manera m&#225;s amplia. La administraci&#243;n Trump tambi&#233;n detuvo casi $500 millones en fondos destinados a vacunas basadas en ARNm. Funcionarios y algunos legisladores republicanos han cuestionado la seguridad de esta tecnolog&#237;a, que ha sido reconocida con el Premio Nobel por su potencial para tratar diversas enfermedades m&#225;s all&#225; de covid, aunque se realizaron ensayos cl&#237;nicos con decenas de miles de voluntarios antes de que las vacunas de ARNm estuvieran disponibles para el p&#250;blico. Numerosos estudios, incluidos algunos nuevos de 2025, muestran que los beneficios de la vacuna contra covid incluyen la reducci&#243;n de la gravedad de la enfermedad, aunque su protecci&#243;n disminuye con el tiempo. Seguir los hallazgos Investigadores afirman que se necesita m&#225;s apoyo —y de mayor alcance— porque todav&#237;a hay mucho que no se sabe sobre covid y su impacto en el cuerpo. La creciente conciencia de que, incluso en casos leves, existe la posibilidad de da&#241;o de &#243;rganos a largo plazo y muchas veces no detectado, tambi&#233;n justifica una mayor investigaci&#243;n, seg&#250;n especialistas. Un estudio publicado este mes en eBioMedicine hall&#243; que personas con problemas neurocognitivos —como cambios en el olfato o dolores de cabeza despu&#233;s de la infecci&#243;n— ten&#237;an niveles significativos de una prote&#237;na vinculada al Alzheimer en el plasma sangu&#237;neo. eBioMedicine es una revista de acceso abierto, revisada por colegas, publicada por The Lancet. En el cerebro, el virus provoca una respuesta inmunitaria que genera inflamaci&#243;n, puede da&#241;ar c&#233;lulas cerebrales e incluso reducir el volumen cerebral, seg&#250;n una investigaci&#243;n con estudios por im&#225;genes publicada en marzo de 2022 en la revista Nature. Un estudio australiano con im&#225;genes cerebrales avanzadas encontr&#243; alteraciones significativas incluso en personas que ya se hab&#237;an recuperado de infecciones leves, lo cual podr&#237;a explicar d&#233;ficits cognitivos que persisten durante a&#241;os. El autor principal del estudio, Kiran Thapaliya, se&#241;al&#243; que la investigaci&#243;n sugiere que el virus &#8220;podr&#237;a dejar un efecto silencioso y duradero en la salud cerebral&#8221;. Al-Aly estuvo de acuerdo. &#8220;No sabemos qu&#233; pasar&#225; con estas personas dentro de 10 a&#241;os&#8221;, dijo. &#8220;La inflamaci&#243;n del cerebro no es algo bueno. Definitivamente no lo es&#8221;. Esa respuesta inflamatoria tambi&#233;n se ha vinculado con co&#225;gulos sangu&#237;neos, arritmias y mayor riesgo de problemas cardiovasculares, incluso despu&#233;s de una infecci&#243;n leve. Un estudio de la Universidad del Sur de California, publicado en octubre de 2024 en la revista Arteriosclerosis, Thrombosis, and Vascular Biology, encontr&#243; que el riesgo de sufrir un evento card&#237;aco importante sigue siendo elevado casi tres a&#241;os despu&#233;s de una infecci&#243;n por covid. Estos resultados se observaron incluso en personas que no fueron hospitalizadas. &#8220;Nos sorprendi&#243; ver efectos tanto tiempo despu&#233;s&#8221;, dijo James R. Hilser, autor principal del estudio y becario postdoctoral en la Facultad de Medicina David Geffen de la UCLA. &#8220;Independientemente del historial individual de enfermedades card&#237;acas&#8221;. El covid tambi&#233;n puede reactivar c&#233;lulas cancer&#237;genas y provocar una reca&#237;da, seg&#250;n una investigaci&#243;n publicada en julio en la revista Nature. Los investigadores encontraron que el riesgo de morir de c&#225;ncer entre sobrevivientes de esta enfermedad era mayor en personas que hab&#237;an tenido covid, especialmente durante el a&#241;o posterior a la infecci&#243;n. La mortalidad por c&#225;ncer casi se duplic&#243; en quienes dieron positivo, en comparaci&#243;n con quienes dieron negativo. Tambi&#233;n se est&#225;n descubriendo nuevos hallazgos sobre el potencial del virus para afectar a generaciones futuras. Investigadores australianos estudiaron ratones machos y descubrieron que aquellos que se infectaron y luego se recuperaron de covid presentaban cambios en su esperma que alteraron el comportamiento de su descendencia, haci&#233;ndola m&#225;s propensa a la ansiedad. Mientras tanto, muchas personas viven —y luchan— contra las secuelas del virus. Dee Farrand, de 57 a&#241;os, residente de Marana, Arizona, sol&#237;a correr cinco millas y le iba muy bien en su trabajo en ventas. Se recuper&#243; de una infecci&#243;n por covid en mayo de 2021. Dos meses despu&#233;s, su coraz&#243;n comenz&#243; a latir de forma irregular. Farrand se someti&#243; a una bater&#237;a de pruebas en un hospital. Finalmente, su condici&#243;n empeor&#243; tanto que necesit&#243; ox&#237;geno suplementario durante dos a&#241;os. Su capacidad cognitiva disminuy&#243; tanto que no pod&#237;a leer, porque olvidaba la primera oraci&#243;n despu&#233;s de leer la segunda. Tambi&#233;n deb&#237;a dejarse recordatorios de que es al&#233;rgica a los camarones o que le gustan los aguacates. Dijo que perdi&#243; su empleo y regres&#243; a su ocupaci&#243;n anterior como trabajadora social. &#8220;Yo era como el conejito de las bater&#237;as y, de repente, me cansaba tanto al vestirme que ten&#237;a que volver a la cama&#8221;, dijo Farrand. Aunque ha mejorado, covid dej&#243; una huella. Dijo que todav&#237;a no puede volver a correr las cinco millas que antes hac&#237;a sin dificultad. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/politicas-del-gobierno-chocan-con-el-conocimiento-emergente-sobre-los-danos-a-largo-plazo-de-covid/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2206524485-covid-research.jpg?w=1024', 'Stephanie Armour', '2026-01-27 09:59:00', '2026-01-29 13:36:35.395929', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["covid", "vacunas", "efectos a largo plazo", "políticas de salud", "administración Trump", "autismo", "envejecimiento cerebral"]', '{"topics": ["efectos crónicos del covid", "políticas gubernamentales", "vacunación", "investigación médica"], "summary": "الخبر يناقش الأبحاث الجديدة التي تكشف عن الأضرار طويلة الأمد لفيروس كوفيد-19، بما في ذلك المخاطر المحتملة على الأطفال والدماغ. كما يسلط الضوء على تأثير السياسات الحكومية السابقة على مكافحة هذه الآثار.", "entities": ["Michael Osterholm", "administración Trump", "Departamento de Salud y Servicios Humanos (HHS)", "Centro de Investigación y Política de Enfermedades Infecciosas de la Universidad de Minnesota"], "credibilityScore": 80}', '2026-01-29 13:36:35.395929', '2026-01-31 08:07:05.967');
INSERT INTO public.radar_items VALUES ('c9b58627-5cfe-4a89-9b7a-97985f607144', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '2966c9e28a63d94b360f9253f693b5a3', 'What the Health? From KFF Health News: Health Spending Is Moving in Congress', NULL, 'Lawmakers appear on the brink of passing a spending bill for the Department of Health and Human Services and a bipartisan health policy bill delayed for over a year. But the outlook is bleaker for the health care outline released by President Trump last week. Sandhya Raman of CQ Roll Call, Sheryl Gay Stolberg of The New York Times, and Paige Winfield Cunningham of The Washington Post join KFF Health News’ Julie Rovner to discuss those stories and more. Also this week, Rovner interviews oncologis', NULL, 'The Host Julie Rovner KFF Health News @jrovner @julierovner.bsky.social Read Julie''s stories. Julie Rovner is chief Washington correspondent and host of KFF Health News&#8217; weekly health policy news podcast, "What the Health?" A noted expert on health policy issues, Julie is the author of the critically praised reference book "Health Care Politics and Policy A to Z," now in its third edition. Congress appears ready to approve a spending bill for the Department of Health and Human Services for the first time in years — minus the dramatic cuts proposed by the Trump administration. Lawmakers are also nearing passage of a health measure, including new rules for prescription drug middlemen known as pharmacy benefit managers, that has been delayed for more than a year after complaints from Elon Musk, who at the time was preparing to join the incoming Trump administration. However, Congress seems less enthusiastic about the health policy outline released by President Donald Trump last week, which includes a handful of proposals that lawmakers have rejected in the past. This week&#8217;s panelists are Julie Rovner of KFF Health News, Sandhya Raman of CQ Roll Call, Sheryl Gay Stolberg of The New York Times, and Paige Winfield Cunningham of The Washington Post. Panelists Sandhya Raman CQ Roll Call @SandhyaWrites @sandhyawrites.bsky.social Read Sandhya''s stories. Sheryl Gay Stolberg The New York Times @SherylNYT Read Sheryl''s stories. Paige Winfield Cunningham The Washington Post @pw_cunningham Read Paige''s stories. Among the takeaways from this week&#8217;s episode: Congress is on track to pass a new appropriations bill for HHS, with the current, short-term funding set to expire next week. The bill includes a slight bump for some agencies and, notably, does not include deep cuts requested by Trump. But with the administration&#8217;s demonstrated willingness to ignore congressionally mandated spending, the question stands: Will Trump follow Congress&#8217; instructions about how to spend the money? A health package with bipartisan support is set to hitch a ride with the spending bill, after falling by the wayside in late 2024 under pressure from then-Trump adviser Musk. However, the president&#8217;s newly released list of health priorities largely isn&#8217;t reflected in the package. The GOP faces headwinds in the midterms after allowing expanded Affordable Care Act premium tax credits to expire, a change that&#8217;s expected to cost many Americans their health insurance. One year into the second Trump administration, its policies are particularly evident in the political takeover of the nation&#8217;s public health infrastructure, the growing number of uninsured Americans, and creeping brain drain in U.S.-based scientific research. And Health and Human Services Secretary Robert F. Kennedy Jr. has fired members of a panel overseeing the federal government&#8217;s vaccine injury compensation program. Kennedy is expected to remake the panel in an effort to expand the list of injuries for which the government will compensate Americans. The current list does not include autism. Also this week, Rovner interviews oncologist and bioethicist Ezekiel Emanuel to discuss his new book, Eat Your Ice Cream: Six Simple Rules for a Long and Healthy Life. And KFF Health News&#8217; annual Health Policy Valentines contest is now open. You can enter the contest here. Plus, for &#8220;extra credit&#8221; the panelists suggest health policy stories they read this week that they think you should read, too: Julie Rovner: CIDRAP&#8217;s &#8220;Minnesota Residents Delay Medical Care for Fear of Encountering ICE,&#8221; by Liz Szabo. Sheryl Gay Stolberg: Rolling Stone&#8217;s &#8220;HHS Gave a $1.6 Million Grant to a Controversial Vaccine Study. These Emails Show How That Happened,&#8221; by Katherine Eban. Paige Winfield Cunningham: Politico&#8217;s &#8220;RFK Jr. Is Bringing the GOP and the Trial Bar Together,&#8221; by Amanda Chu. Sandhya Raman: Popular Information&#8217;s &#8220;ICE Has Stopped Paying for Detainee Medical Treatment,&#8221; by Judd Legum. click to open the transcript Transcript: Health Spending Is Moving in Congress [Editor&#8217;s note: This transcript was generated using transcription software. It has been edited for style and clarity.] Julie Rovner: Hello from KFF Health News and WAMU public radio in Washington, D.C. Welcome to What the Health? I&#8217;m Julie Rovner, chief Washington correspondent for KFF Health News, and I&#8217;m joined by some of the best and smartest health reporters in Washington. We&#8217;re taping this week on Thursday, Jan. 22, at 10 a.m. As always, news happens fast and things might have changed by the time you hear this. So, here we go. Today we are joined via videoconference by Sandhya Raman of CQ Roll Call. Sandhya Raman: Good morning, everyone. Rovner: Sheryl Gay Stolberg of The New York Times. Sheryl Gay Stolberg: Hello, Julie. Glad to be here. Rovner: And Paige Winfield Cunningham of The Washington Post. Paige Winfield Cunningham: Hey, Julie. Rovner: Later in this episode, we&#8217;ll have my interview with Dr. Ezekiel Emanuel, whose new book, Eat Your Ice Cream, is both a takedown of the wellness industrial complex and a kinder, gentler way to live a more pleasant and meaningful life. But first, this week&#8217;s news. So, and I don&#8217;t want to jinx this, it looks like Congress might pass a spending bill for the Department of Health and Human Services that will become law — meaning not a continuing resolution — for the first time in years. And attached to that spending bill, scheduled for a vote in the House today, is a compromise health extenders deal that was dropped from the final spending bill in 2024 and which we&#8217;ll talk about in a minute. But first, the HHS appropriations bill. Sandhya, what are some of the highlights? Raman: So I think overall we just see a little bit of a slight increase for HHS compared to last year. Some agencies get a little bit of a bump: NIH [the National Institutes of Health], SAMHSA [the Substance Abuse and Mental Health Services Administration], HRSA [the Health Resources and Services Administration], Administration for Community Living. CDC [the Centers for Disease Control and Prevention] is kind of the same as last year. But then we do see some cuts in some places. Something that was getting watched a little bit was refugee and entrant assistance, given some of the different national news related to refugees and immigrants, and so that&#8217;s getting cut by about a billion. And some of the back-and-forth there is, some conservatives wanted more than that, some Democrats didn&#8217;t want that to be cut. I think the big thing in health care that we were waiting on on this was whether or not they would prohibit NIH forward funding, which is something the administration has been pushing for, just giving out a lump sum for grants through NIH rather than over a multiyear period. And the concern the Democrats had on that was that if you&#8217;re doing the lump sum all at first, fewer groups would get money for research. And so there is a prohibition on that, on doing the forward funding. Rovner: But just to be clear, the president, the administration, had asked for deep, deep cuts to the Department of Health and Human Services, and Congress is basically saying: Yep. Nope. Raman: Yeah. I think even if you look at what the House had proposed last year, they had cut a lot of programs, or proposed to cut a lot of, and that was not there. I think a lot of times, what we&#8217;ve seen is that even in Trump 1, there&#8217;d be a lot more proposed cuts in their proposal, when the White House puts out their blueprint, and then Congress comes to more of a medium point, kind of similar to previous years. So I think that was something that a lot of the health groups had celebrated, that they weren&#8217;t going to get the steep cuts that they thought could be part of the process. Rovner: Of course, the big question here is: Does the administration actually spend this money? We saw in 2025 them refusing to spend money, cutting grants, cutting off entire universities. And this is money that Congress had appropriated and that the administration is supposed to spend. Are they going to do it this time, is Congress? Have they put anything in this bill to ensure that the administration is going to do it this time? Raman: There&#8217;s a little bit here and there on some of that. I don&#8217;t think there&#8217;s quite the sweeping things that some Democrats would have wanted to prevent some of that. Just last week, we had the back-and-forth with SAMHSA grants getting pulled and then unpulled. And so there&#8217;s a little language related to that in there, just because that was such a big 24-hour issue. And then education funding is coupled with HHS, and there there is specific language saying you can&#8217;t transfer the money that would be for education into another department to dismantle it. So— Rovner: And, I would say, and basically, you can&#8217;t cut the Department of Education unless Congress says you can. Raman: Yeah. So there&#8217;s some things in there that are like that, but to get appropriations done, it has to be a bipartisan thing to get that to the finish line. So no one is going to get everything they wanted, not even President [Donald] Trump. Rovner: Yes, and I will point out that they are not there yet. The House has to pass this. The Senate has to pass this when they come back next week. We&#8217;ve got, apparently, a gigantic snowstorm coming towards Washington, D.C. So it&#8217;s moving in the right direction, but it&#8217;s not there yet. All right. Now onto the health package that&#8217;s catching a ride on this spending bill. What&#8217;s in it? And how close is it to the package that got stripped from the 2024 bill after Elon Musk tweeted that the bill was too many pages long? Raman: I think it&#8217;s fairly similar. We have a lot of the same PBM [pharmacy benefit manager] language that we had when that got dismantled, and a lot of these same kind of extenders that we see from time to time whenever we get an appropriations deal, extending things that are pretty bipartisan but just never have a place to ride elsewhere — National Health Service Corps, Special Diabetes Program, things like that. I think that since this time we haven&#8217;t had that pushback, we don&#8217;t have Elon Musk weighing in and kind of pulling the strings in the way that we did before, these have been very bipartisan provisions that both chambers have been saying that they want to get this done, they want to get this done as soon as possible, even in the beginning of last year. So I don&#8217;t sense that something&#8217;s really going to derail language targeting PBMs and stuff like that. Rovner: I would say the big piece of this is the deal that Congress came up with in 2024 to require more transparency on the part of these pharmacy benefit managers that everybody on both sides is accusing of pocketing some of the savings that they&#8217;re getting from drug companies and therefore making drug prices more expensive for employers and consumers. Raman: So I think that this has been such a priority that this is their shot to get it done. And it seems like as long as nothing derails appropriations in the next day and a half, then this is their chance to do that. Rovner: So what&#8217;s not in either of these packages are most of the pieces of the legislation that President Trump called for last week in his self-titled Great Healthcare Plan, with the PBM provisions being a major exception. What else is in Trump&#8217;s plan? And what are the prospects for passing it in pretty much any form this year? Winfield Cunningham: I would say not great. Yeah. A couple of things that struck me about this plan, which I would note was one page long: This is very Trumpy. Trump obviously loves, he&#8217;s a lot more into hauling pharmaceutical CEOs into the White House to make deals than he is crafting detailed policy. Because if you&#8217;re actually trying to do health care reform, this is not the way that you would do it. What you would do is actually spend a lot of time on the Hill seeing what Republicans can sign onto, and working with staff to craft detailed policies and etc., etc. But, yeah, so most of this stuff — yet I guess another big thing that struck me was a lot of this actually goes after insurers. There are some things in here that drugmakers don&#8217;t like, but Trump goes so far as to propose bypassing insurers entirely and sending money to people. And of course he doesn&#8217;t detail how that would work. And then there&#8217;s a lot of stuff in here about transparency by insurers. I would note the Affordable Care Act had some insurer transparency provisions already. So I think what this plan, if we want to call it a plan, reflects is just Trump&#8217;s desire to have something that he can call a &#8220;great&#8221; health care plan that he&#8217;s promised for a long time and which he&#8217;s going to talk a lot about. But yeah, I don&#8217;t think we&#8217;re going to see Republicans in Congress do much on this. Yeah, with the exception of the PBMs, which is pretty notable, and I think actually represents a really big win for the pharmaceutical industry, which has obviously felt under fire in this administration and has struck these deals with the White House, which they really don&#8217;t like. But they had been threatened that the administration would go further in trying to do this &#8220;most favored nation&#8221; price caps. And so it&#8217;s interesting because insurers are kind of Trump&#8217;s new target. That&#8217;s what I kind of read in this. And of course I would mention today that major insurers are testifying on the Hill because they&#8217;re under fire for raising insurance premiums. Rovner: Although, as we&#8217;ve noted many times, they&#8217;re raising insurance premiums because the cost of health care is going up. Yes, Sheryl. Stolberg: Julie, I think the political context of the Great Healthcare Plan, the so-called Great Healthcare Plan, is important. First of all, Republicans have had trouble for decades coming up with some kind of health plan, even before the Affordable Care Act was passed and signed into law in 2010. They weren&#8217;t able to do it then. President Trump famously said &#8220;nobody knew&#8221; that health care was &#8220;so complicated.&#8221; He&#8217;s in a situation now where Republicans have stripped many Americans of their health insurance by letting the extended Obamacare credits expire, and we&#8217;re going into a midterm election season in which his party and he have promised repeatedly that they were going to come up with a plan. He said he had a concept of a plan. I think this plan, so to speak, is not even a concept of a plan, and its primary provision actually lifts from what Sen. [Bill] Cassidy was promoting, which was to steer money away from insurance companies and toward consumers. Trump kind of latched onto that. He doesn&#8217;t say that explicitly in this 325-word proposal, but it seems clear to me that that is his idea, and that is just not a workable idea. He wants, they want, to move money into health savings accounts. I cracked up my elbow earlier this year. I had surgery to repair it. I saw the bill. The bill was $122,000. I am very blessed to have good health insurance through my company. There is no way that the government is going to steer that kind of money into a health savings account for an uninsured person. These are accounts that are meant to be sort of supplemental to spend on relatively small expenditures. And if you are an uninsured person, there is really no way that you can cover yourself. And that&#8217;s basically what this so-called &#8220;great&#8221; American health care plan is proposing, which I suspect, if most Americans really looked at it, they would say, is not so great. Rovner: Yeah. I also, I broke my wrist this summer. I also had surgery, although I had outpatient surgery, and it cost $30,000. So it&#8217;s, yeah, health care is really expensive, which, as I said, is why insurance premiums are going up. So, this week marks a year since the start of Trump 2.0, and it would take us the rest of the year to detail all that has changed in health policy. But I did want to hit a few themes, some of which you&#8217;ve started to talk about, Sheryl. One is the administration&#8217;s effort to basically end the federal public health structure as we know it. The Centers for Disease Control and Prevention in Atlanta has basically been taken over by political appointees, most of them without health experience or expertise. Sheryl, you&#8217;re our public health expert here. What does it mean for public health to be basically ceded back to the states? Stolberg: Well, I think this is kind of a novel experiment here. The core of the CDC is its infectious disease programs. Now, over the decades, since the 1970s, the CDC has greatly expanded its remit to cover things like chronic disease and gun violence prevention and auto safety, etc. But its core is infectious disease. And we know that infectious disease knows no borders. So what we risk having here is a patchwork of state-by-state vaccine recommendations, where some states will follow the CDC&#8217;s recommendations, presumably those that are red states. This was never political before. And we&#8217;re seeing some states, like blue states like New York and Massachusetts and other New England states, kind of coming together to put forth their own vaccine recommendations. I think this has implications for what vaccines will be covered and what vaccines will be offered by the Vaccines for Children Program, which was created by [President] Bill Clinton to cover poor kids and make sure they get vaccinated. I don&#8217;t think we know how that&#8217;s going to play out. I saw [Health and Human Services] Secretary [Robert F.] Kennedy [Jr.] yesterday in Harrisburg, Pennsylvania, and he insisted that he&#8217;s not taking any vaccines away from anyone. If you want your vaccines, you can get them. But the truth is that for decades, the American public and the medical establishment have relied on the CDC to provide guidance. The CDC doesn&#8217;t mandate anything, but it provides really important guidance to the country, and the agency is crippled now. Its guidance is not going to be followed. And I think we&#8217;re in uncharted territory here. We&#8217;re already seeing measles is on the rise. The country&#8217;s about to lose its measles elimination status, which we acquired in 2000. Whooping cough is on the rise. Rovner: Basically things we know we can prevent with vaccines. Stolberg: Exactly, exactly. Winfield Cunningham: One of the things I keep thinking about is, Kennedy says over and over again that if you&#8217;re a mom, you should do your own research. And it seems like a lot of the effects here is stepping away from this broad recommendation to now this patchwork of recommendations. So when you go to your pediatrician, you might hear guidance based on AAP&#8217;s [the American Academy of Pediatrics&#8217;] guidance, for example. States are doing different things. And as a parent, when you go to your pediatrician, it all of a sudden, I think, becomes a lot more confusing, especially if you&#8217;re someone who maybe already has a little bit of hesitancy about vaccines. I was in with our pediatrician last week and asked her what they&#8217;re seeing, and people are coming in with a lot more questions. And interestingly, they actually are changing their policy for mandatory vaccines. They actually had required every patient to be up to date by age 2 with the CDC-recommended vaccines. Now those vaccines that are under shared clinical decision-making, they&#8217;re no longer going to require those. And it&#8217;s not, and they&#8217;re going to continue to recommend them, but I think they&#8217;re concerned that patients are going to come in and they&#8217;re saying: Hey, the CDC doesn&#8217;t necessarily recommend these now. I&#8217;m worried about them. So it&#8217;s put pediatricians in a difficult place. But, yeah, it&#8217;s, as a parent, you&#8217;re having to make a million decisions about your children, and this just kind of makes that more complicated and confusing, potentially, for parents. Rovner: And takes time away from doctors who would like to counsel about other things, too. Stolberg: I just want to add one thing about that. Kennedy says do your own research. And if you read the package inserts on a vaccine, you&#8217;re going to see that vaccines have side effects, just like any drug. But that information needs context around it, and the parents who are weighing those side effects need also to be told about the risk of the diseases that those vaccines are intended to prevent. And my kids are grown. I&#8217;m wondering how pediatricians are having that conversation, or if they&#8217;re having that conversation, in talking to parents about: These are the risks of the vaccine. But should your child get measles, these are the risks. Before vaccination was widespread for measles, 450 kids died on average every year. Many more were hospitalized. So I think those conversations need to be had. Winfield Cunningham: And I think it&#8217;s hard for pediatricians sometimes to illustrate that, because we&#8217;re so far removed from people having examples or knowing anyone who had these. Rovner: Not anymore. Winfield Cunningham: Not anymore. But largely, right? I have a lot of parent friends, and I don&#8217;t know a child who&#8217;s had measles. Our pediatrician was telling me that when she was in medical school, it was still common for pediatric hospitals to be filled with babies with rotavirus. She said you could smell it down the hallway. And now, actually, the people in medical school, they&#8217;re not experiencing that, because of widespread vaccination. Rovner: All right. Well, the second big thing I want to hit on is, as Sheryl already mentioned, people losing their health insurance. Last summer&#8217;s big budget bill would cut nearly a trillion dollars from the Medicaid program and make it more difficult for people to maintain their coverage through the Affordable Care Act. Republicans refusing to extend the expanded Affordable Care Act subsidies from the Biden era is already prompting people to drop coverage that they can no longer afford. What does it mean to the health care system as a whole that the number of Americans without health insurance is going to begin to rise again? Raman: I think it&#8217;s a multipronged thing. There are some aspects of these things that might not be felt immediately, that might be later this year or early next year as different provisions of the [One] Big Beautiful Bill kind of come into play — work requirements, things like that that might affect how many people have insurance. But also, I think it kind of goes back to some of the things that Sheryl and Paige were saying about, just, if fewer people are vaccinated, it increases the risks for everyone. And if fewer people have health insurance, regardless of what they have, it also makes it more difficult. If people are not getting treated for things, they get exacerbated into more serious conditions. So I think there are a lot of issues at play. Some of them have just, we&#8217;re kind of waiting to see how the effects are. You know, people that may have skipped out on ACA insurance this year, maybe they haven&#8217;t needed to go to the doctor yet. We&#8217;re in the first month. People might not go every month. But that doesn&#8217;t mean they&#8217;re not going to be hit with something big, even tomorrow, next month, month after that. And so I think all of these things kind of compound together to make it a lot more difficult of a situation, and just a lot of the complexities, I think it&#8217;s kind of in both of them where you&#8217;re not sure. Oh, is this renewed? Is this not renewed? It&#8217;s, I think, a lot more difficult for the average person to follow this national conversation as much as people that are really plugged in, so that by the time that it trickles down to them, it&#8217;s like: Can I sign up for health insurance still? Are the costs high? Am I still eligible? It gets more and more confusing. And then people who might be eligible might kind of be scared away with some of that chilling effect. Stolberg: I should say, I think emergency rooms will also bear the brunt of the reduction in insurance, because without, people who don&#8217;t have health insurance will forgo going to the doctor until their [conditions are] unable to be ignored. And then they will wind up in the emergency room. Rovner: And then those, I was going to say, and then those emergency rooms will end up passing the bills that they can&#8217;t pay— Stolberg: Exactly. Rovner: —onto others who can, or in— Stolberg: Exactly. It will drive up costs— Rovner: Paige, started— Stolberg: —in the end. Winfield Cunningham: I think a lot of this is going to become clearer over the next couple of months. We still don&#8217;t really know the effects of those extra subsidies expiring. I was actually surprised to see that the ACA marketplace enrollment figures they released, I believe last week, were not actually that much lower than last year. But people aren&#8217;t kicked off their plan until they haven&#8217;t paid their premium for three months. So I think we need to wait until April or so to see how many people were, say, auto-enrolled in a plan which they can no longer afford, and now they&#8217;re kicked off. And maybe it&#8217;s fewer people than we think. Maybe it&#8217;s more people than we think. But I think we just don&#8217;t know that yet, and we&#8217;re going to have to wait for a couple months to see. Rovner: Yeah, I think you&#8217;re exactly right. I had the same reaction to seeing those numbers. Like, Wow, those are pretty high. And then it&#8217;s like, yeah, but those aren&#8217;t necessarily people who&#8217;ve had to pay their bills yet. Those are just the people who I think may have signed up hoping that Congress was going to do something. So, yeah, we will have to see how many people, I think it&#8217;s called &#8220;effectuated enrollment,&#8221; and we won&#8217;t get those numbers for a little while. Well, finally, dismantling the federal research enterprise. As I said, we&#8217;ve talked about this a lot, but I didn&#8217;t want to let it sort of go unstated. This administration appears to like to keep people guessing by cutting and then restoring research grants, refusing to spend congressionally appropriated funding until they&#8217;re ordered to do it by the court, and firing or laying off workers only to call them back weeks or months later. All that makes it difficult or impossible for researchers and universities to plan their projects and personnel needs. Combined with new limits on federal student loans for a lot of graduate students, are we at risk of losing the next generation of researchers? We&#8217;re already talking about seeing people moving to Europe to continue their research. Stolberg: Yes. I think the answer to that is an unequivocal yes. I am hearing from scientists who are having trouble filling their postdoctoral slots. Or young scientists. It&#8217;s really the next generation, right? People who are here already and who have families are trying as best they can to sort of stick it out, or maybe they&#8217;ll go into industry if they have to leave academia because they&#8217;ve lost their grant funding, or if they&#8217;ve left NIH. But it really is the next generation of researchers. I hate to draw this comparison, but we did see during World War II, the United States absorbed a lot of European researchers. This is how we got Albert Einstein, right? So I don&#8217;t know that we&#8217;ll see necessarily a reversal of that, of scientists fleeing, but we might see more young people choosing not to go into academic biomedicine. Rovner: And we&#8217;re already seeing, it&#8217;s not just Europe. It&#8217;s China and India— Stolberg: Yeah. Right. Rovner: —offering packages. Stolberg: And they&#8217;re recruiting. Those countries are recruiting. Yeah, they&#8217;re recruiting young scientists, especially China. Rovner: Yeah. Stolberg: And that&#8217;s a good point. David Kessler, the former FDA [Food and Drug Administration] commissioner, has argued that this is really a national security threat for the country. China is a main adversary of the United States, certainly of President Trump. And if we&#8217;re at risk of losing highly qualified biomedical researchers to China, then we are giving them an advantage. Rovner: Yeah, something else we will keep an eye on, I think, for the rest of the year. OK, we&#8217;re going to take a quick break. We will be right back. Meanwhile, back to this week&#8217;s news. The American Academy of Pediatrics is leading a coalition of public health groups that are suing to reverse the changes to the childhood vaccine schedule made by the CDC earlier this month. The suit claims that the administration violated portions of the law that oversees federal advisory committees that require membership on those panels to be, quote, &#8220;fairly balanced,&#8221; and not, quote, &#8220;inappropriately influenced.&#8221; Among other things, the lawsuit asked the court to ban the CDC&#8217;s Advisory Committee on Immunization Practices from further meetings. That would basically stop any further changes to the vaccine schedule, I assume? Raman: At the end of the day, what ACIP does is just a recommendation to CDC, and they can choose whether or not to go with that recommendation. So I&#8217;m not really sure what would happen next, but it is kind of a whack-a-mole situation where just because you stop this does not mean that changes above that aren&#8217;t going to happen. Stolberg: Yeah. The Advisory Committee on Immunization Practices is just that. It&#8217;s an advisory committee. So this lawsuit takes issue with appointments to that committee and also complains that the committee was not consulted before the decision was made public to change the vaccine recommendations. I&#8217;m not exactly sure what the legal authority is for that. There&#8217;s apparently a federal law requiring federal advisory committees to be, quote, &#8220;fairly balanced&#8221; and not &#8220;inappropriately influenced.&#8221; But this isn&#8217;t — it&#8217;s an executive action — right? — to appoint committee members. It comes out of the executive branch. So I don&#8217;t know of any situation in the past where the judiciary has weighed in and said, You can appoint these people or not these people, or You have to redo a committee. So it&#8217;s hard to predict what the courts will say about this. Rovner: Meanwhile, it&#8217;s not just the ACIP that HHS Secretary RFK Jr. is taking aim at. Following his remaking of that advisory committee, he&#8217;s now fired some of the members of a separate panel, the Advisory Commission on Childhood Vaccines, which oversees the federal Vaccine Injury Compensation Program, which Kennedy has said he also wants to revamp. That&#8217;s the program that compensates patients who can demonstrate injury from side effects of vaccines. How big a deal could this be if he&#8217;s going to go after the vaccine compensation program? Stolberg: Julie, this is a big deal, and I&#8217;ll tell you why. That committee sets what is known as the table of vaccines. Which injuries does the federal government compensate for? And the federal government does not compensate for autism as a vaccine injury. And I have no evidence of this, but if I were betting, that is where Kennedy wants to go. He does not like the 1986 law that created the National Vaccine Injury Compensation Program because it offered liability protection to pharmaceutical companies. He wants to strip away the liability protection, but as I understand it, he does not want to do away with the law. He does not want to do away with the compensation program. So he may be trying to lay the foundation for the compensation program to be more expansive and cover injuries or allow claims for injuries that are not currently considered vaccine injuries, like autism. Rovner: Which of course would collapse the program because it&#8217;s paid for by an excise tax on vaccines. That was the original deal back in 1986. The vaccine manufacturers said: We&#8217;ll pay you this tax, from which you, the federal government, will determine who gets compensated. And in exchange, you&#8217;ll relieve us of this liability, because we&#8217;re getting sued to death. And if you don&#8217;t do this, we&#8217;re going to stop making vaccines entirely. That was the origin of this back in 1986. And I was there. I covered it. Stolberg: Yeah, exactly. I have read a lot of this history, and the CDC was really over a barrel. The companies were writing to CDC, saying, We&#8217;re going to pull the plug on our vaccines. And the CDC was worried that American kids were going to go without lifesaving vaccines because companies were going to quit making them. So they pushed this bill. [President Ronald] Reagan didn&#8217;t like it. He signed it into law anyway. And it&#8217;s created this program, which is actually imperfect. A lot of people who actually legitimately have vaccine-injured children have trouble getting compensated through this program., and I think many people on all sides of this issue would say that it does need to be overhauled. But it will be interesting to see who Kennedy picks for those committee slots. Rovner: Yeah, I think we&#8217;re going to learn a lot more about it. We&#8217;re going to learn a lot more about it this year. Well, finally, in vaccine land this week, Texas attorney general and U.S. Senate candidate Ken Paxton on Wednesday announced what his office is calling a, quote, &#8220;wide sweeping investigation into unlawful financial incentives related to childhood vaccine recommendations.&#8221; His statement says that there is a, quote, &#8220;multi-level, multi-industry scheme that has illegally incentivized medical providers to recommend childhood vaccines that are not proven to be safe or necessary.&#8221; Actually, one of the reasons that Congress created the Vaccines for Children Program back in the 1990s, Sheryl, as you mentioned earlier, is because most pediatricians lost money on giving vaccines. And today, many people can&#8217;t even get vaccines from their doctors, because it&#8217;s too expensive for the doctors to stock them. What does Paxton think he might find here? Stolberg: This is like stump the panelists. No one knows. Rovner: I see a lot of people&#8217;s— Raman: I&#8217;m not sure what he thinks he might find, but I do think that he is one of the attorneys general that is generally on the forefront of trying things, to throw spaghetti at the wall and see if it sticks on a variety of issues. So it might be the sort of thing where if he finds something, then it could be kind of a jumping point for other conservative attorneys general. And of course just that he&#8217;s primarying Sen. John Cornyn for Senate, so if it raises his profile for more folks. But I&#8217;m not sure if there&#8217;s a specific thing that he&#8217;s looking for. Rovner: So he&#8217;s trying to curry favor with the anti-vaxxers in Texas, of which we know there are a lot. Raman: That would be my best read. Stolberg: Austin is, actually, the state capital in Austin is a hot spot for anti-vaccine activism. Andrew Wakefield, who wrote the 1998 Lancet article that&#8217;s been retracted, is in Austin. Del Bigtree, who runs the Informed Consent Action Network, is in Austin. There&#8217;s a group that I have written about called Texans for Vaccine Choice that is one of the early parent-driven groups seeking to roll back vaccine mandates, is based in Austin. So there&#8217;s a lot of sentiment there that Ken Paxton might be trying to appeal to. Rovner: See? You&#8217;ve answered my question. Thank you. All right, that is this week&#8217;s news. Before we get to my interview with Dr. Zeke Emanuel, a couple of corrections from last week. First, I misspoke when I said House Republicans were becoming a minority in name only. Of course, I meant they were becoming a majority in name only. I also incorrectly said the lawsuit that helped get the Title X family planning money flowing back to clinics was filed by Planned Parenthood. It was actually filed by the ACLU [American Civil Liberties Union] on behalf of the National Family Planning and Reproductive Health Association. Apologies to all. OK, now we will play my interview with Dr. Zeke Emanuel about his new wellness book, and then we&#8217;ll come back and do our extra credits. I am so pleased to welcome back to the podcast Dr. Ezekiel Emanuel. Zeke is an oncologist and bioethicist by training and currently serves as vice provost for global initiatives and professor of medical ethics and health policy at the University of Pennsylvania. He formerly worked at the National Institutes of Health before he helped write and implement the Affordable Care Act while his brother Rahm was serving as President [Barack] Obama&#8217;s White House chief of staff. Zeke&#8217;s latest book, Eat Your Ice Cream: Six Simple Rules for a Long and Healthy Life, is out now. Zeke, welcome back to What the Health? Ezekiel Emanuel: Oh, it&#8217;s my great honor and pleasure. Rovner: So I feel like the subtitle of this book could be How to Keep Yourself Healthy Without Making Yourself Crazy or Broke and that it&#8217;s a not so thinly veiled attack on what many of us refer to as the &#8220;wellness industrial complex.&#8221; What&#8217;s gone wrong with the wellness movement? Isn&#8217;t it good for us to pursue wellness? Emanuel: It is good for us to pursue wellness. I think that there are probably three things that are seriously wrong with the movement. The first one is that they make wellness an obsession that you have to focus all your energy on, which is totally wrong. Wellness should be a habit that sort of works in the background while you focus on the really important things of life. I think the second thing is they tend to overcomplicate things. Part of that is they&#8217;ve got to send out an email every day or every other day. They&#8217;ve got to do a video, a podcast, what have you. And so they make it complicated so that they have something to report on. And the third thing is they make it oversimple. They&#8217;re reductionist. They talk about diet and exercise and sleep, and leave out other very, very important parts of wellness, maybe the most important part of wellness, which is your social interactions. And almost all these experts ignore it. And the last thing I would say — I guess I have four points — the last thing I would say is they have huge conflicts of interest. The wellness industrial complex is between $1- and $2 trillion a year, depending on what you want to include in that bucket, which means that there&#8217;s lots of people chasing lots of money trying to sell you lots of crazy items. So there&#8217;s money to be had and Them thar hills and people make all sorts of exaggerations. I want to emphasize for your listeners, I&#8217;m selling nothing, absolutely nothing. Rovner: I will say, I went to your book party. I&#8217;ve been to a lot of book parties over the years. Yours is the first one where I actually was not expected to buy the book. You actually gave the book away. Emanuel: Yeah, I can&#8217;t stand that. Oh, I hate that. Rovner: I would say, I assume you were making a point with that. I also ate the ice cream, which was very good. Emanuel: Yes. Rovner: I feel like your underlying message here is that it&#8217;s not enough to make yourself biologically healthy — you have to do things that make you happy, too. Is that a fair interpretation? Emanuel: Yes, that&#8217;s a very fair interpretation. Look, if you&#8217;re going to do wellness right, you&#8217;re going to be doing it for years and decades of your life. You cannot will yourself to do something for decades. You can will yourself to do something for a few weeks and a few months, but then, unless it becomes a habit that you actually enjoy, you&#8217;re simply not going to continue to do it. And so if you want to eat well, you want to exercise, you want to have social interactions, you actually have to make them something that&#8217;s pleasurable for your life, something that you find meaningful, even. That&#8217;s, again, I think something that&#8217;s seriously missing from a lot of these wellness influencers, because they make a lot of wellness about self-denial, about: You should deprive yourself. You should fast. Maybe you should fast. That&#8217;s OK if you can do it and you can work it into your schedule. Actually today is one of my fast days, so I am working it into my schedule. But that&#8217;s not for everyone, and it&#8217;s not essential to wellness and living a long and happy life. Rovner: So what are your six simple rules, in two minutes or less? Emanuel: The first one is: Don&#8217;t be a schmuck. Don&#8217;t take unreasonable risks. Don&#8217;t climb Mount Everest. Don&#8217;t go BASE jumping. Don&#8217;t smoke. Don&#8217;t do a lot of other stupid things. The second is: Engage people. A rich social life is the most important thing for a long, healthy, and happy life, and having close friends who you get together with regularly, talk to every week, have dinners with, acquaintances, very, very important. And then casually talking to people who you happen to interact with, either when you get your coffee, you go to the grocery store, you go to the restaurant, you hop in an Uber or a cab. Those are very important social interactions that we tend to ignore and tend to downplay. The third rule is: Keep your mind mentally sharp. And there are important aspects of that. Don&#8217;t retire. Take on new cognitive challenges. The fourth is: Eat well, and make sure you get rid of the unhealthy eating part and eat important, non-processed items. The fifth is: Exercise. Do the three kinds of exercise: aerobic exercise, strength training, and balance and flexibility with yoga. And the last one is: Sleep well. It&#8217;s the one you cannot will yourself to begin doing. You can only sort of prep the bedroom and then hope it happens. Rovner: So this whole thing didn&#8217;t really need to be book length, but you spent a lot of time reviewing the literature on various aspects of health and wellness, like, you know, a scientist would. Are you trying to make a point here about the current state of science and how the public views it? Emanuel: I am. I am a data-driven guy. I like data. I think when you have more than 3 million people that have been surveyed and followed in terms of social interactions and their impact on your wellness and your physical health, that&#8217;s worth noting, and it&#8217;s worth noting what those studies come to. And they all come to the same basic thing, which is you can reduce your risk of death and mortality in the subsequent six, 10, 12 years, depending upon the study, by about 20% to 30% by greater social interaction, more robust friendships. That&#8217;s a pretty impressive number, if you ask me. So I&#8217;m trying to emphasize the data and get people to understand and be motivated by the data. And I think I&#8217;m pretty clear about moments when I, say, interpret the data differently than a lot of other people do, because I think that&#8217;s part of science. So, for example, the PSA [prostate-specific antigen] test. Most guidelines say you should get a PSA test. I&#8217;m against the PSA test because, yes, it will reduce your risk of dying from prostate cancer, but it does not reduce your overall mortality. I think I don&#8217;t much care what&#8217;s written on my death certificate. I care about the length and wellness of my life, and the PSA isn&#8217;t going to affect that. But others disagree, and then I&#8217;m very frank about those kind of disagreements. Rovner: So in 2014 you rather famously wrote an Atlantic article called &#8220;Why I Hope To Die at 75.&#8221; Has writing this book changed your mind about this? And I will say, I&#8217;m only a year younger than you, so I have a stake in this, too. Emanuel: No, writing this book didn&#8217;t change my mind. It did change some things that I do. I will say, what really changed my mind, to the extent that anything changed my mind, was covid and the idea of getting vaccines after 75, I think, is a good thing, especially if whatever&#8217;s going around is targeting older people. It seems easy to protect yourself, whether from the flu or something like covid, with a vaccine. So that, I have changed my mind. Researching this book made me put a little more emphasis on, for example, strength training, which I had not done a whole lot of, directly. I&#8217;d done it because I ride a bicycle and I strengthen my lower half, my quads and my hamstrings and my gluteal muscles, but I hadn&#8217;t really focused on the upper body. Rovner: You should do Pilates. It&#8217;s great. Emanuel: Noted. Rovner: Zeke Emanuel. It is always fun to chat with you. And congratulations on the book. Emanuel: Thank you, Julie. This has been wonderful and very rapid-fire, more rapid-fire than anyone, because you get right to the heart of things. Rovner: Well, we have a lot more that we&#8217;re going to talk about this week. Thank you, Zeke. Emanuel: Take care, Julie. Bye-bye. Rovner: OK, we&#8217;re back. It&#8217;s time for our extra-credit segment. That&#8217;s where we each recognize the story we read this week we think you should read, too. Don&#8217;t worry if you miss it. We will post the links in our show notes on your phone or other mobile device. Sandhya, why don&#8217;t you go first this week? Raman: My extra credit is called &#8220;ICE Has Stopped Paying for Detainee Medical Treatment,&#8221;and it&#8217;s by Judd Legum for Popular Information, his newsletter. And I thought this was really interesting, because, I think, for me, I look very much at HHS and major health agencies, but his piece kind of looks at how ICE [Immigration and Customs Enforcement] has not been paying third-party providers for medical care for detainees since October and that ICE, last week, the agency kind of quietly announced that it would not be processing any of the claims for medical care until April of 2026. And so doctors are instructed to kind of hold on that. And that&#8217;s kind of a downward spiral of providers denying services to detainees because they know they&#8217;re not going to get paid for a while. And so I thought this was a really interesting piece looking at that. Rovner: Yes, indeed. And kind of scary. Paige. Winfield Cunningham: Yeah, mine is a piece in Politico called &#8220;RFK Jr. Is Bringing the GOP and the Trial Bar Together,&#8221; and it&#8217;s by Amanda Chu. And this really caught my eye because it was a look at how RFK&#8217;s demonization of food and pharma is motivating trial lawyers representing consumers who are saying they&#8217;ve been harmed by these products — one example, of course, is the lawsuit against the maker of Tylenol — and how this really kind of goes against where Republicans have usually been, against trial lawyers representing consumers who say they&#8217;ve been harmed by big, bad companies. And so, yeah, it was a really interesting look at that and just at how RFK&#8217;s kind of populist, pro-consumer streak has fueled all of this. Rovner: The world indeed turned upside down. Sheryl. Stolberg: So my extra credit is from Rolling Stone. The headline is &#8220;HHS Gave a $1.6 Million Grant to a Controversial Vaccine Study. These Emails Show How That Happened,&#8221; and it&#8217;s by Katherine Eban. She&#8217;s a terrific journalist. And this is about the study in Guinea-Bissau. When CDC pulled back its recommendation for children to be vaccinated at birth against hepatitis B, HHS gave this grant to these Danish researchers to conduct this study in Guinea-Bissau, which would compare vaccinated infants to unvaccinated infants. And there was a huge howl of protest. This study would never be done in this country. The idea of withholding a vaccine from an infant that has been proven to be safe and effective is highly unethical. It evokes memories of the Tuskegee study, in which government doctors withheld treatment for syphilis. So there was this huge uproar, and it turns out that the researchers who got the grant are these Danish statisticians who have a really questionable research history. And the story documents, through emails, how they got basically this no-bid grant by coordinating with some of Kennedy&#8217;s allies from his movement, from his vaccine advocacy days. And it was kind of an inside deal, basically. So I just think that this study has generated a lot a lot of complaints. I should say that the researchers have amended the protocol, and now I think they&#8217;re going to give shots to one group at age 6 weeks. But still, it&#8217;s a very problematic study, and the story exposes how it came to be. Rovner: Yeah, it is quite the story. Well, I also have an immigration story. It&#8217;s from my former colleague Liz Szabo at the University of Minnesota&#8217;s Center for Infectious Disease Research and Policy, and it&#8217;s called &#8220;Minnesota Residents Delay Medical Care for Fear of Encountering ICE.&#8221; And it&#8217;s not just undocumented people avoiding medical care, as Liz details. U.S. citizens with serious health needs are also scared of getting caught up in the ICE dragnet that&#8217;s now all around the city. And ICE officials have even been entering hospitals and other health facilities — which in previous years they had not been allowed to do. In the dead of winter in Minneapolis, with a particularly severe flu year, this is threatening to become a health crisis as well as an immigration crisis. OK, that&#8217;s this week&#8217;s show. Before we go, it&#8217;s almost February. That means our annual KFF Health News Health Policy Valentine contest is open. Please send us your clever, heartfelt, or hilarious tributes to the policies that shape health care. I will post a link to the formal announcement in the show notes. As always, thanks to our editor, Emmarie Huetteman, and our producer-engineer, Francis Ying. A reminder: What the Health? is now available on WAMU platforms, the NPR app, and wherever you get your podcast, as well as, of course, kffhealthnews.org. Also as always you can email us your comments or questions. We&#8217;re at whatthehealth@kff.org. Or you can find me still on X, @jrovner, or on Bluesky, @julierovner. Where are you folks hanging these days? Sandhya. Raman: On X and Bluesky, @SandhyaWrites. Rovner: Sheryl Stolberg: I&#8217;m on X and Bluesky, @SherylNYT. Rovner: Paige. Winfield Cunningham: I&#8217;m on X, @pw_cunningham, and Bluesky, @paigecunningham. Rovner: We will be back in your feed next week. Until then, be healthy. Credits Francis Ying Audio producer Emmarie Huetteman Editor Click here to find all our podcasts. And subscribe to &#8220;What the Health? From KFF Health News&#8221; on Apple Podcasts, Spotify, the NPR app, YouTube, Pocket Casts, or wherever you listen to podcasts. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/podcast/what-the-health-430-congress-hhs-funding-health-policy-bill-january-22-2026/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2025/12/WTH-3x2_2025.jpg?w=1024', NULL, '2026-01-22 19:25:00', '2026-01-25 06:50:40.977528', 'ar', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["Congress", "health spending", "HHS", "Trump administration", "health policy", "pharmacy benefit managers"]', '{"topics": ["health policy", "government spending", "legislation", "pharmaceutical regulations"], "summary": "الكونغرس يقترب من تمرير مشروع قانون إنفاق لصالح وزارة الصحة والخدمات الإنسانية، بالإضافة إلى قانون صحي مؤجل منذ أكثر من عام. ومع ذلك، يبدو أن خطة السياسة الصحية التي أصدرها الرئيس ترامب الأسبوع الماضي تواجه مقاومة من المشرعين.", "entities": ["Julie Rovner", "KFF Health News", "Sandhya Raman", "Sheryl Gay Stolberg", "Paige Winfield Cunningham", "Donald Trump", "Department of Health and Human Services"], "credibilityScore": 90}', '2026-01-25 06:50:40.977528', '2026-01-29 13:48:57.201');
INSERT INTO public.radar_items VALUES ('043e8e21-78cb-4b30-b402-81355085fab0', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '2015cc46df6ab5ca7d2a3e3c5fa352b4', 'Sick of Fighting Insurers, Hospitals Offer Their Own Medicare Advantage Plans', NULL, 'Breakups between insurers and health systems, on top of plan cuts, left more than 3.7 million Medicare Advantage enrollees facing a tough choice last year: find new insurance or new doctors. But hospital systems say their Advantage plans can avert such upheaval, giving patients peace of mind.', NULL, 'Ever since Larry Wilkewitz retired more than 20 years ago from a wood products company, he&#8217;s had a commercial Medicare Advantage plan from the insurer Humana. But two years ago, he heard about Peak Health, a new Advantage plan started by the West Virginia University Health System, where his doctors practice. It was cheaper and offered more personal attention, plus extras such as an allowance for over-the-counter pharmacy items. Those benefits are more important than ever, he said, as he&#8217;s treated for cancer. &#8220;I decided to give it a shot,&#8221; said Wilkewitz, 79. &#8220;If I didn&#8217;t like it, I could go back to Humana or whatever after a year.&#8221; He&#8217;s sticking with Peak Health. Members of Medicare Advantage plans, a privately run alternative to the government&#8217;s Medicare program, can change plans through the end of March. Now entering its third year, Peak Health has tripled its enrollment since last year, to &#8220;north of 10,000,&#8221; said Amos Ross, its president. It expanded from 20 counties to 49, he said, and moved into parts of western Pennsylvania for the first time. Although hospital-owned plans are only a sliver of the Medicare Advantage market, their enrollment continues to grow, reflecting the overall increase in Advantage members. Of the 62.8 million Medicare beneficiaries eligible to join Advantage plans, 54% signed up last year, according to KFF, the health information nonprofit that includes KFF Health News. While the number of Advantage plans owned by hospital systems is relatively stable, Mass General Brigham in Boston and others are expanding their service areas and types of plan offerings. Health systems have dabbled in the insurance business for years, but it&#8217;s not for everyone. MedStar Health, serving the greater Washington, D.C., area, said it closed its Medicare Advantage plan at the end of 2018, citing financial losses. &#8220;It&#8217;s a ton of work,&#8221; said Ross, who spent more than a decade in the commercial health insurance industry. Like any other health insurer, hospitals entering the business need a back-office infrastructure to enroll patients, sign up providers, fill prescriptions, process claims, hire staff, and — most importantly — assure state regulators they have a reserve of money to pay claims. Once they get a state insurance license, they need approval from the federal Centers for Medicare & Medicaid Services to sell Medicare Advantage policies. Some systems affiliate with or create an insurance subsidiary, and others do most of the job themselves. Kaiser Permanente, the nation&#8217;s largest nonprofit health system by revenue, started an experimental Medicare plan in 1981 and now has nearly 2 million people enrolled in dozens of Advantage plans in eight states and the District of Columbia. The Justice Department announced Jan. 14 that KP had agreed to pay $556 million to settle accusations that its Advantage plans fraudulently billed the government for about $1 billion over a nine-year period. Last year, UCLA Health introduced two Medicare Advantage plans in Los Angeles County, the most populous county in the United States. Other new hospital-owned plans have cropped up in less profitable rural areas. &#8220;These are communities that have been very hard for insurers to move into,&#8221; said Molly Smith, group vice president for public policy at the American Hospital Association. But Advantage plans offered by hospitals have a familiar, trusted name. They don&#8217;t have to move into town, because their owners — the hospitals — never left. Bad Breakups Medicare Advantage plans usually restrict their members to a network of doctors, hospitals, and other clinicians that have contracts with the plans to serve them. But if hospitals and plans can&#8217;t agree to renew those contracts, or when disputes flare up — often spurred by payment delays, denials, or burdensome prior authorization rules — the health care providers can drop out. These breakups, plus planned terminations and service area cuts, forced more than 3.7 million Medicare Advantage enrollees to make a tough choice last year: find new insurance for 2026 that their doctors accept or, if possible, keep their plan but find new doctors. About 1 million of these stranded patients had coverage from UnitedHealthcare, the country&#8217;s largest health insurer. In a July earnings update for financial analysts, chief financial officer John Rex blamed the company&#8217;s retreat on hospitals, where &#8220;most encounters are intensifying in services and costing more.&#8221; The turbulence in the commercial insurance market has upset patients as well as their providers. Sometimes contract disputes have been fought out in the open, with anxious patients in the middle receiving warnings from each side blaming the other for the imminent end to coverage. When Fred Neary, 88, learned his doctors in the Baylor Scott & White Health system in central and northern Texas would be leaving his Medicare Advantage plan, he was afraid the same thing could happen again if he joined a plan from another commercial insurer. Then he discovered that the 53-hospital system had its own Medicare Advantage plan. He enrolled in 2025 and is keeping the plan this year. &#8220;It was very important to me that I would never have to worry about switching over to another plan because they would not accept my Baylor Scott & White doctors,&#8221; he said. Eugene Rich, a senior fellow at Mathematica, a health policy research group, said hospital systems&#8217; Medicare Advantage plans offer &#8220;a lot of stability for patients.&#8221; &#8220;You&#8217;re not suddenly going to discover that your primary care physician or your cardiologist are no longer in the plan,&#8221; he said. A Health Affairs study that Rich co-authored in July found that enrollment in Advantage plans owned by hospital systems grew faster than traditional Medicare enrollment for the first time in 2023, though not as rapidly as the overall rise in sign-ups for all Advantage plans. The massive UCLA Health system introduced its two Medicare Advantage plans in Los Angeles County in January 2025, even though patients already had a list of more than 70 Advantage plans to choose from. Before rolling out the plan, the University of California Board of Regents discussed its merits at a November 2024 meeting. The meeting minutes offer rare insight into a conversation that private hospital systems would usually hold behind closed doors. &#8220;As increasing numbers of Medicare-enrolled patients turn to new Medicare Advantage plans, UC Health&#8217;s experience with these new plans has not been good, either for patients or providers,&#8221; the minutes read, summarizing comments by David Rubin, executive vice president of UC Health. The minutes also describe comments from Jonathon Arrington, CFO of UCLA Health. &#8220;Over the years, in order to care for Medicare Advantage patients, UCLA has entered numerous contracts with other payers, and these contracts have generally not worked out well,&#8221; the minutes read. &#8220;Every two or three years, UCLA has found itself terminating a contract and signing a new one. Patients have remained loyal to UCLA, some going through three iterations of cancelled contracts in order to remain with UCLA Health.&#8221; Costs to Taxpayers CMS pays Advantage plans a monthly fixed amount to care for each enrollee based on the member&#8217;s health condition and location. In 2024, the federal government paid Advantage plans an estimated $494 billion to care for patients, according to the Medicare Payment Advisory Commission, which monitors the program for Congress. The commission said this month that it projects insurers in 2026 will be paid 14%, or about $76 billion, more than it would have cost government-run Medicare to care for similar patients. Many Democratic lawmakers have criticized overpayments to Medicare Advantage insurers, though the program has bipartisan congressional support because of its increasing popularity with Medicare beneficiaries, who are often attracted by dental care and other coverage unavailable through traditional Medicare. Whenever Congress threatens cuts, insurers claim these generous federal payments are essential to keep Medicare Advantage plans afloat. UCLA Health&#8217;s Advantage plans will need at least 15,000 members to be financially sustainable, according to the meeting minutes. CMS data indicates that 7,337 patients signed up in 2025. A study published in JAMA Surgery in August compared patients in commercial Medicare Advantage who had major surgery with those covered by Medicare Advantage plans owned by their hospital. The latter group had fewer complications, said co-author Thomas Tsai, an associate professor in the Department of Health Policy and Management at the Harvard T.H. Chan School of Public Health. Smith, of the American Hospital Association, isn&#8217;t surprised. When insurers and hospitals are not on opposite sides, she said, care delivery can be smoother. &#8220;There&#8217;s more flexibility to manage premium dollars to cover services that maybe wouldn&#8217;t otherwise be covered,&#8221; Smith said. But Tsai warns seniors that hospital-owned Medicare Advantage plans operate under the same rules as those run by commercial health insurance companies. He said patients should consider whether the extra benefits of Advantage plans &#8220;are worth the trade-off of potentially narrow provider networks and more utilization management than they would get from traditional Medicare.&#8221; In Texas, Neary hopes the closer relationship between his doctors and his insurance plan means there&#8217;s less of a chance that bills for his medical care will be kicked back. &#8220;I don&#8217;t think I would run into a situation where they would not provide coverage if one of their own doctors recommended something,&#8221; he said. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/health-insurance-medicare-advantage-plans-hospitals/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-1333508647-resized.jpg?w=1024', 'Susan Jaffe', '2026-01-26 10:00:00', '2026-01-29 13:36:35.649883', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["Medicare Advantage", "hospital-owned plans", "insurance", "health systems", "patient care"]', '{"topics": ["Medicare Advantage plans", "hospital systems in insurance", "patient choices", "healthcare economics"], "summary": "بسبب الخلافات بين شركات التأمين وأنظمة المستشفيات، بدأ بعض المستشفيات تقديم خطط Medicare Advantage الخاصة بهم لتوفير راحة أكبر للمرضى. هذه الخطط تتيح خيارات أوسع وتخفف من التحديات التي يواجهها المرضى عند تغيير التأمين أو الأطباء.", "entities": ["Larry Wilkewitz", "Peak Health", "West Virginia University Health System", "Humana", "Amos Ross", "Mass General Brigham", "MedStar Health", "KFF"], "credibilityScore": 90}', '2026-01-29 13:36:35.649883', '2026-01-31 08:07:00.504');
INSERT INTO public.radar_items VALUES ('63a66d88-3ebe-419a-abdc-dcdbab656269', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '412a79da524ce4cebd13c36b83c263b3', 'When Suicidal Calls Come In, Who Answers? Georgia Crisis Line Response Rates Reveal Gaps', NULL, 'In Georgia, a high number of callers to the 988 crisis line hang up or disconnect before reaching a counselor. Many other calls are transferred out of state.', NULL, 'If you or someone you know may be experiencing a mental health crisis, contact the 988 Suicide & Crisis Lifeline by dialing or texting &#8220;988.&#8221; Kaitlin Cooke of Cartersville, Georgia, was contemplating suicide when she started calling a statewide mental health crisis line in 2018. She said she would sneak outside and call the hotline behind her car, where her boyfriend would not hear her. The counselors who answered her calls were there for her when no one else was, she said. Each time she called, they spoke to her for at least 45 minutes. And they told her that life &#8220;does get better.&#8221; &#8220;If it weren&#8217;t for this resource, I might have been a statistic,&#8221; said Cooke, now 31, who found a local therapist. Starting in March, the call response record for that resource, the Georgia Crisis and Access Line, and its newer national counterpart, the 988 Suicide & Crisis Lifeline, plummeted in the state. The 988 line was created during President Donald Trump&#8217;s first term. National data shows Georgia is one of several states that have struggled to keep their rates of disconnected or rerouted 988 calls low. Disconnected calls typically involve the caller hanging up, possibly after a long wait time. States are largely responsible for funding and staffing their 988 systems, with some money from the federal government. Mental health experts said proper funding for the 988 system in a state, through a well-staffed response network, can influence whether a caller is connected to a local counselor — or chooses to hang up. The future of mental health services appears uncertain amid massive changes from the Trump administration, including Medicaid cuts that could limit access to care. The cuts could also lead states to consider reducing their allocations to crisis lines, said Heather Saunders, senior research manager for the Program on Medicaid and the Uninsured at KFF, a health information nonprofit that includes KFF Health News. The stakes couldn&#8217;t be higher for callers experiencing severe mental health crises. &#8220;Some of the callers are actively experiencing suicidal thoughts,&#8221; Saunders said. &#8220;Sometimes they actively have a suicide plan and it&#8217;s a very urgent situation.&#8221; Alarm About Call Abandonment Rate Georgia has contracted with Carelon Behavioral Health, a unit of insurance giant Elevance Health, to run its crisis lines. When Carelon dropped a subcontractor that managed staffing the lines, performance plunged. Abandoned calls spiked, which means more callers were hanging up or disconnecting before a counselor answered the phone, Kevin Tanner, commissioner of the state Department of Behavioral Health and Developmental Disabilities, pointed out in a letter to Carelon. The state requires a call abandonment rate of 3% or less, and, Tanner wrote, the current rate was 18%. After sending the letter, the state narrowed its definition of abandoned calls, lowering the current rate. The state now counts only calls disconnected after being on hold for more than 30 seconds and not those rerouted to backup centers. Carelon officials have acknowledged the dip in performance. They said it reflected a &#8220;necessary&#8221; transition from the company&#8217;s vendor and that they were hiring more staff to ensure the crisis lines could handle the demand. Carelon spokesperson Hieu Nguyen said the company is &#8220;committed to ensuring that every Georgian in crisis can access help through 988,&#8221; noting that calls not answered locally are routed to national backup centers. With the help of some federal funding, Georgia is paying Carelon $17 million annually to manage 988 and its predecessor, the Georgia Crisis and Access Line, which is still operating. Crisis calls go to the same response team, whether someone calls 988 or the original state line. Carelon and state officials declined to disclose how much of the money went to the subcontractor, Behavioral Health Link, with Carelon saying it is proprietary information. The state can extend its contract with Carelon to 2032. Camille Taylor, a spokesperson for the state Department of Behavioral Health and Developmental Disabilities, said in December that Carelon had improved its call response performance but that the state continues to monitor the company&#8217;s answer rates. ‘Enormous&#8217; Staffing Challenges Launched in 2022, the national 988 Suicide & Crisis Lifeline connects people experiencing mental health problems, emotional distress, or alcohol or drug use concerns to trained counselors. The free hotline, with the three-digit number mirroring the ease of dialing 911, aims to help avert mental health crises and reduce suicide risk. It also supports people who call for someone they care about. &#8220;All behavioral health is having enormous challenges in terms of staffing,&#8221; said Margie Balfour, an Arizona psychiatrist and a member of a national 988 advisory committee. Being a crisis line counselor &#8220;is a very stressful job,&#8221; she said. &#8220;You&#8217;re talking to people at the peak of their crisis.&#8221; In December, Georgia ranked near the bottom of the 50 states in percentage of calls answered that it kept in state, according to Vibrant Emotional Health, which administers the 988 line nationally. A high number of Georgia calls were routed to national call centers, data showed. The latest national data also showed how different the response times to a 988 call can be. In December, it took one second on average if someone called from Mississippi. It took 74 seconds for a caller from Virginia. While the unofficial industry target rate for answering in-state calls is 90%, more than half the states fell below that mark in December, according to the national data. In Georgia, the tracking data for 988 showed that more than 80% of crisis calls were answered within the state — until March, when the number dropped to 73%. Then it fell again in April, to 62%. The rate rose to 72% in October and reached 79% in December. Local counselors &#8220;should be more familiar with the state infrastructure, mental health system, and resources that are available to people who live in the state,&#8221; said Saunders of KFF. Pierluigi Mancini, interim president and CEO of Mental Health America, said it&#8217;s unlikely that an out-of-state counselor would know much about that state&#8217;s mental health system and providers. The service also sends many predominantly Spanish-speaking callers to out-of-state call centers, possibly hindering their connection to local help, Mancini said. Since the 988 rollout, the volume of calls, texts, and chats to the crisis line totaled more than 19 million by November, according to the Substance Abuse and Mental Health Services Administration. A study found that with the national predecessor to 988, the National Suicide Prevention Lifeline, most suicidal callers who were later interviewed said their call helped stop them from killing themselves. More than 49,000 Americans died by suicide in 2023. Nearly 17 million Americans ages 12 and older said in 2024 they had seriously thought about suicide in the previous year, according to the National Survey on Drug Use and Health. For Generation Z adults, the oldest of whom are now reaching their late 20s, suicide is taking more lives than a decade ago when millennials were the same age, according to a Stateline analysis of federal death statistics. The largest increase in suicide rates for the age group was in Georgia, which jumped 65% from 2014 to 2024. Mike Hogan, a consultant who ran mental health systems in three states, said recent Georgia data reflects &#8220;a bungled transition. It looks like performance fell off a cliff.&#8221; For people calling a crisis line, he said, &#8220;counselors, with the right training, can talk people down and away from the suicidal crisis.&#8221; Balfour noted that 988 has bipartisan support. The system can be improved, she said, emphasizing that it&#8217;s still an important resource that&#8217;s effectively helping people in crisis. &#8220;988 is a success,&#8221; Balfour said. &#8220;And it&#8217;s work in progress.&#8221; Healthbeat is a nonprofit newsroom covering public health published by Civic News Company and KFF Health News. Sign up for its newsletters here. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/georgia-988-suicide-crisis-lifeline-hotline-response-rates-hang-up-mental-health/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2205743759_3840x2560web.jpg?w=1024', 'Andy Miller and Rebecca Grapevine, Healthbeat', '2026-01-28 10:00:00', '2026-01-29 13:36:34.766927', 'ar', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["mental health", "crisis line", "988 Suicide & Crisis Lifeline", "Georgia", "counseling"]', '{"topics": ["mental health crisis", "crisis hotline response", "state funding", "Medicaid cuts"], "summary": "تواجه ولاية جورجيا تحديات في استجابة خط الأزمات النفسية 988، حيث يتم تحويل العديد من المكالمات إلى خارج الولاية أو يتم قطعها قبل الوصول إلى مستشار. يشير الخبر إلى تأثير نقص التمويل والدعم على فعالية هذه الخدمة الحيوية للصحة النفسية.", "entities": ["Georgia Crisis and Access Line", "988 Suicide & Crisis Lifeline", "Kaitlin Cooke", "Heather Saunders", "KFF Health News"], "credibilityScore": 90}', '2026-01-29 13:36:34.766927', '2026-01-31 08:07:19.992');
INSERT INTO public.radar_items VALUES ('d2095def-3c6f-4025-9841-33983ba80b73', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '43400acc6259d63c83873f5dc3931dd0', 'To-Go Coffee Cups Release Thousands of Microplastics: How to Stay Safe', NULL, 'Research shows that to-go coffee cups can release microplastics, depending on the temperature of the beverage. Image credit: Vradiy Art/Stocksy A new study found that heat influences the amount of microplastics released from disposable cups. The type of cup can also affect how much microplastic is leached into a beverage. Cups made of stainless steel or ceramic are your safest options. If you must use a disposable cup, paper cups coated with PHA are generally a safe option. Every day, millions o', NULL, 'Research shows that to-go coffee cups can release microplastics, depending on the temperature of the beverage. Image credit: Vradiy Art/Stocksy A new study found that heat influences the amount of microplastics released from disposable cups. The type of cup can also affect how much microplastic is leached into a beverage. Cups made of stainless steel or ceramic are your safest options. If you must use a disposable cup, paper cups coated with PHA are generally a safe option. Every day, millions of people enjoy their coffee, tea, or other beverages from disposable cups, often without a second thought about what might be lurking in their drink. However, research published in the Journal of Hazardous Materials: Plastics has revealed a surprising concern: these cups can release tiny plastic particles, known as microplastics, into the beverages they hold, especially when exposed to hot liquids. Microplastics, which are fragments smaller than 5 millimeters, are increasingly recognized as a public health concern because they can be ingested or inhaled by humans, accumulate in organs like the lungs or digestive tract, and potentially cause inflammation or other health issues. The researchers further found that even paper cups lined with polyethylene can release microplastics, albeit in lesser amounts than fully plastic cups. Per the authors, this implies that your choice of cup material could help reduce your exposure. The researchers caution, however, that the issue requires further study, as other factors, such as particle size, shape, and chemical surface properties, may also influence health risks. What influences release of microplastics? To learn more about the issue, the researchers took a two-pronged approach. They first analyzed data from 30 previous studies, compiling 237 observations related to microplastic release from various plastic products. This analysis focused on factors such as water temperature and soaking time in relation to microplastic release. Secondly, the research team conducted a case study comparing two common types of disposable cups: pure polyethylene (PE) cups and paper cups lined with a polyethylene coating. Their experiments involved filling the cups with deionized water at two temperatures: cold (5°C/41°F) and hot (60°C/140°F). Steps were taken to prevent contamination as well. After 30 minutes, the water was filtered to collect any microplastics that leached into it. Tools such as scanning electron microscopes and atomic force microscopes were used to examine the size and surface features of the microplastics and the cups. Additionally, the team used Fourier Transform Infrared (FTIR) spectroscopy to identify the chemical composition and to detect changes in the cups’ materials after exposure to water at different temperatures. How heat, cup materials release microplastics The review of studies confirmed a clear pattern: as water temperature increases, so does the release of microplastics from plastic products. Polymers like polyethylene (PE), polypropylene (PP), polystyrene (PS), and polyethylene terephthalate (PET) all showed significant increases in microplastic shedding when soaked in hotter water. However, this effect varied widely — from hundreds to millions of particles — depending on the type of plastic. The researchers also noted that the time the cups were soaked in water did not significantly impact the number of microplastics released. Whether the water sat in the container for a minute or several hours, temperature remained the dominant factor influencing microplastic release. The case study revealed that PE cups released more microplastics than PE-coated paper cups under both cold and hot conditions. Specifically, when the water temperature increased from 5°C (41°F) to 60°C (140°F), microplastic release from PE cups rose by 32.7%. The PE-coated paper cups, however, did not show this temperature-dependent increase. Microscopic analysis showed that the surface of PE cups became rougher and more irregular after exposure to hot water, likely due to physical degradation, which may have led to greater shedding of microplastics. In contrast, the paper cups with PE lining had smoother surfaces and less surface damage, which likely contributed to their lower microplastic release. The researchers estimated that someone drinking 300 milliliters of coffee daily from PE cups could ingest around 363,000 microplastic particles per year. Using PE-coated paper cups could reduce this intake to about 244,000 particles annually. Chemical analyses confirmed that while temperature affected the physical structure of the cups, it caused only minor changes in the chemical composition of the materials. The authors say this suggests that the cups remain chemically stable, but physical wear and surface roughness are key factors in microplastic release. How to reduce your intake of microplastics Lauren Gropper, the CEO and Founder of Repurpose and a sustainability expert, told Healthline that the best option for reducing your intake of microplastics is to avoid using disposable cups made of traditional plastic or petroleum-based plastic, since these give off the highest amount of microplastics. Gropper wasn&#8217;t involved in the study. &#8220;When you put hot coffee in a plastic cup, the heat causes the cup to shed microplastics that end up in your coffee and your bloodstream,&#8221; she said. &#8220;The safest and most sustainable option is always to use a reusable cup that is made from stainless steel or ceramics.&#8221; Gropper explained that these materials are inert and won&#8217;t react with a hot liquid or release toxins into your hot beverage. Leah Ford, Director of Marketing at CJ Biomaterials and an expert on compostable materials, added that if you must use a disposable cup, opt for paper cups that are lined with a compostable biopolymer like polyhydroxyalkanoate (PHA). Ford wasn&#8217;t involved in the study. &#8220;Compostable biopolymers like PHA are designed specifically so they won’t create persistent microplastics,&#8221; she said. Ford went on to explain that PHA is made by fermenting plant sugars and is seen as a food source for common microorganisms. It can undergo biodegradation in compost, soil, and marine environments. &#8220;Additionally, PHA is bioabsorbable by the human body and commonly used for in vitro medical devices and sutures,&#8221; she said. Ford concluded by saying that you can identify this type of cup by looking for a compostability certification, such as that provided by BPI (Biodegradable Products Institute). This organization tests products to ensure they are compostable and biodegradable. They also test for toxicity and per- and polyfluoroalkyl substances (PFAS), she said, making these safer and better for the environment.', NULL, 'https://www.healthline.com/health-news/to-go-coffee-cups-release-microplastics-study', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Takeaway-coffee-Stocksy_txp9368dab1xJE400_Medium_6372233-Header.jpg', NULL, NULL, '2026-01-29 13:36:31.14688', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["microplastics", "to-go coffee cups", "health risks", "disposable cups", "beverage safety"]', '{"topics": ["microplastic contamination", "public health", "sustainable alternatives", "beverage safety"], "summary": "دراسة جديدة تكشف أن أكواب القهوة الجاهزة قد تطلق جزيئات بلاستيكية دقيقة في المشروبات، خاصة عند تعرضها للسوائل الساخنة. يُنصح باستخدام أكواب من الفولاذ المقاوم للصدأ أو السيراميك كخيارات أكثر أمانًا لتقليل التعرض لهذه الجزيئات.", "entities": ["Journal of Hazardous Materials", "Vradiy Art/Stocksy"], "credibilityScore": 80}', '2026-01-29 13:36:31.14688', '2026-01-31 08:07:30.546');
INSERT INTO public.radar_items VALUES ('9aeda500-dae0-4d3e-b046-13264b108a1d', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '6e35f9bcb1745cd8c1e552500e8e0bdf', '14 or More Alcoholic Drinks Per Week Could Raise Colorectal Cancer Risk', NULL, 'Research shows that lifetime alcohol consumption may significantly increase colorectal cancer risk. Image Credit: d3sign/Getty Images A recent study indicates that higher lifetime alcohol consumption may raise the risk of colorectal cancer. The findings show that heavy drinking is associated with the highest risk, particularly rectal cancer, and that former drinkers had a lower risk. The research suggests that lower lifetime alcohol consumption may help reduce the overall risk of developing canc', NULL, 'Research shows that lifetime alcohol consumption may significantly increase colorectal cancer risk. Image Credit: d3sign/Getty Images A recent study indicates that higher lifetime alcohol consumption may raise the risk of colorectal cancer. The findings show that heavy drinking is associated with the highest risk, particularly rectal cancer, and that former drinkers had a lower risk. The research suggests that lower lifetime alcohol consumption may help reduce the overall risk of developing cancer. Colorectal cancer is cancer that starts in either the colon or the rectum. It might also be called colon cancer or rectal cancer, depending on where it originates. According to the American Cancer Society (ACS), colorectal cancer is the third leading cause of cancer-related deaths in males, and the fourth leading cause in females. When these groups are combined, colorectal cancer is the second most common cause of cancer-related deaths. A recent study published in Cancer found that people with a higher lifetime consumption of alcohol may be at a higher risk of developing colorectal cancer. “Our study is one of the first to explore how drinking alcohol over the life course relates to both colorectal adenoma and colorectal cancer risk,” co–senior author Erikka Loftfield, PhD, MPH, of the NCI, part of the National Institutes of Health (NIH), noted in a press release. &#8220;While the data on former drinkers were sparse, we were encouraged to see that their risk may return to that of the light drinkers,&#8221; Loftfield continued. Lifetime alcohol use and colorectal cancer risk The researchers analyzed data from U.S. adults who were enrolled in the National Cancer Institute (NCI) Prostate, Lung, Colorectal, and Ovarian (PLCO) Cancer Screening Trial who did not have a cancer baseline. The team observed that 1,679 colorectal cancer cases occurred among 88,092 participants over the course of a median follow-up of 14.5 years. The findings show that those with average alcohol consumption of 14 or more drinks per week had a 25% higher risk of developing colorectal cancer. Average alcohol use was also associated with a 95% higher risk of developing rectal cancer. These findings were compared to those with a lifetime average of consuming 1 drink or less per week. When the researchers examined drinking consistency, they found that heavy drinking (14 or more drinks per week) was associated with a 91% higher risk of colorectal cancer compared with consistent light drinking (1 drink or less per week). In contrast, when they observed former drinkers, they found no evidence of an increased risk of developing colorectal cancer. Former drinkers also showed a lower risk of developing noncancerous colorectal tumors (adenomas), which may go on to become cancerous. This was in comparison to current light drinkers. These findings may indicate that alcohol cessation can lower a person’s risk. “This study provides hope that it is never too late to reduce alcohol consumption since this can lead to fewer colon polyps and potentially cancer reduction,” said Anton Bilchik, MD, PhD, surgical oncologist, chief of medicine and Director of the Gastrointestinal and Hepatobiliary Program at Providence Saint John’s Cancer Institute in Santa Monica, CA. Bilchik wasn&#8217;t involved in the study. However, the researchers note that the data for their findings were limited. Alcohol’s effect on colorectal cancer risk may be associated with carcinogens produced from alcohol metabolism or alcohol’s effects on gut microbes. More research is needed to test whether these mechanisms are involved. “The results of this observational study were not very straightforward and raise the question about how accurate a survey-based study like this can be,” said Timothy Cannon, MD, Sheridan Director, Molecular Tumor Board and Co-Director of the Gastrointestinal Cancer Program at Inova. Cannon wasn&#8217;t involved in the study. How alcohol consumption affects the body Alcohol consumption can have various effects on your body. Short-term effects of alcohol consumption may include: injuries, such as falls and motor vehicle accidents alcohol poisoning violence Long-term effects of alcohol consumption on the body may include: various cancers, including colorectal and breast cancer high blood pressure heart disease liver disease stroke alcohol use disorder weakened immune system mental health issues, such as depression and anxiety “My advice would be to stay in one of those groups that drink 1 or [fewer] drinks per day,” said Cannon. Other risk factors for colorectal cancer Other lifestyle-related risk factors than alcohol consumption include: having overweight or obesity having type 2 diabetes smoking having a diet high in red meat and processed meats “This study provides further insight into how important lifestyle, diet, and alcohol use are in the development of cancer, but that cancer risk can be reduced by paying attention to all these factors,” said Bilchik. Risk factors that you cannot change include: age having your gallbladder removed a personal or family history of colorectal polyps or cancer a personal history of inflammatory bowel disease (IBD) If you have any questions or concerns about your risk of colorectal cancer, speak with a healthcare professional. “Colorectal cancer is now the leading cause of cancer death in people under 50, and its incidence has essentially doubled since the 1970s,” said Cannon. “This increase has been predominantly in left-sided colon cancers, and I found it interesting that this study showed that alcohol induced colorectal cancer also seems to be predominantly left-sided. Future studies should assess how alcohol might contribute to this epidemic,&#8221; Cannon said.', NULL, 'https://www.healthline.com/health-news/lifetime-alcohol-consumption-colorectal-cancer-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/pulling-bottle-shop-shelf-1296x728-header.jpg', NULL, NULL, '2026-01-29 13:36:31.022193', 'en', 'health-news', 'health-reports', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["alcohol consumption", "colorectal cancer", "cancer risk", "lifetime drinking", "health study"]', '{"topics": ["cancer prevention", "alcohol and health", "colorectal cancer research"], "summary": "تشير دراسة حديثة إلى أن الاستهلاك العالي للكحول على مدى الحياة قد يزيد من خطر الإصابة بسرطان القولون والمستقيم، خاصة سرطان المستقيم. كما أظهرت النتائج أن تقليل استهلاك الكحول قد يساعد في تقليل هذا الخطر بشكل عام.", "entities": ["American Cancer Society", "Erikka Loftfield", "National Cancer Institute", "NIH"], "credibilityScore": 90}', '2026-01-29 13:36:31.022193', '2026-01-31 08:07:33.323');
INSERT INTO public.radar_items VALUES ('3dfe899e-552e-402b-b241-568062e07f5e', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', '7e290d6d05649200e7ef71eec6a840a1', 'Plant Based Diet May Improve Heart Health, Lower Cancer, Kidney Disease Risk', 'نظام غذائي نباتي يحمي القلب ويقلل مخاطر السرطان والكلى', 'Research shows that a plant-based diet may offer protective benefits for heart health and prevention against kidney disease and certain cancers. Image Credit: Tom Werner/Getty Images Recent research suggests that a plant-based diet may help lower the risk of prostate cancer and heart disease. Other studies have shown that the Portfolio diet may help reduce the risk of death from heart disease. A new study found that following a plant-forward diet may help reduce the risk of chronic kidney diseas', 'دراسات حديثة تربط الأنماط الغذائية النباتية، ومنها بورتفوليو وEAT‑Lancet، بانخفاض مخاطر أمراض القلب والوفيات وبعض السرطانات ومرض الكلى المزمن، مع توصيات بنهج مرن ومتوازن.', 'Research shows that a plant-based diet may offer protective benefits for heart health and prevention against kidney disease and certain cancers. Image Credit: Tom Werner/Getty Images Recent research suggests that a plant-based diet may help lower the risk of prostate cancer and heart disease. Other studies have shown that the Portfolio diet may help reduce the risk of death from heart disease. A new study found that following a plant-forward diet may help reduce the risk of chronic kidney disease (CKD). A plant-based diet focuses on foods that are primarily from plants. This is more than just fruits and vegetables; it includes nuts, seeds, legumes, whole grains, and oils. Plant-based diets don&#8217;t necessarily mean you can&#8217;t ever eat meat or dairy. Following these eating patterns simply means you choose more foods derived from plant sources. Research has shown that adhering to plant-based or plant-forward diets may have various health benefits. A 2024 review found that following a vegetarian or vegan diet may help reduce the risk of ischemic heart disease, prostate cancer, and gastrointestinal cancer. A study from 2025 shows that following the Portfolio diet may help lower the risk or delay the onset of cardiovascular disease. The findings also suggest this dietary pattern may lower the risk of mortality. Meanwhile, a new study published in CMAJ (Canadian Medical Association Journal) found that adhering to the EAT-Lancet planetary diet helped reduce the risk of chronic kidney disease (CKD). Here&#8217;s what you need to know about the health benefits of plant-based and plant-forward diets. Plant-based diet may reduce cancer risk The 2024 review found that following a vegetarian or vegan diet can help reduce the risk of gastrointestinal cancer, prostate cancer, and heart disease. The findings also suggest this eating pattern could help improve cardiometabolic risk factors, such as: elevated lipids blood sugar body weight BMI inflammation The researchers reviewed 48 studies spanning 23 years. When they compiled the data, they found a strong association between vegan and vegetarian diets and cardiometabolic risk factors. However, the review&#8217;s findings had limitations, including variations in diet, patient demographics, and study length. While this review focused on vegetarian and vegan diets, some experts caution that these diets may not be the best way to eat a plant-based diet. “Research shows that vegan and vegetarian diets are often deficient in essential fatty acids — such as EPA and DHA— Vitamin B12, Vitamin D, and iodine. These are all important nutrients for human health,” said Faith Krisht, a registered dietitian nutritionist, who was not involved in the review. Krisht told Healthline that a flexitarian diet may be a better option for following a plant-based eating plan, as it can help you get all the vital nutrients you need. A flexitarian diet emphasizes plant-based proteins while occasionally adding animal-based proteins. Plant-based diet may lower heart disease risk A 2025 study found that the Portfolio diet helps lower cardiovascular disease risk, including stroke and heart disease. The Portfolio diet may also reduce the risk of mortality from cardiovascular disease and coronary heart disease. The researchers found that moderate adherence to the Portfolio diet could decrease the risk of death from cardiovascular disease by 12% and coronary heart disease by 14%. Moderate adherence also lowered overall mortality by 12%. However, the study also found that the closer a person adhered to the diet, the greater the increase in those numbers. For cardiovascular disease, the risk of death decreased by 16% for those who followed the diet the closest compared to those who adhered the least, and for coronary heart disease by 18%. Overall mortality dropped by 14%. The Portfolio diet gets its name because it calls for substituting foods already in your diet with those from a “portfolio” of cholesterol-lowering ingredients that fall into four categories: Soy/plant proteins: These help to displace saturated fat, while also helping to lower cholesterol. Plant Sterols: These block cholesterol absorption. Tree nuts: These provide heart-healthy unsaturated fats. Soluble fiber: It binds and removes bile and cholesterol. Erin Sheenan, a cardiovascular dietitian at Wellstar, told Healthline the combination of ingredients included in the Portfolio diet create an “additive” effect in lowering cholesterol. Sheenan wasn&#8217;t involved in the study. “When it comes to looking specifically at lowering (bad) LDL cholesterol, that’s where the portfolio diet really shines,” she said. “What we’re doing with this diet is combining a whole bunch of these foods to compound on top of each other and maximize that LDL-lowering effect.” Plant-based diet and kidney disease prevention Chronic kidney disease (CKD) affects about 10% of the global population, according to 2022 information. It&#8217;s estimated to become the fifth leading cause of death worldwide by 2040. A recent study found that following the EAT-Lancet planetary diet was associated with a reduced risk of CKD. “These findings aren’t surprising given the well-established benefits of nuts, vegetables, and legumes for kidney health,” said Michelle Routhenstein, a preventive cardiovascular dietitian at Entirely Nourished, who was not involved in the study. “These foods provide fiber, potassium, magnesium, antioxidants, and plant compounds that help reduce inflammation, oxidative stress, and excess acid load in the diet, all of which can strain the kidneys over time,” she told Healthline. This study was based on the UK Biobank. It involved 179,508 eligible participants ages 40 to 69 from England, Scotland, and Wales. The dietary information was collected through a questionnaire. Over the median follow-up of 12 years, 2.7% of participants developed CKD. “Greater adherence to the EAT–Lancet planetary health diet was significantly associated with a reduced risk of incident CKD,” study co-author Xianhui Qin, MD, of Nanfang Hospital and Southern Medical University in Guangzhou, China, said in a press release. &#8220;This protective association was particularly evident among individuals with low residential green space exposure and specific genetic variants,&#8221; Qin continued. The EAT-Lancet planetary health diet stands out from other plant-based diets by encompassing both human health and environmental sustainability. It emphasizes fruits, vegetables, and legumes, as well as some meat and dairy, and limits added fats and sugars. “A plant-forward, minimally processed diet helps keep blood pressure, cholesterol, and blood sugar in a healthy range, which is critical since hypertension and diabetes are the leading causes of kidney damage,” Routhenstein said. “Better control of these factors lowers pressure inside the kidneys’ filtering units and slows the wear and tear that can lead to chronic kidney disease. This way of eating also supports healthier blood flow and lowers inflammation, helping the kidneys filter waste more efficiently over time,” Routhenstein concluded.', '<p>أشارت أبحاث حديثة إلى أن الأنماط الغذائية المرتكزة على النباتات قد توفر <strong>حماية للقلب</strong> وتقلل مخاطر بعض السرطانات ومرض الكلى المزمن. فمراجعة علمية نُشرت في 2024 ربطت بين الأنظمة النباتية وانخفاض خطر أمراض القلب الإقفارية وسرطان البروستاتا وسرطانات الجهاز الهضمي، فيما أظهرت دراسة في 2025 أن حمية «بورتفوليو» قد تُخفّض الوفاة الناجمة عن أمراض القلب. وبالتوازي، وجدت دراسة في مجلة الجمعية الطبية الكندية (CMAJ) أن الالتزام بالحمية الكوكبية EAT‑Lancet يرتبط بتراجع خطر الإصابة بمرض الكلى المزمن.</p><p>النظام النباتي لا يعني بالضرورة الامتناع التام عن اللحوم أو الألبان؛ بل يركز على أن تأتي معظم اختيارات الطعام من مصادر نباتية: الخضروات والفواكه، الحبوب الكاملة، البقول، المكسرات، البذور والزيوت الصحية. ويمكن تبنّي نهج «نباتي‑مرن» يتيح حصصاً محدودة من المنتجات الحيوانية مع الحفاظ على أولوية الأغذية النباتية.</p><p>في مراجعة 2024، التي حلّلت 48 دراسة على مدى 23 عاماً، وُجد أن اتباع نظام نباتي (نباتي صرف أو نباتي) قد يرتبط بانخفاض خطر أمراض القلب الإقفارية وسرطان البروستاتا وسرطانات الجهاز الهضمي، إلى جانب تحسن عوامل خطر قلبية‑استقلابية مثل: الدهون المرتفعة، سكر الدم، الوزن، مؤشر كتلة الجسم والالتهاب. ومع ذلك، أشار الباحثون إلى حدود منهجية، منها اختلاف أنماط الحميات وخصائص المشاركين وفترات المتابعة.</p><p>ورغم مزايا الحميات النباتية، حذرت اختصاصية التغذية فيث كريشت من أن الأنظمة النباتية الصِرفة قد تفتقر إلى بعض المغذيات المهمة مثل الأحماض الدهنية الأساسية EPA وDHA، وفيتامين B12 وفيتامين D واليود. لذلك قد يكون <strong>النهج المرن</strong> خياراً عملياً لتأمين هذه العناصر عند الحاجة، سواء عبر التنويع الغذائي أو الإغناء/المكمّلات بإشراف مختص.</p><p>أما دراسة 2025 فأظهرت أن الالتزام المعتدل بحمية «بورتفوليو» ارتبط بتراجع خطر الوفاة من أمراض القلب والأوعية بنسبة 12%، ومن مرض القلب التاجي بنسبة 14%، كما انخفضت الوفيات الإجمالية بنسبة 12%. وازدادت الفوائد مع ارتفاع الالتزام: تراجع خطر الوفاة القلبية‑الوعائية 16%، والتاجية 18%، والوفيات الإجمالية 14%. وتستمد الحمية اسمها من «محفظة» من الأطعمة الخافضة للكوليسترول، تشمل الألياف القابلة للذوبان (مثل الشوفان والبقول وبذور القطونا)، البروتينات النباتية (كفول الصويا والبقوليات)، الستيرولات النباتية، والمكسرات، مع تقليل الدهون المشبعة واستبدالها بزيوت نباتية.</p><p>من جانب آخر، ربطت دراسة في CMAJ الالتزام بالحمية الكوكبية EAT‑Lancet، الغنية بالأغذية النباتية والمراعية لاستدامة الغذاء، بانخفاض خطر مرض الكلى المزمن. وقد يُفسَّر ذلك بانخفاض العبء الحمضي وزيادة الألياف والمركبات النباتية الواقية. وفي كل الأحوال، يحتاج الأشخاص المصابون بأمراض الكلى أو المعرضون لها إلى تخطيط غذائي فردي بالتعاون مع فرقهم الطبية.</p><p>الخلاصة: الأنماط الغذائية النباتية، سواء بصيغة نباتية صِرفة أو «نباتية‑مرنة»، ترتبط بتحسين مؤشرات الصحة القلبية وتقليل مخاطر بعض السرطانات ومرض الكلى المزمن. ومع أن هذه النتائج <strong>ارتباطية وليست إثباتاً للسببية</strong>، فإن تعزيز الحبوب الكاملة والبقول والخضروات والفواكه، وإدراج المكسرات والبذور والزيوت الصحية، والحد من اللحوم الحمراء والمصنعة، مع الانتباه للمغذيات الدقيقة الأساسية، يظل نهجاً واعداً لتعزيز الصحة.</p>', 'https://www.healthline.com/health-news/plant-based-diet-heart-health-benefits-cancer-kidney-disesase-prevention', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/Plant-based-Diet-GettyImages-2042526290-Header.jpg', NULL, NULL, '2026-01-29 13:36:30.895866', 'en', 'nutrition', 'nutrition', 90, NULL, false, false, NULL, 'pending', NULL, '2026-01-29 13:44:27.151', NULL, '["plant-based diet", "heart health", "cancer prevention", "kidney disease", "Portfolio diet", "vegetarian", "vegan"]', '{"topics": ["dietary health", "chronic disease prevention", "cardiovascular health", "nutrition research"], "summary": "تشير الأبحاث إلى أن النظام الغذائي النباتي قد يوفر فوائد وقائية لصحة القلب ويقلل من خطر الإصابة بأمراض الكلى وبعض أنواع السرطان. كما أظهرت الدراسات أن اتباع أنظمة غذائية مثل Portfolio وEAT-Lancet يمكن أن يحسن عوامل الخطر القلبية والتمثيل الغذائي.", "entities": ["CMAJ", "EAT-Lancet", "Tom Werner/Getty Images"], "credibilityScore": 85}', '2026-01-29 13:36:30.895866', '2026-01-31 08:07:35.925');
INSERT INTO public.radar_items VALUES ('f50085cb-ae7b-4d6e-9b79-fd5fd6590767', 'dfe2763e-0ec2-48cb-94cf-458dca898861', '34a334793431969908aff75cb3c95695', 'As US Is Poised To Lose Measles-Free Status, RFK Jr.’s New CDC Deputy Downplays Its Significance', NULL, 'Measles is at a 30-year high in the U.S., but technicalities may stave off the loss of the nation’s measles elimination status.', NULL, 'After a year of ongoing measles outbreaks that have sickened more than 2,400 people, the United States is poised to lose its status as a measles-free country. However, the newly appointed principal deputy director at the Centers for Disease Control and Prevention, Ralph Abraham, said he was unbothered by the prospect at a briefing for journalists this week. &#8220;It&#8217;s just the cost of doing business with our borders being somewhat porous for global and international travel,&#8221; Abraham said. &#8220;We have these communities that choose to be unvaccinated. That&#8217;s their personal freedom.&#8221; Infections from other countries, however, accounted for only about 10% of measles cases detected since Jan. 20, 2025, the official start of the deadly measles outbreak in West Texas, which spread to other states and Mexico. The rest were acquired domestically. This marks a change since the U.S. eliminated measles in 2000. Measles occasionally popped up in the U.S. from people infected abroad, but the cases rarely sparked outbreaks, because of extremely high rates of vaccination. Two doses of the measles, mumps, and rubella vaccine strongly prevent infection and halt the virus&#8217;s spread. To maintain its measles elimination status, the U.S. must prove that the virus has not circulated continuously in the nation for a year, between Jan. 20, 2025, and Jan. 20, 2026. To answer the question, scientists are examining whether the major outbreaks in South Carolina, Utah, Arizona, and Texas were linked. Health officials confirmed that the main measles virus strain in each of these outbreaks is D8-9171. But because this strain also occurs in Canada and Mexico, CDC scientists are now analyzing the entire genomes of measles viruses — about 16,000 genetic letters long — to see whether those in the United States are more closely related to one another than to those in other countries. The CDC expects to complete its studies within a couple of months and make the data public. Then the Pan American Health Organization, which oversees the Americas in partnership with the World Health Organization, will decide whether the U.S. will lose its measles elimination status. And that would mean that costly, potentially deadly, and preventable measles outbreaks could become common again. &#8220;When you hear somebody like Abraham say ‘the cost of doing business,&#8217; how can you be more callous,&#8221; said pediatrician and vaccine specialist Paul Offit, in an online discussion hosted by the health blog Inside Medicine on Jan. 20. &#8220;Three people died of measles last year in this country,&#8221; Offit added. &#8220;We eliminated this virus in the year 2000 — eliminated it. Eliminated circulation of the most contagious human infection. That was something to be proud of.&#8221; Abraham said vaccination remains the most effective way to prevent measles but that parents must have the freedom to decide whether to vaccinate their children. Several states have loosened school vaccine requirements since 2020, and vaccine rates have dropped. A record rate of kindergartners, representing about 138,000 children, obtained vaccine exemptions for the 2024-25 school year. Information on vaccines has been muddied by Health and Human Services Secretary Robert F. Kennedy Jr., who previously founded an anti-vaccine organization. He has undermined vaccines throughout his tenure. On national television, he has repeated scientifically debunked rumors that vaccines may cause autism, brain swelling, and death. Jennifer Nuzzo, director of the Pandemic Center at Brown University, disparaged the Trump administration&#8217;s focus on finding genetic technicalities that may spare the country&#8217;s measles-free status. &#8220;This is the wrong thing to pay attention to. Our attention has to be on stopping the outbreaks,&#8221; she said. &#8220;If we keep our status, it should be because we have stopped the spread of measles,&#8221; she said. &#8220;It&#8217;s like they&#8217;re trying to be graded on a curve.&#8221; The Trump administration impeded the CDC&#8217;s ability to assist West Texas during the first critical weeks of its outbreak and slowed the release of federal emergency funds, according to KFF Health News investigations. However, the agency stepped up its activity last year, providing local health departments with measles vaccines, communication materials, and testing. Abraham said HHS would give South Carolina $1.5 million to respond to its outbreak, which began nearly four months ago and had reached 646 cases as of Jan. 20. If the CDC&#8217;s genomic analyses show that last year&#8217;s outbreaks resulted from separate introductions from abroad, political appointees will probably credit Kennedy for saving the country&#8217;s status, said Demetre Daskalakis, a former director of the CDC&#8217;s national immunization center, who resigned in protest of Kennedy&#8217;s actions in August. And if studies suggest the outbreaks are linked, Daskalakis predicted, the administration will cast doubt on the findings and downplay the reversal of the country&#8217;s status: &#8220;They&#8217;ll say, who cares.&#8221; Indeed, at the briefing, Abraham told a reporter from Stat that a reversal in the nation&#8217;s status would not be significant: &#8220;Losing elimination status does not mean that the measles would be widespread.&#8221; Data shows otherwise. Case counts last year were the highest since 1991, before the government enacted vaccine policies to ensure that all children could be protected with measles immunization. Lauren Sausser contributed reporting. KFF Health News is a national newsroom that produces in-depth journalism about health issues and is one of the core operating programs at KFF—an independent source of health policy research, polling, and journalism. Learn more about KFF.USE OUR CONTENTThis story can be republished for free (details).', NULL, 'https://kffhealthnews.org/news/article/measles-free-status-us-cdc-ralph-abraham-paho-who-outbreaks-vaccines/', 'https://kffhealthnews.org/wp-content/uploads/sites/2/2026/01/GettyImages-2201702057.jpg?w=1024', 'Amy Maxmen', '2026-01-21 20:38:49', '2026-01-25 06:50:41.404237', 'ar', 'health-news', 'health-news', 85, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '["measles", "CDC", "vaccination", "outbreaks", "public health"]', '{"topics": ["measles elimination status", "vaccination rates", "public health policy", "disease outbreaks"], "summary": "الولايات المتحدة تواجه خطر فقدان وضعها كدولة خالية من الحصبة بعد تفشي المرض الذي أصاب أكثر من 2400 شخص. المسؤول الجديد في CDC يقلل من أهمية الوضع، مشيراً إلى قضايا السفر العالمي والمجتمعات غير الملقحة.", "entities": ["Centers for Disease Control and Prevention (CDC)", "Ralph Abraham", "United States"], "credibilityScore": 90}', '2026-01-25 06:50:41.404237', '2026-01-31 08:07:46.843');
INSERT INTO public.radar_items VALUES ('311b2d1e-6b84-486b-91f7-3395f991f001', '490fde3d-85bd-4d4f-b8b9-33004455eadc', 'a9b02b2f8047b7208a49d166de675103', 'CDC Surpasses 1 Million Voluntary Air Travel Participants in Biosurveillance Program', NULL, 'CDC announced its Traveler-Based Genomic Surveillance program surpassed one million participants', NULL, '', NULL, 'https://tools.cdc.gov/podcasts/download.asp?m=132608&c=763300', NULL, NULL, '2026-01-30 05:00:00', '2026-01-31 08:09:28.570925', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:28.570925', '2026-01-31 08:09:28.570925');
INSERT INTO public.radar_items VALUES ('c468d740-c885-4d86-8b03-5f37312aa60e', '490fde3d-85bd-4d4f-b8b9-33004455eadc', '4537d08172076644721a09a38cbf41b7', 'New recall in <em>Salmonella</em> outbreak linked to dietary supplements containing moringa leaf powder', NULL, 'As of January 29, a total of 65 people in 28 states have now been reported', NULL, '', NULL, 'https://tools.cdc.gov/podcasts/download.asp?m=132608&c=763298', NULL, NULL, '2026-01-29 05:00:00', '2026-01-31 08:09:28.741306', 'en', 'health-news', NULL, 0, NULL, false, false, NULL, 'pending', NULL, NULL, NULL, '[]', NULL, '2026-01-31 08:09:28.741306', '2026-01-31 08:09:28.741306');
INSERT INTO public.radar_items VALUES ('5da0dd5d-240b-4d62-ad21-7628013e8f2c', 'e3af2ce4-35c2-4ac8-a535-403ddb38079d', 'f61c12d9106a2098f0ae42b86983319b', 'Are You a Night Owl? Your Cardiovascular Disease Risk May Be Higher', 'محبو السهر يواجهون خطراً أعلى لأمراض القلب والسكتة', 'New research suggests that people who go bed later may have a higher risk of cardiovascular disease. Image Credit: Ani Dimi/Stocksy “Night owls,” or people who tend to go to bed later, may face higher risks of heart attack and stroke. New research suggests that night owls have less favorable cardiovascular health than those with more traditional sleep schedules. The risks, which were largely driven by lifestyle factors, are mostly modifiable. People with a night owl lifestyle as well as shift wo', 'دراسة بريطانية واسعة تربط نمط السهر بزيادة مخاطر النوبات القلبية والسكتات، لكن معظم العوامل المؤثرة قابلة للتعديل بنمط حياة صحي.', 'New research suggests that people who go bed later may have a higher risk of cardiovascular disease. Image Credit: Ani Dimi/Stocksy &#8220;Night owls,&#8221; or people who tend to go to bed later, may face higher risks of heart attack and stroke. New research suggests that night owls have less favorable cardiovascular health than those with more traditional sleep schedules. The risks, which were largely driven by lifestyle factors, are mostly modifiable. People with a night owl lifestyle as well as shift workers can make adjustmentsto protect their heart health. “Night owls,” or people who go to bed later for any number of reasons, may have worse cardiovascular health outcomes compared to those who follow traditional sleep patterns. A new study published on January 28 in the Journal of the American Heart Association found that night owls had higher risks of cardiovascular events like heart attack and stroke. The esearchers investigated the relationship between chronotype, cardiovascular disease (CVD), and common risk factors like nicotine use, sleep, and physical activity levels, as defined in the American Heart Association’s Life’s Essential 8 framework. Chronotypes are broad categories that describe people’s sleep–wake patterns based on their internal biological clock, also known as circadian rhythm. Researchers have long known that disrupted or insufficient sleep has widespread effects on the body, including on heart health, but whether a person’s chronotype plays a role has been less clear. While only a minority of people identified as “night owls” — those who favor both a later bedtime and wakeup time — that preference appears to be associated with worse cardiovascular health. The effect was even more prominent in women. Meanwhile, morning people or “larks” generally had better heart health. However, there is a silver lining: most of that risk appears to stem from modifiable factors rather than from an individual’s chronotype itself. In other words, no matter when you go to bed, there are meaningful steps you can take to improve your heart health. “The key point is not that chronotype is ‘good’ or ‘bad,’ but that being a ‘night owl’ often travels with a less favorable heart-health profile,” Sina Kianersi, DVM, PhD, a postdoctoral research fellow at Brigham and Women’s Hospital/Harvard Medical School and first author of the study, told Healthline. Night Owls have 16% higher risk of heart attack, stroke Researchers analyzed health data from more than 300,000 adults in the United Kingdom using a large medical database known as the UK Biobank. The cohort included adults ages 39 to 74 who had not had a heart attack or stroke at baseline. Participants were predominantly white, and just over half were female, with an average age of 57. The data included self-reported chronotype, with participants asked to describe themselves as “definitely morning,” “definitely evening,” or somewhere in between. Most participants (67%) identified as the latter, an intermediate chronotype. About one in four identified as a morning person, while only 8% identified as night owls. Individuals were also assigned a heart health score based on Life’s Essential 8, a framework developed by the American Heart Association to define cardiovascular risk using eight modifiable factors. This framework includes behavioral components such as diet and sleep, as well as biological measures such as blood pressure and cholesterol. Individuals received a score based on these factors to measure their risk of cardiovascular disease. After nearly 14 years of follow-up, the night owls of the cohort had a 79% higher prevalence of poor overall cardiovascular health as defined by Life’s Essential 8 compared to the intermediate chronotype. Moreover, that translated into a meaningful increase in heart attack and stroke risk: 16% higher than the intermediate group. Night owls had worse scores in six out of the eight risk factors that make up Life’s Essential 8. The study has broad implications for improving heart health, not just for night owls, but also for shift workers, and underscores the importance of addressing modifiable risk factors. Kristen Knutson, PhD, a volunteer expert with the AHA and associate professor of sleep medicine at Northwestern University Feinberg School of Medicine, who wasn’t involved in the research, described the findings as “good news.” “It means that night owls have ways to reduce their risk of CVD,” she told Healthline. In contrast, the “definitely morning” people had a 5% lower prevalence of poor heart health scores in comparison to the intermediate chronotype. The research does not lay the blame for CVD risk and poor heart health at the feet of an individual&#8217;s chronotype, but rather points out that night owls are more closely linked with unhealthy behaviors. Nicotine use had the largest impact on heart health. It was responsible for more than one-third of the CVD risk associated with being a night owl. Poor sleep was behind that, being responsible for about 14% of the risk. “If someone identifies as a night owl, our findings suggest it is especially important to pay attention to overall cardiovascular health,&#8221; Kianersi said. &#8220;For individual risk, the biggest drivers are still the basics, such as blood pressure, cholesterol, blood sugar, nicotine exposure, physical activity, body weight, diet, and sleep health.” How night owls can protect heart health Heart disease is the leading cause of death for Americans, killing two people every three minutes. Knowing your chronotype could be useful as part of a cardiovascular disease prevention strategy, especially if you consider yourself a night owl. The study suggests that it is the risk factors associated with being a night owl, not when you go to bed, that drive poorer cardiovascular outcomes. “We can’t change the circadian rhythm, because it is intrinsic and not really changeable. Instead, we can concentrate on these modifiable risk factors,” said Eleanor Levin, MD, clinical professor of cardiovascular medicine at Stanford Medicine. Levin wasn’t involved in the research. Life’s Essential 8 spells out exactly how to achieve good heart health. Those recommendations are even more important for night owls. Life’s Essential 8 makes the following recommendations about reducing CVD risk: stopping smoking being more active getting healthy sleep managing weight controlling cholesterol managing blood sugar managing blood pressure eating better Making lifestyle changes to support your heart health makes a difference. A new report from the AHA estimates that up to 40% of U.S. deaths related to cardiovascular disease could be prevented with optimal Life’s Essential 8 scores. For shift workers who must work hours that interfere with traditional sleeping hours, experts have some additional tips. “Overnight schedules can create circadian misalignment, meaning the internal body clock is out of sync with sleep, meals, and daily routines,” said Kianersi. Levin told Healthline that shift workers need to be wary of lost sleep and make up for it. “If you develop a sleep debt over several nights, you&#8217;ve got to get extra sleep sometime during the day,” she said. Additionally, she recommends making sure to keep healthy food and snack options available and to limit junk food both at home and while on shift. Wearable fitness trackers can also be helpful, according to Levin, which can not only track daily steps but also warn users of heart conditions such as atrial fibrillation. However, these should not replace medical evaluation and care. “The practical message is to protect consistent, sufficient sleep as much as possible and stay proactive about overall cardiovascular health,” Kianersi said. “We are also actively studying whether a mismatch between chronotype and work schedule further increases cardiovascular risk, but more research is needed before drawing firm conclusions about specific chronotype and shift-work combinations.”', '<p>تشير دراسة جديدة إلى أن الأشخاص الذين يفضّلون السهر وموعد النوم المتأخر قد يواجهون مخاطر أعلى للإصابة بالنوبات القلبية والسكتات الدماغية مقارنة بمن يتبعون أنماط نوم تقليدية، إلا أن معظم هذه المخاطر ترتبط بعوامل نمط الحياة وقابلة للتعديل.</p><p>نُشرت الدراسة في 28 يناير في «مجلة جمعية القلب الأمريكية»، واعتمدت على بيانات أكثر من 300 ألف بالغ في المملكة المتحدة ضمن قاعدة «UK Biobank». شمل التحليل بالغين تتراوح أعمارهم بين 39 و74 عاماً لم يسبق لهم التعرّض لنوبة قلبية أو سكتة عند بداية المتابعة، وكان متوسط العمر 57 عاماً، وغالبية المشاركين من ذوي البشرة البيضاء، مع تفوق طفيف للنساء.</p><p>طُلب من المشاركين تحديد نمطهم الزمني (chronotype) بوصف أنفسهم كأشخاص صباحيين أو مسائيين أو بينهما. عرّف 67% أنفسهم كنمط وسيط، ونحو واحد من كل أربعة كأشخاص صباحيين، فيما شكّل «محبو السهر» 8% فقط. وعلى مدى متابعة قرابة 14 عاماً، سجّل محبو السهر انتشاراً أعلى بنسبة 79% للحالة القلبية الوعائية السيئة الشاملة وفق مؤشر «الضروريات الثمانية للحياة» مقارنة بذوي النمط الوسيط، وترجم ذلك إلى زيادة قدرها 16% في خطر الإصابة بالنوبات القلبية والسكتات.</p><p>أظهرت النتائج أن محبي السهر سجّلوا درجات أسوأ في ستة من أصل ثمانية عوامل ضمن إطار «الضروريات الثمانية للحياة»، كما بدا التأثير أوضح لدى النساء. في المقابل، تمتع الأشخاص الصباحيون عموماً بمؤشرات أفضل لصحة القلب.</p><p>تُعرَّف الأنماط الزمنية بأنها تفضيلات الفرد الطبيعية لمواعيد النوم والاستيقاظ وفق إيقاعه البيولوجي الداخلي. ورغم أن اضطراب النوم أو قلته معروف بتأثيره السلبي على القلب، توضح هذه الدراسة أن <strong>العامل الحاسم غالباً هو السلوكيات الصحية القابلة للتعديل</strong> أكثر من النمط الزمني بحد ذاته. كما قال الباحث الرئيسي سينا كيانهيرسي من مستشفى بريغهام والنساء/كلية طب هارفارد: ليست المسألة أن النمط «صباحي» جيد و«مسائي» سيئ؛ بل أن نمط السهر غالباً ما يقترن بملف صحي أقل ملاءمة للقلب.</p><p>يشمل إطار «الضروريات الثمانية للحياة» عوامل سلوكية وبيولوجية قابلة للتحسين، من أبرزها:</p><ul><li>النظام الغذائي</li><li>النشاط البدني</li><li>التعرّض للنيكوتين/التدخين</li><li>صحة النوم</li><li>مؤشر كتلة الجسم</li><li>ضغط الدم</li><li>دهون الدم</li><li>سكر الدم</li></ul><p>بالنسبة لمحبي السهر والعاملين بنظام المناوبات، توصي الدراسة بإجراء تعديلات عملية على نمط الحياة لتحسين صحة القلب، مثل تحسين جودة النوم، والالتزام بالنشاط البدني، وضبط ضغط الدم والدهون والسكر، والابتعاد عن النيكوتين، ما يعني أن توقيت النوم ليس قدراً محتوماً إذا ترافق مع سلوكيات صحية.</p>', 'https://www.healthline.com/health-news/night-owls-higher-cardiovascular-disease-risk', 'https://media.post.rvohealth.io/wp-content/uploads/2026/01/night-owl-Stocksy_txp73d54598sTE400_Medium_4694053-Header.jpg', NULL, NULL, '2026-01-31 08:09:37.292399', 'en', 'health-news', NULL, 7, NULL, false, false, NULL, 'approved', NULL, '2026-01-31 08:28:48.465', NULL, '["السهر", "أمراض القلب", "السكتة الدماغية", "صحة القلب", "الإيقاع اليومي", "نمط الحياة", "النوم", "جمعية القلب الأمريكية"]', '{"topics": ["السهر", "أمراض القلب", "السكتة الدماغية", "صحة القلب", "الإيقاع اليومي", "نمط الحياة", "النوم", "جمعية القلب الأمريكية"], "summary": "دراسة بريطانية واسعة تربط نمط السهر بزيادة مخاطر النوبات القلبية والسكتات، لكن معظم العوامل المؤثرة قابلة للتعديل بنمط حياة صحي.", "entities": [], "seoTitle": "السهر يرفع خطر أمراض القلب والسكتة: دراسة بريطانية كبرى", "subtitle": "دراسة كبرى: المخاطر ناتجة عن عوامل قابلة للتغيير", "seoDescription": "تحليل لبيانات أكثر من 300 ألف بالغ في المملكة المتحدة يبين أن محبي السهر أكثر عرضة للنوبات القلبية والسكتة، لكن معظم عوامل الخطر قابلة للتعديل بنمط صحي.", "credibilityScore": 70}', '2026-01-31 08:09:37.292399', '2026-01-31 08:28:48.465');


